INSERT INTO `banners` VALUES (1,'Tổng kết 2019 vững mạnh, hướng tới 2020 đột phá','Tổ chức thành công trọn vẹn Lễ tổng kết hoạt động sản xuất kinh doanh năm 2019','1602435296-jpg.jpg',1,2,NULL,'2020-10-11 16:54:56','2020-12-07 18:55:13','2020-12-07 18:55:13','http://cic-demo.emst.webstarterz.com/',0),(2,'Tổng kết 2019 vững mạnh, hướng tới 2020 đột phá','Lễ tổng kết hoạt động sản xuất kinh doanh năm 2019','1602435310-jpg.jpg',1,2,NULL,'2020-10-11 16:55:10','2020-12-07 18:55:19','2020-12-07 18:55:19','http://cic-demo.emst.webstarterz.com/',0),(3,'Cabinet Vision 2021','Cabinet Vision 2021 đang ở giai đoạn thử nghiệm với nhiều tính năng hoàn toàn mới. Sau đây là 5 điểm mới đáng chú ý trong phiên bản sắp tới','1607567658-jpg.jpg',1,2,NULL,'2020-10-11 16:57:06','2020-12-16 20:22:21',NULL,'https://nghenoithat.vn/bai-viet/cac-tinh-nang-moi-se-xuat-hien-trong-cabinet-vision-2021',0),(4,'8 loại vật liệu thông dụng dùng cho thiết kế và sản xuất đồ trang trí','Hãy cùng Nghenoithat.vn điểm lại 8 loại vật liệu thông dụng dùng cho thiết kế và sản xuất đồ trang trí nội thất và ngoại thất chung cư, biệt thự và nhà phố','1607568051-jpg.jpg',1,2,NULL,'2020-10-11 16:57:59','2021-06-20 21:31:51','2021-06-20 21:31:51','https://nghenoithat.vn/bai-viet/8-loai-vat-lieu-thong-dung-dung-cho-thiet-ke-va-san-xuat-do-trang-tri',0),(5,'Webinar online với chủ đề “Giải pháp công nghệ nâng cao hiệu quả thiết kế và sản xuất nội thất gỗ”','Nghenoithat.vn phối hợp với Hãng phần mềm Pytha Lab (Đức) tổ chức hội thảo trực tuyến với chủ đề “Giải pháp công nghệ nâng cao hiệu quả thiết kế và sản xuất nội thất gỗ”','1607996493-jpg.jpg',1,2,NULL,'2020-12-14 18:41:33','2021-06-20 21:17:10',NULL,'https://nghenoithat.vn/bai-viet/webinar-online-voi-chu-de-giai-phap-cong-nghe-nang-cao-hieu-qua-thiet-ke-va-san-xuat-noi-that-go',0),(6,'Hội thảo trực tuyến với chủ đề “Giải pháp công nghệ mới cho nhà thầu nhôm kính”','Nghenoithat.vn tổ chức Hội thảo trực tuyến với chủ đề “Giải pháp công nghệ mới cho nhà thầu nhôm kính”','1627031456-jpg.jpg',1,2,NULL,'2021-07-22 00:20:01','2021-09-26 21:14:07','2021-09-26 21:14:07','https://nghenoithat.vn/bai-viet/nghenoithatvn-to-chuc-hoi-thao-truc-tuyen-voi-chu-de-giai-phap-cong-nghe-moi-cho-nha-thau-nhom-kinh',0),(7,'Showroom ảo – Giải pháp chuyển đổi số cho doanh nghiệp nội thất và Vật liệu xây dựng','Thị trường mua sắm trực tuyến trở nên sôi động hơn khi người mua dần có xu hướng mua bán online, thay vì cách thức đến trực tiếp cửa hàng offline như trước kia.','1637644839-PNG.PNG',1,2,NULL,'2021-11-22 22:20:39','2021-11-22 22:20:39',NULL,'https://nghenoithat.vn/bai-viet/showroom-ao-giai-phap-chuyen-doi-so-cho-doanh-nghiep-noi-that-va-vat-lieu-xay-dung',0),(8,'Floori – Giải pháp chuyển đổi số hỗ trợ sales và marketing cho ván sàn – gạch ốp lát','Là giải pháp diễn họa áp dụng cho sàn gỗ, Floori mang đến cho khách hàng trải nghiệm hoàn toàn mới.','1638525108-png.png',1,2,NULL,'2021-12-03 02:51:48','2021-12-03 02:51:48',NULL,'https://nghenoithat.vn/san-pham/floori-giai-phap-chuyen-doi-so-trong-kinh-doanh-van-san-gach-da-op-lat',0);
