INSERT INTO `blogs` VALUES (1,'Công ty CIC vinh dự là cộng sự và đối tác cung cấp phần mềm cho công ty Mai – Archi','2020-10-29 12:58:00','1602395990-cong-ty-cic-vinh-du-la-cong-su-va-doi-tac-cung-cap-phan-mem-cho-cong-ty-mai-archi.jpg','Công ty CIC tự hào là đối tác cung cấp các phần mềm liên quan tới xây dựng, kỹ thuật, thiết kế ,... cho Công ty Mai – Archi.','<div class=\"section2_right3\">\r\n<p class=\"content1\">C&ocirc;ng ty CIC tự h&agrave;o l&agrave; đối t&aacute;c cung cấp c&aacute;c phần mềm li&ecirc;n quan tới x&acirc;y dựng, kỹ thuật, thiết kế ,... cho C&ocirc;ng ty Mai &ndash; Archi.</p>\r\n</div>\r\n<div class=\"section2_right4\">\r\n<p class=\"content2\">&nbsp;</p>\r\n<p><strong>MAI-ARCHI</strong>&nbsp;l&agrave; một c&ocirc;ng ty chuy&ecirc;n nghiệp trong lĩnh vực tư vấn thiết kế Kiến tr&uacute;c c&ocirc;ng tr&igrave;nh, Quy hoạch đ&ocirc; thị v&agrave; Lập dự &aacute;n đầu tư được th&agrave;nh lập v&agrave;o năm 2006. C&ocirc;ng ty đ&atilde; c&oacute; những sản phẩm đạt chất lượng cao về chuy&ecirc;n m&ocirc;n, đạt hiệu quả cao về đầu tư. Với phương ch&acirc;m ph&aacute;t triển: &ldquo;Nhiệt t&igrave;nh, s&aacute;ng tạo kh&ocirc;ng ngừng v&agrave; lu&ocirc;n xem sự th&agrave;nh c&ocirc;ng của kh&aacute;ch h&agrave;ng l&agrave; thước đo cho sự th&agrave;nh c&ocirc;ng của ch&iacute;nh m&igrave;nh&rdquo; c&ocirc;ng ty MAI-ARCHI đ&atilde; được nhiều kh&aacute;ch h&agrave;ng tin cậy lựa chọn.</p>\r\n<p><br /><strong>MAI-ARCHI</strong>&nbsp;đ&atilde; tham gia v&agrave; đạt được nhiều giải thưởng lớn uy t&iacute;n trong nước như: Giải thưởng Kiến tr&uacute;c Quốc gia năm 2007 v&agrave; năm 2014; Giải thưởng S&aacute;ng t&aacute;c, quảng b&aacute; t&aacute;c phẩm về chủ đề học tập v&agrave; l&agrave;m việc theo tấm gương đạo đức Hồ Ch&iacute; Minh năm 2015, Nhiều lần đạt giải thưởng BCI Asia Awards vinh danh Top 10 C&ocirc;ng ty Thiết kế v&agrave; Chủ đầu tư h&agrave;ng đầu Việt Nam. B&ecirc;n cạnh đ&oacute;, c&ocirc;ng ty c&ograve;n c&oacute; nhiều t&aacute;c phẩm Kiến tr&uacute;c đoạt giải cao trong c&aacute;c kỳ thi tuyển phương &aacute;n của Doanh nghiệp v&agrave; Nh&agrave; nước.</p>\r\n<p><img src=\"https://www.cic.com.vn/upload_images/images/2020/09/09/Mai-archi-logo.jpg\" alt=\"maiarchi-logo\" /></p>\r\n<p>Với sự hợp t&aacute;c giữa hai b&ecirc;n,&nbsp;<a href=\"https://www.cic.com.vn/\"><strong>C&ocirc;ng ty CP C&ocirc;ng nghệ &amp; tư vấn&nbsp;CIC</strong></a>&nbsp;vinh dự vừa l&agrave; cộng sự trong c&aacute;c dự &aacute;n của Mai Archi, đồng thời cũng l&agrave; đối t&aacute;c cung cấp c&aacute;c sản phẩm phần mềm thiết kế cho Mai- Archi như:&nbsp;<em><a href=\"https://enjicad.cic.com.vn/\">phần mềm enjiCAD</a></em>,&nbsp;<em><a href=\"https://www.cic.com.vn/san-pham.html?hangsx=csi\">phần mềm của h&atilde;ng CSI</a></em>, phần mềm Microsoft,&nbsp;<a href=\"https://www.cic.com.vn/san-pham.html?hangsx=autodesk\">phần mềm Autodesk</a>, ....&nbsp;C&aacute;c sản phẩm phần mềm n&agrave;y đ&atilde; gi&uacute;p cho Mai-Archi n&acirc;ng cao năng lực v&agrave; chất lượng sản phẩm của m&igrave;nh.</p>\r\n<p>Trong thời gian tới hai b&ecirc;n sẽ tiếp tục hợp t&aacute;c chặt chẽ c&ugrave;ng nhau để phục vụ kh&aacute;ch h&agrave;ng tốt hơn, mang lại nhiều gi&aacute; trị hơn trong c&aacute;c sản phẩm, dịch vụ của c&aacute;c b&ecirc;n.&nbsp;</p>\r\n</div>\r\n<div id=\"eJOY__extension_root\" class=\"eJOY__extension_root_class\" style=\"all: unset;\">&nbsp;</div>','Công ty CIC vinh dự là cộng sự và đối tác cung cấp phần mềm cho công ty Mai – Archi',NULL,'cong-ty-cic-vinh-du-la-cong-su-va-doi-tac-cung-cap-phan-mem-cho-cong-ty-mai-archi','Công ty CIC vinh dự là cộng sự và đối tác cung cấp phần mềm cho công ty Mai – Archi','Công ty CIC','Published',2,NULL,0,0,'2020-10-11 05:59:50','2020-12-10 02:11:42','2020-12-10 02:11:42'),(2,'Phát hành CSiCol v10','2020-10-07 23:19:00','1602433384-phat-hanh-csicol-v10.png','Hãng CSI vừa cho ra mắt version mới của phần mềm CSiCol. CSiCol v10 ngoài các tính năng như trước đây, hiện đã được bổ sung thêm các tính năng mới trong đó có tính năng nhập thông tin cột từ Etabs, hoạc nhập tiết diện từ text và file CAD DXF.','<div class=\"section2_right3\">\r\n<p class=\"content1\">H&atilde;ng CSI vừa cho ra mắt version mới của phần mềm CSiCol. CSiCol v10 ngo&agrave;i c&aacute;c t&iacute;nh năng như trước đ&acirc;y, hiện đ&atilde; được bổ sung th&ecirc;m c&aacute;c t&iacute;nh năng mới trong đ&oacute; c&oacute; t&iacute;nh năng nhập th&ocirc;ng tin cột từ Etabs, hoạc nhập tiết diện từ text v&agrave; file CAD DXF. Chi tiết t&iacute;nh năng mới của CSiCol v10 được tổng hợp như dưới đ&acirc;y:</p>\r\n</div>\r\n<div class=\"section2_right4\">\r\n<p class=\"content2\">&nbsp;</p>\r\n<p><img src=\"https://www.cic.com.vn/upload_images/images/2020/09/11/1.png\" alt=\"ra-met-csicolv10\" /></p>\r\n<h2><strong>Tổng quan CSiCol</strong></h2>\r\n<h2>CSiCol phần mềm ph&acirc;n t&iacute;ch thiết kế kết cấu cột b&ecirc; t&ocirc;ng, b&ecirc; t&ocirc;ng cốt th&eacute;p v&agrave; vật liệu composite. CSiCol với c&ocirc;ng cụ Quick Design Wizard gi&uacute;p truy cập v&agrave;o tất cả c&aacute;c biểu mẫu th&ocirc;ng số cần thiết trong qu&aacute; tr&igrave;nh thiết kế cột, gi&uacute;p đơn giản qu&aacute; tr&igrave;nh thiết kế, c&oacute; tổ chức v&agrave; tăng hiệu quả. Thiết kế c&oacute; thể tu&acirc;n theo c&aacute;c ti&ecirc;u chuẩn quốc tế. Qu&aacute; tr&igrave;nh ph&acirc;n t&iacute;ch v&agrave; thiết kế c&oacute; t&iacute;nh tương t&aacute;c.<br /><br /><strong>Một số t&iacute;nh năng mới</strong></h2>\r\n<p><strong>1. Khả năng ph&acirc;n t&iacute;ch &amp; thiết kế:</strong><br />Nhập m&ocirc; h&igrave;nh cột từ&nbsp;<a href=\"https://www.consoft.vn/csi/etabs.html\">Etabs</a>&nbsp;với đầy đủ t&iacute;nh th&ocirc;ng số của chất vật liệu, tiết diện mặt cắt, tải trọng v&agrave; khung kết cấu.</p>\r\n<p><img src=\"https://www.cic.com.vn/upload_images/images/2020/09/11/2.png\" alt=\"nhap-mo-hinh-tu-etabs\" /></p>\r\n<p>&nbsp;</p>\r\n<div class=\"btgrid\">\r\n<div class=\"row row-1\">\r\n<div class=\"col col-md-6\">\r\n<div class=\"content\">\r\n<p><strong>2. Hỗ trợ c&aacute;c ti&ecirc;u chuẩn quốc tế sau:</strong></p>\r\n<p>ACI 318-19</p>\r\n<p>ACI 318-14</p>\r\n<p>ACI 318-11</p>\r\n<p>ACI 530-11</p>\r\n<p>AS 3600-18</p>\r\n<p>BS 8110-97</p>\r\n<p>Chinese 2010</p>\r\n<p>CSA A23.3-04</p>\r\n<p>Eurocode 2-2004</p>\r\n<p>Hong Kong CP:2013</p>\r\n<p>IS 456:2000</p>\r\n<p>KBC 2016</p>\r\n<p>Mexican RCDF:2017</p>\r\n<p>NZS 3101:2006</p>\r\n<p>Singapore CP 65-99</p>\r\n<p>TS 500:2000</p>\r\n</div>\r\n</div>\r\n<div class=\"col col-md-6\">\r\n<div class=\"content\">\r\n<p><img src=\"https://www.cic.com.vn/upload_images/images/2020/09/11/3.png\" alt=\"\" /></p>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<p>&nbsp;</p>\r\n<p><strong>3. Tạo tiết diện cột:</strong></p>\r\n<p>Bắt đầu từ bất kỳ tiết diện h&igrave;nh học n&agrave;o được x&aacute;c định trước, bao gồm tiết diện đặc, rỗng v&agrave; c&aacute;c mặt b&iacute;ch. Nhiều lựa chọn với c&aacute;c tiết diện theo ti&ecirc;u chuẩn. Hoặc vẽ h&igrave;nh dạng tiết diện của ri&ecirc;ng bạn, cũng c&oacute; thể tạo tiết diện mới bằng c&aacute;ch gh&eacute;p c&aacute;c tiết diện v&agrave; trừ c&aacute;c phần giao.</p>\r\n<p><img src=\"https://www.cic.com.vn/upload_images/images/2020/09/11/4.png\" alt=\"tao-tiet-dien-cot\" /></p>\r\n<h2>&nbsp;</h2>\r\n<p><strong>4. Kết quả t&iacute;nh to&aacute;n v&agrave; b&aacute;o c&aacute;o</strong></p>\r\n<p>In đồ thị P-M hoặc M-M trong c&ugrave;ng một biểu đồ với c&aacute;c gi&aacute; trị kh&aacute;c nhau cho Cường độ n&eacute;n của b&ecirc; t&ocirc;ng (fc &rsquo;), Cường độ k&eacute;o của th&eacute;p (fy) hoặc k&iacute;ch thước cốt th&eacute;p</p>\r\n<p><img src=\"https://www.cic.com.vn/upload_images/images/2020/09/11/5.png\" alt=\"\" /></p>\r\n<p>&nbsp;</p>\r\n<p>Tạo b&aacute;o c&aacute;o một trang chứa c&aacute;c chi tiết như đặc t&iacute;nh mặt cắt v&agrave; vật liệu, chi tiết cốt th&eacute;p v&agrave; tổ hợp tải trọng chi phối cho từng cột trong dự &aacute;n.</p>\r\n<p><img src=\"https://www.cic.com.vn/upload_images/images/2020/09/11/6.png\" alt=\"\" /></p>\r\n<p>&nbsp;</p>\r\n</div>\r\n<div id=\"eJOY__extension_root\" class=\"eJOY__extension_root_class\" style=\"all: unset;\">&nbsp;</div>','Phát hành CSiCol v10',NULL,'phat-hanh-csicol-v10','Hãng CSI vừa cho ra mắt version mới của phần mềm CSiCol. CSiCol v10 ngoài các tính năng như trước đây, hiện đã được bổ sung thêm các tính năng mới trong đó có tính năng nhập thông tin cột từ Etabs, hoạc nhập tiết diện từ text và file CAD DXF.','CSiCol, CIC','Published',2,NULL,0,0,'2020-10-11 16:23:04','2020-12-10 02:11:46','2020-12-10 02:11:46'),(3,'Ứng dụng BIM trong xây dựng và Giải pháp từ CIC','2020-10-06 23:24:00','1606813416-ung-dung-bim-trong-xay-dung-va-giai-phap-tu-cic.jpg','BIM là một quy trình liên quan tới việc tạo lập và quản lý những đặc trưng kỹ thuật số (được gọi là mô hình thông tin kỹ thuật số) trong các khâu thiết kế, thi công và vận hành các công trình (công trình ở đây có thể là công trình xây dựng hay các sản phẩm công nghiệp).','<div class=\"section2_right3\">\r\n<p class=\"content1\">BIM l&agrave; một quy tr&igrave;nh li&ecirc;n quan tới việc tạo lập v&agrave; quản l&yacute; những đặc trưng kỹ thuật số (được gọi l&agrave; m&ocirc; h&igrave;nh th&ocirc;ng tin kỹ thuật số) trong c&aacute;c kh&acirc;u thiết kế, thi c&ocirc;ng v&agrave; vận h&agrave;nh c&aacute;c c&ocirc;ng tr&igrave;nh (c&ocirc;ng tr&igrave;nh ở đ&acirc;y c&oacute; thể l&agrave; c&ocirc;ng tr&igrave;nh x&acirc;y dựng hay c&aacute;c sản phẩm c&ocirc;ng nghiệp).</p>\r\n</div>\r\n<div class=\"section2_right4\">\r\n<p class=\"content2\">&nbsp;</p>\r\n<h2><strong>V&Igrave; SAO N&Ecirc;N SỬ DỤNG BIM?</strong></h2>\r\n<p>Về bản chất, c&oacute; thể xem BIM l&agrave; một hồ sơ thiết kế gồm những&nbsp;<a title=\"Tập tin\" href=\"https://vi.wikipedia.org/wiki/T%E1%BA%ADp_tin\">tập tin</a>&nbsp;hay&nbsp;<a title=\"Dữ liệu\" href=\"https://vi.wikipedia.org/wiki/D%E1%BB%AF_li%E1%BB%87u\">dữ liệu</a>&nbsp;<a title=\"Kỹ thuật số\" href=\"https://vi.wikipedia.org/wiki/K%E1%BB%B9_thu%E1%BA%ADt_s%E1%BB%91\">kỹ thuật số</a>, chứa c&aacute;c mối li&ecirc;n hệ logic về mặt kh&ocirc;ng gian, k&iacute;ch thước, số lượng, vật liệu của từng cấu kiện, bộ phận trong c&ocirc;ng tr&igrave;nh. Những th&ocirc;ng tin n&agrave;y được trao đổi v&agrave; kết nối trực tuyến với nhau th&ocirc;ng qua c&aacute;c&nbsp;<a title=\"Phần mềm\" href=\"https://vi.wikipedia.org/wiki/Ph%E1%BA%A7n_m%E1%BB%81m\">phần mềm</a>, để hỗ trợ cho việc quản l&yacute; v&agrave; ra những quyết định li&ecirc;n quan tới c&ocirc;ng tr&igrave;nh.</p>\r\n<p>Việc kết hợp c&aacute;c th&ocirc;ng tin về c&aacute;c bộ phận trong c&ocirc;ng tr&igrave;nh với c&aacute;c th&ocirc;ng tin kh&aacute;c như định mức, đơn gi&aacute;, tiến độ thi c&ocirc;ng... sẽ tạo n&ecirc;n một m&ocirc; h&igrave;nh&nbsp;<a title=\"Thực tế ảo\" href=\"https://vi.wikipedia.org/wiki/Th%E1%BB%B1c_t%E1%BA%BF_%E1%BA%A3o\">thực tại ảo</a>&nbsp;của c&ocirc;ng tr&igrave;nh, nhằm mục đ&iacute;ch tối ưu h&oacute;a thiết kế, thi c&ocirc;ng, vận h&agrave;nh quản l&yacute; c&ocirc;ng tr&igrave;nh, từ đ&oacute; đơn giản h&oacute;a c&ocirc;ng việc quản l&yacute; v&agrave; tối ưu h&oacute;a chi ph&iacute;.</p>\r\n<h2><strong>C&Aacute;C MỨC ĐỘ ỨNG DỤNG BIM?</strong></h2>\r\n<p><strong><img src=\"https://www.cic.com.vn/upload_images/images/2020/04/27/1.png\" alt=\"BIM-levels\" /></strong></p>\r\n<ul>\r\n<li><strong><em>BIM 3D:</em></strong>&nbsp;L&agrave; m&ocirc; h&igrave;nh 3D (k&iacute;ch thước 3 chiều) được dựng bằng c&aacute;c phần mềm đồ họa 3D, từ đ&acirc;y tr&iacute;ch xuất ra c&aacute;c sản phẩm thiết kế l&agrave; c&aacute;c bản vẽ h&igrave;nh chiếu 2D. Th&ocirc;ng tin dữ liệu thống nhất.</li>\r\n<li><strong><em>BIM 4D:</em></strong>&nbsp;Khai th&aacute;c th&ocirc;ng tin từ m&ocirc; h&igrave;nh 3D chuyển qua c&aacute;c ứng dụng kh&aacute;c để lập kế hoạch thi c&ocirc;ng, b&aacute;o c&aacute;o, thống k&ecirc; ...</li>\r\n<li><strong><em>BIM 5D:</em></strong>&nbsp;Khai th&aacute;c th&ocirc;ng tin 3D, 4D để lập dự to&aacute;n, thanh quyết to&aacute;n nhanh ch&oacute;ng theo thời gian thực.</li>\r\n<li><strong><em>BIM 6D:</em></strong>&nbsp;Kết nối th&ocirc;ng tin từ nhiều đối t&aacute;c, tập hợp v&agrave; quản l&yacute; một c&aacute;ch xuy&ecirc;n suốt theo chiều ngang lẫn chiều dọc của dự &aacute;n.</li>\r\n<li><strong><em>Chất lượng v&agrave; an to&agrave;n:</em></strong>&nbsp;Song song với c&aacute;c cấp độ tr&ecirc;n ở bất k&igrave; một c&ocirc;ng tr&igrave;nh n&agrave;o cũng cần phải kiểm tra chất lượng, quản l&yacute; khiếm khuyết, quản l&yacute; rủi do v&agrave; check list &amp; hand over.</li>\r\n</ul>\r\n<h2><strong>C&Aacute;C MỨC ĐỘ BIM ỨNG DỤNG HIỆU QUẢ CHO DOANH NGHIỆP</strong><br />T&ugrave;y theo nhu cầu của mỗi doanh nghiệp ch&uacute;ng ta c&oacute; mức độ ứng dụng kh&aacute;c nhau v&agrave; thiết lập n&ecirc;n c&aacute;c hệ thống BIM cụ thể, r&otilde; r&agrave;ng cho mục ti&ecirc;u doanh nghiệp:</h2>\r\n<ol start=\"5\">\r\n<li><strong>Đối với chủ đầu tư:</strong>&nbsp;Họ lu&ocirc;n cần th&ocirc;ng tin về d&ograve;ng vốn v&agrave; hiệu quả đầu tư. Để c&oacute; th&ocirc;ng tin về d&ograve;ng vốn họ cần th&ocirc;ng tin chi ph&iacute; tức thời tại từng thời điểm họ muốn. Điều n&agrave;y BIM mang lại cho họ lợi &iacute;ch khi thực hiện được BIM 5D. Để c&oacute; th&ocirc;ng tin về hiệu quả th&igrave; họ cần BIM quản trị ở mức 6D.</li>\r\n<li value=\"5\"><strong>Đối với nh&agrave; thầu:</strong>&nbsp;Hầu hết c&aacute;c mức từ 5D đến 6D đều c&oacute; ứng dụng cho họ.</li>\r\n<li><strong>Đối với tư vấn thiết kế:</strong>&nbsp;Hai mức quan trọng nhất m&agrave; BIM mang lại hiệu quả cao cho đơn vị tư vấn thiết kế đ&oacute; l&agrave; BIM 3D v&agrave; 6D. C&ograve;n BIM 4D v&agrave; 5D chỉ gi&uacute;p tăng sức cạnh tranh chứ kh&ocirc;ng nhất thiết đối với họ.</li>\r\n</ol>\r\n<h2><strong>NHỮNG KH&Oacute; KHĂN DOANH NGHIỆP GẶP PHẢI KHI BƯỚC ĐẦU &Aacute;P DỤNG BIM</strong></h2>\r\n<p><strong>1. Thi&ecirc;́u chuy&ecirc;n m&ocirc;n</strong></p>\r\n<p>Khi ti&ecirc;́n hành đi&ecirc;̀u tra khảo sát, r&acirc;́t nhi&ecirc;̀u các c&ocirc;ng ty x&acirc;y dựng đã có những báo cáo khác nhau v&ecirc;̀ thách thức và rào cản mà họ phải đ&ocirc;́i mặt trong khi k&ecirc;́t hợp BIM.</p>\r\n<p>Thứ nh&acirc;́t, khái ni&ecirc;̣m BIM còn khá mới mẻ so với nhi&ecirc;̀u người, và họ sẽ gặp nhi&ecirc;̀u vướng mắc khi tri&ecirc;̉n khai. BIM đã được hi&ecirc;̉u theo những chi&ecirc;̀u hướng&nbsp;phức tạp hơn. Tuy nhi&ecirc;n, thách thức khó khăn nh&acirc;́t là thi&ecirc;́u năng lực. Những người trong ngành x&acirc;y dựng thi&ecirc;́u các ki&ecirc;́n thức chuy&ecirc;n m&ocirc;n và ki&ecirc;́n thức đ&ecirc;̉ thực hi&ecirc;̣n khái ni&ecirc;̣m mới này.</p>\r\n<p><strong>2. Ngại thay đ&ocirc;̉i</strong></p>\r\n<p>Đ&ecirc;̉ k&ecirc;́t hợp BIM, m&ocirc;̣t cách thức làm vi&ecirc;̣c cởi mở thực sự c&acirc;̀n thi&ecirc;́t giữa các b&ecirc;n li&ecirc;n quan của dự án.</p>\r\n<p>Trong ngành x&acirc;y dựng, nơi các nhà quản lý dự án dành ph&acirc;̀n lớn thời gian ngoài c&ocirc;ng trường và làm vi&ecirc;̣c theo cách của họ. Tuy nhi&ecirc;n trong trường hợp áp dụng BIM, những người quản lý dự án c&acirc;̀n phải tu&acirc;n theo các hướng d&acirc;̃n và quy trình nghi&ecirc;m ngặt. Đ&acirc;y cũng là m&ocirc;̣t trong những thách thức đ&ocirc;́i với các c&ocirc;ng ty mới dùng BIM tại Vi&ecirc;̣t Nam.</p>\r\n<p><strong>3. Quản lý th&ocirc;ng tin</strong></p>\r\n<p>M&ocirc;̣t thách thức khác mà các c&ocirc;ng ty phải đ&ocirc;́i mặt là vi&ecirc;̣c quản lý th&ocirc;ng tin và tài nguy&ecirc;n trong quá trình thực hi&ecirc;̣n BIM.</p>\r\n<p>C&ocirc;ng ty phải đảm bảo rằng các nhà cung c&acirc;́p và th&acirc;̀u phụ cũng phải nắm được c&ocirc;ng ngh&ecirc;̣ này và tu&acirc;n thủ đúng nguy&ecirc;n tắc thực hi&ecirc;̣n. Sự tham gia của các b&ecirc;n như nhà cung c&acirc;́p và nhà th&acirc;̀u phụ sẽ d&acirc;̃n đ&ecirc;́n vi&ecirc;̣c phải quản lý nhi&ecirc;̀u th&ocirc;ng tin hơn. Do v&acirc;̣y các đơn vị c&acirc;̀n sáng su&ocirc;́t lựa chọn những đ&ocirc;́i tác giàu kinh nghi&ecirc;̣m đ&ecirc;̉ h&ocirc;̃ trợ v&ecirc;̀ trình đ&ocirc;̣, ki&ecirc;́n thức, kinh nghi&ecirc;̣m và ngu&ocirc;̀n lực.</p>\r\n<p><strong>4. Chi phí phát sinh</strong></p>\r\n<p>Chi phí ph&acirc;̀n m&ecirc;̀m BIM và sự kh&ocirc;ng tương thích với các ph&acirc;̀n m&ecirc;̀m khác cũng là rào cản mà các c&ocirc;ng ty c&acirc;̀n phải lường trước khi chọn BIM. Những thách thức như l&ocirc;̃i ph&acirc;̀n m&ecirc;̀m hoặc các phương thức l&acirc;̣p m&ocirc; hình kh&ocirc;ng chính xác do thi&ecirc;́u kinh nghi&ecirc;̣m trong vi&ecirc;̣c sử dụng m&ocirc; hình 3D.</p>\r\n<p>Cu&ocirc;́i cùng nhưng kh&ocirc;ng kém ph&acirc;̀n quan trọng, các c&ocirc;ng ty đang tri&ecirc;̉n khai BIM c&acirc;̀n phải thay đ&ocirc;̉i quy trình làm vi&ecirc;̣c. Đ&ecirc;̉ thực hi&ecirc;̣n những sự thay đ&ocirc;̉i c&acirc;̀n thi&ecirc;́t này, chi phí sẽ được phát sinh. Và các c&ocirc;ng ty đang boăn khoăn nhi&ecirc;̀u hơn v&ecirc;̀ chi phí sau khi thực hi&ecirc;̣n BIM.</p>\r\n<p>BIM c&acirc;̀n được nhìn nh&acirc;̣n từ quan đi&ecirc;̉m của giá trị gia tăng. Vi&ecirc;̣c tri&ecirc;̉n khai BIM kèm các ph&acirc;̀n m&ecirc;̀m BIM sẽ g&acirc;y ra sự thay đ&ocirc;̉i trong ngành c&ocirc;ng nghi&ecirc;̣p x&acirc;y dựng. Tuy nhi&ecirc;n lợi ích l&acirc;u dài là kh&ocirc;ng th&ecirc;̉ ch&ocirc;́i cãi được.</p>\r\n<h2><strong>C&Ocirc;NG TY CỔ PHẦN C&Ocirc;NG NGHỆ V&Agrave; TƯ VẤN CIC GI&Uacute;P DOANH NGHIỆP ỨNG DỤNG BIM NHƯ THẾ N&Agrave;O?</strong><br />Với mục ti&ecirc;u l&agrave;m sao đem lại hiệu quả thực tế cho DN n&ecirc;n CIC đi theo hướng may đo trực tiếp chứ kh&ocirc;ng đ&agrave;o tạo đại tr&agrave; v&igrave; vậy:</h2>\r\n<ol start=\"5\">\r\n<li>C&aacute;c DN sẽ c&oacute; một quy tr&igrave;nh, một lộ tr&igrave;nh &aacute;p dụng ph&ugrave; hợp nhất ph&ugrave; hợp với mong muốn nhu cầu d&agrave;i hạn, ngắn hạn của DN tr&aacute;nh l&atilde;ng ph&iacute;, thất tho&aacute;t.</li>\r\n<li value=\"5\">Song h&agrave;nh c&ugrave;ng DN trong giai đoạn &aacute;p dụng BIM, tư vấn cho DN hướng xử l&yacute; đối với những vấn đề ph&aacute;t sinh, những vấn đề c&ograve;n tồn đọng về &aacute;p dụng BIM ở DN để chắc chắn lộ tr&igrave;nh đạt đ&uacute;ng tiến độ.</li>\r\n</ol>\r\n<p><strong>BIM 3D:&nbsp;</strong>Với đội ngũ Chuy&ecirc;n gia, Kỹ thuật, IT l&acirc;u năm, d&agrave;y dạn kinh nghiệm. CIC sẽ gi&uacute;p DN bước đầu &aacute;p dụng c&aacute;c phần mềm BIM 3D của&nbsp;<a href=\"https://www.cic.com.vn/san-pham.html?hangsx=autodesk\">Autodesk</a>&nbsp;nhưng vẫn đem lại được sản phẩm bằng những c&ocirc;ng cụ ph&ugrave; hợp. Nghĩa l&agrave; c&aacute;c DN sẽ c&oacute; thể &aacute;p dụng lu&ocirc;n v&agrave;o dự &aacute;n hiện tại.</p>\r\n<p><img src=\"https://www.cic.com.vn/upload_images/images/2020/04/27/2.jpg\" alt=\"BIM-3d-cic\" /></p>\r\n<p><strong>BIM 4D:</strong>&nbsp;Ch&uacute;ng t&ocirc;i sẽ tư vấn để chọn ra hướng đi ph&ugrave; hợp nhất, hiệu quả nhất đối với việc &aacute;p dụng BIM 4D cho DN. Một trong số đ&oacute; c&oacute; Fuzor đ&atilde; đ&aacute;p ứng rất tốt trong cấp độ n&agrave;y.</p>\r\n<p><img src=\"https://www.cic.com.vn/upload_images/images/2020/04/27/3.jpg\" alt=\"BIM-4d-fuzor\" /></p>\r\n<p><strong>BIM 5D:&nbsp;</strong>Vấn đề Chi ph&iacute; l&agrave; vấn đề quan t&acirc;m h&agrave;ng đầu của c&aacute;c DN, V&igrave; vậy CIC đ&atilde; chọn ra được một chuỗi hướng đi để ph&ugrave; hợp nhất với phương hướng ph&aacute;t triển, t&igrave;nh h&igrave;nh năng lực của doanh nghiệp để l&agrave;m sao ra được hiệu quả tối ưu nhất, &iacute;t tốn k&eacute;m chi ph&iacute; nhất.</p>\r\n<p>Trong chuỗi giải ph&aacute;p n&agrave;y c&oacute; bộ phần mềm&nbsp;<a href=\"https://cubicost.cic.com.vn/\">Cubicost</a>&nbsp;l&agrave; bộ phần mềm hỗ trợ b&oacute;c t&aacute;ch khối lượng một c&aacute;ch th&ocirc;ng minh tr&ecirc;n nền tảng BIM v&agrave; CAD. Gi&uacute;p giảm thiểu tối đa những c&ocirc;ng việc mang t&iacute;nh chất lặp đi lặp lại của c&aacute;c kỹ sư từ đ&oacute; gi&uacute;p tiết kiệm thời gian v&agrave; n&acirc;ng cao năng suất của c&ocirc;ng việc b&oacute;c t&aacute;ch khối lượng v&agrave; l&agrave;m hồ sơ thầu.</p>\r\n<ul>\r\n<li><strong>Cubicost:</strong>&nbsp;Một bộ sản phẩm ho&agrave;n chỉnh của Cubicost bao gồm 4 phần mềm với những chức năng kh&aacute;c nhau, hoạt động c&ugrave;ng nhau để tạo th&agrave;nh một giải ph&aacute;p b&oacute;c t&aacute;ch khối lượng dự to&aacute;n ho&agrave;n chỉnh.<br /><strong>TAS C:</strong>&nbsp;B&oacute;c t&aacute;ch khối lượng b&ecirc; t&ocirc;ng, v&aacute;n khu&ocirc;n, đ&agrave;o đắp, ho&agrave;n thiện.<br /><strong>TRB C:</strong>&nbsp;B&oacute;c t&aacute;ch khối lượng cốt th&eacute;p<br /><strong>TME&nbsp;&nbsp; :</strong>&nbsp;B&oacute;c t&aacute;ch khối lượng MEP<br /><strong>TBQ&nbsp;&nbsp;&nbsp; :</strong>&nbsp;Tổng khối lượng từ TAS, TRB v&agrave; TME. Quản l&yacute; khối lượng v&agrave; l&agrave;m hồ sơ thầu.</li>\r\n</ul>\r\n<p>C&aacute;c khối lượng xuất ra tr&ecirc;n Cubicost sẽ c&oacute; diễn giải chi tiết từng cấu kiện một, c&oacute; thể kiểm tra lại trực tiếp tr&ecirc;n m&ocirc; h&igrave;nh v&igrave; vậy việc bảo vệ khối lượng kh&ocirc;ng c&ograve;n l&agrave; nỗi lo với c&aacute;c kỹ sư QS.</p>\r\n<p><img src=\"https://www.cic.com.vn/upload_images/images/2020/04/27/4.png\" alt=\"BIM-5d-cubicost\" /></p>\r\n<ul>\r\n<li>Từ bản vẽ 2D, vector PDF c&aacute;c kỹ sư c&oacute; thể m&ocirc; h&igrave;nh một c&aacute;ch nhanh ch&oacute;ng với t&iacute;nh năng tự động nhận diện c&aacute;c cấu kiện, việc m&ocirc; h&igrave;nh sẽ trở n&ecirc;n rất đơn giản chỉ với v&agrave;i c&uacute; click chuột.</li>\r\n</ul>\r\n<p><img src=\"https://www.cic.com.vn/upload_images/images/2020/04/27/5.png\" alt=\"tas-cubicost-bim-5d-boc-tach-2d\" /></p>\r\n<ul>\r\n<li>Từ m&ocirc; h&igrave;nh 3D file IFC hoặc&nbsp;<a href=\"https://www.cic.com.vn/autodesk-revit-p243.html\">Revit</a>&nbsp;nhận được th&igrave; chỉ cần một v&agrave;i thao t&aacute;c v&agrave; t&iacute;nh to&aacute;n phần mềm sẽ xuất ra khối lượng một c&aacute;ch ch&iacute;nh x&aacute;c, đầy đủ m&agrave; kh&ocirc;ng cần mất c&ocirc;ng m&ocirc; h&igrave;nh lại.</li>\r\n</ul>\r\n<p><img src=\"https://www.cic.com.vn/upload_images/images/2020/04/27/6.png\" alt=\"tas-cubicost-bim-5d-boc-tach-3d\" /></p>\r\n<ul>\r\n<li>Ngo&agrave;i ra để tăng hiệu quả của Cubicost mang lại CIC đ&atilde; ph&aacute;t triển c&aacute;c giải ph&aacute;p kết hợp với Digicost</li>\r\n</ul>\r\n<p><strong>Digicost:&nbsp;</strong>C&ocirc;ng cụ kết hợp c&aacute;c dữ liệu từ m&ocirc; h&igrave;nh BIM xuất ra, từ đấy kết hợp với định mức, đơn gi&aacute; của Nh&agrave; nước, DN để xuất ra một bảng BoQ đầy đủ, tự động ho&agrave;n to&agrave;n quy tr&igrave;nh l&agrave;m việc về khối lượng của một kỹ sư QS</p>\r\n<p>&nbsp;</p>\r\n<p>- Cubicost + Digicost: Từ khối lượng xuất ra tr&ecirc;n Cubicost sẽ đưa v&agrave;o Digicost để ra một bảng BoQ</p>\r\n<p>-&nbsp;<a href=\"https://www.cic.com.vn/autodesk-revit-p243.html\">Revit</a>&nbsp;+&nbsp;<a href=\"https://cubicost.cic.com.vn/\">Cubicost</a>&nbsp;+ Digicost: D&ugrave;ng Revit để c&oacute; thể m&ocirc; h&igrave;nh c&oacute; thể sử dụng tốt hơn cho c&aacute;c mục đ&iacute;ch BIM tiếp theo như 4D, 6D, đ&aacute;p ứng nhu cầu ph&aacute;t triển l&acirc;u d&agrave;i cho DN</p>\r\n<p><img src=\"https://www.cic.com.vn/upload_images/images/2020/04/27/7.png\" alt=\"revit-cubicost-digicost-bim-6d\" /></p>\r\n<p><strong>BIM 6D:&nbsp;</strong>Ecodomus l&agrave; bộ c&ocirc;ng cụ th&ocirc;ng minh giải quyết được b&agrave;i to&aacute;n quản l&yacute; vận h&agrave;nh hợp với thị trường Việt Nam nhất hiện nay, c&oacute; thể kết hợp với c&aacute;c ứng dụng BIM kh&aacute;c.<em>&nbsp;</em></p>\r\n</div>\r\n<div id=\"eJOY__extension_root\" class=\"eJOY__extension_root_class\" style=\"all: unset;\">&nbsp;</div>','Ứng dụng BIM trong xây dựng và Giải pháp từ CIC',NULL,'ung-dung-bim-trong-xay-dung-va-giai-phap-tu-cic','Ứng dụng BIM trong xây dựng và Giải pháp từ CIC','Công ty CIC , GPR','Published',2,NULL,1,0,'2020-10-11 16:25:53','2020-12-10 02:11:56','2020-12-10 02:11:56'),(4,'CIC trúng gói thầu “Mua sắm phần mềm cho ngành Khoa học vật liệu\" của Trường Đại học Việt Đức','2020-10-07 23:26:00','1602433661-cic-trung-goi-thau-mua-sam-phan-mem-cho-nganh-khoa-hoc-vat-lieu-cua-truong-dai-hoc-viet-duc.jpg','Vật liệu ngày càng đóng vai trò quan trọng trong quá trình đổi mới công nghệ. Đẩy mạnh nghiên cứu, giảng dạy ngành khoa học vật liệu có ý nghĩa hết sức quan trọng, đem lại sự phát triển công nghệ đặc biệt cần thiết cho các nước đang phát triển điển hình như Việt Nam hiện nay. Trường Đại học Việt Đức là một trong những cơ sở nghiên cứu và đào tạo hàng đầu trong lĩnh vực khoa học vật liệu ở Việt Nam','<p>Th&aacute;ng 6 vừa qua,&nbsp;<strong>Trường Đại học Việt Đức</strong>&nbsp;đ&atilde; k&yacute; hợp đồng với&nbsp;<strong>C&ocirc;ng ty Cổ phần C&ocirc;ng nghệ v&agrave; Tư vấn CIC</strong>&nbsp;về việc mua sắm c&aacute;c phần mềm chuy&ecirc;n ng&agrave;nh Khoa học&nbsp;vật liệu&nbsp;bao gồm:<br />-&nbsp;<em><strong>Phần mềm Thermo-Calc của h&atilde;ng Thermo-Calc&nbsp;(Thụy Điển)</strong></em>&nbsp;bao gồm m&ocirc; đun DICTRA v&agrave; TC-PRISMA: cho ph&eacute;p sinh vi&ecirc;n l&agrave;m việc độc lập với cơ sở dữ liệu nhiệt động để tạo sơ đồ pha bằng c&aacute;ch sử dụng v&agrave; sửa đổi c&aacute;c v&iacute; dụ đơn giản<br />-&nbsp;<em><strong>Phần mềm MICRESS của h&atilde;ng ACCESS (Đức):</strong></em>&nbsp;m&ocirc; phỏng sự h&igrave;nh th&agrave;nh vi cấu tr&uacute;c dựa tr&ecirc;n dữ liệu nhiệt động<br />-&nbsp;<em><strong>Phần mềm TOPAS Academic của h&atilde;ng Coelho Software (&Uacute;c):</strong></em>&nbsp;cho ph&eacute;p đ&aacute;nh gi&aacute; dữ liệu nhiễu xạ bột tia X v&agrave; neutron (ti&ecirc;u chuẩn v&agrave; thời gian bay) bằng c&aacute;ch sử dụng phương ph&aacute;p tham số cơ bản.<br />-&nbsp;<em><strong>Phần mềm HSC Chemistry h&atilde;ng OUTOTEC (Phần Lan):&nbsp;</strong></em>cho ph&eacute;p t&iacute;nh to&aacute;n trực tiếp c&aacute;c t&iacute;nh chất nhiệt động kh&aacute;c nhau.</p>\r\n<p>&nbsp;</p>\r\n<p><em><strong>Phần mềm&nbsp;Thermo-Calc</strong></em>&nbsp;bao gồm m&ocirc; đun DICTRA v&agrave; TC-PRISMA&nbsp;cho ph&eacute;p sinh vi&ecirc;n l&agrave;m việc độc lập với cơ sở dữ liệu nhiệt động để tạo sơ đồ pha bằng c&aacute;ch sử dụng v&agrave; sửa đổi c&aacute;c v&iacute; dụ đơn giản&nbsp;bao gồm nhiều t&iacute;nh năng như: C&acirc;n bằng pha, dự liệu nhiệt h&oacute;a, nhiệt độ chuyển pha, động lực cho sự biến đổi pha&hellip; Phần mềm&nbsp;chạy trong hệ điều h&agrave;nh&nbsp;Windows hoặc&nbsp;Linux đem lại thao t&aacute;c dễ d&agrave;ng cho người sử dụng.</p>\r\n<p><img src=\"https://www.cic.com.vn/upload_images/images/2020/07/23/1.png\" alt=\"\" /></p>\r\n<p>&nbsp;</p>\r\n<p><em><strong>Phần mềm MICRESS Research TQ</strong></em>&nbsp;m&ocirc; phỏng sự h&igrave;nh th&agrave;nh vi cấu tr&uacute;c dựa tr&ecirc;n dữ liệu nhiệt động,&nbsp;bao gồm c&aacute;c t&iacute;nh nắng t&iacute;nh to&aacute;n sự h&igrave;nh th&agrave;nh cấu tr&uacute;c vi m&ocirc;, ứng suất v&agrave; biến dạng, khuếch t&aacute;n th&agrave;nh phần, ảnh hưởng của d&ograve;ng chảy chất lỏng, sử dụng bộ dữ liệu c&oacute; sẵn tr&ecirc;n thị trường, c&oacute; chức năng m&ocirc; phỏng 3D.</p>\r\n<p><img src=\"https://www.cic.com.vn/upload_images/images/2020/07/23/2.png\" alt=\"\" /></p>\r\n<p>&nbsp;</p>\r\n<p><strong>Phần mềm&nbsp;<em>TOPAS Academic</em></strong>&nbsp;cho ph&eacute;p đ&aacute;nh gi&aacute; dữ liệu nhiễu xạ bột tia X v&agrave; neutron (ti&ecirc;u chuẩn v&agrave; thời gian bay) bằng c&aacute;ch sử dụng phương ph&aacute;p tham số cơ bản, xem hoặc chỉnh sửa cấu tr&uacute;c trong tinh thể học, h&oacute;a học trạng th&aacute;i rắn v&agrave; tối ưu h&oacute;a, ưu ti&ecirc;n cả xem v&agrave; chỉnh sửa, chương tr&igrave;nh Rietveld đầy đủ chức năng, hệ điều h&agrave;nh được hỗ trợ l&agrave; Windows đ&atilde; rất quen thuộc.</p>\r\n<p><img src=\"https://www.cic.com.vn/upload_images/images/2020/07/23/3.png\" alt=\"\" /></p>\r\n<p>&nbsp;</p>\r\n<p><strong>Phần mềm&nbsp;<em>HSC Chemistry&nbsp;</em></strong>cho ph&eacute;p t&iacute;nh to&aacute;n trực tiếp c&aacute;c t&iacute;nh chất nhiệt động kh&aacute;c nhau. Phần mềm thực hiện t&iacute;nh to&aacute;n nhiệt động, &aacute;p dụng l&yacute; thuyết qu&aacute; tr&igrave;nh phức tạp (complex process theory) theo định dạng dễ sử dụng, &aacute;p dụng c&aacute;c ph&eacute;p t&iacute;nh phức tạp trong thời gian ngắn, tất cả c&aacute;c c&ocirc;ng cụ v&agrave; cơ sở dữ liệu m&agrave; người d&ugrave;ng cần trong một g&oacute;i duy nhất, hệ điều h&agrave;nh Windows hoặc Unix dễ d&agrave;ng sử dụng, ưu ti&ecirc;n hỗ trợ c&aacute;c chức năng sau:<br />+ Ph&aacute;t triển c&aacute;c qu&aacute; tr&igrave;nh mới v&agrave; cải thiện c&aacute;c qu&aacute; tr&igrave;nh hiện c&oacute; th&ocirc;ng qua m&ocirc; h&igrave;nh h&oacute;a v&agrave; m&ocirc; phỏng<br />+ Ph&aacute;t triển c&aacute;c m&ocirc; h&igrave;nh process flowsheet v&agrave; thử nghiệm &yacute; tưởng trước khi thử nghiệm ở ph&ograve;ng th&iacute; nghiệm hay chạy th&iacute; điểm<br />+ T&iacute;nh to&aacute;n c&aacute;c vết m&ocirc;i trường (environmental footprint) của c&aacute;c qu&aacute; tr&igrave;nh, để đ&aacute;nh gi&aacute; v&ograve;ng đời</p>\r\n<p><img src=\"https://www.cic.com.vn/upload_images/images/2020/07/23/4.png\" alt=\"\" /></p>\r\n<p>&nbsp;</p>\r\n<p>CIC rất h&acirc;n hạnh v&igrave; đ&atilde; đ&oacute;ng g&oacute;p 1 phần nhỏ trong việc n&acirc;ng cao năng lực đ&agrave;o tạo cho ng&agrave;nh Khoa học Vật liệu của Trường Đại học Việt Đức. CIC c&oacute; hơn 30 năm kinh nghiệm trong cung cấp c&aacute;c giải ph&aacute;p c&ocirc;ng nghệ trong đ&agrave;o tạo như:<br />- C&aacute;c phần mềm v&agrave; thiết bị cho ng&agrave;nh Logistic v&agrave; chuỗi cung ứng<br />- C&aacute;c phần mềm v&agrave; thiết bị cho ng&agrave;nh Khoa học vật liệu<br />- C&aacute;c phần mềm v&agrave; thiết bị cho ng&agrave;nh X&acirc;y dựng, giao th&ocirc;ng<br />- C&aacute;c phần mềm v&agrave; thiết bị cho ng&agrave;nh M&ocirc;i trường, Thủy lợi<br />Vui l&ograve;ng li&ecirc;n hệ ch&uacute;ng t&ocirc;i để được tư vấn giải ph&aacute;p ph&ugrave; hợp nhất.<br />Hotline: 024-3974 1373<br />&nbsp;</p>\r\n<div id=\"eJOY__extension_root\" class=\"eJOY__extension_root_class\" style=\"all: unset;\">&nbsp;</div>','ETABS',NULL,'cic-trung-goi-thau-mua-sam-phan-mem-cho-nganh-khoa-hoc-vat-lieu-cua-truong-dai-hoc-viet-duc','Vật liệu ngày càng đóng vai trò quan trọng trong quá trình đổi mới công nghệ. Đẩy mạnh nghiên cứu, giảng dạy ngành khoa học vật liệu có ý nghĩa hết sức quan trọng, đem lại sự phát triển công nghệ đặc biệt cần thiết cho các nước đang phát triển điển hình như Việt Nam hiện nay. Trường Đại học Việt Đức là một trong những cơ sở nghiên cứu và đào tạo hàng đầu trong lĩnh vực khoa học vật liệu ở Việt Nam','Công ty CIC , GPR','Published',2,NULL,0,0,'2020-10-11 16:27:41','2020-12-10 02:11:49','2020-12-10 02:11:49'),(5,'CIC trúng gói thầu “Cung cấp các Phần mềm Logistics và quản lý chuỗi cung ứng” cho Trung tâm Nghiên cứu giao thông vận tải Việt Đức thuộc Trường ĐH Việt Đức','2020-09-30 23:28:00','1602433769-cic-trung-goi-thau-cung-cap-cac-phan-mem-logistics-va-quan-ly-chuoi-cung-ung-cho-trung-tam-nghien-cuu-giao-thong-van-tai-viet-duc-thuoc-truong-dh-viet-duc.jpg','Logistic và chuỗi cung ứng đang ngày ngày ảnh hưởng đến cuộc sống hiện đại của chúng ta. Ngành Logistics đảm bảo hàng hóa và dịch vụ đến đúng nơi và đúng thời điểm. Các nhà Logistics giám sát vòng đời của sản phẩm, vị trí lưu hàng và trạng thái vận chuyển….Đi đôi với sự phát triển kinh tế và ngoại thương của Việt Nam, nhu cầu về nhân lực ngành Logistics, đặc biệt là nhân lực chất lượng cao ngày càng tăng. Không có Logistics, mọi hoạt động sản xuất, kinh doanh đứng trước nguy cơ bị dừng lại. Chính vì vậy việ','<p>Th&aacute;ng 6/2020, CIC đ&atilde; k&yacute; hợp đồng với Trường Đại học Việt Đức cung cấp Phần mềm Logistics v&agrave; quản l&yacute; chuỗi cung ứng cho Trung t&acirc;m Nghi&ecirc;n cứu giao th&ocirc;ng vận tải Việt Đức bao gồm:<br />- Phần mềm m&ocirc; phỏng hoạt động cảng &ndash; FlexTerm Port Simulation System<br />- Phần mềm m&ocirc; h&igrave;nh h&oacute;a &ndash; GAMS base module + LINDO solver<br />- Phần mềm m&ocirc; phỏng kho h&agrave;ng &ndash; CLASS-Warehouse Simulation.&nbsp;</p>\r\n<p><br /><strong>Phần mềm m&ocirc; phỏng hoạt động cảng &ndash; FlexTerm Port Simulation System</strong>&nbsp;bao gồm nhiều t&iacute;nh năng tiện lợi dễ sử dụng như m&ocirc; phỏng rời rạc, c&aacute;c thị trường sơ cấp Logistics v&agrave; chuối cung ứng, thư vi&ecirc;̣n cho hoạt động của cảng (Library for port operations) được ưu ti&ecirc;n, thư vi&ecirc;̣n cho vận tải đường sắt (rail logistics) được ưu ti&ecirc;n, m&ocirc; hình đ&ocirc;̀ họa, t&ocirc;́i ưu hóa m&ocirc; hình, thi&ecirc;́t k&ecirc;́ thực nghi&ecirc;̣m, tính toán chi phí, hình họa (Animation), hình họa 3D (3D animation), nh&acirc;̣p được các file CAD, ng&ocirc;n ngữ l&acirc;̣p trình JAVA hoặc C hoặc Virtual Logic, hệ điều h&agrave;nh tương thích Windows hoặc iOS hoặc Linux, các phần mềm tương th&iacute;ch để thực hiện c&aacute;c chức năng chuy&ecirc;n dụng: Excel; OptQuest hoặc SQL Database</p>\r\n<p><img src=\"https://www.cic.com.vn/upload_images/images/2020/07/20/2.jpg\" alt=\"\" /><br /><em>M&ocirc; phỏng cảng</em></p>\r\n<p><br /><strong>Phần mềm m&ocirc; h&igrave;nh h&oacute;a (Modelling Software) &ndash; GAMS base module + LINDO Solver</strong>&nbsp;sẵn c&oacute; nhiều chương tr&igrave;nh to&aacute;n học tr&ecirc;n phần mềm như chương trình tuy&ecirc;́n tính (Linear Program &nbsp;solver), chương trình phương trình b&acirc;̣c hai, chương trình phi tuy&ecirc;́n, chương trình mixed integer linear program, chương trình Tối ưu h&oacute;a to&agrave;n cầu,&hellip;v&agrave; nhiều chương tr&igrave;nh tiện &iacute;ch kh&aacute;c, chuy&ecirc;n dụng kh&aacute;c.&nbsp;</p>\r\n<p><img src=\"https://www.cic.com.vn/upload_images/images/2020/07/20/3.png\" alt=\"\" /><img src=\"https://www.cic.com.vn/upload_images/images/2020/07/20/3.png\" alt=\"\" /><br />&nbsp;</p>\r\n<p>Ngo&agrave;i ra Phần mềm c&ograve;n c&oacute; chức năng vẽ biểu đồ, Hệ điều h&agrave;nh tương thích Windows, iOS, Linux.&nbsp;</p>\r\n<p><br /><strong>Phần mềm m&ocirc; phỏng kho hàng (Warehouse Simulation)</strong>&nbsp;được &aacute;p dụng trong lĩnh vực gi&aacute;o dục v&agrave; c&ocirc;ng nghệ. Phần mềm mang lại nhiều t&iacute;nh năng như thư vi&ecirc;̣n v&ecirc;̀ kho/xử l&yacute; vật liệu, t&ocirc;́i ưu hóa m&ocirc; hình, m&ocirc; hình đ&ocirc;̀ họa, thi&ecirc;́t k&ecirc;́ thực nghi&ecirc;̣m, tính toán chi phí, tạo b&aacute;o c&aacute;o tính toán KPI tự động được ưu ti&ecirc;n, đ&aacute;nh gi&aacute; hiệu suất dựa tr&ecirc;n thiết kế kho được ưu ti&ecirc;n, đ&aacute;nh gi&aacute; an to&agrave;n dựa tr&ecirc;n thiết kế kho được ưu ti&ecirc;n, hình họa 3D, nh&acirc;̣p được các file CAD,&hellip;</p>\r\n<p><img src=\"https://www.cic.com.vn/upload_images/images/2020/07/20/4.jpg\" alt=\"mo-phong-kho-hang\" /><br /><em>M&ocirc; phỏng kho h&agrave;ng</em></p>\r\n<p>CIC rất h&acirc;n hạnh v&igrave; đ&atilde; đ&oacute;ng g&oacute;p 1 phần nhỏ trong việc n&acirc;ng cao năng lực đ&agrave;o tạo cho ng&agrave;nh Logistic v&agrave; chuỗi cung ứng của VGU.</p>\r\n<p>CIC c&oacute; hơn 30 năm kinh nghiệm trong cung cấp c&aacute;c giải ph&aacute;p c&ocirc;ng nghệ trong đ&agrave;o tạo như:<br />- C&aacute;c phần mềm v&agrave; thiết bị cho ng&agrave;nh Logistic v&agrave; chuỗi cung ứng<br />- C&aacute;c phần mềm v&agrave; thiết bị cho ng&agrave;nh Khoa học vật liệu<br />- C&aacute;c phần mềm v&agrave; thiết bị cho ng&agrave;nh X&acirc;y dựng, giao th&ocirc;ng<br />- C&aacute;c phần mềm v&agrave; thiết bị cho ng&agrave;nh M&ocirc;i trường, Thủy lợi<br />Vui l&ograve;ng li&ecirc;n hệ ch&uacute;ng t&ocirc;i để được tư vấn giải ph&aacute;p ph&ugrave; hợp nhất.<br />Hotline: 024-3974 1373</p>\r\n<div id=\"eJOY__extension_root\" class=\"eJOY__extension_root_class\" style=\"all: unset;\">&nbsp;</div>','Radar xuyên đất (GPR/GEORADAR)',NULL,'cic-trung-goi-thau-cung-cap-cac-phan-mem-logistics-va-quan-ly-chuoi-cung-ung-cho-trung-tam-nghien-cuu-giao-thong-van-tai-viet-duc-thuoc-truong-dh-viet-duc','Logistic và chuỗi cung ứng đang ngày ngày ảnh hưởng đến cuộc sống hiện đại của chúng ta. Ngành Logistics đảm bảo hàng hóa và dịch vụ đến đúng nơi và đúng thời điểm. Các nhà Logistics giám sát vòng đời của sản phẩm, vị trí lưu hàng và trạng thái vận chuyển….Đi đôi với sự phát triển kinh tế và ngoại thương của Việt Nam, nhu cầu về nhân lực ngành Logistics, đặc biệt là nhân lực chất lượng cao ngày càng tăng. Không có Logistics, mọi hoạt động sản xuất, kinh doanh đứng trước nguy cơ bị dừng lại. Chính vì vậy việ','ETABS, sản phẩm thủy lợi','Published',2,NULL,0,0,'2020-10-11 16:29:29','2020-12-10 02:11:53','2020-12-10 02:11:53'),(6,'CIC cung cấp thiết bị ghi địa chấn 48 kênh SUMMIT X ONE của hãng DMT (Đức) cho Tổng công ty Tư vấn thiết kế GTVT – CTCP (TEDI)','2020-10-13 23:30:00','1602433861-cic-cung-cap-thiet-bi-ghi-dia-chan-48-kenh-summit-x-one-cua-hang-dmt-duc-cho-tong-cong-ty-tu-van-thiet-ke-gtvt-ctcp-tedi.jpg','Vừa qua, CIC cung cấp thiết bị ghi địa chấn 48 kênh Summit X One của hàng DMT (Đức) cho Tổng công ty tư vấn & thiết kế giao thông vận tải – CTCP (TEDI)','<p>Với uy t&iacute;n v&agrave; kinh nghiệm l&acirc;u năm trong lĩnh vực cung cấp phần mềm, thiết bị c&ocirc;ng nghệ cho lĩnh vực giao th&ocirc;ng - x&acirc;y dựng, mới đ&acirc;y, C&ocirc;ng ty CP C&ocirc;ng nghệ v&agrave; Tư vấn CIC đ&atilde; k&yacute; kết hợp đồng cung cấp Thiết bị ghi địa chấn 48 k&ecirc;nh SUMMIT X ONE của h&atilde;ng DMT (Đức) cho Tổng c&ocirc;ng ty Tư vấn Thiết kế GTVT &ndash; CTCP (TEDI). Hệ thống thiết bị được k&yacute; kết bao gồm:</p>\r\n<p>-&nbsp;&nbsp; &nbsp;01 bộ thiết bị ghi địa chấn 48 k&ecirc;nh&nbsp;<br />-&nbsp;&nbsp; &nbsp;01 bộ phần mềm minh giải dữ liệu địa chấn SWAN<br />-&nbsp;&nbsp; &nbsp;01 bộ phần mềm minh giải dữ liệu địa chấn ReflexW 2D/3D</p>\r\n<p><br /><img src=\"https://www.cic.com.vn/upload_images/images/2020/07/17/2.png\" alt=\"summitxone-dmt-1\" /></p>\r\n<p>SUMMIT X One l&agrave; hệ thống thu thập dữ liệu địa chấn linh hoạt, cung cấp giải ph&aacute;p tốt nhất cho c&aacute;c ph&eacute;p đo địa chấn 2D v&agrave; 3D độ ph&acirc;n giải cao ở mọi địa h&igrave;nh.</p>\r\n<p>Ứng dụng:<br />- Khảo s&aacute;t địa chất c&ocirc;ng tr&igrave;nh.<br />- Khảo s&aacute;t địa chất m&ocirc;i trường.<br />- T&igrave;m kiếm thăm d&ograve; dầu kh&iacute;.<br />- T&igrave;m kiếm thăm d&ograve; kho&aacute;ng sản.<br />- Khảo cổ học.<br />Chi tiết th&ocirc;ng tin về&nbsp;<em>Thiết bị&nbsp;ghi địa chấn 48 k&ecirc;nh SUMMIT X ONE của h&atilde;ng DMT</em>, qu&yacute; kh&aacute;ch vui l&ograve;ng tham khảo tại:<br /><a href=\"https://www.cic.com.vn/san-pham/thiet-bi-do-dia-chan-da-kenh-summit-x-p269.html\">https://www.cic.com.vn/san-pham/thiet-bi-do-dia-chan-da-kenh-summit-x-p269.html</a></p>\r\n<p><img src=\"https://www.cic.com.vn/upload_images/images/2020/07/17/1.png\" alt=\"summitxone-dmt-2\" /></p>\r\n<p><em><strong>C&ocirc;ng ty CP C&ocirc;ng nghệ v&agrave; Tư vấn CIC</strong></em>&nbsp;ph&acirc;n phối đầy đủ v&agrave; đa dạng c&aacute;c giải ph&aacute;p thiết bị đo địa chấn từ c&aacute;c h&atilde;ng cung cấp uy t&iacute;n v&agrave; nổi tiếng tr&ecirc;n thế giới như: DMT (Đức), Geotomographie (Đức), OYO (Nhật), IRIS (Ph&aacute;p),...<br />Ch&uacute;ng t&ocirc;i xin ch&acirc;n th&agrave;nh cảm ơn Qu&yacute; Kh&aacute;ch h&agrave;ng tin tưởng v&agrave; trao cơ hội hợp t&aacute;c!</p>\r\n<p>&nbsp;</p>\r\n<p>Mọi th&ocirc;ng tin xin vui l&ograve;ng li&ecirc;n hệ:<br />Trung t&acirc;m Giải ph&aacute;p Phần mềm v&agrave; Thiết bị C&ocirc;ng nghệ<br />Hotline: 024-3974 1373</p>\r\n<div id=\"eJOY__extension_root\" class=\"eJOY__extension_root_class\" style=\"all: unset;\">&nbsp;</div>','ETABS',NULL,'cic-cung-cap-thiet-bi-ghi-dia-chan-48-kenh-summit-x-one-cua-hang-dmt-duc-cho-tong-cong-ty-tu-van-thiet-ke-gtvt-ctcp-tedi','Vừa qua, CIC cung cấp thiết bị ghi địa chấn 48 kênh Summit X One của hàng DMT (Đức) cho Tổng công ty tư vấn & thiết kế giao thông vận tải – CTCP (TEDI)','ETABS, sản phẩm thủy lợi','Published',2,NULL,1,0,'2020-10-11 16:31:01','2020-12-10 02:12:01','2020-12-10 02:12:01'),(7,'Glodon Vietnam tổ chức Cuộc thi BIM dành cho QS tại Việt Nam 2020','2020-10-08 23:36:00','1606813636-glodon-vietnam-to-chuc-cuoc-thi-bim-danh-cho-qs-tai-viet-nam-2020.jpg','Nhằm thúc đẩy việc ứng dụng BIM trong xây dựng tại Việt Nam, vào tháng 7 này, Glodon Vietnam sẽ tổ chức cuộc thi BIM dành cho QS lần đầu tiên ở Việt Nam năm 2020. Đây là cuộc thi có tính chuyên môn cao, khai thác trên nền tảng phần mềm Cubicost, với giá trị mỗi giải thưởng lên tới hơn 2000 USD.','<h2><strong>Điều kiện tham gia:</strong></h2>\r\n<p>Tham gia theo đội 2 người, th&agrave;nh vi&ecirc;n l&agrave; Kỹ sư QS hoặc Sinh vi&ecirc;n/Giảng vi&ecirc;n c&oacute; chuy&ecirc;n ng&agrave;nh li&ecirc;n quan đến b&oacute;c t&aacute;ch khối lượng d&acirc;n dụng Đăng k&yacute; tham gia qua đường link:&nbsp;</p>\r\n<p><a href=\"https://register.gotowebinar.com/register/151663743160342799?source=C\">https://register.gotowebinar.com/register/151663743160342799?source=C</a></p>\r\n<p><img src=\"https://www.cic.com.vn/upload_images/images/2020/07/13/1.jpg\" alt=\"Co_cau_giai_thuong_BIM_Cubicost\" /></p>\r\n<h2><strong>Cơ cấu giải thưởng</strong></h2>\r\n<p><em>1 Giải nhất:</em>&nbsp;Trị gi&aacute; 2000 USD TIỀN MẶT v&agrave; 2 bộ phần mềm Cubicost (bao gồm TASC-II/TRBC-II) c&oacute; gi&aacute; trị trong v&ograve;ng 1 năm</p>\r\n<p><em>2 Giải nh&igrave;:</em>&nbsp;Trị gi&aacute; 1000 USD TIỀN MẶT v&agrave; 1 bộ phần mềm Cubicost (bao gồm TASC-II/TRBC-II) c&oacute; gi&aacute; trị trong v&ograve;ng 1 năm</p>\r\n<p><em>3 Giải ba:&nbsp;</em>Trị gi&aacute; 500 USD TIỀN MẶT v&agrave; 1 bộ phần mềm Cubicost (bao gồm TASC-II/TRBC-II) c&oacute; gi&aacute; trị trong v&ograve;ng 6 th&aacute;ng</p>\r\n<h2><strong>Cơ cấu đ&aacute;nh gi&aacute;</strong></h2>\r\n<p><strong><img src=\"https://www.cic.com.vn/upload_images/images/2020/07/13/2.jpg\" alt=\"the_le_cuoc_thi_BIM_Cubicost\" /></strong></p>\r\n<h2><strong>Về Cubicost</strong></h2>\r\n<p>Phần mềm BIM Cubicost l&agrave; bộ phần mềm b&oacute;c t&aacute;ch khối lượng tr&ecirc;n nền tảng BIM, đ&atilde; đạt được chứng chỉ chuẩn đầu ra, đầu v&agrave;o IFC của Building Smart. Bộ phần mềm BIM Cubicost bao gồm bốn phần mềm ri&ecirc;ng biệt tr&ecirc;n tr&ecirc;n nền tảng BIM (TASC, TRBC, TME, TBQ), tập trung v&agrave;o c&aacute;c nhu cầu kh&aacute;c nhau của c&ocirc;ng việc b&oacute;c t&aacute;ch v&agrave; xử l&yacute; khối lượng. Tất cả bốn phần mềm n&agrave;y đem lại hầu như tất cả c&aacute;c y&ecirc;u cầu chung của c&ocirc;ng việc dự to&aacute;n chi ph&iacute; x&acirc;y dựng. Phần mềm Cubicost đ&atilde; được tin d&ugrave;ng ở rất nhiều nước trong khu vực Đ&ocirc;ng Nam &Aacute; như Singapore, Malaysia, Phillipine, Th&aacute;i Lan v&agrave; Việt Nam.<br />Th&ocirc;ng tin chi tiết về Cubicost tại website:&nbsp;<a href=\"https://cubicost.cic.com.vn/\">https://cubicost.cic.com.vn/</a></p>\r\n<p>&nbsp;</p>\r\n<p><em>Mọi thắc mắc xin vui l&ograve;ng li&ecirc;n hệ<br />Email: hoanglinh@cic.com.vn<br />Điện thoại: 097 384 6357</em></p>\r\n<div id=\"eJOY__extension_root\" class=\"eJOY__extension_root_class\" style=\"all: unset;\">&nbsp;</div>','Test',NULL,'glodon-vietnam-to-chuc-cuoc-thi-bim-danh-cho-qs-tai-viet-nam-2020','Nhằm thúc đẩy việc ứng dụng BIM trong xây dựng tại Việt Nam, vào tháng 7 này, Glodon Vietnam sẽ tổ chức cuộc thi BIM dành cho QS lần đầu tiên ở Việt Nam năm 2020. Đây là cuộc thi có tính chuyên môn cao, khai thác trên nền tảng phần mềm Cubicost, với giá trị mỗi giải thưởng lên tới hơn 2000 USD.','ETABS, sản phẩm thủy lợi','Published',2,NULL,1,0,'2020-10-11 16:37:42','2020-12-10 02:12:04','2020-12-10 02:12:04'),(8,'Gỗ công nghiệp','2020-10-12 08:54:00','1606813508-go-cong-nghiep.jpg','Gỗ công nghiệp - Sản phẩm công nghiệp','<p>C&aacute;c loại gỗ c&ocirc;ng nghiệp được d&ugrave;ng cho đồ gỗ nội thất</p>\r\n<p>Thị trường Việt Nam, đồ gỗ nội thất được l&agrave;m từ 6 loại gỗ c&ocirc;ng nghiệp chiếm ưu thế vượt trội về chất lượng v&agrave; số lượng, đ&aacute;ng ch&uacute; &yacute; gồm MFC, MDF v&agrave; HDF. 3&nbsp;loại gỗ c&ograve;n lại&nbsp;bao gồm: Gỗ Plywood, Gỗ gh&eacute;p thanh v&agrave; V&aacute;n gỗ nhựa. Cả 6 loại đều c&oacute; những t&iacute;nh chất v&agrave; c&aacute;c đặc điểm kh&aacute;c nhau ph&ugrave; hợp với nhiều y&ecirc;u cầu của kh&aacute;ch h&agrave;ng. Th&ocirc;ng tin chi tiết về từng loại:</p>\r\n<div id=\"eJOY__extension_root\" class=\"eJOY__extension_root_class\" style=\"all: unset;\">&nbsp;</div>',NULL,NULL,'go-cong-nghiep','Tesst',NULL,'Published',1,NULL,1,0,'2020-10-12 01:55:22','2020-12-01 02:05:46','2020-12-01 02:05:46'),(9,'1. Gỗ công nghiệp MFC – Melamine Faced Chipboard','2020-10-12 08:56:00','1602467811-1-go-cong-nghiep-mfc-melamine-faced-chipboard.jpg','1. Gỗ công nghiệp MFC – Melamine Faced Chipboard','<ol>\r\n<li>Gỗ c&ocirc;ng nghiệp MFC &ndash; Melamine Faced Chipboard loại gỗ tốt nhất thị trường.</li>\r\n</ol>',NULL,NULL,'1-go-cong-nghiep-mfc-melamine-faced-chipboard',NULL,NULL,'Published',1,NULL,1,0,'2020-10-12 01:56:51','2020-12-01 02:06:32','2020-12-01 02:06:32'),(10,'8 loại vật liệu thông dụng dùng cho thiết kế và sản xuất đồ trang trí','2020-11-24 16:07:00','1607592191-8-loai-vat-lieu-thong-dung-dung-cho-thiet-ke-va-san-xuat-do-trang-tri.jpg','Hãy cùng Nghenoithat.vn điểm lại 8 loại vật liệu thông dụng dùng cho thiết kế và sản xuất đồ trang trí nội thất và ngoại thất chung cư, biệt thự và nhà phố:','<h2 style=\"text-align: justify;\"><strong><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">1. Gỗ tự nhi&ecirc;n &ndash; loại vật liệu l&acirc;u đời:</span></strong></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Đ&acirc;y l&agrave; loại vật l&agrave; loại vật liệu đầu ti&ecirc;n trong danh s&aacute;ch v&agrave; c&oacute; lẽ cũng l&agrave; loại vật liệu x&acirc;y dựng cổ nhất đến n&agrave;y vẫn c&ograve;n được sử dụng. Kh&ocirc;ng phải ngẫu nhi&ecirc;n m&agrave; gỗ tự nhi&ecirc;n được sử dụng nhiều v&agrave; l&acirc;u đến thế. B&agrave;n, ghế, giường, tủ&hellip; Những đồ nội thất l&agrave;m bằng đồ gỗ tự nhi&ecirc;n lu&ocirc;n c&oacute; sức h&uacute;t kỳ lạ đối với ch&uacute;ng ta. Hiện nay từ phong c&aacute;ch cổ điển đến hiện đại c&aacute;c kiến tr&uacute;c sư đều rất ưa th&iacute;ch sử dụng gỗ tự nhi&ecirc;n để tạo điểm nhấn.</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">C&aacute;c loại gỗ tự nhi&ecirc;n cổ truyền của ch&uacute;ng ta gồm c&oacute;: Sến, T&aacute;u, Đinh, Lim, Hương, Trắc, Cẩm&hellip; những loại gỗ n&agrave;y thường rất bền v&agrave; đẹp nhưng gi&aacute; th&agrave;nh cũng rất cao. Gần đ&acirc;y ta c&ograve;n thấy xuất hiện một số loại gỗ nhập khẩu như gỗ Sồi, &Oacute;c Ch&oacute;, Bạch Dương&hellip; Những loại gỗ n&agrave;y c&oacute; vấn rất đẹp bền chắc nhưng gi&aacute; th&agrave;nh cũng kh&ocirc;ng hề rẻ v&agrave; thường được sử dụng l&agrave;m nội thất trang c&aacute;c c&ocirc;ng tr&igrave;nh cao cấp hoặc c&aacute;c gia đ&igrave;nh c&oacute; điều kiện.</span></p>\r\n<p style=\"text-align: justify;\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/FZaQ2PK81tZUcMPeOC4JQwZmbZuGwpbbBfsjnlaT.jpeg\" alt=\"vat-lieu-go\" width=\"600\" height=\"400\" /><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Để đ&aacute;p ứng nhu cầu sử dụng gỗ tự nhi&ecirc;n l&agrave;m đồ nội thất th&igrave; hiện nay tr&ecirc;n thị trường c&ograve;n c&oacute; 2 loại gỗ rất phổ biến v&agrave; được ưa chuộng đ&oacute; l&agrave; gỗ th&ocirc;ng v&agrave; gỗ teak. Hai lại loại gỗ n&agrave;y đều cho v&acirc;n gỗ rất đẹp m&agrave;u sắc tươi. Gi&aacute; th&agrave;nh của 2 loại gỗ n&agrave;y th&igrave; đều ở mức vừa phải dễ chịu kh&ocirc;ng qu&aacute; cao như những loại gỗ ở tr&ecirc;n n&ecirc;n được y&ecirc;u th&iacute;ch sử dụng rất nhiều.</span></p>\r\n<h2 style=\"text-align: justify;\"><br /><strong><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">2. Gỗ c&ocirc;ng nghiệp Laminate:</span></strong></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Được xếp v&agrave;o loại vật liệu phủ bề mặt l&ecirc;n gỗ c&ocirc;ng nghiệp, laminate l&agrave; loại vật liệu nội thất phổ biến v&agrave; đang được rất nhiều nh&agrave; thiết kế lựa chọn.</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Cấu tạo của laminate bao gồm nhiều lớp xếp chồng l&ecirc;n nhau, được li&ecirc;n kết bằng keo d&aacute;n gỗ cao cấp melamine, &eacute;p ở nhiệt độ v&agrave; &aacute;p suất rất cao.</span></p>\r\n<p><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/yfm3CnaCg7Idh1oITp3Ng7OOZ3IeTR4oAbSD6pbk.jpeg\" alt=\"\" width=\"600\" height=\"400\" /></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">C&aacute;c loại cốt gỗ thường d&ugrave;ng để d&aacute;n laminate l&agrave; gỗ MDF, gỗ HDF (c&oacute; thể t&ugrave;y chọn loại kh&aacute;ng ẩm hoặc kh&ocirc;ng). Bề mặt sản phẩm laminate c&oacute; nhiều loại: mặt mờ, mịn, xước, v&acirc;n nổi, sần, gương b&oacute;ng&hellip;</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">C&aacute;c sản phẩm nội thất đ&oacute;ng bằng gỗ laminate thường theo xu thế hiện đại, c&oacute; độ bền cao, chống va đập cũng như chống trầy xước rất tốt. </span><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Đ&acirc;y l&agrave; loại vật liệu hiện đang được sử dụng rất nhiều trong c&aacute;c căn hộ chung cư tầm trung để l&agrave;m b&agrave;n bếp, tủ bếp tử quần &aacute;o, s&agrave;n gỗ&hellip;</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Ưu điểm lớn nhất của gỗ c&ocirc;ng nghiệp Laminate l&agrave; c&oacute; khả năng kh&aacute;ng nước v&agrave; gi&aacute; th&agrave;nh lại rất rẻ. Một điểm nữa l&agrave; ta c&oacute; thể thỏa th&iacute;ch lựa chọn m&agrave;u sắc v&agrave; c&aacute;c loại v&acirc;n.</span></p>\r\n<h2 style=\"text-align: justify;\"><br /><strong><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">3. K&iacute;nh &ndash; vật liệu hiện đại:</span></strong></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Vật liệu k&iacute;nh đ&atilde; rất quen thuộc trong thiết kế nội thất biệt thự, chung cư, nh&agrave; phố hiện nay. Ưu điểm của loại vật liệu n&agrave;y l&agrave; khả năng ph&ugrave; hợp với tất cả c&aacute;c phong c&aacute;ch thiết kế t&acirc;y, ta từ cổ điển đến hiện đại.</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">K&iacute;nh được sử dụng trong nội thất thường c&oacute; 2 loại k&iacute;nh cường lực v&agrave; k&iacute;nh d&aacute;n. 2 loại k&iacute;nh n&agrave;y đều c&oacute; thể lựa chọn loại c&oacute; nhiều lớp v&agrave; nhiều m&agrave;u sắc kh&aacute;c nhau.</span></p>\r\n<p style=\"text-align: justify;\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/zwBLO66flgQ4rxEHYFVCkaXuvQComSbDggtSe1nO.jpeg\" alt=\"\" width=\"600\" height=\"400\" /><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">V&igrave; gần như đ&atilde; qu&aacute; phổ biến n&ecirc;n gi&aacute; th&agrave;nh của loại vẫn liệu n&agrave;y cũng kh&ocirc;ng c&ograve;n qu&aacute; cao ngoại trừ một số loại đặc biệt. Một điểm m&agrave; loại vật liệu n&agrave;y được y&ecirc;u th&iacute;ch nhất c&oacute; lẽ l&agrave; độ bền. Về độ bền của k&iacute;nh th&igrave; gần như l&agrave; vĩnh cửu. Chả thể m&agrave; c&oacute; c&acirc;u &ldquo;nh&agrave; hỏng, k&iacute;nh chưa hỏng&rdquo;.</span></p>\r\n<h2 style=\"text-align: justify;\"><br /><strong><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">4. Đ&aacute; Granite (đ&aacute; hoa cương):</span></strong></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Đ&acirc;y l&agrave; một loại vật liệu được sử dụng ở gần như mọi c&ocirc;ng tr&igrave;nh từ bậc cầu thang, mặt b&agrave;n bếp, mặt b&agrave;n l&agrave;m việc, quầy bar, ốp s&agrave;n. Đặc điểm của loại vật liệu n&agrave;y l&agrave; độ b&oacute;ng, rất cứng chắc, bền bỉ Khi sử dụng tạo n&ecirc;n độ s&aacute;ng v&agrave; hiện đại cho ng&ocirc;i nh&agrave;. Ch&iacute;nh đặc điểm n&agrave;y n&ecirc;n đ&aacute; Granite cũng lu&ocirc;n được sử dụng rất nhiều.</span></p>\r\n<p style=\"text-align: justify;\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/mF07V9AasA7oHsyGradsPh4Cwhp43xQUPnWsJvD9.jpeg\" alt=\"vat-lieu-da-hoa-cuong\" width=\"600\" height=\"450\" /><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Đ&aacute; Granite thường c&oacute; gi&aacute; kh&aacute; cao n&ecirc;n chỉ được sử dụng ở một số vị tr&iacute; đặc biệt để tạo điểm nhấn nếu muốn sử dụng nhiều th&igrave; bạn phải chấp nhận bỏ ra một số tiền kha kh&aacute;.</span></p>\r\n<h2 style=\"text-align: justify;\"><br /><strong><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">5. Đ&aacute; Marble (đ&aacute; cẩm thạch)</span></strong></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Đ&aacute; Marble l&agrave; một trong những vật liệu trang tr&iacute; nội thất mới được nhiều người sử dụng. Loại vật liệu mới n&agrave;y gi&uacute;p ng&ocirc;i nh&agrave; trở n&ecirc;n tinh tế, sang trọng, cũng như mang đến sự tho&aacute;ng đ&atilde;ng, m&aacute;t mẻ trong m&ugrave;a h&egrave;.</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Ưu điểm nổi bật của đ&aacute; Marble ch&iacute;nh l&agrave; những đường v&acirc;n mềm mại với n&eacute;t hoa văn độc đ&aacute;o tr&ecirc;n mặt đ&aacute;. Đặc biệt, đ&aacute; marble rất kh&oacute; thi c&ocirc;ng do dễ vỡ, v&igrave; vậy đ&ograve;i hỏi người thợ phải l&agrave;nh nghề.</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Thực sự để c&oacute; thể sử dụng loại vật liệu n&agrave;y gia chủ phải l&agrave; người chịu chi vỉ muốn sử dụng đ&aacute; Marble để trang tr&iacute; nội thất ngo&agrave;i gi&aacute; th&agrave;nh của bản th&acirc;n vật liệu đ&atilde; cao m&agrave; c&ograve;n cần thợ thi c&ocirc;ng l&agrave;nh nghề v&agrave; c&oacute; b&agrave;n tay kh&eacute;o l&eacute;o.</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">V&iacute; l&yacute; do n&agrave;y m&agrave; đ&aacute; Marble thường chỉ sử dụng trong c&aacute;c căn biệt thự hoặc những khu chung cư cao cấp.</span></p>\r\n<h2 style=\"text-align: justify;\"><br /><strong><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">6. Tấm thạch cao 3D</span></strong></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Những tấm thạch cao 3D n&agrave;y rất được c&aacute;c kiến tr&uacute;c sư v&agrave; chủ nh&agrave; y&ecirc;u th&iacute;ch sử dụng để ốp trần. Bạn c&oacute; thể thoải m&aacute;i lựa chọn hoa văn, họa tiết của tấm. Đ&acirc;y cũng ch&iacute;nh l&agrave; ưu điểm của loại vật liệu n&agrave;y. Ngo&agrave;i ra với phần xương cố định được l&agrave;m bằng sợi thủy tinh đảm bảo độ bền cho vật liệu.</span></p>\r\n<p style=\"text-align: justify;\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/MkpbsWnzEW8QIjvG1adUFs00IctBloL005woSnI0.jpeg\" alt=\"\" width=\"600\" height=\"450\" /><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Chỉ cần kết hợp kh&eacute;o l&eacute;o tấm thạch cao n&agrave;y với hệ thống đ&egrave;n chiếu s&aacute;ng v&agrave; đ&egrave;n trang tr&iacute; l&agrave; ta đ&atilde; c&oacute; một trần nh&agrave; kh&ocirc;ng những đẹp m&agrave; c&ograve;n v&ocirc; c&ugrave;ng độc đ&aacute;o.</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Một điểm cộng nữa l&agrave; gi&aacute; th&agrave;nh của loại vật liệu n&agrave;y cũng kh&ocirc;ng qu&aacute; đắt rất ph&ugrave; hợp với t&uacute;i tiền của đa số người Việt.</span></p>\r\n<h2 style=\"text-align: justify;\"><br /><strong><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">7. Th&eacute;p kh&ocirc;ng gỉ</span></strong></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Th&eacute;p l&agrave; loại vật liệu nội thất c&oacute; nhiều t&aacute;c dụng tuyệt vời c&oacute; thể sử dụng được ở nhiều vị tr&iacute; kh&aacute;c nhau như cầu thang, lan can ban c&ocirc;ng, hay thậm ch&iacute; l&agrave; b&agrave;n, ghế, x&iacute;ch đu.</span></p>\r\n<p style=\"text-align: justify;\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/QUHm2IUlqLj3OfDsOU3D5hxLVXhMZAvww3tSnKa4.jpeg\" alt=\"\" width=\"600\" height=\"450\" /><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Sử dụng vật liệu tạo n&ecirc;n phong c&aacute;ch hiện đại cho kh&ocirc;ng gian hơn với những ai th&iacute;ch sự chắc chắn, th&ocirc; cứng th&igrave; chắc chắn kh&ocirc;ng thể bỏ qua loại vật liệu n&agrave;y. Tuy vậy vật liệu n&agrave;y chưa thực sự được sử dụng nhiều ở nước ta m&agrave; mới chỉ bước đầu dừng lại ở việc l&agrave;m đồ đạc, trang tr&iacute;. Hi vọng sang năm 2020 n&oacute; sẽ được sử dụng nhiều hơn.</span></p>\r\n<h2 style=\"text-align: justify;\"><br /><strong><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">8. Tấm ốp giả da</span></strong></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Đ&acirc;y l&agrave; c&aacute;c tấm trang tr&iacute; được l&agrave;m giả v&acirc;n da. Loại vật liệu n&agrave;y thường được sử dụng trong nh&agrave; nh&agrave; tắm. ph&ograve;ng bếp, ốp tường ph&ograve;ng kh&aacute;ch hoặc ph&ograve;ng ngủ.</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Khi sử dụng c&aacute;c tấm giả da n&agrave;y kh&ocirc;ng gian sẽ trở n&ecirc;n sang trọng n&ecirc;n rất nhiều. Một đặc điểm rất nổi bật của c&aacute;c tấm giả da l&agrave; ch&uacute;ng được l&agrave;m từ cao su n&ecirc;n rất dễ lau ch&ugrave;i, l&agrave;m sạch.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>','8 loại vật liệu thông dụng dùng cho thiết kế và sản xuất đồ trang trí',NULL,'8-loai-vat-lieu-thong-dung-dung-cho-thiet-ke-va-san-xuat-do-trang-tri','8 loại vật liệu thông dụng dùng cho thiết kế và sản xuất đồ trang trí nội thất và ngoại thất chung cư, biệt thự và nhà phố','vật liệu nội thất, vật liệu xây dựng','Published',2,NULL,1,0,'2020-12-01 02:08:12','2020-12-10 02:31:15',NULL),(11,'Partical board là gì? Tất cả những điều cần biết','2020-12-01 08:51:00','1607651665-partical-board-la-gi-tat-ca-nhung-dieu-can-biet.jpg','Bạn đang có ý định mua một loại ván gỗ công nghiệp để sử dụng cho công trình nhà mình. Nhưng có quá nhiều loại ván gỗ công nghiệp khiến bạn không biết lựa chọn loại nào. Bạn hoang mang không hiểu Particle Board là gì và chúng có bao nhiêu loại. Hãy cùng theo dõi bài viết dưới đây để tìm hiểu về những loại Particle Board đang rất được ưa chuộng nhé!','<h2><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>Particle Board l&agrave; g&igrave;?</strong></span></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Đ&acirc;y l&agrave; một loại vật liệu x&acirc;y dựng hay thường được gọi l&agrave; v&aacute;n Okal. Đ&acirc;y l&agrave; một loại v&aacute;n gỗ được sản xuất nh&acirc;n tạo dựa tr&ecirc;n những nguy&ecirc;n liệu như gỗ rừng (gỗ cao su, gỗ bạch đ&agrave;n, &hellip;). Những cốt gỗ từ c&acirc;y gỗ trồng được đưa v&agrave;o m&aacute;y nghiền n&aacute;t th&agrave;nh dăm. Sau đ&oacute; được trộn với keo v&agrave; được đem đi &eacute;p lại theo những ti&ecirc;u chuẩn, độ d&agrave;y kh&aacute;c nhau.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Ch&uacute;ng ta c&oacute; thể dễ d&agrave;ng nhận biết được loại v&aacute;n n&agrave;y được ứng dụng trong cuộc sống. Particle Board c&oacute; bề ngo&agrave;i được phủ một lớp&nbsp;<a href=\"https://dongsuh.vn/blogs/tin-tuc-noi-that/go-melanime-la-gi-va-nhung-dieu-can-biet-ve-loai-go-cong-nghiep-dac-biet-nay\" target=\"_blank\" rel=\"noopener noreferrer\">Melamine</a>&nbsp;hay&nbsp;<a href=\"https://dongsuh.vn/blogs/cam-nang-trang-tri/go-acrylic-la-gi-nhung-dieu-ban-nen-biet-ve-loai-go-duoc-yeu-thich-hien-nay\" target=\"_blank\" rel=\"noopener noreferrer\">Acrylic</a>&nbsp;nhưng khi b&oacute;c ra sẽ lộ những dăm gỗ đ&atilde; nghiền n&aacute;t. Th&ocirc;ng thường ta sẽ nh&igrave;n thấy Particle Board c&oacute; m&agrave;u của gỗ như v&agrave;ng, n&acirc;u v&agrave; loại v&aacute;n chống ẩm th&igrave; thường c&oacute; m&agrave;u xanh.</span></p>\r\n<p><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/ljW7VcE31kCK5fEmZ2NsSFFh0hvPOPlLi6WenMEO.jpeg\" alt=\"\" width=\"600\" height=\"600\" /></p>\r\n<h2 style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Đặc điểm của&nbsp;Particle Board</span></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Trước hết l&agrave; về ưu điểm của v&aacute;n Particle Board. Loại v&aacute;n n&agrave;y so với c&aacute;c loại v&aacute;n d&aacute;n hay v&aacute;n MDF thường c&oacute; gi&aacute; th&agrave;nh thấp hơn, vừa với t&uacute;i tiền người mua v&agrave; mục đ&iacute;ch sử dụng. Lớp giữa được cấu tạo từ dăm gỗ n&ecirc;n c&oacute; độ cứng nhất định v&agrave; độ bền kh&aacute; cao. Đồng thời, n&oacute; c&oacute; khả năng b&aacute;m ốc v&iacute;t rất tốt, rất tiện lợi trong qu&aacute; tr&igrave;nh thi c&ocirc;ng.&nbsp;</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">B&ecirc;n cạnh đ&oacute;, ta thấy một số nhược điểm của Particle Board như khả năng chịu trọng tải k&eacute;m hơn so với c&aacute;c loại v&aacute;n kh&aacute;c. Đ&acirc;y l&agrave; yếu tố cần c&acirc;n nhắc khi bạn mua v&aacute;n Particle Board để sử dụng v&agrave;o việc g&igrave;. Do c&oacute; cấu tạo từ c&aacute;c dăm gỗ n&ecirc;n khi tiến h&agrave;nh cắt v&aacute;n kh&eacute;o l&eacute;o đến đ&acirc;u th&igrave; vẫn sẽ bị mẻ, tạo thẩm mỹ kh&ocirc;ng tốt n&ecirc;n ta tốn chi ph&iacute; bọc lại. Tuổi thọ nh&igrave;n chung thấp hơn so với c&aacute;c loại v&aacute;n &eacute;p c&ocirc;ng nghiệp kh&aacute;c.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<h2 style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>Ứng dụng của v&aacute;n Particle Board</strong></span></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Trong cuộc sống thường ng&agrave;y ta c&oacute; thể dễ d&agrave;ng thấy được&nbsp;ứng dụng v&aacute;n Particle Board. Sau khi tr&aacute;ng c&aacute;c bề mặt trang tr&iacute; c&oacute; họa tiết giả v&acirc;n gỗ, ch&uacute;ng được sử dụng nhiều trong việc thiết kế v&agrave; sản xuất đồ nội thất.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Đối với cốt dăm gỗ kh&ocirc;ng chống ẩm th&igrave; sản phẩm nội thất thường được để ở nơi kh&ocirc; r&aacute;o, tho&aacute;ng đ&atilde;ng v&agrave; c&oacute; &aacute;nh s&aacute;ng, &iacute;t tiếp x&uacute;c với nước. V&iacute; dụ như b&agrave;n l&agrave;m việc, b&agrave;n ghế văn ph&ograve;ng, tủ quần &aacute;o, kệ trang tr&iacute;, &hellip;</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">C&ograve;n đối với cốt dăm gỗ c&oacute; khả năng chống ẩm th&igrave; được ứng dụng rộng r&atilde;i hơn ở nhiều m&ocirc;i trường hơn. V&iacute; dụ như tủ &acirc;m tường, cửa ph&ograve;ng ra v&agrave;o, kệ bếp, &hellip; Tuy nhi&ecirc;n, ta cũng kh&ocirc;ng n&ecirc;n để ch&uacute;ng tiếp x&uacute;c với qu&aacute; nhiều nước trong thời gian d&agrave;i. Bởi cốt của v&aacute;n dăm l&agrave; gỗ nghiền nền c&oacute; thể ngấm nước hoặc bở ra, g&acirc;y hỏng h&oacute;c sản phẩm.</span></p>\r\n<div id=\"eJOY__extension_root\" class=\"eJOY__extension_root_class\" style=\"all: unset;\">&nbsp;</div>','Partical board là gì? Tất cả những điều cần biết',NULL,'partical-board-la-gi-tat-ca-nhung-dieu-can-biet','Bạn đang có ý định mua một loại ván gỗ công nghiệp để sử dụng cho công trình nhà mình. Nhưng có quá nhiều loại ván gỗ công nghiệp khiến bạn không biết lựa chọn loại nào. Bạn hoang mang không hiểu Particle Board là gì và chúng có bao nhiêu loại. Hãy cùng theo dõi bài viết dưới đây để tìm hiểu về những loại Particle Board đang rất được ưa chuộng nhé!','nội thất gỗ, particle board, gỗ công nghiệp','Published',2,NULL,0,1100,'2020-12-10 18:54:25','2020-12-13 09:21:05',NULL),(12,'Gỗ MDF là gì?','2020-12-02 09:07:00','1607653100-go-mdf-la-gi.jpg','Trong thế giới các sản phẩm nội thất, có lẽ phổ biến nhất chính là các sản phẩm từ gỗ ván MDF. Vậy gỗ MDF là gi? Đặc điểm ra sao? Và vì sao chúng lại phổ biển tới vậy? Hãy cùng nghenoithat.vn tìm hiểu trong bài viết dưới đây','<h2 style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>MDF l&agrave; g&igrave;?</strong></span></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">MDF l&agrave; t&ecirc;n viết tắt của cụm từ&nbsp;<a href=\"https://en.wikipedia.org/wiki/Medium-density_fibreboard\" target=\"_blank\" rel=\"noopener noreferrer\">Medium Density Fiberboard</a>, tức l&agrave; một loại gỗ &eacute;p c&ocirc;ng nghiệp. Loại gỗ n&agrave;y được sản xuất từ qu&aacute; tr&igrave;nh li&ecirc;n kết c&aacute;c sợi gỗ bằng keo tổng hợp. Th&agrave;nh phần ch&iacute;nh của lớp cốt gỗ trong tấm&nbsp;gỗ MDF&nbsp;l&agrave; c&aacute;c sợi gỗ được lấy từ c&aacute;c loại gỗ mềm. Ngo&agrave;i ra c&ograve;n c&oacute; c&aacute;c th&agrave;nh phần gỗ cứng kh&aacute;c.&nbsp;</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">C&oacute; hai quy tr&igrave;nh sản xuất&nbsp;gỗ MDF &eacute;p&nbsp;th&ocirc;ng thường l&agrave; sản xuất kh&ocirc; v&agrave; sản xuất ướt. T&ugrave;y v&agrave;o ứng dụng v&agrave; mong muốn của kh&aacute;ch h&agrave;ng m&agrave; nh&agrave; sản xuất sẽ c&oacute; quy tr&igrave;nh sản xuất sản phẩm ph&ugrave; hợp. Hiện nay, người ta đ&atilde; ph&aacute;t triển c&ocirc;ng nghệ kiểm so&aacute;t độ ẩm trong tấm gỗ MDF gi&uacute;p cho khả năng ứng dụng v&agrave; mức độ ưa chuộng được tăng cao.</span></p>\r\n<h2 style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Ưu nhược điểm của gỗ &eacute;p MDF</span></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Tấm gỗ MDF c&oacute; thể đem lại nhiều ưu điểm hơn tấm v&aacute;n dăm m&agrave; ta c&oacute; thể thấy được. Trước hết l&agrave; gi&aacute; th&agrave;nh của tấm&nbsp;v&aacute;n gỗ c&ocirc;ng nghiệp&nbsp;thấp hơn rất nhiều so với gỗ tự nhi&ecirc;n m&agrave; chất lượng lại kh&ocirc;ng hề thua k&eacute;m. Hơn nữa, gỗ MDF c&ograve;n kh&ocirc;ng bị cong v&ecirc;nh, hay mối mọt như gỗ tự nhi&ecirc;n. Bề mặt của tấm MDF bằng phẳng đem lại nhiều c&ocirc;ng dụng.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Hơn thế, qu&aacute; tr&igrave;nh sản xuất một tấm MDF kh&aacute; nhanh ch&oacute;ng n&ecirc;n c&oacute; thể cung cấp một số lượng lớn sản phẩm nếu cần. Bề mặt phẳng của n&oacute; gi&uacute;p ch&uacute;ng ta c&oacute; thể sơn, vẽ hay phủ những lớp hoa văn trang tr&iacute; như v&acirc;n gỗ, tạo n&eacute;t thẩm mỹ cực cao.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">B&ecirc;n cạnh ưu điểm, ta c&oacute; thể thấy một số điểm trừ của tấm MDF như kh&ocirc;ng c&oacute; độ dẻo dai m&agrave; chỉ c&oacute; độ cứng. Những tấm MDF th&ocirc;ng thường th&igrave; kh&ocirc;ng c&oacute; khả năng chống ẩm, chịu nước m&agrave; những tấm MDF m&agrave;u xanh mới c&oacute; khả năng chống ẩm. V&igrave; l&agrave; tấm gỗ được sản xuất c&ocirc;ng nghiệp từ nhiều th&agrave;nh phần n&ecirc;n ch&uacute;ng ta kh&ocirc;ng thể khắc hay chạm trổ trực tiếp l&ecirc;n đ&oacute;.&nbsp;</span></p>\r\n<p><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/374DtIBcig7akc93y89CKdCjQF1bvv6BBVtK0Oia.jpeg\" alt=\"\" width=\"600\" height=\"375\" /></span></p>\r\n<h2><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>Gỗ MDF c&oacute; c&ocirc;ng dụng g&igrave;?</strong></span></h2>\r\n<p><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Hiện nay,&nbsp;ứng dụng của MDF&nbsp;được sử dụng rộng r&atilde;i với nhiều chủng loại kh&aacute;c nhau. Với tấm MDF d&ugrave;ng trong nh&agrave; th&igrave; c&oacute; thể sử dụng để sản xuất những sản phẩm nội thất như b&agrave;n ghế, tủ, kệ, giường, &hellip; MDF d&ugrave;ng ngo&agrave;i trời th&igrave; c&oacute; khả năng chịu nhiệt v&agrave; chị sự ẩm ướt như d&ugrave;ng l&agrave;m ghế ngo&agrave;i trời, cột hay biển hiệu, &hellip;</span></p>\r\n<p><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Ngo&agrave;i ra c&ograve;n c&oacute; những tấm MDF mặt trơn, bạn c&oacute; thể sơn m&agrave;u l&ecirc;n ch&uacute;ng để sử dụng l&agrave;m tấm trang tr&iacute; hay tấm v&aacute;ch, kệ nhỏ, &hellip; Tấm MDF kh&ocirc;ng trơn th&igrave; d&ugrave;ng l&agrave;m vật liệu trang tr&iacute; hay đ&oacute;ng th&agrave;nh phẩm sau khi phủ một lớp như&nbsp;<a href=\"https://dongsuh.vn/blogs/tin-tuc-noi-that/go-melanime-la-gi-va-nhung-dieu-can-biet-ve-loai-go-cong-nghiep-dac-biet-nay\" target=\"_blank\" rel=\"noopener noreferrer\">Melamine</a>,&nbsp;<a href=\"https://dongsuh.vn/blogs/tin-tuc-noi-that/veneer-la-gi\" target=\"_blank\" rel=\"noopener noreferrer\">Veneer</a>, &hellip;</span></p>','Gỗ MDF là gì?',NULL,'go-mdf-la-gi','Trong thế giới các sản phẩm nội thất, có lẽ phổ biến nhất chính là các sản phẩm từ gỗ ván MDF. Vậy gỗ MDF là gi? Đặc điểm ra sao? Và vì sao chúng lại phổ biển tới vậy? Hãy cùng nghenoithat.vn tìm hiểu trong bài viết dưới đây','nội thất gỗ, gỗ mdf, gỗ công nghiệp','Published',2,NULL,1,0,'2020-12-10 19:18:20','2020-12-10 19:18:20',NULL),(13,'Những điều cần biết về gỗ HDF','2020-12-03 10:00:00','1607655980-nhung-dieu-can-biet-ve-go-hdf.jpg','Ván gỗ HDF là loại vật liệu được rất nhiều người ưa chuộng bởi những đặc tính hữu ích, tốt hơn các loại gỗ công nghiệp khác. Hãy cùng Nghenoithat.vn khám phá những thông tin hữu ích nhất về gỗ HDF.','<h2 style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>HDF l&agrave; g&igrave;?</strong></span></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Tấm gỗ hay c&ograve;n gọi l&agrave; tấm v&aacute;n &eacute;p HDF l&agrave; viết tắt của cụm từ High Density Fiberboard, nghĩa l&agrave; tấm&nbsp;v&aacute;n gỗ c&ocirc;ng nghiệp&nbsp;được &eacute;p từ bột gỗ c&ocirc;ng nghiệp. Đ&acirc;y l&agrave; loại v&aacute;n sử dụng 80-85% th&agrave;nh phần l&agrave; bột gỗ tự nhi&ecirc;n, c&ograve;n lại l&agrave; phụ gia l&agrave;m cứng, chống mối mọt.&nbsp;Gỗ HDF&nbsp;thường được &eacute;p dưới &aacute;p suất cực lớn, tạo th&agrave;nh những tấm v&aacute;n c&oacute; độ d&agrave;y v&agrave; k&iacute;ch thước kh&aacute;c nhau.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">C&aacute;c loại l&otilde;i của tấm HDF hầu hết đều đạt ti&ecirc;u chuẩn E1, tức l&agrave; ti&ecirc;u chuẩn đảm bảo độ cứng, độ bền v&agrave; độ tự nhi&ecirc;n, kh&ocirc;ng g&acirc;y hại cho sức khỏe v&agrave; m&ocirc;i trường. Kh&aacute;c với c&aacute;c loại tấm &eacute;p tr&ecirc;n, m&agrave;u của tấm gỗ HDF t&ugrave;y thuộc v&agrave; đầu v&agrave;o của bột gỗ v&agrave; kh&ocirc;ng li&ecirc;n quan g&igrave; đến chất lượng v&agrave; t&iacute;nh chất của tấm v&aacute;n &eacute;p.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/vdc2gb09TDIwBUbJYgnv2GHNM0FxEYf5sB4n4tWZ.jpeg\" alt=\"go-hdf-la-gi\" width=\"600\" height=\"450\" /></span></p>\r\n<h2 style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Gỗ HDF c&oacute; tốt kh&ocirc;ng?</span></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Ta c&oacute; thể thấy được một loạt những ưu điểm của tấm gỗ HDF khi quyết định sử dụng tấm v&aacute;n n&agrave;y như khả năng c&aacute;ch &acirc;m cực kỳ tốt. Khung gỗ xương c&ocirc;ng nghiệp b&ecirc;n trong tấm v&aacute;n gi&uacute;p cho n&oacute; khắc phục được những nhược điểm như nặng, cong v&ecirc;nh. M&agrave;u sắc của c&aacute;c tấm MDF kh&aacute; đa dạng, l&ecirc;n tới hơn 40 m&agrave;u cho bạn thỏa sức lựa chọn.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Quy tr&igrave;nh &eacute;p đặc biệt gi&uacute;p cho tấm gỗ HDF giữ được những v&acirc;n gỗ gần như thật, đem lại t&iacute;nh thẩm mỹ rất ho&agrave;n hảo. Vẻ ngo&agrave;i tấm v&aacute;n thường nhẵn b&oacute;ng, kh&ocirc;ng bị loang lổ m&agrave;u sắc. Do kết cấu tốt n&ecirc;n&nbsp;khả năng chống ẩm của HDF&nbsp;cũng cực k&igrave; tốt, hơn loại v&aacute;n MDF v&agrave; độ cứng cũng rất cao.</span></p>\r\n<h2 style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>&nbsp;C&ocirc;ng dụng của gỗ HDF</strong></span></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Tấm v&aacute;n MDF đ&uacute;ng l&agrave; một &yacute; tưởng tuyệt vời cho mọi c&ocirc;ng tr&igrave;nh v&igrave; sự đa dạng trong c&ocirc;ng năng của n&oacute; khi sử dụng được cả trong nh&agrave; v&agrave; ngo&agrave;i trời. Bạn c&oacute; thể&nbsp;ứng dụng HDF&nbsp;l&agrave;m tấm v&aacute;n l&aacute;t s&agrave;n cũng được. Hoặc d&ugrave;ng để đ&oacute;ng c&aacute;c sản phẩm như b&agrave;n ghế, giường, tủ, cửa, v&aacute;ch ngăn th&igrave; thật tuyệt vời.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Hiện nay, người ta đang ưa chuộng sử dụng tấm gỗ HDF l&aacute;t s&agrave;n nh&agrave; bởi những ưu điểm vượt trội của n&oacute;. Bạn c&oacute; thể thấy được ở những c&ocirc;ng tr&igrave;nh d&acirc;n dụng của một số nước như Nhật Bản, H&agrave;n Quốc đều sử dụng tấm v&aacute;n n&agrave;y bởi t&iacute;nh thẩm mỹ cũng như sự tuyệt vời của n&oacute;.</span></p>','Những điều cần biết về gỗ HDF',NULL,'nhung-dieu-can-biet-ve-go-hdf','Ván gỗ HDF là loại vật liệu được rất nhiều người ưa chuộng bởi những đặc tính hữu ích, tốt hơn các loại gỗ công nghiệp khác. Hãy cùng Nghenoithat khám phá những thông tin hữu ích nhất về gỗ HDF.','vật liệu nội thất, vật liệu xây dựng, gỗ công nghiệp, hdf, phần mềm gỗ','Published',2,NULL,0,0,'2020-12-10 20:06:20','2020-12-10 20:06:20',NULL),(14,'Những xu hướng thiết kế 2020','2020-12-08 10:34:00','1607658030-xu-huong-thiet-ke-2020.jpg','Hãy cùng nghenoithat.vn tìm hiểu các phong cách thiết kế, trang trí và sáng tạo không gian đang trở thành xu hướng trong năm 2020 nhé.','<div class=\"o9v6fnle cxmmr5t8 oygrvhab hcukyx3x c1et5uql ii04i59q\">\r\n<h2 dir=\"auto\"><strong><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">1. Phong c&aacute;ch c&ocirc;ng nghiệp</span></strong></h2>\r\n</div>\r\n<div class=\"o9v6fnle cxmmr5t8 oygrvhab hcukyx3x c1et5uql ii04i59q\">\r\n<div dir=\"auto\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Phong c&aacute;ch c&ocirc;ng nghiệp được hiểu đơn giản l&agrave; sử dụng những vật liệu th&ocirc; sơ, mộc mạc nhằm gợi nhớ đến kh&ocirc;ng gian sản xuất c&ocirc;ng nghiệp thời kỳ hưng thịnh. Điểm nhấn ch&iacute;nh của phong c&aacute;ch n&agrave;y l&agrave; những vật liệu th&ocirc;, đơn giản l&agrave;m to&aacute;t l&ecirc;n vẻ đẹp mạnh mẽ, khỏe khoắn của nội thất.</span></div>\r\n<div dir=\"auto\">&nbsp;</div>\r\n</div>\r\n<p><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/v7dLLjsSMfBVm6ZccgDXAXJYKyFkm5u1oa4yA0EU.jpeg\" alt=\"\" width=\"600\" height=\"420\" /></p>\r\n<div class=\"o9v6fnle cxmmr5t8 oygrvhab hcukyx3x c1et5uql ii04i59q\">\r\n<h2 dir=\"auto\"><strong><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">2. Nội thất bọc nhung</span></strong></h2>\r\n</div>\r\n<div class=\"o9v6fnle cxmmr5t8 oygrvhab hcukyx3x c1et5uql ii04i59q\">\r\n<div dir=\"auto\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Mặc d&ugrave; phong c&aacute;ch bọc nhung từng được xem l&agrave; lạc hậu, nhưng cũng như bao thị trường kh&aacute;c c&aacute;c hiện tượng, xu hướng cứ thay đổi li&ecirc;n tục.</span></div>\r\n</div>\r\n<div class=\"o9v6fnle cxmmr5t8 oygrvhab hcukyx3x c1et5uql ii04i59q\">\r\n<div dir=\"auto\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Những m&oacute;n đồ bọc nhung với vẻ đẹp diễm lệ v&agrave; được cải tiến trở n&ecirc;n sang trọng, đẳng cấp hơn l&agrave; sự lựa chọn ho&agrave;n hảo cho kh&ocirc;ng gian ph&ograve;ng kh&aacute;ch trong thiết kế nội thất căn hộ 90m2 của bạn. Ngo&agrave;i ra, ch&uacute;ng c&ograve;n c&oacute; thể được ứng dụng trong thiết kế nội thất văn ph&ograve;ng cao cấp. C&oacute; rất nhiều m&agrave;u sắc đa dạng để bạn c&oacute; nhiều sự lựa chọn như m&agrave;u đỏ đun, m&agrave;u hồng, m&agrave;u x&aacute;m, m&agrave;u v&agrave;ng dầu,&hellip;</span></div>\r\n<div dir=\"auto\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/PvJHS8OaZxaGN8DcEMn23gSbd59mWGklGKDEvdKr.jpeg\" alt=\"\" width=\"600\" height=\"537\" /></span></div>\r\n<div dir=\"auto\">&nbsp;</div>\r\n</div>\r\n<div class=\"o9v6fnle cxmmr5t8 oygrvhab hcukyx3x c1et5uql ii04i59q\">\r\n<div dir=\"auto\"><strong><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">3. Đồ d&ugrave;ng &aacute;nh kim v&agrave;ng đồng</span></strong></div>\r\n</div>\r\n<div class=\"o9v6fnle cxmmr5t8 oygrvhab hcukyx3x c1et5uql ii04i59q\">\r\n<div dir=\"auto\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Điểm nổi bật gi&uacute;p phong c&aacute;ch n&agrave;y nhận được sự ưa chuộng nhiều đến vậy l&agrave; do n&oacute; ph&ugrave; hợp với nhiều kh&ocirc;ng gian nội thất như thiết kế nội thất nh&agrave; ống, thiết kế nội thất nh&agrave; liền kề, thiết kế nội thất nh&agrave; h&agrave;ng,.. Tất cả đều sẽ trở n&ecirc;n thu h&uacute;t với c&aacute;c đồ vật c&oacute; bọc lớp &aacute;nh kim.</span></div>\r\n<div dir=\"auto\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/CHJD8nremVbcjC5EV8pHGW69Pw5BzAacbV0aguzw.jpeg\" alt=\"\" width=\"600\" height=\"807\" /></div>\r\n</div>\r\n<div class=\"o9v6fnle cxmmr5t8 oygrvhab hcukyx3x c1et5uql ii04i59q\">\r\n<h2 dir=\"auto\"><strong><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">4. Xu hướng nh&agrave; trong vườn</span></strong></h2>\r\n</div>\r\n<div class=\"o9v6fnle cxmmr5t8 oygrvhab hcukyx3x c1et5uql ii04i59q\">\r\n<div dir=\"auto\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Chưa bao giờ c&aacute;c yếu tố thi&ecirc;n nhi&ecirc;n lại được ứng dụng v&agrave;o thiết kế theo phong c&aacute;ch nội thất hiện đại nh&agrave; ở như hiện nay, c&aacute;c chuy&ecirc;n gia cũng dự đo&aacute;n rằng phong c&aacute;ch n&agrave;y sẽ c&ograve;n ph&aacute;t triển mạnh mẽ hơn nữa trong tương lai. Ngo&agrave;i ra, thiết kế nội thất văn ph&ograve;ng hiện đại cũng đang l&agrave; xu hướng thịnh h&agrave;nh ng&agrave;y nay. V</span><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">iệc mang yếu tố thi&ecirc;n nhi&ecirc;n v&agrave;o nội thất c&ograve;n gi&uacute;p n&acirc;ng cao sức khỏe của c&aacute;c th&agrave;nh vi&ecirc;n trong gia đ&igrave;nh.</span></div>\r\n</div>\r\n<div class=\"o9v6fnle cxmmr5t8 oygrvhab hcukyx3x c1et5uql ii04i59q\">\r\n<div dir=\"auto\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/dfF6V4eV3BJdxAvg3DO0qbtg6XaW8NxBNtPp7JED.jpeg\" alt=\"\" width=\"600\" height=\"400\" /></div>\r\n</div>\r\n<div class=\"o9v6fnle cxmmr5t8 oygrvhab hcukyx3x c1et5uql ii04i59q\">\r\n<h2 dir=\"auto\"><strong><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">5. Đồ họa h&igrave;nh học trong trang tr&iacute;</span></strong></h2>\r\n</div>\r\n<div class=\"o9v6fnle cxmmr5t8 oygrvhab hcukyx3x c1et5uql ii04i59q\">\r\n<div dir=\"auto\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Đồ họa h&igrave;nh học đ&atilde; xuất hiện được một thời gian v&agrave; n&oacute; dự đo&aacute;n sẽ trở th&agrave;nh xu hướng năm 2020. Xu hướng n&agrave;y sẽ ảnh hưởng trực tiếp l&ecirc;n việc chọn lựa thảm, ga, r&egrave;m cửa, giấy d&aacute;n tường,&hellip;</span></div>\r\n<div dir=\"auto\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/PkEJiiQ6vSbmdzydB4r2At0YgHerU1yxAX8W5xHZ.jpeg\" alt=\"\" width=\"600\" height=\"338\" /></span></div>\r\n</div>','Những xu hướng thiết kế 2020',NULL,'nhung-xu-huong-thiet-ke-2020','Hãy cùng nghenoithat.vn tìm hiểu các phong cách thiết kế, trang trí và sáng tạo không gian đang trở thành xu hướng trong năm 2020 nhé.','thiết kế nội thất, nội thất, nội thất gỗ','Published',2,NULL,1,0,'2020-12-10 20:40:30','2020-12-10 23:38:11',NULL),(15,'Kích thước tủ bếp tiêu chuẩn người Việt','2020-12-11 14:12:00','1607670874-kich-thuoc-tu-bep-tieu-chuan-nguoi-viet.jpg','Bạn đang có nhu cầu đóng tủ bếp nhưng không biết kích thước tủ bếp chuẩn phù hợp với chiều cao người Việt. Và sẽ thật khó chịu nếu phần tủ bếp của nhà bạn không có được kích thước hợp lý. Khi đó, công việc nội trợ trở thành một nhiệm vụ khó khăn.\r\nKích thước tủ bếp tiêu chuẩn được lấy trên mặt bằng chung, nó có thể điều chỉnh tùy theo chiều cao của người sử dụng và diện tích của không gian bếp nhà bạn. Chẳng hạn như chiều cao của tủ cũng phải phù hợp với chiều cao trần nhà và mặt sàn để dễ dàng vệ sinh','<div class=\"o9v6fnle cxmmr5t8 oygrvhab hcukyx3x c1et5uql ii04i59q\">\r\n<div dir=\"auto\" style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Với chiều cao tổng thể của to&agrave;n bộ phần tủ bếp v&agrave;o khoảng 220 cm &ndash; 240 cm, k&iacute;ch thước tủ dưới ti&ecirc;u chuẩn cao 0.8 m. Khoảng c&aacute;ch trống giữa phần tủ dưới v&agrave; tr&ecirc;n chỉ n&ecirc;n ở mức 50 cm, t&ugrave;y theo thiết kế. Nhưng cho d&ugrave; khoảng c&aacute;ch đ&oacute; lớn hay nhỏ th&igrave; tầm với cao nhất cũng chỉ n&ecirc;n tối đa 180 cm. Đối với chiều s&acirc;u, phần tủ dưới trung b&igrave;nh khoảng 50 cm- 60 cm, c&ograve;n phần tủ tr&ecirc;n l&agrave; 30 cm -35 cm.</span></div>\r\n<div dir=\"auto\" style=\"text-align: justify;\">&nbsp;</div>\r\n</div>\r\n<div class=\"o9v6fnle cxmmr5t8 oygrvhab hcukyx3x c1et5uql ii04i59q\" style=\"text-align: justify;\">\r\n<div dir=\"auto\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Điều quan trọng l&agrave; người sử dụng c&oacute; thể bao qu&aacute;t được to&agrave;n bộ bếp v&agrave; lu&ocirc;n thoải m&aacute;i trong tư thế khi sử dụng. Một bộ tủ bếp gia đ&igrave;nh tu&acirc;n theo k&iacute;ch thước tủ bếp ti&ecirc;u chuẩn sẽ mang lại thuận lợi cho người nội trợ trong qu&aacute; tr&igrave;nh sử dụng. Nếu mọi người trong gia đ&igrave;nh c&oacute; chiều cao hạn chế nhưng bạn lại lắp tủ bếp qu&aacute; cao th&igrave; sẽ rất vất vả mỗi lần lấy đồ, nhưng nếu c&aacute;c th&agrave;nh vi&ecirc;n đều rất cao m&agrave; lại thiết kế tủ bếp thấp sẽ rất bất tiện mỗi khi sử dụng. Do đ&oacute; khi thiết kế tủ bếp cần phải c&oacute; phương &aacute;n ph&ugrave; hợp để mang lại sự thuận tiện nhất cho mọi người.</span></div>\r\n<div dir=\"auto\">&nbsp;</div>\r\n<div dir=\"auto\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/mKsjXBAuYwfYaOcK8RE2bSPSJ6WLeTTih9BsUYIR.jpeg\" alt=\"kich-thuoc-tu-bep\" width=\"600\" height=\"407\" /></span></div>\r\n<div dir=\"auto\">&nbsp;</div>\r\n</div>\r\n<div class=\"o9v6fnle cxmmr5t8 oygrvhab hcukyx3x c1et5uql ii04i59q\" style=\"text-align: justify;\">\r\n<div dir=\"auto\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Khi thiết kế tủ bếp cho gia đ&igrave;nh, bạn cần biết những ti&ecirc;u chuẩn k&iacute;ch thước tủ bếp trước khi bắt tay v&agrave;o thực hiện. Bởi nếu thiết kế bị sai từ đầu, bạn sẽ kh&oacute; khăn trong việc sửa chữa v&agrave; tất nhi&ecirc;n nếu sửa chữa sẽ v&ocirc; c&ugrave;ng tốn k&eacute;m. Ngo&agrave;i ra, k&iacute;ch thước tủ bếp cũng cần ph&ugrave; hợp với k&iacute;ch thước chung của căn bếp, bởi nếu tủ bếp qu&aacute; lớn sẽ chiếm nhiều kh&ocirc;ng gian của bếp g&acirc;y cảm gi&aacute;c bức b&aacute;ch v&agrave; chật chội. Chiều cao của tủ cũng phải ph&ugrave; hợp</span><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"> với chiều cao trần nh&agrave; v&agrave; mặt s&agrave;n để dễ d&agrave;ng vệ sinh, ch&ugrave;i rửa cũng như sự h&agrave;i h&ograve;a trong ng&ocirc;i nh&agrave;.</span></div>\r\n<div dir=\"auto\">&nbsp;</div>\r\n</div>\r\n<div class=\"o9v6fnle cxmmr5t8 oygrvhab hcukyx3x c1et5uql ii04i59q\" style=\"text-align: justify;\">\r\n<div dir=\"auto\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Sau đ&acirc;y l&agrave; k&iacute;ch thước tủ bếp ti&ecirc;u chuẩn cho người Việt:</span></div>\r\n<div dir=\"auto\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">&ndash; K&iacute;ch thước tủ bếp dưới ti&ecirc;u chuẩn: chiều cao của tủ bếp dưới th&ocirc;ng thường l&agrave; từ 80 đến 90cm, chiều s&acirc;u tủ từ 45 đến 50cm. Với k&iacute;ch thước n&agrave;y, tủ bếp dưới ph&ugrave; hợp để lắp m&aacute;y rửa b&aacute;t &acirc;m tủ, l&ograve; nướng &acirc;m tủ, c&aacute;c loại bếp từ &ndash; bếp điện từ &acirc;m tủ,&hellip;</span></div>\r\n<div dir=\"auto\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">&ndash; K&iacute;ch thước tủ bếp tr&ecirc;n ti&ecirc;u chuẩn: phần tủ tr&ecirc;n c&oacute; độ cao từ 45 đến 75cm v&agrave; độ s&acirc;u tủ trung b&igrave;nh từ 30 đến 35cm. Với phần tủ bếp tr&ecirc;n như vậy rất ph&ugrave; hợp với k&iacute;ch thước ti&ecirc;u chuẩn của c&aacute;c thiết bị như m&aacute;y h&uacute;t m&ugrave;i , m&aacute;y sấy b&aacute;t,&hellip;</span></div>\r\n<div dir=\"auto\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">&ndash; Khoảng c&aacute;ch giữa tủ bếp tr&ecirc;n v&agrave; dưới ti&ecirc;u chuẩn khu vực h&uacute;t m&ugrave;i: m&aacute;y h&uacute;t m&ugrave;i từ 60 đến 80cm. Khoảng c&aacute;ch vừa đủ gi&uacute;p h&uacute;t m&ugrave;i hoạt động tốt , h&uacute;t được triệt để m&agrave; vẫn kh&ocirc;ng g&acirc;y bất tiện khi sử dụng.</span></div>\r\n<div dir=\"auto\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">&ndash; Khoảng c&aacute;ch giữa tủ bếp tr&ecirc;n v&agrave; dưới khu vực khoang chậu rửa, v&agrave; khu vực kh&aacute;c từ 40 đến 60 cm.</span></div>\r\n<div dir=\"auto\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">&ndash; Tổng chiều cao của to&agrave;n bộ tủ từ 2,4 m &ndash; 2,5 m, tầm với mở cửa tủ tr&ecirc;n tối đa từ 1,8m &ndash; 1, 9m, thiết kế tầm với mở cửa cao qu&aacute; rất bất tiện khi sử dụng. T&ugrave;y chiều cao của trần nh&agrave; bếp m&agrave; l&agrave;m loại tủ cao hay thấp nhưng tổng chiều cao của cả tủ tr&ecirc;n v&agrave; dưới kh&ocirc;ng n&ecirc;n qu&aacute; 2,4m.</span></div>\r\n<div dir=\"auto\">&nbsp;</div>\r\n<div dir=\"auto\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/aLp92aCKweQSHrVdzcvGBYZhWkgltv4WSQ9mPgIn.jpeg\" alt=\"kich-thuoc-tu-nguoi-viet\" width=\"600\" height=\"463\" /></span></div>\r\n<div dir=\"auto\">&nbsp;</div>\r\n<div dir=\"auto\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">&ndash; K&iacute;ch thước mặt đ&aacute; tủ bếp: Đ&acirc;y l&agrave; k&iacute;ch thước kh&aacute; quan trọng, c&oacute; ảnh hưởng trực tiếp đến mức độ đẹp v&agrave; thẩm mỹ của tủ bếp. Một bộ tủ bếp thật sự đẹp sẽ kh&ocirc;ng thể thiếu được sự g&oacute;p mặt của một mặt b&agrave;n đ&aacute; tủ bếp. Tuy nhi&ecirc;n để c&oacute; thể sử dụng được bộ tủ bếp l&acirc;u d&agrave;i cũng như mang đến t&iacute;nh thẩm mỹ cao nhất th&igrave; bạn n&ecirc;n chọn k&iacute;ch thước mặt đ&aacute; tủ bếp ti&ecirc;u chuẩn bao gồm: Chiều s&acirc;u: 60cm &ndash; 62cm, chiều d&agrave;i đ&aacute; trong khoảng từ 150cm &ndash; 210cm, tối đa 320cm t&ugrave;y theo từng loại đ&aacute; kh&aacute;c nhau, độ d&agrave;y 15mm &ndash; 18mm &ndash; 20mm.</span></div>\r\n<div dir=\"auto\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">&ndash; K&iacute;ch thước c&aacute;nh tủ bếp: T&ugrave;y v&agrave;o loại gỗ, chất liệu sử dụng m&agrave; c&oacute; k&iacute;ch thước c&aacute;nh tủ bếp ph&ugrave; hợp. Tủ bếp gỗ c&ocirc;ng nghiệp v&agrave; gỗ tự nhi&ecirc;n sử dụng chiều cao c&aacute;nh tủ bếp từ 70cm &ndash; 80cm, chiều cao n&agrave;y ph&ugrave; hợp với chiều cao của người Việt, đặc biệt l&agrave; phụ nữ. Ri&ecirc;ng với k&iacute;ch thước c&aacute;nh tủ bếp theo chiều rộng th&igrave; c&oacute; sự ch&ecirc;nh lệch kh&aacute; lớn giữa gỗ tự nhi&ecirc;n v&agrave; gỗ c&ocirc;ng nghiệp. Cụ thể đối với gỗ tự nhi&ecirc;n chiều rộng từ 30cm &ndash; 37cm để đảm bảo gỗ kh&ocirc;ng bị biến dạng. C&ograve;n với gỗ c&ocirc;ng nghiệp thường được gia c&ocirc;ng chắc chắn, &eacute;p th&agrave;nh tấm lớn, sẽ kh&ocirc;ng bị cong v&ecirc;nh như gỗ tự nhi&ecirc;n, v&igrave; vậy k&iacute;ch thước sử dụng dao động từ 30cm &ndash; 70cm. (Th&ocirc;ng thường chỉ n&ecirc;n sử dụng chiều rộng đến 50cm sẽ mang t&iacute;nh thẩm mỹ cao nhất).</span></div>\r\n</div>\r\n<div class=\"o9v6fnle cxmmr5t8 oygrvhab hcukyx3x c1et5uql ii04i59q\">\r\n<div dir=\"auto\" style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">C&oacute; một số ti&ecirc;u chuẩn nhất định khi muốn thiết kế tủ bếp đẹp, k&iacute;ch thước tủ bếp ti&ecirc;u chuẩn c&oacute; thể được điều chỉnh t&ugrave;y theo chiều cao của người sử dụng. Tuy nhi&ecirc;n, kh&ocirc;ng n&ecirc;n tạo cho phần bếp nh&agrave; m&igrave;nh một k&iacute;ch thước qu&aacute; đặc biệt. Bạn sẽ kh&oacute; khăn khi muốn b&aacute;n nh&agrave;, hoặc g&acirc;y rắc rối cho vị kh&aacute;ch n&agrave;o đ&oacute; t&igrave;nh nguyện v&agrave;o bếp rửa b&aacute;t hộ. Nếu c&oacute; &yacute; định tự thiết kế tủ bếp cho gia đ&igrave;nh, bạn c&oacute; thế dựa v&agrave;o c&aacute;c th&ocirc;ng số k&iacute;ch thước quy chuẩn tr&ecirc;n.</span></div>\r\n</div>','Kích thước tủ bếp tiêu chuẩn người Việt',NULL,'kich-thuoc-tu-bep-tieu-chuan-nguoi-viet','Bạn đang có nhu cầu đóng tủ bếp nhưng không biết kích thước tủ bếp chuẩn phù hợp với chiều cao người Việt. Và sẽ thật khó chịu nếu phần tủ bếp của nhà bạn không có được kích thước hợp lý. Khi đó, công việc nội trợ trở thành một nhiệm vụ khó khăn.\r\nKích thước tủ bếp tiêu chuẩn được lấy trên mặt bằng chung, nó có thể điều chỉnh tùy theo chiều cao của người sử dụng và diện tích của không gian bếp nhà bạn. Chẳng hạn như chiều cao của tủ cũng phải phù hợp với chiều cao trần nhà và mặt sàn để dễ dàng vệ sinh','thiết kế nội thất, nội thất, nội thất gỗ, tủ bếp','Published',2,NULL,1,0,'2020-12-11 00:14:34','2020-12-11 00:25:38',NULL),(16,'TEst','2020-12-30 22:35:00','1607873766-test.jpg','aaaaaa','<p>aaaaaaaaaa</p>\r\n<div id=\"eJOY__extension_root\" class=\"eJOY__extension_root_class\" style=\"all: unset;\">&nbsp;</div>',NULL,NULL,'test',NULL,NULL,'Published',2,NULL,1,0,'2020-12-13 08:36:06','2020-12-13 18:39:46','2020-12-13 18:39:46'),(17,'Công ty CP Gỗ An Cường - Làm chủ công nghệ sẽ làm chủ thị trường','2020-12-14 15:20:00','1607934241-cong-ty-cp-go-an-cuong-lam-chu-cong-nghe-se-lam-chu-thi-truong.jpg','“Công nghệ là xu thế, bao gồm cả công nghệ cho người tiêu dùng và trong sản xuất với doanh nghiệp gỗ nội thất. Ai có công nghệ tốt sẽ làm chủ \'sân chơi\' trên thị trường, ngay cả lúc ảnh hưởng từ dịch bệnh như hiện nay”, đại diện Công ty cổ phần Gỗ An Cường chia sẻ.','<h2 style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>C&ocirc;ng nghệ l&agrave; xu thế</strong></span></h2>\r\n<p><span style=\"font-weight: 400; font-family: \'times new roman\', times, serif; font-size: 14pt;\">C&aacute;ch mạng c&ocirc;ng nghiệp 4.0 đ&atilde; tạo ra những thay đổi chưa từng c&oacute; trong lịch sử với nhiều ng&agrave;nh nghề, lĩnh vực, trong đ&oacute; c&oacute; lĩnh vực sản xuất - kinh doanh đồ nội thất.</span></p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-weight: 400; font-family: \'times new roman\', times, serif; font-size: 14pt;\">Tại Việt Nam, trước đ&acirc;y, sự tương t&aacute;c trực tiếp của c&aacute;c doanh nghiệp sản xuất nội thất (5.300 doanh nghiệp) với thị trường ti&ecirc;u thụ (nhu cầu, thị hiếu, kiểu d&aacute;ng mẫu m&atilde;, c&aacute;c thay đổi của thị trường&hellip;) c&ograve;n rất &iacute;t, dẫn tới việc hạn chế trong đổi mới sản xuất, ngh&egrave;o n&agrave;n về mẫu m&atilde;, chủng loại, n&ecirc;n thường bị động trước biến đổi của thị trường.</span></p>\r\n<p><span style=\"font-weight: 400; font-family: \'times new roman\', times, serif; font-size: 14pt;\">Tuy nhi&ecirc;n hiện nay, với sự ph&aacute;t triển của c&ocirc;ng nghệ v&agrave; thị trường, thị hiếu của người d&ugrave;ng, nhiều doanh nghiệp sản xuất đồ nội thất như C&ocirc;ng ty cổ phần Gỗ An Cường, C&ocirc;ng ty cổ phần Woodsland, C&ocirc;ng ty cổ phần Gỗ Nam Định&hellip; đ&atilde; bỏ h&agrave;ng chục tỷ đồng để đầu tư, đổi mới c&ocirc;ng nghệ trong sản xuất v&agrave; b&aacute;n h&agrave;ng.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-family: \'times new roman\', times, serif; font-size: 14pt;\">Nhờ ti&ecirc;n phong trong việc đầu tư, đổi mới c&ocirc;ng nghệ, c&aacute;c doanh nghiệp n&agrave;y đ&atilde; chiếm được thị phần lớn tr&ecirc;n thị trường, n&acirc;ng cao h&igrave;nh ảnh, uy t&iacute;n trong mắt người ti&ecirc;u d&ugrave;ng cả trong nước v&agrave; nước ngo&agrave;i.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-family: \'times new roman\', times, serif; font-size: 14pt;\">Để đối ph&oacute; với dịch Covid-19, h&agrave;ng loạt doanh nghiệp thuộc mọi ng&agrave;nh nghề, lĩnh vực chọn giải ph&aacute;p thu hẹp, tạm dừng sản xuất, thậm ch&iacute; đ&oacute;ng cửa, th&igrave; An Cường chọn c&aacute;ch ứng dụng c&ocirc;ng nghệ v&agrave;o c&ocirc;ng t&aacute;c b&aacute;n h&agrave;ng. Cụ thể, c&ocirc;ng ty n&agrave;y vừa cho ra mắt th&ecirc;m app (ứng dụng) b&aacute;n h&agrave;ng online mới c&oacute; th&ecirc;n AnCuong Catalogue, đồng thời k&yacute; th&ecirc;m hợp đồng với hai đối t&aacute;c về thương mại điện tử để đưa sản phẩm của m&igrave;nh l&ecirc;n s&agrave;n điện tự đến với người ti&ecirc;u d&ugrave;ng.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-family: \'times new roman\', times, serif; font-size: 14pt;\">&ldquo;C&ocirc;ng nghệ l&agrave; xu thế kh&ocirc;ng chỉ trong ng&agrave;nh gỗ nội thất, m&agrave; n&oacute; đ&atilde; t&aacute;c động v&agrave; hiện diện l&ecirc;n tất cả c&aacute;c ng&agrave;nh nghề, lĩnh vực. Đặc biệt, trong thời điểm t&igrave;nh h&igrave;nh dịch bệnh như hiện nay c&agrave;ng thấy r&otilde; vai tr&ograve; của c&ocirc;ng nghệ đối với đời sống n&oacute;i chung v&agrave; thị trường gỗ nội thất n&oacute;i ri&ecirc;ng. Do đ&oacute;, c&aacute;c doanh nghiệp phải đi theo xu thế, trong đ&oacute; c&oacute; cả c&ocirc;ng nghệ d&agrave;nh cho người ti&ecirc;u d&ugrave;ng v&agrave; c&ocirc;ng nghệ d&ugrave;ng cho sản xuất, c&ocirc;ng nghệ trong quản trị điều h&agrave;nh của c&ocirc;ng ty&rdquo;, đại diện An Cường khẳng định.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-family: \'times new roman\', times, serif; font-size: 14pt;\">Cũng theo đại diện n&agrave;y, ứng dụng AnCuong Catalogue c&oacute; thể sử dụng tr&ecirc;n c&aacute;c điện thoại th&ocirc;ng minh, m&aacute;y t&iacute;nh bảng. App n&agrave;y chứa tất cả c&aacute;c th&ocirc;ng số, tư liệu về cả 3 c&ocirc;ng ty của thương hiệu gỗ An Cường.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-family: \'times new roman\', times, serif; font-size: 14pt;\">Khi kh&aacute;ch h&agrave;ng chọn một loại sản phẩm bất kỳ n&agrave;o của gỗ An Cường, n&oacute; sẽ đưa ra tất c&aacute;c mẫu m&atilde;, đồng thời sẽ cung cấp đầy đủ th&ocirc;ng tin về sản phẩm cần t&igrave;m, m&agrave;u sắc, gi&aacute; cả, thiết kế, k&iacute;ch thước, hướng dẫn lắp đặt&hellip;</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-family: \'times new roman\', times, serif; font-size: 14pt;\">Ngo&agrave;i ra, sự ưu việt của ứng dụng b&aacute;n h&agrave;ng n&agrave;y l&agrave; khi kh&aacute;ch h&agrave;ng đ&atilde; c&agrave;i, th&igrave; tất cả c&aacute;c th&ocirc;ng tin về gi&aacute; cả, sản phẩm mới, khuyến mại, ưu đ&atilde;i kh&aacute;ch h&agrave;ng&hellip; m&agrave; An Cường đưa ra đều sẽ tự động cập nhật v&agrave; th&ocirc;ng b&aacute;o cho người ti&ecirc;u d&ugrave;ng để lựa chọn, tham khảo, tư vấn nếu cần thiết.</span></p>\r\n<p><span style=\"font-weight: 400; font-family: \'times new roman\', times, serif; font-size: 14pt;\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/xkZLEiwCF6GaSJa2992WyuCiv7wqqjpv9cl9x56f.jpeg\" alt=\"\" width=\"660\" height=\"371\" /></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-family: \'times new roman\', times, serif; font-size: 14pt;\">&ldquo;Ch&iacute;nh điều n&agrave;y kh&ocirc;ng chỉ tạo ra sự tương t&aacute;c hai chiều tốt giữa kh&aacute;ch h&agrave;ng với C&ocirc;ng ty, m&agrave; c&ograve;n l&agrave; cơ hội cho kh&aacute;ch h&agrave;ng hiểu th&ecirc;m về C&ocirc;ng ty v&agrave; dễ tiếp cận sản phẩm hơn rất nhiều. Đặc biệt, trong bối cảnh dịch bệnh đang diễn biến kh&oacute; lường như hiện nay, việc sử dụng c&aacute;c phần mềm b&aacute;n h&agrave;ng trực tuyến tương tự như thế n&agrave;y sẽ rất thuận tiện. Kh&aacute;ch h&agrave;ng kh&ocirc;ng cần phải đến showroom, m&agrave; chỉ cần sử dụng c&ocirc;ng nghệ để t&igrave;m hiểu tham khảo v&agrave; đặt h&agrave;ng qua mạng&rdquo;, đại diện An Cường cho biết.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-family: \'times new roman\', times, serif; font-size: 14pt;\">&Ocirc;ng Nguyễn T&ocirc;n Quyền, Trưởng ban cố vấn Hiệp hội Gỗ v&agrave; L&acirc;m sản Việt Nam cho biết, nếu trước đ&acirc;y c&aacute;c doanh nghiệp gỗ nội thất Việt chủ yếu sản xuất theo đơn đặt h&agrave;ng sẵn từ c&aacute;c đối t&aacute;c nước ngo&agrave;i hoặc trong nước, dẫn đến lu&ocirc;n bị động trong kinh doanh, th&igrave; giờ đ&acirc;y, nhờ c&ocirc;ng nghệ, họ c&oacute; thể tự thiết kế c&aacute;c mẫu m&atilde;, giới thiệu sản phẩm n&ecirc;n chủ động được việc kinh doanh của m&igrave;nh. Chẳng hạn, C&ocirc;ng ty cổ phần Woodsland, C&ocirc;ng ty cổ phần gỗ Nam Định đ&atilde; c&oacute; những bước tiến vượt bậc trong kinh doanh với kim ngạch xuất khẩu trung b&igrave;nh từ 3.000 - 5.000 tỷ đồng/năm.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-family: \'times new roman\', times, serif; font-size: 14pt;\">B&ecirc;n cạnh đ&oacute;, theo &ocirc;ng Đỗ Xu&acirc;n Lập, Chủ tịch Hiệp hội Gỗ v&agrave; L&acirc;m sản Việt Nam, hiện nay, kh&ocirc;ng &iacute;t doanh nghiệp ng&agrave;nh gỗ nội thất đ&atilde; nh&igrave;n thấy xu thế của c&ocirc;ng nghệ trong kinh doanh, sản xuất, n&ecirc;n đ&atilde; mạnh dạn đầu tư, chuyển đổi, n&acirc;ng cấp c&ocirc;ng nghệ. Đồng thời, li&ecirc;n kết lại với nhau th&agrave;nh chuỗi gi&aacute; trị để tạo n&ecirc;n thế mạnh, sự bền vững tr&ecirc;n thị trường gỗ nội thất hiện nay.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<h2 style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>L&agrave;m chủ s&acirc;n chơi</strong></span></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-family: \'times new roman\', times, serif; font-size: 14pt;\">Từ 2 th&aacute;ng trở về trước, người nghe radio c&oacute; lẽ đ&atilde; thuộc l&agrave;u c&aacute;c quảng c&aacute;o của c&aacute;c h&atilde;ng nội thất như H&ugrave;ng T&uacute;y, PTCasa&hellip; khi c&aacute;c quảng c&aacute;o n&agrave;y được ph&aacute;t li&ecirc;n tục tr&ecirc;n VOV giao th&ocirc;ng, hay c&aacute;c k&ecirc;nh s&oacute;ng FM kh&aacute;c. Tuy nhi&ecirc;n, kể từ sau Tết Nguy&ecirc;n đ&aacute;n tới nay, c&aacute;c quảng c&aacute;o n&agrave;y đ&atilde; thưa dần tr&ecirc;n s&oacute;ng.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-family: \'times new roman\', times, serif; font-size: 14pt;\">Điều n&agrave;y c&oacute; thể l&agrave; dấu hiệu cho thấy, doanh nghiệp đang gặp những kh&oacute; khăn trong việc ti&ecirc;u thụ sản phẩm trong bối cảnh chịu ảnh hưởng chung của dịch Covid-19.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-family: \'times new roman\', times, serif; font-size: 14pt;\">Trong khi đ&oacute;, theo t&igrave;m hiểu của ph&oacute;ng vi&ecirc;n B&aacute;o Đầu tư Bất động sản, website của c&aacute;c c&ocirc;ng ty được thiết kế đơn giản, thiếu sự tương t&aacute;c với kh&aacute;ch h&agrave;ng, kh&ocirc;ng c&oacute; c&aacute;c phần mềm chọn mẫu đa chiều&hellip; v&agrave; cũng chưa thấy th&ocirc;ng b&aacute;o về việc sử dụng ứng dụng b&aacute;n h&agrave;ng trực tuyến.</span></p>\r\n<p><span style=\"font-weight: 400; font-family: \'times new roman\', times, serif; font-size: 14pt;\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/ljuMN18ftjx83bs4VXNX0DxleKoNLWEYInu9igAa.jpeg\" alt=\"\" width=\"660\" height=\"371\" /></span></p>\r\n<p style=\"text-align: center;\"><span style=\"font-weight: 400; font-family: \'times new roman\', times, serif; font-size: 14pt;\"><span style=\"font-size: 12pt;\"><em><span style=\"font-weight: 400;\">An Cường l&agrave; một trong những doanh nghiệp nội thất ti&ecirc;n phong &aacute;p dụng c&ocirc;ng nghệ v&agrave;o sản xuất, b&aacute;n h&agrave;ng</span></em></span></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-family: \'times new roman\', times, serif; font-size: 14pt;\">Trong khi đ&oacute;, theo đại diện thương hiệu gỗ An Cường, việc đi trước trong &aacute;p dụng c&ocirc;ng nghệ v&agrave;o sản xuất - kinh doanh, gi&uacute;p doanh nghiệp c&oacute; nhiều lợi thế. Cụ thể, d&ugrave; t&igrave;nh h&igrave;nh dịch bệnh đang diễn kh&oacute; lường, nhưng c&ocirc;ng t&aacute;c b&aacute;n h&agrave;ng của C&ocirc;ng ty kh&ocirc;ng bị ảnh hưởng nhiều do c&oacute; nhiều kh&aacute;ch h&agrave;ng đặt mua th&ocirc;ng qua app b&aacute;n h&agrave;ng trực tuyến.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-family: \'times new roman\', times, serif; font-size: 14pt;\">&ldquo;Hiện nay, lượng kh&aacute;ch h&agrave;ng t&igrave;m hiểu mua h&agrave;ng qua c&aacute;c app b&aacute;n h&agrave;ng của C&ocirc;ng ty đ&atilde; tăng đến 50% so với thời điểm trước Tết Nguy&ecirc;n đ&aacute;n 2020&rdquo;, đại diện An Cường th&ocirc;ng tin.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-family: \'times new roman\', times, serif; font-size: 14pt;\">Đại diện H&atilde;ng nội thất M-Home cho biết, c&ocirc;ng nghệ lu&ocirc;n lu&ocirc;n được cải tiến buộc c&aacute;c doanh nghiệp phải thay đổi nhiều theo hướng cập nhật li&ecirc;n tục tiến bộ của khoa học c&ocirc;ng nghệ để ph&aacute;t triển. Điều n&agrave;y sẽ gi&uacute;p cho doanh nghiệp về mọi mặt từ quản l&yacute;, cải tiến mẫu m&atilde;, thiết kế, đến b&aacute;n h&agrave;ng&hellip; Đồng thời, cũng mang lại những lợi &iacute;ch kh&ocirc;ng nhỏ cho người ti&ecirc;u d&ugrave;ng về lựa chọn sản phẩm, nh&agrave; ph&acirc;n phối uy t&iacute;n, ph&ugrave; hợp với m&igrave;nh.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-family: \'times new roman\', times, serif; font-size: 14pt;\">&ldquo;Khi cả khị thị trường đều &aacute;p dụng c&ocirc;ng nghệ v&agrave;o c&ocirc;ng t&aacute;c b&aacute;n h&agrave;ng, th&igrave; doanh nghiệp n&agrave;o c&oacute; sản phẩm tốt, c&ocirc;ng nghệ tốt sẽ chiếm được nhiều lợi thế tr&ecirc;n thị trường&rdquo;, vị đại diện n&agrave;y cho hay.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-family: \'times new roman\', times, serif; font-size: 14pt;\">Ở g&oacute;c độ kh&aacute;c, theo &ocirc;ng Đỗ Xu&acirc;n Lập, việc &aacute;p dụng c&ocirc;ng nghệ v&agrave;o sản xuất c&oacute; t&iacute;nh chất quyết định th&agrave;nh bại của sản phẩm tr&ecirc;n thị trường. Chẳng hạn với sản phẩm v&aacute;n &eacute;p, hiện tại Việt Nam c&oacute; rất nhiều nh&agrave; m&aacute;y, nhưng chỉ c&oacute; 3 nh&agrave; m&aacute;y đạt chuẩn xuất khẩu v&agrave;o thị trường Mỹ. C&ograve;n lại khoảng 20 nh&agrave; m&aacute;y kh&aacute;c chỉ đ&aacute;p ứng phục vụ nội địa. Do đ&oacute;, c&aacute;c doanh nghiệp cần thay đổi về c&ocirc;ng nghệ trong kinh doanh, về sự an to&agrave;n sản phẩm đảm bảo về sức khỏe người ti&ecirc;u d&ugrave;ng, m&ocirc;i trường, h&igrave;nh d&aacute;ng gỗ mới đ&aacute;p ứng được nhu cầu thị trường.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-family: \'times new roman\', times, serif; font-size: 14pt;\">&ldquo;Ch&uacute;ng t&ocirc;i đang khuyến kh&iacute;ch c&aacute;c nh&agrave; sản xuất v&aacute;n, c&aacute;c doanh nghiệp gỗ nội thất thay đổi c&ocirc;ng nghệ, quy tr&igrave;nh sản sản xuất để đ&aacute;p ứng thị trường trong v&agrave; ngo&agrave;i nước&rdquo;, &ocirc;ng Lập cho hay.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>Theo Nhất Nam</strong><span style=\"font-weight: 400;\"><br /></span><em><span style=\"font-weight: 400;\">B&aacute;o Đầu tư Bất động&nbsp;sản</span></em></span></p>','Công ty CP Gỗ An Cường - Làm chủ công nghệ sẽ làm chủ thị trường',NULL,'cong-ty-cp-go-an-cuong-lam-chu-cong-nghe-se-lam-chu-thi-truong','“Công nghệ là xu thế, bao gồm cả công nghệ cho người tiêu dùng và trong sản xuất với doanh nghiệp gỗ nội thất. Ai có công nghệ tốt sẽ làm chủ \'sân chơi\' trên thị trường, ngay cả lúc ảnh hưởng từ dịch bệnh như hiện nay”, đại diện Công ty cổ phần Gỗ An Cường chia sẻ.','thiết kế nội thất, nội thất, nội thất gỗ, công nghệ gỗ, phần mềm gỗ','Published',2,NULL,1,1,'2020-12-14 01:24:01','2020-12-28 01:07:42',NULL),(18,'Các tính năng mới sẽ xuất hiện trong Cabinet Vision 2021','2020-12-12 09:56:00','1608174902-cac-tinh-nang-moi-se-xuat-hien-trong-cabinet-vision-2021.jpg','Cabinet Vision hiện nay là giải pháp kỹ thuật hoàn thiện cho ngành sản xuất tủ gỗ công nghiệp. Qua từng phiên bản nâng cấp, phần mềm liên tục cải thiện hiệu năng, bổ sung các thuật toán và chức năng mới, hỗ trợ tối đa việc hoàn thiện quy trình từ thiết kế đến sản xuất cho các doanh nghiệp. Hiện tại, Cabinet Vision 2021 đang ở giai đoạn thử nghiệm với nhiều tính năng hoàn toàn mới. Sau đây là 5 điểm mới đáng chú ý trong phiên bản sắp tới:','<h2 style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>1. T&ugrave;y biến thanh c&ocirc;ng cụ (Ribbon Bar):</strong></span></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Đ&acirc;y l&agrave; 1 thay đổi lớn v&agrave; đặc biệt hữu &iacute;ch với những kh&aacute;ch h&agrave;ng sử dụng Cabinet Vision l&acirc;u năm. Với Cabinet Vision 2021, người d&ugrave;ng dễ d&agrave;ng lựa chọn th&ecirc;m hoặc bỏ c&aacute;c t&iacute;nh năng sẽ được hiển thị tr&ecirc;n thanh c&ocirc;ng cụ. Ngo&agrave;i ra, bản cập nhật mới hỗ trợ việc th&ecirc;m c&aacute;c ph&iacute;m tắt để truy cập c&aacute;c t&iacute;nh năng cơ bản v&agrave; t&iacute;nh năng n&acirc;ng cao được lựa chọn.</span></p>\r\n<p style=\"text-align: center;\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/DAFhDhDopKrlbde7aXnMZZZ9lTKrzTduxesqAR8H.png\" alt=\"ribbon-cabinetvision-2021\" width=\"600\" height=\"313\" /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><em>Giao diện t&ugrave;y biến thanh c&ocirc;ng cụ</em></span></p>\r\n<h2 style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>2. Tr&igrave;nh quản l&yacute; sản xuất cửa (Door Manager) mới:</strong></span></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Thay đổi ho&agrave;n to&agrave;n c&aacute;ch thức quản l&yacute; thư viện cửa nhờ t&iacute;nh năng Door Catalog, hỗ trợ việc t&igrave;m kiếm v&agrave; thay đổi h&igrave;nh dạng tấm cửa bất k&yacute;. Việc th&ecirc;m v&agrave;o hệ thống Door CAM Editor gi&uacute;p tối ưu t&iacute;nh linh hoạt trong việc tạo c&aacute;c nguy&ecirc;n c&ocirc;ng mới tr&ecirc;n tấm cửa (Khoan, soi, phay r&atilde;nh,&hellip;)</span></p>\r\n<p style=\"text-align: center;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/lj0ThTxn16KLSlNlgl8ul88V0NhuIIdNhixwIB0s.png\" alt=\"door-manager-cabinetvision-2021\" width=\"600\" height=\"312\" /><br /></span><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><em>Giao diện Door Manager mới</em></span></p>\r\n<h2 style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>3. X&acirc;y dựng phương thức tạo h&igrave;nh/ lắp gh&eacute;p phụ kiện Shadowline:</strong></span></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Trong Cabinet Vision 2021, người d&ugrave;ng được giới thiệu một phương thức lắp gh&eacute;p, x&acirc;y dựng phụ kiện tay nắm Shadowline ho&agrave;n to&agrave;n mới. Người d&ugrave;ng t&ugrave;y chỉnh c&aacute;c th&ocirc;ng số v&egrave; h&igrave;nh dạng, k&iacute;ch thước, vị tr&iacute; của li&ecirc;n kết, ph&ugrave; hợp t&iacute;nh thẩm mỹ v&agrave; nhu cầu sản xuất của doanh nghiệp. Phương thức n&agrave;y đặc biệt ph&ugrave; hợp cho c&aacute;c tủ bếp y&ecirc;u cầu trang bị thanh định h&igrave;nh Gola.</span></p>\r\n<p style=\"text-align: center;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><em><br /><img src=\"/storage/uploads/tinymce/v01EMvSpjD2LMbs4CV4Q6pZcLcWhgo4vFmzDpssx.png\" alt=\"shadowline-cabinetvision2021\" width=\"566\" height=\"583\" /><br />Tủ sử dụng phụ kiện Shadowline</em></span></p>\r\n<h2 style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>4. T&iacute;nh năng Walkthrough v&agrave; cải thiện chất lượng kết xuất h&igrave;nh ảnh (Real Time Rendering):</strong></span></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Nắm bắt được m&ocirc; h&igrave;nh v&agrave; nhu cầu của c&aacute;c doanh nghiệp sản xuất nội thất trong giai đoạn sale/marketing, Cabinet Vision 2021 tập trung cải thiện hiệu năng v&agrave; chất lượng h&igrave;nh ảnh được kết xuất cuối c&ugrave;ng nhằm tăng t&iacute;nh thuyết phục với kh&aacute;ch h&agrave;ng trong việc x&acirc;y dựng m&ocirc; h&igrave;nh kh&ocirc;ng gian nội thất sơ bộ. Trợ năng +Tour mới hỗ trợ người d&ugrave;ng lưu lại c&aacute;c g&oacute;c đặt camera v&agrave; tạo đoạn phim ngắn (Walkthrough), mang đến trải nghiệm ch&acirc;n thực chưa từng c&oacute;.</span></p>\r\n<p style=\"text-align: center;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><em><br /><img src=\"/storage/uploads/tinymce/sHiL5Fy9Lg9vMMg3eSK841a78uVoB7FTDKWN8r7T.png\" alt=\"walkthrough-cabinetvision2021\" width=\"600\" height=\"353\" /><br />T&iacute;nh năng Walkthough mới</em></span></p>\r\n<h2 style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>5. Cải thiện t&iacute;nh năng tối ưu h&oacute;a sơ đồ cắt</strong></span></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Cabinet Vision 2021 tối đa khả năng sử dụng nguy&ecirc;n liệu đầu v&agrave;o với việc bổ sung t&ugrave;y chọn Scrap Cut trong phần c&agrave;i đặt sử dụng m&aacute;y. Nguy&ecirc;n liệu hao ph&iacute; sẽ được chia nhỏ, đơn giản h&oacute;a việc loại bỏ ch&uacute;ng khi c&ocirc;ng việc rải v&aacute;n v&agrave; cắt v&aacute;n kết th&uacute;c.</span></p>\r\n<p style=\"text-align: center;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><em><br /><img src=\"/storage/uploads/tinymce/PM2ry9aKx0moXwOh0ozhwiIbIiFWqMP78LHi0jgo.png\" alt=\"scrap-cut-cabinetvision2021\" width=\"600\" height=\"312\" /><br />T&iacute;nh năng Scrap Cut</em></span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>','Các tính năng mới sẽ xuất hiện trong Cabinet Vision 2021',NULL,'cac-tinh-nang-moi-se-xuat-hien-trong-cabinet-vision-2021','Cabinet Vision hiện nay là giải pháp kỹ thuật hoàn thiện cho ngành sản xuất tủ gỗ công nghiệp. Qua từng phiên bản nâng cấp, phần mềm liên tục cải thiện hiệu năng, bổ sung các thuật toán và chức năng mới, hỗ trợ tối đa việc hoàn thiện quy trình từ thiết kế đến sản xuất cho các doanh nghiệp. Hiện tại, Cabinet Vision 2021 đang ở giai đoạn thử nghiệm với nhiều tính năng hoàn toàn mới. Sau đây là 5 điểm mới đáng chú ý trong phiên bản sắp tới','thiết kế nội thất, nội thất, nội thất gỗ, công nghệ gỗ, phần mềm gỗ, cabinet vision 2021','Published',2,NULL,1,1,'2020-12-16 20:15:02','2020-12-16 20:22:59',NULL),(19,'Những điểm nổi bật trong tạo hình đối tượng của Haixun 4','2020-11-22 11:01:00','1608178874-nhung-diem-noi-bat-trong-tao-hinh-doi-tuong-cua-haixun-4.jpg','Đầu năm nay, Haixun Software đã ra mắt Haixun 4.0, phiên bản này được đánh giá là cải tiện vượt trội so với các phiên bản tiền nhiệm, tối ưu mạnh mẽ ở tất cả các khâu từ thiết kế tới sản xuất. Hãy cùng Nghề nội thất điểm qua những nổi bật trong tạo hình đối tượng của Haixun 4.0.','<h2 style=\"text-align: justify;\"><strong><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">1. Thiết kế c&aacute;c h&igrave;nh dạng đặc biệt nhanh ch&oacute;ng </span></strong></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">&bull; Người d&ugrave;ng c&oacute; thể dễ d&agrave;ng thiết kế c&aacute;c h&igrave;nh dạng đặc biệt &nbsp;một c&aacute;ch nhanh ch&oacute;ng m&agrave; kh&ocirc;ng cần sử dụng bất cứ c&ocirc;ng cụ thiết kế hay c&aacute;c lệnh, m&atilde; phức tạp n&agrave;o.&nbsp;</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">&bull; C&aacute;c h&igrave;nh dạng đặc biệt n&agrave;y c&oacute; thể được lưu lại dựa tr&ecirc;n c&aacute;c th&ocirc;ng số, k&iacute;ch thước v&agrave;o thư viện dữ liệu cục bộ.&nbsp;</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">&bull; C&aacute;c &nbsp;tham số về mẫu bi&ecirc;n dạng n&agrave;y c&oacute; thể được t&iacute;nh to&aacute;n một c&aacute;ch tự động để c&oacute; thể sử dụng một c&aacute;ch trực tiếp, tiện lợi v&agrave; nhanh ch&oacute;ng ở c&aacute;c &nbsp;lần thiết kế sau.</span></p>\r\n<h2><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/LZT01Y4nKJJuW1q1Yf8BnEbAXyBp4FLoOjzhHpyI.png\" alt=\"hinh-dang-dac-biet-haixun\" width=\"600\" height=\"320\" /><br /><br /><strong><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">2. Thiết kế ngược (Reverse Modelling)</span></strong></h2>\r\n<p><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">T&iacute;nh năng Reverse Modeling cho ph&eacute;p thiết kế dựa tr&ecirc;n c&aacute;c mẫu c&oacute; sẵn v&agrave; lưu lại để c&oacute; thể sử dụng một c&aacute;ch nhanh ch&oacute;ng. C&aacute;c mẫu tủ n&agrave;y được lưu lại th&agrave;nh một mẫu trong cơ sở dữ liệu cục bộ của phần mềm. Trong c&aacute;c lần sử dụng tiếp theo, k&iacute;ch cỡ, chiều d&agrave;y tấm, tỉ lệ v&agrave; c&aacute;c th&ocirc;ng số kh&aacute;c c&oacute; thể được t&ugrave;y chỉnh theo nhu cầu, gi&uacute;p r&uacute;t ngắn thời gian thiết kế.&nbsp;</span></p>\r\n<p style=\"text-align: center;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><img src=\"/storage/uploads/tinymce/tPl6TZvJVhXTR4djaK2O6sNwPEJkiRE65cKlZqiy.png\" alt=\"thiet-ke-nguoc-haixun\" width=\"600\" height=\"321\" /></span></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<h2><strong><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">3. Sơ đồ lắp đặt </span></strong></h2>\r\n<p><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">H&igrave;nh ảnh tổng quan về tủ cho ph&eacute;p người sử dụng quan s&aacute;t to&agrave;n bộ c&aacute;c kết cấu cũng như cấu tr&uacute;c b&ecirc;n trong n&agrave;o chỉ trong gi&acirc;y l&aacute;t, từ đ&oacute; giảm tối đa lỗi ph&aacute;t sinh v&agrave; thuận tiện cho qu&aacute; tr&igrave;nh lắp đặt. C&aacute;c m&atilde; QR tự động c&oacute; thể qu&eacute;t bằng điện thoại th&ocirc;ng minh, từ đ&oacute; x&acirc;y dựng được sơ đồ lắp đặt với đầy đủ thứ tự c&aacute;c tấm bản cũng như c&aacute;c t&ugrave;y chỉnh về vật liệu ph&ugrave; hơp với nhu cầu sản xuất.</span></p>\r\n<p><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/Wtw75P3JYMrTIf1R6tivgUoVFN5LQXErtmGrM9AV.png\" alt=\"so-do-lap-dat-haixun4\" width=\"600\" height=\"321\" /></span></p>\r\n<h2><strong><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">4. Thiết kế tạo h&igrave;nh 6 mặt</span></strong></h2>\r\n<p><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Kiểu thiết kế 3D s&aacute;u mặt được sử dụng nhằm dựng c&aacute;c tủ chữ L v&agrave; tủ h&igrave;nh chữ U. Người d&ugrave;ng c&oacute; thể t&ugrave;y chỉnh c&aacute;c g&oacute;c nh&igrave;n kh&aacute;c nhau, từ đ&oacute; x&acirc;y dựng c&aacute;c bản vẽ kỹ thuật. C&ugrave;ng với đ&oacute;, v&aacute;n v&agrave; c&aacute;c chi tiết như ngăn k&eacute;o cũng c&oacute; thể được th&ecirc;m v&agrave;o t&ugrave;y &yacute;. &nbsp;</span></p>\r\n<p><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/v1qGlNHBTuX2eucbHCb9vYvJ6Y35GUz0OaTaCfPl.png\" alt=\"tao-hinh-6-mat-haixun4\" width=\"600\" height=\"319\" /></span></p>\r\n<h2><strong><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">5. Xuất v&agrave; nhập CAD</span></strong></h2>\r\n<p><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">C&aacute;c chi tiết CAD c&oacute; thể được th&ecirc;m v&agrave;o v&agrave; tự động điều chỉnh theo kh&ocirc;ng gian thiết kế c&oacute; sẵn. C&aacute;c chi tiết n&agrave;y c&oacute; thể lưu được th&agrave;nh c&aacute;c mẫu v&agrave; cập nhật v&agrave;o trong thư viện &nbsp;cơ sở dữ liệu cục bộ. C&aacute;c k&iacute;ch cỡ, tỉ lệ v&agrave; c&aacute;c th&ocirc;ng số c&oacute; thể dễ d&agrave;ng điều chỉnh phục vụ mục đ&iacute;ch sử dụng l&acirc;u d&agrave;i. C&aacute;c bản vẽ 3D, c&aacute;c h&igrave;nh dạng đặc biệt dạng CAD, v.v&hellip; cũng được hỗ trợ xuất nhập nhanh ch&oacute;ng.</span></p>\r\n<p style=\"text-align: center;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/HlRYCOgdww0DD6vxg81XrMmbMxFBXqiilTG3zZVL.png\" alt=\"xuat-nhap-cad-haixun4\" width=\"600\" height=\"320\" /><br /><img src=\"/storage/uploads/tinymce/4wE8Uld3UEFWbA9v05kkjQKVAQDQMR0nR9baJFaI.png\" alt=\"xuat-nhap-cad-haixun4\" width=\"600\" height=\"320\" /></span></p>\r\n<p>&nbsp;</p>\r\n<h2><strong><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">6. Tự động căn chỉnh k&iacute;ch thước</span></strong></h2>\r\n<p><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Vị tr&iacute;, k&iacute;ch thước của c&aacute;c tấm c&oacute; thể thay đổi v&agrave; tự động điều chỉnh theo vị tr&iacute;, k&iacute;ch thước của kh&ocirc;ng gian c&oacute; li&ecirc;n quan. Sau thiết kế, k&iacute;ch thước của c&aacute;c kh&ocirc;ng gian tủ c&oacute; thể được t&ugrave;y chỉnh một c&aacute;ch tự do. T&iacute;nh năng n&agrave;y gi&uacute;p giảm c&aacute;c thao t&aacute;c x&oacute;a, căn chỉnh cũng như t&iacute;nh to&aacute;n trong qu&aacute; tr&igrave;nh thiết kế, gi&uacute;p cho việc thiết kế trở n&ecirc;n linh hoạt hơn.&nbsp;</span></p>\r\n<p style=\"text-align: center;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><img src=\"/storage/uploads/tinymce/npLJTc1N7TwJnptOvRX0cuclUXv7LtRPtn6fcCCJ.png\" alt=\"can-chinh-kich-thuoc-haixun\" width=\"600\" height=\"319\" /></span></p>\r\n<h2><strong><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">7. Thiết kế c&aacute;c g&oacute;c v&aacute;t nhanh ch&oacute;ng</span></strong></h2>\r\n<p><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Việc thực hiện chỉnh sửa c&aacute;c g&oacute;c v&aacute;t v&agrave; tạo h&igrave;nh theo gầm cầu thang được Haixun 4.0 hỗ trợ tối đa. C&aacute;c th&ocirc;ng số như vị tr&iacute; lỗ khoan, g&oacute;c nghi&ecirc;ng, hay tấm nghi&ecirc;ng được tạo v&agrave; t&ugrave;y chỉnh theo thiết kế thực tế, đảm bảo y&ecirc;u cầu thẩm mỹ v&agrave; t&iacute;nh thực tiễn trong sản xuất&nbsp;</span></p>\r\n<p style=\"text-align: center;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><img src=\"/storage/uploads/tinymce/RHPFAGlyLs9Cagc29c35YsQOVurdBSV3MqI5hHQ5.png\" alt=\"goc-vat-haixun\" width=\"600\" height=\"320\" /></span></p>\r\n<h2><strong><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">8. Thiết kế tủ rượu</span></strong></h2>\r\n<p><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Người d&ugrave;ng c&oacute; thể tạo ra c&aacute;c mẫu tủ rượu nhanh ch&oacute;ng chỉ với 1 số thao t&aacute;c đơn giản . C&aacute;c chi tiết như d&aacute;n cạnh, r&atilde;nh soi, k&iacute;ch thước v&agrave; c&aacute;c th&ocirc;ng số của tủ rượu c&oacute; thể được điều chỉnh tự do, v&agrave; khoảng c&aacute;ch của tủ rượu c&oacute; thể được t&iacute;nh to&aacute;n v&agrave; sửa đổi dựa tr&ecirc;n những ti&ecirc;u chuẩn đ&atilde; được &aacute;p dụng phổ biến tr&ecirc;n thị trường.</span></p>\r\n<p><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/D2e7UZGWdi8x8tU9kVQbyYAri4EQuqKNulKCdo5J.png\" alt=\"thiet-ke-tu-ruou-haixun\" width=\"600\" height=\"320\" /></span></p>\r\n<h2><strong><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">9. Điều chỉnh tham số</span></strong></h2>\r\n<p style=\"text-align: center;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">C&aacute;c phụ kiện như ray trượt, tay nắm, bản lề, trụ tay nắm,&hellip; c&oacute; thể được th&ecirc;m v&agrave;o một c&aacute;ch tự động. Vị tr&iacute; lỗ gia c&ocirc;ng cũng c&oacute; thể được th&ecirc;m v&agrave;o tự động hoặc điều chỉnh theo nhu cầu sản xuất.</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">&nbsp;</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">&nbsp;<img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/pRy1Yypd79WKeLMDKdknQDb3hyaO02kPH1Lc28bQ.png\" alt=\"dieu-chinh-tham-so-haixun\" width=\"600\" height=\"590\" /><br /></span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><img src=\"/storage/uploads/tinymce/1wY7FcWUdOOzDi8U2Jln7bcY49TRI7gtsgYYIPmI.png\" alt=\"dieu-chinh-tham-so-haixun\" width=\"600\" height=\"593\" />&nbsp;</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">&nbsp;</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">&nbsp;</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">&nbsp;</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">&nbsp;</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">&nbsp;</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">&nbsp;</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">&nbsp;</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>','Những điểm nổi bật trong tạo hình đối tượng của Haixun 4',NULL,'nhung-diem-noi-bat-trong-tao-hinh-doi-tuong-cua-haixun-4','Đầu năm nay, Haixun Software đã ra mắt Haixun 4.0, phiên bản này được đánh giá là cải tiện vượt trội so với các phiên bản tiền nhiệm, tối ưu mạnh mẽ ở tất cả các khâu từ thiết kế tới sản xuất. Hãy cùng Nghề nội thất điểm qua những nổi bật trong tạo hình đối tượng của Haixun 4.0.','thiết kế nội thất, nội thất, nội thất gỗ, công nghệ gỗ, phần mềm gỗ','Published',2,NULL,1,1,'2020-12-16 21:21:14','2020-12-16 21:21:14',NULL),(20,'Haixun Software - Khuyến mãi đặc biệt cuối năm','2020-11-30 14:37:00','1608277747-haixun-software-khuyen-mai-dac-biet-cuoi-nam.png','Nhân dịp cuối năm 2020, Haixun Software thực hiện chương trình khuyến mãi đặc biệt cho mọi khách hàng mua bản quyền phần mềm.','<p style=\"text-align: justify;\">Từ ng&agrave;y 01/12 đến hết ng&agrave;y 31/12, Haixun software thực hiện chương tr&igrave;nh ưu đ&atilde;i đặc biệt duy nhất trong năm:</p>\r\n<p style=\"text-align: center;\"><strong>Giảm gi&aacute; 10% cho mọi license phần mềm Haixun</strong></p>\r\n<p><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/JeJNkadKGdydpfWYruLkxU3ACaPHbQ2pYfepYsYs.jpeg\" alt=\"khuyen-mai-haixun\" width=\"600\" height=\"333\" /></p>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: justify;\">Đ&acirc;y l&agrave; chương tr&igrave;nh ưu đ&atilde;i đặc biệt, qu&yacute; kh&aacute;ch h&agrave;ng v&agrave; bạn đọc của Nghề nội thất c&oacute; thể tận dụng để đầu tư hiệu quả cho năm 2021 sắp tới.</p>\r\n<p style=\"text-align: justify;\"><a href=\"/san-pham/phan-mem-noi-that-go-haixun\" target=\"_blank\" rel=\"noopener\"><strong>Phần mềm thiết kế v&agrave; sản xuất nội thất Haixun</strong></a>&nbsp;l&agrave; một phần mềm hỗ trợ to&agrave;n bộ qu&aacute; tr&igrave;nh sản xuất đồ gỗ từ thiết kế, b&oacute;c t&aacute;ch, dự to&aacute;n nguy&ecirc;n vật liệu, điều khiển m&aacute;y cưa, m&aacute;y khoan, quản l&yacute; kho vật tư, bao g&oacute;i v.v&hellip; gi&uacute;p tối ưu chi ph&iacute; v&agrave; năng suất. Haixun lu&ocirc;n nỗ lực để trở th&agrave;nh phần mềm nội thất h&agrave;ng đầu, đơn giản nhất nhưng khả năng ứng dụng cao nhất, v&agrave; cung cấp giải ph&aacute;p t&iacute;ch hợp \"Từ thiết kế - quản l&yacute; tới gia c&ocirc;ng - sản xuất\" cho ng&agrave;nh c&ocirc;ng nghiệp nội thất.&nbsp;</p>\r\n<p style=\"text-align: justify;\">Li&ecirc;n hệ đội ngũ của ch&uacute;ng t&ocirc;i để được tư vấn chi tiết:<br />Nghề nội thất<br />Trung t&acirc;m thương mại Golden Land, 275 Nguyễn Tr&atilde;i, Thanh Xu&acirc;n, H&agrave; Nội<br />Điện thoại: 0868934576</p>','Haixun Software - Khuyến mãi đặc biệt cuối năm',NULL,'haixun-software-khuyen-mai-dac-biet-cuoi-nam','Nhân dịp cuối năm 2020, Haixun Software thực hiện chương trình khuyến mãi đặc biệt cho mọi khách hàng mua bản quyền phần mềm.','thiết kế nội thất, nội thất, nội thất gỗ, công nghệ gỗ, phần mềm gỗ, haixun','Published',2,NULL,1,2,'2020-12-18 00:49:07','2020-12-18 00:49:07',NULL),(21,'Hướng dẫn tạo chốt cam âm chữ U không lộ liên kết trong Cabinet Vision','2020-12-24 11:01:00','1609126564-huong-dan-tao-chot-cam-am-chu-u-khong-lo-lien-ket-trong-cabinet-vision.jpg','Chốt cam âm chữ U là công nghệ mới nhất thay thế Cam 3 chi tiết truyền thống. Loại liên kết ngày được sử dụng cho các máy CNC, máy khoan ngang, máy khoan dàn hoặc các dụng cụ cầm tay để soi. Theo lý thuyết, việc lắp đặt các cam chữ U trong loại liên kết này tiết kiệm đến 60% thời gian so với cách làm với cam 3 chi tiết. Thêm vào đó, tính thẩm mỹ cũng là một ưu thế khi đặc tính của liên kết âm chữ U sẽ không để lộ vị trí lắp đặt ở sản phẩm cuối cùng.','<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><audio class=\"audio-for-speech\"></audio></span></p>\r\n<h2 class=\"translate-icons\" style=\"text-align: justify;\"><strong><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">1. Chốt cam &acirc;m chữ U</span></strong></h2>\r\n<p class=\"translate-icons\" style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Chốt cam &acirc;m chữ U l&agrave; c&ocirc;ng nghệ mới nhất thay thế cam 3 chi ti&ecirc;́t truyền thống. Loại li&ecirc;n kết ng&agrave;y được sử dụng cho c&aacute;c m&aacute;y CNC, m&aacute;y khoan ngang, m&aacute;y khoan d&agrave;n hoặc c&aacute;c dụng cụ cầm tay để soi. Chốt cam &acirc;m chữ U đang ng&agrave;y c&agrave;ng được nhiều đơn vị sản xuất nội thất sử dụng do c&aacute;c ưu điểm sau:</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- Gi&aacute; th&agrave;nh rẻ</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- Lắp đặt nhanh</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><span style=\"text-align: justify;\">- Th&aacute;o ra lắp vào thuận tiện dễ d&agrave;ng<br /></span>- Kh&ocirc;ng lộ chi ti&ecirc;́t li&ecirc;n kết giống như cam nh&ocirc;m</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- Giảm chi ph&iacute; lao động v&agrave; vận chuyển trong khi tăng gấp đ&ocirc;i c&ocirc;ng suất - kh&ocirc;ng cần đầu tư th&ecirc;m vốn.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<h2 style=\"text-align: justify;\"><strong><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">2. C&aacute;ch th&ecirc;m li&ecirc;n kết &acirc;m chữ U trong Cabinet Vision:</span></strong></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">&nbsp; &nbsp; &nbsp; &nbsp; Để th&ecirc;m li&ecirc;n kết &acirc;m chữ U trong Cabinet Vision, người d&ugrave;ng sẽ tiến h&agrave;nh th&ecirc;m c&aacute;c g&oacute;i c&agrave;i đặt (Setup Package) cần thiết để phần mềm tự động x&acirc;y dựng c&aacute;c ti&ecirc;u chuẩn người d&ugrave;ng (UCS) c&oacute; thể t&ugrave;y biến theo nhu cầu sản xuất đặc th&ugrave; của từng doanh nghiệp</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">C&aacute;c bước tiến h&agrave;nh:</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">B1: Tải về Setup Package cần thiết</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">&nbsp;<a href=\"/storage/img/document/1608781612-cv12-lockdowel-setup-package.pkg\">CV12 Lockdowel Setup Package</a></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">&nbsp;<a href=\"/storage/img/document/1608781675-cv12-standard-drawer-rollouts-construction.pkg\">CV12 Standard Drawer Rollouts Construction</a></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">&nbsp;<a href=\"/storage/img/document/1608781740-cv12-horizontal-clip-standard-drawer-rollouts-construction-update.pkg\">CV12 Horizontal Clip Standard Drawer Rollouts Construction Update</a></span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">B2:&nbsp; Truy cập <strong>Ultilities</strong> ----&gt;<strong> Setup Packages</strong></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/1QLZAl51tYKoS2K8fWCy1EaGecspy8ynCFLijUan.png\" alt=\"Setup-Packages-Cabinet-vision\" width=\"600\" height=\"310\" /></strong></span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">B3. Chọn c&aacute;c Setup Package vừa tải về</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/CwsQrxD7hDBEx2KHviPAahc4UONRpfzP3m6Tr5uo.png\" alt=\"\" width=\"600\" height=\"310\" /></span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">B4. Chọn <strong>Swap Between Creation and Import Modes</strong></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/P2XCz64DR6Rr9cggj1eW5B1A3jtpZ1XLZnTwIIz5.png\" alt=\"\" width=\"600\" height=\"310\" /></strong></span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">B5. Chọn <strong>Import Package Contents</strong></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/nYqvjAVmLATl5AzhBU8b8IF6oZde9owCwK1wGRPg.png\" alt=\"import-package-cabinetvision\" width=\"600\" height=\"310\" /></strong></span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Kết quả:</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/EHLqrjjAgT46Me9J4bN2bI62ho6UB10Rw04eZGtR.png\" alt=\"\" width=\"600\" height=\"309\" /></span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<h2 style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>3. Sử dụng li&ecirc;n kết &acirc;m chữ U trong Cabinet Vision:&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</strong>&nbsp;&nbsp;&nbsp;</span></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Sau khi đ&atilde; th&ecirc;m c&aacute;c Setup Package cần thiết, người d&ugrave;ng c&oacute; thể t&ugrave;y biến k&iacute;ch thước, vị tr&iacute; c&aacute;c chốt &acirc;m chữ U với bảng th&ocirc;ng số thuộc t&iacute;nh nằm b&ecirc;n tr&aacute;i giao diện thiết kế</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/m4BzGJbovieP9eInOh6INAXm8DnMhZ0XpWsCEMGx.png\" alt=\"lien-ket-U-cabinet-vision\" width=\"600\" height=\"309\" /></span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Kết quả:</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/7EwBOuV7wT8IgQG6quo1CZlOfgNVfLn808UUNz5h.png\" alt=\"\" width=\"600\" height=\"309\" /></span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>','Hướng dẫn tạo chốt cam âm chữ U không lộ liên kết trong Cabinet Vision',NULL,'huong-dan-tao-chot-cam-am-chu-u-khong-lo-lien-ket-trong-cabinet-vision','Chốt cam âm chữ U là công nghệ mới nhất thay thế Cam 3 chi tiết truyền thống. Loại liên kết ngày được sử dụng cho các máy CNC, máy khoan ngang, máy khoan dàn hoặc các dụng cụ cầm tay để soi. Theo lý thuyết, việc lắp đặt các cam chữ U trong loại liên kết này tiết kiệm đến 60% thời gian so với cách làm với cam 3 chi tiết. Thêm vào đó, tính thẩm mỹ cũng là một ưu thế khi đặc tính của liên kết âm chữ U sẽ không để lộ vị trí lắp đặt ở sản phẩm cuối cùng.','nội thất gỗ, gỗ công nghiệp, liên kết âm chữ U, cabinet vision','Published',2,NULL,0,100,'2020-12-23 21:14:53','2020-12-28 01:09:20',NULL),(22,'Ngành gỗ nội thất: Cạnh tranh bằng công nghệ','2020-12-12 09:27:00','1609122930-nganh-go-noi-that-canh-tranh-bang-cong-nghe.jpg','Để đạt mục tiêu kim ngạch xuất khẩu (XK) 20 tỷ USD vào năm 2025 của ngành gỗ Việt Nam, nhiều doanh nghiệp (DN) chế biến gỗ trong nước đã chủ động ứng dụng công nghệ trong sản xuất, quản trị DN và bán hàng.','<h2 style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>B&agrave;i học từ Malaysia</strong></span></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Hội nhập kinh tế quốc tế gi&uacute;p ng&agrave;nh c&ocirc;ng nghiệp chế biến (CNCB) gỗ của Việt Nam thay đổi t&iacute;ch cực trong những năm qua, sản lượng v&agrave; chất lượng sản phẩm tăng cao, được ti&ecirc;u thụ rộng r&atilde;i ở nhiều nước tr&ecirc;n thế giới. Tuy nhi&ecirc;n, b&ecirc;n cạnh cơ hội, ng&agrave;nh CNCB gỗ v&agrave; l&acirc;m sản Việt Nam hiện đang phải đối mặt với sức &eacute;p cạnh tranh từ Trung Quốc, Đ&agrave;i Loan v&agrave; c&aacute;c nước trong khu vực&hellip;</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Theo kinh nghiệm từ Malaysia, để khắc phục những tồn tại tr&ecirc;n, c&ocirc;ng nghệ được xem l&agrave; giải ph&aacute;p quan trọng, gi&uacute;p DN chế biến gỗ n&acirc;ng cao năng suất, chất lượng sản phẩm.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Cụ thể, những năm gần đ&acirc;y, Malaysia XK khoảng 23 tỷ USD gỗ v&agrave; sản phẩm từ gỗ mỗi năm, chủ yếu bao gồm đồ gỗ v&agrave; c&aacute;c sản phẩm panel như MDF v&agrave; v&aacute;n &eacute;p. Để đạt được kết quả n&agrave;y, c&aacute;c nh&agrave; sản xuất Malaysia đ&atilde; quyết liệt trong đầu tư c&ocirc;ng nghệ cho chế biến s&acirc;u, ph&aacute;t triển c&ocirc;ng nghiệp hỗ trợ (CNHT), coi đ&oacute; l&agrave; điều kiện quan trọng để giữ vị thế đứng đầu Đ&ocirc;ng Nam &Aacute; trong chế biến gỗ.</span></p>\r\n<p><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/ua7JiCWZrfLgrUQWvVOsxKHl1wtKLEgkmuOX3o9v.jpeg\" alt=\"\" width=\"650\" height=\"393\" /></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">C&ugrave;ng với c&ocirc;ng nghệ, c&aacute;c DN Malaysia c&ograve;n ph&aacute;t triển c&aacute;c sản phẩm CNHT cho ng&agrave;nh gỗ, đơn cử như keo gắn gỗ v&agrave; c&aacute;c vật liệu ngo&agrave;i gỗ. V&igrave; thực tế, keo gắn gỗ c&oacute; thể đ&oacute;ng g&oacute;p đến 30-35% gi&aacute; trị sản phẩm của ng&agrave;nh CNCB gỗ nh&acirc;n tạo. Do đ&oacute;, để c&oacute; thể l&agrave;m chủ từ kh&acirc;u thiết kế, việc kiểm so&aacute;t tốt c&aacute;c sản phẩm phụ kiện n&agrave;y hết sức quan trọng, cho ng&agrave;nh Malaysia tiếp tục ph&aacute;t triển trong bối cảnh cạnh tranh to&agrave;n cầu gay gắt v&agrave; nhiều biến động.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Ng&agrave;nh CNCB đồ gỗ của Malaysia cũng ch&uacute; trọng nghi&ecirc;n cứu v&agrave; ph&aacute;t triển (R&amp;D), nhằm tạo ra c&aacute;c sản phẩm th&iacute;ch ứng với thị trường v&agrave; bảo vệ sức khỏe người ti&ecirc;u d&ugrave;ng&hellip; Để ho&agrave;n thiện chuỗi gi&aacute; trị, Malaysia c&ograve;n th&agrave;nh lập một trung t&acirc;m nội thất tập trung, nơi tất cả c&aacute;c hoạt động li&ecirc;n quan đến ng&agrave;nh, bao gồm: Từ thiết kế v&agrave; đ&agrave;o tạo, R&amp;D c&aacute;c sản phẩm CNHT được đặt tại một địa điểm v&igrave; lợi &iacute;ch của tất cả c&aacute;c DN trong ng&agrave;nh.</span></p>\r\n<h2><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>Kh&ocirc;ng c&oacute; lựa chọn</strong></span></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Theo &ocirc;ng Nguyễn Quốc Khanh - Chủ tịch Hội thủ c&ocirc;ng mỹ nghệ v&agrave; chế biến gỗ TP. Hồ Ch&iacute; Minh (HAWA): Với l&agrave;n s&oacute;ng đầu tư nước ngo&agrave;i đang dịch chuyển v&agrave;o Việt Nam dẫn đến t&igrave;nh trạng khan hiếm lao động. Điều n&agrave;y đ&atilde; khiến c&aacute;c DN chế biến gỗ Việt Nam đối diện với nhiều kh&oacute; khăn, do vừa phải giải quyết những vấn đề nội tại để đảm bảo chất lượng, đ&aacute;p ứng đơn h&agrave;ng, gia tăng năng suất thu h&uacute;t kh&aacute;ch h&agrave;ng mới, mặt kh&aacute;c phải linh hoạt, để trụ vững v&agrave; đ&oacute;n đầu những thay đổi trong tương lai.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">B&agrave;i to&aacute;n m&agrave; DN chế biến gỗ Việt Nam đang đối mặt kh&ocirc;ng đơn giản. &ldquo;DN trong ng&agrave;nh cần c&oacute; một tầm nh&igrave;n mới, một tư duy s&acirc;u. Ch&igrave;a kh&oacute;a để c&ugrave;ng l&uacute;c giải hai b&agrave;i to&aacute;n ấy l&agrave; tư duy lại m&ocirc; h&igrave;nh sản xuất của m&igrave;nh, ứng dụng c&ocirc;ng nghệ để gia tăng nội lực&rdquo;, &ocirc;ng Nguyễn Quốc Khanh nhận định.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">&Yacute; thức được xu thế n&agrave;y, nhiều DN chế biến gỗ của Việt Nam đ&atilde; chủ động đổi mới c&ocirc;ng nghệ. Điển h&igrave;nh l&agrave; C&ocirc;ng ty TNHH Sản xuất kinh doanh v&agrave; Vận tải Ti&ecirc;n Phong (Th&aacute;i B&igrave;nh), đ&atilde; đầu tư hơn 3 tỷ đồng &aacute;p dụng c&ocirc;ng nghệ mới nhằm cải tiến d&acirc;y chuyền gh&eacute;p gỗ, gh&eacute;p thanh tự động. Nhờ đ&oacute; đ&atilde; giảm chi ph&iacute; v&agrave; nh&acirc;n lực lao động 2 lần so với c&ocirc;ng nghệ cũ, năng suất, chất lượng sản phẩm cũng tăng cao. Duy tr&igrave; ổn định c&aacute;c đơn h&agrave;ng v&agrave; tạo việc l&agrave;m cho gần 200 lao động, với mức lương b&igrave;nh qu&acirc;n từ 5 - 7 triệu đồng; thực hiện nộp ng&acirc;n s&aacute;ch nh&agrave; nước gần 300 triệu đồng/1 năm.</span></p>\r\n<p style=\"text-align: justify;\"><em><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Theo Thu Hường - Tạp tr&iacute; C&ocirc;ng Thương</span></em></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>','Ngành gỗ nội thất: Cạnh tranh bằng công nghệ',NULL,'nganh-go-noi-that-canh-tranh-bang-cong-nghe','Để đạt mục tiêu kim ngạch xuất khẩu (XK) 20 tỷ USD vào năm 2025 của ngành gỗ Việt Nam, nhiều doanh nghiệp (DN) chế biến gỗ trong nước đã chủ động ứng dụng công nghệ trong sản xuất, quản trị DN và bán hàng.','nội thất, nội thất gỗ, công nghệ gỗ, phần mềm gỗ','Published',2,NULL,1,3,'2020-12-27 19:35:30','2020-12-27 19:40:05',NULL),(23,'6 sai lầm khi thiết kế căn hộ có diện tích nhỏ','2020-12-27 11:02:00','1609128553-6-sai-lam-khi-thiet-ke-can-ho-co-dien-tich-nho.jpg','Hiện nay, những căn hộ có diện tích vừa và nhỏ được rất nhiều các gia đình trẻ yêu thích và lựa chọn. Tuy nhiên, lựa chọn những căn hộ hạn chế về diện tích có thể dẫn tới một số khó khăn trong quá trình thiết kế, trang trí căn hộ về sau. Nếu không có đủ trình độ có thể dẫn tới một số sai lầm khi thiết kế căn hộ cho gia đình mình. Hãy cùng Nghề nội thất điểm qua một vài sai lầm nhiều người thường mắc phải trong quá trình thiết kế những căn hộ như vậy nhé.','<h2 style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>1. Chọn sai phong c&aacute;ch thiết kế</strong></span></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Phong c&aacute;ch thiết kế đ&oacute;ng vai tr&ograve; v&ocirc; c&ugrave;ng quan trọng trong việc tạo n&ecirc;n kh&ocirc;ng gian sống. Đối với c&aacute;c căn hộ c&oacute; diện t&iacute;ch nhỏ việc chọn đ&uacute;ng phong c&aacute;ch thiết kế căn hộ lại đ&oacute;ng vai tr&ograve; quan trọng hơn.</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Hiện nay, c&oacute; rất nhiều người mắc sai lầm khi chọn sai phong c&aacute;ch thiết kế cho căn hộ nhỏ. Bạn biết đấy, với diện t&iacute;ch hạn chế ch&uacute;ng ta n&ecirc;n lựa chọn phong c&aacute;ch đơn giản, hiện đại thay v&igrave; những thiết kế mang t&iacute;nh chất rườm r&agrave;.</span></p>\r\n<h2 style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>2. Chưa tận dụng được hết kh&ocirc;ng gian</strong></span></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Hạn chế lớn nhất của những căn hộ nhỏ đ&oacute; ch&iacute;nh l&agrave; về diện t&iacute;ch cũng như kh&ocirc;ng gian bị b&oacute; hẹp. Ch&iacute;nh v&igrave; vậy, trong qu&aacute; tr&igrave;nh thiết kế những căn hộ n&agrave;y, c&aacute;c bạn n&ecirc;n lưu &yacute; cần phải tận dụng tối đa mọi kh&ocirc;ng gian.</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Việc tận dụng hết kh&ocirc;ng gian sẽ khiến c&ocirc;ng năng của căn hộ được đảm bảo. C&aacute;c th&agrave;nh vi&ecirc;n trong gia đ&igrave;nh vẫn cảm thấy thoải m&aacute;i trong sinh hoạt, nghỉ ngơi h&agrave;ng ng&agrave;y. Nếu kh&ocirc;ng biết c&aacute;ch tận dụng hết kh&ocirc;ng gian, diện t&iacute;ch vốn c&oacute;, chắc chắn đ&oacute; l&agrave; một sai lầm lớn khi thiết kế căn hộ m&agrave; bạn đ&atilde; mắc phải.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><img src=\"/storage/uploads/tinymce/fbKIaGQSJNgoRu5yGC65K9C7wYCcW2p7KFCbsCPI.jpeg\" alt=\"sai-lam-thiet-ke-1\" width=\"700\" height=\"442\" /></span></p>\r\n<h2><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>3. Kh&ocirc;ng biết kết hợp giữa m&agrave;u sắc v&agrave; &aacute;nh s&aacute;ng</strong></span></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Để kh&ocirc;ng gian c&aacute;c căn hộ nhỏ hẹp v&agrave; chật chội trở n&ecirc;n tho&aacute;ng đ&atilde;ng hơn, bạn n&ecirc;n kết hợp m&agrave;u sắc v&agrave; &aacute;nh s&aacute;ng. Tuy nhi&ecirc;n, kh&ocirc;ng phải ai trong số ch&uacute;ng ta cũng biết tận dụng được sự kết hợp mang lại hiệu quả đ&aacute;nh lừa thị gi&aacute;c cực cao n&agrave;y. Thậm ch&iacute;, một số người c&ograve;n khiến căn hộ của m&igrave;nh trở n&ecirc;n chật chội hơn khi sử dụng m&agrave;u sắc kh&ocirc;ng ch&iacute;nh x&aacute;c như m&agrave;u qu&aacute; l&ograve;e loẹt.</span></p>\r\n<h2 style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>4. Cứng nhắc khi thiết kế căn hộ</strong></span></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Một sai lầm nhiều người thường mắc phải nữa đ&oacute; ch&iacute;nh l&agrave; qu&aacute; cứng nhắc trong qu&aacute; tr&igrave;nh thiết kế căn hộ đặc biệt l&agrave; c&aacute;c căn hộ c&oacute; diện t&iacute;ch nhỏ.</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Bạn biết đấy, thiết kế, trang tr&iacute; căn hộ nhằm mục đ&iacute;ch tạo n&ecirc;n sự h&agrave;i h&ograve;a trong bố cục căn hộ mang lại sự tiện dụng thoải m&aacute;i trong qu&aacute; tr&igrave;nh sinh sống. Tuy nhi&ecirc;n, mỗi căn hộ lại c&oacute; một đặc điểm ri&ecirc;ng. Ch&iacute;nh v&igrave; vậy, trong qu&aacute; tr&igrave;nh thiết kế điều cần thiết l&agrave; phải c&oacute; sự ứng biến linh hoạt. Phải thiết kế l&agrave;m sao để căn hộ kh&ocirc;ng qu&aacute; rợp khu&ocirc;n những căn hộ kh&aacute;c vừa kh&aacute;c biệt lại vừa thoải m&aacute;i, rộng r&atilde;i hơn.</span></p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/ruI9TgsWGqZ3XmyFRUh2SrpbVBxrLH91CKjknWxO.jpeg\" alt=\"sai-lam-thiet-ke-noi-that\" width=\"700\" height=\"527\" /></span></p>\r\n<h2 style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>5. Kh&ocirc;ng sử dụng nội thất th&ocirc;ng minh</strong></span></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Hiện nay, nội thất th&ocirc;ng minh được ứng dụng kh&aacute; rộng r&atilde;i trong lĩnh vực thiết kế. Đ&acirc;y được xem như một giải ph&aacute;p ho&agrave;n hảo nhằm mang tới một kh&ocirc;ng gian rộng r&atilde;i hơn cho những căn hộ nhỏ v&agrave; vừa. </span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Thật sai lầm nếu trong qu&aacute; tr&igrave;nh thiết kế những căn hộ như vậy m&agrave; bạn lại &ldquo;bỏ qu&ecirc;n&rdquo; giải ph&aacute;p quan trọng ấy. Do đ&oacute;, đừng ngần ngại sử dụng nội thất th&ocirc;ng minh trong khi thiết kế căn hộ cho m&igrave;nh nh&eacute;.</span></p>','6 sai lầm khi thiết kế căn hộ có diện tích nhỏ',NULL,'6-sai-lam-khi-thiet-ke-can-ho-co-dien-tich-nho','Hiện nay, những căn hộ có diện tích vừa và nhỏ được rất nhiều các gia đình trẻ yêu thích và lựa chọn. Tuy nhiên, lựa chọn những căn hộ hạn chế về diện tích có thể dẫn tới một số khó khăn trong quá trình thiết kế, trang trí căn hộ về sau. Nếu không có đủ trình độ có thể dẫn tới một số sai lầm khi thiết kế căn hộ cho gia đình mình. Hãy cùng Nghề nội thất điểm qua một vài sai lầm nhiều người thường mắc phải trong quá trình thiết kế những căn hộ như vậy nhé.','thiết kế nội thất, nội thất, nội thất gỗ, công nghệ gỗ, phần mềm gỗ','Published',2,NULL,0,NULL,'2020-12-27 21:09:13','2020-12-27 21:13:22',NULL),(24,'Cách chọn bàn ăn phù hợp với phòng bếp của gia đình','2020-12-12 14:41:00','1609142355-cach-chon-ban-an-phu-hop-voi-phong-bep-cua-gia-dinh.jpg','Khi thiết kế nội thất cho phòng bếp, việc chọn một bộ bàn ăn sang trọng, phù hợp là rất cần thiết. Vậy khi chọn mua một bộ bàn ăn, chúng ta cần lưu ý đến những tiêu chí nào của chúng? Nghề nội thất sẽ định hướng cho bạn qua bài viết dưới đây!','<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">T&ugrave;y v&agrave;o phong c&aacute;ch, bạn sẽ thấy c&oacute; rất nhiều loại b&agrave;n ăn kh&aacute;c nhau. C&oacute; chiếc được chau chuốt cầu kỳ, tỉ mỉ, sử dụng những đường n&eacute;t uốn cong mềm mại, những đường chạm khắc qu&yacute; tộc theo kiểu cổ điển ch&acirc;u &Acirc;u. C&oacute; những loại đơn giản, mộc mạc trơn nhẵn. Cũng c&oacute; loại ph&aacute; c&aacute;ch kết hợp c&aacute;c họa tiết h&igrave;nh học ừa tr&ograve;n vừa vu&ocirc;ng theo phong c&aacute;ch đương đại.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Điều ti&ecirc;n quyết trong việc lựa chọn phong c&aacute;ch của chiếc b&agrave;n l&agrave; xem x&eacute;t nội thất nh&agrave; bạn đang đi theo phong c&aacute;ch thiết kế n&agrave;o. </span><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Bạn kh&ocirc;ng thể trang ho&agrave;ng cho kh&ocirc;ng gian hiện đại, sử dụng c&aacute;c chất liệu mới, đồ đa năng bằng một chiếc b&agrave;n ăn theo phong c&aacute;ch cổ điển được. Sự lạc l&otilde;ng v&agrave; kh&ocirc;ng thống nhất về chủ đề thiết kế ch&iacute;nh l&agrave; điều tối kỵ. Sự kh&aacute;c biệt phải tạo th&agrave;nh điểm nhấn v&agrave; h&agrave;i h&ograve;a với c&aacute;c đồ nội thất kh&aacute;c trong ph&ograve;ng thay v&igrave; ph&aacute; hỏng phong c&aacute;ch vốn c&oacute;.</span></p>\r\n<h2><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>Lựa chọn phong c&aacute;ch của b&agrave;n ăn ph&ugrave; hợp với ph&ograve;ng bếp</strong></span></h2>\r\n<p><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/GOYf38jeTSY2ZthPASCwdUtDaqstcH7sM1gfF3uB.jpeg\" alt=\"\" width=\"700\" height=\"338\" /></strong></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">T&ugrave;y v&agrave;o phong c&aacute;ch, bạn sẽ thấy c&oacute; rất nhiều loại b&agrave;n ăn kh&aacute;c nhau. C&oacute; chiếc được chau chuốt cầu kỳ, tỉ mỉ, sử dụng những đường n&eacute;t uốn cong mềm mại, những đường chạm khắc qu&yacute; tộc theo kiểu cổ điển ch&acirc;u &Acirc;u. C&oacute; những loại đơn giản, mộc mạc trơn nhẵn. Cũng c&oacute; loại ph&aacute; c&aacute;ch kết hợp c&aacute;c họa tiết h&igrave;nh học ừa tr&ograve;n vừa vu&ocirc;ng theo phong c&aacute;ch đương đại.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Điều ti&ecirc;n quyết trong việc lựa chọn phong c&aacute;ch của chiếc b&agrave;n l&agrave; xem x&eacute;t nội thất nh&agrave; bạn đang đi theo phong c&aacute;ch thiết kế n&agrave;o.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Bạn kh&ocirc;ng thể trang ho&agrave;ng cho kh&ocirc;ng gian hiện đại, sử dụng c&aacute;c chất liệu mới, đồ đa năng bằng một chiếc b&agrave;n ăn theo phong c&aacute;ch cổ điển được. Sự lạc l&otilde;ng v&agrave; kh&ocirc;ng thống nhất về chủ đề thiết kế ch&iacute;nh l&agrave; điều tối kỵ. Sự kh&aacute;c biệt phải tạo th&agrave;nh điểm nhấn v&agrave; h&agrave;i h&ograve;a với c&aacute;c đồ nội thất kh&aacute;c trong ph&ograve;ng thay v&igrave; ph&aacute; hỏng phong c&aacute;ch vốn c&oacute;.</span></p>\r\n<h2 style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>Lựa chọn h&igrave;nh d&aacute;ng của b&agrave;n ăn ph&ugrave; hợp với ph&ograve;ng bếp</strong></span></h2>\r\n<p><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/j1d6xd2b3DAa7Bct0Ul66L3N1wjEfkftS9uaR2wI.jpeg\" alt=\"hinh-dang-ban-an\" width=\"700\" height=\"700\" /></strong></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">H&igrave;nh d&aacute;ng cũng l&agrave; một ti&ecirc;u ch&iacute; quan trọng khi chọn mua b&agrave;n ăn. T&ugrave;y v&agrave;o c&aacute;c loại kh&ocirc;ng gian m&agrave; b&agrave;n tr&ograve;n, b&agrave;n vu&ocirc;ng, b&agrave;n h&igrave;nh chữ nhật.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Nếu bạn muốn kh&ocirc;ng gian thi&ecirc;n về sự mềm mại, h&atilde;y chọn b&egrave;n c&oacute; h&igrave;nh d&aacute;ng tr&ograve;n, tạo sự qu&acirc;y quần. B&agrave;n tr&ograve;n ph&ugrave; hợp với kh&ocirc;ng gian c&oacute; chiều d&agrave;i v&agrave; chiều rộng bằng nhau. Ch&uacute;ng tạo thế vu&ocirc;ng tr&ograve;n trời đất trong phong thủy mang lại t&agrave;i vận, may mắn cho kh&ocirc;ng gian.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">B&agrave;n h&igrave;nh vu&ocirc;ng n&ecirc;n d&ugrave;ng cho c&aacute;c gia đ&igrave;nh c&oacute; số lượng th&agrave;nh vi&ecirc;n vừa phải, thường chỗ ngồi của ch&uacute;ng sẽ l&agrave; c&aacute;c số chẵn như 4 hoặc 8 sẽ l&agrave; ph&ugrave; hợp nhất. N&eacute;t vu&ocirc;ng của bản ăn thể hiện sự thanh lịch, vững ch&atilde;i, h&agrave;i h&ograve;a cho kh&ocirc;ng gian.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">B&agrave;n h&igrave;nh chữ nhật sẽ ph&ugrave; hợp với gia đ&igrave;nh đ&ocirc;ng người, nhiều th&agrave;nh vi&ecirc;n hoặc cho gia đ&igrave;nh thường xuy&ecirc;n tiếp đ&oacute;n họ h&agrave;ng, kh&aacute;ch khứa.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Ngo&agrave;i ra, nếu bạn muốn tạo sự ph&aacute; c&aacute;ch cho kh&ocirc;ng gian hiện đại, sẽ c&oacute; c&aacute;c d&aacute;ng b&agrave;n thiết kế theo kiểu kết hợp, kiểu mở rộng, h&igrave;nh lục gi&aacute;c, ngũ gi&aacute;c mới lạ.</span></p>\r\n<h2 style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>Lựa chọn k&iacute;ch thước của b&agrave;n ăn</strong></span></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">B&agrave;n ăn qu&aacute; nhỏ sẽ g&acirc;y bất tiện trong qu&aacute; tr&igrave;nh sử dụng. Ngược lại, b&agrave;n ăn qu&aacute; lớn sẽ tạo khoảng c&aacute;ch giữa c&aacute;c th&agrave;nh vi&ecirc;n trong gia đ&igrave;nh.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Trung b&igrave;nh một người sẽ cần khoảng 160 cm vu&ocirc;ng diện t&iacute;ch b&agrave;n để sử dụng. Tức cứ mỗi 80 cm chiều d&agrave;i sẽ l&agrave; vừa vặn cho một người. Bốn người c&oacute; thể chọn b&agrave;n khoảng 2 m&eacute;t vu&ocirc;ng. B&agrave;n tr&ograve;n cho bốn người n&ecirc;n c&oacute; đường k&iacute;nh khoảng 120 cm l&agrave; hợp l&yacute;.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Khi lựa chọn k&iacute;ch thước b&agrave;n ăn, bạn n&ecirc;n c&acirc;n nhắc đến độ thoải m&aacute;i di chuyển, thao t&aacute;c của người ngồi.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Ngo&agrave;i ra, k&iacute;ch thước của b&agrave;n ăn phải ph&ugrave; hợp với kh&ocirc;ng gian lắp đặt. B&agrave;n lớn sẽ l&agrave;m kh&ocirc;ng gian trở n&ecirc;n chật chội, b&agrave;n nhỏ g&acirc;y ra qu&aacute; nhiều diện t&iacute;ch thừa. H&atilde;y đảm bảo b&agrave;n ăn c&oacute; khoảng c&aacute;ch với c&aacute;c đồ nội thất kh&aacute;c, đủ độ rộng để đi lại v&agrave; tạo sự h&agrave;i h&ograve;a trong mắt nh&igrave;n. Đảm bảo ch&uacute;ng c&aacute;ch với c&aacute;c đồ nội thất kh&aacute;c &iacute;t nhất 1m để tạo sự thoải m&aacute;i cho mắt nh&igrave;n.</span></p>\r\n<h2 style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>Lựa chọn m&agrave;u sắc của b&agrave;n ăn</strong></span></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">M&agrave;u sắc của b&agrave;n ăn phải h&agrave;i h&ograve;a với m&agrave;u sắc của c&aacute;c đồ nội thất kh&aacute;c xung quanh. Bạn kh&ocirc;ng thể chọn một chiếc b&agrave;n c&oacute; m&agrave;u phản lại c&aacute;c m&agrave;u kh&aacute;c trong ph&ograve;ng, ch&uacute;ng tạo cảm gi&aacute;c rối mắt. Nhiều m&agrave;u sẽ l&agrave;m giảm hứng th&uacute; ăn uống.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/Zr67woFwX5ag8rjYaWY4jYKPAfor4JFFtzj53d8M.jpeg\" alt=\"kich-thuoc-ban-an\" width=\"693\" height=\"487\" /></strong></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">C&aacute;c chuy&ecirc;n gia tin rằng c&aacute;c m&agrave;u sắc tạo cảm gi&aacute;c k&iacute;ch th&iacute;ch ăn uống l&agrave; c&aacute;c m&agrave;u n&oacute;ng như hồng, cam v&agrave; đỏ. M&agrave;u trắng v&agrave; m&agrave;u gỗ l&agrave; m&agrave;u trung t&iacute;nh, dễ kết hợp với nhiều loại kh&ocirc;ng gian. Gam m&agrave;u lạnh như xanh nước biển tuy l&agrave;m giảm sự k&iacute;ch th&iacute;ch ăn uống nhưng lại mang cảm gi&aacute;c thoải m&aacute;i, dễ chịu cho kh&ocirc;ng gian.</span></p>\r\n<h2 style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>Lựa chọn chất liệu của b&agrave;n ăn</strong></span></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><em><strong>Chất liệu c&ocirc;ng nghiệp</strong></em></span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Chất liệu c&ocirc;ng nghiệp l&agrave; c&aacute;c loại b&agrave;n ăn l&agrave;m từ hợp kim, nhựa, k&iacute;nh, inox . Ch&uacute;ng mang vẻ đẹp hiện đại, đơn giản, thanh lịch. Gi&aacute; cả của c&aacute;c b&agrave;n ăn theo phong c&aacute;ch c&ocirc;ng nghiệp cũng rất phải chăng, l&agrave; sự lựa chọn tối ưu cho nhiều người.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><em><strong>Chất liệu gỗ</strong></em></span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">C&aacute;c b&agrave;n ăn bằng gỗ mang lị vẻ tự nhi&ecirc;n, mộc mạc, thanh lịch, dễ kết hợp với c&aacute;c đồ nội thất kh&aacute;c trong nh&agrave;. Tuy nhi&ecirc;n, bạn n&ecirc;n lưu &yacute; chất liệu gỗ kh&aacute; kh&oacute; vệ sinh v&agrave; nhanh hỏng nếu d&iacute;nh bẩn dầu mỡ của đồ ăn. Sử dụng đồ bằng gỗ c&oacute; nghĩa l&agrave; bạn cần vệ sinh v&agrave; bảo dưỡng ch&uacute;ng thường xuy&ecirc;n để giữ độ bền v&agrave; độ b&oacute;ng của gỗ.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><em><strong>Chất liệu đ&aacute; cao cấp</strong></em></span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">C&aacute;c loại đ&aacute; được sử dụng để l&agrave;m mặt b&agrave;n như thạch anh, đ&aacute; cẩm thạch, granite,&hellip; c&oacute; độ b&oacute;ng, độ sang trọng tuyệt vời. Đ&acirc;y l&agrave; chất liệu gi&uacute;p gia chủ thể hiện sự đẳng cấp, địa vị v&agrave; sự sang trọng. Chất liệu n&agrave;y bền, chịu lực, chịu nhiệt v&agrave; độ bền thời gian rất tốt. Chất liệu n&agrave;y cũng rất dễ cho người d&ugrave;ng trong qu&aacute; tr&igrave;nh vệ sinh.</span></p>','Cách chọn bàn ăn phù hợp với phòng bếp của gia đình',NULL,'cach-chon-ban-an-phu-hop-voi-phong-bep-cua-gia-dinh','Khi thiết kế nội thất cho phòng bếp, việc chọn một bộ bàn ăn sang trọng, phù hợp là rất cần thiết. Vậy khi chọn mua một bộ bàn ăn, chúng ta cần lưu ý đến những tiêu chí nào của chúng? Nghề nội thất sẽ định hướng cho bạn qua bài viết dưới đây!','thiết kế nội thất, nội thất, nội thất gỗ','Published',2,NULL,0,NULL,'2020-12-28 00:59:15','2020-12-28 01:01:18',NULL),(25,'6 yếu tố quan trọng trong thiết kế Nội thất không thể bỏ qua','2021-01-08 10:53:00','1610079646-6-yeu-to-quan-trong-trong-thiet-ke-noi-that-khong-the-bo-qua.jpg','Thiết kế nội thất là một phần không thể thiếu trong thiết kế và hoàn thiện ngôi nhà. Đây là tập hợp quy trình của những công đoạn tạo hình bên trong một công trình xây dựng. Không chỉ là trang trí, thiết kế nội thất còn bao gồm cả những yếu tố về bố trí, thi công và cấu trúc nói chung. Hãy cùng Nghề nội thất điểm qua 6 yếu tố quan trọng trong thiết kế nội thất mà bạn không nên bỏ qua.','<h2 style=\"text-align: justify;\"><strong>1. Kh&ocirc;ng gian </strong></h2>\r\n<p style=\"text-align: justify;\">Đ&acirc;y l&agrave; một trong những yếu tố quan trọng nhất, &ldquo;l&agrave;m nền&rdquo; cho to&agrave;n bộ c&ocirc;ng tr&igrave;nh x&acirc;y dựng. Để thiết kế nội thất được ho&agrave;n thiện nhất cần nắm r&otilde; về kh&ocirc;ng gian c&oacute; sẵn. Bao gồm k&iacute;ch thước v&agrave; c&aacute;c tiện &iacute;ch m&agrave; n&oacute; c&oacute; thể mang lại.</p>\r\n<p style=\"text-align: justify;\">Kh&ocirc;ng gian được chia th&agrave;nh hai loại cụ thể&nbsp;<br />- Mặt bằng hai chiều bao phủ s&agrave;n nh&agrave;, giới hạn bởi chiều d&agrave;i v&agrave; chiều rộng.<br />- Kh&ocirc;ng gian ba chiều tạo th&agrave;nh kh&ocirc;ng gian sống. Bao gồm chiều d&agrave;i, chiều rộng v&agrave; chiều cao.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/RytTDfT6sbwlPJpSSawl5khJXTahNWjtskqEbD9L.jpeg\" alt=\"\" width=\"700\" height=\"466\" /></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Một c&aacute;ch ph&acirc;n chia kh&aacute;c l&agrave; kh&ocirc;ng gian chứa đồ nội thất l&agrave; Kh&ocirc;ng gian dương c&ograve;n lại l&agrave; Kh&ocirc;ng gian &acirc;m. Một kh&ocirc;ng gian hợp l&yacute; l&agrave; nơi c&oacute; thể c&acirc;n bằng giữa kh&ocirc;ng gian dương v&agrave; &acirc;m. Từ đ&oacute; tạo n&ecirc;n sự thống nhất h&agrave;i h&ograve;a trong m&ocirc;i trường sống.</p>\r\n<h2><strong>2. Đường n&eacute;t</strong></h2>\r\n<p style=\"text-align: justify;\">Đường n&eacute;t l&agrave; yếu tố căn bản để định h&igrave;nh kh&ocirc;ng gian khi thiết kế nội thất - đặc biệt l&agrave; nội thất t&acirc;n cổ điển. Yếu tố n&agrave;y tạo ra cảm gi&aacute;c h&agrave;i h&ograve;a, tương phản hoặc thống nhất cho một kh&ocirc;ng gian sống. Trong khi c&aacute;c đường ngang t&ocirc; điểm b&agrave;n, ghế v&agrave; giường, tạo th&ecirc;m cảm gi&aacute;c an to&agrave;n&hellip; Th&igrave; c&aacute;c đường thẳng đứng tr&ecirc;n c&aacute;c cửa sổ, cửa ra v&agrave;o cho cảm gi&aacute;c tự do v&agrave; mở rộng.</p>\r\n<p style=\"text-align: justify;\">Ngo&agrave;i ra, đường n&eacute;t cũng nằm ở c&aacute;c chi tiết uốn lượn, họa tiết, c&aacute;c g&oacute;c bo tr&ograve;n hay lồi l&otilde;m của c&aacute;c đối tượng lập thể.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/fDA1aSmyhHlDq3IgZab1153W2YCev6Ce8UUIUnwy.jpeg\" alt=\"\" width=\"700\" height=\"393\" /></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<h2><strong>3. H&igrave;nh khối:</strong></h2>\r\n<p style=\"text-align: justify;\">H&igrave;nh khối trong thiết kế nội thất c&oacute; thể được tạo n&ecirc;n từ 2 hoặc nhiều h&igrave;nh dạng kh&aacute;c nhau, được l&agrave;m nổi bật nhờ sự thay đổi, t&iacute;nh tương phản trong m&agrave;u sắc cũng như họa tiết tr&ecirc;n n&oacute;. Việc sử dụng hợp l&yacute; v&agrave; ph&acirc;n bố h&agrave;i h&ograve;a c&aacute;c h&igrave;nh khối kh&aacute;c nhau sẽ tạo n&ecirc;n sự đột ph&aacute;, tăng t&iacute;nh ổn định của kh&ocirc;ng gian tổng thể. C&oacute; 2 xu hướng thể hiện h&igrave;nh khối thường được sử dụng trong thiết kế nội thất hiện đại : Geometric (Nh&acirc;n tạo) v&agrave; Pure (Tự nhi&ecirc;n)</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/EJ66MYFitFduXzn0DDRijE4doRdEA0jaVDMpqs2O.jpeg\" alt=\"\" width=\"700\" height=\"442\" /></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<h2><strong>4. M&agrave;u sắc</strong></h2>\r\n<p style=\"text-align: justify;\">M&agrave;u sắc c&ugrave;ng đường n&eacute;t g&oacute;p phần tạo ranh giới v&agrave; kết nối cho đối tượng nội thất. Yếu tố n&agrave;y kh&ocirc;ng chỉ do kiến tr&uacute;c sư quyết định, m&agrave; c&ograve;n phải được lựa chọn dựa tr&ecirc;n t&acirc;m l&yacute; v&agrave; suy nghĩ của gia chủ ng&ocirc;i nh&agrave;.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/azgFWOQDD0u7Y637QxuWV0BfrADf4d20Q1kGuJDr.jpeg\" alt=\"\" width=\"700\" height=\"466\" /></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">C&aacute;c yếu tố then chốt trong việc lựa chọn m&agrave;u sắc l&agrave; t&ocirc;ng m&agrave;u, gi&aacute; trị v&agrave; cường độ. Việc lựa chọn m&agrave;u sắc ph&ugrave; hợp c&oacute; thể gi&uacute;p người nh&igrave;n c&oacute; thể cảm nhận được dụng &yacute;, &yacute; nghĩa của từng gam m&agrave;u, qua đ&oacute; n&ecirc;u bật được chủ đề của kh&ocirc;ng gian nội thất đồng thời tạo n&ecirc;n một kh&ocirc;ng gian sống ph&ugrave; hợp.</p>\r\n<h2><strong>5</strong><strong>. &Aacute;nh s&aacute;ng</strong></h2>\r\n<p style=\"text-align: justify;\">&Aacute;nh s&aacute;ng l&agrave; một trong những yếu tố c&oacute; vai tr&ograve; quan trọng nhất của thiết kế nội thất. M&agrave;u sắc, đường n&eacute;t hay họa tiết đều sẽ trở n&ecirc;n v&ocirc; nghĩa nếu kh&ocirc;ng c&oacute; yếu tố n&agrave;y &ndash; cho d&ugrave; l&agrave; tự nhi&ecirc;n hay nh&acirc;n tạo.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/oYq7juCzvIL45h0GV387IKAKgCUI17JFFPlwAY2J.jpeg\" alt=\"\" width=\"700\" height=\"420\" /></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Nguồn s&aacute;ng tự nhi&ecirc;n l&agrave; li&ecirc;n kết ch&iacute;nh tạo tương t&aacute;c giữa m&ocirc;i trường b&ecirc;n ngo&agrave;i v&agrave; nội thất b&ecirc;n trong. Kh&ocirc;ng gian nhận được nhiều &aacute;nh s&aacute;ng từ tự nhi&ecirc;n sẽ trở n&ecirc;n sinh động v&agrave; đầy sức sống. Trong đ&oacute;, &aacute;nh s&aacute;ng v&agrave;o c&aacute;c thời điểm kh&aacute;c nhau trong ng&agrave;y c&oacute; những đặc điểm, t&aacute;c động ho&agrave;n to&agrave;n kh&aacute;c nhau về mặt t&acirc;m &ndash; sinh l&yacute; với người sử dụng.</p>\r\n<p style=\"text-align: justify;\">Trong khi đ&oacute;, &aacute;nh s&aacute;ng nh&acirc;n tạo c&oacute; thể c&oacute; nhiều t&aacute;c dụng. Như chiếu s&aacute;ng thẩm mỹ, kiến tạo kh&ocirc;ng gian, hay &aacute;nh s&aacute;ng th&ocirc;ng minh &ndash; kết hợp với kh&ocirc;ng gian tạo n&ecirc;n c&aacute;c mục đich kh&aacute;c nhau.</p>\r\n<h2><strong>6. Họa tiết</strong></h2>\r\n<p style=\"text-align: justify;\">Họa tiết thường được gắn liền với thiết kế bề mặt nội thất, điển h&igrave;nh trong việc tạo ra cảm quan cho c&aacute;c chi tiết s&agrave;n, tường hoặc trần. Họa tiết cũng l&agrave; một yếu tố kh&ocirc;ng thể thiếu nhằm tăng chiều s&acirc;u, mang đến sự thu h&uacute;t của kh&ocirc;ng gian nội thất v&agrave; tr&ecirc;n hết, tạo n&ecirc;n t&iacute;nh nhất qu&aacute;n của kh&ocirc;ng gian sống. Thiết kế họa tiết cũng chia th&agrave;nh hai loại: Họa tiết cơ bản - tập trung x&acirc;y dựng c&aacute;i nh&igrave;n trực quan tr&ecirc;n bề mặt đối tượng v&agrave; họa tiết ch&iacute;nh x&aacute;c - tập trung v&agrave; cảm nhận người nh&igrave;n v&agrave; thể hiện &yacute; đồ thiết kế.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/SVZVwQkaThLTz7pZ6jLkf5gnZndrfZPVRh3R8dhI.jpeg\" alt=\"\" width=\"700\" height=\"482\" /></p>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: justify;\">Trong thể hiện họa tiết, người kiến tr&uacute;c sư lu&ocirc;n phải ch&uacute; &yacute; tới sự tương phản trong việc sử dụng c&aacute;c mẫu họa tiết kh&aacute;c nhau nhằm tr&aacute;nh sự đơn điệu nh&agrave;m ch&aacute;n, song cũng cần đảm bảo được việc truyền tải nội dung thiết kế, hay ch&iacute;nh l&agrave; chủ đề của kh&ocirc;ng gian sống.</p>\r\n<h2>Kết</h2>\r\n<p style=\"text-align: justify;\">Để tạo ra kh&ocirc;ng gian sống đ&uacute;ng chuẩn mực, tiện nghi v&agrave; tạo ra những cảm x&uacute;c t&iacute;ch cực cho gia chủ, những yếu tố quan trọng n&agrave;y cần được kiến tr&uacute;c sư c&acirc;n nhắc kỹ lưỡng v&agrave; c&oacute; sự điều chỉnh h&agrave;i h&ograve;a</p>','6 yếu tố quan trọng trong thiết kế Nội thất không thể bỏ qua',NULL,'6-yeu-to-quan-trong-trong-thiet-ke-noi-that-khong-the-bo-qua','Thiết kế nội thất là một phần không thể thiếu trong thiết kế và hoàn thiện ngôi nhà. Đây là tập hợp quy trình của những công đoạn tạo hình bên trong một công trình xây dựng. Không chỉ là trang trí, thiết kế nội thất còn bao gồm cả những yếu tố về bố trí, thi công và cấu trúc nói chung. Hãy cùng Nghề nội thất điểm qua 6 yếu tố quan trọng trong thiết kế nội thất mà bạn không nên bỏ qua.',NULL,'Published',2,NULL,1,3,'2021-01-07 21:20:46','2021-01-07 21:22:38',NULL),(26,'imm Cologne 2021 - Hội chợ hàng đầu thế giới về Nội thất và Thiết kế nội thất','2021-01-15 11:10:00','1610684599-imm-cologne-2021-hoi-cho-hang-dau-the-gioi-ve-noi-that-va-thiet-ke-noi-that.png','Diễn ra từ 18 - 24.01.2021 tại Trung tâm hội chợ Koelnmesse, thành phố Cologne, CHLB Đức, imm Cologne - Hội chợ được tổ chức hàng năm vào mùa mua hàng đầu tiên trong năm, là nơi trưng bày hàng loạt sản phẩm nội thất và thiết kế nội thất của các nhà sản xuất danh tiếng Châu Âu, cũng như từ các nước khác trên khắp thế giới.','<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\"><strong>imm Cologne 2021</strong>&nbsp;l&agrave; nơi trưng b&agrave;y h&agrave;ng loạt c&aacute;c sản phẩm nội thất v&agrave; thiết kế nội thất của c&aacute;c nh&agrave; sản xuất danh tiếng tr&ecirc;n to&agrave;n cầu. Tại imm cologne 2021, nơi m&agrave; những sản phẩm mới nhất, độc đ&aacute;o nhất được trưng b&agrave;y, được tr&igrave;nh diễn bởi những c&ocirc;ng ty lớn, cũng như h&agrave;ng loại c&aacute;c c&ocirc;ng ty c&aacute;c từ c&aacute;c thị trường sản xuất v&agrave; xuất khẩu đồ nội thất. Đồng thời, imm Cologne cũng l&agrave; nơi m&agrave; c&aacute;c nh&agrave; thiết kế trẻ v&agrave; tiềm năng trưng b&agrave;y c&aacute;c sản phẩm s&aacute;ng tạo v&agrave; đặc sắc của họ</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">Đặc biệt 2021, sự kết hợp tổ chức song song hai hội chợ imm Cologne v&agrave; LivingKitchen - Hội chợ Quốc tế chuy&ecirc;n về trang thiết bị nh&agrave; bếp khẳng định vai tr&ograve; quan trọng của th&agrave;nh phố Cologne, s&agrave;n giao dịch quan trọng h&agrave;ng đầu của c&aacute;c nh&agrave; sản xuất v&agrave; kinh doanh đồ nội thất. C&aacute;c c&ocirc;ng ty tham gia trưng b&agrave;y sẽ được những lợi &iacute;ch hỗ trợ tương t&aacute;c từ hai sự kiện tr&ecirc;n.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p><span style=\"font-size: 12pt;\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/zZ6VGPxWC4tlRKnaRInoRyLlpS43a2c4c7fe6NQQ.png\" alt=\"imm-cologne-2021\" width=\"700\" height=\"451\" /></span></p>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">C&aacute;c kh&aacute;ch thăm thương mại lu&ocirc;n đ&aacute;nh gi&aacute; cao m&ocirc;i trường kinh doanh, cũng như c&aacute;ch thức tổ chức v&agrave; c&aacute;c dịch vụ tại hội chợ. Hội chợ cũng mở cửa rộng r&atilde;i d&agrave;nh cho c&aacute;c kh&aacute;ch thăm c&ocirc;ng ch&uacute;ng v&agrave;o 3 ng&agrave;y cuối, điều n&agrave;y tạo cơ hội cho c&aacute;c c&ocirc;ng ty trưng b&agrave;y giới thiệu sản phẩm của c&ocirc;ng ty đến kh&aacute;ch h&agrave;ng cuối c&ugrave;ng v&agrave; c&oacute; cơ hội nghe những phản hồi trực tiếp từ kh&aacute;ch h&agrave;ng. C&ugrave;ng với nhiều sự kiện đặc biệt kh&aacute;c được tổ chức đồng thời tại th&agrave;nh phố Cologne, hội chợ <strong><em>imm Cologne 2021</em></strong><em> thực sự trở th&agrave;nh t&acirc;m điểm của tuần lễ Thế giới đồ nội thất v&agrave; thiết kế nội thất quốc tế.</em></span></p>\r\n<p><span style=\"font-size: 12pt;\"><em>&nbsp;</em></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\"><strong>Những lợi &iacute;ch khi tham dự trưng b&agrave;y tại imm Cologne 2021:</strong></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">- Gặp gỡ của c&aacute;c nh&agrave; quản l&yacute;, thiết kế, hoạch định cấp cao v&agrave; mua h&agrave;ng những người c&oacute; thẩm quyền quyết định cho c&aacute;c hoạt động kinh doanh của c&ocirc;ng ty</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">-&nbsp; Nơi tạo dựng việc kinh doanh hiệu quả với m&ocirc;i trường l&yacute; tưởng v&agrave; thời gian ph&ugrave; hợp cho c&aacute;c giao dịch kinh doanh <em>(Th&aacute;ng 1&nbsp; l&agrave; th&aacute;ng khởi đầu cho m&ugrave;a mua h&agrave;ng đầu ti&ecirc;n trong năm của c&aacute;c c&ocirc;ng ty mua h&agrave;ng quốc tế)</em></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">-&nbsp; Trải nghiệm những xu hướng nội thất mới, với nhiều chủng loại sản phẩm đa dạng, từ những thiết kế độc nhất một sản phẩm cho đến c&aacute;c sản phẩm được thiết kế sản xuất h&agrave;ng loạt, mặt h&agrave;ng trang tr&iacute; nội thất từ ph&ograve;ng kh&aacute;ch, ph&ograve;ng ngủ, ph&ograve;ng ăn, sản phẩm chiếu s&aacute;ng, phụ kiện, vải trang tr&iacute;&hellip;</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">-&nbsp; Thu h&uacute;t giới truyền th&ocirc;ng cho ng&agrave;nh nội thất v&agrave; thiết kế nội thất của thế giới</span></p>\r\n<ul>\r\n<li style=\"text-align: justify;\"><span style=\"font-size: 12pt;\"> S&agrave;n trưng b&agrave;y h&agrave;ng h&oacute;a l&yacute; tưởng, m&agrave; n&oacute; được kết nối trực tiếp đến c&aacute;c thị trường ph&aacute;t triển nhất, với vị tr&iacute; tọa lạc ngay tại trung t&acirc;m Ch&acirc;u &Acirc;u.</span></li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: center;\"><span style=\"font-size: 12pt;\"><img src=\"/storage/uploads/tinymce/PpRbo9Ejws4pYKSroG4bmX8us4VxFhg3sYobeybW.png\" alt=\"\" width=\"700\" height=\"466\" /></span></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\"><strong>Chi ph&iacute; thu&ecirc; gian h&agrave;ng trưng b&agrave;y tại imm Cologne 2021 </strong>(<em>gian th&ocirc;, chưa d&agrave;n dựng</em>):</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">+ <strong>195.00 Euro</strong>/<strong>m<sup>2</sup></strong> (gi&aacute; ưu đ&atilde;i, chỉ &aacute;p dụng đến ng&agrave;y <strong>28/02/2020</strong>)</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">+ <strong>205.00 Euro/m<sup>2</sup></strong> (gi&aacute; ưu đ&atilde;i, &aacute;p dụng đến ng&agrave;y <strong>30/04/2020</strong>)</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">+ <strong>215.00 Euro/m<sup>2</sup></strong> (gi&aacute; ch&iacute;nh thức từ ng&agrave;y <strong>01/05/2020</strong>)</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">(<em>Diện t&iacute;ch gian h&agrave;ng tối thiểu l&agrave; 12 m<sup>2</sup>)</em></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\"><strong><em>* Lưu &yacute;</em></strong><em> : C&aacute;c c&ocirc;ng ty Ch&acirc;u &Aacute; (bao gồm c&aacute;c c&ocirc;ng ty Việt Nam), khi muốn thu&ecirc; gian h&agrave;ng trưng b&agrave;y tại imm Cologne (nếu đi trưng b&agrave;y lần đầu) phải gửi brochure c&ocirc;ng ty, h&igrave;nh ảnh d&atilde;y sản phẩm dự định trưng b&agrave;y tại hội chợ cho Bộ phận dự &aacute;n để xem x&eacute;t! Chỉ c&oacute; những c&ocirc;ng ty v&agrave; những sản phẩm đủ ti&ecirc;u chuẩn tham dự trưng b&agrave;y tại imm Cologne mới được xem x&eacute;t v&agrave; cấp ph&aacute;t gian h&agrave;ng!</em></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\"><em>&nbsp;</em></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\"><strong>D&atilde;y sản phẩm trưng b&agrave;y imm Cologne 2021:</strong></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">- <strong>Global Lifestyles: </strong>Đồ d&ugrave;ng d&agrave;nh cho ph&ograve;ng kh&aacute;ch v&agrave; ph&ograve;ng ngủ</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">- <strong>Prime: </strong>Đồ gỗ d&agrave;nh cho ph&ograve;ng kh&aacute;ch v&agrave; ph&ograve;ng ngủ hiện đại, đồ gỗ đặc khối, nội thất cho trẻ em, b&agrave;n, ghế, đồ d&ugrave;ng cho ph&ograve;ng ăn, b&aacute;n th&agrave;nh phẩm v&agrave; những sản phẩm sản xuất từ vật liệu t&aacute;i chế</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">- <strong>Comfort: </strong>C&aacute;c loại đồ bọc vải, bộ ghế sofa, ghế b&agrave;nh, ghế trường kỷ, ghế sofa đơn, giường sofa</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">- <strong>Smart: </strong>C&aacute;c sản phẩm nội thất c&oacute; thể th&aacute;o lắp v&agrave; c&oacute; phong c&aacute;ch trẻ trung, nội thất ph&ograve;ng ngủ, ph&ograve;ng trẻ em, v&agrave; c&aacute;c bộ đồ d&ugrave;ng trang tr&iacute;</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">- <strong>Sleep: </strong>Nệm v&agrave; c&aacute;c đồ d&ugrave;ng ph&ograve;ng ngủ, giường, đệm nước, bộ đồ ph&ograve;ng ngủ (chăn, ra, gối&hellip;), khăn trải giường, &aacute;o gối v&agrave; c&aacute;c phụ kiện kh&aacute;c</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">- <strong>Pure: </strong>C&aacute;c loại đồ gỗ thiết kế ti&ecirc;n tiến, hiện đại</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">-<strong> Pure Editions</strong>: C&aacute;c &yacute; tưởng thiết kế sản phẩm ti&ecirc;n tiến v&agrave; độc đ&aacute;o</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">-<strong> Pure Studios: </strong>C&aacute;c &yacute; tưởng thiết kế của c&aacute;c nh&agrave; thiết kế trẻ: c&aacute;c thiết kế trong ph&ograve;ng lab, ph&ograve;ng thu, nh&agrave; mạng</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">-<strong> Pure Talents: </strong>Sản phẩm mới lạ của c&aacute;c nh&agrave; thiết kế đến từ c&aacute;c trường đ&agrave;o tạo thiết kế</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><span style=\"font-size: 12pt;\"><img src=\"/storage/uploads/tinymce/hMpReBkxBafjOV8DxkNWf5iLbD4ACDN7oiATwfDp.png\" alt=\"\" width=\"700\" height=\"466\" /></span></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><strong>Nh&oacute;m c&ocirc;ng ty trưng b&agrave;y mục ti&ecirc;u imm Cologne 2021:</strong></p>\r\n<p style=\"text-align: justify;\">- C&aacute;c nh&agrave; sản xuất &amp; cung cấp đồ gỗ, đồ nội thất ph&ograve;ng kh&aacute;ch, ph&ograve;ng tắm, ph&ograve;ng ngủ, c&aacute;c loại nệm v&agrave; đồ d&ugrave;ng trang tr&iacute; ph&ograve;ng ngủ</p>\r\n<p style=\"text-align: justify;\">- C&aacute;c nh&agrave; sản xuất &amp; cung cấp giấy d&aacute;n tường, thảm trải s&agrave;n, c&aacute;c loại vải trang tr&iacute; nội thất, đ&egrave;n trang tr&iacute; v&agrave; c&aacute;c linh kiện thuộc d&atilde;y sản phẩm chuy&ecirc;n dụng cũng như trang thiết bị ph&ograve;ng tắm</p>\r\n<p style=\"text-align: justify;\">- C&aacute;c nh&agrave; sản xuất &amp; cung cấp những sản phẩm nội thất kh&aacute;c</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><strong>Nh&oacute;m kh&aacute;ch thăm mục ti&ecirc;u imm Cologne 2021:</strong></p>\r\n<p style=\"text-align: justify;\"><strong>-</strong> C&aacute;c nh&agrave; kinh doanh xuất nhập khẩu chuy&ecirc;n về đồ gỗ v&agrave; đồ nội thất</p>\r\n<p style=\"text-align: justify;\">- C&aacute;c nh&agrave; b&aacute;n lẻ thiết bị, đồ d&ugrave;ng ph&ograve;ng ngủ</p>\r\n<p style=\"text-align: justify;\">- C&aacute;c nh&agrave; thiết kế nội thất, kiến tr&uacute;c sư, nh&agrave; thiết kế, chuy&ecirc;n gia đồ gỗ, thợ mộc, v&agrave; c&aacute;c nh&agrave; trang tr&iacute; nội thất&hellip;</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><strong>Một v&agrave;i con số về imm Cologne 2020:</strong></p>\r\n<p style=\"text-align: justify;\">- C&ocirc;ng ty trưng b&agrave;y<strong>: 1.233 c&ocirc;ng ty </strong><em>(đến từ 51 quốc gia)</em></p>\r\n<p style=\"text-align: justify;\">- Số lượng kh&aacute;ch thăm<strong>: 125.000 kh&aacute;ch thăm </strong><em>(đến từ 145 quốc gia)</em></p>\r\n<p style=\"text-align: justify;\">- Diện t&iacute;ch s&agrave;n trưng b&agrave;y<strong><em>: </em>245.000m<sup>2</sup></strong><em> (14 sảnh trưng b&agrave;y)</em></p>\r\n<p>&nbsp;</p>','imm Cologne 2021 - Hội chợ hàng đầu thế giới về Nội thất và Thiết kế nội thất',NULL,'imm-cologne-2021-hoi-cho-hang-dau-the-gioi-ve-noi-that-va-thiet-ke-noi-that','Diễn ra từ 18 - 24.01.2021 tại Trung tâm hội chợ Koelnmesse, thành phố Cologne, CHLB Đức\r\nimm Cologne - Hội chợ được tổ chức hàng năm vào mùa mua hàng đầu tiên trong năm, là nơi trưng bày hàng loạt sản phẩm nội thất và thiết kế nội thất của các nhà sản xuất danh tiếng Châu Âu, cũng như từ các nước khác trên khắp thế giới.','thiết kế nội thất, nội thất, nội thất gỗ','Published',2,NULL,1,3,'2021-01-14 21:23:19','2021-01-14 21:25:06',NULL),(27,'Những lưu ý khi bố trí nội thất phòng ngủ có diện tích nhỏ','2021-01-25 11:40:00','1611550198-nhung-luu-y-khi-bo-tri-noi-that-phong-ngu-co-dien-tich-nho.jpg','Việc thiết kế và bố trí đồ nội thất cho không gian phòng ngủ là vô cùng cần thiết nhằm tạo sự thông thoáng, thoải mái cho người sử dụng. Đối với những căn hộ sở hữu không gian phòng ngủ có diện tích khiêm tốn, người thiết kế có thể cần có một vài lưu ý dưới đây nhằm tối ưu diện tích sử dụng đồng thời giữ được sự hài hòa về bố cục tổng thể cho căn phòng.','<h2><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>Lựa chọn đồ nội thất đa năng</strong></span></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Trong ph&ograve;ng ngủ, đồ nội thất c&oacute; thể chiếm đến 90% kh&ocirc;ng gian, l&agrave; nh&acirc;n tố ảnh hưởng trực tiếp đến t&iacute;nh thẩm mỹ v&agrave; diện t&iacute;ch căn ph&ograve;ng n&ecirc;n cần được lựa chọn v&agrave; bố tr&iacute; hợp l&yacute;. Đặc biệt đối với ph&ograve;ng ngủ c&oacute; diện t&iacute;ch nhỏ, bạn n&ecirc;n c&acirc;n nhắc tối giản diện t&iacute;ch b&agrave;i tr&iacute; đồ đạc v&agrave; ưu ti&ecirc;n sử dụng đồ nội thất đa năng. Việc sử dụng nội thất đa năng cũng đang trở th&agrave;nh xu hướng thiết kế nội thất trong thời gian gần đ&acirc;y.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><img src=\"/storage/uploads/tinymce/9f81OIcsctim88epF2NcRDrU9PPrXpjhtBq0wIkX.jpeg\" alt=\"\" width=\"650\" height=\"479\" /></span></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Với sản phẩm nội thất đa năng, ch&uacute;ng c&oacute; thể gi&uacute;p bạn tiết kiệm được một khoảng kh&ocirc;ng gian rộng r&atilde;i. Đồng thời vẫn đ&aacute;p ứng đầy đủ nhu cầu sử dụng cần thiết của người d&ugrave;ng. C&aacute;c sản phẩm nội thất đa năng c&oacute; thể kể đến như giường đa năng, kệ kết hợp b&agrave;n l&agrave;m việc, tủ kết hợp v&aacute;ch ngăn,...</span></p>\r\n<p>&nbsp;</p>\r\n<h2><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>Treo đồ tiết kiệm khoảng kh&ocirc;ng</strong></span></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">T&iacute;ch hợp c&aacute;c gi&aacute; treo đồ tr&ecirc;n tường sẽ gi&uacute;p bạn tiết kiệm được khoảng kh&ocirc;ng gian trong ph&ograve;ng. Đ&acirc;y được coi l&agrave; giải ph&aacute;p hữu hiệu được đ&ocirc;ng đảo c&aacute;c nh&agrave; thiết kế sử dụng, nhằm biến tấu kh&ocirc;ng gian chật hẹp trở n&ecirc;n th&ocirc;ng tho&aacute;ng hơn.</span></p>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: center;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><img src=\"/storage/uploads/tinymce/7vAcmXR5vQPE6Sn8ulJxBTD0FV1o0qc01EQC2xRh.jpeg\" alt=\"\" width=\"650\" height=\"650\" /></span></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Bạn c&oacute; thể thiết kế c&aacute;c kệ treo gắn tường trong ph&ograve;ng l&agrave;m gi&aacute; s&aacute;ch, nơi chứa đồ d&ugrave;ng thiết yếu hoặc đặt c&aacute;c chậu c&acirc;y xanh, những vật dụng trang tr&iacute; nhỏ để tạo điểm nhấn cho kh&ocirc;ng gian ph&ograve;ng ngủ của m&igrave;nh.</span></p>\r\n<p>&nbsp;</p>\r\n<h2><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>Sử dụng nội thất m&agrave;u sắc tối giản</strong></span></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Việc sử dụng m&agrave;u sắc tối giản cũng l&agrave; một ti&ecirc;u ch&iacute; kh&ocirc;ng thể thiếu để c&oacute; thể cải thiện hạn chế về diện th&iacute;ch của kh&ocirc;ng gian ph&ograve;ng ngủ. M&agrave;u sắc của c&aacute;c vật dụng trong ph&ograve;ng cần h&agrave;i h&ograve;a, thống nhất với nhau, tạo cảm gi&aacute;c thư th&aacute;i.</span></p>\r\n<p style=\"text-align: center;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><img src=\"/storage/uploads/tinymce/A5tw2m0K94qASGWRJGPrnpSQnvfBrE9h3pOxanbr.jpeg\" alt=\"\" width=\"650\" height=\"468\" /></span></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Đối với kh&ocirc;ng gian ph&ograve;ng ngủ chật hẹp, h&atilde;y bố tr&iacute; nội thất với c&aacute;c gam m&agrave;u: trắng, xanh hoặc pastel. Đ&acirc;y l&agrave; những gam m&agrave;u nhẹ nh&agrave;ng, gi&uacute;p ph&ograve;ng ngủ trở n&ecirc;n rộng r&atilde;i v&agrave; th&ocirc;ng tho&aacute;ng hơn. Lưu &yacute;, kh&ocirc;ng n&ecirc;n sử dụng c&aacute;c gam m&agrave;u qu&aacute; n&oacute;ng, qu&aacute; nổi bật: đỏ, v&agrave;ng, t&iacute;m,... bởi ch&uacute;ng sẽ l&agrave;m cho kh&ocirc;ng kh&iacute; của ph&ograve;ng ngủ trở n&ecirc;n ngột ngạt, dễ g&acirc;y cảm gi&aacute;c căng thẳng, thiếu thoải m&aacute;i cho gia chủ.</span></p>\r\n<p>&nbsp;</p>\r\n<h2><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>Chiếu s&aacute;ng ph&ograve;ng ngủ nhỏ hẹp</strong></span></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">C&oacute; thể n&oacute;i, &aacute;nh s&aacute;ng ảnh hưởng rất nhiều đến t&iacute;nh thẩm mỹ v&agrave; của kh&ocirc;ng gian nội thất, v&igrave; vậy bạn kh&ocirc;ng n&ecirc;n bỏ qua yếu tố &aacute;nh s&aacute;ng trong thiết kế ph&ograve;ng ngủ. Những chiếc đ&egrave;n chiếu s&aacute;ng ph&ugrave; hợp sẽ khiến kh&ocirc;ng gian ph&ograve;ng ngủ trở n&ecirc;n th&ocirc;ng tho&aacute;ng v&agrave; rộng r&atilde;i hơn.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Đối với m&agrave;u sắc &aacute;nh s&aacute;ng chiếu trong ph&ograve;ng ngủ,&nbsp; n&ecirc;n sử dụng c&aacute;c m&agrave;u sắc dịu nhẹ, kh&ocirc;ng qu&aacute; gay gắt. Đặc biệt, bạn n&ecirc;n sử dụng &aacute;nh s&aacute;ng m&agrave;u v&agrave;ng cho ph&ograve;ng ngủ, bởi &aacute;nh s&aacute;ng v&agrave;ng kh&ocirc;ng những gi&uacute;p bảo vệ đ&ocirc;i mắt c&ograve;n gi&uacute;p bạn đi v&agrave;o giấc ngủ dễ d&agrave;ng hơn.</span></p>','Những lưu ý khi bố trí nội thất phòng ngủ có diện tích nhỏ',NULL,'nhung-luu-y-khi-bo-tri-noi-that-phong-ngu-co-dien-tich-nho','Việc thiết kế và bố trí đồ nội thất cho không gian phòng ngủ là vô cùng cần thiết nhằm tạo sự thông thoáng, thoải mái cho người sử dụng. Đối với những căn hộ sở hữu không gian phòng ngủ có diện tích khiêm tốn, người thiết kế có thể cần có một vài lưu ý dưới đây nhằm tối ưu diện tích sử dụng đồng thời giữ được sự hài hòa về bố cục tổng thể cho căn phòng.','thiết kế nội thất, nội thất, nội thất gỗ, nội thất phòng ngủ','Published',2,NULL,0,1,'2021-01-24 21:49:58','2021-01-24 22:04:46',NULL),(28,'Nghiên cứu, sản xuất sản phẩm mới trong lĩnh vực trang trí nội thất góp phần tăng trưởng doanh thu, lợi nhuận cho Tập đoàn Nhựa Đông Á','2021-02-02 16:49:00','1612259380-nghien-cuu-san-xuat-san-pham-moi-trong-linh-vuc-trang-tri-noi-that-gop-phan-tang-truong-doanh-thu-loi-nhuan-cho-tap-doan-nhua-dong-a.jpg','Nếu như trước đây trong lĩnh vực trang trí nội thất, đá cẩm thạch hay gỗ tự nhiên là vật liệu được dùng để thể hiện sự đẳng cấp, sang trọng nhưng nhược điểm là thi công khó và giá thành cao thì trong thời đại hoàng kim của trang trí nột thất hiện nay, tấm ốp tường, tấm micacrylic DAG của Công ty cổ phần Tập đoàn Nhựa Đông Á (DAG) như một luồng gió mới, mang đến cho người tiêu dùng sự lựa chọn hoàn hảo nhất.','<p style=\"text-align: justify;\">Tấm ốp tường l&agrave; một loại vật liệu thi c&ocirc;ng d&ugrave;ng thay thế cho c&aacute;c hạng mục x&acirc;y dựng như tr&aacute;t vữa, gỗ tự nhi&ecirc;n hay đ&aacute; cẩm thạch. Nhưng nhược điểm của những vật liệu truyền thống n&agrave;y l&agrave; qu&aacute; tr&igrave;nh thi c&ocirc;ng tốn nhiều sức, độc hại, ng&agrave;y c&agrave;ng khan hiếm lại gi&aacute; th&agrave;nh cao.</p>\r\n<p style=\"text-align: justify;\">Lu&ocirc;n l&agrave; đơn vị ti&ecirc;n phong tạo n&ecirc;n vật liệu mới trong ng&agrave;nh nội thất, DAG đ&atilde; đưa c&ocirc;ng nghệ 4.0 mới nhất tr&ecirc;n thế giới &aacute;p dụng tại Việt Nam cho ra đời tấm ốp tường PVC Nano.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/lJaplQQMrXU319uujNrm4ASpMZ7Z5Zp0Y5Kb65UL.jpeg\" alt=\"\" width=\"750\" height=\"652\" /><br /><em>Tấm ốp tường PVC &ndash; Tập Đo&agrave;n Nhựa Đ&ocirc;ng &Aacute;</em></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Tấm ốp tường l&agrave; một loại vật liệu thi c&ocirc;ng d&ugrave;ng thay thế cho c&aacute;c hạng mục x&acirc;y dựng như tr&aacute;t vữa, gỗ tự nhi&ecirc;n hay đ&aacute; cẩm thạch. Nhưng nhược điểm của những vật liệu truyền thống n&agrave;y l&agrave; qu&aacute; tr&igrave;nh thi c&ocirc;ng tốn nhiều sức, độc hại, ng&agrave;y c&agrave;ng khan hiếm lại gi&aacute; th&agrave;nh cao.</p>\r\n<p style=\"text-align: justify;\">Lu&ocirc;n l&agrave; đơn vị ti&ecirc;n phong tạo n&ecirc;n vật liệu mới trong ng&agrave;nh nội thất, DAG đ&atilde; đưa c&ocirc;ng nghệ 4.0 mới nhất tr&ecirc;n thế giới &aacute;p dụng tại Việt Nam cho ra đời tấm ốp tường PVC Nano.</p>\r\n<p style=\"text-align: justify;\">Với sự kết hợp ho&agrave;n hảo từ nhựa c&acirc;y v&agrave; bột đ&aacute;, sản xuất tr&ecirc;n d&acirc;y chuyền c&ocirc;ng nghệ Nano 4.0 hiện đại, tấm PVC Nano c&oacute; độ bền l&ecirc;n tới tr&ecirc;n 50 năm, bất chấp mọi điều kiện khắc nghiệt của thời tiết.</p>\r\n<p style=\"text-align: justify;\">Tấm ốp tường của DAG được sử dụng c&ocirc;ng nghệ 4 lớp hiện đại, ti&ecirc;n tiến nhất gồm lớp cốt, lớp v&acirc;n đ&aacute;, lớp UV v&agrave; lớp m&agrave;ng bảo vệ PE. Đ&acirc;y l&agrave; bước đột ph&aacute; kh&ocirc;ng chỉ của DAG m&agrave; c&ograve;n l&agrave; dấu ấn của thị trường Việt Nam khi một doanh nghiệp trong nước đ&atilde; gi&uacute;p người ti&ecirc;u d&ugrave;ng c&oacute; th&ecirc;m sự lựa chọn về vật liệu thi c&ocirc;ng ốp tường.</p>\r\n<p style=\"text-align: justify;\">Tấm ốp tường PVC &ndash; DAG được d&ugrave;ng trong những c&ocirc;ng tr&igrave;nh thi c&ocirc;ng l&acirc;u đ&agrave;i, biệt thự, kh&aacute;ch sạn, t&ograve;a nh&agrave; chung cư cao tầng, văn ph&ograve;ng, nh&agrave; h&agrave;ng tiệc cưới, thẩm mỹ viện, spa&hellip;</p>\r\n<p style=\"text-align: justify;\">Với sự ứng dụng rộng r&atilde;i đ&oacute;, tấm ốp tường của DAG nổi danh l&agrave; vật liệu trang tr&iacute; thời hiện đại với những t&iacute;nh năng ưu việt như: m&agrave;u sắc v&agrave; mẫu m&atilde; phong ph&uacute;, an to&agrave;n tuyệt đối, kh&ocirc;ng độc hại, khả năng chịu nhiệt, chống ch&aacute;y cao, dễ thi c&ocirc;ng, gi&aacute; th&agrave;nh hợp l&yacute;, t&iacute;nh thẩm mỹ&hellip;</p>\r\n<p style=\"text-align: justify;\">Ngo&agrave;i tấm ốp tường ,Tấm Mica PS ( hay c&ograve;n gọi l&agrave; Mica Polystyrene) hiện DAG đang l&agrave; nh&agrave; cung cấp số 1 trong nước.Với sự nghi&ecirc;n cứu ph&aacute;t triển kh&ocirc;ng nghừng hiện tại ngo&agrave;i tấm Mica PS. tấm Mica Acrylic DAG cũng l&agrave; một trong những vật liệu được ưa chuộng trong thiết kế nội ngoại thất v&agrave; sử dụng nhiều trong ng&agrave;nh quảng c&aacute;o.</p>\r\n<p style=\"text-align: justify;\">Với những đặc t&iacute;nh như xuy&ecirc;n s&aacute;ng tốt, m&agrave;u sắc đa dạng, dễ d&agrave;ng gia c&ocirc;ng lắp gh&eacute;p, uốn &eacute;p theo &yacute; muốn, chịu được nhiệt độ cao v&agrave; chống ăn m&ograve;n, kh&ocirc;ng dẫn điện, dẫn nhiệt. Mica Acrylic c&oacute; thể h&uacute;t nổi v&agrave; d&ugrave;ng để xử l&yacute; bề mặt.được d&ugrave;ng l&agrave;m hộp đ&egrave;n, chữ nổi mica&hellip;</p>\r\n<p style=\"text-align: justify;\">Hiện tại c&oacute; một số đối t&aacute;c sản xuất b&oacute;ng đ&egrave;n trong nước đang hợp t&aacute;c để l&agrave;m hộp cho đ&egrave;n led từ Mica Acrylic.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/5aLQFfrRF7vJZv2AJCXu4ptYVLb7ZXuIxn6cZWVF.jpeg\" alt=\"\" width=\"750\" height=\"558\" /><br />Mica Acrylic DAG được d&ugrave;ng để l&agrave;m m&aacute;ng đ&egrave;n led v&agrave; h&uacute;t nổi</p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Với phương ch&acirc;m kh&ocirc;ng ngừng học hỏi, kh&ocirc;ng ngừng s&aacute;ng tạo, lu&ocirc;n lu&ocirc;n mong muốn đem lại cho thị trường những sản phẩm mới, cao cấp, chất lượng, ph&ugrave; hợp v&agrave; đ&aacute;p ứng tối đa h&oacute;a nhu cầu thị trường. C&ugrave;ng với sự ra đời th&agrave;nh c&ocirc;ng của tấm V&aacute;n nhựa gỗ PVSmart, tấm Fomex, thanh Profile uPVC m&agrave;u v&agrave; v&acirc;n gỗ,&hellip;</p>\r\n<p style=\"text-align: justify;\">Tấm ốp tường l&agrave; một trong những bước đột ph&aacute; của DAG được ứng dụng đa dạng trong c&aacute;c lĩnh vực của cuộc sống thời hiện đại ng&agrave;y nay nhờ những đặc t&iacute;nh tối ưu hơn so với những loại vật liệu kh&aacute;c.</p>\r\n<p style=\"text-align: justify;\">Đ&acirc;y l&agrave; bước đi kh&aacute;c biệt của một doanh nghiệp Việt mang t&ecirc;n DAG để khẳng định thương hiệu của m&igrave;nh lu&ocirc;n ti&ecirc;n phong tạo n&ecirc;n vật liệu mới trong ng&agrave;nh trang tr&iacute; nội thất tại Việt Nam.</p>\r\n<p style=\"text-align: justify;\">Những sản phẩm mới n&agrave;y đ&atilde; g&oacute;p phần gi&uacute;p DAG tăng trưởng mạnh về mặt doanh thu , Qu&yacute; 4 năm 2020 đạt 611 tỉ, gần gấp đ&ocirc;i doanh thu qu&yacute; 4 năm 2019 (318 tỉ), cả năm doanh thu 1.764 tỉ tăng gần 10% so với năm 2019.</p>\r\n<p style=\"text-align: justify;\">Ho&agrave;n thiện sản xuất, mở rộng thị phần, tăng trưởng doanh thu trong năm 2020 sẽ l&agrave; n&ecirc;n tảng cho Tập đo&agrave;n nhựa Đ&ocirc;ng &aacute; - DAG cất c&aacute;nh trong năm 2021 v&agrave; những năm tiếp theo.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><strong><em>Theo: tinnhanhchungkhoan.vn</em></strong></p>',NULL,NULL,'nghien-cuu-san-xuat-san-pham-moi-trong-linh-vuc-trang-tri-noi-that-gop-phan-tang-truong-doanh-thu-loi-nhuan-cho-tap-doan-nhua-dong-a','Nếu như trước đây trong lĩnh vực trang trí nội thất, đá cẩm thạch hay gỗ tự nhiên là vật liệu được dùng để thể hiện sự đẳng cấp, sang trọng nhưng nhược điểm là thi công khó và giá thành cao thì trong thời đại hoàng kim của trang trí nột thất hiện nay, tấm ốp tường, tấm micacrylic DAG của Công ty cổ phần Tập đoàn Nhựa Đông Á (DAG) như một luồng gió mới, mang đến cho người tiêu dùng sự lựa chọn hoàn hảo nhất.',NULL,'Published',2,NULL,0,1,'2021-02-02 02:49:40','2021-02-02 02:49:40',NULL),(29,'Haixun Tutorial - Thiết kế mẫu tủ sách độc lạ với phần mềm Haixun 4.0','2021-02-03 14:55:00','1612341204-haixun-tutorial-thiet-ke-mau-tu-sach-doc-la-voi-phan-mem-haixun-40.png','Haixun là một trong những giải pháp phần mềm hàng đầu cho quá trình thiết kế và sản xuất nội thất gỗ công nghiệp. Haixun có tính linh hoạt cao trong thiết kế, hỗ trợ tạo hình những sản phẩm độc đáo. Sau đây, Nghề nội thất sẽ hướng dẫn quý độc giả các bước thiết kế một mẫu tủ sách độc đáo, bắt mắt.','<p>Đầu ti&ecirc;n, h&atilde;y c&ugrave;ng xem qua bản thiết kế của mẫu tủ:</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/48ejn3LcdMpq77C07fRrBDNYMP0wCGx1SfV93c9D.png\" alt=\"\" width=\"750\" height=\"555\" /></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p><strong>Bước 1:</strong> Tạo khung trống với k&iacute;ch thước bao 1500x400x2000</p>\r\n<p><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/Cb7oR2OkMYtvP4dGexhoAgmWUP7sVRgwzmcB0VQy.png\" alt=\"\" width=\"750\" height=\"401\" /></p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/3VzBuiWMgrIOjQeWCawcfaxiwxT6TBRGE69JiN1r.png\" alt=\"\" width=\"750\" height=\"402\" /></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><strong>Bước 2:</strong> Th&ecirc;m c&aacute;c tấm n&oacute;c, hồi, đ&aacute;y tủ theo k&iacute;ch thước bản vẽ với bộ c&ocirc;ng cụ tấm như h&igrave;nh vẽ</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/xcpH82QQrUXbmPvalZxj9CXVHTLSs2CEjGNPk6f0.png\" alt=\"\" width=\"750\" height=\"402\" /></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Lưu &yacute;: C&aacute;c th&ocirc;ng số về k&iacute;ch thước về tấm hậu (Bảng nối đa năng) c&oacute; thể được điều chỉnh tại bảng b&ecirc;n phải của giao diện thiết kế</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p>Kết quả:</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/59hvznOlYINZDqqRiuq53nRnermL9MTLitaK6Y8w.png\" alt=\"\" width=\"750\" height=\"402\" /></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><strong>Bước 3:</strong> Th&ecirc;m v&agrave; điều chỉnh vị tr&iacute;, k&iacute;ch thước đợt gỗ</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/WUzjEnNm1C3VcjH4lubqeG1iCCQvJ527ePtKPU4H.png\" alt=\"\" width=\"750\" height=\"402\" /></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Kết quả:</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/KputVFJBKvgDyMd1KIV0ggx0izSKhBHKjX6LSxQG.jpeg\" alt=\"\" width=\"750\" height=\"402\" /></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p><strong>Bước 4:</strong> Th&ecirc;m v&agrave; điều chỉnh k&iacute;ch thước tấm cửa</p>\r\n<p><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/LWItPD7q7hEz4uBffRksCfi3XGYLmj5nglmq8szR.png\" alt=\"\" width=\"750\" height=\"401\" /></p>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: justify;\">Kết quả:</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/1n0CVuYlkAngOsK7C3aif7ROVQtioHy4KHxzfp0w.jpeg\" alt=\"\" width=\"750\" height=\"402\" /></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p><strong>Bước 5:</strong> Th&ecirc;m c&aacute;c gi&aacute; để s&aacute;ch với vị tr&iacute; cho trước trong bản vẽ thiết kế</p>\r\n<p><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/1MMYASigDMO6pNWAbpYDBSVgLV2MVbTKiJzxtdm6.jpeg\" alt=\"\" width=\"750\" height=\"401\" /></p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Bước 6:</strong> Điều chỉnh k&iacute;ch thước c&aacute;c tấm theo k&iacute;ch thước trong bản vẽ thiết kế</p>\r\n<p><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/mG2AHM7LUCgbgZSsI4k0x7JjtQAEAl0x14AwgAcM.jpeg\" alt=\"\" width=\"750\" height=\"402\" /></p>\r\n<p>&nbsp;</p>\r\n<p>Kết quả:</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/tryefDLiX7SYOalseWsbTgAC5k5QnqXIHW8jwDg7.jpeg\" alt=\"\" width=\"750\" height=\"402\" /></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p><strong>Bước 7:</strong> Xoay 2 tấm v&aacute;ch tủ như h&igrave;nh vẽ</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/71cMgENlIM8Fz8sigcMaICvmwUazXFFsw709CyBz.jpeg\" alt=\"\" width=\"750\" height=\"402\" /></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p>Kết quả:</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/rLllQnS0OdurZbtWVrHebjODiz6PCECH4iqSzWoY.jpeg\" alt=\"\" width=\"750\" height=\"402\" /></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p><strong>Bước 8</strong>: Lựa chọn m&agrave;u gỗ theo bản vẽ thiết kế</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/XLMXt0JFKNqA8kpULy0z1ZFx7qQH2xH7cg0gg23c.jpeg\" alt=\"\" width=\"750\" height=\"402\" /></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p><strong>Bước 9:</strong> Kiểm tra c&aacute;c li&ecirc;n kết sử dụng sau thiết kế với t&iacute;nh năng (Kiểm tra m&aacute;ng lỗ)</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/8l8UtUkhVUsgZwRWpKFG9dUZUuYK1KeD3rLdD3cP.jpeg\" alt=\"\" width=\"748\" height=\"402\" /></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p>Kết quả:</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/kzyKMzZIs28Ia8GTJfuy4Yr0WZK7hks2t47qkhtf.jpeg\" alt=\"\" width=\"750\" height=\"402\" /></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p><strong>Bước 10:</strong> Kiểm tra vị tr&iacute; v&agrave; sai lệch tấm bản (nếu c&oacute;) sau thiết kế</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/nIs6Sv5ORCPUzHibiGAJry0LJuFLuf8UjaYu3Wbr.jpeg\" alt=\"\" width=\"750\" height=\"402\" /></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Kết quả:&nbsp;</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/0ZDKBIZBqBHt3pa0q8RYUTMbsCWDWcWBXKmphWxS.jpeg\" alt=\"\" width=\"750\" height=\"402\" /></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Sản phẩm cuối c&ugrave;ng:&nbsp;</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/g6BYKrsG6X6ky2rGOcSHi3ZZDurN1iBZ9PJc6EP2.jpeg\" alt=\"\" width=\"750\" height=\"562\" /></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Video hướng dẫn chi tiết:</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><iframe src=\"https://www.youtube.com/embed/oDCTlXuqCzM\" width=\"560\" height=\"315\" frameborder=\"0\" allowfullscreen=\"\"></iframe></p>','Thiết kế mẫu tủ sách độc lạ với phần mềm Haixun 4.0',NULL,'haixun-tutorial-thiet-ke-mau-tu-sach-doc-la-voi-phan-mem-haixun-40','Haixun là một trong những giải pháp phần mềm hàng đầu cho quá trình thiết kế và sản xuất nội thất gỗ công nghiệp. Haixun có tính linh hoạt cao trong thiết kế, hỗ trợ tạo hình những sản phẩm độc đáo. Sau đây, Nghề nội thất sẽ hướng dẫn quý độc giả các bước thiết kế một mẫu tủ sách độc đáo, bắt mắt.','thiết kế nội thất, nội thất, nội thất gỗ, haixun','Published',2,NULL,1,4,'2021-02-03 01:33:24','2021-02-03 03:05:03',NULL),(30,'Hành trình vượt bão ở House3D','2021-02-18 09:47:00','1613617036-hanh-trinh-vuot-bao-o-house3d.jpg','Cú lội ngược dòng ngoạn mục từ bên mép bờ phá sản vào giữa năm 2020 đầy “giông bão”, đến gấp đôi về doanh thu vào cuối năm, được chọn tham gia sáng kiến 100 khởi nghiệp kỳ lân của Microsoft, là một hành trình đầy ấn tượng của của công ty khởi nghiệp House3D.','<h2 style=\"text-align: justify;\"><span style=\"font-size: 12pt;\"><strong>&ldquo;Chiến đấu&rdquo; hoặc l&agrave; &ldquo;chết&rdquo;</strong></span></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">1h30 s&aacute;ng một ng&agrave;y đ&ocirc;ng lạnh gi&aacute;, anh B&ugrave;i Sỹ Nguy&ecirc;n, CEO House3D đ&aacute;p chuyến bay từ TP.HCM ra H&agrave; Nội. Đ&oacute; l&agrave; một chuyến c&ocirc;ng t&aacute;c d&agrave;i ng&agrave;y để thực hiện chuyển đổi số cho một doanh nghiệp kh&aacute; lớn c&ugrave;ng với kế hoạch chuẩn bị x&acirc;y lại đội ngũ ở khu vực miền Nam.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">Kh&aacute; mệt mỏi sau khi về đến nh&agrave; muộn do lịch bay bị tr&igrave; ho&atilde;n v&agrave;i tiếng, vừa chợp mắt chưa được bao l&acirc;u, anh lại vội v&agrave;ng thức giấc chuẩn bị qua gặp gỡ l&atilde;nh đạo một c&ocirc;ng ty sản xuất c&oacute; tầm cỡ để b&agrave;n về kế hoạch hợp t&aacute;c. Cũng may l&agrave; sau hơn hai năm lăn lộn tạo dựng quan hệ hợp t&aacute;c với h&agrave;ng trăm doanh nghiệp, kỹ năng chuẩn bị t&agrave;i liệu v&agrave; thuyết tr&igrave;nh đ&atilde; trở th&agrave;nh một bản năng n&ecirc;n anh kh&ocirc;ng mất nhiều thời gian như những ng&agrave;y đầu.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">Mấy th&aacute;ng vừa qua c&oacute; lẽ l&agrave; qu&atilde;ng thời gian m&agrave; ban l&atilde;nh đạo House3D phải dồn lực v&agrave; tr&iacute; nhiều nhất từ trước đến nay để c&oacute; thể đưa doanh nghiệp vượt qua khủng hoảng. Kh&ocirc;ng chỉ l&agrave; người s&aacute;ng lập, người quản l&yacute;, người l&agrave;m kỹ thuật m&agrave; họ c&ograve;n trở th&agrave;nh những &ldquo;chiến binh b&aacute;n h&agrave;ng&rdquo; thực sự. Đ&acirc;u c&ograve;n c&aacute;ch n&agrave;o kh&aacute;c, hoặc &ldquo;chiến đấu&rdquo;, hoặc l&agrave; &ldquo;chết&rdquo;.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">&ldquo;Nửa năm đầu ch&uacute;ng t&ocirc;i kh&ocirc;ng tin rằng m&igrave;nh c&oacute; thể qua được năm nay v&igrave; tất cả mảng B2C kết nối thiết kế thi c&ocirc;ng tới nh&agrave; d&acirc;n bị đ&oacute;ng băng. Kh&oacute; khăn lớn nhất l&agrave; su&yacute;t nữa ch&uacute;ng t&ocirc;i ph&aacute; sản&rdquo;, nhấp vội ch&eacute;n tr&agrave; n&oacute;ng, anh Nguy&ecirc;n kể lại.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">Từ khi H&agrave; Nội ghi nhận ca nhiễm đầu ti&ecirc;n v&agrave;o th&aacute;ng 3/2020, anh Nguy&ecirc;n đ&atilde; cho to&agrave;n bộ nh&acirc;n vi&ecirc;n l&agrave;m việc trực tuyến bởi lẽ anh x&aacute;c định, l&agrave;m startup đ&atilde; kh&oacute; khăn rồi, nếu startup c&oacute; trường hợp n&agrave;o bị dương t&iacute;nh th&igrave; chắc chắn &ldquo;dẹo&rdquo; ngay lập tức.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">Dịch bệnh khiến cho đội b&aacute;n h&agrave;ng của House3D ho&agrave;n to&agrave;n t&ecirc; liệt, kh&ocirc;ng c&oacute; nguồn tiền về trong khi phải g&aacute;nh chi ph&iacute; rất lớn. Trong khi đ&oacute;, đội l&agrave;m nghi&ecirc;n cứu v&agrave; ph&aacute;t triển (R&amp;D) vẫn hoạt động b&igrave;nh thường nhưng lại l&agrave; đội ti&ecirc;u tiền nhiều nhất.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">&ldquo;C&oacute; những l&uacute;c kh&oacute; khăn đến mức m&agrave; chỗ n&agrave;o vay được th&igrave; ch&uacute;ng t&ocirc;i đ&atilde; vay hết, c&aacute;i g&igrave; b&aacute;n được th&igrave; đ&atilde; b&aacute;n hết, t&agrave;i sản c&aacute; nh&acirc;n c&aacute;i g&igrave; cầm cố được th&igrave; cầm cố hết. Ch&uacute;ng t&ocirc;i phải quản l&yacute; chi ph&iacute; rất lớn, từ hạ tầng m&aacute;y chủ đến nh&acirc;n sự, ph&ograve;ng ốc&hellip;&rdquo;, anh Nguy&ecirc;n cho biết.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">Chỉ ri&ecirc;ng tiền thu&ecirc; văn ph&ograve;ng nằm tr&ecirc;n phố Nguyễn Tu&acirc;n (H&agrave; Nội) đ&atilde; &ldquo;ngốn&rdquo; của House3D 60 triệu đồng mỗi th&aacute;ng. Dịch bệnh kh&oacute; khăn nhưng ngặt nỗi kh&ocirc;ng nhận được sự th&ocirc;ng cảm của chủ t&ograve;a nh&agrave;. C&oacute; những khi kh&ocirc;ng đ&oacute;ng tiền kịp, chủ nh&agrave; li&ecirc;n tục nhắn tin dọa cắt điện, cắt nước ngay cuối ng&agrave;y.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">&ldquo;Cứ mỗi lần như thế t&ocirc;i phải t&igrave;m c&aacute;ch trả trước một &iacute;t, rồi gọi điện n&oacute;i chuyện, d&ugrave;ng hết c&aacute;c khả năng ngoại giao ngọt nhạt, gọi thẳng l&ecirc;n cả tổng gi&aacute;m đốc nhưng cũng kh&ocirc;ng nhận được ch&uacute;t th&ocirc;ng cảm n&agrave;o&rdquo;, anh Nguy&ecirc;n kể lại.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">Cầm cự m&atilde;i đến th&aacute;ng 8, anh quyết định chuyển sang thu&ecirc; một căn hộ rộng 150m2 ở một nơi c&aacute;ch đ&oacute; kh&ocirc;ng xa để l&agrave;m văn ph&ograve;ng với mức ph&iacute; chỉ 15 triệu đồng mỗi th&aacute;ng. Anh Nguy&ecirc;n l&yacute; giải, phải đến cuối th&aacute;ng mới chuyển ra v&igrave; từ qu&yacute; II trở đi đ&atilde; thấy c&oacute; t&iacute;n hiệu hồi phục, nghĩ rằng nếu chuyển văn ph&ograve;ng lại phải mất thời gian sắp xếp n&ecirc;n đ&agrave;nh &ldquo;nghiến răng&rdquo; th&ecirc;m mấy th&aacute;ng. Anh thừa nhận đ&oacute; l&agrave; một điểm chưa hợp l&yacute;.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">Đứng trước nguy cơ ph&aacute; sản, anh Nguy&ecirc;n cũng phải ra quyết định cắt bớt nh&acirc;n sự d&ugrave; đ&oacute; l&agrave; điều kh&ocirc;ng ai muốn. Từ 35 người l&agrave;m việc to&agrave;n thời gian chỉ c&ograve;n 15 người cốt c&aacute;n.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">&ldquo;Quyết định cắt giảm nh&acirc;n sự kh&ocirc;ng hề nằm trong kế hoạch trước đ&oacute; v&igrave; theo quan niệm của giới khởi nghiệp, cắt giảm nh&acirc;n sự m&agrave; phải cắt v&agrave;o phần l&otilde;i th&igrave; coi như đ&oacute; l&agrave; dấu hiệu của một startup sắp chết&rdquo;, CEO House3D cho biết.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">May mắn của House3D l&agrave; chỉ mất một lượng rất &iacute;t nh&acirc;n sự l&otilde;i, phần n&ograve;ng cốt vẫn giữ nguy&ecirc;n. Vấn đề lớn nhất l&agrave; đội ngũ s&aacute;ng lập House3D phải quay cuồng khi c&oacute; một v&agrave;i người trong nh&oacute;m n&ograve;ng cốt ngỏ &yacute; rời đi, nhất l&agrave; người phụ tr&aacute;ch mảng Nội thất một giờ - đang đ&oacute;ng vai tr&ograve; xương sống ở House3D.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">Sau khi người n&agrave;y rời đi, b&ecirc;n cạnh việc phải t&igrave;m c&aacute;ch trả lại khoản tiền vốn g&oacute;p, anh Nguy&ecirc;n c&ograve;n phải t&iacute;nh to&aacute;n để thay thế nh&acirc;n sự, đ&oacute; phải l&agrave; &ldquo;tướng, l&agrave; người t&agrave;i chứ kh&ocirc;ng b&igrave;nh thường được&rdquo; như lời anh m&ocirc; tả. Do một qu&aacute; tr&igrave;nh d&agrave;i kiểm so&aacute;t d&ograve;ng tiền kh&ocirc;ng tốt dẫn đến thua lỗ, c&ugrave;ng một số l&yacute; do kh&aacute;c, mảng n&agrave;y hiện đang được tạm dừng v&agrave; được kỳ vọng sẽ trở lại mạnh mẽ trong năm 2021.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">Đối với c&aacute;c nh&acirc;n sự kh&aacute;c, l&atilde;nh đạo House3D l&ecirc;n kịch bản v&agrave; kế hoạch r&otilde; r&agrave;ng, trước hết l&agrave; th&ocirc;ng b&aacute;o rộng r&atilde;i đến to&agrave;n bộ nh&acirc;n vi&ecirc;n về việc giảm lương v&agrave; khả năng nợ lương nếu dịch bệnh k&eacute;o d&agrave;i. C&oacute; những người v&igrave; điều kiện gia đ&igrave;nh kh&oacute; khăn đ&atilde; chủ động ngỏ &yacute; xin nghỉ. C&oacute; những người được anh Nguy&ecirc;n cho đi &ldquo;cấy rẽ&rdquo; bằng c&aacute;ch gửi nhờ sang c&aacute;c c&ocirc;ng ty uy t&iacute;n m&agrave; anh quen biết.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">Ri&ecirc;ng trong TP.HCM, từ 10 nh&acirc;n sự giảm chỉ c&ograve;n một người duy nhất l&agrave;m kỹ thuật được chuyển về bi&ecirc;n chế của H&agrave; Nội dưới sự quản l&yacute; của ph&oacute; gi&aacute;m đốc phụ tr&aacute;ch văn ph&ograve;ng H&agrave; Nội. Nh&acirc;n sự n&agrave;y l&agrave;m việc từ xa, kh&ocirc;ng c&oacute; văn ph&ograve;ng cố định m&agrave; chỉ d&ugrave;ng ph&ograve;ng họp ở kh&ocirc;ng gian l&agrave;m việc chung mỗi khi cần. Anh Nguy&ecirc;n cho biết, một trong những nhiệm vụ ch&ocirc;ng gai của House3D trong năm 2021 l&agrave; x&acirc;y dựng lại lực lượng ở TP.HCM.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><span style=\"font-size: 12pt;\"><img src=\"/storage/uploads/tinymce/vohQDQu6n42c99WQUz46qlaSCsDUA3jtBdFzwp8i.jpeg\" alt=\"\" width=\"650\" height=\"367\" /></span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<h2 class=\"titxen\"><span style=\"font-size: 12pt;\"><strong>T&igrave;m ra &ldquo;khe cửa hẹp&rdquo;</strong></span></h2>\r\n<p class=\"BodyText1\" style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">Trong nguy c&oacute; cơ, anh Nguy&ecirc;n c&ugrave;ng đội ngũ bắt đầu t&igrave;m ra &ldquo;khe s&aacute;ng&rdquo; v&agrave;o giữa năm 2020. L&atilde;nh đạo House3D nhận thấy doanh số b&aacute;n bản quyền phần mềm thiết kế kh&ocirc;ng nhiều v&agrave; đang dần trở n&ecirc;n &iacute;t quan trọng hơn. Họ quyết định tập trung thực hiện triển khai dịch vụ nền tảng c&ocirc;ng nghệ thiết kế - sản xuất - thương mại, chuyển đổi số cho doanh nghiệp ng&agrave;nh nội thất.</span></p>\r\n<p class=\"BodyText1\" style=\"text-align: justify;\">&nbsp;</p>\r\n<p class=\"BodyText1\" style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">Mảng n&agrave;y đặc biệt đột ph&aacute; v&agrave;o dịp cuối năm khi c&aacute;c doanh nghiệp lớn kh&ocirc;ng những kh&ocirc;ng đầu h&agrave;ng trước Covid-19 m&agrave; c&ograve;n tranh thủ thời gian dịch bệnh để kiểm tra quy tr&igrave;nh nội bộ, l&agrave;m chuyển đổi số để chuẩn bị tốt hơn cho cạnh tranh sau Covid.</span></p>\r\n<p class=\"BodyText1\" style=\"text-align: justify;\">&nbsp;</p>\r\n<p class=\"BodyText1\" style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">Theo CEO House3D, c&aacute;c doanh nghiệp đều c&oacute; nhu cầu chuyển đổi số nhưng lại kh&ocirc;ng c&oacute; đủ thời gian để thực hiện trong điều kiện b&igrave;nh thường khi c&aacute;c quy tr&igrave;nh nghiệp vụ đang chạy tốt, hoạt động b&igrave;nh thường v&agrave; d&ograve;ng tiền vẫn đang về. Khi gặp Covid-19, đa phần hoạt động của doanh nghiệp buộc phải dừng lại trong khi hoạt động chuyển đổi số lại trở n&ecirc;n cấp thiết nhất. Mảng n&agrave;y b&ugrave;ng nổ v&agrave;o qu&yacute; III v&agrave; đến qu&yacute; cuối của năm đ&atilde; c&oacute; c&aacute;c hợp đồng lớn.</span></p>\r\n<p class=\"BodyText1\" style=\"text-align: justify;\">&nbsp;</p>\r\n<p class=\"BodyText1\" style=\"text-align: center;\"><span style=\"font-size: 12pt;\"><em><img src=\"/storage/uploads/tinymce/Wh5GcJvksqfTIwmwIYicoROUWwP7OeqAFkA38kyL.jpeg\" alt=\"\" width=\"650\" height=\"523\" /></em></span><br /><span style=\"font-size: 12pt;\"><em>&ldquo;C&ocirc;ng trường&rdquo; năng động tại House3D</em></span></p>\r\n<p class=\"BodyText1\" style=\"text-align: justify;\">&nbsp;</p>\r\n<p class=\"BodyText1\" style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">Hiện nay House3D chỉ c&oacute; một văn ph&ograve;ng ở miền Bắc, phục vụ dưới dạng tổng đ&agrave;i cho c&aacute;c kh&aacute;ch h&agrave;ng cả ba khu vực Bắc-Trung-Nam, mỗi lần triển khai dự &aacute;n phải cử người đi. Như anh Nguy&ecirc;n gần đ&acirc;y phải bay li&ecirc;n tục.</span></p>\r\n<p class=\"BodyText1\" style=\"text-align: justify;\">&nbsp;</p>\r\n<p class=\"BodyText1\" style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">B&ecirc;n cạnh việc nắm bắt được cơ hội từ nhu cầu chuyển đổi số rất lớn của c&aacute;c doanh nghiệp, theo l&yacute; giải của anh Nguy&ecirc;n, năm trước chiến lược c&ograve;n chưa đến tầm th&igrave; giai đoạn n&agrave;y lại đ&uacute;ng v&agrave;o sự b&ugrave;ng nổ theo chu kỳ. Năm 2019, House3D chỉ mới tập trung l&agrave;m rất s&acirc;u mảng R&amp;D, nhiều thứ c&ograve;n dang dở. Năm 2020, c&ocirc;ng nghệ v&agrave; sản phẩm ho&agrave;n thiện hơn, dịch vụ tốt hơn v&agrave; sức cạnh tranh lớn hơn.</span></p>\r\n<p class=\"BodyText1\" style=\"text-align: justify;\">&nbsp;</p>\r\n<p class=\"BodyText1\" style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">Nhớ lại những hợp đồng đầu ti&ecirc;n trở lại sau nửa năm kh&oacute; khăn, anh Nguy&ecirc;n cho biết, đội ngũ b&aacute;n h&agrave;ng ở cấp thấp của House3D kh&ocirc;ng đủ năng lực tư vấn trong m&ugrave;a dịch, c&aacute;ch b&aacute;n h&agrave;ng như cũ kh&ocirc;ng thể &aacute;p dụng trong giai đoạn n&agrave;y. Từ khi hết gi&atilde;n c&aacute;ch, cả ba l&atilde;nh đạo cốt c&aacute;n nhất của House3D phải &ldquo;lao ra ngo&agrave;i đường b&aacute;n h&agrave;ng&rdquo;; v&agrave; d&ugrave; ngồi họp với kh&aacute;ch phải đeo khẩu trang nhưng cũng phải t&igrave;m mọi c&aacute;ch để tiếp cận. Đ&oacute; l&agrave; thời điểm v&agrave;ng, cần phải nắm bắt.</span></p>\r\n<p class=\"BodyText1\" style=\"text-align: justify;\">&nbsp;</p>\r\n<p class=\"BodyText1\" style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">V&agrave; rồi, một loạt doanh nghiệp sản xuất thuộc loại lớn nhất ở Việt Nam đ&atilde; t&igrave;m đến, một doanh nghiệp lớn kh&aacute;c trong mảng thương mại vốn l&agrave; kh&aacute;ch h&agrave;ng của House3D cũng tiếp tục chốt th&ecirc;m c&aacute;c hợp đồng mới c&oacute; gi&aacute; trị lớn hơn. D&ugrave; vậy, hợp đồng k&yacute; v&agrave;o th&aacute;ng 6 nhưng m&atilde;i đến th&aacute;ng 8 mới c&oacute; tiền về, theo kiểu nhỏ giọt. Đ&oacute; l&agrave; khoảng thời gian m&agrave; l&atilde;nh đạo House3D phải t&igrave;m mọi c&aacute;ch để cầm cự.</span></p>\r\n<p class=\"BodyText1\" style=\"text-align: justify;\">&nbsp;</p>\r\n<p class=\"BodyText1\" style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">Đến cuối th&aacute;ng 9, House3D quyết định th&iacute; điểm dự &aacute;n kết nối ph&acirc;n phối đồ nội thất th&ocirc;ng qua nền tảng House3D với hy vọng t&igrave;m được nguồn tiền mới v&igrave; d&ograve;ng tiền về từ c&aacute;c hợp đồng chuyển đổi số chỉ mới đ&aacute;p ứng y&ecirc;u cầu tối thiểu để duy tr&igrave; doanh nghiệp. Th&ocirc;ng qua k&ecirc;nh n&agrave;y, người mua h&agrave;ng c&oacute; thể mua được mức gi&aacute; thấp hơn so với mua trực tiếp ở cửa h&agrave;ng, c&aacute;c đối t&aacute;c của House3D cũng c&oacute; được một k&ecirc;nh ph&acirc;n phối tiềm năng.</span></p>\r\n<p class=\"BodyText1\" style=\"text-align: justify;\">&nbsp;</p>\r\n<p class=\"BodyText1\" style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">Bất ngờ l&agrave; chỉ trong một qu&yacute;, doanh số từ mảng kết nối ph&acirc;n phối nội thất đ&atilde; bằng tổng doanh số của c&aacute;c mảng c&ograve;n lại trong suốt cả năm. Đ&oacute; l&agrave; một điểm s&aacute;ng. L&atilde;nh đạo House3D cho biết đang kỳ vọng nhiều hơn về mảng n&agrave;y trong năm 2021 với tỷ lệ doanh số c&oacute; thể tăng l&ecirc;n đến 70-80%.</span></p>\r\n<p class=\"BodyText1\" style=\"text-align: justify;\">&nbsp;</p>\r\n<p class=\"BodyText1\" style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">Một số mảng kh&aacute;c của House3D cũng bắt đầu &ldquo;nảy số&rdquo; như chuyển đổi số cho ng&agrave;nh bất động sản, du lịch v&agrave; bảo t&agrave;ng. Kể cả sau khi dịch kết th&uacute;c, mảng n&agrave;y vẫn được đ&aacute;nh gi&aacute; l&agrave; c&oacute; tiềm năng do th&oacute;i quen của người ti&ecirc;u d&ugrave;ng đ&atilde; thay đổi theo xu hướng O2O (tiếp cận trực tuyến trước rồi đến mua h&agrave;ng trực tiếp tại cửa h&agrave;ng).</span></p>\r\n<p class=\"BodyText1\" style=\"text-align: justify;\">&nbsp;</p>\r\n<p class=\"BodyText1\" style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">Đến nay, House3D đ&atilde; c&oacute; tất cả bốn nh&oacute;m sản phẩm ch&iacute;nh. Một l&agrave; giải ph&aacute;p c&ocirc;ng nghệ nền tảng House3D ki&ecirc;m dịch vụ chuyển đổi số theo nguy&ecirc;n l&yacute; C2M (từ người ti&ecirc;u d&ugrave;ng tới nh&agrave; m&aacute;y). Hai l&agrave; Nội thất một giờ, kết nối thiết kế thi c&ocirc;ng tới nh&agrave; d&acirc;n. Ba l&agrave; dịch vụ kết nối ph&acirc;n phối đồ nội thất th&ocirc;ng qua nền tảng House3D.</span></p>\r\n<p class=\"BodyText1\" style=\"text-align: justify;\">&nbsp;</p>\r\n<p class=\"BodyText1\" style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">Bốn l&agrave; ứng dụng dữ liệu lớn (Big data) v&agrave; tr&iacute; tuệ nh&acirc;n tạo (AI) để hỗ trợ người d&acirc;n tự diễn họa kh&ocirc;ng gian nh&agrave; theo đ&uacute;ng &yacute; của m&igrave;nh. Mảng thứ tư dự kiến sẽ ch&iacute;nh thức được ra mắt v&agrave;o cuối 2021 khi đ&atilde; c&oacute; lượng dữ liệu đủ lớn về sản phẩm, đơn gi&aacute;, kết xuất đồ họa&hellip;</span></p>\r\n<p class=\"BodyText1\" style=\"text-align: justify;\">&nbsp;</p>\r\n<p class=\"BodyText1\" style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">Đến đầu th&aacute;ng 12/2020, House3D đ&oacute;n nhận tin vui khi l&agrave; một trong 23 startup ch&acirc;u &Aacute; &ndash; Th&aacute;i B&igrave;nh Dương lọt danh s&aacute;ch c&aacute;c startup được Microsoft lựa chọn tham gia s&aacute;ng kiến &ldquo;Highway to a 100 Unicorns&rdquo; (tạm dịch: con đường trở th&agrave;nh 100 c&ocirc;ng ty khởi nghiệp kỳ l&acirc;n).</span></p>\r\n<p class=\"BodyText1\" style=\"text-align: justify;\">&nbsp;</p>\r\n<p class=\"BodyText1\" style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">Ngo&agrave;i nhận được t&agrave;i trợ từ Microsoft về m&aacute;y chủ v&agrave; hỗ trợ giải quyết c&aacute;c vấn đề nan giải về hạ tầng c&ocirc;ng nghệ, giải ph&aacute;p của House3D c&ograve;n được Microsoft giới thiệu tới c&aacute;c kh&aacute;ch h&agrave;ng tiềm năng l&agrave; c&ocirc;ng ty v&agrave; tập đo&agrave;n lớn tại Việt Nam.</span></p>\r\n<p class=\"BodyText1\" style=\"text-align: justify;\">&nbsp;</p>\r\n<p class=\"BodyText1\" style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">L&atilde;nh đạo House3D c&ograve;n được tham gia c&aacute;c kh&oacute;a huấn luyện m&agrave; cố vấn ch&iacute;nh l&agrave; c&aacute;c tỷ ph&uacute; đ&ocirc; la đ&atilde; rất s&agrave;nh sỏi tr&ecirc;n thương trường. Đ&oacute; l&agrave; những b&agrave;i học về tinh thần doanh nh&acirc;n, c&aacute;ch đối mặt với th&aacute;ch thức, xử l&yacute; khủng hoảng, giải quyết b&agrave;i to&aacute;n d&ograve;ng tiền&hellip; Theo anh Nguy&ecirc;n, đ&oacute; l&agrave; những thứ qu&yacute; gi&aacute; nhất m&agrave; anh nhận được.</span></p>\r\n<p class=\"BodyText1\" style=\"text-align: justify;\">&nbsp;</p>\r\n<p class=\"TITDAM\" style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">Sau một năm đầy biến động vừa qua, House3D kết th&uacute;c 2020 một c&aacute;ch &ecirc;m đẹp khi doanh số tăng gấp đ&ocirc;i so với năm ngo&aacute;i, mặc d&ugrave; kế hoạch đ&atilde; đặt ra trong 2019 l&agrave; gấp năm lần. Đ&acirc;y l&agrave; một sự tự h&agrave;o cho đội ngũ House3D trước nỗ lực đưa doanh nghiệp tho&aacute;t khỏi &ldquo;cửa tử&rdquo; v&agrave; sẵn s&agrave;ng cho sự b&ugrave;ng nổ trong năm 2021 với kế hoạch tận dụng điểm rơi của chu kỳ sử dụng vốn để &ldquo;đ&aacute;nh mạnh&rdquo; thị trường Đ&ocirc;ng Nam &Aacute;.</span></p>\r\n<p class=\"TITDAM\" style=\"text-align: justify;\">&nbsp;</p>\r\n<p class=\"TITDAM\" style=\"text-align: justify;\">&nbsp;</p>\r\n<p class=\"TITDAM\" style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">Theo: Theleader.vn</span></p>','Hành trình vượt bão ở House3D',NULL,'hanh-trinh-vuot-bao-o-house3d','Cú lội ngược dòng ngoạn mục từ bên mép bờ phá sản vào giữa năm 2020 đầy “giông bão”, đến gấp đôi về doanh thu vào cuối năm, được chọn tham gia sáng kiến 100 khởi nghiệp kỳ lân của Microsoft, là một hành trình đầy ấn tượng của của công ty khởi nghiệp House3D.','thiết kế nội thất, nội thất, phần mềm nội thất','Published',2,NULL,0,10,'2021-02-17 19:57:16','2021-02-21 20:49:01',NULL),(31,'Tải và dùng thử phần mềm nội thất Cabinet Vision - Download & Demo','2021-02-16 14:14:00','1613632718-tai-va-dung-thu-phan-mem-noi-that-cabinet-vision-download-demo.png','Cabinet Vision là công cụ phần mềm hàng đầu trong ngành để thiết kế và sản xuất tủ bếp, tủ đựng quần áo, đồ dùng thương mại và hơn thế nữa. Nghề nội thất xin giới thiệu và cung cấp link download dùng thử phần mềm này tới các bạn.','<h2 style=\"text-align: justify;\"><span style=\"font-size: 12pt;\"><strong>Cabinet Vision</strong></span></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">CABINET VISION l&agrave; một c&ocirc;ng cụ phần mềm thiết kế v&agrave; sản xuất cho ph&eacute;p bạn tr&igrave;nh b&agrave;y chi tiết tất cả c&aacute;c c&ocirc;ng việc của m&igrave;nh, từ tủ bếp đến c&aacute;c dự &aacute;n kiến ​​tr&uacute;c phức tạp. Phi&ecirc;n bản Solid Advanced tự động tạo bản vẽ, kết xuất 3D, y&ecirc;u cầu vật liệu, bảng lắp r&aacute;p v&agrave; dữ liệu ước t&iacute;nh. Bố tr&iacute; đồ họa c&ocirc;ng việc của bạn để nhanh ch&oacute;ng tạo bản vẽ cửa h&agrave;ng của bạn hoặc sử dụng chức năng Nhập đơn h&agrave;ng được t&iacute;ch hợp sẵn để ước t&iacute;nh nhanh ch&oacute;ng.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">C&aacute;c thanh ribbon dễ d&agrave;ng điều hướng gi&uacute;p định vị c&aacute;c mục dễ d&agrave;ng. Danh s&aacute;ch tủ v&agrave; thiết kế m&agrave;n h&igrave;nh chia nhỏ cung cấp sơ đồ mặt bằng, độ cao v&agrave; g&oacute;c nh&igrave;n phối cảnh, c&oacute; thể được hiển thị tất cả tr&ecirc;n một m&agrave;n h&igrave;nh. X&acirc;y dựng menu &lsquo;Y&ecirc;u th&iacute;ch&rsquo; từ c&aacute;c mục được sử dụng thường xuy&ecirc;n nhất, tiết kiệm thời gian t&igrave;m kiếm trong thư viện. Tự động điền v&agrave;o một kế hoạch với tủ, khu&ocirc;n v&agrave; mặt b&agrave;n chỉ bằng một n&uacute;t nhấn.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><span style=\"font-size: 12pt;\"><img src=\"/storage/uploads/tinymce/EjuwA0hA7ZGvkmUWj3YdBXtZFzO0QxjwiBZXRgkt.png\" alt=\"\" width=\"750\" height=\"389\" /></span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<h3 style=\"text-align: justify;\"><strong><span style=\"font-size: 12pt;\">Tải Cabinet Vision&nbsp;</span></strong></h3>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">C&aacute;c bạn c&oacute; thể tải bản c&agrave;i đặt Cabinet Vision từ nghenoithat.vn tại link sau: <a href=\"https://drive.google.com/file/d/1BByUCznTjfITBRAMQht7RenpRZGYlfD2/view?usp=sharing\">Download Cabinet Vision</a></span><br /><em><span style=\"font-size: 12pt;\">Pass giải n&eacute;n: nghenoithat.vn</span></em></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<h2 style=\"text-align: justify;\"><strong><span style=\"font-size: 12pt;\">D&ugrave;ng thử v&agrave; trải nghiệm Cabinet Vision</span></strong></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">Nghenoithat.vn hiện tại đang c&oacute; chương tr&igrave;nh d&ugrave;ng thử v&agrave; hướng dẫn demo phần mềm, gi&uacute;p người sử dụng l&agrave;m quen với c&aacute;c phần mềm mới dễ d&agrave;ng v&agrave; nhanh ch&oacute;ng. Qu&yacute; bạn đọc c&oacute; nhu cầu demo hướng dẫn l&agrave;m quen c&oacute; thể li&ecirc;n hệ ch&uacute;ng t&ocirc;i qua số điện thoại 0866.059.659&nbsp;để đăng k&yacute;.</span></p>','Tải và dùng thử phần mềm nội thất Cabinet Vision - Download & Demo',NULL,'tai-va-dung-thu-phan-mem-noi-that-cabinet-vision-download-demo','Cabinet Vision là công cụ phần mềm hàng đầu trong ngành để thiết kế và sản xuất tủ bếp, tủ đựng quần áo, đồ dùng thương mại và hơn thế nữa. Nghề nội thất xin giới thiệu và cung cấp link download dùng thử phần mềm này tới các bạn.','Phần mềm Cabinet Vision, phần mềm gỗ, phần mềm cnc, cnc gỗ','Published',2,NULL,1,3,'2021-02-18 00:18:38','2022-07-20 01:59:19',NULL),(32,'Top 5 phần mềm thiết kế nội thất và sản xuất nội thất gỗ công nghiệp tốt nhất 2021','2021-03-08 16:01:00','1615195987-top-5-phan-mem-thiet-ke-noi-that-va-san-xuat-go-cong-nghiep-tot-nhat-2021.jpg','Hiện nay, sản xuất đồ nội thất gỗ công nghiệp đang dần trở thành một xu thế tất yếu bên cạnh việc xây dựng các công trình dân sinh cũng như phục vụ mục đích thương mại. Vì vậy, nhu cầu sử dụng các phần mềm sản xuất chuyên dụng nhằm tiết kiệm được thời gian, chi phí cho các doanh nghiệp ngành gỗ cũng được tăng lên đáng kể. Hôm nay, Nghề nội thất sẽ giới thiệu tới bạn đọc Top 5 phần mềm thiết kế và sản xuất đồ nội thất gỗ công nghiệp phổ biến hiện nay trên thị trường','<h2><strong>1. Cabinet Vision:</strong>&nbsp;</h2>\r\n<p>Cabinet Vision l&agrave; giải ph&aacute;p kỹ thuật ho&agrave;n thiện cho ng&agrave;nh sản xuất tủ gỗ c&ocirc;ng nghiệp. Được tin d&ugrave;ng &nbsp;hơn 35000 kĩ sư thiết kế chuy&ecirc;n v&agrave; kh&ocirc;ng chuy&ecirc;n tại hơn 52 quốc gia tr&ecirc;n to&agrave;n thế giới.&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/6zIBtHgcnr8I2yG2QMc5xaNyrdkhjlAxX4BiylUr.png\" alt=\"phan-mem-noi-that-cabinet-vision\" width=\"650\" height=\"343\" /></p>\r\n<p>&nbsp;</p>\r\n<p>Cabinet Vision đ&atilde; x&acirc;y dựng ph&aacute;t triển c&aacute;c giải ph&aacute;p phần mềm, n&acirc;ng cao chất lượng v&agrave; t&iacute;nh ứng dụng trong ng&agrave;nh sản xuất nội thất trong hơn 30 năm. Hiện nay, phần mềm đ&atilde; c&oacute; thể sử dụng với 13 ng&ocirc;n ngữ kh&aacute;c nhau.</p>\r\n<p>T&igrave;m hiểu th&ecirc;m về Cabinet Vision tại: <a href=\"/san-pham/cabinet-vision\" target=\"_blank\" rel=\"noopener\">Phần mềm Cabinet Vision</a></p>\r\n<p>&nbsp;</p>\r\n<h2><strong>2. PYTHA:</strong></h2>\r\n<p>PYTHA được ph&aacute;t triển bởi PYTHA Lab (1978), c&ocirc;ng ty chuy&ecirc;n cung cấp c&aacute;c giải ph&aacute;p về thiết kế nội thất gỗ c&ocirc;ng nghiệp tại Đức. Được coi l&agrave; một trong những giải ph&aacute;p tổng thể h&agrave;ng đầu tr&ecirc;n thế giới với những t&iacute;nh năng đa dạng như: Linh hoạt trong tạo h&igrave;nh, t&iacute;nh thống nhất, hệ thống trong to&agrave;n bộ quy tr&igrave;nh từ marketing b&aacute;n h&agrave;ng, thiết kế cho đến gia c&ocirc;ng, sản xuất.</p>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/CkjYH3r7IYBBwJCKmxFqQxZwez9TPZQ7D8u0B21j.jpeg\" alt=\"phan-mem-noi-that-pytha\" width=\"650\" height=\"365\" />&nbsp;</p>\r\n<p style=\"text-align: justify;\"><br />&nbsp;Ưu điểm:<br />- &nbsp;C&ocirc;ng cụ tạo h&igrave;nh mạnh mẽ, đa dạng về c&aacute;ch thức, linh hoạt trong t&ugrave;y biến k&iacute;ch thước, tương quan vị tr&iacute; của c&aacute;c chi tiết trong đối tượng 3D<br />- Thực hiện việc tối ưu xếp v&aacute;n kh&ocirc;ng cần th&ecirc;m phần mềm hỗ trợ&nbsp;<br />- Th&iacute;ch hợp cho bộ phận d&aacute;n tem nh&atilde;n tự động của m&aacute;y CNC trung t&acirc;m<br />- T&iacute;nh năng Radio Lab mạnh mẽ, ch&acirc;n thực<br />&nbsp;<br />T&igrave;m hiểu th&ecirc;m về PYTHA tại: <a href=\"/san-pham/phan-mem-noi-that-go-pytha\">Phần mềm PYTHA</a></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<h2><strong>3. Haixun:</strong></h2>\r\n<p>Haixun được ph&aacute;t triển bởi Hisoonsoft, c&ocirc;ng ty chuy&ecirc;n cung cấp c&aacute;c giải ph&aacute;p về thiết kế nội thất gỗ c&ocirc;ng nghiệp, c&oacute; trụ sở tại Thanh Đảo (Trung Quốc). Đ&acirc;y được coi l&agrave; giải ph&aacute;p thiết kế v&agrave; sản xuất to&agrave;n diện h&agrave;ng đầu tại khu vực, đối thủ nặng k&yacute; của c&aacute;c phần mềm kh&aacute;c về t&iacute;nh ứng dụng.</p>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/ziTch8hK839Jr46zpvvrVJI0eXjRlFvxZkKleunb.png\" alt=\"phan-mem-noi-that-haixun\" width=\"650\" height=\"352\" /></p>\r\n<p>&nbsp;</p>\r\n<p>Ưu điểm:<br />- &nbsp;C&ocirc;ng cụ tạo h&igrave;nh đa dạng về c&aacute;ch thức, linh hoạt về việc chỉnh sửa k&iacute;ch thước, tương quan vị tr&iacute; của c&aacute;c chi tiết trong tủ<br />- &nbsp;Quản l&yacute; c&aacute;c đơn h&agrave;ng nhanh ch&oacute;ng, thuận tiện<br />- Thực hiện việc tối ưu xếp v&aacute;n kh&ocirc;ng cần th&ecirc;m phần mềm hỗ trợ<br />- Th&iacute;ch hợp cho bộ phận d&aacute;n tem nh&atilde;n tự động của m&aacute;y CNC trung t&acirc;m<br />- Hỗ trợ t&iacute;nh năng Cloud Rendering cập nhật theo thời gian thực</p>\r\n<p>T&igrave;m hiểu th&ecirc;m về Haixun tại: <a href=\"/san-pham/phan-mem-noi-that-go-haixun\">Phần mềm Haixun</a></p>\r\n<p>&nbsp;</p>\r\n<h2><strong>4. Bazis:&nbsp;</strong></h2>\r\n<p><strong>Bazis </strong><span style=\"font-weight: 400;\">l&agrave; một phần mềm hỗ trợ to&agrave;n bộ qu&aacute; tr&igrave;nh sản xuất đồ gỗ từ thiết kế, b&oacute;c t&aacute;ch, dự to&aacute;n nguy&ecirc;n vật liệu, điều khiển m&aacute;y cưa, m&aacute;y khoan, quản l&yacute; kho vật tư, bao g&oacute;i v.v&hellip;</span></p>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: center;\"><span style=\"font-weight: 400;\"><img src=\"/storage/uploads/tinymce/8N1djmbyRha8aGbaokIvgWzqwHDoMlKOi4oS8YGx.jpeg\" alt=\"\" width=\"650\" height=\"406\" /></span></p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-weight: 400;\">Đặc biệt, người thiết kế c&oacute; thể lựa chọn Bazis Cabinet với khả năng thiết kế linh hoạt c&aacute;c module tủ, kệ th&ocirc;ng dụng hoặc Bazis Mebelshik - phi&ecirc;n bản chuy&ecirc;n dụng xử l&yacute; c&aacute;c thiết kế với bi&ecirc;n dạng đặc biệt.</span></p>\r\n<p>&nbsp;</p>\r\n<h2><strong>5. Baicic:</strong></h2>\r\n<p><span style=\"font-weight: 400;\">Baicic software design: L&agrave; phần mềm thiết kế, b&oacute;c t&aacute;ch, quản l&yacute;, chuyển giao sản xuất nội thất gỗ c&ocirc;ng nghiệp được sử dụng cho c&aacute;c đơn vị c&oacute; quy m&ocirc; nhỏ v&agrave; vừa.</span></p>\r\n<p><span style=\"font-weight: 400;\">&nbsp;</span></p>\r\n<p style=\"text-align: center;\"><span style=\"font-weight: 400;\"><img src=\"/storage/uploads/tinymce/cBKFCH7VGyjSwuwOuO0xXibQ7yigNxJnz9rxDELt.jpeg\" alt=\"\" width=\"650\" height=\"365\" /></span></p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-weight: 400;\">Baicic thưể hiện sự ưu việt của m&igrave;nh ở khả năng nesting th&ocirc;ng minh; t&iacute;nh to&aacute;n vật tư phụ kiện tương đối ch&iacute;nh x&aacute;c. Th&ecirc;m v&agrave;o đ&oacute;, cấu h&igrave;nh phần cứng để sử dụng được Baicic cũng y&ecirc;u cầu kh&ocirc;ng qu&aacute; cao</span></p>',NULL,NULL,'top-5-phan-mem-thiet-ke-noi-that-va-san-xuat-noi-that-go-cong-nghiep-tot-nhat-2021','Hiện nay, sản xuất đồ nội thất gỗ công nghiệp đang dần trở thành một xu thế tất yếu bên cạnh việc xây dựng các công trình dân sinh cũng như phục vụ mục đích thương mại. Vì vậy, nhu cầu sử dụng các phần mềm sản xuất chuyên dụng nhằm tiết kiệm được thời gian, chi phí cho các doanh nghiệp ngành gỗ cũng được tăng lên đáng kể. Hôm nay, Nghề nội thất sẽ giới thiệu tới bạn đọc Top 5 phần mềm thiết kế và sản xuất đồ nội thất gỗ công nghiệp phổ biến hiện nay trên thị trường','thiết kế nội thất, nội thất, nội thất gỗ, phần mềm thiết kế nội thất, cabinet vision, pytha, haixun,','Published',2,NULL,1,10,'2021-03-08 02:33:07','2021-03-17 21:25:16',NULL),(33,'Webinar online với chủ đề “Tự động hóa trong sản xuất nội thất gỗ công nghiệp”','2021-03-18 10:56:00','1616040554-hoi-thao-online-voi-chu-de-tu-dong-hoa-trong-san-xuat-noi-that-go-cong-nghiep.png','Vào 09h00 ngày 31/03/2021, Website nghenoithat.vn phối hợp cùng Hãng phần mềm nội thất Haixun, tổ chức hội thảo online với chủ đề “Tự động hóa trong sản xuất nội thất gỗ công nghiệp”.','<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Hiện nay, ứng dụng c&ocirc;ng nghệ đang l&agrave; xu hướng trong mọi lĩnh vực, v&agrave; ng&agrave;nh sản xuất nội thất cũng kh&ocirc;ng phải l&agrave; ngoại lệ. Việc ứng dụng c&ocirc;ng nghệ trong sản xuất gỗ c&ocirc;ng nghiệp gi&uacute;p tạo quy tr&igrave;nh kh&eacute;p k&iacute;n đảm bảo chất lượng sản phẩm, giảm ti&ecirc;u hao nguy&ecirc;n vật liệu, cắt giảm thời gian v&agrave; nh&acirc;n c&ocirc;ng, &hellip; Tuy nhi&ecirc;n, việc ứng dụng c&ocirc;ng nghệ v&agrave;o sản xuất vẫn chưa phổ biến ở thị trường Việt Nam.</span></p>\r\n<p style=\"text-align: justify;\"><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Nhận thức được thực trạng đ&oacute;, ch&uacute;ng t&ocirc;i, trang th&ocirc;ng tin tổng hợp Nghenoithat.vn, tr&acirc;n trọng mời Qu&yacute; kh&aacute;ch h&agrave;ng, Qu&yacute; độc giả tham dự webinar với chủ đề &ldquo;Tự động h&oacute;a trong sản xuất nội thất gỗ c&ocirc;ng nghiệp&rdquo;</span></p>\r\n<p style=\"text-align: justify;\"><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Nghenoithat.vn sẽ phối hợp với H&atilde;ng sản xuất phần mềm nội thất h&agrave;ng đầu thị trường Trung Quốc, Haixun tổ chức chương tr&igrave;nh hội thảo trực tuyến với mục ti&ecirc;u gi&uacute;p c&aacute;c đơn vị doanh nghiệp đang hoạt động trong lĩnh vực, thiết kế v&agrave; sản xuất đồ nội thất c&oacute; g&oacute;c nh&igrave;n tổng quan về thị trường ng&agrave;nh nội thất tại Việt Nam, m&ocirc; h&igrave;nh, hiện trạng ứng dụng c&ocirc;ng nghệ v&agrave;o sản xuất đồ nội thất của c&aacute;c doanh nghiệp hiện nay, đồng thời c&oacute; cơ hội tiếp cận t&igrave;m hiểu c&aacute;c c&ocirc;ng nghệ, giải ph&aacute;p mới c&oacute; thể ứng dụng trong sản xuất.&nbsp;</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/CgERhpigahqO5aOWJ8LWHV58A806g8XMS9n3pGiu.jpeg\" alt=\"webiner-phan-mem-noi-that-haixun\" width=\"700\" height=\"446\" /></p>\r\n<p style=\"text-align: justify;\"><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Chương tr&igrave;nh webinar sẽ được diễn ra từ 09h00 &ndash; 10h30 (giờ H&agrave; Nội), ng&agrave;y 31/03/2021.&nbsp;</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Qu&yacute; kh&aacute;ch h&agrave;ng, Qu&yacute; độc giả c&oacute; thể đăng k&yacute; tham dự Hội thảo bằng c&aacute;ch qu&eacute;t m&atilde; QR tr&ecirc;n h&igrave;nh ảnh hoặc đăng k&yacute; tại đ&acirc;y: <a href=\"https://docs.google.com/forms/d/e/1FAIpQLSdz2oCLihbqAi-WeJmgiPbPouKIrAkUqCXl8XOx_qlEMMpfkA/viewform\" target=\"_blank\" rel=\"noopener\">Đăng k&yacute; tham dự</a></span></p>\r\n<p style=\"text-align: justify;\"><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Nghenoithat.vn xin tr&acirc;n trọng th&ocirc;ng b&aacute;o để Qu&yacute; kh&aacute;ch h&agrave;ng, Qu&yacute; độc giả quan t&acirc;m c&oacute; thể đăng k&yacute; tham dự. Rất hi vọng c&oacute; được sự tham gia của Qu&yacute; vị./.</span></p>','Hội thảo online với chủ đề “Tự động hóa trong sản xuất nội thất gỗ công nghiệp”','https://nghenoithat.vn/bai-viet/webiner-chu-de-tu-dong-hoa-trong-san-xuat-noi-that-go-cong-nghiep','webinar-online-voi-chu-de-tu-dong-hoa-trong-san-xuat-noi-that-go-cong-nghiep','Vào 09h00 ngày 31/03/2021, Website nghenoithat.vn phối hợp cùng Hãng phần mềm nội thất Haixun, tổ chức hội thảo online với chủ đề “Tự động hóa trong sản xuất nội thất gỗ công nghiệp”.','thiết kế nội thất, nội thất, nội thất gỗ, công nghệ gỗ, phần mềm gỗ, haixun','Published',2,NULL,1,10,'2021-03-17 21:09:14','2021-03-24 21:19:08',NULL),(34,'Về thị trường nội địa, doanh nghiệp gỗ chạy đua công nghệ','2021-03-31 13:32:00','1617172399-ve-thi-truong-noi-dia-doanh-nghiep-go-chay-dua-cong-nghe.jpg','Trong thị trường cạnh tranh ngày càng tăng, và yêu cầu khắt khe, công nghệ trở thành yếu tố quyết định trong cuộc đua giành thị phần tại thị trường nội thất.','<p style=\"text-align: justify;\">Gia nhập thị trường nội thất Việt Nam chưa bao l&acirc;u, Meister đ&atilde; g&acirc;y ch&uacute; &yacute; v&igrave; c&aacute;ch l&agrave;m ho&agrave;n to&agrave;n mới: l&agrave;m trung gian giữa c&aacute;c c&ocirc;ng ty thiết kế nhỏ kh&ocirc;ng mạnh về tiếp thị hoặc những xưởng nội thất nhỏ &iacute;t vốn, với người mua sau c&ugrave;ng. Hay n&oacute;i c&aacute;ch kh&aacute;c, Meister cung cấp những hỗ trợ cần thiết, gi&uacute;p c&aacute;c doanh nghiệp nội thất nhỏ b&aacute;n sản phẩm cho người ti&ecirc;u d&ugrave;ng một c&aacute;ch hiệu quả hơn.</p>\r\n<h2 style=\"text-align: justify;\"><strong>Quay về nội địa</strong></h2>\r\n<p style=\"text-align: justify;\">Đằng sau Meister ch&iacute;nh l&agrave; H&auml;fele, nh&agrave; cung cấp giải ph&aacute;p cho dự &aacute;n v&agrave; nh&agrave; ở th&ocirc;ng minh nổi tiếng của Đức. Th&ocirc;ng qua mạng x&atilde; hội v&agrave; c&aacute;c nền tảng trực tuyến, Meister sẽ thu h&uacute;t người ti&ecirc;u d&ugrave;ng rồi đưa họ đến đối t&aacute;c để c&oacute; thể l&agrave;m việc trực tiếp với người ti&ecirc;u d&ugrave;ng về đo đạc, thiết kế v&agrave; lắp đặt. Từ c&aacute;c chi tiết nội thất kh&aacute;c nhau do Meister cung cấp, đối t&aacute;c c&oacute; thể chọn sản phẩm ph&ugrave; hợp với nhu cầu của kh&aacute;ch h&agrave;ng v&agrave; H&auml;fele sẽ đưa đi sản xuất. Meister cũng tổ chức đ&agrave;o tạo về sản phẩm, dịch vụ v&agrave; chiến lược kinh doanh để đối t&aacute;c c&oacute; thể phục vụ kh&aacute;ch h&agrave;ng tốt hơn.</p>\r\n<p style=\"text-align: justify;\">Theo &ocirc;ng Dominik Fruth, Tổng Gi&aacute;m đốc H&auml;fele Việt Nam, Meister được ph&aacute;t triển từ phần mềm t&ugrave;y chỉnh (configurator) của doanh nghiệp n&agrave;y. Phần mềm đ&oacute; cho ph&eacute;p kh&aacute;ch h&agrave;ng doanh nghiệp đặt mua trực tuyến phụ kiện v&agrave; c&aacute;c chi tiết nội thất như v&aacute;n gỗ được cắt theo y&ecirc;u cầu, khung nh&ocirc;m, hộc tủ&hellip; Phần mềm t&ugrave;y chỉnh khi đ&oacute; sẽ tạo &ldquo;hồ sơ&rdquo; sản xuất c&oacute; thể gửi đến một trong nhiều đối t&aacute;c sản xuất của H&auml;fele tại nơi gần với kh&aacute;ch h&agrave;ng nhất.</p>\r\n<p style=\"text-align: justify;\">&Ocirc;ng Dominik Fruth cho biết: &ldquo;Thời gian qua, ch&uacute;ng t&ocirc;i đầu tư nhiều v&agrave;o việc số h&oacute;a tất cả phụ kiện theo định dạng CAD/CAM để phần mềm sản xuất nội thất c&oacute; thể đọc được th&ocirc;ng tin sản phẩm. Qua đ&oacute;, ch&uacute;ng t&ocirc;i c&oacute; thể gi&uacute;p c&aacute;c thợ mộc truyền thống n&acirc;ng cấp d&acirc;y chuyền sản xuất của họ th&agrave;nh nh&agrave; m&aacute;y số. Gần đ&acirc;y, ch&uacute;ng t&ocirc;i vừa khai trương Trung t&acirc;m Năng lực Sản xuất Kỹ thuật số ở B&igrave;nh Dương l&agrave; nơi sẽ đ&agrave;o tạo c&aacute;c thợ mộc trong khu vực để họ c&oacute; thể sẵn s&agrave;ng cho thời đại số 4.0. Khi quy tr&igrave;nh sản xuất được số h&oacute;a ch&iacute;nh l&agrave; chất lượng được đảm bảo. Chỉ cần c&aacute;c nguy&ecirc;n liệu như gỗ v&agrave; phụ kiện như nhau th&igrave; &ldquo;hồ sơ&rdquo; sản xuất sẽ điều khiển m&aacute;y khoan ch&iacute;nh x&aacute;c theo c&ugrave;ng một khu&ocirc;n mẫu, bất kể m&aacute;y m&oacute;c ở đ&acirc;u&rdquo;.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/Y56twgBiRXMwWlia4qKCKJCQE5IU6Z10dopnQlVI.jpeg\" alt=\"\" width=\"632\" height=\"390\" /></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">&Ocirc;ng Phan Thế Hải, Gi&aacute;m đốc C&ocirc;ng ty Triệu Ph&uacute; Lộc (thị x&atilde; T&acirc;n Uy&ecirc;n, B&igrave;nh Dương), cho biết l&acirc;u nay v&agrave;i lần v&ocirc; t&igrave;nh thấy nhiều sản phẩm của m&igrave;nh quay ngược lại thị trường trong nước&nbsp; với gi&aacute; th&agrave;nh đội l&ecirc;n nhiều lần khiến &ocirc;ng Hải quyết đẩy mạnh sản xuất c&aacute;c mặt h&agrave;ng cao cấp d&agrave;nh cho thị trường nội địa. Những năm qua, c&acirc;u chuyện n&agrave;y cũng diễn ra ở nhiều doanh nghiệp kh&aacute;c.</p>\r\n<p style=\"text-align: justify;\">Tuy nhi&ecirc;n, để th&acirc;m nhập thị trường nội địa, doanh nghiệp phải lập kế hoạch kinh doanh ho&agrave;n to&agrave;n mới từ b&aacute;n h&agrave;ng, marketing, sản xuất đến t&agrave;i ch&iacute;nh, xu hướng cung &ndash; cầu v&agrave; mối tương quan với xuất khẩu&hellip; Chẳng hạn, C&ocirc;ng ty V&aacute;n s&agrave;n Sao Nam (T&acirc;n Uy&ecirc;n) quay về thị trường nội địa bằng c&aacute;ch li&ecirc;n kết với c&aacute;c đơn vị thiết kế nội thất để tiếp cận kh&aacute;ch h&agrave;ng. C&ocirc;ng ty cũng đầu tư nhiều hệ thống m&aacute;y m&oacute;c, thiết bị hiện đại nhằm đ&aacute;p ứng y&ecirc;u cầu đơn h&agrave;ng của thị trường.</p>\r\n<h2 style=\"text-align: justify;\"><strong>Nhắm tới cao cấp</strong></h2>\r\n<p style=\"text-align: justify;\">Theo đ&aacute;nh gi&aacute; của giới chuy&ecirc;n m&ocirc;n, ng&agrave;nh chế biến gỗ của Việt Nam vẫn chưa thể s&aacute;nh bằng sản phẩm của c&aacute;c nước Đức, &Yacute;, Ba Lan, v&igrave; c&aacute;c quốc gia n&agrave;y đều nhắm v&agrave;o ph&acirc;n kh&uacute;c cao cấp v&agrave; d&acirc;y chuyền sản xuất được tự động h&oacute;a gần như 100%. Song với việc nhiều doanh nghiệp đang đồng loạt nhập về m&aacute;y m&oacute;c thiết bị rất hiện đại cũng như đầu tư nhiều hơn cho quản l&yacute;, sản xuất th&igrave; tương lai kh&ocirc;ng xa, ng&agrave;nh chế biến gỗ của Việt Nam sẽ c&oacute; nhiều sản phẩm cạnh tranh ở ph&acirc;n kh&uacute;c cao cấp.</p>\r\n<p style=\"text-align: justify;\">&Ocirc;ng L&ecirc; Văn Minh, Ph&oacute; Gi&aacute;m đốc phụ tr&aacute;ch đ&agrave;o tạo của Hội Chế biến gỗ B&igrave;nh Dương (BIFA), cho rằng doanh nghiệp ng&agrave;y c&agrave;ng c&oacute; nhiều lựa chọn về sản phẩm c&ocirc;ng nghệ cho sản xuất v&agrave; điều h&agrave;nh. Chẳng hạn, thiết lập v&agrave; lập tr&igrave;nh thiết bị đ&uacute;ng c&aacute;ch sẽ gi&uacute;p tạo ra sai số nhỏ, nhờ đ&oacute; loại bỏ việc phải l&agrave;m lại sản phẩm cũng như giảm thiểu lượng phế liệu được tạo ra. Những thiết lập n&agrave;y gi&uacute;p cho c&ocirc;ng nh&acirc;n vận h&agrave;nh c&oacute; tay nghề cao r&uacute;t ngắn thời gian khi tạo ra sản phẩm. C&aacute;c m&aacute;y tự động được thiết kế để thực hiện nhiều thao t&aacute;c c&ugrave;ng một l&uacute;c, do đ&oacute; kh&ocirc;ng cần phải di chuyển vật liệu sau mỗi giai đoạn sản xuất, sản phẩm ho&agrave;n chỉnh c&oacute; thể gửi trực tiếp đến nơi lưu trữ m&agrave; kh&ocirc;ng cần sự can thiệp của con người.</p>\r\n<p style=\"text-align: justify;\">Thị trường nội thất Việt Nam đang v&agrave; sẽ thu h&uacute;t nhiều tay chơi to&agrave;n cầu. Ngo&agrave;i IKEA với kế hoạch x&acirc;y dựng trung t&acirc;m b&aacute;n lẻ trị gi&aacute; 450 triệu euro tại H&agrave; Nội, vừa qua thương hiệu Dongsuh của H&agrave;n Quốc cũng ch&iacute;nh thức tập trung v&agrave;o thị trường nội địa Việt Nam với kế hoạch mở th&ecirc;m 3 xưởng sản xuất nội thất, nhằm phục vụ xu hướng mua sắm nội thất online.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/aPuGsm3uYL5dOYRbkBnmejfQPdHXsooOF1nfEtuk.jpeg\" alt=\"\" width=\"600\" height=\"400\" /></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Hiện nay, h&atilde;ng nội thất Baya cũng đ&atilde; đầu tư lớn v&agrave;o nội dung số từ k&ecirc;nh b&aacute;n h&agrave;ng, nền tảng quản l&yacute; v&agrave; b&aacute;n h&agrave;ng, cũng như cấp tốc tối ưu nội dung tr&ecirc;n website chuẩn SEO v&agrave; chạy quảng c&aacute;o từ kh&oacute;a tới kh&aacute;ch h&agrave;ng. Gần 20 cửa h&agrave;ng tr&ecirc;n to&agrave;n quốc của Baya &ndash; vốn c&oacute; lịch sử l&agrave; thương hiệu UMA, giờ đ&acirc;y kho&aacute;c l&ecirc;n m&igrave;nh bộ c&aacute;nh mới: phục vụ nhu cầu mua b&aacute;n online. Theo nhận x&eacute;t của Tổng Gi&aacute;m đốc H&auml;fele Việt Nam, nhu cầu của người ti&ecirc;u d&ugrave;ng hiện nay kh&ocirc;ng chỉ l&agrave; sản phẩm nội thất c&ocirc;ng năng, th&ocirc;ng minh v&agrave; được l&agrave;m theo y&ecirc;u cầu c&aacute; nh&acirc;n m&agrave; c&ograve;n phải hợp l&yacute; về gi&aacute; cả v&agrave; giao h&agrave;ng nhanh ch&oacute;ng. Đ&acirc;y l&agrave; một th&aacute;ch thức đ&aacute;ng kể đối với c&aacute;c xưởng mộc v&agrave; cả những nh&agrave; sản xuất nội thất lớn.</p>\r\n<p style=\"text-align: justify;\">Khảo s&aacute;t của Bộ N&ocirc;ng nghiệp v&agrave; Ph&aacute;t triển N&ocirc;ng th&ocirc;n cho thấy thị trường nội địa chiếm khoảng 40% gi&aacute; trị đồ gỗ Việt Nam. Trong đ&oacute;, cơ cấu cho khu vực d&acirc;n cư th&agrave;nh thị chiếm 30%, khu vực n&ocirc;ng th&ocirc;n chiếm 30% v&agrave; 40% c&ograve;n lại thuộc về x&acirc;y dựng v&agrave; bất động sản.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span class=\"source-title\">Nguồn:</span></p>\r\n<div class=\"sa-source-content\">\r\n<div class=\"news-source\"><a href=\"https://nhipcaudautu.vn/kinh-doanh/ve-thi-truong-noi-dia-doanh-nghiep-go-chay-dua-cong-nghe-3339667/\" target=\"_blank\" rel=\"noopener\">Cẩm T&uacute;/Tạp ch&iacute; Nhịp cầu Đầu tư</a></div>\r\n</div>','Về thị trường nội địa, doanh nghiệp gỗ chạy đua công nghệ',NULL,'ve-thi-truong-noi-dia-doanh-nghiep-go-chay-dua-cong-nghe','Trong thị trường cạnh tranh ngày càng tăng, và yêu cầu khắt khe, công nghệ trở thành yếu tố quyết định trong cuộc đua giành thị phần tại thị trường nội thất.','công nghệ nội thất','Published',2,NULL,0,NULL,'2021-03-30 23:33:19','2021-03-30 23:33:19',NULL),(35,'Việt Nam đứng thứ hai toàn cầu về xuất khẩu nội thất','2021-04-08 14:33:00','1617867358-viet-nam-dung-thu-hai-toan-cau-ve-xuat-khau-noi-that.jpg','Việt Nam đã vượt qua Ba Lan, Đức, Ý và chỉ đứng sau Trung Quốc trong tốp các quốc gia xuất khẩu gỗ và sản phẩm gỗ trên thế giới.','<p style=\"text-align: justify;\">Mới đ&acirc;y, tại buổi giới thiệu về sự kiện &ldquo;Vietnam Furniture Matching Week - Tuần lễ giao thương quốc tế ng&agrave;nh chế biến gỗ v&agrave; thủ c&ocirc;ng mỹ nghệ&rdquo;, &ocirc;ng Nguyễn Ch&aacute;nh Phương- Ph&oacute; Chủ tịch Hội Mỹ nghệ v&agrave; Chế biến gỗ TP.HCM (HAWA) cho biết, d&ugrave; bị ảnh hưởng dịch COVID-19 nhưng ng&agrave;nh gỗ Việt Nam đ&atilde; c&oacute; nhiều chuyển biến t&iacute;ch cực.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Tổng kết năm 2020, ng&agrave;nh gỗ lại ghi nhận th&ecirc;m một năm to&agrave;n ng&agrave;nh đạt th&agrave;nh t&iacute;ch rất đ&aacute;ng kh&iacute;ch lệ, khi kim ngạch xuất khẩu l&acirc;m sản đạt 13,17 tỉ đ&ocirc; la Mỹ, tăng 16,4% so c&ugrave;ng kỳ năm 2019 v&agrave; vượt 5,4% kế hoạch năm 2020.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Đ&aacute;ng ch&uacute; &yacute;, đ&acirc;y cũng l&agrave; năm Việt Nam đ&atilde; vượt qua Ba Lan, Đức, &Yacute; v&agrave; chỉ đứng sau Trung Quốc trong tốp c&aacute;c quốc gia xuất khẩu gỗ v&agrave; sản phẩm gỗ tr&ecirc;n thế giới, theo b&aacute;o c&aacute;o của Trung t&acirc;m nghi&ecirc;n cứu c&ocirc;ng nghiệp.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Hiện t&igrave;nh h&igrave;nh đơn h&agrave;ng xuất khẩu với doanh nghiệp ng&agrave;nh n&agrave;y đang c&oacute; chiều hướng tăng l&ecirc;n, đ&aacute;ng ch&uacute; &yacute; l&agrave; thị trường Mỹ. &Ocirc;ng Phương cho biết, đến năm 2021, b&ecirc;n cạnh mục ti&ecirc;u xuất khẩu gỗ v&agrave; l&acirc;m sản đạt 14 tỷ USD, ng&agrave;nh cần ch&uacute; trọng đến c&aacute;c chỉ số quan trọng kh&aacute;c như năng suất lao động, gi&aacute; trị sản phẩm, c&aacute;c yếu tố ph&aacute;t triển bền vững về x&atilde; hội v&agrave; m&ocirc;i trường.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Tuy nhi&ecirc;n, &ocirc;ng cũng lưu &yacute; trong bối cảnh dịch bệnh vẫn ho&agrave;nh h&agrave;nh, để vượt qua th&aacute;ch thức v&agrave; ho&agrave;n th&agrave;nh mục ti&ecirc;u, doanh nghiệp trong ng&agrave;nh chế biến gỗ sẽ phải nỗ lực hơn rất nhiều. &ldquo;Tận dụng c&ocirc;ng nghệ, chuyển đổi số, chuyển đổi đa dạng h&igrave;nh thức tiếp cận kh&aacute;ch h&agrave;ng l&agrave; giải ph&aacute;p hết sức cần thiết\"- &ocirc;ng Phương chia sẻ.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">B&agrave; Dương Thị Minh Tuệ - Ủy vi&ecirc;n Ban chấp h&agrave;nh HAWA, cũng đồng quan điểm v&agrave; chỉ ra rằng, để c&oacute; thể giữ vững vị thế, việc giữ ch&acirc;n kh&aacute;ch h&agrave;ng v&agrave; t&igrave;m kiếm thị trường mới phải được triển khai xuy&ecirc;n suốt. Theo b&agrave;, th&aacute;ng 3 v&agrave; th&aacute;ng 4 được xem l&agrave; thời gian đặt h&agrave;ng lớn nhất trong năm v&agrave; đ&atilde; trở th&agrave;nh điểm hẹn thường ni&ecirc;n cho c&aacute;c nh&agrave; mua h&agrave;ng quốc tế tại nhiều hội chợ lớn ở khu vực ch&acirc;u &Aacute;.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Tuy nhi&ecirc;n, do bị ảnh hưởng từ dịch bệnh m&agrave; những sự kiện thường ni&ecirc;n n&agrave;y kh&ocirc;ng thể diễn ra. Do đ&oacute;, trong bối cảnh b&igrave;nh thường mới, doanh nghiệp thực sự cần tận dụng tối đa c&aacute;c k&ecirc;nh quảng b&aacute;, x&uacute;c tiến thương mại từ online cho đến offline để duy tr&igrave; sự hiện diện v&agrave; năng động của m&igrave;nh đối với c&aacute;c nh&agrave; mua h&agrave;ng.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">&ldquo;V&agrave;, số ho&aacute; c&ocirc;ng t&aacute;c triển l&atilde;m, giao thương ch&iacute;nh l&agrave; lựa chọn hiệu quả nhất hiện nay. Vietnam Furniture Matching Week được tổ chức v&igrave; nhu cầu n&agrave;y&rdquo; - B&agrave; Tuệ ph&aacute;t biểu.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/0HVGzZBTDRXl9B8sm7Zr0ZCyOYUEXgg5GoaiVENn.jpeg\" alt=\"\" width=\"700\" height=\"525\" /><br /><em class=\"image_caption\">B&agrave; Phạm Thị Hồng Quang cho biết doanh nghiệp nhờ ứng dụng nền tảng HOPE đ&atilde; l&agrave;m tăng doanh thu l&ecirc;n đến 40% trong năm 2020</em></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Theo đ&oacute; sự kiện sẽ diễn ra từ ng&agrave;y 12 đến 19-4. Chuỗi sự kiện n&agrave;y nhằm kết nối nh&agrave; sản xuất Việt Nam với h&agrave;ng ng&agrave;n kh&aacute;ch h&agrave;ng quốc tế c&ugrave;ng c&aacute;c văn ph&ograve;ng đại diện của họ tại Việt Nam.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Điểm nhấn trong chuỗi hoạt động của Vietnam Furniture Matching Week l&agrave; sự kiện Furniture Sourcing Day diễn ra v&agrave;o ng&agrave;y 14-4 tại TP HCM, quy tụ hơn 300 kh&aacute;ch mời l&agrave; nh&agrave; sản xuất v&agrave; đối t&aacute;c trong v&agrave; ngo&agrave;i nước, với c&aacute;c t&ecirc;n tuổi lớn trong ng&agrave;nh như Kingfisher, IKEA, Ashley, Te Rite...</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">B&ecirc;n cạnh đ&oacute;, Vietnam Furniture Matching Week sẽ tiếp cận nh&agrave; mua h&agrave;ng to&agrave;n cầu bằng c&aacute;c hoạt động online tr&ecirc;n nền tảng trực tuyến hopefairs.com. Cụ thể sự kiện triển l&atilde;m trực tuyến v&agrave; online B2B Matching tr&ecirc;n nền tảng trực tuyến sẽ giới thiệu hơn 100 nh&agrave; sản xuất Việt Nam với gần 10.000 sản phẩm.&nbsp;</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Theo đ&oacute; kh&aacute;ch h&agrave;ng trong nước v&agrave; quốc tế đều c&oacute; thể truy cập HOPE- một nền tảng triển l&atilde;m trực tuyến 3D đầu ti&ecirc;n của ng&agrave;nh c&ocirc;ng nghiệp nội thất Việt Nam để tham quan hang loạt mẫu thiết kế mới nhất của c&ocirc;ng nghiệp nội thất Việt Nam.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">&Ocirc;ng Phương nhận định: &ldquo;Với vị thế l&agrave; quốc gia đứng thứ hai trong xuất khẩu nội thất to&agrave;n cầu trong năm 2020, Việt Nam đang l&agrave; ng&ocirc;i sao s&aacute;ng, sự lựa chọn ti&ecirc;n phong của c&aacute;c nh&agrave; mua h&agrave;ng quốc tế&rdquo;.</p>','Việt Nam đứng thứ hai toàn cầu về xuất khẩu nội thất',NULL,'viet-nam-dung-thu-hai-toan-cau-ve-xuat-khau-noi-that','Việt Nam đã vượt qua Ba Lan, Đức, Ý và chỉ đứng sau Trung Quốc trong tốp các quốc gia xuất khẩu gỗ và sản phẩm gỗ trên thế giới.',NULL,'Published',2,NULL,1,11,'2021-04-08 00:35:58','2021-04-08 00:37:20',NULL),(36,'Hệ mặt dựng Unitized trong gia công cấu trúc nhôm kính','2021-04-12 10:10:00','1618198149-he-mat-dung-unitized-trong-gia-cong-cau-truc-nhom-kinh.jpg','Hệ mặt dựng Unitized là giải pháp công nghệ tiên tiến nhất trong ngành mặt dựng và sự ra đời của nó gần như đã giải quyết được tất cả các yêu cầu về kiến trúc và kết cấu của mặt dựng bao ngoài các tòa nhà. Hãy cùng Nghề nội thất tìm hiểu về hệ mặt dựng này và các giải pháp công nghệ hỗ trợ thiết kế thi công mặt dựng.','<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">Hệ mặt dựng Unitized l&agrave; &nbsp;hệ thống mặt dựng nh&ocirc;m k&iacute;nh&nbsp;được sản xuất, gia c&ocirc;ng v&agrave; ho&agrave;n thiện th&agrave;nh c&aacute;c tấm modul (hay c&ograve;n gọi l&agrave; panel) ngay từ trong nh&agrave; m&aacute;y, sau đ&oacute; được chuyển đến c&ocirc;ng tr&igrave;nh để lắp dựng v&agrave; ho&agrave;n thiện tổng thể. Hệ mặt dựng nh&ocirc;m k&iacute;nh Unitized sử dụng tốt nhất cho c&ocirc;ng tr&igrave;nh c&oacute; mặt ngo&agrave;i đồng nhất v&agrave; c&aacute;c tầng c&oacute; chiều cao như nhau.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">Hệ thống Unitized được sử dụng rất rộng r&atilde;i trong c&aacute;c c&ocirc;ng tr&igrave;nh cao ốc văn ph&ograve;ng, kh&aacute;ch sạn, c&aacute;c trung t&acirc;m thương mại hiện đại&hellip;v&agrave; đang l&agrave; xu hướng thiết kế mặt dựng phổ biến tr&ecirc;n thế giới.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<h2 style=\"text-align: justify;\"><span style=\"font-size: 12pt;\"><strong>Ưu điểm:&nbsp;</strong></span></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">&ndash; Bề mặt của mặt dựng hệ Unitized&nbsp;đồng nhất n&ecirc;n đảm bảo c&aacute;c ti&ecirc;u ch&iacute; về mặt mỹ thuật.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">&ndash; Thi c&ocirc;ng dễ d&agrave;ng, thời gian thi c&ocirc;ng nhanh đ&aacute;p ứng được y&ecirc;u cầu của c&aacute;c c&ocirc;ng tr&igrave;nh đ&ograve;i hỏi tiến độ gấp.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">&ndash; Kiểm so&aacute;t được chặt chẽ chất lượng sản phẩm ngay tại nh&agrave; m&aacute;y.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">&ndash; Hệ thống vững chắc, khả năng b&aacute;m chịu đặc biệt tốt, th&iacute;ch nghi được với những t&aacute;c động dịch chuyển của t&ograve;a nh&agrave;.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">&ndash; Kết cấu k&iacute;n kh&iacute;t, đảm bảo độ c&aacute;ch &acirc;m, c&aacute;ch nhiệt v&agrave; ch&ocirc;́ng th&acirc;́m cho c&ocirc;ng tr&igrave;nh.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">&ndash; Thi c&ocirc;ng được cả trong thời tiết kh&ocirc;ng thuận lơi.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">&ndash; An to&agrave;n lao động được đảm bảo hơn.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">&ndash; Hệ thống Unitized ngo&agrave;i khả năng khử được chuyển vị do ảnh hưởng của sự gi&atilde;n nở nhiệt, c&ograve;n c&oacute; khả năng giảm t&aacute;c động do chuyển vị của t&ograve;a nh&agrave; v&agrave; dư chấn động đất g&acirc;y ra, nhằm đảm bảo hệ thống lu&ocirc;n trong trạng th&aacute;i ổn định.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<h2 style=\"text-align: justify;\"><span style=\"font-size: 12pt;\"><strong>Cấu tạo hệ mặt dựng Unitized</strong><strong>:</strong></span></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">Cấu tạo cơ bản của hệ mặt dựng Unitized gồm: nh&ocirc;m, k&iacute;nh, hệ gioăng (hoặc keo silicone) v&agrave; bulong, ốc v&iacute;t.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><span style=\"font-size: 12pt;\"><img src=\"/storage/uploads/tinymce/4uipt3CCnEPpr87q6Zyst0d8oGOW5VXtUSW7gSOM.jpeg\" alt=\"\" width=\"370\" height=\"370\" /></span></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\"><strong>Về hệ nh&ocirc;m:</strong>&nbsp;Th&ocirc;ng thường sẽ được chỉ định rất r&otilde; r&agrave;ng trong hồ sơ thiết kế. Nh&agrave; m&aacute;y gia c&ocirc;ng&nbsp;sẽ thực hiện theo đ&uacute;ng y&ecirc;u cầu thiết kế đ&atilde; được duyệt với độ ch&iacute;nh x&aacute;c rất cao.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><span style=\"font-size: 12pt;\"><img src=\"/storage/uploads/tinymce/I53p93b97oZPlVZTz2bYFND2TBC5O7AIuhu4spWl.jpeg\" alt=\"\" width=\"370\" height=\"370\" /></span></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\"><strong>Về k&iacute;nh:</strong>&nbsp;K&iacute;nh sử dụng cho hệ mặt dựng Unitized phần lớn l&agrave; k&iacute;nh hộp&nbsp;ngo&agrave;i ra vẫn c&oacute; thể sử dụng k&iacute;nh đơn hoặc k&iacute;nh d&aacute;n an to&agrave;n. Trường hợp sử dụng k&iacute;nh hộp, th&ocirc;ng thường l&agrave; sự kết hợp của một tấm k&iacute;nh an to&agrave;n phản quang ph&iacute;a ngo&agrave;i v&agrave; một tấm k&iacute;nh trắng cường lực ph&iacute;a trong.</span></p>\r\n<p>&nbsp;</p>\r\n<h2><span style=\"font-size: 12pt;\"><strong>Ứng dụng của hệ mặt dựng Unitized</strong></span></h2>\r\n<p><span style=\"font-size: 12pt;\">&ndash; D&ugrave;ng l&agrave;m tường k&iacute;nh b&ecirc;n ngo&agrave;i c&aacute;c to&agrave; nh&agrave;, cao ốc văn ph&ograve;ng, trung t&acirc;m thương mại, kh&aacute;ch sạn,&hellip;.</span></p>\r\n<p><span style=\"font-size: 12pt;\">&ndash; Hệ mặt dựng Unitized l&agrave; sản phẩm kỹ thuật cao trong x&acirc;y dựng, c&oacute; thể d&ugrave;ng cho c&aacute;c to&agrave; nh&agrave; c&oacute; y&ecirc;u cầu đặc biệt như chống ồn, c&aacute;ch &acirc;m hay c&aacute;ch nhiệt tuyệt đối.</span></p>\r\n<p>&nbsp;</p>\r\n<h2><span style=\"font-size: 12pt;\"><strong>Một số c&ocirc;ng tr&igrave;nh m&agrave; CAG thi c&ocirc;ng sử dụng&nbsp;hệ&nbsp;mặt dựng Unitized:</strong></span></h2>\r\n<p style=\"text-align: center;\"><span style=\"font-size: 12pt;\"><strong><img src=\"/storage/uploads/tinymce/rmKzM3OuRWT9JptpZzVdmuCX06R7OPzj87qc7gCU.jpeg\" alt=\"\" width=\"700\" height=\"393\" /><br /></strong><em>Diamond Flower Tower</em></span></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><span style=\"font-size: 12pt;\"><em><img src=\"/storage/uploads/tinymce/pcWIJsvquMfz89JXzGBbXKycA4m9vUl3abHp5WIq.jpeg\" alt=\"\" width=\"700\" height=\"525\" /><br />T&ograve;a nh&agrave; VTC</em></span></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">Hiện tại, nghenoithat.vn đang cung cấp c&aacute;c phần mềm hỗ trợ việc thiết kế, t&iacute;nh to&aacute;n b&oacute;c t&aacute;ch, xuất code CNC, ... phục vụ việc sản xuất, thi c&ocirc;ng nh&ocirc;m k&iacute;nh n&oacute;i chung v&agrave; li&ecirc;n kết Unitized n&oacute;i ri&ecirc;ng. C&aacute;c c&ocirc;ng ty sản xuất, thi c&ocirc;ng thuộc lĩnh vực nh&ocirc;m k&iacute;nh c&oacute; thể tham khảo c&aacute;c phần mềm: <a href=\"/san-pham/logikal-phan-mem-gia-cong-he-cua-he-vach-dung\">Logikal</a>, <a href=\"/san-pham/phan-mem-thiet-ke-gia-cong-nhom-kinh-opera\">OPERA</a>, <a href=\"/san-pham/phan-mem-gia-cong-kinh-aw\">A+W</a>, ...</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">Qu&yacute; kh&aacute;ch, Qu&yacute; độc giả c&oacute; nhu cầu trang bị c&aacute;c phần mềm tr&ecirc;n c&oacute; thể li&ecirc;n hệ ch&uacute;ng t&ocirc;i:</span></p>\r\n<p style=\"text-align: justify;\"><em><strong><span style=\"font-size: 12pt;\">Trang tin tức Nghề nội thất<br /></span></strong></em><span style=\"font-size: 12pt;\">Trung t&acirc;m thương mại Golden Land, 275 Nguyễn Tr&atilde;i, Thanh Xu&acirc;n, H&agrave; Nội<br />Email: info@nghenoithat.vn<br />Hotline: 0868934576 - 0389893187</span></p>','Hệ mặt dựng Unitized trong gia công cấu trúc nhôm kính',NULL,'he-mat-dung-unitized-trong-gia-cong-cau-truc-nhom-kinh','Hệ mặt dựng Unitized là giải pháp công nghệ tiên tiến nhất trong ngành mặt dựng và sự ra đời của nó gần như đã giải quyết được tất cả các yêu cầu về kiến trúc và kết cấu của mặt dựng bao ngoài các tòa nhà. Hãy cùng Nghề nội thất tìm hiểu về hệ mặt dựng này và các giải pháp công nghệ hỗ trợ thiết kế thi công mặt dựng.','Hệ mặt dựng Unitized trong gia công cấu trúc nhôm kính','Published',2,NULL,1,11,'2021-04-11 20:29:09','2021-04-11 20:31:36',NULL),(37,'Các máy móc và phần mềm cần có cho xưởng gỗ công nghiệp','2021-04-08 11:24:00','1618202112-cac-loai-may-cho-xuong-go-cong-nghiep.jpg','Để có thể sản xuất được những sản phẩm nội thất gỗ chất lượng, một xưởng nội thất gỗ công nghiệp cần có các thiết bị máy móc như: máy cắt gỗ, máy cưa, máy chà nhám, máy khoan, máy dán cạnh… Song song với đó là các phần mềm điều khiển, hỗ trợ nâng cao hiệu suất. Hãy cùng Nghề nội thất tìm hiểu qua các loại máy và phần mềm sau đây.','<h2 style=\"text-align: justify;\"><span id=\"May_cat_go_cong_nghiep\"><strong>M&aacute;y cắt gỗ c&ocirc;ng nghiệp</strong></span></h2>\r\n<p style=\"text-align: justify;\">Tất cả c&aacute;c xưởng sản xuất gỗ c&ocirc;ng nghiệp hiện đại đều phải c&oacute; m&aacute;y cắt gỗ c&ocirc;ng nghiệp. Thiết bị l&agrave; giải ph&aacute;p l&yacute; tưởng để giảm chi ph&iacute; nh&acirc;n c&ocirc;ng, gi&uacute;p căn chỉnh v&agrave; cắt thanh gỗ đạt độ ch&iacute;nh x&aacute;c cao nhất.&nbsp; Nhưng t&ugrave;y v&agrave;o quy m&ocirc; sản xuất, điều kiện t&agrave;i ch&iacute;nh m&agrave; mua chiếc m&aacute;y ph&ugrave; hợp.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/sS62t8iDTW62wQAGtDympV9WVAAbnMu4c6dIq6K6.jpeg\" alt=\"may-cat-go-cong-nghiep\" width=\"700\" height=\"380\" /></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Một số d&ograve;ng m&aacute;y cắt phổ biến như:</p>\r\n<ul>\r\n<li style=\"text-align: justify;\">M&aacute;y cắt gỗ CNC vi t&iacute;nh 12 dao c&oacute; b&agrave;n cấp ph&ocirc;i hoặc kh&ocirc;ng cấp ph&ocirc;i</li>\r\n<li style=\"text-align: justify;\">M&aacute;y CNC 12 dao c&oacute; cụm đầu khoan 9 mũi kh&ocirc;ng c&oacute; b&agrave;n cấp nhả ph&ocirc;i hoặc c&oacute; b&agrave;n cấp nhả ph&ocirc;i tự động</li>\r\n<li style=\"text-align: justify;\">M&aacute;y CNC 12 dao hai b&agrave;n cắt</li>\r\n<li style=\"text-align: justify;\">M&aacute;y cắt gỗ c&ocirc;ng nghiệp CNC 02, 03, 04 Spindle độc lập kh&ocirc;ng c&oacute; bộ nhả ph&ocirc;i/ c&oacute; b&agrave;n cấp nhả ph&ocirc;i&hellip;</li>\r\n<li style=\"text-align: justify;\">M&aacute;y cưa b&agrave;n trượt c&oacute; thể cắt nhỏ lẻ, cắt theo nhiều h&igrave;nh dạng kh&aacute;c nhau, cắt nghi&ecirc;ng, cắt dọc, cắt r&atilde;nh&hellip; độ ch&iacute;nh x&aacute;c cao</li>\r\n<li style=\"text-align: justify;\">M&aacute;y cưa Panel l&agrave; loại m&aacute;y cưa gỗ khổ lớn, được d&ugrave;ng rất nhiều trong cắt v&aacute;n MDF, gỗ &eacute;p, gỗ d&aacute;n, c&oacute; loại m&aacute;y 1 lưỡi cưa hoặc 2 lưỡi cưa</li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<h2><span id=\"May_nen_khi\"><strong>M&aacute;y n&eacute;n kh&iacute;</strong></span></h2>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/vFru9BtMzv9kuhbUNYhTwkTeRLmBWIUZEUOhZjvv.jpeg\" alt=\"may-nen-khi\" width=\"550\" height=\"364\" /></p>\r\n<p style=\"text-align: justify;\">Trong xưởng sản xuất gỗ c&ocirc;ng nghiệp, m&aacute;y n&eacute;n kh&iacute; c&oacute; t&aacute;c dụng vận chuyển mạt cưa v&agrave; vỏ b&agrave;o hoặc tẩm thấm gỗ, d&ugrave;ng để thao t&aacute;c dụng cụ kh&iacute; ( dụng cụ khắc gỗ, khoan, đ&oacute;ng đinh, đ&aacute;nh b&oacute;ng, b&agrave;o soi, m&agrave;i b&oacute;ng, xiết đinh v&iacute;t&hellip;)</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<h2><span id=\"May_khoan_lo\"><strong>M&aacute;y khoan lỗ</strong></span></h2>\r\n<p style=\"text-align: center;\"><strong><img src=\"/storage/uploads/tinymce/YV2EtFkyhElJRnQaLTn0SZmQeOgnRChSyKGrA358.jpeg\" alt=\"may-khoan\" width=\"700\" height=\"500\" /></strong></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">M&aacute;y khoan lỗ c&oacute; t&aacute;c dụng tạo lỗ khoan cực kỳ nhanh ch&oacute;ng, độ ch&iacute;nh x&aacute;c cao, chuẩn kỹ thuật thiết kế. Từ đ&oacute; giảm thiểu chi ph&iacute; nh&acirc;n c&ocirc;ng v&agrave; thời gian ho&agrave;n thiện cho xưởng sản xuất. C&aacute;c loại m&aacute;y như:</p>\r\n<ul>\r\n<li style=\"text-align: justify;\">M&aacute;y khoan ngang 6 mũi</li>\r\n<li style=\"text-align: justify;\">M&aacute;y khoan ngang 10 mũi</li>\r\n<li style=\"text-align: justify;\">M&aacute;y khoan đứng v&agrave; ngang 24 mũi</li>\r\n<li style=\"text-align: justify;\">m&aacute;y khoan ngang v&agrave; nghi&ecirc;ng</li>\r\n<li style=\"text-align: justify;\">M&aacute;y khoan 2 đầu</li>\r\n<li style=\"text-align: justify;\">M&aacute;y khoan tự động 3 chiều</li>\r\n<li style=\"text-align: justify;\">M&aacute;y khoan 6 trục</li>\r\n<li style=\"text-align: justify;\">M&aacute;y khoan CNC khoan lỗ cam cạnh ngang sử dụng tia hồng ngoại x&aacute;c định t&acirc;m lỗ khoan</li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<h2><span id=\"May_ep_go\"><strong>M&aacute;y &eacute;p gỗ</strong></span></h2>\r\n<p style=\"text-align: justify;\">M&aacute;y &eacute;p gỗ l&agrave; thiết bị kh&ocirc;ng thể thiếu trong một xưởng nội thất gỗ c&ocirc;ng nghiệp. M&aacute;y &eacute;p gỗ được d&ugrave;ng để &eacute;p c&aacute;c tấm v&aacute;n gỗ, gỗ vi&ecirc;n, gỗ vụn&hellip; th&agrave;nh tấm v&aacute;n gỗ c&ocirc;ng nghiệp mới với k&iacute;ch thước, độ d&agrave;y như mong muốn. Ngo&agrave;i ra, thiết bị n&agrave;y cũng c&oacute; thể d&ugrave;ng để &eacute;p laminate, &eacute;p veneer l&ecirc;n bề mặt của tấm v&aacute;n gỗ.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/z405FsMFbOPwIUFptd48Y1nh1t4NeGmDI3O12rQJ.jpeg\" alt=\"\" width=\"700\" height=\"582\" /></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">C&oacute; 2 loại m&aacute;y &eacute;p gỗ c&oacute; 2 loại: m&aacute;y &eacute;p nguội v&agrave; m&aacute;y &eacute;p n&oacute;ng.</p>\r\n<ul style=\"text-align: justify;\">\r\n<li>M&aacute;y &eacute;p nguội c&oacute; b&agrave;n &eacute;p nguội, thực hiện loại &eacute;p từ tr&ecirc;n xuống v&agrave; từ dưới l&ecirc;n, dễ d&agrave;ng &eacute;p được cả những v&aacute;n gỗ c&oacute; độ d&agrave;y lớn. C&aacute;c loại như: m&aacute;y &eacute;p nguội 50 tấn, 60 tấn. Thiết bị ph&ugrave; hợp với nh&agrave; xưởng sản xuất gỗ c&ocirc;ng nghiệp nhỏ lẻ.</li>\r\n<li>M&aacute;y &eacute;p n&oacute;ng c&oacute; b&agrave;n &eacute;p n&oacute;ng, tấm gỗ được &eacute;p với nhau ở nhiệt độ cao. Người vận h&agrave;nh c&oacute; thể chủ động điều chỉnh nhiệt độ th&iacute;ch hợp. Tuy nhi&ecirc;n quy tr&igrave;nh &eacute;p sẽ tốn nhiều thời gian hơn do phải chờ đợi m&aacute;y đạt nhiệt độ cần thiết. C&aacute;c sản phẩm như: m&aacute;y &eacute;p nguội thủy lực 1 lớp 100/120/160 tấn, m&aacute;y &eacute;p nguội thủy lực 3 lớp 100/120/160 tấn. D&ograve;ng sản phẩm m&agrave;y sẽ hợp với xưởng sản xuất đồ nội thất c&ocirc;ng nghiệp quy m&ocirc; rộng lớn.</li>\r\n</ul>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<h2 style=\"text-align: justify;\"><span id=\"May_cha_nham\"><strong>M&aacute;y ch&agrave; nh&aacute;m</strong></span></h2>\r\n<p style=\"text-align: justify;\">M&aacute;y ch&agrave; nh&aacute;m được d&ugrave;ng để ch&agrave; mịn, đ&aacute;nh b&oacute;ng mặt phẳng của sản phẩm trước khi phun sơn, d&aacute;n gỗ, tấm nhựa hoặc d&aacute;n keo&hellip; Khi bề mặt sản phẩm được ch&agrave; mịn, lớp sơn sẽ l&igrave; v&agrave; b&aacute;m chắc, mịn m&agrave;ng gi&uacute;p t&iacute;nh thẩm mỹ v&agrave; độ bền của c&aacute;c đồ d&ugrave;ng nội thất gỗ c&ocirc;ng nghiệp.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/oy1bsUQm0KvHhEJW6Wujna9liA77aY660gunTY0f.jpeg\" alt=\"\" width=\"680\" height=\"555\" /></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Hiện nay, m&aacute;y ch&agrave; nh&aacute;m tr&ecirc;n thị trường rất đa dạng. C&oacute; loại cầm tay hoặc cố định, loại d&ugrave;ng điện hoặc d&ugrave;ng kh&iacute;. Tuy nhi&ecirc;n với c&aacute;c xưởng gỗ c&ocirc;ng nghiệp quy m&ocirc; lớn, thường sử dụng c&aacute;c loại m&aacute;y ch&agrave; nh&aacute;m cố định, chạy bằng điện. Phổ biến hiện nay l&agrave;:</p>\r\n<ul>\r\n<li style=\"text-align: justify;\">M&aacute;y ch&agrave; nh&aacute;m th&ugrave;ng</li>\r\n<li style=\"text-align: justify;\">M&aacute;y ch&agrave; nh&aacute;m cạnh bo tr&ograve;n</li>\r\n<li style=\"text-align: justify;\">M&aacute;y ch&agrave; nh&aacute;m cong</li>\r\n<li style=\"text-align: justify;\">M&aacute;y ch&agrave; nh&aacute;m băng</li>\r\n<li style=\"text-align: justify;\">M&aacute;y ch&agrave; nh&aacute;m bo</li>\r\n<li style=\"text-align: justify;\">M&aacute;y ch&agrave; nh&aacute;m trục m&uacute;t</li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<h2 style=\"text-align: justify;\"><span id=\"May_dan_canh\"><strong>M&aacute;y d&aacute;n cạnh</strong></span></h2>\r\n<p style=\"text-align: justify;\">M&aacute;y d&aacute;n cạnh hay c&ograve;n gọi l&agrave; m&aacute;y d&aacute;n chỉ được sử dụng trong xưởng gỗ nhằm mục đ&iacute;ch d&aacute;n cạnh gỗ, v&aacute;n &eacute;p, cạnh của c&aacute;c đồ d&ugrave;ng nội thất gỗ c&ocirc;ng nghiệp như giường, tủ, b&agrave;n, ghế&hellip; gi&uacute;p cho bề mặt sản phẩm b&oacute;ng mượt, đảm bảo đ&uacute;ng kỹ thuật v&agrave; t&iacute;nh thẩm mỹ của sản phẩm khi đến tay kh&aacute;ch h&agrave;ng.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/zD7cR9TNWrl24fSmWcdiQ7AeqwWuEJF588r8PAvL.jpeg\" alt=\"\" width=\"700\" height=\"472\" /></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Hiện nay tr&ecirc;n thị trường c&oacute; c&aacute;c loại m&aacute;y d&aacute;n cạnh từ 4 chức năng đến 13 chức năng. T&ugrave;y thuộc v&agrave;o nhu cầu sản xuất của mỗi xưởng c&oacute; thể lựa chọn d&ograve;ng m&aacute;y ph&ugrave; hợp như:</p>\r\n<ul style=\"text-align: justify;\">\r\n<li>M&aacute;y d&aacute;n cạnh 4 chức năng bao gồm: sấy ph&ocirc;i, phết keo d&aacute;n cạnh, sửa tinh, đ&aacute;nh b&oacute;ng</li>\r\n<li>M&aacute;y d&aacute;n cạnh 5 chức năng bao gồm: d&aacute;n cạnh, cắt đầu đu&ocirc;i thừa, sửa tinh, cạo cạnh, đ&aacute;nh b&oacute;ng bề mặt</li>\r\n<li>M&aacute;y d&aacute;n cạnh 6 chức năng bao gồm: d&aacute;n cạnh, cắt đầu đu&ocirc;i, sửa th&ocirc; v&agrave; tinh, cạo cạnh, đ&aacute;nh b&oacute;ng, bo g&oacute;c</li>\r\n<li>M&aacute;y d&aacute;n cạnh 8 chức năng bao gồm: d&aacute;n cạnh, cắt đầu đu&ocirc;i, sửa th&ocirc; v&agrave; sửa tinh, cạo cạnh, đ&aacute;nh b&oacute;ng, bo g&oacute;c, soi r&atilde;nh, phay cạnh tốc độ cao.</li>\r\n</ul>\r\n<p style=\"text-align: justify;\">Một số xưởng sản xuất gỗ c&ocirc;ng nghiệp nhỏ lẻ c&oacute; thể tham khảo những mẫu m&aacute;y d&aacute;n cạnh cầm tay để tiết kiệm chi ph&iacute;.</p>\r\n<p style=\"text-align: justify;\">Ngo&agrave;i ra, trong xưởng sản xuất cũng c&oacute; một số m&aacute;y m&oacute;c cần thiết kh&aacute;c như: hệ thống m&aacute;y b&agrave;o, m&aacute;y cắt phay, m&aacute;y cắt mộng, m&aacute;y gh&eacute;p &ndash; ch&eacute;p h&igrave;nh, m&aacute;y l&agrave;m gỗ gh&eacute;p, m&aacute;y lăn keo, hệ thống m&aacute;y h&uacute;t bụi cho xưởng sản xuất&hellip;</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<h2 style=\"text-align: justify;\"><span id=\"May_dan_canh\"><strong>Phần mềm phụ trợ</strong></span></h2>\r\n<p style=\"text-align: justify;\">Ngo&agrave;i c&aacute;c trang bị phần cứng, m&aacute;y m&oacute;c th&igrave; c&aacute;c xưởng gỗ c&ocirc;ng nghiệp cũng cần trang bị c&aacute;c hệ thống phần mềm thiết kế, ph&acirc;n t&iacute;ch b&oacute;c t&aacute;ch, chạy code CNC,... C&aacute;c phần mềm thiết kế nội thất v&agrave; sản xuất nội thất sẽ gi&uacute;p c&aacute;c xưởng gỗ tối ưu được nguy&ecirc;n liệu, thời gian sản xuất, cắt giảm chi ph&iacute; nh&acirc;n lực, hơn nữa, một số phần mềm c&ograve;n c&oacute; c&aacute;c t&iacute;nh năng hỗ trợ m&ocirc; phỏng 3D trong thời gian ngắn gi&uacute;p việc tư vấn kh&aacute;ch h&agrave;ng hiệu quả v&agrave; nhanh ch&oacute;ng.&nbsp;</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/hxdHQnJhZl9AIzqWWp9nNGZchL6tQyqHMJP8QzSe.jpeg\" alt=\"giao-dien-haixun\" width=\"700\" height=\"393\" /><br /><em>Giao diện phần mềm Haixun</em></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Một số phần mềm ti&ecirc;u biểu c&oacute; thể n&oacute;i tới như phầm mềm <a href=\"/san-pham/cabinet-vision\" target=\"_blank\" rel=\"noopener\">Cabinet Vision</a>, <a href=\"/san-pham/phan-mem-noi-that-go-haixun\">Haixun</a>, <a href=\"/san-pham/phan-mem-noi-that-go-pytha\">Pytha</a>, ... Đ&acirc;y đều l&agrave; c&aacute;c phần mềm đ&atilde; v&agrave; đang được sử dụng phổ biến tại nhiều xưởng, doang nghiệp nội thất tại Việt Nam v&agrave; tr&ecirc;n to&agrave;n cầu v&agrave; mang lại hiệu quả cao.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Tr&ecirc;n đ&acirc;y l&agrave; c&aacute;c trang bị m&aacute;y m&oacute;c, phần mềm m&agrave; Nghề nội thất cho rằng mọi xưởng sản xuất nội thất gỗ c&ocirc;ng nghiệp cần c&oacute; để đảm bảo hiệu suất v&agrave; t&iacute;nh cạnh tranh. Qu&yacute; kh&aacute;ch c&oacute; nhu cầu về phần mềm v&agrave; thiết bị ng&agrave;nh gỗ c&oacute; thể li&ecirc;n hệ ch&uacute;ng t&ocirc;i để được tư vấn chi tiết nhất:</p>\r\n<p style=\"text-align: justify;\"><em><strong>Trang tin tức Nghề nội thất<br /></strong></em>Trung t&acirc;m thương mại Golden Land, 275 Nguyễn Tr&atilde;i, Thanh Xu&acirc;n, H&agrave; Nội<br />Email: info@nghenoithat.vn<br />Hotline: 0868934576 - 0389893187</p>',NULL,NULL,'cac-may-moc-va-phan-mem-can-co-cho-xuong-go-cong-nghiep','Để có thể sản xuất được những sản phẩm nội thất gỗ chất lượng, một xưởng nội thất gỗ công nghiệp cần có các thiết bị máy móc như: máy cắt gỗ, máy cưa, máy chà nhám, máy khoan, máy dán cạnh… Song song với đó là các phần mềm điều khiển, hỗ trợ nâng cao hiệu suất. Hãy cùng Nghề nội thất tìm hiểu qua các loại máy và phần mềm sau đây.','Các máy móc và phần mềm cần có cho xưởng gỗ công nghiệp','Published',2,NULL,1,11,'2021-04-11 21:35:12','2021-04-12 01:09:33',NULL),(38,'Lãi thật từ showroom ảo','2021-04-19 16:05:00','1618823326-lai-that-tu-showroom-ao.jpg','Đưa sản phẩm lên showroom ảo, doanh nghiệp gỗ, nội thất Việt Nam không chỉ tăng kết nối, thu hẹp khoảng cách với khách hàng, mà qua đó còn chốt được những đơn hàng xuất khẩu ngoài kỳ vọng.','<h2 style=\"text-align: justify;\"><strong>Hiệu quả từ k&ecirc;nh tiếp thị trực tuyến</strong></h2>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: justify;\">Th&aacute;ng 2 v&agrave; th&aacute;ng 3 h&agrave;ng năm l&agrave; thời điểm rất quan trọng với c&aacute;c nh&agrave; sản xuất trong lĩnh vực đồ gỗ, nội thất xuất khẩu khi phải dồn nguồn lực cho kh&acirc;u tiếp thị. Th&ocirc;ng thường, nh&agrave; mua h&agrave;ng sẽ t&igrave;m kiếm nh&agrave; cung ứng trong giai đoạn n&agrave;y rồi đặt đơn theo xu hướng từng m&ugrave;a.&nbsp;</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Tuy nhi&ecirc;n, giao thương trực tiếp bắt đầu trắc trở khi đại dịch Covid-19 xuất hiện.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Đến giờ n&agrave;y, b&agrave; Phạm Thị Hồng Quang, Gi&aacute;m đốc C&ocirc;ng ty Thủ c&ocirc;ng mỹ nghệ Nguồn Việt (VietS, tại TP.HCM) vẫn chưa qu&ecirc;n cảm gi&aacute;c hụt hẫng khi nhận được th&ocirc;ng b&aacute;o tạm ho&atilde;n từ Ban Tổ chức Hội chợ quốc tế đồ gỗ v&agrave; mỹ nghệ xuất khẩu Việt Nam (VIFA Expo) sau khi vừa kịp trở về nước từ một hội chợ quốc tế tại Đức v&agrave;o th&aacute;ng 2/2020, trước khi lệnh đ&oacute;ng bi&ecirc;n được &aacute;p dụng.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">VIFA Expo l&agrave; hội chợ x&uacute;c tiến thương mại thường ni&ecirc;n lớn nhất của ng&agrave;nh nội thất Việt Nam v&agrave; cũng l&agrave; nơi gi&uacute;p VietS đ&oacute;n kh&aacute;ch h&agrave;ng quen, kết nối th&ecirc;m nh&agrave; mua h&agrave;ng mới.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Theo b&agrave; Hồng Quang, thủ c&ocirc;ng mỹ nghệ l&agrave; mặt h&agrave;ng c&oacute; t&iacute;nh thời trang, n&ecirc;n thị hiếu đối với những sản phẩm n&agrave;y kh&ocirc;ng ngừng thay đổi. V&igrave; thế, mỗi năm, c&aacute;c nh&agrave; nhập khẩu thường sang Việt Nam để tham quan nh&agrave; xưởng, thảo luận về mẫu m&atilde;&hellip; Nếu kh&ocirc;ng duy tr&igrave; được kết nối n&agrave;y, doanh nghiệp rất kh&oacute; để c&oacute; được đơn h&agrave;ng.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Trước t&igrave;nh thế kh&oacute; khăn, ban l&atilde;nh đạo VietS kh&ocirc;ng chọn dừng hoạt động, m&agrave; nỗ lực t&igrave;m kiếm giải ph&aacute;p. Kết quả, cuối năm 2020, VietS ghi nhận tăng trưởng doanh số khoảng 40% so với năm trước.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">&ldquo;Trải qua năm 2020, t&ocirc;i r&uacute;t ra b&agrave;i học lớn, đ&oacute; l&agrave;&nbsp;<a href=\"https://baodautu.vn/\">đầu tư</a>&nbsp;cho tiếp thị trực tuyến rất quan trọng. H&agrave;ng năm, ch&uacute;ng t&ocirc;i chi ra v&agrave;i trăm ng&agrave;n USD để tham gia hội chợ ở c&aacute;c quốc gia, nhưng đầu tư cho k&ecirc;nh trực tuyến cũng sẽ mang lại hiệu quả kh&ocirc;ng nhỏ&rdquo;, b&agrave; Hồng Quang chia sẻ.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Một trong những k&ecirc;nh đầu tư tiếp thị trực tuyến quan trọng m&agrave; Gi&aacute;m đốc VietS nhắc đến ch&iacute;nh l&agrave; Hope - nền tảng triển l&atilde;m trực tuyến đầu ti&ecirc;n của ng&agrave;nh c&ocirc;ng nghiệp nội thất Việt Nam, do Hội Mỹ nghệ v&agrave; Chế biến gỗ TP.HCM (Hawa) phối hợp với một số đơn vị thực hiện từ một năm trước, nhằm &ldquo;gỡ rối&rdquo; cho c&aacute;c hội vi&ecirc;n trước nỗi lo về đại dịch Covid-19.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">VietS l&agrave; một trong những doanh nghiệp đầu ti&ecirc;n tham gia Hope. L&atilde;nh đạo C&ocirc;ng ty thừa nhận, giai đoạn đầu, họ &ldquo;kh&ocirc;ng tin tưởng lắm&rdquo; về t&iacute;nh hiệu quả của c&ocirc;ng cụ tiếp thị trực tuyến n&agrave;y. Nhưng thực tế đ&atilde; cho thấy, kh&ocirc;ng chỉ VietS, m&agrave; h&agrave;ng loạt doanh nghiệp như C&ocirc;ng ty cổ phần Cổ kim mỹ nghệ, C&ocirc;ng ty Gỗ Minh Dương, SF Home&hellip; đ&atilde; k&yacute; kết được nhiều đơn h&agrave;ng xuất khẩu, c&oacute; th&ecirc;m nhiều đối t&aacute;c th&ocirc;ng qua &ldquo;nền tảng hy vọng&rdquo; Hope.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<h2 style=\"text-align: justify;\"><strong>Tạo trải nghiệm tốt cho kh&aacute;ch h&agrave;ng</strong></h2>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">C&acirc;u chuyện tiếp thị, b&aacute;n h&agrave;ng th&ocirc;ng qua &ldquo;b&agrave; mối&rdquo; Hope của C&ocirc;ng ty cổ phần Cổ kim mỹ nghệ (B&igrave;nh Thuận) cũng th&uacute; vị kh&ocirc;ng k&eacute;m, khi mặt h&agrave;ng v&aacute;n lướt tồn kho được d&ugrave;ng để k&ecirc; sản phẩm ch&iacute;nh tr&ecirc;n showroom ảo lại lọt v&agrave;o tầm ngắm của kh&aacute;ch h&agrave;ng. Kết quả, c&ocirc;ng ty n&agrave;y chốt được đơn h&agrave;ng 2 container xuất khẩu sang Mỹ ngay trong giai đoạn tạm đ&oacute;ng cửa nh&agrave; xưởng v&igrave; Covid-19.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Thực ra, khi tham gia c&aacute;c showroom ảo như Hope, doanh nghiệp kh&ocirc;ng n&ecirc;n nh&igrave;n nhận đ&oacute; l&agrave; c&ocirc;ng cụ b&aacute;n sản phẩm, m&agrave; n&ecirc;n x&aacute;c định đ&oacute; l&agrave; &ldquo;c&acirc;y cầu&rdquo; kết nối, thu hẹp khoảng c&aacute;ch với kh&aacute;ch h&agrave;ng. Bởi, từ khi biết th&ocirc;ng tin sản phẩm đến l&uacute;c ra quyết định đặt h&agrave;ng, b&ecirc;n mua cần thời gian tương t&aacute;c với nh&agrave; cung ứng.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Với doanh nghiệp sản xuất - kinh doanh c&aacute;c sản phẩm tủ bếp, tủ lavabo, bồn tắm bằng chất liệu sợi thuỷ tinh, đ&aacute; cẩm thạch nh&acirc;n tạo từ c&ocirc;ng nghệ chuyển giao của Tập đo&agrave;n Gruber Systems (Mỹ) như SF Home, việc kh&aacute;ch h&agrave;ng t&igrave;m đến v&agrave; duy tr&igrave; thời gian ở lại tr&ecirc;n website của m&igrave;nh đ&atilde; l&agrave; th&agrave;nh quả rất quan trọng.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Hai năm trước, SF Home từng tiếp cận showroom ảo của một đơn vị cung cấp với chi ph&iacute; 50 - 100 triệu đồng, song &ocirc;ng Nguyễn Phong Ph&uacute;, nh&agrave; s&aacute;ng lập, Tổng gi&aacute;m đốc SF Home vẫn chưa h&agrave;i l&ograve;ng, v&igrave; tr&ecirc;n kh&ocirc;ng gian trực tuyến đ&oacute;, chỉ c&oacute; h&igrave;nh ảnh được trưng ra, thiếu khả năng tạo trải nghiệm thực, thiếu t&iacute;nh kết nối với c&aacute;c c&ocirc;ng cụ tiếp thị&hellip;</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">&ldquo;80% doanh số của SF Home đến từ kh&aacute;ch h&agrave;ng nước ngo&agrave;i, n&ecirc;n h&igrave;nh ảnh website kh&ocirc;ng đủ để tạo trải nghiệm tốt cho kh&aacute;ch. Với Hope, ch&uacute;ng t&ocirc;i chỉ mất chi ph&iacute; khoảng 10 triệu đồng, m&agrave; th&ocirc;ng qua đ&oacute; thu được kh&ocirc;ng &iacute;t dữ liệu về h&agrave;nh vi kh&aacute;ch h&agrave;ng, đơn cử, thời gian kh&aacute;ch h&agrave;ng ở lại website&hellip;&rdquo;, &ocirc;ng Ph&uacute; chia sẻ.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Nếu tham gia hội chợ trực tiếp, c&aacute;c doanh nghiệp chỉ c&oacute; thể trưng b&agrave;y một số sản phẩm trong h&agrave;ng trăm sản phẩm m&igrave;nh c&oacute;. Sự hạn chế n&agrave;y ảnh hưởng đến nhu cầu tiếp cận đa dạng mẫu m&atilde;, m&agrave;u sắc, khả năng phối kết hợp trực tiếp giữa c&aacute;c sản phẩm&hellip; của kh&aacute;ch h&agrave;ng.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Trong khi đ&oacute;, qua showroom ảo, kh&aacute;ch h&agrave;ng c&oacute; thể trực tiếp t&ugrave;y chỉnh kết hợp c&aacute;c sản phẩm với nhau để đ&aacute;nh gi&aacute; mức độ ph&ugrave; hợp.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">&ldquo;Trước khi v&agrave;o showroom, kh&aacute;ch chỉ c&oacute; nhu cầu mua chiếc b&agrave;n, nhưng ch&uacute;ng t&ocirc;i sắp xếp chiếc ghế cạnh b&ecirc;n ph&ugrave; hợp v&agrave; họ thấy vừa mắt, th&igrave; chắc chắn, nhu cầu mua th&ecirc;m sẽ ph&aacute;t sinh&rdquo;, b&agrave; Hồng Quang n&oacute;i.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Th&ocirc;́ng k&ecirc; của Statista Digital Market Outlook năm 2019 cho th&acirc;́y, doanh s&ocirc;́ b&aacute;n h&agrave;ng trực tuyến nh&oacute;m đồ gia dụng v&agrave; nội thất tr&ecirc;n to&agrave;n thế giới đạt khoảng 200 tỷ USD, dự b&aacute;o tăng trưởng b&igrave;nh qu&acirc;n 10%/năm trong giai đoạn 2019 - 2023. Trung Qu&ocirc;́c l&agrave; thị trường ti&ecirc;u thụ nội thất trực tuyến lớn nhất với doanh thu khoảng 80 tỷ USD; c&ograve;n doanh thu ở thị trường Mỹ l&agrave; 44,5 tỷ USD.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Những con số n&agrave;y đ&atilde; cho thấy mức độ tiềm năng của k&ecirc;nh b&aacute;n h&agrave;ng trực tuyến. C&aacute;c showroom ảo đang mang đến doanh thu thật, lợi nhuận &ldquo;khủng&rdquo; cho doanh nghiệp. Đ&ecirc;̉ gia tăng sự nhận bi&ecirc;́t v&ecirc;̀ ng&agrave;nh gỗ Việt Nam đ&ocirc;́i với nh&agrave; mua h&agrave;ng qu&ocirc;́c t&ecirc;́, theo c&aacute;c chuy&ecirc;n gia, b&ecirc;n cạnh k&ecirc;nh tiếp thị trực tuyến, doanh nghiệp cần chuẩn bị kỹ c&agrave;ng về nguồn lực, đầu tư để đ&aacute;p ứng những ti&ecirc;u ch&iacute; của ph&iacute;a mua h&agrave;ng.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Theo: https://baodautu.vn/</p>','Lãi thật từ showroom ảo',NULL,'lai-that-tu-showroom-ao','Đưa sản phẩm lên showroom ảo, doanh nghiệp gỗ, nội thất Việt Nam không chỉ tăng kết nối, thu hẹp khoảng cách với khách hàng, mà qua đó còn chốt được những đơn hàng xuất khẩu ngoài kỳ vọng.','thiết kế nội thất, nội thất, nội thất gỗ, công nghệ gỗ, phần mềm gỗ','Published',2,NULL,1,12,'2021-04-19 02:08:46','2021-04-19 02:11:46',NULL),(39,'Top 4 phần mềm chạy máy CNC và thiết kế nội thất gỗ công nghiệp tốt nhất 2021','2021-04-20 09:07:00','1618884669-top-4-phan-mem-thiet-ke-noi-that-va-chay-may-cnc-go-cong-nghiep-tot-nhat-2021.jpg','Máy CNC là tên gọi chung cho các dòng máy có sử dụng lập trình để điều khiển với sự hỗ trợ của máy tính. Khác với các máy CNC được dùng cho gia công kim loại máy CNC ngành gỗ được chế tạo với các thông số đặc biệt phục vụ mục đích gia công vật liệu gỗ. Việc sử dụng các máy CNC trong gia công đã  tăng hiệu quả công việc lên nhiều lần, tiết kiệm thời gian và công sức của con người, chưa kể đến khả năng tạo hình đồng thời các chi tiết nhỏ mà việc cắt gọt  thủ công không thể làm được.','<p style=\"text-align: center;\"><span style=\"font-size: 14pt;\"><img src=\"/storage/uploads/tinymce/znLzPqdhOZUYWzTXz4AhmVddLCYrzXuhBT48aTIy.jpeg\" alt=\"cnc-nesting-Holztek-Pro-R4F\" width=\"700\" height=\"525\" /></span><br /><span style=\"font-size: 12pt;\"><em><span style=\"font-weight: 400;\">M&aacute;y CNC Nesting 4 đầu độc lập Holztek Pro-R4F</span></em></span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-size: 12pt;\">Tuy nhi&ecirc;n, việc sử dụng c&aacute;c m&aacute;y CNC trong sản xuất sẽ kh&ocirc;ng thể đạt được hiệu quả cao nhất nếu kh&ocirc;ng c&oacute; sự trợ gi&uacute;p đắc lực từ c&aacute;c phần mềm sản xuất chuy&ecirc;n dụng. Hiện nay, tr&ecirc;n thị trường c&oacute; rất nhiều c&aacute;c phần mềm chạy m&aacute;y CNC kết hợp thiết kế nội thất được c&aacute;c doanh nghiệp sử dụng. H&ocirc;m nay, h&atilde;y c&ugrave;ng Nghề Nội Thất điểm lại một v&agrave;i phần mềm nổi bật như vậy:</span></p>\r\n<p style=\"text-align: justify;\"><br /><br /></p>\r\n<h2><span style=\"font-size: 12pt;\"><strong>1. Cabinet Vision:</strong></span></h2>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-size: 12pt;\">Cabinet Vision l&agrave; giải ph&aacute;p phần mềm ho&agrave;n thiện cho ng&agrave;nh sản xuất tủ gỗ c&ocirc;ng nghiệp. Được tin d&ugrave;ng&nbsp; hơn 35000 kỹ sư thiết kế chuy&ecirc;n v&agrave; kh&ocirc;ng chuy&ecirc;n tại hơn 52 quốc gia tr&ecirc;n to&agrave;n thế giới.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><span style=\"font-weight: 400; font-size: 12pt;\"><img src=\"/storage/uploads/tinymce/r8Ov0XOqYR2HaHx211cBNuMvfHmkjhjBBDuRbhPC.png\" alt=\"thiet-ke-noi-that-cabinetvision\" width=\"700\" height=\"525\" /><br /><em>Thiết kế với phần mềm Cabinet Vision</em></span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-size: 12pt;\">Cabinet Vision đ&atilde; x&acirc;y dựng ph&aacute;t triển c&aacute;c giải ph&aacute;p phần mềm, n&acirc;ng cao chất lượng v&agrave; t&iacute;nh ứng dụng trong ng&agrave;nh sản xuất nội thất trong hơn 30 năm. Hiện nay, phần mềm đ&atilde; c&oacute; thể sử dụng với 13 ng&ocirc;n ngữ kh&aacute;c nhau.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-size: 12pt;\">Với phi&ecirc;n bản hiện tại, Cabinet Vision 2021 c&oacute; khả năng kết nối với hầu hết c&aacute;c d&ograve;ng m&aacute;y CNC Nesting, m&aacute;y gia c&ocirc;ng trung t&acirc;m đến từ Ch&acirc;u &Acirc;u (Homag, Biesse,SCM, Anderson,...) hoặc c&aacute;c d&ograve;ng m&aacute;y CNC đến từ Trung Quốc (Excitech, Nanxing, KDT,...)</span></p>\r\n<p style=\"text-align: center;\"><span style=\"font-weight: 400; font-size: 12pt;\"><img src=\"/storage/uploads/tinymce/QSgCmmIj1ZmJTnOsMiQaytUSeah38RVXH91B0Mnf.png\" alt=\"thu-vien-cnc-cabinetvision\" width=\"700\" height=\"500\" /><br /><br /><em>Thư viện m&aacute;y CNC đa dạng của Cabinet Vision</em></span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-size: 12pt;\">Ngo&agrave;i việc điều khiển chạy m&aacute;y CNC, Cabinet Vision c&ograve;n hỗ trợ người d&ugrave;ng thiết kế, xuất b&aacute;o c&aacute;o vật tư, tem nh&atilde;n, bản vẽ kỹ thuật. Cabinet Vision hiện đang l&agrave; phần mềm chạy m&aacute;y CNC ti&ecirc;u biểu, nổi bật trong ng&agrave;nh nội thất gỗ c&ocirc;ng nghiệp.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-size: 12pt;\">T&igrave;m hiểu th&ecirc;m tại: <a href=\"/san-pham/cabinet-vision\">Phần mềm Cabinet Vision</a></span></p>\r\n<p>&nbsp;</p>\r\n<h2><span style=\"font-size: 12pt;\"><strong>2. Haixun:</strong></span></h2>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-size: 12pt;\">Haixun được ph&aacute;t triển bởi Hisoonsoft, c&ocirc;ng ty chuy&ecirc;n cung cấp c&aacute;c giải ph&aacute;p về thiết kế nội thất gỗ c&ocirc;ng nghiệp, c&oacute; trụ sở tại Thanh Đảo (Trung Quốc). Đ&acirc;y được coi l&agrave; giải ph&aacute;p thiết kế v&agrave; sản xuất to&agrave;n diện h&agrave;ng đầu tại khu vực, đối thủ nặng k&yacute; của c&aacute;c phần mềm kh&aacute;c về t&iacute;nh khả năng tạo h&igrave;nh linh hoạt c&ugrave;ng khả năng điều khiển c&aacute;c d&ograve;ng m&aacute;y CNC phổ biến.</span></p>\r\n<p style=\"text-align: center;\"><span style=\"font-weight: 400; font-size: 12pt;\"><img src=\"/storage/uploads/tinymce/0ZvDUwWk0PXwNdH8HU2gBLqBddJFHtQQpM9bxEau.png\" alt=\"thiet-ke-haixun\" width=\"700\" height=\"525\" /><br /><em>Thiết kế với phần mềm Haixun</em></span></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-size: 12pt;\">Kh&aacute;c với Cabinet Vision, Haixun tập trung v&agrave;o việc tạo quy tr&igrave;nh gia c&ocirc;ng liền mạch từ m&aacute;y CNC Nesting v&agrave; c&aacute;c m&aacute;y khoan ngang của Trung Quốc. Ri&ecirc;ng với m&aacute;y CNC, người d&ugrave;ng c&oacute; thể t&ugrave;y chọn c&aacute;c d&ograve;ng m&aacute;y như: M&aacute;y CNC 1 đầu, m&aacute;y CNC nhiều đầu, m&aacute;y CNC 1 đầu thay dao tự động hay thậm ch&iacute; l&agrave; c&aacute;c m&aacute;y c&oacute; t&iacute;ch hợp ổ khoan 9 mũi.</span></p>\r\n<p style=\"text-align: center;\"><span style=\"font-weight: 400; font-size: 12pt;\"><img src=\"/storage/uploads/tinymce/C9KCse9EGiTQeMCFS9TKDRzuZoyydX4RfS2eN4aw.png\" alt=\"lua-chon-cnc-trong-haixun\" width=\"700\" height=\"550\" /><br /><em>Lựa chọn d&ograve;ng m&aacute;y CNC ph&ugrave; hợp cho sản xuất</em></span></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">T&igrave;m hiểu th&ecirc;m tại: <a href=\"/san-pham/phan-mem-noi-that-go-haixun\">Phần mềm Haixun</a></span></p>\r\n<p>&nbsp;</p>\r\n<h2><span style=\"font-size: 12pt;\"><strong>3. Pytha:</strong></span></h2>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-size: 12pt;\">PYTHA được ph&aacute;t triển bởi PYTHA Lab (1978), c&ocirc;ng ty chuy&ecirc;n cung cấp c&aacute;c giải ph&aacute;p về thiết kế nội thất gỗ c&ocirc;ng nghiệp tại Đức. Được coi l&agrave; một trong những giải ph&aacute;p tổng thể h&agrave;ng đầu tr&ecirc;n thế giới với những t&iacute;nh năng đa dạng như: Linh hoạt trong tạo h&igrave;nh, t&iacute;nh thống nhất, hệ thống trong to&agrave;n bộ quy tr&igrave;nh từ marketing, thiết kế module nội thất cho đến việc chạy m&aacute;y CNC.</span></p>\r\n<p style=\"text-align: center;\"><span style=\"font-weight: 400; font-size: 12pt;\"><img src=\"/storage/uploads/tinymce/e7AoTlUU4NUuriGZT7lOA8J1avFsRkjPferhgxlU.jpeg\" alt=\"tao-hinh-pytha\" width=\"700\" height=\"530\" /><br /><em>Tạo h&igrave;nh c&aacute;c đối tượng 3D trong Pytha</em></span></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Về khả năng kết nối m&aacute;y CNC, Pytha sẽ tập trung v&agrave;o việc xử l&yacute; c&aacute;c định dạng file d&ugrave;ng cho c&aacute;c m&aacute;y xuất xứ từ ch&acirc;u &Acirc;u. C&aacute;c d&ograve;ng m&aacute;y xuất xứ từ Trung Quốc cũng c&oacute; thể được điều khiển dễ d&agrave;ng th&ocirc;ng qua c&aacute;c tệp tin với định dạng G Code ti&ecirc;u chuẩn&nbsp;</span></p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">T&igrave;m hiểu th&ecirc;m tại: <a href=\"/san-pham/phan-mem-noi-that-go-pytha\">Phần mềm PYTHA</a></span></p>\r\n<p>&nbsp;</p>\r\n<h2><span style=\"font-size: 12pt;\"><strong>4. ALPHACAM:</strong></span></h2>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: center;\"><span style=\"font-size: 12pt;\"><strong><img src=\"/storage/uploads/tinymce/pXxcUQdY2D2crUj8JLDbcAfhqdB3ADUj1mFNKZha.png\" alt=\"thiet-ke-pytha\" width=\"700\" height=\"550\" /><br /><em><span style=\"font-weight: 400;\">Lập tr&igrave;nh gia c&ocirc;ng mẫu m&acirc;m trần hoa l&aacute; t&acirc;y trong Alphacam</span></em></strong></span></p>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-size: 12pt;\">Kh&aacute;c với 3 phần mềm tr&ecirc;n, ngo&agrave;i việc sử dụng cho mục đ&iacute;ch tạo sơ đồ cắt tối ưu tr&ecirc;n m&aacute;y CNC Nesting, ALPHACAM tập trung tạo h&igrave;nh v&agrave; lập tr&igrave;nh gia c&ocirc;ng tr&ecirc;n c&aacute;c m&aacute;y gia c&ocirc;ng P2P (Point-to-Point) nhằm ph&aacute;t huy khả năng gia c&ocirc;ng mạnh mẽ tr&ecirc;n c&aacute;c m&aacute;y gia c&ocirc;ng 4 đến 5 trục.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-size: 12pt;\">Th&ecirc;m v&agrave;o đ&oacute;, ALPHACAM sẽ l&agrave; c&ocirc;ng cụ ph&ugrave; hợp đối với c&aacute;c chi tiết hoa l&aacute; t&acirc;y, c&aacute;c bức ph&ugrave; đi&ecirc;u hay c&aacute;c tranh lithophane được gia c&ocirc;ng tr&ecirc;n c&aacute;c m&aacute;y đục CNC (hay m&aacute;y đục vi t&iacute;nh), vốn kh&ocirc;ng phải l&agrave; thế mạnh của c&aacute;c phần mềm cho m&aacute;y CNC Nesting đơn thuần. Điều đ&oacute; l&agrave; nhờ khả năng nhập c&aacute;c định dạng như .stl, .dxf, .skp, .stp, .iges,..... Người d&ugrave;ng ho&agrave;n to&agrave;n c&oacute; thể kiểm so&aacute;t c&aacute;c th&ocirc;ng số về tốc độ cắt hay đường k&iacute;nh dao, chiều cao an to&agrave;n thậm ch&iacute; l&agrave; hiệu chỉnh tr&igrave;nh bi&ecirc;n dịch (post-processor) cho nhiều loại m&aacute;y CNC ri&ecirc;ng biệt với bộ c&ocirc;ng cụ AlphaEdit mạnh mẽ.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><span style=\"font-weight: 400; font-size: 12pt;\"><img src=\"/storage/uploads/tinymce/XWYhQuNjivreMXl3KQN8Ak6uX8zpJ1jDD035S98e.png\" alt=\"post-processor-alphacam\" width=\"700\" height=\"550\" /><br /><em>Tr&igrave;nh chỉnh sửa Post-processor AlphaEdit</em></span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">T&igrave;m hiểu th&ecirc;m tại: <a href=\"/san-pham/phan-mem-alphacam-thiet-ke-va-san-xuat-go-tu-nhien\">Phần mềm ALPHACAM</a></span></p>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\">Tr&ecirc;n đ&acirc;y l&agrave; Top phần mềm hỗ trợ thiết kế v&agrave; đồng thời xuất được G-code chạy m&aacute;y CNC gỗ c&ocirc;ng nghiệp rất hữu dụng cho c&aacute;c xưởng v&agrave; doanh nghiệp sản xuất gỗ c&ocirc;ng nghiệp. Qu&yacute; độc giả c&oacute; nhu cầu t&igrave;m hiểu chuy&ecirc;n s&acirc;u về c&aacute;c phần mềm tr&ecirc;n c&oacute; thể li&ecirc;n hệ Nghề nội thất để được tư vấn v&agrave; demo d&ugrave;ng thử miễn ph&iacute; qua số điện thoại <em><strong>086 893 4576.</strong></em></span></p>','Top 4 phần mềm thiết kế nội thất và chạy máy CNC gỗ công nghiệp tốt nhất 2021',NULL,'top-4-phan-mem-chay-may-cnc-va-thiet-ke-noi-that-go-cong-nghiep-tot-nhat-2021','Máy CNC là tên gọi chung cho các dòng máy có sử dụng lập trình để điều khiển với sự hỗ trợ của máy tính. Khác với các máy CNC được dùng cho gia công kim loại máy CNC ngành gỗ được chế tạo với các thông số đặc biệt phục vụ mục đích gia công vật liệu gỗ. Việc sử dụng các máy CNC trong gia công đã  tăng hiệu quả công việc lên nhiều lần, tiết kiệm thời gian và công sức của con người, chưa kể đến khả năng tạo hình đồng thời các chi tiết nhỏ mà việc cắt gọt  thủ công không thể làm được. Có thể nói máy CNC gỗ đã m','thiết kế nội thất, nội thất, nội thất gỗ, công nghệ gỗ, phần mềm gỗ, máy cnc','Published',2,NULL,1,12,'2021-04-19 19:11:09','2021-04-19 19:23:45',NULL),(40,'Top 4 phần mềm sản xuất cửa nhôm xingfa, kính','2021-04-22 14:37:00','1619077887-top-4-phan-mem-san-xuat-cua-nhom-xingfa-kinh.jpg','Sản xuất hệ cửa nhôm kính (hay cửa nhôm xingfa) là một trong những ngành công nghiệp luôn giữ được sức nóng của mình trên thị trường. Với đặc điểm đa dạng về chủng loại, mẫu mã từ các dòng thanh nhôm như nhôm hệ Xingfa, nhôm Việt Pháp, nhôm PMI, hoặc các hệ nhôm độc quyền như EUA, NH (Nam Hải Group)... cũng như  các mẫu mã sản phẩm đáp ứng thị hiếu của nhiều phân khúc khách hàng.','<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">Hiện nay, một số doanh nghiệp trong ng&agrave;nh đang thực hiện m&ocirc; h&igrave;nh quản l&yacute; v&agrave; lưu trữ th&ocirc;ng tin t&iacute;nh to&aacute;n với Excel. B&ecirc;n cạnh những ưu điểm dễ thấy của Excel l&agrave; đơn giản, song đơn thuần chỉ thể hiện k&iacute;ch thước cắt ph&ocirc;i nh&ocirc;m, kh&ocirc;ng thể tạo b&aacute;o c&aacute;o phối nh&ocirc;m, phụ kiện. Mọi hao ph&iacute; được t&iacute;nh to&aacute;n thủ c&ocirc;ng v&agrave; dựa nhiều tr&ecirc;n kinh nghiệm của người thợ; đ&oacute; l&agrave; chưa kể đến việc phần mềm n&agrave;y cũng kh&ocirc;ng thể xử l&yacute; c&aacute;c t&iacute;nh to&aacute;n li&ecirc;n quan đến thiết kế m&aacute;i v&ograve;m, v&aacute;ch dựng.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><span style=\"font-weight: 400;\"><img src=\"/storage/uploads/tinymce/uPaa5Ytf0mVDBN3LtrQivyX1Wuxz0p2jR4YxZaYT.jpeg\" alt=\"san-xuat-nhom-dinh-hinh\" width=\"700\" height=\"466\" /><br /><br /><em>D&acirc;y chuyền sản xuất nh&ocirc;m thanh định h&igrave;nh</em></span></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">Với những bất cập kể tr&ecirc;n, r&otilde; r&agrave;ng nhu cầu sử dụng đến một phần mềm chuy&ecirc;n ng&agrave;nh c&oacute; thể đảm nhận to&agrave;n bộ quy tr&igrave;nh thiết kế v&agrave; sản xuất , đồng thời ph&acirc;n chia được c&aacute;c c&ocirc;ng đoạn cụ thể tr&ecirc;n từng bộ phận của to&agrave;n bộ d&acirc;y chuyền. Trong b&agrave;i viết n&agrave;y, Nghề Nội Thất sẽ c&ugrave;ng bạn đọc điểm qua một số phần mềm được cho l&agrave; những giải ph&aacute;p h&agrave;ng đầu trong ng&agrave;nh c&ocirc;ng nghiệp sản xuất cửa - v&aacute;ch dựng tr&ecirc;n thế giới cũng như tại Việt Nam.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\"><em>&nbsp;</em></span></p>\r\n<h2 style=\"text-align: justify;\"><strong>1. Phần mềm LOGIKAL</strong></h2>\r\n<h3 style=\"text-align: justify;\"><strong>Tổng quan</strong></h3>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">Logikal l&agrave; phần mềm t&iacute;nh to&aacute;n thiết kế, lập tr&igrave;nh sản xuất cửa sổ, hệ cửa đi v&agrave; hệ mặt dựng ph&aacute;t triển bởi Orgadata (Đức). Đ&acirc;y l&agrave; giải ph&aacute;p mạnh mẽ, to&agrave;n diện khi từng c&ocirc;ng đoạn của quy tr&igrave;nh sản xuất đ&atilde; được ph&acirc;n định r&otilde; r&agrave;ng nhưng vẫn đảm bảo t&iacute;nh kết nối li&ecirc;n tục, hỗ trợ tối đa việc đảm bảo năng suất cũng như t&iacute;nh ho&agrave;n thiện của sản phẩm cửa.</span></p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/t4HfEZUsSnAksPtQLdc1p2ryidIPZsCx9XSQK9kE.png\" alt=\"thiet-ke-cua-trong-logikal\" width=\"700\" height=\"459\" /><br /><em><span style=\"font-weight: 400;\">Thiết kế hệ cửa đi trong Logikal</span></em></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<h3 style=\"text-align: justify;\"><strong>Chi tiết t&iacute;nh năng:&nbsp;&nbsp;</strong></h3>\r\n<p style=\"text-align: justify;\"><em><strong>Thiết kế (Input of Elements)</strong></em></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">Thiết kế theo phương thức nhập tuần tự đặc t&iacute;nh c&aacute;c th&agrave;nh phần của 1 hệ cửa hoặc hệ v&aacute;ch dựng theo k&iacute;ch thước, vị tr&iacute;, li&ecirc;n kết,&hellip; đảm bảo việc tạo h&igrave;nh đối tượng thiết kế được ho&agrave;n chỉnh, tr&aacute;nh sai s&oacute;t</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">&nbsp;</span></p>\r\n<p style=\"text-align: justify;\"><em><strong>B&aacute;o c&aacute;o (Printouts)</strong></em></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">Với LogiKal&reg;, tất cả c&aacute;c th&ocirc;ng tin sản xuất quan trọng c&oacute; thể được thể hiện tr&ecirc;n c&aacute;c b&aacute;o c&aacute;o kh&aacute;c nhau. Người d&ugrave;ng ho&agrave;n to&agrave;n c&oacute; thể chỉ định th&ocirc;ng tin n&agrave;o sẽ xuất hiện tr&ecirc;n b&aacute;o c&aacute;o. C&aacute;c đối tượng ho&agrave;n chỉnh, to&agrave;n bộ hoặc chỉ c&aacute;c mục đ&atilde; chọn sẽ được hiển thị,thậm ch&iacute; l&agrave; kết hợp c&aacute;c th&ocirc;ng tin từ c&aacute;c đối tượng kh&aacute;c nhau v&agrave; liệt k&ecirc; ch&uacute;ng trong một b&aacute;o c&aacute;o duy nhất. T&ugrave;y thuộc v&agrave;o b&aacute;o c&aacute;o, việc chỉnh sửa trong c&aacute;c tr&igrave;nh soạn thảo th&ocirc;ng dụng hoặc trực tiếp trong MSWord hoặc MSExcel cũng v&ocirc; c&ugrave;ng nhanh ch&oacute;ng, dễ d&agrave;ng</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">&nbsp;</span></p>\r\n<p style=\"text-align: justify;\"><em><strong>Tối ưu h&oacute;a (Optimisation)</strong></em></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">Tất cả c&aacute;c profile theo thứ tự được sắp xếp sao cho hao ph&iacute; nguy&ecirc;n vật liệu l&agrave; nhỏ nhất. X&acirc;y dựng h&igrave;nh ảnh hiển thị trực quan dụng cụ v&agrave; đường cắt c&ugrave;ng thứ tự c&aacute;c k&iacute;ch thước cắt đơn lẻ. C&aacute;c khoảng độ d&agrave;i kh&aacute;c nhau tr&ecirc;n thanh nh&ocirc;m cũng c&oacute; thể được sắp xếp th&agrave;nh c&aacute;c khoảng c&aacute;ch cố định, nhằm tạo nhiều k&iacute;ch thước cắt tr&ecirc;n c&ugrave;ng một profile</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">&nbsp;</span></p>\r\n<p style=\"text-align: justify;\"><em><strong>CNC</strong></em></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">Ngay từ c&ocirc;ng đoạn thiết kế, LogiKal&reg;&nbsp; tự động t&iacute;nh to&aacute;n c&aacute;c dữ liệu gia c&ocirc;ng cần thiết để chuyển sang c&ocirc;ng đoạn sản xuất. Sử dụng LogiKal&reg; CNC nhằm chuyển giao c&aacute;c nguy&ecirc;n c&ocirc;ng khoan, phay, cắt g&oacute;c từ m&ocirc;&nbsp; h&igrave;nh thiết kế tới c&aacute;c trung t&acirc;m gia c&ocirc;ng CNC 3 đến 5 trục một c&aacute;ch ch&iacute;nh x&aacute;c v&agrave; nhanh ch&oacute;ng.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">&nbsp;</span></p>\r\n<p style=\"text-align: justify;\"><em><strong>Kết nối giải ph&aacute;p ERP/PPS</strong></em></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">Dễ d&agrave;ng kết nối LogiKal&reg; tới c&aacute;c giải ph&aacute;p ERP/PPS phổ biến hiện h&agrave;nh bằng giao diện chuy&ecirc;n biệt. Dữ liệu được xuất ra c&aacute;c định dạng XML, CSV v&agrave; DSTV.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><em><strong>Hệ thống Profile (Profile Systems)</strong></em></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">LogiKal&reg; cung cấp bộ cơ sở dữ liệu từ c&aacute;c nh&agrave; cung cấp v&agrave; tạo h&igrave;nh profile h&agrave;ng đầu tr&ecirc;n thế giới.LogiKal&reg; ph&acirc;n biệt r&otilde; v&agrave; thể hiện trực quan điểm kh&aacute;c biệt trong thiết kế profile của từng nh&agrave; cung cấp, hỗ trợ người d&ugrave;ng lựa chọn một hoặc nhiều profile kh&aacute;c nhau ph&ugrave; hợp với nhu cầu sản xuất của từng doanh nghiệp.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">T&igrave;m hiểu th&ecirc;m về Logikal tại: <a href=\"/san-pham/logikal-phan-mem-gia-cong-he-cua-he-vach-dung\" target=\"_blank\" rel=\"noopener\">Phần mềm Logikal</a></span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<h2><strong>2. Phần mềm SOFTTECH V6</strong></h2>\r\n<h3 style=\"text-align: justify;\"><strong>T&iacute;nh năng cơ bản</strong></h3>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">SoftTech V6 l&agrave; phần mềm t&iacute;nh to&aacute;n thiết kế, lập tr&igrave;nh sản xuất cửa sổ, hệ cửa đi v&agrave; hệ mặt dựng, ph&aacute;t triển bởi SoftTech (Mỹ)</span></p>\r\n<p style=\"text-align: center;\"><span style=\"font-weight: 400;\"><img src=\"/storage/uploads/tinymce/ZOs3QYWItJA8ksOz3pSUnhy2to7tBsE5jxIiqKEi.png\" alt=\"thiet-ke-cua-lua-softtechv6\" width=\"700\" height=\"459\" /><br /><em>Thiết kế cửa l&ugrave;a trong SoftTech V6</em><br /></span></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p><em><strong>Thiết kế</strong></em></p>\r\n<p><span style=\"font-weight: 400;\">- Linh hoạt giữa việc thiết kế: Thiết kế mới hoặc từ bộ thư viện c&oacute; sẵn</span></p>\r\n<p><span style=\"font-weight: 400;\">- Chỉnh sửa m&ocirc; h&igrave;nh 3D trực quan, hỗ trợ x&acirc;y dựng m&ocirc; h&igrave;nh h&igrave;nh học phức tạp</span></p>\r\n<p><span style=\"font-weight: 400;\">- X&acirc;y dựng bản vẽ kỹ thuật với đầy đủ h&igrave;nh cắt v&agrave; c&aacute;c th&ocirc;ng số kỹ thuật k&egrave;m theo</span></p>\r\n<p>&nbsp;</p>\r\n<p><em><strong>B&aacute;o gi&aacute;</strong></em></p>\r\n<p><span style=\"font-weight: 400;\">- Nhập đơn h&agrave;ng đầu v&agrave;o với số lượng kh&ocirc;ng giới hạn</span></p>\r\n<p><span style=\"font-weight: 400;\">- Nhanh ch&oacute;ng cập nhật những thay đổi ph&aacute;t sinh trong đơn h&agrave;ng với t&iacute;nh năng &ldquo;what-if&rdquo;</span></p>\r\n<p><span style=\"font-weight: 400;\">- Hỗ trợ in trực tiếp b&aacute;o c&aacute;o từ đơn h&agrave;ng hiện c&oacute;</span></p>\r\n<p><span style=\"font-weight: 400;\">- Hỗ trợ chỉnh sửa b&aacute;o c&aacute;o theo y&ecirc;u cầu về định dạng của người d&ugrave;ng</span></p>\r\n<p>&nbsp;</p>\r\n<p><em><strong>Sản xuất</strong></em></p>\r\n<p><span style=\"font-weight: 400;\">- Điều khiển qu&aacute; tr&igrave;nh gia c&ocirc;ng tr&ecirc;n hệ trục tọa độ Oxyz thường</span></p>\r\n<p><span style=\"font-weight: 400;\">- Tạo file DXF. cho c&aacute;c chi tiết đ&atilde; gia c&ocirc;ng</span></p>\r\n<p><span style=\"font-weight: 400;\">- Tạo G Code gia c&ocirc;ng thanh nh&ocirc;m</span></p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-weight: 400;\">T&igrave;m hiểu th&ecirc;m về SoftTech V6 tại: <a href=\"/san-pham/softtech-v6\" target=\"_blank\" rel=\"noopener\">Phần mềm Softtech v6</a></span></p>\r\n<p>&nbsp;</p>\r\n<h2><strong>3. Phần mềm nh&ocirc;m k&iacute;nh Opera</strong></h2>\r\n<p><span style=\"font-weight: 400;\">Opera l&agrave; phần mềm sản xuất cửa - v&aacute;ch dựng với giao diện th&acirc;n thiện được ph&aacute;t triển bởi Opera Company (&Yacute;)</span></p>\r\n<p style=\"text-align: center;\"><span style=\"font-weight: 400;\"><img src=\"/storage/uploads/tinymce/VG6TVl1hQHq26ZG4MzQrpl5DcE2PUIfBCjLAFGRa.png\" alt=\"giao-dien-opera-job-management\" width=\"700\" height=\"459\" /><br /><em>Giao diện Opera Job Management</em></span></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">Để đảm bảo được ho&agrave;n thiện c&aacute;c c&ocirc;ng đoạn của d&acirc;y chuyền sản xuất trong nh&agrave; m&aacute;y, người d&ugrave;ng sẽ sử dụng module Opera Job Management. B&ecirc;n cạnh đ&oacute;, phần mềm sẽ c&oacute; c&aacute;c module kh&aacute;c với mục đ&iacute;ch kết nối nhiều loại m&aacute;y CNC hay cưa NC kh&aacute;c nhau, cũng như ph&acirc;n quyền c&ocirc;ng việc cho c&aacute;c bộ phận kh&aacute;c nhau của c&ocirc;ng ty.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">&nbsp;</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">C&aacute;c t&iacute;nh năng ch&iacute;nh của Opera Job Management (v3.8):</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">&nbsp;</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">-</span><span style=\"font-weight: 400;\"> &nbsp; &nbsp; &nbsp; &nbsp; </span><span style=\"font-weight: 400;\">Quản l&yacute; cơ sở dữ liệu về profile nh&ocirc;m v&agrave; phụ kiện;</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">-</span><span style=\"font-weight: 400;\"> &nbsp; &nbsp; &nbsp; &nbsp; </span><span style=\"font-weight: 400;\">Quản l&yacute; cơ sở dữ liệu về loại sản phẩm (Typologies);</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">-</span><span style=\"font-weight: 400;\"> &nbsp; &nbsp; &nbsp; &nbsp; </span><span style=\"font-weight: 400;\">Quản l&yacute; cơ sở dữ liệu đơn h&agrave;ng;</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">-</span><span style=\"font-weight: 400;\"> &nbsp; &nbsp; &nbsp; &nbsp; </span><span style=\"font-weight: 400;\">Tr&iacute;ch xuất b&aacute;o c&aacute;o vật tư theo dự &aacute;n, l&ocirc; sản xuất hoặc dựa tr&ecirc;n từng sản phẩm;</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">-</span><span style=\"font-weight: 400;\"> &nbsp; &nbsp; &nbsp; &nbsp; </span><span style=\"font-weight: 400;\">T&iacute;nh to&aacute;n chi ph&iacute; sản xuất vật liệu, thời gian chế tạo, thời gian lắp đặt v&agrave; chi ph&iacute; thầu phụ;</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">-</span><span style=\"font-weight: 400;\"> &nbsp; &nbsp; &nbsp; &nbsp; </span><span style=\"font-weight: 400;\">Xử l&yacute; c&aacute;c đơn đặt h&agrave;ng theo nh&agrave; cung cấp;</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">-</span><span style=\"font-weight: 400;\"> &nbsp; &nbsp; &nbsp; &nbsp; </span><span style=\"font-weight: 400;\">In b&aacute;o gi&aacute; theo bố cục c&oacute; thể t&ugrave;y chỉnh;</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">-</span><span style=\"font-weight: 400;\"> &nbsp; &nbsp; &nbsp; &nbsp; </span><span style=\"font-weight: 400;\">T&iacute;nh to&aacute;n truyền nhiệt dựa tr&ecirc;n ti&ecirc;u chuẩn ISO 10077-1: 2010;</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">-</span><span style=\"font-weight: 400;\"> &nbsp; &nbsp; &nbsp; &nbsp; </span><span style=\"font-weight: 400;\">Nhập/xuất c&aacute;c chi tiết c&ocirc;ng việc như:</span></p>\r\n<ul style=\"text-align: justify;\">\r\n<li><span style=\"font-weight: 400;\"> &nbsp; &nbsp; &nbsp; </span><span style=\"font-weight: 400;\">B&aacute;o c&aacute;o vật tư</span></li>\r\n<li><span style=\"font-weight: 400;\"> &nbsp; &nbsp; &nbsp; </span><span style=\"font-weight: 400;\">Danh s&aacute;ch pha cắt</span></li>\r\n<li><span style=\"font-weight: 400;\"> &nbsp; &nbsp; &nbsp; </span><span style=\"font-weight: 400;\">Bản vẽ</span></li>\r\n<li><span style=\"font-weight: 400;\"> &nbsp; &nbsp; &nbsp; </span><span style=\"font-weight: 400;\">Chi ph&iacute;</span></li>\r\n<li><span style=\"font-weight: 400;\"> &nbsp; &nbsp; &nbsp; </span><span style=\"font-weight: 400;\">Gi&aacute; b&aacute;n</span></li>\r\n</ul>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">C&aacute;c t&agrave;i liệu được xuất ra c&oacute; định dạng XML. Th&ocirc;ng qua t&iacute;nh năng n&agrave;y, người d&ugrave;ng c&oacute; thể x&acirc;y dựng to&agrave;n bộ dự &aacute;n dựa tr&ecirc;n file Excel c&oacute; chưa danh s&aacute;ch cửa, cửa sổ hoặc xuất b&aacute;o c&aacute;o vật tư, chi tiết danh s&aacute;ch sản phẩm của từng dự &aacute;n v&oacute;i c&aacute;c th&ocirc;ng tin chi tiết về số lượng, m&ocirc; tả chi tiết v&agrave; gi&aacute;.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">-</span><span style=\"font-weight: 400;\"> &nbsp; &nbsp; &nbsp; &nbsp; </span><span style=\"font-weight: 400;\">Tạo bảng gi&aacute; cho cửa sổ v&agrave; cửa ra v&agrave;o;</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">-</span><span style=\"font-weight: 400;\"> &nbsp; &nbsp; &nbsp; &nbsp; </span><span style=\"font-weight: 400;\">Tối ưu pha cắt nh&ocirc;m;</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">-</span><span style=\"font-weight: 400;\"> &nbsp; &nbsp; &nbsp; &nbsp; </span><span style=\"font-weight: 400;\">Tạo v&agrave; in nh&atilde;n phục vụ: cắt, k&iacute;nh, khung v&agrave; vận chuyển;</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">-</span><span style=\"font-weight: 400;\"> &nbsp; &nbsp; &nbsp; &nbsp; </span><span style=\"font-weight: 400;\">Tr&iacute;ch xuất v&agrave; tạo một số b&aacute;o c&aacute;o gia c&ocirc;ng như bản vẽ, mặt cắt, sơ đồ chi tiết với c&aacute;c bộ phận v&agrave; k&iacute;ch thước đầy đủ;</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">-</span><span style=\"font-weight: 400;\"> &nbsp; &nbsp; &nbsp; &nbsp; </span><span style=\"font-weight: 400;\">Tr&iacute;ch xuất 3D với c&aacute;c kịch bản c&oacute; thể t&ugrave;y chỉnh ở định dạng webGL, VRML v&agrave; POVray;</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">-</span><span style=\"font-weight: 400;\"> &nbsp; &nbsp; &nbsp; &nbsp; </span><span style=\"font-weight: 400;\">Xuất DXF đối với c&aacute;c bản vẽ, mặt cắt v&agrave; 3D.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">T&igrave;m hiểu th&ecirc;m về Opera tại: <a href=\"/san-pham/phan-mem-thiet-ke-gia-cong-nhom-kinh-opera\" target=\"_blank\" rel=\"noopener\">Phần mềm nh&ocirc;m k&iacute;nh Opera</a></span></p>\r\n<p>&nbsp;</p>\r\n<h2><strong>4. Window Star</strong></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">Tiếp theo sẽ l&agrave; Window Star, phần mềm thiết kế cửa nh&ocirc;m - nhựa đến từ DecaSoft ( Trung Quốc)</span></p>\r\n<p style=\"text-align: center;\"><span style=\"font-weight: 400;\"><img src=\"/storage/uploads/tinymce/gVV4xZY9L619fDZu75NHNhbDNnHaPQrAliqzyKvV.jpeg\" alt=\"giao-dien-window-star\" width=\"700\" height=\"459\" /><br /><em>Giao diện Window Star</em><br /></span></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">Hiện nay phần mềm Window Star 2006 đ&atilde; được n&acirc;ng cấp l&ecirc;n phần mềm window star 2008 với nhiều t&iacute;nh năng hữu &iacute;ch cho người d&ugrave;ng. Nhưng đều c&oacute; những điểm chung sau:</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">+ Phần mềm Window Star đ&atilde; được Việt h&oacute;a tiện cho người d&ugrave;ng.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">+ Khit sử dụng th&agrave;nh thạo phần mềm th&igrave; bạn ho&agrave;n to&agrave;n c&oacute; thể y&ecirc;n t&acirc;m trở th&agrave;nh thợ sản xuất l&yacute; thuyết chuy&ecirc;n nghiệp.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">+ Sử dụng phần mềm c&oacute; khả năng tổng hợp số thanh profile nhựa, nh&ocirc;m cần chuẩn bị khối lượng l&agrave; bao nhi&ecirc;u.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">+ T&iacute;nh được độ d&agrave;i c&aacute;c thanh cần cắt gọt của đơn h&agrave;ng cụ thể</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">+ Đồng thời nhờ phần mềm bạn c&ograve;n t&iacute;nh to&aacute;n được k&iacute;ch thước số lượng k&iacute;nh cần cắt l&agrave; bao nhi&ecirc;u.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">+ Ra được từng loại phụ kiện cho c&ocirc;ng tr&igrave;nh tổng hợp&nbsp;</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">+ Gi&uacute;p quản l&yacute; được lượng kh&aacute;ch h&agrave;ng lớn</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">+ C&ograve;n c&oacute; thể tổng hợp quản l&yacute; kho (Ở mức cơ bản)</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">Tuy nhi&ecirc;n, do t&iacute;nh tối giản của phần mềm, Window Star sẽ kh&ocirc;ng thực sự ph&aacute;t huy được hiệu quả c&ocirc;ng việc khi quy m&ocirc; sản xuất được tăng l&ecirc;n.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">Tr&ecirc;n đ&acirc;y l&agrave; Top 4 c&aacute;c phần mềm sản xuất, t&iacute;nh to&aacute;n, vẽ cửa nh&ocirc;m k&iacute;nh rất cần thiết cho c&aacute;c doanh nghiệp, nh&agrave; m&aacute;y kinh doanh trong lĩnh vực n&agrave;y. Qu&yacute; độc giả c&oacute; nhu cầu t&igrave;m hiểu chuy&ecirc;n s&acirc;u về c&aacute;c phần mềm tr&ecirc;n c&oacute; thể li&ecirc;n hệ Nghề nội thất để được tư vấn v&agrave; demo d&ugrave;ng thử miễn ph&iacute; qua số điện thoại <em><strong>0866 059 659.</strong></em></span></p>','Top 4 phần mềm sản xuất cửa nhôm xingfa, kính',NULL,'top-4-phan-mem-san-xuat-cua-nhom-xingfa-kinh','Sản xuất hệ cửa nhôm kính (hay cửa nhôm xingfa) là một trong những ngành công nghiệp luôn giữ được sức nóng của mình trên thị trường. Với đặc điểm đa dạng về chủng loại, mẫu mã từ các dòng thanh nhôm như nhôm hệ Xingfa, nhôm Việt Pháp, nhôm PMI, hoặc các hệ nhôm độc quyền như EUA, NH (Nam Hải Group)... cũng như  các mẫu mã sản phẩm đáp ứng thị hiếu của nhiều phân khúc khách hàng.','nhôm kính, phần mềm nhôm kính, phần mềm cửa nhôm, phần mềm nhôm xingfa','Published',2,NULL,1,12,'2021-04-22 00:51:27','2022-07-07 21:01:55',NULL),(41,'Webinar online với chủ đề \"Giải pháp công nghệ cho nhà thầu nhôm kính”','2021-05-04 10:19:00','1620114611-webinar-online-voi-chu-de-giai-phap-cong-nghe-cho-nha-thau-nhom-kinh.jpg','Vào 09h30 ngày 12/05/2021, Website nghenoithat.vn phối hợp cùng Hãng phần mềm Logikal, tổ chức hội thảo online với chủ đề \"Giải pháp công nghệ cho nhà thầu nhôm kính”.','<p style=\"text-align: justify;\">Hiện nay, ứng dụng c&ocirc;ng nghệ đang l&agrave; xu hướng trong mọi lĩnh vực, v&agrave; ng&agrave;nh gia c&ocirc;ng nh&ocirc;m k&iacute;nh cũng kh&ocirc;ng phải l&agrave; ngoại lệ. Nhận thức được thực trạng đ&oacute;, ch&uacute;ng t&ocirc;i, trang th&ocirc;ng tin tổng hợp Nghenoithat.vn, tr&acirc;n trọng mời Qu&yacute; kh&aacute;ch h&agrave;ng, Qu&yacute; độc giả tham dự webinar với chủ đề \"Giải ph&aacute;p c&ocirc;ng nghệ cho nh&agrave; thầu nh&ocirc;m k&iacute;nh&rdquo;.</p>\r\n<p style=\"text-align: justify;\"><br />Nghenoithat.vn sẽ phối hợp với H&atilde;ng phần mềm Logikal tổ chức. Chương tr&igrave;nh hội thảo trực tuyến với mục ti&ecirc;u gi&uacute;p c&aacute;c đơn vị doanh nghiệp đang hoạt động trong lĩnh vực sản xuất v&agrave; gia c&ocirc;ng nh&ocirc;m k&iacute;nh c&oacute; g&oacute;c nh&igrave;n tổng quan tới chi tiết về việc ứng dụng phần mềm c&ocirc;ng nghệ, cụ thể l&agrave; Logikal, v&agrave;o sản xuất, gia c&ocirc;ng: cửa sổ, cửa đi, hệ mặt dựng, ...&nbsp;</p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/8JVtgIXUuBfqUzweqHxpEoXIU1ZbriSF1ffoTTwN.jpeg\" alt=\"\" width=\"750\" height=\"478\" /></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p>Chương tr&igrave;nh webinar sẽ được diễn ra từ 09h30 &ndash; 11h00 (giờ H&agrave; Nội), ng&agrave;y 12/05/2021.</p>\r\n<p>&nbsp;</p>\r\n<p>Qu&yacute; kh&aacute;ch h&agrave;ng, Qu&yacute; độc giả c&oacute; thể đăng k&yacute; tham dự Hội thảo bằng c&aacute;ch qu&eacute;t m&atilde; QR tr&ecirc;n h&igrave;nh ảnh hoặc đăng k&yacute; tại đ&acirc;y:&nbsp;<a href=\"https://docs.google.com/forms/d/e/1FAIpQLSfnYDGra2iF4LjPG_Of2btISfNMiZrxK8EngvYTCuXcu8GVrQ/viewform\" target=\"_blank\" rel=\"noopener\">Đăng k&yacute; tham dự</a></p>\r\n<p><br />Nghenoithat.vn xin tr&acirc;n trọng th&ocirc;ng b&aacute;o để Qu&yacute; kh&aacute;ch h&agrave;ng, Qu&yacute; độc giả quan t&acirc;m c&oacute; thể đăng k&yacute; tham dự. Rất hi vọng c&oacute; được sự tham gia của Qu&yacute; vị./.</p>','Webinar online với chủ đề \"Giải pháp công nghệ cho nhà thầu nhôm kính”',NULL,'webinar-online-voi-chu-de-giai-phap-cong-nghe-cho-nha-thau-nhom-kinh','Vào 09h30 ngày 12/05/2021, Website nghenoithat.vn phối hợp cùng Hãng phần mềm Logikal, tổ chức hội thảo online với chủ đề \"Giải pháp công nghệ cho nhà thầu nhôm kính”.',NULL,'Published',2,NULL,1,13,'2021-05-03 20:51:08','2021-05-04 18:28:01',NULL),(42,'Nội thất Việt Nam vượt Trung Quốc vào Mỹ','2021-05-10 15:55:00','1620637153-noi-that-viet-nam-vuot-trung-quoc-vao-my.jpg','Thông tin này vừa được tạp chí chuyên ngành có uy tín trong ngành nội thất Furniture Today công bố trong một nghiên cứu gần đây.','<h2 style=\"text-align: justify;\"><strong>Nội thất Việt sang Mỹ tăng 31%</strong></h2>\r\n<p style=\"text-align: justify;\"><br />Theo Furniture Today, năm 2020, Việt Nam đ&atilde; xuất 7,4 tỉ USD đồ nội thất sang Mỹ, tăng 31% so với năm 2019. Trong khi đ&oacute;, Trung Quốc đ&atilde; xuất 7,33 tỉ USD sang thị trường n&agrave;y trong c&ugrave;ng kỳ, giảm 25% so với năm 2019. Furniture Today nhận định d&ugrave; khoảng c&aacute;ch l&agrave; tương đối nhỏ, nhưng vị tr&iacute; của Việt Nam tr&ecirc;n thị trường thế giới cho thấy ng&agrave;nh nội thất nước n&agrave;y đ&atilde; ph&aacute;t triển như thế n&agrave;o trong những năm qua.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Kh&ocirc;ng chỉ c&oacute; thị trường Mỹ, xuất khẩu đồ gỗ v&agrave; sản phẩm gỗ của Việt Nam sang thị trường EU cũng tăng rất tốt. Th&aacute;ng 4 đạt 27 triệu USD, tăng 102% so với c&ugrave;ng kỳ năm ngo&aacute;i. T&iacute;nh chung trong 4 th&aacute;ng đầu năm nay, xuất khẩu gỗ v&agrave; sản phẩm gỗ sang EU ước đạt 247,1 triệu USD, tăng 31,3% so với c&ugrave;ng kỳ năm ngo&aacute;i.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><br />Cụ thể, trong 2 năm trở lại đ&acirc;y, ch&iacute;nh phủ Mỹ &aacute;p đặt mức thuế cao tới 25% đối với hầu hết c&aacute;c loại đồ nội thất. Nửa cuối năm 2018, khi thuế quan của Trung Quốc bắt đầu ở mức 10%, ng&agrave;nh c&ocirc;ng nghiệp n&agrave;y đ&atilde; bắt đầu chuyển ra khỏi Trung Quốc. C&aacute;c l&ocirc; h&agrave;ng đồ nội thất của Trung Quốc giảm 1% xuống 13,6 tỉ USD.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><br />Trong khi đ&oacute;, c&aacute;c l&ocirc; h&agrave;ng của Việt Nam đ&atilde; tăng 9% l&ecirc;n 4,2 tỉ USD (từ 3,9 tỉ USD trong năm 2017). Chuyển biến &ldquo;mạnh mẽ&rdquo; hơn bắt đầu v&agrave;o năm 2019, khi h&agrave;ng nội thất Trung Quốc xuất sang Mỹ giảm 28% xuống c&ograve;n 9,7 tỉ USD. C&ugrave;ng thời điểm, h&agrave;ng Việt Nam tăng 35% l&ecirc;n khoảng 5,7 tỉ USD.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><br />Furniture Today dẫn lời Gi&aacute;m đốc điều h&agrave;nh của Tập đo&agrave;n nội thất Riverside (Mỹ) cho biết h&agrave;ng nội thất ph&ograve;ng ngủ, ph&ograve;ng ăn, nội thất văn ph&ograve;ng v&agrave; ph&ograve;ng l&agrave;m việc tại nh&agrave; đều được doanh nghiệp n&agrave;y nhập khẩu phần lớn từ Việt Nam. Vị n&agrave;y cũng khẳng định Việt Nam ph&ugrave; hợp trong lĩnh vực sản xuất nội thất &ldquo;như l&agrave; nguồn cung h&agrave;ng đầu&rdquo; của doanh nghiệp. Cũng theo tạp ch&iacute; tr&ecirc;n, một số &yacute; kiến kh&aacute;c nhận định thuế suất đối với h&agrave;ng h&oacute;a từ Trung Quốc v&agrave;o Mỹ đ&atilde; t&aacute;c động đến gi&aacute; cả. Đại diện của H&atilde;ng Klaussner Home Furnishings cho biết doanh số b&aacute;n h&agrave;ng trong ph&acirc;n kh&uacute;c gỗ từ Việt Nam đ&atilde; tăng 10% trong năm 2020. Đồ nội thất bằng gỗ kh&aacute;c l&agrave; mặt h&agrave;ng xuất khẩu lớn nhất từ Việt Nam với 1,9 tỉ USD, tăng 43% so với năm trước.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<h2 style=\"text-align: justify;\"><strong>Cẩn trọng với c&aacute;c biện ph&aacute;p ph&ograve;ng vệ thương mại</strong></h2>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: justify;\">&Ocirc;ng Nguyễn Ch&aacute;nh Phương, Ph&oacute; chủ tịch ki&ecirc;m Tổng thư k&yacute; Hội Mỹ nghệ v&agrave; chế biến gỗ TP.HCM, cũng cho biết xuất khẩu đồ nội thất của Việt Nam sang Mỹ tăng mạnh, hiện thị trường Mỹ chiếm hơn 60% tổng kim ngạch xuất khẩu nội thất v&agrave; sản phẩm từ gỗ của Việt Nam.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><br />Tuy nhi&ecirc;n, &ocirc;ng cảnh b&aacute;o: &ldquo;Cũng cần &ldquo;tỉnh t&aacute;o&rdquo; để thấy r&otilde; những doanh nghiệp xuất khẩu nội thất chiếm trị gi&aacute; lớn phần lớn l&agrave; doanh nghiệp c&oacute; vốn đầu tư nước ngo&agrave;i (FDI), trong đ&oacute; FDI từ Trung Quốc trong v&agrave;i năm trở lại đ&acirc;y lại chiếm con số lớn&rdquo;.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><br />C&oacute; 2 lo lắng m&agrave; ng&agrave;nh sản xuất đồ nội thất cần nh&igrave;n thấy. Đ&oacute; l&agrave; khi c&aacute;c nh&agrave; đầu tư nước ngo&agrave;i t&igrave;m cơ hội từ Việt Nam bằng việc tăng tốc đầu tư, t&igrave;nh trạng khan hiếm nguồn nguy&ecirc;n liệu v&agrave; tiền thu&ecirc; mặt bằng sản xuất sẽ tăng mạnh g&acirc;y kh&ocirc;ng &iacute;t kh&oacute; khăn cho doanh nghiệp trong nước. &ldquo;Những doanh nghiệp sản xuất quy m&ocirc; nhỏ hơn, trước sự &ldquo;tấn c&ocirc;ng&rdquo; ồ ạt của c&aacute;c doanh nghiệp ngoại, nguy cơ bị đ&agrave;o thải nhiều hơn&rdquo;, &ocirc;ng Phương nhấn mạnh. Điều lo lắng thứ 2, theo &ocirc;ng Phương, l&agrave; nguy cơ đồ gỗ v&agrave; sản xuất từ gỗ của Việt Nam bị điều tra ph&ograve;ng vệ thương mại nếu xuất hiện t&igrave;nh trạng doanh nghiệp ngoại đầu tư &ldquo;n&uacute;p b&oacute;ng&rdquo;, chỉ l&agrave;m c&ocirc;ng đoạn cuối xuất khẩu sang Mỹ.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><br />&ldquo;Thực tế ng&agrave;nh hải quan cuối năm vừa qua đ&atilde; c&oacute; cảnh b&aacute;o hơn chục doanh nghiệp ngoại mới th&agrave;nh lập, kim ngạch xuất khẩu tăng đột biến, nh&agrave; xưởng kh&ocirc;ng bao nhi&ecirc;u..., nhưng đến nay việc điều tra chưa ra. Đ&oacute; l&agrave; nguy cơ m&agrave; những doanh nghiệp l&agrave;m ăn ch&acirc;n ch&iacute;nh trong ng&agrave;nh tại Việt Nam lo lắng&rdquo;, &ocirc;ng Phương n&oacute;i v&agrave; dẫn chứng việc 7 doanh nghiệp l&agrave;m h&agrave;ng sofa tại Việt Nam vừa bị ph&iacute;a t&ograve;a &aacute;n Canada kết luận sơ bộ &aacute;p thuế 101,5% vừa qua l&agrave; lời cảnh b&aacute;o.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Theo: B&aacute;o Thanh ni&ecirc;n</p>','Nội thất Việt Nam vượt Trung Quốc vào Mỹ',NULL,'noi-that-viet-nam-vuot-trung-quoc-vao-my','Thông tin này vừa được tạp chí chuyên ngành có uy tín trong ngành nội thất Furniture Today công bố trong một nghiên cứu gần đây.',NULL,'Published',2,NULL,1,14,'2021-05-10 01:59:13','2021-05-10 01:59:13',NULL),(43,'Tổ chức thành công hội thảo online với chủ đề “Giải pháp công nghệ cho các nhà thầu nhôm kính”','2021-05-13 09:56:00','1620875719-to-chuc-thanh-cong-hoi-thao-online-voi-chu-de-giai-phap-cong-nghe-cho-cac-nha-thau-nhom-kinh.jpg','Ngày 12/05/2021, Nghề nội thất đã có buổi trình bày, giới thiệu về phần mềm Logikal - phần mềm chuyên dụng thiết kế, sản xuất hệ cửa sổ, cửa đi, hệ vách dựng của hãng Orgadata (Đức). Buổi giới thiệu đã diễn ra thành công với sự tham gia của nhiều đơn vị là các nhà thầu nhôm kính lớn tại Việt Nam.','<p style=\"text-align: center;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><img src=\"/storage/uploads/tinymce/BlqL4r6Pycy5xQpUVSf1XWmA1az2dzuSf5s0qoRR.jpeg\" alt=\"\" width=\"748\" height=\"275\" /></span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-family: \'times new roman\', times, serif; font-size: 14pt;\">Mở đầu buổi hội thảo, Nghề nội thất c&ugrave;ng đại diện cho c&aacute;c doanh nghiệp tham gia đ&atilde; c&ugrave;ng nhau trao đổi v&agrave; thẳng thắn chỉ ra những vấn đề bất cập, những điểm c&ograve;n tồn tại trong quy tr&igrave;nh thiết kế, sản xuất của c&aacute;c đơn vị thầu nh&ocirc;m k&iacute;nh tại Việt Nam. Một trong số đ&oacute; l&agrave; việc phải d&agrave;nh nhiều thời gian cho kh&acirc;u thao t&aacute;c với c&aacute;c phần mềm CAD, rủi ro sai s&oacute;t trong b&oacute;c t&aacute;ch vật tư, lập dự to&aacute;n c&ocirc;ng tr&igrave;nh v&agrave; tỷ lệ hao ph&iacute; vật tư ở mức cao.&nbsp;</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><img src=\"/storage/uploads/tinymce/1N7P0h0NuFAShcKRUysolZTbf76D3w2zPOlEzwXN.jpeg\" alt=\"thuc-trang-nganh-nhom-kinh\" width=\"652\" height=\"332\" /></span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-family: \'times new roman\', times, serif; font-size: 14pt;\">Hiểu được những hạn chế, kh&oacute; khăn m&agrave; c&aacute;c doanh nghiệp thầu nh&ocirc;m k&iacute;nh gặp phải trong qu&aacute; tr&igrave;nh l&agrave;m việc, webinar với chủ đề &ldquo;Giải ph&aacute;p c&ocirc;ng nghệ cho c&aacute;c nh&agrave; thầu nh&ocirc;m k&iacute;nh&rdquo; đ&atilde; được thực hiện nhằm giới thiệu về giải ph&aacute;p Logikal - giải ph&aacute;p h&agrave;ng đầu cho c&aacute;c nh&agrave; thầu nh&ocirc;m k&iacute;nh.&nbsp;&nbsp;</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-family: \'times new roman\', times, serif; font-size: 14pt;\">Được ph&aacute;t h&agrave;nh bởi H&atilde;ng phần mềm Orgadata (Đức), Logikal được đ&aacute;nh gi&aacute; l&agrave; một trong số những phần mềm chuy&ecirc;n dụng h&agrave;ng đầu cho c&aacute;c nh&agrave; thầu nh&ocirc;m k&iacute;nh với nhiều t&iacute;nh năng nổi bật như:</span></p>\r\n<ul style=\"text-align: justify;\">\r\n<li style=\"font-weight: 400; text-align: justify;\" aria-level=\"1\"><span style=\"font-weight: 400; font-family: \'times new roman\', times, serif; font-size: 14pt;\">Khả năng thiết kế nhanh ch&oacute;ng c&aacute;c hệ cửa đi, cửa sổ, hệ mặt v&aacute;ch dựng lớn;</span></li>\r\n<li style=\"font-weight: 400; text-align: justify;\" aria-level=\"1\"><span style=\"font-weight: 400; font-family: \'times new roman\', times, serif; font-size: 14pt;\">Kho thư viện profile đa dạng, chủ động;</span></li>\r\n<li style=\"font-weight: 400; text-align: justify;\" aria-level=\"1\"><span style=\"font-weight: 400; font-family: \'times new roman\', times, serif; font-size: 14pt;\">Khả năng b&oacute;c t&aacute;ch vật tư nhanh ch&oacute;ng, ch&iacute;nh x&aacute;c, to&agrave;n diện;</span></li>\r\n<li style=\"font-weight: 400; text-align: justify;\" aria-level=\"1\"><span style=\"font-weight: 400; font-family: \'times new roman\', times, serif; font-size: 14pt;\">Tối ưu pha cắt nh&ocirc;m với tỷ lệ hao ph&iacute; ở mức tối thiểu;</span></li>\r\n<li style=\"font-weight: 400; text-align: justify;\" aria-level=\"1\"><span style=\"font-weight: 400; font-family: \'times new roman\', times, serif; font-size: 14pt;\">T&iacute;nh to&aacute;n kết cấu, tải trọng hỗ trợ tối đa nh&agrave; thầu khi lựa chọn vật tư;</span></li>\r\n<li style=\"font-weight: 400; text-align: justify;\" aria-level=\"1\"><span style=\"font-weight: 400; font-family: \'times new roman\', times, serif; font-size: 14pt;\">Khả năng kết nối m&aacute;y gia c&ocirc;ng CNC đa dạng, tăng khả năng tự động ho&aacute; trong sản xuất;</span></li>\r\n</ul>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><span style=\"font-weight: 400; font-family: \'times new roman\', times, serif; font-size: 14pt;\"><img src=\"/storage/uploads/tinymce/lAAMAF0SEDaf2CjfxPMuejY1vdAq2YsehjgX0m8u.png\" alt=\"thiet-ke-cua-di-logikal\" width=\"700\" height=\"459\" /><br /><em>Thiết kế hệ cửa đi trong Logikal</em></span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-family: \'times new roman\', times, serif; font-size: 14pt;\">Phần tr&igrave;nh b&agrave;y nhận được sự ủng hộ, hưởng ứng lớn từ đại diện c&aacute;c doanh nghiệp tham gia. Sau phần giới thiệu, Nghề nội thất đ&atilde; giải đ&aacute;p v&agrave; cung cấp đầy đủ th&ocirc;ng tin đối với những thắc mắc, c&acirc;u hỏi được đặt ra tại buổi hội thảo.&nbsp;</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Mọi th&ocirc;ng tin chi tiết xin li&ecirc;n hệ:&nbsp;</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>Trung t&acirc;m Giải ph&aacute;p C&ocirc;ng nghệ Ng&agrave;nh nội thất &ndash; Vật liệu x&acirc;y dựng&nbsp;CIC</strong></span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Hotline: 0866.059.659</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Website: cic.com.vn</span></p>','CIC tổ chức buổi hội thảo online webinar với chủ đề “Giải pháp công nghệ cho các nhà thầu nhôm kính”',NULL,'to-chuc-thanh-cong-hoi-thao-online-voi-chu-de-giai-phap-cong-nghe-cho-cac-nha-thau-nhom-kinh','Ngày 12/05/2021, Công ty CP Công nghệ và Tư vấn CIC và Nghề nội thất đã có buổi trình bày, giới thiệu về phần mềm Logikal - phần mềm chuyên dụng thiết kế, sản xuất hệ cửa sổ, cửa đi, hệ vách dựng của hãng Orgadata (Đức). Buổi giới thiệu đã diễn ra thành công với sự tham gia của nhiều đơn vị là các nhà thầu nhôm kính lớn tại Việt Nam.',NULL,'Published',2,NULL,1,14,'2021-05-12 20:15:19','2022-06-27 19:45:52',NULL),(44,'Sử dụng liên kết Peanut trong Cabinet Vision 2021','2021-05-18 09:21:00','1621306559-su-dung-lien-ket-peanut-trong-cabinet-vision-2021.jpg','Mới đây, nhà sản xuất và phân phối phụ kiện Intelligent Fixing (Anh) đã cho ra mắt bộ phụ kiện thông minh Peanut (với 3 phiên bản). Không chỉ đảm bảo yếu tố kĩ thuật về tính vững chắc trong các kết cấu đồ nội thất gỗ công nghiệp, Peanut hoàn toàn đáp ứng nhu cầu về mặt thẩm mỹ trong ứng dụng thực tiễn.','<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">Những ưu điểm nổi bật của Peanut so với cam chốt th&ocirc;ng thường:</span></p>\r\n<ul style=\"text-align: justify;\">\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><span style=\"font-weight: 400;\">Th&aacute;o lắp dễ d&agrave;ng</span></li>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><span style=\"font-weight: 400;\">T&iacute;nh cứng vững cao</span></li>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><span style=\"font-weight: 400;\">Cho ph&eacute;p lắp đặt trước vận chuyển (Đảm bảo sự ch&iacute;nh x&aacute;c)</span></li>\r\n</ul>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">C&acirc;u hỏi được đặt ra l&agrave; nếu c&aacute;c đơn vị sản xuất nội thất gỗ c&ocirc;ng nghiệp muốn sử dụng loại li&ecirc;n kết ưu việt n&agrave;y trong thiết kế cũng như lắp đặt th&igrave; đ&acirc;u sẽ l&agrave; giải ph&aacute;p cho họ?</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400;\">Hiện nay, phần mềm Cabinet Vision đ&atilde; cập nhật bộ phụ kiện Peanut trong bộ cơ sở dữ liệu của phi&ecirc;n bản 2021.Người d&ugrave;ng ho&agrave;n to&agrave;n c&oacute; thể đưa v&agrave;o sử dụng bộ phụ kiện n&agrave;y với k&iacute;ch thước&nbsp; ti&ecirc;u chuẩn cho c&aacute;c thiết kế của đơn vị</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><span style=\"font-weight: 400;\"><img src=\"/storage/uploads/tinymce/dEBxqvAQUwm4ZW13i8DakBawRP0CVRz6kMmvrKrf.png\" alt=\"\" width=\"700\" height=\"515\" /><br /><em>Li&ecirc;n kết Peanut trong Cabinet Vision 2021</em><br /></span></p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-weight: 400;\">B&ecirc;n cạnh đ&oacute;, với c&aacute;c c&agrave;i đặt được t&ugrave;y chỉnh theo nhu cầu thiết kế ri&ecirc;ng, c&aacute;c module tủ, đồ nội thất cũng sẽ được tự động cập nhật sử dụng li&ecirc;n kết Peanut một c&aacute;ch nhanh ch&oacute;ng.</span></p>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: center;\"><span style=\"font-weight: 400;\"><img src=\"/storage/uploads/tinymce/jFK57jcqpDreiPJ1CAezpnQnrwC0AyE3UMofEMJ7.png\" alt=\"\" width=\"700\" height=\"512\" /><br /><em>Tủ bếp dưới 2 c&aacute;nh sử dụng li&ecirc;n kết Peanut</em></span></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p><span style=\"font-weight: 400;\">Video minh họa c&aacute;ch th&ecirc;m v&agrave; sử dụng li&ecirc;n kết Peanut trong Cabinet Vision 2021: <a href=\"https://www.youtube.com/watch?v=ZfIQmfWY5Z8\">Sử dụng li&ecirc;n kết Peanut trong Cabinet Vision</a></span></p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-weight: 400;\">T&igrave;m hiểu th&ecirc;m về phần mềm Cabinet Vision 2021 tại: <a href=\"/san-pham/cabinet-vision\" target=\"_blank\" rel=\"noopener\">Phần mềm Cabinet Vision</a></span></p>','Sử dụng liên kết Peanut trong Cabinet Vision 2021',NULL,'su-dung-lien-ket-peanut-trong-cabinet-vision-2021','Mới đây, nhà sản xuất và phân phối phụ kiện Intelligent Fixing (Anh) đã cho ra mắt bộ phụ kiện thông minh Peanut (với 3 phiên bản). Không chỉ đảm bảo yếu tố kĩ thuật về tính vững chắc trong các kết cấu đồ nội thất gỗ công nghiệp, Peanut hoàn toàn đáp ứng nhu cầu về mặt thẩm mỹ trong ứng dụng thực tiễn.',NULL,'Published',2,NULL,1,15,'2021-05-17 19:55:59','2021-05-17 19:55:59',NULL),(45,'EU áp thuế đối với nhôm nhập khẩu từ Trung Quốc sẽ tác động ra sao tới ngành nhôm Việt Nam?','2021-05-21 15:37:00','1621586392-eu-ap-thue-doi-voi-nhom-nhap-khau-tu-trung-quoc-se-tac-dong-ra-sao-toi-nganh-nhom-viet-nam.jpg','Liên minh Châu Âu (EU) ngày 30/3/2021 đã chính thức công bố áp thuế đối với các sản phẩm nhôm nhập khẩu từ Trung Quốc, sau khi kết quả điều tra cho thấy nhôm Trung Quốc bán cho EU có giá thấp một cách không công bằng.','<p style=\"text-align: justify;\">Theo đ&oacute;, Ủy ban Ch&acirc;u &Acirc;u &ndash; cơ quan gi&aacute;m s&aacute;t ch&iacute;nh s&aacute;ch thương mại của 27 quốc gia EU, đặt ra mức thuế chống b&aacute;n ph&aacute; gi&aacute; trong khoảng từ 21,2% đến 31,2% đối với c&aacute;c nh&agrave; sản xuất nh&ocirc;m định h&igrave;nh của Trung Quốc (nh&ocirc;m định h&igrave;nh dạng thanh, dạng que hoặc dạng ống).</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Mức thuế n&agrave;y thấp hơn so với mức thuế tạm thời l&agrave; 30,4% đến 48,0% &aacute;p dụng trong qu&aacute; tr&igrave;nh điều tra.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Được biết, EC đ&atilde; mở cuộc điều tra từ th&aacute;ng 2/2020 đối với những sản phẩm nh&ocirc;m được sử dụng rộng r&atilde;i trong lĩnh vực vận tải, x&acirc;y dựng v&agrave; điện, sau khi nhận được đơn khiếu nại của European Aluminium về việc nh&ocirc;m Trung Quốc cạnh tranh kh&ocirc;ng c&ocirc;ng bằng tr&ecirc;n thị trường EU. C&aacute;c th&agrave;nh vi&ecirc;n của European Aluminium bao gồm Norsk Hydro, Rio Tinto&nbsp; v&agrave; Alcoa.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Cụ thể, sản phẩm nh&ocirc;m định h&igrave;nh của c&aacute;c c&ocirc;ng ty Guangdong Haomei New Materials Co Ltd V&Agrave; Guangdong King Metal Light Alloy Technology Co Ltd sẽ phải chịu mức thuế chống ph&aacute; gi&aacute; 21,2%, trong khi của Press Metal International Ltd chịu thuế 25%. Những c&ocirc;ng ty kh&aacute;c c&oacute; \"hợp t&aacute;c\" trong qu&aacute; tr&igrave;nh điều tra sẽ chịu mức thuế 22,1%, v&agrave; nguy&ecirc;n liệu từ c&aacute;c c&ocirc;ng ty kh&aacute;c nữa sẽ chịu thuế 32,1%.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Hiệp hội Kim loại Trung Quốc đ&atilde; gọi động th&aacute;i n&agrave;y của EU l&agrave; \"h&agrave;nh động v&ocirc; căn cứ\".</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Việc nh&ocirc;m định h&igrave;nh của Trung Quốc bị &aacute;p thuế chống b&aacute;n ph&aacute; gi&aacute; ở EU c&oacute; thể dẫn tới việc c&aacute;c nh&agrave; sản xuất nh&ocirc;m Trung Quốc chuyển hướng tăng cường xuất khẩu sang những thị trường kh&aacute;c, trong đ&oacute; c&oacute; Việt Nam, giữa l&uacute;c EU đang điều tra gian lận xuất xứ đối với nh&ocirc;m nhập khẩu từ Việt Nam xem c&oacute; dấu hiệu lẩn tr&aacute;nh biện ph&aacute;p ph&ograve;ng vệ thương mại hay kh&ocirc;ng, sau khi xuất khẩu nh&ocirc;m của Việt Nam gia tăng đột biến.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Th&aacute;ng 11/2020, Bộ C&ocirc;ng Thương Việt Nam cũng đ&atilde; ban h&agrave;nh Quyết định r&agrave; so&aacute;t lần thứ nhất việc &aacute;p dụng biện ph&aacute;p chống b&aacute;n ph&aacute; gi&aacute; một số sản phẩm nh&ocirc;m c&oacute; xuất xứ từ Trung Quốc (m&atilde; AR01.AD05). Theo đ&oacute;, c&aacute;c c&ocirc;ng ty được r&agrave; so&aacute;t mức thuế chống b&aacute;n ph&aacute; gi&aacute; trong vụ việc AR01.AD05 gồm: Nh&oacute;m c&ocirc;ng ty Xingfa (bao gồm C&ocirc;ng ty Guangdong Xingfa Aluminium Co., Ltd v&agrave; c&aacute;c c&ocirc;ng ty li&ecirc;n kết); nh&oacute;m c&ocirc;ng ty JMA (bao gồm C&ocirc;ng ty Guangdong JMA Aluminium Profile Factory (Group) Co., Ltd v&agrave; c&aacute;c c&ocirc;ng ty li&ecirc;n kết); C&ocirc;ng ty Bazhou Jinwoshengdi Aluminum Products Co., Ltd; C&ocirc;ng ty Fujian Zhangzhou Antai Aluminium Co., Ltd v&agrave; C&ocirc;ng ty Guangdong Weiye Aluminum Factory Group Co., Ltd.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Trước đ&oacute;, ng&agrave;y 28/9/2019, Bộ C&ocirc;ng thương ban h&agrave;nh Quyết định số 2942/QĐ-BCT về việc &aacute;p dụng biện ph&aacute;p chống b&aacute;n ph&aacute; gi&aacute; ch&iacute;nh thức đối với một số sản phẩm nh&ocirc;m c&oacute; xuất xứ từ Trung Quốc (vụ việc AD05). Đến ng&agrave;y 29/7/2020, Bộ C&ocirc;ng thương ph&aacute;t th&ocirc;ng b&aacute;o nhận hồ sơ y&ecirc;u cầu r&agrave; so&aacute;t lần thứ nhất của vụ việc.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Được biết, lượng nh&ocirc;m xuất khẩu của cả nước chỉ dưới 10% sản lượng v&agrave; tập trung ở một số doanh nghiệp FDI.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Trước t&igrave;nh trạng ng&agrave;y c&agrave;ng nhiều nước tr&ecirc;n thế giới &aacute;p dụng c&aacute;c biến ph&aacute;p chống b&aacute;n ph&aacute; gi&aacute; nghi&ecirc;m ngặt đối với nh&ocirc;m nhập khẩu, tại buổi l&agrave;m việc giữa Hội nh&ocirc;m thanh định h&igrave;nh Việt Nam với Cục Xuất nhập khẩu &ndash; Bộ C&ocirc;ng thương th&aacute;ng 1/2021 về t&igrave;nh h&igrave;nh xuất nhập khẩu của ng&agrave;nh Nh&ocirc;m Việt Nam năm qua, Cục Xuất nhập khẩu v&agrave; Hiệp hội cảnh b&aacute;o c&aacute;c doanh nghiệp cần lưu &yacute; khi hợp t&aacute;c với c&aacute;c doanh nghiệp FDI để xuất khẩu nh&ocirc;m định h&igrave;nh sang EU v&agrave; c&aacute;c nước kh&aacute;c bởi c&aacute;c thủ đoạn để gian lận xuất xứ đang ng&agrave;y c&agrave;ng tinh vi hơn.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Đối với thị trường Mỹ, hiện nay Mỹ &aacute;p thuế chống b&aacute;n ph&aacute; gi&aacute; ở mức rất cao đối với một số sản phẩm nh&ocirc;m, nhưng đa số c&aacute;c sản phẩm nh&ocirc;m của Việt Nam xuất sang thị trường n&agrave;y kh&ocirc;ng thuộc m&atilde; bị &aacute;p thuế cao n&ecirc;n vẫn duy tr&igrave; được hoạt động xuất khẩu trong năm qua. Mặc d&ugrave; vậy, nếu nh&ocirc;m xuất khẩu của Việt Nam sang Mỹ tăng đột biến hoặc c&oacute; biểu hiện bất thường kh&aacute;c, khi đ&oacute; kh&ocirc;ng loại trừ khả năng Mỹ sẽ xem x&eacute;t tới c&aacute;c biện ph&aacute;p điều tra chống b&aacute;n ph&aacute; gi&aacute;.&nbsp;</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Tr&ecirc;n thực tế, ng&agrave;y 2/3/2021, Bộ Thương mại Mỹ đ&atilde; ban h&agrave;nh mức thuế chống b&aacute;n ph&aacute; gi&aacute; cuối c&ugrave;ng đối với nh&ocirc;m tấm hợp kim th&ocirc;ng thường (một sản phẩm c&aacute;n phẳng được sử dụng trong việc x&acirc;y dựng bề mặt v&agrave; th&ugrave;ng xe tải cho đến biển b&aacute;o đường phố) từ 18 quốc gia bị điều tra, bao gồm cả mức thuế l&ecirc;n tới 242,8% đối với h&agrave;ng nhập khẩu từ Đức v&agrave; 4,83% đối với h&agrave;ng nhập khẩu từ Bahrain. Theo đ&oacute;, Đức c&oacute; mức chống b&aacute;n ph&aacute; gi&aacute; cao nhất, từ 49,4% đến 242,8%, v&agrave; l&agrave; nước xuất khẩu nh&ocirc;m tấm lớn nhất sang Mỹ, với trị gi&aacute; 286,6 triệu USD trong năm 2019. Bahrain, đứng thứ hai với lượng nh&ocirc;m tấm trị gi&aacute; 241,2 triệu USD xuất khẩu sang Mỹ, nhận mức thuế chống b&aacute;n ph&aacute; gi&aacute; 4,83% v&agrave; mức thuế chống trợ cấp l&ecirc;n tới 6,44%.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Sau năm 2020 gặp kh&ocirc;ng &iacute;t kh&oacute; khăn, ng&agrave;nh nh&ocirc;m Việt Nam bước v&agrave;o năm 2021 vẫn c&ograve;n rất nhiều kh&oacute; khăn do th&igrave; nguồn cung nguy&ecirc;n vật liệu bị đứt g&atilde;y, khan hiếm nh&ocirc;m nguy&ecirc;n liệu nhập khẩu&hellip;Đặc biệt, chi ph&iacute; xuất khẩu tăng l&ecirc;n rất nhiều khiến cho nhiều đơn h&agrave;ng của doanh nghiệp đ&atilde; k&yacute; kết trước đ&oacute; bị đội chi ph&iacute; l&ecirc;n nhiều lần, doanh nghiệp xuất khẩu bị lỗ trầm trọng.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Gi&aacute; nh&ocirc;m thế giới gần đ&acirc;y tăng cao do ch&iacute;nh s&aacute;ch l&agrave;m sạch m&ocirc;i trường ở Nội M&ocirc;ng, nơi sản xuất nh&ocirc;m lớn của Trung Quốc.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Gi&aacute; nh&ocirc;m tr&ecirc;n s&agrave;n Thượng Hải đầu th&aacute;ng 3/2021 đ&atilde; đạt mức cao nhất 9,5 năm, l&agrave; 18.000 CNY (2.740 USD)/tấn, sau khi th&agrave;nh phố Baotou (Nội M&ocirc;ng) ra lệnh một số cơ sở sản xuất c&ocirc;ng nghiệp v&agrave; nh&agrave; m&aacute;y điện phải đ&oacute;ng cửa v&igrave; vi phạm quy định về m&ocirc;i trường. C&ocirc;ng ty tư vấn CRU dự đo&aacute;n sản lượng nh&ocirc;m của Trung Quốc c&oacute; thể giảm 100.000 tấn/năm do động th&aacute;i n&agrave;y của Nội M&ocirc;ng. Chủ tịch c&ocirc;ng ty Chalco dự b&aacute;o gi&aacute; nh&ocirc;m sẽ c&ograve;n tiếp tục duy tr&igrave; ở mức cao trong năm 2021.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><em>Tham khảo từ Reuters v&agrave; một số nguồn tin kh&aacute;c</em></p>','EU áp thuế đối với nhôm nhập khẩu từ Trung Quốc sẽ tác động ra sao tới ngành nhôm Việt Nam?',NULL,'eu-ap-thue-doi-voi-nhom-nhap-khau-tu-trung-quoc-se-tac-dong-ra-sao-toi-nganh-nhom-viet-nam','Liên minh Châu Âu (EU) ngày 30/3/2021 đã chính thức công bố áp thuế đối với các sản phẩm nhôm nhập khẩu từ Trung Quốc, sau khi kết quả điều tra cho thấy nhôm Trung Quốc bán cho EU có giá thấp một cách không công bằng.',NULL,'Published',2,NULL,1,15,'2021-05-21 01:39:52','2021-05-21 01:40:16',NULL),(46,'Xây dựng sơ đồ cắt tối ưu và quản lý nguyên liệu thừa với Opera Cutting Assistant','2021-05-31 09:55:00','1622519098-xay-dung-so-do-cat-toi-uu-va-quan-ly-nguyen-lieu-thua-voi-opera-cutting-assistant.jpg','Có trụ sở tại Sardinia,Ý; Opera là 1 công ty phát triển phần mềm năng động với hơn 5000 sản phẩm đã được bán ra tại hơn 70 quốc gia trên thế giới. Trong quá trình phát triển, Opera đã liên tục  nâng cấp, hoàn thiện phần mềm Opera Job Management như một công cụ hỗ trợ các đơn vị nhà thầu nhôm kính trong việc thiết kế, bóc tách vật tư, xây dựng tư liệu sản xuất và hỗ trợ gia công trên máy CNC','<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-size: 12pt; font-family: arial, helvetica, sans-serif;\">B&ecirc;n cạnh đ&oacute;, h&atilde;ng Opera đ&atilde; ph&aacute;t triển th&ecirc;m một phần mềm với t&ecirc;n gọi Cutting Assistant - vốn được coi l&agrave; một module nhỏ b&ecirc;n cạnh Opera Job Management với c&aacute;c t&iacute;nh năng ch&iacute;nh sau:&nbsp;</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-size: 12pt; font-family: arial, helvetica, sans-serif;\">- Kết nối v&agrave; điều khiển c&aacute;c m&aacute;y cưa NC (Điều khiển số)</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt; font-family: arial, helvetica, sans-serif;\"><strong>- </strong><span style=\"font-weight: 400;\">X&acirc;y dựng sơ đồ tối ưu cắt thanh profile (C&oacute; thể nhập c&aacute;c danh s&aacute;ch cắt dưới dạng txt, csv, xml, xls, dwg, dxf,...)</span></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt; font-family: arial, helvetica, sans-serif;\"><strong>- </strong><span style=\"font-weight: 400;\">Tạo v&agrave; in tem nh&atilde;n (Cho thanh profile th&agrave;nh phẩm v&agrave; thanh profile dư)</span></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-size: 12pt; font-family: arial, helvetica, sans-serif;\">- Đồng bộ với Opera JM để quản l&yacute; qu&aacute; tr&igrave;nh cắt thanh profile từ m&aacute;y t&iacute;nh tr&ecirc;n văn ph&ograve;ng</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-size: 12pt; font-family: arial, helvetica, sans-serif;\">- Quản l&yacute; kho thanh profile dư c&oacute; thể sử dụng lại (Li&ecirc;n kết trực tiếp đến Opera Job Management)</span></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><span style=\"font-weight: 400; font-size: 12pt; font-family: arial, helvetica, sans-serif;\"><img src=\"/storage/uploads/tinymce/cUQZCnJiMRIP8NmH4Uec1OM1ugbVC3rD4yBqNEZT.png\" alt=\"giao-dien-cutting-assistant-opera\" width=\"753\" height=\"533\" /><br /></span></p>\r\n<p style=\"text-align: center;\"><span style=\"font-size: 12pt; font-family: arial, helvetica, sans-serif;\"><em><span style=\"font-weight: 400;\">Giao diện Cutting Assistant</span></em></span></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<h2><span style=\"font-size: 12pt; font-family: arial, helvetica, sans-serif;\"><strong>X&acirc;y dựng sơ đồ cắt tối ưu thanh profile trong Cutting Assistant</strong></span></h2>\r\n<p><span style=\"font-weight: 400; font-size: 12pt; font-family: arial, helvetica, sans-serif;\">Cutting Assistant sử dụng c&aacute;c thanh profile nh&ocirc;m đ&atilde; lưu trữ trong cơ sở dữ liệu của Opera Job Management</span></p>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: center;\"><span style=\"font-weight: 400; font-size: 12pt; font-family: arial, helvetica, sans-serif;\"><img src=\"/storage/uploads/tinymce/XnLSrj3xlYwhkVDBhA7WYWHNfgteiyPziXHveipF.png\" alt=\"profile-trong-cutting-assistant\" width=\"750\" height=\"532\" /><br /><em>Lưu trữ thanh profile trong Cutting Assistant</em></span></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-size: 12pt; font-family: arial, helvetica, sans-serif;\">Trước khi tiến h&agrave;nh cắt c&aacute;c thanh nh&ocirc;m theo chiều d&agrave;i đ&atilde; được t&iacute;nh to&aacute;n theo từng vị tr&iacute; của mỗi hệ cửa kh&aacute;c nhau, người d&ugrave;ng cần chuyển dữ liệu chiều d&agrave;i thanh từ Opera Job Management tới Cutting Assistant với t&iacute;nh năng <strong>Transmission.</strong></span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><span style=\"font-weight: 400; font-size: 12pt; font-family: arial, helvetica, sans-serif;\"><strong><img src=\"/storage/uploads/tinymce/lsPXTrc0n8P5i01vCdGXDs5howO3mgYHSEtxjZoR.png\" alt=\"Transmission-opera\" width=\"750\" height=\"532\" /><br /></strong><em>T&iacute;nh năng Transmission</em></span></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-size: 12pt; font-family: arial, helvetica, sans-serif;\">Sau khi qu&aacute; tr&igrave;nh chuyển dữ liệu ho&agrave;n tất, tại thư mục lưu trữ đ&atilde; c&agrave;i đặt ban đầu, phần mềm sẽ tự động tạo một tệp c&oacute; t&ecirc;n 1001. LOZ như dưới h&igrave;nh. Cutting Assistant sẽ tự động t&igrave;m tới tệp n&agrave;y để tiến h&agrave;nh thực hiện việc tối ưu gia c&ocirc;ng thanh profile.</span></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><span style=\"font-weight: 400; font-size: 12pt; font-family: arial, helvetica, sans-serif;\"><img src=\"/storage/uploads/tinymce/cIj9oPVsnfTzBswikhxICMoMI92wCqyE6zaz20T3.png\" alt=\"tep-tin-1001.loz\" width=\"750\" height=\"532\" /><br /><em>Tệp tin 1001.LOZ được tạo tự động</em></span></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><span style=\"font-weight: 400; font-size: 12pt; font-family: arial, helvetica, sans-serif;\"><img src=\"/storage/uploads/tinymce/UCsWv5Gvk83Sl9jyDAQu8NseMBdmgF9fmlggxLiq.png\" alt=\"\" width=\"750\" height=\"532\" /><br /><em>Phần mềm Cutting Assistant tự động nhận diện tệp tin th&ocirc;ng tin cắt</em></span></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-size: 12pt; font-family: arial, helvetica, sans-serif;\">Sau đ&oacute;, Cutting Assistant sẽ lần lượt đưa c&aacute;c thanh profile theo thứ tự (Người d&ugrave;ng c&oacute; thể lựa chọn thứ tự cắt t&ugrave;y &yacute;). Như trong v&iacute; dụ dưới đ&acirc;y, thanh profile 60100 d&ugrave;ng tại vị tr&iacute; khung c&aacute;nh cửa đi đang được đưa v&agrave;o cắt sau qu&aacute; tr&igrave;nh tối ưu. C&aacute;c thanh đang cắt sẽ được t&ocirc; m&agrave;u đỏ trong khi c&aacute;c thanh đ&atilde; được cắt t&ocirc; m&agrave;u x&aacute;m. B&ecirc;n cạnh đ&oacute;, từng thanh nh&ocirc;m sau cắt sẽ c&oacute; 1 tem nh&atilde;n k&egrave;m theo&nbsp; thể hiện vị tr&iacute; lắp, k&iacute;ch thước, m&agrave;u sắc v&agrave; 1 số th&ocirc;ng tin kh&aacute;c (Người d&ugrave;ng c&oacute; thể tự thiết kế mẫu tem theo nhu cầu sản xuất).</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><span style=\"font-weight: 400; font-size: 12pt; font-family: arial, helvetica, sans-serif;\"><img src=\"/storage/uploads/tinymce/xLUlBJGjAUlTGlIODI3T1ol0zVDMvGE4ZwlUcUsH.png\" alt=\"\" width=\"750\" height=\"532\" /><br /><em>Qu&aacute; tr&igrave;nh tối ưu v&agrave; gia c&ocirc;ng trong Cutting Assistant</em></span></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<h2><span style=\"font-size: 12pt; font-family: arial, helvetica, sans-serif;\"><strong>&nbsp;Quản l&yacute; thanh profile dư trong Cutting Assistant</strong></span></h2>\r\n<p><span style=\"font-weight: 400; font-size: 12pt; font-family: arial, helvetica, sans-serif;\">Cutting Assistant hỗ trợ người d&ugrave;ng quản l&yacute; c&aacute;c thanh profile dư của mỗi dự &aacute;n để c&oacute; thể sử dụng cho những lần cắt sau đ&oacute;. C&aacute;c thanh n&agrave;y sẽ được quản l&yacute; với c&aacute;c tem nh&atilde;n ri&ecirc;ng biệt.</span></p>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: center;\"><span style=\"font-weight: 400; font-size: 12pt; font-family: arial, helvetica, sans-serif;\"><img src=\"/storage/uploads/tinymce/OS7IDtHWHA6ZqrFlzN06K2HFOpPE9N1KVcrWL6PW.png\" alt=\"\" width=\"750\" height=\"532\" /><br /><em>Lưu kho thanh profile tại vị tr&iacute; chỉ định (Kho C1)</em></span></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><span style=\"font-weight: 400; font-size: 12pt; font-family: arial, helvetica, sans-serif;\"><img src=\"/storage/uploads/tinymce/1eILgeInOJvIO84BeT6SnDAFyftKWmrDwSdQtKil.png\" alt=\"\" width=\"750\" height=\"532\" /><br /><em>Tem nh&atilde;n quản l&yacute; thanh profile dư</em></span></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-size: 12pt; font-family: arial, helvetica, sans-serif;\">C&aacute;c thanh profile dư lưu kho sẽ được tự động ưu ti&ecirc;n sử dụng trước cho c&aacute;c dự &aacute;n kế tiếp.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><span style=\"font-weight: 400; font-size: 12pt; font-family: arial, helvetica, sans-serif;\"><img src=\"/storage/uploads/tinymce/sWRnLNRoQpvOUJOB00A0jVrdKJ40GUBpC9iD992q.png\" alt=\"\" width=\"750\" height=\"532\" /><br /><em>Thanh profile dư REM1 được ưu ti&ecirc;n sử dụng khi tối ưu</em></span></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 12pt; font-family: arial, helvetica, sans-serif;\"><strong>Quản l&yacute; qu&aacute; tr&igrave;nh cắt theo thời gian thực với Opera Job Management</strong></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-size: 12pt; font-family: arial, helvetica, sans-serif;\">&nbsp;</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-size: 12pt; font-family: arial, helvetica, sans-serif;\">Qu&aacute; tr&igrave;nh cắt tr&ecirc;n Cutting Assistant c&oacute; thể được theo d&otilde;i từ xa với Opera Job Management. Số lượng c&ocirc;ng việc đ&atilde; được thực hiện sẽ được theo d&otilde;i tổng quan hoặc theo d&otilde;i tr&ecirc;n từng thanh profile cụ thể. T&iacute;nh năng n&agrave;y sẽ ph&ugrave; hợp với c&aacute;c đơn vị sản xuất đặt ph&acirc;n xưởng, nh&agrave; m&aacute;y tại vị tr&iacute; xa so với văn ph&ograve;ng thiết kế nhưng vẫn c&oacute; nhu cầu theo d&otilde;i qu&aacute; tr&igrave;nh sản xuất hiện thời.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><span style=\"font-weight: 400; font-size: 12pt; font-family: arial, helvetica, sans-serif;\"><img src=\"/storage/uploads/tinymce/mHUHY8z4z0WhuUOez7F3uqICIIeOQoRKw77xsENI.png\" alt=\"\" width=\"750\" height=\"532\" /><br /><em>Theo d&otilde;i qu&aacute; tr&igrave;nh cắt với t&iacute;nh năng Timing trong Opera Job Management</em><br /></span></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-size: 12pt; font-family: arial, helvetica, sans-serif;\"><em>T&igrave;m hiểu th&ecirc;m về Opera tại: <a href=\"/san-pham/phan-mem-thiet-ke-gia-cong-nhom-kinh-opera\" target=\"_blank\" rel=\"noopener\">Phần mềm gia c&ocirc;ng nh&ocirc;m k&iacute;nh Opera</a></em></span></p>\r\n<p>&nbsp;</p>','Xây dựng sơ đồ cắt tối ưu và quản lý nguyên liệu thừa với Opera Cutting Assistant',NULL,'xay-dung-so-do-cat-toi-uu-va-quan-ly-nguyen-lieu-thua-voi-opera-cutting-assistant','Có trụ sở tại Sardinia,Ý; Opera là 1 công ty phát triển phần mềm năng động với hơn 5000 sản phẩm đã được bán ra tại hơn 70 quốc gia trên thế giới. Trong quá trình phát triển, Opera đã liên tục  nâng cấp, hoàn thiện phần mềm Opera Job Management như một công cụ hỗ trợ các đơn vị nhà thầu nhôm kính trong việc thiết kế, bóc tách vật tư, xây dựng tư liệu sản xuất và hỗ trợ gia công trên máy CNC','phần mềm nhôm kính, Softtech V6, opera aluminium','Published',2,NULL,1,15,'2021-05-31 20:44:58','2021-05-31 21:18:38',NULL),(47,'Webinar \"Những điểm mới trong Softech V6 Version 3.8\"','2021-06-04 14:36:00','1622792816-webinar-nhung-diem-moi-trong-softech-v6-version-38.jpg','Vừa qua, Hãng phần mềm Softech đã tổ chức thành công Webinar giới thiệu bản cập nhật mới nhất của phần mềm V6 với nhiều tính năng hấp dẫn.','<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><span style=\"font-family: arial, helvetica, sans-serif; font-size: 14pt;\"><img src=\"/storage/uploads/tinymce/fmRNNhoCvQI1AkWQAgZQy5iikBgDbm050icovnLm.png\" alt=\"\" width=\"672\" height=\"386\" /></span></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"line-height: 150%; text-align: justify;\"><span style=\"font-size: 14pt; line-height: 150%; font-family: arial, helvetica, sans-serif; color: #444444;\">Trong buổi webinar n&agrave;y, h&atilde;ng phần mềm Softech đ&atilde; chia sẻ c&aacute;c t&iacute;nh năng ch&iacute;nh của giải ph&aacute;p V6 như thiết kế cửa sổ v&agrave; cửa ra v&agrave;o, c&aacute;ch tạo c&aacute;c b&aacute;o c&aacute;o một c&aacute;ch nhanh v&agrave; ch&iacute;nh x&aacute;c, &hellip;. Phần mềm V6 c&oacute; thể xử l&yacute; bất kỳ loại sản phẩm như cửa sổ, cửa ra v&agrave;o, mặt tiền cửa h&agrave;ng, &hellip; với c&aacute;c loại vật liệu kh&aacute;c nhau: nh&ocirc;m, nhựa vinyl, th&eacute;p, &hellip; </span></p>\r\n<p style=\"line-height: 150%; text-align: justify;\"><span style=\"font-size: 14pt; line-height: 150%; font-family: arial, helvetica, sans-serif; color: #444444;\">Với bản cập nhật mới nhất của V6 3.8 ra mắt v&agrave;o th&aacute;ng trước, phần mềm đ&atilde; c&oacute; một giao diện ho&agrave;n to&agrave;n mới v&agrave; th&acirc;n thiện hơn với người d&ugrave;ng.</span></p>\r\n<p style=\"line-height: 150%; text-align: justify;\">&nbsp;</p>\r\n<p style=\"line-height: 150%; text-align: center;\"><span style=\"font-size: 14pt; line-height: 150%; font-family: arial, helvetica, sans-serif; color: #444444;\"><img src=\"/storage/uploads/tinymce/Wt6jV11eH6vn6VqIYqiYasaYT7OVXvVZYz4f5iSO.png\" alt=\"\" width=\"700\" height=\"354\" /></span></p>\r\n<p style=\"line-height: 150%; text-align: center;\">&nbsp;</p>\r\n<p style=\"line-height: 150%; text-align: justify;\"><span style=\"font-family: arial, helvetica, sans-serif; font-size: 14pt;\"><span style=\"line-height: 150%; color: #444444;\">Trong năm nay, h&atilde;ng phần mềm Softech đ&atilde; đưa ra h&agrave;ng loại c&aacute;c c&ocirc;ng cụ, module, v&agrave; c&aacute;c bản cập nhật mới nhằm cải thiện hiệu năng xử l&yacute;, hiệu quả của phần mềm. Trong số đ&oacute; bao gồm t&iacute;nh năng </span><span style=\"line-height: 150%;\">Drawing Module<span style=\"color: #444444;\">, </span>ERP solution<span style=\"color: #444444;\"> cho c&aacute;c doanh nghiệp k&iacute;nh cửa, giao diện web </span>Dealer Management<span style=\"color: #444444;\"> v&agrave; bảo mật </span>Cloud Solutions<span style=\"color: #444444;\"> để hỗ trợ chuyển đổi số.</span></span></span></p>\r\n<p style=\"line-height: 150%; text-align: justify;\">&nbsp;</p>\r\n<p style=\"line-height: 150%; text-align: center;\"><span style=\"font-size: 14pt; line-height: 150%; font-family: arial, helvetica, sans-serif;\"><span style=\"color: #444444;\"><img src=\"/storage/uploads/tinymce/2CkxFWaEcGtYaghb6t3iLFKeeXoFPg0SvN4offt1.png\" alt=\"\" width=\"700\" height=\"379\" /></span></span></p>\r\n<p style=\"line-height: 150%; text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: arial, helvetica, sans-serif; font-size: 14pt;\">Trong buổi hội thảo n&agrave;y, H&atilde;ng cũng đ&atilde; l&agrave;m nổi bật những điểm mới của V6 trong việc thiết kế c&aacute;c loại cửa sổ, cửa đi, c&aacute;ch tạo ước t&iacute;nh ch&iacute;nh x&aacute;c, c&aacute;ch tạo những b&aacute;o c&aacute;o đầu ra cần thiết như bản vẽ shop drawing hay những b&aacute;o c&aacute;o c&oacute; chức năng kh&aacute;c nhau.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: arial, helvetica, sans-serif; font-size: 14pt;\">Thời gian tới, Softech sẽ tiếp tục tập trung n&acirc;ng cao trải nghiệm cho kh&aacute;ch h&agrave;ng để tối ưu h&oacute;a phần &nbsp;điều hướng, tạo, cập nhật v&agrave; nắm bắt th&ocirc;ng tin cần thiết để trở n&ecirc;n dễ d&agrave;ng hơn nhiều.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: arial, helvetica, sans-serif; font-size: 14pt;\">H&atilde;y c&ugrave;ng kh&aacute;m ph&aacute; những t&iacute;nh năng mới nhất của phần mềm V6 <a href=\"https://youtu.be/asOI8iYNy9U?list=PLlNTCdjRlNJI4WZq9TncmZ79tw6tTKWPZ\">tại đ&acirc;y</a>. Nếu bạn muốn nhận t&igrave;m hiểu về phần mềm, h&atilde;y li&ecirc;n hệ với ch&uacute;ng t&ocirc;i để nhận bản demo miễn ph&iacute;.</span></p>','Webinar \"Những điểm mới trong Softech V6 Version 3.8\"',NULL,'webinar-nhung-diem-moi-trong-softech-v6-version-38','Vừa qua, Hãng phần mềm Softech đã tổ chức thành công Webinar giới thiệu bản cập nhật mới nhất của phần mềm V6 với nhiều tính năng hấp dẫn.','thiết kế nội thất, nội thất, nội thất gỗ, công nghệ gỗ, phần mềm gỗ','Published',2,NULL,1,15,'2021-06-04 00:46:56','2021-06-04 00:46:56',NULL),(48,'Công ty PYTHA tài trợ phần mềm cho sinh viên ngành Thiết kế Nội thất','2021-06-09 17:11:00','1623233636-cong-ty-pytha-tai-tro-phan-mem-cho-sinh-vien-nganh-thiet-ke-noi-that.jpg','Chiều ngày 31/10/2018, đại diện công ty phần mềm thiết kế PYTHA đã có buổi làm việc với ban chủ nhiệm khoa Thiết kế và Nghệ thuật, Trường Đại học Hoa Sen.','<p style=\"text-align: justify;\">Đại diện ph&iacute;a c&ocirc;ng ty &nbsp;PYTHA&nbsp;CAD gồm c&oacute; &ocirc;ng Willy Flassig (Người s&aacute;ng lập v&agrave; điều h&agrave;nh PYTHA), Aaron Boo (Gi&aacute;m đốc&nbsp;PYTHA&nbsp;Ch&acirc;u &Aacute;), Zac Chen (Quản l&yacute;&nbsp;PYTHA&nbsp;Ch&acirc;u &Aacute;) đ&atilde; đến gặp gỡ v&agrave; c&oacute; buổi n&oacute;i chuyện với Ban chủ nhiệm Khoa Thiết kế v&agrave; Nghệ thuật, Thạc sỹ, Kiến tr&uacute;c sư Từ Ph&uacute; Đức &ndash; Quyền trưởng khoa, Khoa Thiết kế v&agrave; Nghệ thuật, c&ugrave;ng trưởng bộ m&ocirc;n Thiết kế Nội thất, Tiến sỹ, Kiến tr&uacute;c sư Trần Minh Đức.</p>\r\n<p style=\"text-align: justify;\">Sau buổi l&agrave;m việc, ph&iacute;a đối t&aacute;c cho biết, PYTHA rất sẵn l&ograve;ng gi&uacute;p đỡ v&agrave; hỗ trợ cho việc học của sinh vi&ecirc;n ng&agrave;nh Thiết kế Nội thất tại Trường Đại học Hoa Sen, đặc biệt l&agrave; cung cấp phần mềm&nbsp;PYTHA&nbsp;CAD miễn ph&iacute; cho ph&ograve;ng học m&aacute;y t&iacute;nh (gồm 50 m&aacute;y) v&agrave; sinh vi&ecirc;n được to&agrave;n quyền sử dụng phần mềm trong suốt 4 năm theo học tại trường.</p>\r\n<p style=\"text-align: justify;\">Ngo&agrave;i ra, Mr. Aaron Boo - Gi&aacute;m đốc&nbsp;PYTHA&nbsp;Ch&acirc;u &Aacute; cũng cho biết, &ocirc;ng sẽ nhận sinh vi&ecirc;n tham gia thực tập của Khoa Thiết kế v&agrave; Nghệ thuật l&agrave;m việc tại PYTHA&nbsp;CAD Singapore.</p>\r\n<p style=\"text-align: justify;\">Hai b&ecirc;n đ&atilde; thống nhất về việc k&yacute; kết MOU giữa Khoa Thiết kế v&agrave; Nghệ thuật, Trường Đại học Hoa Sen v&agrave; c&ocirc;ng ty PYTHA CAD trong năm 2018, đồng thời tiến h&agrave;nh c&agrave;i đặt phần mềm cho ph&ograve;ng m&aacute;y t&iacute;nh. B&ecirc;n cạnh đ&oacute;, sẽ c&oacute; những chuy&ecirc;n gia trong ng&agrave;nh trực tiếp đến training cho giảng vi&ecirc;n để giảng dạy về phương ph&aacute;p sử dụng cũng như c&aacute;ch sử dụng phần mềm để việc giảng dạy đạt được hiệu quả tối ưu nhất.</p>\r\n<p style=\"text-align: justify;\">Sau buổi l&agrave;m việc với Ban chủ nhiệm khoa Thiết kế v&agrave; Nghệ thuật, đại diện PYTHA CAD đ&atilde; c&oacute; buổi gặp gỡ sinh vi&ecirc;n v&agrave; tr&igrave;nh b&agrave;y về c&aacute;c t&iacute;nh năng ưu việt của phần mềm PYTHA CAD trong việc thiết kế nội thất.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><img src=\"/storage/uploads/tinymce/kMwvzT7s1gLLKMZdDlRuZgGZWwbRT798BqSyAOO1.jpeg\" alt=\"\" width=\"800\" height=\"444\" /></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><img src=\"/storage/uploads/tinymce/tg3AV7SPSNDp3j4VrVXUhopn1F6oUlHQKI9PxS4z.jpeg\" alt=\"\" width=\"800\" height=\"533\" /></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><strong>PYTHA</strong>&nbsp;l&agrave; phần mềm to&agrave;n diện cho thiết kế v&agrave; sản xuất nội thất, PYTHA được ph&aacute;t triển đến nay đ&atilde; hơn 35 năm tại Đức v&agrave; c&oacute; hơn 10.000 người sử dụng tr&ecirc;n to&agrave;n thế giới. PYTHA tạo ra m&ocirc;i trường thiết kế 3D ti&ecirc;n tiến v&agrave; th&acirc;n thuộc với người sử dụng, gi&uacute;p cho c&aacute;c nh&agrave; thiết kế c&oacute; thể tr&igrave;nh chiếu ngay thiết kế của m&igrave;nh bằng h&igrave;nh ảnh độ n&eacute;t cao hoặc bằng video, mặt kh&aacute;c c&oacute; thể tương t&aacute;c được với thiết kế của m&igrave;nh bằng c&ocirc;ng nghệ thực tế ảo. V&agrave; bạn thực sự bước v&agrave;o v&agrave; sống trong t&aacute;c phẩm của m&igrave;nh, c&oacute; thể tự do kiểm tra mọi g&oacute;c độ thiết kế, phối m&agrave;u sắc v&agrave; vật liệu, đ&oacute;ng mở cửa, l&ecirc;n xuống tầng lầu... V&agrave; hơn thế nữa PYTHA biến c&aacute;c thiết kế đ&oacute; th&agrave;nh c&aacute;c bản vẽ kỹ thuật, c&aacute;c danh s&aacute;ch chi tiết cấu tạo v&agrave; chương tr&igrave;nh điều khiển gia c&ocirc;ng CNC.&nbsp;</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><img src=\"/storage/uploads/tinymce/QQRelLTWeuCLsiSPkggaSogVVtaU1nOCRUkbtJJm.jpeg\" alt=\"\" width=\"800\" height=\"450\" /></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">PYTHA&nbsp;CAD l&agrave; phần mềm c&oacute; giao diện rất th&acirc;n thiện với người d&ugrave;ng giống như giao diện của Sketch up. Tuy nhi&ecirc;n ưu điểm của phần mềm rất nổi bật v&igrave; t&iacute;nh linh hoạt trong tạo h&igrave;nh, thiết kế, lighting, render, v&agrave; tối ưu h&oacute;a vật liệu sản xuất c&aacute;c th&agrave;nh phần nội thất bằng phương ph&aacute;p kỹ thuật số (digital manufacturing). Phần mềm t&iacute;ch hợp rất nhiều t&iacute;nh năng ưu việt dựng h&igrave;nh của Autocad, Rhino, Grasshopper, 3dMax, v&agrave; Revit, sẽ rất hữu &iacute;ch cho sinh vi&ecirc;n trong việc t&igrave;m &yacute; tưởng v&agrave; thử nghiệm c&aacute;c thiết kế mới dễ d&agrave;ng. Phần mềm PYTHA c&oacute; thể kết nối với c&aacute;c phần mềm m&agrave; sinh vi&ecirc;n Hoa Sen đang học như Autocad, Sketchup, 3D max, đặc biệt l&agrave; được d&ugrave;ng cho phần lớn m&aacute;y cắt CNC tạo m&ocirc; h&igrave;nh, hoặc sản phẩm thực tế.</p>\r\n<p style=\"text-align: justify;\">PYTHA&nbsp;CAD gọi phần mềm n&agrave;y l&agrave; \"one for all\", chỉ một cho tất cả.</p>','Công ty PYTHA tài trợ phần mềm cho sinh viên ngành Thiết kế Nội thất',NULL,'cong-ty-pytha-tai-tro-phan-mem-cho-sinh-vien-nganh-thiet-ke-noi-that','Chiều ngày 31/10/2018, đại diện công ty phần mềm thiết kế PYTHA đã có buổi làm việc với ban chủ nhiệm khoa Thiết kế và Nghệ thuật, Trường Đại học Hoa Sen.',NULL,'Published',2,NULL,1,16,'2021-06-09 03:13:56','2021-06-10 18:46:58',NULL),(49,'Webinar online với chủ đề “Giải pháp công nghệ nâng cao hiệu quả thiết kế và sản xuất nội thất gỗ”','2021-06-16 09:53:00','1623985333-webinar-online-voi-chu-de-giai-phap-cong-nghe-nang-cao-hieu-qua-thiet-ke-va-san-xuat-noi-that-go.jpg','Trang thông tin điện tử Nghenoithat.vn phối hợp với Hãng phần mềm Pytha Lab (Đức) tổ chức hội thảo trực tuyến với chủ đề “Giải pháp công nghệ nâng cao hiệu quả thiết kế và sản xuất nội thất gỗ”','<p style=\"text-align: justify;\">Bắt nhịp xu hướng ph&aacute;t triển theo thời kỳ chuyển đổi số, việc ứng dụng c&ocirc;ng nghệ đang trở th&agrave;nh c&acirc;u chuyện tất yếu trong mọi lĩnh vực, ng&agrave;nh nghề của x&atilde; hội v&agrave; ng&agrave;nh thiết kế - sản xuất đồ nội thất gỗ cũng kh&ocirc;ng phải l&agrave; ngoại lệ.</p>\r\n<p style=\"text-align: justify;\">Đối với ng&agrave;nh c&ocirc;ng nghiệp thiết kế - sản xuất h&agrave;ng nội thất gỗ, c&aacute;c phần mềm hỗ trợ lu&ocirc;n l&agrave; yếu tố quan trọng quyết định đến năng suất lao động, hiệu quả c&ocirc;ng việc của c&aacute;c doanh nghiệp tham gia. Để cho ra được một sản phẩm đồ nội thất gỗ, nh&agrave; sản xuất phải trải qua cả một qu&aacute; tr&igrave;nh d&agrave;i với nhiều c&ocirc;ng đoạn kh&aacute;c nhau từ l&ecirc;n &yacute; tưởng, dựng h&igrave;nh thiết kế cho đến b&oacute;c t&aacute;ch vật tư, triển khai sản xuất, kết nối m&aacute;y gia c&ocirc;ng tr&ecirc;n m&aacute;y. Điều n&agrave;y đặt ra th&aacute;ch thức lớn đối với mỗi doanh nghiệp sản xuất trong ng&agrave;nh bởi hầu hết c&aacute;c phần mềm tr&ecirc;n thị trường hiện nay chỉ hỗ trợ một hoặc một v&agrave;i c&ocirc;ng đoạn nhất định. Ch&iacute;nh v&igrave; thế để đ&aacute;p ứng qu&aacute; tr&igrave;nh sản xuất, c&aacute;c doanh nghiệp phải ứng dụng nhiều c&aacute;c giải ph&aacute;p, phần mềm kh&aacute;c nhau dẫn đến sự kh&ocirc;ng đồng nhất, rủi ro sai lệch khi sản phẩm được chuyển qua c&aacute;c giai đoạn. Điều n&agrave;y đặt ra b&agrave;i to&aacute;n về một phần mềm tối ưu hỗ trợ tối đa c&aacute;c doanh nghiệp trong to&agrave;n bộ c&aacute;c giai đoạn từ thiết kế, dựng h&igrave;nh, b&oacute;c t&aacute;ch vật tư, triển khai sản xuất cho tới gia c&ocirc;ng.</p>\r\n<p style=\"text-align: justify;\">Thấu hiểu được điều n&agrave;y, trang th&ocirc;ng tin tổng hợp Nghenoithat.vn phối hợp c&ugrave;ng H&atilde;ng phần mềm Pytha Lab (Đức) tổ chức hội thảo trực tuyến với chủ đề &ldquo;<em>Giải ph&aacute;p c&ocirc;ng nghệ n&acirc;ng cao hiệu quả thiết kế v&agrave; sản xuất nội thất gỗ</em>&rdquo;, trong đ&oacute; Hội thảo tập trung giới thiệu giải ph&aacute;p phần mềm mới, <strong>Pytha 3D CAD</strong> với nhiều t&iacute;nh năng, bộ c&ocirc;ng cụ ưu việt hỗ trợ doanh nghiệp sản xuất nội thất gỗ từ thiết kế cho tới sản xuất tại nh&agrave; m&aacute;y.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/j3IdAOcxvLgEaSFNc5hBgBNRBuUzxHAqhrLjWBTt.jpeg\" alt=\"\" width=\"750\" height=\"417\" /></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><em>Th&ocirc;ng tin chi tiết về buổi hội thảo trực tuyến như sau:</em></p>\r\n<ol style=\"text-align: justify;\">\r\n<li><strong> Nội dung ch&iacute;nh:</strong></li>\r\n</ol>\r\n<p style=\"text-align: justify;\"><strong><em>* Phần 1: Giới thiệu chung</em></strong></p>\r\n<p style=\"text-align: justify;\">- Giới thiệu về H&atilde;ng PYTHA Lab (CHLB Đức);</p>\r\n<p style=\"text-align: justify;\">- Giới thiệu th&agrave;nh phần tham dự;</p>\r\n<p style=\"text-align: justify;\"><strong><em>* Phần 2:</em></strong> <strong><em>Giới thiệu giải ph&aacute;p PYTHA 3D CAD</em></strong></p>\r\n<p style=\"text-align: justify;\">- Giới thiệu về <em>PYTHA 3D CAD</em> v&agrave; ứng dụng trong thiết kế v&agrave; sản xuất đồ nội thất gỗ;</p>\r\n<p style=\"text-align: justify;\">- Demo triển khai một số mẫu sản phẩm tr&ecirc;n <em>PYTHA 3D CAD<strong>;</strong></em></p>\r\n<ul>\r\n<li style=\"text-align: justify;\"><strong><em>Phần 3: Tham luận: </em></strong>Hỏi v&agrave; đ&aacute;p</li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<ol style=\"text-align: justify;\" start=\"2\">\r\n<li><strong> Thời gian:</strong></li>\r\n</ol>\r\n<p style=\"text-align: justify;\">Thời gian: <strong>từ 09 giờ đến 10 giờ 30 ph&uacute;t s&aacute;ng ng&agrave;y 29/06/2021</strong></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<ol style=\"text-align: justify;\" start=\"3\">\r\n<li>\r\n<p>Qu&yacute; độc giả c&oacute; thể đăng k&yacute; tham dự Hội thảo bằng c&aacute;ch qu&eacute;t m&atilde; QR tr&ecirc;n h&igrave;nh ảnh hoặc đăng k&yacute; tại đ&acirc;y:</p>\r\n<strong> <a href=\"https://docs.google.com/forms/d/e/1FAIpQLSfIZChguL79WdZxkE4UguGB5V27BKr_-TVecnBBsef94h_3gw/viewform\">Đăng k&yacute; tham dự</a></strong></li>\r\n</ol>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: justify;\"><strong>Pytha 3D CAD</strong> l&agrave; giải ph&aacute;p c&ocirc;ng nghệ gi&uacute;p c&aacute;c nh&agrave; thiết kế v&agrave; sản xuất đồ nội thất gỗ tối ưu to&agrave;n bộ quy tr&igrave;nh từ kh&acirc;u l&ecirc;n &yacute; tưởng, thiết kế tại văn ph&ograve;ng cho đến qu&aacute; tr&igrave;nh triển khai gia c&ocirc;ng v&agrave; sản xuất tại nh&agrave; m&aacute;y với nhiều t&iacute;nh năng, bộ c&ocirc;ng cụ vượt trội. Khả năng hỗ trợ thiết kế tối ưu gi&uacute;p <strong>Pytha 3D CAD</strong> thiết kế c&aacute;c mẫu sản phẩm mang t&iacute;nh thẩm mỹ cao với nhiều h&igrave;nh dạng, kiểu c&aacute;ch phức tạp m&agrave; hầu hết c&aacute;c phần mềm thiết kế - sản xuất kh&aacute;c tr&ecirc;n thị trường đều kh&ocirc;ng thể xử l&yacute;.</p>\r\n<p style=\"text-align: justify;\"><strong>Pytha 3D CAD</strong> cung cấp bộ c&ocirc;ng cụ gi&uacute;p người sử dụng tự động b&oacute;c t&aacute;ch, triển khai c&aacute;c mẫu thiết kế 3D sang sản xuất bằng c&aacute;c bản vẽ kỹ thuật, c&aacute;c danh s&aacute;ch chi tiết cấu tạo v&agrave; chương tr&igrave;nh điều khiển gia c&ocirc;ng CNC tr&ecirc;n c&aacute;c d&ograve;ng m&aacute;y hiện đại. B&ecirc;n cạnh giao diện th&acirc;n thiện như Sketchup, phần mềm t&iacute;ch hợp rất nhiều t&iacute;nh năng ưu việt dựng h&igrave;nh của Autocad, Rhino, Grasshopper, 3dMax, v&agrave; Revit. C&oacute; thể n&oacute;i, <strong>Pytha 3D CAD </strong>l&agrave; một giải ph&aacute;p \"one for all\", (tạm dịch: <em>chỉ một cho tất cả)</em>.</p>',NULL,NULL,'webinar-online-voi-chu-de-giai-phap-cong-nghe-nang-cao-hieu-qua-thiet-ke-va-san-xuat-noi-that-go','Trang thông tin điện tử Nghenoithat.vn phối hợp với Hãng phần mềm Pytha Lab (Đức) tổ chức hội thảo trực tuyến với chủ đề “Giải pháp công nghệ nâng cao hiệu quả thiết kế và sản xuất nội thất gỗ”','thiết kế nội thất, nội thất, nội thất gỗ, công nghệ gỗ, phần mềm gỗ','Published',2,NULL,1,16,'2021-06-17 20:02:13','2021-06-17 20:02:13',NULL),(50,'Hội thảo Online giới thiệu phần mềm Pytha – “Giải pháp công nghệ nâng cao hiệu quả thiết kế và sản xuất nội thất gỗ”','2021-07-07 16:07:00','1625649296-hoi-thao-online-gioi-thieu-phan-mem-pytha-giai-phap-cong-nghe-nang-cao-hieu-qua-thiet-ke-va-san-xuat-noi-that-go.jpeg','Ngày 29/6 vừa qua, Trang thông tin tổng hợp Nghenoithat.vn phối hợp với Hãng phần mềm Pytha Lab (Đức) tổ chức thành công buổi hội thảo trực tuyến giới thiệu những tính năng, ưu điểm vượt trội của giải pháp phần mềm Pytha 3D CAD.','<p style=\"text-align: justify;\">Chương tr&igrave;nh hội thảo ch&agrave;o đ&oacute;n sự tham gia của gần 20 đơn vị l&agrave; c&aacute;c c&aacute; nh&acirc;n, đại diện cho c&aacute;c đơn vị thiết kế v&agrave; sản xuất đồ nội thất tr&ecirc;n to&agrave;n Việt Nam. Mở đầu buổi hội thảo, Pytha Lab đ&atilde; giới thiệu tổng quan về qu&aacute; tr&igrave;nh h&igrave;nh th&agrave;nh v&agrave; ph&aacute;t triển của H&atilde;ng cũng như cung cấp c&aacute;i nh&igrave;n tổng quan nhất về giải ph&aacute;p phần mềm Pytha 3D CAD.</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/WLdf3jTtZMU3vQDEiub89S9U4FiS7C4JwtqzAkWC.jpeg\" alt=\"\" width=\"750\" height=\"422\" /></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Với lịch sử 35 năm ph&aacute;t triển c&ugrave;ng số người sử dụng tr&ecirc;n to&agrave;n thế giới l&ecirc;n tới 10,000 kh&aacute;ch h&agrave;ng, Pytha 3D CAD hứa hẹn sẽ l&agrave; một giải ph&aacute;p tối ưu, giải quyết những vấn đề kh&oacute; khăn trong việc dựng, gia c&ocirc;ng v&agrave; sản xuất tại nh&agrave; m&aacute;y với nhiều t&iacute;nh năng, bộ c&ocirc;ng cụ vượt trội.</p>\r\n<p style=\"text-align: justify;\">Sau phần giới thiệu tổng quan, chuy&ecirc;n gia H&atilde;ng phần mềm Pytha đ&atilde; c&oacute; phần demo trực tiếp thể hiện một số c&aacute;c t&iacute;nh năng vượt trội của phần mềm Pytha 3D CAD, trong đ&oacute; tập trung v&agrave;o triển khai, dựng h&igrave;nh c&aacute;c mẫu sản phẩm như b&agrave;n kệ, quầy lễ t&acirc;n,&hellip;c&oacute; kết cấu đa dạng, h&igrave;nh th&ugrave; phức tạp.</p>\r\n<p style=\"text-align: justify;\">Cuối chương tr&igrave;nh hội thảo, chuy&ecirc;n gia H&atilde;ng phần mềm đ&atilde; giải đ&aacute;p hầu hết c&aacute;c thắc mắc của c&aacute;c anh chị tham gia hội thảo về giải ph&aacute;p Pytha 3D CAD.&nbsp;</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/IFsQ9KraJzMrb5JLpBWS4tCwsuV8DMmmiM3O0df6.jpeg\" alt=\"\" width=\"750\" height=\"408\" /></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Một số ưu điểm vượt trội của Pytha c&oacute; thể kể đến như:<br />- &nbsp;C&ocirc;ng cụ tạo h&igrave;nh mạnh mẽ, đa dạng về c&aacute;ch thức, linh hoạt trong t&ugrave;y biến a k&iacute;ch thước, tương quan vị tr&iacute; của c&aacute;c chi tiết trong đối tượng 3D<br />- Thực hiện việc tối ưu xếp v&aacute;n kh&ocirc;ng cần th&ecirc;m phần mềm hỗ trợ&nbsp;<br />- Th&iacute;ch hợp cho bộ phận d&aacute;n tem nh&atilde;n tự động của m&aacute;y CNC trung t&acirc;m<br />- T&iacute;nh năng Radio Lab mạnh mẽ, ch&acirc;n thực</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><strong>Trang tin tức Nghề nội thất</strong></p>\r\n<p style=\"text-align: justify;\">Hotline: 0868934576</p>\r\n<p style=\"text-align: justify;\">Website: nghenoithat.vn</p>\r\n<p>&nbsp;</p>',NULL,'Hội thảo Online giới thiệu phần mềm Pytha – “Giải pháp công nghệ nâng cao hiệu quả thiết kế và sản xuất nội thất gỗ”','hoi-thao-online-gioi-thieu-phan-mem-pytha-giai-phap-cong-nghe-nang-cao-hieu-qua-thiet-ke-va-san-xuat-noi-that-go','Ngày 29/6 vừa qua, Trang thông tin tổng hợp Nghenoithat.vn phối hợp với Hãng phần mềm Pytha Lab (Đức) tổ chức thành công buổi hội thảo trực tuyến giới thiệu những tính năng, ưu điểm vượt trội của giải pháp phần mềm Pytha 3D CAD.',NULL,'Published',2,NULL,0,15,'2021-07-07 02:14:56','2021-07-07 02:14:56',NULL),(51,'Nghenoithat.vn tổ chức Hội thảo trực tuyến với chủ đề “Giải pháp công nghệ mới cho nhà thầu nhôm kính”','2021-07-19 14:24:00','1626679453-nghenoithatvn-to-chuc-hoi-thao-truc-tuyen-voi-chu-de-giai-phap-cong-nghe-moi-cho-nha-thau-nhom-kinh.jpg','Vào 09h00, ngày 27/07/2021, Trang thông tin điện tử Nghenoithat.vn phối hợp với Hãng phần mềm Opera (Ý) tổ chức hội thảo trực tuyến với chủ đề “Giải pháp công nghệ mới cho nhà thầu nhôm kính”','<p style=\"text-align: justify;\">Để bắt nhịp xu hướng ph&aacute;t triển trong thời kỳ chuyển đổi số, việc ứng dụng c&ocirc;ng nghệ đang trở th&agrave;nh c&acirc;u chuyện cấp thiết đối với từng ngh&agrave;nh nghề v&agrave; mỗi doanh nghiệp.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Thấu hiểu được điều n&agrave;y, trang th&ocirc;ng tin tổng hợp Nghenoithat.vn phối hợp c&ugrave;ng H&atilde;ng phần mềm Opera (&Yacute;) tổ chức hội thảo trực tuyến với chủ đề &ldquo;<em>Giải ph&aacute;p c&ocirc;ng nghệ mới cho nh&agrave; thầu nh&ocirc;m k&iacute;nh</em>&rdquo;, trong đ&oacute; Hội thảo tập trung giới thiệu giải ph&aacute;p phần mềm mới, <strong>Opera Job Management version 3.8</strong> với nhiều t&iacute;nh năng, bộ c&ocirc;ng cụ ưu việt hỗ trợ doanh nghiệp thầu nh&ocirc;m k&iacute;nh thiết kế, b&oacute;c t&aacute;ch vật tư, triển khai một c&aacute;ch sản xuất, ch&iacute;nh x&aacute;c.</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/ZopcUnhixGPHr0h7Uw7KdiQIHaJu7ZD8Ly5q5zZL.jpeg\" alt=\"\" width=\"600\" height=\"333\" /></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Được ph&aacute;t triển từ những năm 1990<strong>, Opera Job Management </strong>đ&atilde; được n&acirc;ng cấp nhiều lần trong suốt hơn 30 năm qua với nhiều phi&ecirc;n bản kh&aacute;c nhau. Hiện tại phi&ecirc;n bản mới nhất của <strong>Opera</strong> l&agrave; phi&ecirc;n bản 3.8 với nhiều ưu điểm vượt trội.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Với giao diện thao t&aacute;c th&acirc;n thiện, đơn giản, dễ nhớ, người d&ugrave;ng Opera c&oacute; thể nhanh ch&oacute;ng l&agrave;m chủ to&agrave;n bộ t&iacute;nh năng, bộ c&ocirc;ng cụ dựng h&igrave;nh, thiết kế của phần mềm. C&aacute;c mẫu cửa sổ, cửa đi v&agrave; hệ mặt dựng phức tạp c&oacute; thể được xử l&yacute; chỉ trong nh&aacute;y mắt. Từ đ&oacute;, c&aacute;c b&aacute;o c&aacute;o vật tư, dự to&aacute;n cho c&ocirc;ng tr&igrave;nh của bạn cũng c&oacute; thể được tạo một c&aacute;ch đơn giản v&agrave; ch&iacute;nh x&aacute;c. Kh&ocirc;ng đơn thuần l&agrave; phần mềm dựng h&igrave;nh v&agrave; b&oacute;c t&aacute;ch vật tư, Opera c&ograve;n hỗ trợ kết nối với nhiều d&ograve;ng m&aacute;y CNC phục vụ gia c&ocirc;ng, sản xuất.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Một trong những điểm nổi bật của phần mềm <strong>Opera</strong> l&agrave; t&iacute;nh năng quản l&yacute; kho. <strong>Opera</strong> cho ph&eacute;p người d&ugrave;ng lưu trữ v&agrave; quản l&yacute; kho nguy&ecirc;n liệu, vật tư thừa từ c&aacute;c dự &aacute;n trước đ&oacute; để c&oacute; thể tận dụng lại ở c&aacute;c dự &aacute;n sau, qua đ&oacute; gi&uacute;p tiết kiệm nguy&ecirc;n vật liệu, giảm chi ph&iacute;m sản xuất của doanh nghiệp.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">B&ecirc;n cạnh đ&oacute;, <strong>Opera</strong> hỗ trợ người d&ugrave;ng tự kiểm so&aacute;t, chủ động kho dữ liệu về hệ nh&ocirc;m của phần mềm. Cụ thể, người d&ugrave;ng ho&agrave;n to&agrave;n chủ động đưa v&agrave;o c&aacute;c hệ nh&ocirc;m, định dạng profile mới v&agrave;o trong database th&ocirc;ng qua c&aacute;c thao t&aacute;c hết sức kh&ocirc;ng qu&aacute; phức tạp. Điều n&agrave;y gi&uacute;p doanh nghiệp sử dụng giảm sự phụ thuộc v&agrave;o nh&agrave; cung cấp phần mềm.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Tr&ecirc;n đ&acirc;y chỉ l&agrave; một trong nhiều c&aacute;c điểm ưu việt, t&iacute;nh năng vượt trội của giải ph&aacute;p mới, <strong>Opera Job Management version 3.8. </strong>K&iacute;nh mời Qu&yacute; doanh nghiệp, Qu&yacute; độc giả tham dự hội thảo online sắp tới để t&igrave;m hiểu, nắm r&otilde; hơn về giải ph&aacute;p n&agrave;y.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><em>Th&ocirc;ng tin chi tiết về buổi hội thảo trực tuyến như sau:</em></p>\r\n<ol style=\"text-align: justify;\">\r\n<li><strong> Nội dung ch&iacute;nh:</strong></li>\r\n</ol>\r\n<p style=\"text-align: justify;\"><strong><em>* Phần 1: Giới thiệu chung</em></strong></p>\r\n<p style=\"text-align: justify;\">- Giới thiệu về H&atilde;ng OPERA (&Yacute;);</p>\r\n<p style=\"text-align: justify;\">- Giới thiệu th&agrave;nh phần tham dự;</p>\r\n<p style=\"text-align: justify;\"><strong><em>* Phần 2:</em></strong> <strong><em>Giới thiệu giải ph&aacute;p OPERA</em></strong></p>\r\n<p style=\"text-align: justify;\">- Giới thiệu về điểm nổi bật của <em>OPERA</em>;</p>\r\n<p style=\"text-align: justify;\">- Demo triển khai một số mẫu sản phẩm tr&ecirc;n <em>OPERA<strong>;</strong></em></p>\r\n<p style=\"text-align: justify;\"><strong><em>* Phần 3: Tham luận: </em></strong>Hỏi v&agrave; đ&aacute;p</p>\r\n<ol style=\"text-align: justify;\" start=\"2\">\r\n<li><strong> Thời gian: </strong>09 giờ đến 10 giờ 30 ph&uacute;t s&aacute;ng ng&agrave;y 27/07/2021</li>\r\n</ol>\r\n<ol style=\"text-align: justify;\" start=\"3\">\r\n<li><strong> Đăng k&yacute; tham gia: </strong>Qu&yacute; độc giả c&oacute; thể đăng k&yacute; tham dự Hội thảo bằng c&aacute;ch qu&eacute;t m&atilde; QR tr&ecirc;n h&igrave;nh ảnh hoặc đăng k&yacute;: <a href=\"https://docs.google.com/forms/d/e/1FAIpQLSdgkbJm2mDhjbZqGjrvMAcO40vashbH4QsBYqVTYJs6PD4XPw/viewform\">Tại đ&acirc;y</a></li>\r\n</ol>',NULL,NULL,'nghenoithatvn-to-chuc-hoi-thao-truc-tuyen-voi-chu-de-giai-phap-cong-nghe-moi-cho-nha-thau-nhom-kinh','Trang thông tin điện tử Nghenoithat.vn phối hợp với Hãng phần mềm Opera (Ý) tổ chức hội thảo trực tuyến với chủ đề “Giải pháp công nghệ mới cho nhà thầu nhôm kính”',NULL,'Published',2,NULL,1,17,'2021-07-19 00:24:13','2021-07-22 00:16:04',NULL),(52,'AA CORPORATION HỖ TRỢ 5,000 BỘ TRANG PHỤC PHÒNG CHỐNG DỊCH ĐẾN QUỸ PHÒNG, CHỐNG DỊCH COVID -19 TẠI TỈNH TÂY NINH','2021-07-21 14:56:00','1626854341-aa-corporation-ho-tro-5000-bo-trang-phuc-phong-chong-dich-den-quy-phong-chong-dich-covid-19-tai-tinh-tay-ninh.jpg','Ngày 5/6 vừa qua, Công ty AA đã hỗ trợ 5,000 bộ trang phục phòng chống dịch (tương đương 500,000,000 đồng) để đóng góp vào Quỹ phòng, chống dịch Covid – 19 tỉnh Tây Ninh.','<p style=\"text-align: justify;\">Trong thời gian vừa qua, t&igrave;nh h&igrave;nh dịch bệnh Covid-19 tiếp tục c&oacute; những diễn biến phức tạp tr&ecirc;n khắp c&aacute;c tỉnh th&agrave;nh Việt Nam. Đặc biệt c&aacute;c v&ugrave;ng l&acirc;n cận, nhất l&agrave; TP.HCM. Mặt kh&aacute;c c&aacute;c ca dương t&iacute;nh kh&ocirc;ng ngừng gia tăng từ người Việt tại Campuchia nhập cảnh về. Đứng trước nguy cơ b&ugrave;ng dịch cao trong cộng đồng, c&aacute;c cấp ch&iacute;nh quyền tỉnh T&acirc;y Ninh c&ugrave;ng Sở y tế Tỉnh đang nỗ lực để thực hiện tốt c&aacute;c biện ph&aacute;p ph&ograve;ng, chống dịch nhằm g&oacute;p phần kiểm so&aacute;t, kh&ocirc;ng để dịch bệnh l&acirc;y lan, bảo đảm ph&aacute;t triển kinh tế, giữ vững an ninh ch&iacute;nh trị, trật tự an to&agrave;n x&atilde; hội.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Đ&oacute;ng vai tr&ograve; l&agrave; một trong những Doanh nghiệp ti&ecirc;u biểu trong ng&agrave;nh nội thất tại Việt Nam. Đầu tư nh&agrave; m&aacute;y 50ha, c&ugrave;ng đội ngũ c&aacute;n bộ C&ocirc;ng nh&acirc;n vi&ecirc;n hơn 2000 người đang l&agrave;m việc tại tỉnh T&acirc;y Ninh, C&ocirc;ng ty AA đ&atilde; cấp b&aacute;ch thực hiện C&ocirc;ng Văn xin ph&eacute;p được đ&oacute;ng g&oacute;p 500,000,000 đồng để hỗ trợ Quỹ Ph&ograve;ng, Chống Dịch Covid-19 tại tỉnh T&acirc;y Ninh. Theo C&ocirc;ng Văn , &ocirc;ng Nguyễn Quốc Khanh &ndash; Chủ tịch HĐQT C&ocirc;ng ty AA khẳng định việc Doanh nghiệp chung tay ph&ograve;ng chống dịch c&ugrave;ng c&aacute;c c&aacute;c đơn vị cơ quan Th&agrave;nh phố &amp; địa phương l&agrave; hết sức cấp thiết hiện nay.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/EkjbpG5SZkEfWEb5FVu1w1xtvCgHULjJetMr0wXK.jpeg\" alt=\"noi-that-aa\" width=\"900\" height=\"505\" /></p>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: justify;\">Tiếp nhận C&ocirc;ng Văn từ C&ocirc;ng ty AA, UBND tỉnh T&acirc;y Ninh &ndash; Ban Chỉ Đạo Ph&ograve;ng Chống Dịch Covid &ndash; 19 đ&atilde; thể hiện sự tr&acirc;n trọng v&agrave; cần thiết đối với 5,000 Bộ trang phục ph&ograve;ng chống dịch (loại cấp độ 2), để T&acirc;y Ninh ho&agrave;n th&agrave;nh tốt nhiệm vụ ph&ograve;ng, chống dịch Covid &ndash; 19.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">C&ocirc;ng ty AA đ&atilde; thực hiện ngay việc hỗ trợ từ những th&ocirc;ng tin đề xuất của Ban Chỉ Đạo Ph&ograve;ng Chống Dịch Covid &ndash; 19 &ndash; UBND tỉnh T&acirc;y Ninh. Song song, C&ocirc;ng ty AA đ&atilde; v&agrave; sẽ phối hợp, tu&acirc;n thủ chặt chẽ c&aacute;c quy định về ph&ograve;ng chống dịch theo quy định của Nh&agrave; nước v&agrave; sẵn s&agrave;ng hỗ trợ, n&acirc;ng cao nhận thức của người d&acirc;n tại c&aacute;c nh&agrave; m&aacute;y, c&aacute;c khu c&ocirc;ng nghiệp trong c&ocirc;ng t&aacute;c tuy&ecirc;n truyền, quảng b&aacute;, đ&oacute;ng g&oacute;p, v&agrave; chung tay ph&ograve;ng, chống dịch Covid- 19 c&ugrave;ng địa phương.</p>','AA CORPORATION HỖ TRỢ 5,000 BỘ TRANG PHỤC PHÒNG CHỐNG DỊCH ĐẾN QUỸ PHÒNG, CHỐNG DỊCH COVID -19 TẠI TỈNH TÂY NINH',NULL,'aa-corporation-ho-tro-5000-bo-trang-phuc-phong-chong-dich-den-quy-phong-chong-dich-covid-19-tai-tinh-tay-ninh','Ngày 5/6 vừa qua, Công ty AA đã hỗ trợ 5,000 bộ trang phục phòng chống dịch (tương đương 500,000,000 đồng) để đóng góp vào Quỹ phòng, chống dịch Covid – 19 tỉnh Tây Ninh.','thiết kế nội thất, nội thất, nội thất gỗ, công nghệ gỗ, phần mềm gỗ','Published',2,NULL,1,17,'2021-07-21 00:59:01','2021-07-22 00:15:27',NULL),(53,'Opera webinar: “Giải pháp công nghệ cho các nhà thầu nhôm kính”','2021-07-28 17:41:00','1627641919-opera-webinar-giai-phap-cong-nghe-cho-cac-nha-thau-nhom-kinh.jpg','Ngày 27/7 vừa qua, Nghenoithat.vn phối hợp với Hãng phần mềm Opera đã tổ chức thành công buổi hội thảo trực tuyến để giới thiệu về những tính năng, ưu điểm vượt trội của phần mềm Opera – giải pháp hiệu quả cho nhà thầu nhôm kính.','<p style=\"text-align: justify;\">Mở đầu buổi hội thảo, đại diện website Nghenoithat đ&atilde; giới thiệu một v&agrave;i n&eacute;t ch&iacute;nh về h&atilde;ng phần mềm Opera cũng như những t&iacute;nh năng ch&iacute;nh của phần mềm Opera.</p>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/Ul6YtBb4OR7OWSsrUilbmc3ni132Uy08M9yAzU40.png\" alt=\"\" width=\"700\" height=\"400\" /></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Opera c&oacute; trụ sở tại Sardinia,&Yacute; với hơn 30 năm kinh nghiệm trong lĩnh vực ph&aacute;t triển c&aacute;c giải ph&aacute;p phần mềm trong lĩnh vực thầu nh&ocirc;m k&iacute;nh. Hiện Opera đ&atilde; c&oacute; hơn 5000 kh&aacute;ch h&agrave;ng, trải khắp tr&ecirc;n 70 quốc gia tr&ecirc;n to&agrave;n thế giới.</p>\r\n<p style=\"text-align: justify;\">Với giao diện thao t&aacute;c th&acirc;n thiện, đơn giản, dễ nhớ, Opera cho ph&eacute;p người d&ugrave;ng c&oacute; thể nhanh ch&oacute;ng l&agrave;m chủ to&agrave;n bộ t&iacute;nh năng, bộ c&ocirc;ng cụ dựng h&igrave;nh, thiết kế của phần mềm. C&aacute;c mẫu cửa sổ, cửa đi v&agrave; hệ mặt dựng phức tạp c&oacute; thể được xử l&yacute; chỉ trong nh&aacute;y mắt. Từ đ&oacute;, c&aacute;c b&aacute;o c&aacute;o vật tư, dự to&aacute;n cho c&ocirc;ng tr&igrave;nh của bạn cũng c&oacute; thể được tạo một c&aacute;ch đơn giản v&agrave; ch&iacute;nh x&aacute;c. Kh&ocirc;ng đơn thuần l&agrave; phần mềm dựng h&igrave;nh v&agrave; b&oacute;c t&aacute;ch vật tư, Opera c&ograve;n hỗ trợ kết nối với nhiều d&ograve;ng m&aacute;y CNC phục vụ gia c&ocirc;ng, sản xuất.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/T6fgvbB6MBQwOxCzOGe4ydJmJErI6ugaROkbp2EH.jpeg\" alt=\"\" width=\"700\" height=\"380\" /></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Một trong những điểm nổi bật của phần mềm Opera l&agrave; t&iacute;nh năng quản l&yacute; kho. Opera cho ph&eacute;p người d&ugrave;ng lưu trữ v&agrave; quản l&yacute; kho nguy&ecirc;n liệu, vật tư thừa từ c&aacute;c dự &aacute;n trước đ&oacute; để c&oacute; thể tận dụng lại ở c&aacute;c dự &aacute;n sau, qua đ&oacute; gi&uacute;p tiết kiệm nguy&ecirc;n vật liệu, giảm chi ph&iacute;m sản xuất của doanh nghiệp.</p>\r\n<p style=\"text-align: justify;\">B&ecirc;n cạnh đ&oacute;, Opera hỗ trợ người d&ugrave;ng tự kiểm so&aacute;t, chủ động kho dữ liệu về hệ nh&ocirc;m của phần mềm. Cụ thể, người d&ugrave;ng ho&agrave;n to&agrave;n chủ động đưa v&agrave;o c&aacute;c hệ nh&ocirc;m, định dạng profile mới v&agrave;o trong database th&ocirc;ng qua c&aacute;c thao t&aacute;c hết sức kh&ocirc;ng qu&aacute; phức tạp. Điều n&agrave;y gi&uacute;p doanh nghiệp sử dụng giảm sự phụ thuộc v&agrave;o nh&agrave; cung cấp phần mềm.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/Q44b41PLFJ70iAkGhQozHzYgr4qZJPyFicwlZdgu.jpeg\" alt=\"\" width=\"700\" height=\"380\" /></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Với sự tham dự của hơn 40 vị kh&aacute;ch mời từ c&aacute;c c&ocirc;ng ty trong ng&agrave;nh từ Bắc v&agrave;o Nam, buổi hội thảo đ&atilde; diễn ra th&agrave;nh c&ocirc;ng tốt đẹp v&agrave; nhận được nhiều thắc mắc cũng như c&aacute;c phản hồi t&iacute;ch cực của những b&ecirc;n tham dự.</p>\r\n<p style=\"text-align: justify;\"><strong>&nbsp;</strong></p>\r\n<p style=\"text-align: justify;\">Mọi th&ocirc;ng tin chi tiết xin li&ecirc;n hệ:&nbsp;</p>\r\n<p style=\"text-align: justify;\"><strong>Trang tin tức Nghề nội thất</strong></p>\r\n<p style=\"text-align: justify;\">Hotline: 0868934576</p>\r\n<p style=\"text-align: justify;\">Website: nghenoithat.vn</p>','Opera webinar: “Giải pháp công nghệ cho các nhà thầu nhôm kính”',NULL,'opera-webinar-giai-phap-cong-nghe-cho-cac-nha-thau-nhom-kinh','Ngày 27/7 vừa qua, Nghenoithat.vn phối hợp với Hãng phần mềm Opera đã tổ chức thành công buổi hội thảo trực tuyến để giới thiệu về những tính năng, ưu điểm vượt trội của phần mềm Opera – giải pháp hiệu quả cho nhà thầu nhôm kính.',NULL,'Published',2,NULL,1,17,'2021-07-30 03:45:19','2021-07-30 03:45:19',NULL),(54,'Pytha 3D-CAD Version 25: Sự linh hoạt đạt đến mức hoàn hảo','2021-08-25 17:24:00','1629887299-pytha-3d-cad-version-25-su-linh-hoat-dat-den-muc-hoan-hao.jpg','Từ giai đoạn lên ý tưởng đến những bước hoàn thành, Pytha 3D CAD là một trong những hệ thống CAD 3D hàng đầu cho ngành công nghiệp chế biến gỗ, thiết kế đồ nội thất, đồ gỗ thương mại, nhà bếp cao cấp, trưng bày triển lãm và các lĩnh vực khác liên quan đến thiết kế nội thất.','<p style=\"text-align: justify;\">Với Version 25 mạnh mẽ, c&aacute;c nh&agrave; ph&aacute;t triển người Đức của Pytha Lab đ&atilde; tạo ra những ti&ecirc;u chuẩn cao hơn trong thế giới CAD. Một điểm nhấn đặc biệt ở V25 l&agrave; c&ocirc;ng cụ kết xuất mới, được t&iacute;ch hợp liền mạch, cho ph&eacute;p kết xuất cao cấp trực tiếp trong Pytha modeller. Chỉ trong v&ograve;ng v&agrave;i gi&acirc;y, người d&ugrave;ng giờ đ&acirc;y c&oacute; thể xem h&igrave;nh ảnh ch&acirc;n thực m&agrave; kh&ocirc;ng cần chuyển đổi hay sử dụng c&aacute;c phần mềm kh&aacute;c. Sau đ&oacute;, người d&ugrave;ng c&oacute; thể tiếp tục l&agrave;m việc một c&aacute;ch dễ d&agrave;ng với những kh&ocirc;ng gian đ&atilde; được tạo.</p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/dutar8nW0XX2vrWmzvJjPMcn86PMvKtUbt1nH2wX.jpeg\" alt=\"\" width=\"750\" height=\"422\" /></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Do đ&oacute;, Pytha cho ph&eacute;p mọi người d&ugrave;ng đạt được kết quả gần như ho&agrave;n hảo chỉ với những thao t&aacute;c cơ bản. Người d&ugrave;ng kh&ocirc;ng cần phải l&agrave; những chuy&ecirc;n gia cho việc dựng h&igrave;nh hay điều chỉnh chiếu s&aacute;ng, Pytha c&oacute; thể tự động điều chỉnh để tạo ra những bức h&igrave;nh một c&aacute;ch dễ d&agrave;ng v&agrave; đơn giản.</p>\r\n<p style=\"text-align: justify;\">Pytha c&oacute; bộ c&agrave;i đặt độ s&aacute;ng th&ocirc;ng minh cho ph&eacute;p tạo ra c&aacute;c ph&eacute;p t&iacute;nh h&igrave;nh ảnh tuyệt đẹp, d&ugrave; l&agrave; ban ng&agrave;y hay ban đ&ecirc;m. Do đ&oacute;, những h&igrave;nh ảnh to&agrave;n cảnh HDR m&agrave; Pytha tạo ra c&oacute; &aacute;nh s&aacute;ng tự nhi&ecirc;n v&agrave; ch&acirc;n thực. Bộ đ&egrave;n của c&ocirc;ng cụ n&agrave;y được điều chỉnh dễ d&agrave;ng v&agrave; ch&iacute;nh x&aacute;c với c&aacute;c gi&aacute; trị &aacute;nh s&aacute;ng t&iacute;nh bằng lumen (độ s&aacute;ng) v&agrave; Kelvin (nhiệt độ m&agrave;u). Hơn nữa, người d&ugrave;ng ho&agrave;n to&agrave;n c&oacute; thể lưu những điều chỉnh đ&egrave;n th&agrave;nh một bộ thư viện ri&ecirc;ng để tiết kiệm thời gian cho việc chỉnh sửa.</p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/yHPHbWZUlliB3aPNETAUljk2iNtIY0ldld43TAw1.jpeg\" alt=\"\" width=\"750\" height=\"422\" /></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Giờ đ&acirc;y, c&ocirc;ng cụ kết xuất của Pytha đ&atilde; được trang bị &aacute;nh s&aacute;ng gi&aacute;n tiếp ch&acirc;n thực, mang lại cho người d&ugrave;ng ấn tượng m&agrave;u sắc thực. Hơn nữa, c&aacute;c vật liệu được cải tiến mang l&agrave;m cho khung h&igrave;nh trở n&ecirc;n sống động.</p>\r\n<p style=\"text-align: justify;\">Kh&ocirc;ng chỉ vậy, c&aacute;c nh&agrave; ph&aacute;t triển Pytha cũng đ&atilde; cải thiện tốc độ t&iacute;nh to&aacute;n của việc tạo ra c&aacute;c khung h&igrave;nh. Bộ lọc tiếng ồn th&ocirc;ng minh c&oacute; t&ecirc;n l&agrave; &ldquo;bộ giảm &acirc;m&rdquo; đ&atilde; gi&uacute;p tạo ra h&igrave;nh ảnh ho&agrave;n chỉnh với chất lượng cao nhất trong v&ograve;ng v&agrave;i gi&acirc;y. Điều n&agrave;y cho ph&eacute;p bất kỳ người d&ugrave;ng n&agrave;o kết xuất c&aacute;c dự &aacute;n với chất lượng ảnh ch&acirc;n thực v&agrave; tạo ra c&aacute;c bản tr&igrave;nh b&agrave;y mang đầy t&iacute;nh thuyết phục.</p>\r\n<p style=\"text-align: justify;\">Ngo&agrave;i ra, vẫn c&ograve;n nhiều t&iacute;nh năng mới kh&aacute;c c&oacute; trong Pytha Version 25 chờ mọi người c&ugrave;ng kh&aacute;m ph&aacute;.&nbsp;</p>\r\n<p style=\"text-align: justify;\">Th&ocirc;ng tin chi tiết về phần mềm Pytha V24 <a href=\"/san-pham/phan-mem-noi-that-go-pytha\">tại đ&acirc;y.&nbsp;</a></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<div id=\"gtx-trans\" style=\"position: absolute; left: 297px; top: 1572px;\">\r\n<div class=\"gtx-trans-icon\">&nbsp;</div>\r\n</div>','Pytha 3D-CAD Version 25: Sự linh hoạt đạt đến mức hoàn hảo',NULL,'pytha-3d-cad-version-25-su-linh-hoat-dat-den-muc-hoan-hao','Từ giai đoạn lên ý tưởng đến những bước hoàn thành, Pytha 3D CAD là một trong những hệ thống CAD 3D hàng đầu cho ngành công nghiệp chế biến gỗ, thiết kế đồ nội thất, đồ gỗ thương mại, nhà bếp cao cấp, trưng bày triển lãm và các lĩnh vực khác liên quan đến thiết kế nội thất.','thiết kế nội thất, nội thất, nội thất gỗ, công nghệ gỗ, phần mềm gỗ, pytha','Published',2,NULL,1,20,'2021-08-25 03:28:19','2021-08-25 08:57:16',NULL),(55,'Homestyler – Thiết kế 3D những ngôi nhà trong mơ','2021-09-27 11:02:00','1632715987-homestyler-thiet-ke-3d-nhung-ngoi-nha-trong-mo.jpg','Homestyler là giải pháp cung cấp công cụ thiết kế nội thất 3D hiệu quả cho các nhà thiết kế và cung cấp các giải pháp chuyển đổi kỹ thuật số cho ngành nội thất và bất động sản.','<h2 style=\"text-align: justify;\"><strong>Giới thiệu chung về HomeStyler:</strong></h2>\r\n<p style=\"text-align: justify;\">- C&ocirc;ng cụ vẽ mặt bằng 2D/3D dễ d&agrave;ng sử dụng:</p>\r\n<p style=\"text-align: justify;\">+ Chỉ với c&aacute;c thao t&aacute;c k&eacute;o thả trực quan v&agrave; giao diện th&acirc;n thiện với người sử dụng, rất dễ d&agrave;ng để vẽ c&aacute;c mặt bằng 2D/3D.</p>\r\n<p style=\"text-align: justify;\">+ C&aacute;c c&ocirc;ng dụ trực quan v&agrave; t&iacute;ch hợp c&aacute;c t&iacute;nh năng mạnh mẽ khiến n&oacute; trở th&agrave;nh một c&ocirc;ng cụ tối ưu d&agrave;nh cho c&aacute;c nh&agrave; thiết kế nội thất.</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/hfsG8WzhyDjJHQu5QzoqIoJXgLx9QKRGeC6pIl9f.png\" alt=\"\" width=\"750\" height=\"425\" /></p>\r\n<p style=\"text-align: justify;\">- Tối ưu h&oacute;a thời gian thiết kế:</p>\r\n<p style=\"text-align: justify;\">+ Bộ thư viện với h&agrave;ng ngh&igrave;n sản phẩm nội thất, đồ trang tr&iacute;, v&aacute;n s&agrave;n của c&aacute;c nh&atilde;n hiệu để trang tr&iacute; kh&ocirc;ng gian nội thất một c&aacute;ch ch&acirc;n thực</p>\r\n<p style=\"text-align: justify;\">+ Nhiều mẫu kh&ocirc;ng gian để lựa chọn</p>\r\n<p style=\"text-align: justify;\">- Render nhanh ch&oacute;ng dựa tr&ecirc;n c&ocirc;ng nghệ điện to&aacute;n đ&aacute;m m&acirc;y</p>\r\n<p style=\"text-align: justify;\">+ H&igrave;nh ảnh render đẹp mắt với chất lượng ảnh SD, HD, Full HD, 2K, 4K</p>\r\n<p style=\"text-align: justify;\">+ Thời gian render ảnh ấn tượng</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/d2Jts4ib7GpaSIx4RamKVximbuZ4QMDtyLiSilZL.jpeg\" alt=\"\" width=\"764\" height=\"425\" /></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">- Cộng đồng người sử dụng đ&ocirc;ng đảo:</p>\r\n<p style=\"text-align: justify;\">Đ&acirc;y l&agrave; một nền tảng được nhiều người tr&ecirc;n thế giới sử dụng v&agrave; đ&oacute;ng g&oacute;p c&aacute;c kh&ocirc;ng gian ấn tượng.</p>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/QR6KLix50c6U5TUEkmW3k4576KKybNaoX5pzjvzY.jpeg\" alt=\"\" width=\"792\" height=\"440\" /></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<h2 style=\"text-align: justify;\"><strong>2. Chi tiết t&iacute;nh năng</strong></h2>\r\n<p style=\"text-align: justify;\">- C&ocirc;ng cụ thiết kế kh&ocirc;ng gian nội thất một c&aacute;ch đơn giản</p>\r\n<p style=\"text-align: justify;\">Với c&ocirc;ng cụ vẽ mặt bằng 2D/3D nhanh ch&oacute;ng v&agrave; mạnh mẽ v&agrave; bộ thư viện đồ nội thất đa dạng, c&ocirc;ng việc của người thiết kế c&oacute; thể dễ d&agrave;ng thiết kế những kh&ocirc;ng gian nội thất của người d&ugrave;ng.</p>\r\n<p style=\"text-align: justify;\">- Cloud Rendering</p>\r\n<p style=\"text-align: justify;\">Với c&ocirc;ng nghệ Cloud Computing mạnh mẽ, chỉ mất một thời gian ngắn để Homestyler mang đến những bức ảnh 3D, panorama một c&aacute;ch ch&acirc;n thực c&ugrave;ng chất lượng h&igrave;nh ảnh sắc n&eacute;t.</p>\r\n<p style=\"text-align: justify;\">- Giải ph&aacute;p Marketing trong thời đại mới</p>\r\n<p style=\"text-align: justify;\">Đ&acirc;y ch&iacute;nh l&agrave; xu hướng marketing mới khiến cho kh&aacute;ch h&agrave;ng c&oacute; thể trải nghiệm được sản phẩm nội thất trong ch&iacute;nh ng&ocirc;i nh&agrave; của m&igrave;nh. Ngo&agrave;i ra, ứng&nbsp; dụng điện thoại của Homestyler l&agrave; một giải ph&aacute;p mới khiến cho việc trải nghiệm c&aacute;c đồ nội thất trong ch&iacute;nh kh&ocirc;ng gian của kh&aacute;ch h&agrave;ng c&agrave;ng trở n&ecirc;n dễ d&agrave;ng hơn.</p>\r\n<p>&nbsp;</p>','Homestyler – Thiết kế 3D những ngôi nhà trong mơ',NULL,'homestyler-thiet-ke-3d-nhung-ngoi-nha-trong-mo','Homestyler là giải pháp cung cấp công cụ thiết kế nội thất 3D hiệu quả cho các nhà thiết kế và cung cấp các giải pháp chuyển đổi kỹ thuật số cho ngành nội thất và bất động sản.','thiết kế nội thất, nội thất, nội thất gỗ, công nghệ gỗ, phần mềm gỗ, homestyler','Published',2,NULL,1,20,'2021-09-26 21:13:07','2021-09-26 21:13:07',NULL),(56,'Hỗ trợ mùa dịch: Haixun discount 20-25% giá trị phần mềm','2021-10-07 08:41:00','1634002967-ho-tro-mua-dich-haixun-discount-20-25-gia-tri-phan-mem.jpg','Nghenoithat kết hợp cùng hãng phần mềm Haixun đang triển khai kế hoạch hỗ trợ các doanh nghiệp ngành nội thất trong thời điểm đại dịch Covid với mức giá ưu đãi khi triển khai phần mềm trong khoảng thời gian từ nay đến tháng 11.','<p style=\"text-align: justify;\">Đại dịch Covid - 19 l&agrave; c&uacute; sốc mạnh đối với thị trường kinh tế v&agrave; lao động, g&acirc;y ảnh hưởng trầm trọng đến nguồn cung sản xuất h&agrave;ng h&oacute;a v&agrave; dịch vụ, g&acirc;y ra những t&aacute;c động mạnh tới nhu cầu ti&ecirc;u d&ugrave;ng v&agrave; đầu tư kh&ocirc;ng chỉ ở Việt Nam m&agrave; c&ograve;n tr&ecirc;n to&agrave;n thế giới. T&aacute;c động của cuộc khủng hoảng đ&atilde; l&agrave;m đứt gẫy qu&aacute; tr&igrave;nh sản xuất trong nước. Ở Việt Nam, c&aacute;c biện ph&aacute;p ph&ograve;ng chống dịch bệnh của Ch&iacute;nh phủ đang ph&aacute;t huy tốt t&aacute;c dụng ngăn chặn dịch bệnh của m&igrave;nh. Tuy nhi&ecirc;n, với Chỉ thị 16 của Ch&iacute;nh phủ, c&aacute;c xưởng gỗ hầu như đều ngừng hoạt động, khiến cho những người trong nghề gặp rất nhiều kh&oacute; khăn.</p>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/BZXT4W1rJL5FDMugsEw5KhimHFM6hxISaXYYBRS3.jpeg\" alt=\"\" width=\"700\" height=\"389\" /></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Hiểu được những vấn đề m&agrave; c&aacute;c đơn vị l&agrave;m nghề gỗ đang gặp phải, Nghenoithat c&ugrave;ng h&atilde;ng phần mềm Haixun đ&atilde; đưa ra một ch&iacute;nh s&aacute;ch ưu đ&atilde;i về gi&aacute; cho c&aacute;c đơn vị thiết kế v&agrave; thi c&ocirc;ng nội thất. Trong khoảng thời gian từ nay đến th&aacute;ng 11, mức gi&aacute; triển khai phần mềm được ưu đ&atilde;i l&ecirc;n đến 25% tr&ecirc;n gi&aacute; gốc của phần mềm.</p>\r\n<p style=\"text-align: justify;\">Hiện nay, Haixun l&agrave; một trong những phần mềm mạnh mẽ, hỗ trợ đắc lực cho c&aacute;c đơn vị l&agrave;m nội thất. Phần mềm thiết kế v&agrave; sản xuất nội thất Haixun l&agrave; một phần mềm hỗ trợ to&agrave;n bộ qu&aacute; tr&igrave;nh sản xuất đồ gỗ từ thiết kế, b&oacute;c t&aacute;ch, dự to&aacute;n nguy&ecirc;n vật liệu, điều khiển m&aacute;y cưa, m&aacute;y khoan, quản l&yacute; kho vật tư, bao g&oacute;i v.v&hellip; gi&uacute;p tối ưu chi ph&iacute; v&agrave; năng suất. Haixun lu&ocirc;n nỗ lực để trở th&agrave;nh phần mềm nội thất h&agrave;ng đầu, đơn giản nhất nhưng khả năng ứng dụng cao nhất, v&agrave; cung cấp giải ph&aacute;p t&iacute;ch hợp \"Từ thiết kế - quản l&yacute; tới gia c&ocirc;ng - sản xuất\" cho ng&agrave;nh c&ocirc;ng nghiệp nội thất.</p>\r\n<p style=\"text-align: justify;\">T&iacute;nh năng ch&iacute;nh của phần mềm Haixun:</p>\r\n<p style=\"text-align: justify;\">- Thiết kế c&aacute;c mẫu tủ, kệ v&agrave; lưu lại th&agrave;nh bộ thư viện phục vụ sử dụng l&acirc;u d&agrave;i</p>\r\n<p style=\"text-align: justify;\">- Kết xuất đồ họa 3D kh&ocirc;ng gian nội thất, mang đến h&igrave;nh ảnh trực quan cho người thiết kế v&agrave; kh&aacute;ch h&agrave;ng (Cloud Rendering)</p>\r\n<p style=\"text-align: justify;\">- X&acirc;y dựng b&aacute;o c&aacute;o nguy&ecirc;n liệu, vật tư, tư liệu sản xuất (Sơ đồ rải v&aacute;n, danh s&aacute;ch cắt, bản vẽ lắp,...) v&agrave; b&aacute;o gi&aacute;</p>\r\n<p style=\"text-align: justify;\">- Tạo bản vẽ kỹ thuật phục vụ x&acirc;y dựng bộ hồ sơ thiết kế, thi c&ocirc;ng</p>\r\n<p style=\"text-align: justify;\">- Tạo m&atilde; lệnh phục vụ gia c&ocirc;ng v&agrave; tem nh&atilde;n quản l&yacute; sản phẩm cuối c&ugrave;ng.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><strong><em>Để biết th&ecirc;m th&ocirc;ng tin chi tiết, xin li&ecirc;n hệ: </em></strong></p>\r\n<p style=\"text-align: justify;\"><em>Trung t&acirc;m thương mại Golden Land, 275 Nguyễn Tr&atilde;i, Thanh Xu&acirc;n, H&agrave; Nội</em></p>\r\n<p style=\"text-align: justify;\"><em>Email: info@nghenoithat.vn</em></p>\r\n<p style=\"text-align: justify;\"><em>Hotline: 0868934576</em></p>\r\n<p style=\"text-align: justify;\"><em>SĐT: 02439741436</em></p>','Hỗ trợ mùa dịch: Haixun discount 20-25% giá trị phần mềm',NULL,'ho-tro-mua-dich-haixun-discount-20-25-gia-tri-phan-mem','Nghenoithat kết hợp cùng hãng phần mềm Haixun đang triển khai kế hoạch hỗ trợ các doanh nghiệp ngành nội thất trong thời điểm đại dịch Covid với mức giá ưu đãi khi triển khai phần mềm trong khoảng thời gian từ nay đến tháng 11.',NULL,'Published',2,NULL,1,21,'2021-10-11 18:42:47','2021-10-11 18:43:06',NULL),(57,'Floori – Giải pháp hỗ trợ sales và marketing cho các ngành công nghiệp ván sàn – gạch ốp lát','2021-10-11 08:46:00','1634004019-floori-giai-phap-visualizer-cho-cac-nganh-cong-nghiep-van-san-gach-op-lat.jpg','Floori là giải pháp diễn họa trực quan các sản phẩm ván sàn, thảm, gạch ốp lát trong chính không gian của khách hàng.','<p style=\"text-align: justify;\">V&aacute;n s&agrave;n, gạch ốp l&aacute;t l&agrave; một trong những yếu tố quan trọng tạo n&ecirc;n một kh&ocirc;ng gian sống. Tuy chỉ l&agrave; một phần trong tổng thể kh&ocirc;ng gian ph&ograve;ng, nhưng việc lựa chọn những loại vật liệu, m&agrave;u sắc, kiểu d&aacute;ng v&agrave; hoa văn kh&aacute;c nhau sao cho ph&ugrave; hợp th&igrave; kh&ocirc;ng phải chuyện dễ d&agrave;ng. Th&ocirc;ng thường, kh&aacute;ch h&agrave;ng sẽ gh&eacute; thăm một cửa h&agrave;ng hoặc trang web v&aacute;n s&agrave;n, t&igrave;m hiểu c&aacute;c loại gạch ốp l&aacute;t hay v&aacute;n s&agrave;n kh&aacute;c nhau v&agrave; cố gắng tưởng tượng xem ch&uacute;ng c&oacute; ph&ugrave; hợp với nh&agrave; của họ kh&ocirc;ng dựa tr&ecirc;n c&aacute;c mẫu hoặc ảnh do nh&acirc;n vi&ecirc;n b&aacute;n h&agrave;ng hoặc nh&agrave; sản xuất cung cấp.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/ZjlIx7QmjxyW5mUQGgdK0QaFkvSRsXscTXiov9ZJ.jpeg\" alt=\"\" width=\"700\" height=\"388\" /></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Tuy nhi&ecirc;n, trong nhiều trường hợp kết quả thực tế khi kh&aacute;ch h&agrave;ng mua về lại kh&aacute;c so với tưởng tượng của họ khi xem tại showrooom. May mắn thay, những tiến bộ c&ocirc;ng nghệ hiện nay đang tạo ra những bước tiến vượt bậc nhằm n&acirc;ng cao trải nghiệm kh&aacute;ch h&agrave;ng. Với c&ocirc;ng nghệ thực tế tăng cường (AR), ng&agrave;nh c&ocirc;ng nghiệp v&aacute;n s&agrave;n tr&ecirc;n thế giới đang c&oacute; những thay đổi vượt bậc trong c&aacute;ch tiếp thị sản phẩm v&aacute;n s&agrave;n của họ cho người ti&ecirc;u d&ugrave;ng.&nbsp;&nbsp;</p>\r\n<p style=\"text-align: justify;\">C&ocirc;ng nghệ AR kh&ocirc;ng hề xa lạ với ch&uacute;ng ta m&agrave; n&oacute; đ&atilde; c&oacute; mặt trong chiếc điện thoại smartphone từ l&acirc;u. Những bức ảnh được chụp với những filter dễ thương ch&iacute;nh l&agrave; một trong những ứng dụng thường thấy nhất của AR. Nhưng AR kh&ocirc;ng chỉ d&agrave;nh cho c&aacute;c ứng dụng x&atilde; hội, c&ocirc;ng nghệ n&agrave;y c&ograve;n &aacute;p dụng cho nhiều lĩnh vực kh&aacute;c như thiết kế nội thất m&agrave; trong đ&oacute;, v&aacute;n s&agrave;n v&agrave; gạch ốp l&aacute;t l&agrave; những d&ograve;ng sản phẩm m&agrave; dễ c&oacute; thể &aacute;p dụng v&agrave; mang lại hiệu quả vượt bậc với mọi đối tượng kh&aacute;ch h&agrave;ng.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/CEsnL7Cl9lrd66bDsAKtO5TPfaMRuETadc2pXqId.png\" alt=\"\" width=\"700\" height=\"345\" /></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Floori l&agrave; một nền tảng cho ph&eacute;p c&aacute;c đơn vị cung cấp v&aacute;n s&agrave;n, gạch ốp l&aacute;t c&oacute; thể t&iacute;ch hợp c&ocirc;ng nghệ n&agrave;y tr&ecirc;n ch&iacute;nh website của m&igrave;nh. Khi kh&aacute;ch h&agrave;ng v&agrave;o website để lựa chọn sản phẩm, ngo&agrave;i việc thay thế những mẫu v&aacute;n hay gạch ốp l&aacute;t trong một số kh&ocirc;ng gian sẵn c&oacute; th&igrave; điểm nổi bật của Floori l&agrave; c&oacute; thể để kh&aacute;ch h&agrave;ng upload kh&ocirc;ng gian nội thất của ch&iacute;nh kh&aacute;ch h&agrave;ng v&agrave; thay những mẫu sản phẩm trong kho thư viện. Bằng c&ocirc;ng nghệ AI v&agrave; AR, việc kh&aacute;ch h&agrave;ng c&oacute; thể tự trải nghiệm những mẫu v&aacute;n s&agrave;n hay c&aacute;c mẫu gạch ốp l&aacute;t chưa bao giờ dễ d&agrave;ng hơn thế.</p>','Floori – Giải pháp hỗ trợ sales và marketing cho các ngành công nghiệp ván sàn – gạch ốp lát',NULL,'floori-giai-phap-ho-tro-sales-va-marketing-cho-cac-nganh-cong-nghiep-van-san-gach-op-lat','Floori là giải pháp diễn họa trực quan các sản phẩm ván sàn, thảm, gạch ốp lát trong chính không gian của khách hàng.',NULL,'Published',2,NULL,1,21,'2021-10-11 19:00:19','2021-10-13 03:16:10',NULL),(58,'Hội thảo trực tuyến với chủ đề “Các giải pháp chuyển đổi số trong kinh doanh Nội thất và Vật liệu xây dựng’’','2021-10-13 17:13:00','1634120261-hoi-thao-truc-tuyen-voi-chu-de-cac-giai-phap-chuyen-doi-so-trong-kinh-doanh-noi-that-va-vat-lieu-xay-dung.jpg','Trong những năm gần đây, xu hướng chuyển đổi số và ứng dụng công nghệ 4.0 ngày càng được quan tâm và từng bước được áp dụng mang lại hiệu quả tốt cho nhiều doanh nghiệp tại Việt Nam. Đặc biệt trong lĩnh vực nội thất và vật liệu xây dựng, các giải pháp chuyển đổi số phục vụ hoạt động kinh doanh trên môi trường mạng internet đang ngày càng chiếm ưu thế với tình hình dịch bệnh Covid-19 hiện nay.','<p style=\"text-align: justify;\">Với mong muốn đồng h&agrave;nh c&ugrave;ng c&aacute;c doanh nghiệp nội thất v&agrave; vật liệu x&acirc;y dựng đang kinh doanh tại thị trường Việt Nam trong việc tiếp cận v&agrave; ứng dụng c&aacute;c giải ph&aacute;p ph&ugrave; hợp với khả năng v&agrave; nhu cầu của từng doanh nghiệp, Trang th&ocirc;ng tin tổng hợp Nghề Nội thất phối hợp c&ugrave;ng với C&ocirc;ng ty CIC tổ chức 1 buổi webinar - hội thảo trực tuyến (online) với chủ đề <strong>&ldquo;<em>C&aacute;c giải ph&aacute;p chuyển đổi số trong kinh doanh Nội thất v&agrave; Vật liệu x&acirc;y dựng&rsquo;&rsquo;</em></strong>, th&ocirc;ng tin chi tiết về buổi hội thảo trực tuyến như sau<em>:</em></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<ol style=\"text-align: justify;\">\r\n<li><strong> Nội dung ch&iacute;nh:</strong></li>\r\n</ol>\r\n<p style=\"text-align: justify;\"><strong><em>* Phần 1: Giới thiệu chung</em></strong></p>\r\n<p style=\"text-align: justify;\">- Giới thiệu về tổng quan c&aacute;c giải ph&aacute;p chuyển đổi số từ đơn giản tới phức tạp ứng dụng cho c&aacute;c doanh nghiệp nội thất v&agrave; vật liệu x&acirc;y dựng</p>\r\n<p style=\"text-align: justify;\"><strong><em>* Phần 2:</em></strong> <strong><em>Tr&igrave;nh b&agrave;y chi tiết c&aacute;c nh&oacute;m giải ph&aacute;p</em></strong></p>\r\n<p>- Giải ph&aacute;p <strong>catalog động</strong> (dynamic catalog hay e-catalog): tạo ra một m&ocirc;i trường ảo cho ph&eacute;p c&aacute;c nh&agrave; cung cấp tr&igrave;nh diễn một danh mục c&aacute;c sản phẩm của m&igrave;nh tr&ecirc;n đ&oacute; một c&aacute;ch trực quan sinh động với đầy đủ c&aacute;c th&ocirc;ng tin chi tiết sản phẩm, cũng như cho ph&eacute;p li&ecirc;n kết tới một hệ thống e-commerce (thương mại điện tử) sẵn c&oacute;</p>\r\n<p>- Giải ph&aacute;p <strong>Homestyler thiết kế minh họa v&agrave; render nhanh tr&ecirc;n nền Cloud</strong>: giải ph&aacute;p c&ocirc;ng nghệ cho ph&eacute;p c&aacute;c nh&agrave; thiết kế thực hiện thiết kế nội ngoại thất 1 c&aacute;ch nhanh ch&oacute;ng, cũng như tạo render chất lượng cao trong thời gian 1 v&agrave;i ph&uacute;t, tất cả tr&ecirc;n nền Cloud, gi&uacute;p tr&igrave;nh b&agrave;y &yacute; tưởng v&agrave; diễn họa cho c&aacute;c kh&aacute;ch h&agrave;ng</p>\r\n<p>- Giải ph&aacute;p diễn họa <strong>Showroom ảo của h&atilde;ng Matterport</strong>: cho ph&eacute;p c&aacute;c tổ chức cung cấp c&aacute;c sản phẩm nội thất v&agrave; VLXD sở hữu 1 showroom đầy đủ tr&ecirc;n kh&ocirc;ng gian mạng, l&agrave; nơi m&agrave; kh&aacute;ch h&agrave;ng c&oacute; thể truy cấp mọi l&uacute;c, mọi nơi để tham quan v&agrave; t&igrave;m hiểu về c&aacute;c sản phẩm m&agrave; tổ chức cung cấp</p>\r\n<p>- Giải ph&aacute;p <strong>Floori diễn họa Visualizer &aacute;p dụng cho c&aacute;c sản phẩm Gạch, đ&aacute; ốp l&aacute;t, s&agrave;n gỗ</strong>: cung cấp một phương thức trải nghiệm kh&aacute;ch h&agrave;ng ho&agrave;n to&agrave;n mới khi truy cập v&agrave; thao t&aacute;c tr&ecirc;n website của nh&agrave; cung cấp gạch, đ&aacute; ốp l&aacute;t, cho ph&eacute;p người d&ugrave;ng cuối xem những diễn họa gần nhất với thực tế về những sản phẩm m&agrave; họ quan t&acirc;m v&agrave; c&oacute; thể đặt mua</p>\r\n<p>- Giải ph&aacute;p <strong>Threekit diễn họa Visualizer &aacute;p dụng cho c&aacute;c sản phẩm sofa, b&agrave;n ghế v&agrave; c&aacute;c nội thất kh&aacute;c</strong>: gi&uacute;p cho c&aacute;c kh&aacute;ch h&agrave;ng c&oacute; nhu cầu mua đồ nội thất c&oacute; thể xem sản phẩm dưới dạng 3D qua nhiều g&oacute;c nh&igrave;n tại ch&iacute;nh kh&ocirc;ng gian nội thất nh&agrave; của m&igrave;nh th&ocirc;ng qua c&ocirc;ng nghệ thực tế ảo tăng cường AR, đồng thời c&oacute; thể t&ugrave;y biến c&aacute;c lựa chọn về vật liệu, m&agrave;u sắc, cấu tạo của nội thất đang quan t&acirc;m.</p>\r\n<p><strong><em>* Phần 3: Thảo luận - </em></strong>Hỏi v&agrave; đ&aacute;p</p>\r\n<p>&nbsp;</p>\r\n<ol style=\"text-align: justify;\" start=\"2\">\r\n<li><strong> Th&agrave;nh phần tham dự dự kiến</strong></li>\r\n</ol>\r\n<p style=\"text-align: justify;\"><strong>Kh&aacute;ch mời:</strong></p>\r\n<ul style=\"text-align: justify;\">\r\n<li>C&aacute;c c&ocirc;ng ty thiết kế v&agrave; thi c&ocirc;ng nội thất</li>\r\n<li>C&aacute;c c&ocirc;ng ty sản xuất kinh doanh đồ nội thất &ndash; vật liệu x&acirc;y dựng</li>\r\n<li>C&aacute;c c&ocirc;ng ty b&aacute;n lẻ, ph&acirc;n phối nội thất, vật liệu x&acirc;y dựng</li>\r\n<li>C&aacute;c chuỗi si&ecirc;u thị nội thất &ndash; vật liệu x&acirc;y dựng</li>\r\n<li>C&aacute;c c&ocirc;ng ty sản xuất, kinh doanh ph&acirc;n phối thiết bị trong dự &aacute;n x&acirc;y dựng c&ocirc;ng tr&igrave;nh</li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<ol style=\"text-align: justify;\" start=\"3\">\r\n<li><strong> Thời gian v&agrave; địa điểm:</strong></li>\r\n</ol>\r\n<p style=\"text-align: justify;\">Thời gian: <strong>từ 9:00 đến 10:30 buổi s&aacute;ng ng&agrave;y 28/10/2021</strong></p>\r\n<p style=\"text-align: justify;\">Link tham dự: sẽ được ch&uacute;ng t&ocirc;i gửi trực tiếp v&agrave;o email sau khi c&oacute; x&aacute;c nhận đăng k&yacute; của Qu&yacute; đơn vị.</p>\r\n<p style=\"text-align: justify;\">Ch&uacute;ng t&ocirc;i mong nhận được x&aacute;c nhận của Q&uacute;y đơn vị trước ng&agrave;y <strong>26/10/2021</strong> để ch&uacute;ng t&ocirc;i thực hiện c&aacute;c c&ocirc;ng t&aacute;c chuẩn bị như kế hoạch ở tr&ecirc;n.</p>\r\n<p style=\"text-align: justify;\">Qu&yacute; đơn vị vui l&ograve;ng đăng k&yacute; <a href=\"https://docs.google.com/forms/d/e/1FAIpQLSfcTwR7cwwfS8vVOEnO8frQPNMDTuv-H4faUoln1AUl8ylDtw/viewform\" target=\"_blank\" rel=\"noopener\">tại đ&acirc;y</a></p>','Hội thảo trực tuyến với chủ đề “Các giải pháp chuyển đổi số trong kinh doanh Nội thất và Vật liệu xây dựng’’',NULL,'hoi-thao-truc-tuyen-voi-chu-de-cac-giai-phap-chuyen-doi-so-trong-kinh-doanh-noi-that-va-vat-lieu-xay-dung','Trong những năm gần đây, xu hướng chuyển đổi số và ứng dụng công nghệ 4.0 ngày càng được quan tâm và từng bước được áp dụng mang lại hiệu quả tốt cho nhiều doanh nghiệp tại Việt Nam. Đặc biệt trong lĩnh vực nội thất và vật liệu xây dựng, các giải pháp chuyển đổi số phục vụ hoạt động kinh doanh trên môi trường mạng internet đang ngày càng chiếm ưu thế với tình hình dịch bệnh Covid-19 hiện nay.',NULL,'Published',2,NULL,1,22,'2021-10-13 03:17:41','2021-10-13 23:35:59',NULL),(59,'Showroom ảo – Giải pháp chuyển đổi số cho doanh nghiệp nội thất và Vật liệu xây dựng','2021-11-12 09:39:00','1637030852-showroom-ao-giai-phap-chuyen-doi-so-cho-doanh-nghiep-noi-that-va-vat-lieu-xay-dung.jpg','Ngày nay, song hành cùng sự phát triển của công nghệ, thương mại điện tử (E-commerce) ngày càng phát triển và mở rộng, được ứng dụng ở rất nhiều lĩnh vực khác nhau. Thị trường mua sắm trực tuyến trở nên sôi động hơn khi người mua dần có xu hướng mua bán online, thay vì cách thức đến trực tiếp cửa hàng offline như trước kia. Đối với ngành nội thất, Showroom thực tế ảo dần đóng vai trò quan trọng trong cơ cấu bán hàng của các doanh nghiệp, giúp tiết kiệm chi phí và gia tăng lợi thế cạnh tranh dài hạn cho các','<p style=\"text-align: justify;\"><strong>Thay đổi trong xu hướng mua sắm của kh&aacute;ch h&agrave;ng</strong></p>\r\n<p style=\"text-align: justify;\">Theo Hiệp hội mỹ nghệ v&agrave; chế biến gỗ TP.HCM (HAWA), ng&agrave;nh nội thất truyền thống c&oacute; đặc th&ugrave; l&agrave; kh&ocirc;ng gian rộng để trưng b&agrave;y v&agrave; giới thiệu sản phẩm, phục vụ th&oacute;i quen &ldquo;thấy tận mắt, sờ tận tay&rdquo; của người ti&ecirc;u d&ugrave;ng. Tuy nhi&ecirc;n, sự b&ugrave;ng ph&aacute;t của dịch COVID-19 khiến hoạt động kinh doanh trở n&ecirc;n kh&oacute; khăn, người d&acirc;n hạn chế ra ngo&agrave;i, kh&aacute;ch h&agrave;ng kh&oacute; c&oacute; thể đến trực tiếp tham quan tại cửa h&agrave;ng.</p>\r\n<p style=\"text-align: justify;\">B&ecirc;n cạnh đ&oacute;, sự ph&aacute;t triển của c&aacute;c trang TMĐT đ&atilde; chuyển h&igrave;nh thức mua sắm của kh&aacute;ch h&agrave;ng từ phương thức truyền thống sang mua h&agrave;ng trực tuyến. Cụ thể, một nghi&ecirc;n cứu đầu năm 2021 đ&atilde; cho thấy 86% số người sử dụng internet đ&atilde; mua h&agrave;ng trực tuyến, con số n&agrave;y đ&atilde; tăng gấp 3 lần so với năm 2017.</p>\r\n<p style=\"text-align: justify;\"><a href=\"https://kienviet.net/wp-content/uploads/2021/07/kienviet-showroom-ao-giai-phap-chuyen-doi-so-tang-doanh-th-cho-doanh-nghiep-noi-that-1.jpg\"><img src=\"/storage/uploads/tinymce/U1iPwaIXWb1VEDsOwL7H6qHgLiez5Fj7QX6DTfsN.jpeg\" alt=\"\" width=\"700\" height=\"394\" /></a></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Kh&ocirc;ng dừng lại ở đ&oacute;, việc đầu tư showroom truyền thống l&agrave; một sự tốn k&eacute;m, đặc biệt với c&aacute;c doanh nghiệp vừa v&agrave; nhỏ. Cụ thể, chi ph&iacute; trung b&igrave;nh một doanh nghiệp đầu tư cho 1 showroom sẽ rơi v&agrave;o khoảng 100 &ndash; 300 triệu chưa kể chi ph&iacute; thu&ecirc; mặt bằng v&agrave; vận h&agrave;nh. Kh&aacute;c với showroom truyền thống, showroom ảo l&agrave; c&ocirc;ng cụ trưng b&agrave;y sản phẩm di động m&agrave; nh&acirc;n vi&ecirc;n b&aacute;n h&agrave;ng c&oacute; thể dễ d&agrave;ng sử dụng để giới thiệu sản phẩm đến kh&aacute;ch h&agrave;ng mọi l&uacute;c mọi nơi. Điều n&agrave;y kh&ocirc;ng được t&igrave;m thấy ở m&ocirc; h&igrave;nh offline. Vậy, thay đổi l&agrave; bức thiết!</p>\r\n<p style=\"text-align: justify;\">R&otilde; r&agrave;ng với t&aacute;c động từ thị trường th&igrave; việc c&aacute;c doanh nghiệp chuyển m&igrave;nh từ offline sang online l&agrave; điều cần thiết. V&agrave; trước hết, việc sử dụng showroom online sẽ l&agrave; c&ocirc;ng cụ gi&uacute;p tiếp cận v&agrave; b&aacute;n h&agrave;ng hiệu quả. Qua đ&oacute;, kh&aacute;ch h&agrave;ng c&oacute; thể tham quan showroom, nh&agrave; m&aacute;y một c&aacute;ch trực quan từ xa. Giải ph&aacute;p n&agrave;y kh&ocirc;ng chỉ giải quyết được vấn đề ngắn hạn trong đại dịch covid m&agrave; c&ograve;n l&agrave; đ&ograve;n bẩy cho một bước tiến d&agrave;i hạn.</p>\r\n<p style=\"text-align: justify;\">Showroom ảo đang dần trở th&agrave;nh xu hướng tất yếu trong hoạt động kinh doanh của c&aacute;c doanh nghiệp sản xuất v&agrave; kinh doanh sản phẩm nội thất trong tương lai. Showroom ảo được k&igrave; vọng sẽ gi&uacute;p n&acirc;ng cao trải nghiệm của kh&aacute;ch h&agrave;ng v&agrave; tối ưu chi ph&iacute; cho doanh nghiệp. Đ&acirc;y hứa hẹn sẽ l&agrave; giải ph&aacute;p tuyệt vời cho c&aacute;c doanh nghiệp nội thất trong tương lai.</p>\r\n<p style=\"text-align: justify;\">Để t&igrave;m hiểu c&aacute;c giải ph&aacute;p chuyển đổi số mới trong ng&agrave;nh nội thất v&agrave; VLXD, vui l&ograve;ng li&ecirc;n hệ hotline của Nghề nội thất: 0868934576 hoặc email: <a href=\"mailto:info@nghenoithat.vn\">info@nghenoithat.vn</a>.</p>','Showroom ảo – Giải pháp chuyển đổi số cho doanh nghiệp nội thất và Vật liệu xây dựng',NULL,'showroom-ao-giai-phap-chuyen-doi-so-cho-doanh-nghiep-noi-that-va-vat-lieu-xay-dung','Ngày nay, song hành cùng sự phát triển của công nghệ, thương mại điện tử (E-commerce) ngày càng phát triển và mở rộng, được ứng dụng ở rất nhiều lĩnh vực khác nhau. Thị trường mua sắm trực tuyến trở nên sôi động hơn khi người mua dần có xu hướng mua bán online, thay vì cách thức đến trực tiếp cửa hàng offline như trước kia. Đối với ngành nội thất, Showroom thực tế ảo dần đóng vai trò quan trọng trong cơ cấu bán hàng của các doanh nghiệp, giúp tiết kiệm chi phí và gia tăng lợi thế cạnh tranh dài hạn cho các đơn vị ứng dụng…','thiết kế nội thất, nội thất, nội thất gỗ, công nghệ gỗ, phần mềm nội thất','Published',2,NULL,1,NULL,'2021-11-15 19:47:32','2021-11-15 19:49:29','2021-11-15 19:49:29'),(60,'Showroom ảo – Giải pháp chuyển đổi số cho doanh nghiệp nội thất và Vật liệu xây dựng','2021-11-12 09:39:00','1637030853-showroom-ao-giai-phap-chuyen-doi-so-cho-doanh-nghiep-noi-that-va-vat-lieu-xay-dung.jpg','Ngày nay, song hành cùng sự phát triển của công nghệ, thương mại điện tử ngày càng phát triển, được ứng dụng ở rất nhiều lĩnh vực khác nhau. Thị trường mua sắm trực tuyến trở nên sôi động hơn khi người mua dần có xu hướng mua bán online, thay vì cách thức đến trực tiếp cửa hàng offline như trước kia. Đối với ngành nội thất, Showroom thực tế ảo dần đóng vai trò quan trọng trong cơ cấu bán hàng của doanh nghiệp, giúp tiết kiệm chi phí và gia tăng lợi thế cạnh tranh cho các đơn vị ứng dụng nó.','<p style=\"text-align: justify;\"><strong>Thay đổi trong xu hướng mua sắm của kh&aacute;ch h&agrave;ng</strong></p>\r\n<p style=\"text-align: justify;\">Theo Hiệp hội mỹ nghệ v&agrave; chế biến gỗ TP.HCM (HAWA), ng&agrave;nh nội thất truyền thống c&oacute; đặc th&ugrave; l&agrave; kh&ocirc;ng gian rộng để trưng b&agrave;y v&agrave; giới thiệu sản phẩm, phục vụ th&oacute;i quen &ldquo;thấy tận mắt, sờ tận tay&rdquo; của người ti&ecirc;u d&ugrave;ng. Tuy nhi&ecirc;n, sự b&ugrave;ng ph&aacute;t của dịch COVID-19 khiến hoạt động kinh doanh trở n&ecirc;n kh&oacute; khăn, người d&acirc;n hạn chế ra ngo&agrave;i, kh&aacute;ch h&agrave;ng kh&oacute; c&oacute; thể đến trực tiếp tham quan tại cửa h&agrave;ng.</p>\r\n<p style=\"text-align: justify;\">B&ecirc;n cạnh đ&oacute;, sự ph&aacute;t triển của c&aacute;c trang TMĐT đ&atilde; chuyển h&igrave;nh thức mua sắm của kh&aacute;ch h&agrave;ng từ phương thức truyền thống sang mua h&agrave;ng trực tuyến. Cụ thể, một nghi&ecirc;n cứu đầu năm 2021 đ&atilde; cho thấy 86% số người sử dụng internet đ&atilde; mua h&agrave;ng trực tuyến, con số n&agrave;y đ&atilde; tăng gấp 3 lần so với năm 2017.</p>\r\n<p style=\"text-align: justify;\"><a href=\"https://kienviet.net/wp-content/uploads/2021/07/kienviet-showroom-ao-giai-phap-chuyen-doi-so-tang-doanh-th-cho-doanh-nghiep-noi-that-1.jpg\"><img src=\"/storage/uploads/tinymce/U1iPwaIXWb1VEDsOwL7H6qHgLiez5Fj7QX6DTfsN.jpeg\" alt=\"\" width=\"700\" height=\"394\" /></a></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Kh&ocirc;ng dừng lại ở đ&oacute;, việc đầu tư showroom truyền thống l&agrave; một sự tốn k&eacute;m, đặc biệt với c&aacute;c doanh nghiệp vừa v&agrave; nhỏ. Cụ thể, chi ph&iacute; trung b&igrave;nh một doanh nghiệp đầu tư cho 1 showroom sẽ rơi v&agrave;o khoảng 100 &ndash; 300 triệu chưa kể chi ph&iacute; thu&ecirc; mặt bằng v&agrave; vận h&agrave;nh. Kh&aacute;c với showroom truyền thống, showroom ảo l&agrave; c&ocirc;ng cụ trưng b&agrave;y sản phẩm di động m&agrave; nh&acirc;n vi&ecirc;n b&aacute;n h&agrave;ng c&oacute; thể dễ d&agrave;ng sử dụng để giới thiệu sản phẩm đến kh&aacute;ch h&agrave;ng mọi l&uacute;c mọi nơi. Điều n&agrave;y kh&ocirc;ng được t&igrave;m thấy ở m&ocirc; h&igrave;nh offline. Vậy, thay đổi l&agrave; bức thiết!</p>\r\n<p style=\"text-align: justify;\">R&otilde; r&agrave;ng với t&aacute;c động từ thị trường th&igrave; việc c&aacute;c doanh nghiệp chuyển m&igrave;nh từ offline sang online l&agrave; điều cần thiết. V&agrave; trước hết, việc sử dụng showroom online sẽ l&agrave; c&ocirc;ng cụ gi&uacute;p tiếp cận v&agrave; b&aacute;n h&agrave;ng hiệu quả. Qua đ&oacute;, kh&aacute;ch h&agrave;ng c&oacute; thể tham quan showroom, nh&agrave; m&aacute;y một c&aacute;ch trực quan từ xa. Giải ph&aacute;p n&agrave;y kh&ocirc;ng chỉ giải quyết được vấn đề ngắn hạn trong đại dịch covid m&agrave; c&ograve;n l&agrave; đ&ograve;n bẩy cho một bước tiến d&agrave;i hạn.</p>\r\n<p style=\"text-align: justify;\">Showroom ảo đang dần trở th&agrave;nh xu hướng tất yếu trong hoạt động kinh doanh của c&aacute;c doanh nghiệp sản xuất v&agrave; kinh doanh sản phẩm nội thất trong tương lai. Showroom ảo được k&igrave; vọng sẽ gi&uacute;p n&acirc;ng cao trải nghiệm của kh&aacute;ch h&agrave;ng v&agrave; tối ưu chi ph&iacute; cho doanh nghiệp. Đ&acirc;y hứa hẹn sẽ l&agrave; giải ph&aacute;p tuyệt vời cho c&aacute;c doanh nghiệp nội thất trong tương lai.</p>\r\n<p style=\"text-align: justify;\">Để t&igrave;m hiểu c&aacute;c giải ph&aacute;p chuyển đổi số mới trong ng&agrave;nh nội thất v&agrave; VLXD, vui l&ograve;ng li&ecirc;n hệ hotline của Nghề nội thất: 0868934576 hoặc email: <a href=\"mailto:info@nghenoithat.vn\">info@nghenoithat.vn</a>.</p>','Showroom ảo – Giải pháp chuyển đổi số cho doanh nghiệp nội thất và Vật liệu xây dựng',NULL,'showroom-ao-giai-phap-chuyen-doi-so-cho-doanh-nghiep-noi-that-va-vat-lieu-xay-dung','Ngày nay, song hành cùng sự phát triển của công nghệ, thương mại điện tử (E-commerce) ngày càng phát triển và mở rộng, được ứng dụng ở rất nhiều lĩnh vực khác nhau. Thị trường mua sắm trực tuyến trở nên sôi động hơn khi người mua dần có xu hướng mua bán online, thay vì cách thức đến trực tiếp cửa hàng offline như trước kia. Đối với ngành nội thất, Showroom thực tế ảo dần đóng vai trò quan trọng trong cơ cấu bán hàng của các doanh nghiệp, giúp tiết kiệm chi phí và gia tăng lợi thế cạnh tranh dài hạn cho các đơn vị ứng dụng…','thiết kế nội thất, nội thất, nội thất gỗ, công nghệ gỗ, phần mềm nội thất','Published',2,NULL,1,23,'2021-11-15 19:47:33','2021-11-17 03:34:27',NULL),(61,'Hệ thống điều hành sản xuất Manufacturing execution systems (MES) và tầm quan trọng','2022-01-20 17:22:00','1642674290-he-thong-dieu-hanh-san-xuat-manufacturing-execution-systems-mes-va-tam-quan-trong.jpg','Manufacturing execution systems (MES) là hệ thống máy tính – phần mềm được sử dụng trong nhà máy, dùng  để theo dõi, giám sát và lưu trữ thông tin từ vật tư đầu vào thành sản phẩm đầu ra. MES cung cấp thông tin giúp những người ra quyết định trong nhà máy hiểu được tình trạng hiện thời của nhà máy nhằm tối ưu và cải tiến hoạt đột sản xuất. Hệ thống MES làm việc trực tuyến thời gian thực để điều khiển nhiều thiết bị cùng lúc trong sản xuất. (đầu vào, con người, máy máy và dịch vụ hỗ trợ)','<p style=\"text-align: justify;\"><strong>MES l&agrave; th&agrave;nh phần kh&ocirc;ng thể thiếu trong nh&agrave; m&aacute;y th&ocirc;ng minh (Smart Factory)</strong></p>\r\n<p style=\"text-align: justify;\">MESA, Hiệp hội Giải ph&aacute;p Doanh nghiệp Sản xuất đ&atilde; từng chỉ ra rằng: \"Sản xuất th&ocirc;ng minh l&agrave; s&aacute;ng kiến ​​mang lại một cuộc c&aacute;ch mạng trong chiến lược sản xuất kinh doanh, biến c&aacute;c nh&agrave; m&aacute;y truyền thống từ trung t&acirc;m chi ph&iacute; th&agrave;nh trung t&acirc;m đổi mới c&oacute; lợi nhuận.\"&nbsp;&nbsp;Theo đ&oacute;, nh&agrave; m&aacute;y sản xuất sẽ l&agrave; trung t&acirc;m của doanh nghiệp v&agrave; tương ứng với n&oacute; l&agrave; MES -&nbsp;Hệ thống điều h&agrave;nh thực thi sản xuất, tr&aacute;i tim của hệ thống quản trị doanh nghiệp.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/8Z0D4IuTKXvUy0nIKmvbUsnvfAZFU8xZBceKnGDH.jpeg\" alt=\"\" width=\"624\" height=\"298\" /></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Trong hệ thống n&agrave;y, internet of things (IoT) đ&oacute;ng vai tr&ograve; rất quan trọng.&nbsp;IoT l&agrave; nguồn cung dữ liệu ch&iacute;nh x&aacute;c cho qu&aacute; tr&igrave;nh quản trị điều h&agrave;nh v&agrave; sau đ&oacute; l&agrave; hệ thống quản trị kinh doanh tổng thể doanh nghiệp bao gồm ERP, CRM, HRM,&hellip; Nhờ c&oacute; IoT m&agrave; việc kết nối giữa MES v&agrave;&nbsp;ERP, CRM, HRM,... trở l&ecirc;n dễ d&agrave;ng hơn,&nbsp;gi&uacute;p nh&agrave; quản trị c&oacute; bức tranh tổng h&ograve;a doanh nghiệp, theo d&otilde;i sức khoẻ của doanh nghiệp một c&aacute;ch ch&iacute;nh x&aacute;c nhất v&agrave; từ đ&oacute;, đưa ra c&aacute;c quyết định ph&ugrave; hợp kịp thời.&nbsp;</p>\r\n<p style=\"text-align: justify;\"><strong>Lợi &iacute;ch khi sử dụng Hệ thống điều h&agrave;nh sản xuất MES</strong></p>\r\n<p style=\"text-align: justify;\">Hệ thống điều h&agrave;nh sản xuất MES mang lại rất nhiều lợi &iacute;ch cho c&aacute;c doanh nghiệp sản xuất trong việc quản l&yacute; v&agrave; điều h&agrave;nh hệ thống sản xuất của m&igrave;nh. Thứ nhất, MES gi&uacute;p cho c&aacute;c doanh nghiệp đ&aacute;nh gi&aacute; được t&igrave;nh h&igrave;nh sử dụng của một thiết bị cụ thể trong bộ m&aacute;y sản xuất. Th&ocirc;ng qua đ&oacute;, doanh nghiệp c&oacute; thể c&acirc;n đối lại việc sử dụng c&aacute;c thiết bị sao cho đạt hiệu quả cao nhất. Nhờ c&aacute;c dữ liệu được phần mềm cung cấp, c&aacute;c doanh nghiệp c&oacute; thể điều chỉnh chi ph&iacute; sản xuất theo đơn đặt h&agrave;ng (job costing/price) nhằm tăng hay giảm cường độ khai th&aacute;c cho thiết bị đ&oacute;. Hệ thống điều h&agrave;nh sản xuất MES gi&uacute;p ghi ch&eacute;p v&agrave; lưu dữ liệu tốt hơn.</p>\r\n<p style=\"text-align: justify;\"><strong>Hệ thống điều h&agrave;nh sản xuất MES c&oacute; khả năng ph&acirc;n bổ nguồn lực cho doanh nghiệp</strong></p>\r\n<p style=\"text-align: justify;\">Với khả năng lớn về lưu trữ dữ liệu về t&agrave;i nguy&ecirc;n sản xuất , c&aacute;c hệ thống điều h&agrave;nh sản xuất MES c&oacute; thể dựa v&agrave;o những th&ocirc;ng tin n&agrave;y v&agrave; đưa ra chiến lược ph&acirc;n bổ nguồn lực. Từ những th&ocirc;ng tin về nh&agrave; xưởng như EQ, c&ocirc;ng cụ, nh&agrave; cung cấp,&hellip;v.v, MES gi&uacute;p quản l&yacute; trạng th&aacute;i của tất cả c&aacute;c d&acirc;y chuyền sản xuất, thiết bị, nắm bắt được v&ograve;ng đời của c&ocirc;ng cụ v&agrave; thiết bị th&ocirc;ng qua việc ph&acirc;n t&iacute;ch. Mỗi một quyết định ph&acirc;n bổ nguồn lực được đưa ra từ hệ thống điều h&agrave;nh sản xuất MES đều c&oacute; t&iacute;nh ch&iacute;nh x&aacute;c rất cao.</p>\r\n<p style=\"text-align: justify;\"><strong>Hệ thống MES gi&uacute;p doanh nghiệp quản l&yacute; qu&aacute; tr&igrave;nh bảo tr&igrave; m&aacute;y m&oacute;c</strong></p>\r\n<p style=\"text-align: justify;\">Do nắm được th&ocirc;ng tin về t&igrave;nh trạng m&aacute;y m&oacute;c n&ecirc;n hệ thống điều h&agrave;nh sản xuất MES c&oacute; khả năng quản l&yacute; được lịch tr&igrave;nh bảo tr&igrave; m&aacute;y m&oacute;c một c&aacute;ch ch&iacute;nh x&aacute;c. Đặc biệt, với những doanh nghiệp c&oacute; số lượng l&ecirc;n tới h&agrave;ng trăm m&aacute;y c&aacute;c loại, việc quản l&yacute; lịch tr&igrave;nh l&agrave; cực k&igrave; kh&oacute; khăn v&agrave; trong nhiều trường hợp, nhiều m&aacute;y m&oacute;c bị qu&aacute; thời gian bảo tr&igrave;. Việc ứng dụng hệ thống điều h&agrave;nh sản xuất MES sẽ gi&uacute;p khắc phục t&igrave;nh trạng n&agrave;y, nhất l&agrave; khi c&aacute;c doanh nghiệp mở rộng quy m&ocirc; sản xuất.</p>\r\n<p style=\"text-align: justify;\"><strong>Hệ thống MES thu thập dữ liệu đầy đủ v&agrave; nhanh ch&oacute;ng</strong></p>\r\n<p style=\"text-align: justify;\">Với khả năng lưu trữ th&ocirc;ng tin lớn bằng c&aacute;c c&ocirc;ng nghệ đ&aacute;m m&acirc;y, hệ thống điều h&agrave;nh sản xuất MES thu thập lại từng dữ liệu hoạt động trong qu&aacute; tr&igrave;nh sản xuất của doanh nghiệp. C&aacute;c dữ liệu thu thập được sẽ được c&ocirc;ng cụ Spec Check kiểm trả sắp xếp v&agrave; lưu lại trong bộ nhớ hệ điều h&agrave;nh. Đ&acirc;y l&agrave; một trong những ưu thế m&agrave; chỉ hệ thống điều h&agrave;nh sản xuất như MES mới c&oacute; thể thực hiện được, c&ograve;n c&aacute;c c&aacute;c quản l&yacute; sản xuất thủ c&ocirc;ng th&ocirc;ng thường đều kh&ocirc;ng đ&aacute;p ứng được.</p>\r\n<p style=\"text-align: justify;\"><strong>Hệ thống MES kiểm so&aacute;t tốt quy tr&igrave;nh thống k&ecirc;</strong></p>\r\n<p style=\"text-align: justify;\">Quy tr&igrave;nh thống k&ecirc; trong qu&aacute; tr&igrave;nh sản xuất của c&aacute;c doanh nghiệp l&agrave; v&ocirc; c&ugrave;ng quan trọng bởi thống k&ecirc; sẽ gi&uacute;p doanh nghiệp nhận ra những thiếu s&oacute;t hoặc vấn đề để kịp thời xử l&yacute;. C&aacute;c hệ thống MES đa số điều được trang bị c&aacute;c chức năng như: biểu đồ trực tuyến, Xbar-R, Xbar-S, XRS, P, Pn, C, U, Zbar-S, Delta-S v&agrave; c&aacute;c ph&eacute;p t&iacute;nh to&aacute;n c&aacute;c giới hạn của quy tr&igrave;nh sản xuất. Th&ocirc;ng qua những th&ocirc;ng tin n&agrave;y, chỉ trong thời gian ngắn, MES c&oacute; thể t&igrave;m ra những vấn đề m&agrave; c&aacute;c doanh nghiệp đang gặp phải v&agrave; giải ph&aacute;p cho ch&uacute;ng.</p>\r\n<p style=\"text-align: justify;\"><strong>Hệ thống MES gi&uacute;p cập nhật b&aacute;o c&aacute;o thường xuy&ecirc;n tr&ecirc;n kho dữ liệu trực tuyến.</strong></p>\r\n<p style=\"text-align: justify;\">Th&ocirc;ng qua việc sử dụng c&aacute;c nguồn lưu trữ dữ liệu điện to&aacute;n đ&aacute;m m&acirc;y, hệ thống điều h&agrave;nh sản xuất MES thường xuy&ecirc;n cập nhật c&aacute;c b&aacute;o c&aacute;o l&ecirc;n một kho dữ liệu trực tuyến. Điều n&agrave;y gi&uacute;p tr&aacute;nh được t&igrave;nh trạng mất dữ liệu trong một số trường hợp v&agrave; c&oacute; thể back up dữ liệu ngay khi cần. Những b&aacute;o c&aacute;o thường xuy&ecirc;n v&agrave; li&ecirc;n tục n&agrave;y sẽ gi&uacute;p cho c&aacute;c chủ doanh nghiệp nắm bắt được t&igrave;nh h&igrave;nh sản xuất hiện tại của c&ocirc;ng ty. X&eacute;t về l&acirc;u d&agrave;i, những th&ocirc;ng tin n&agrave;y cũng gi&uacute;p cho doanh nghiệp theo d&otilde;i được qu&aacute; tr&igrave;nh ph&aacute;t triển của nh&agrave; m&aacute;y một c&aacute;ch s&aacute;t sao v&agrave; ch&iacute;nh x&aacute;c về mặt thời gian.</p>\r\n<p style=\"text-align: justify;\"><strong>Hệ thống MES ph&acirc;n t&iacute;ch được hiệu suất c&ocirc;ng việc.</strong></p>\r\n<p style=\"text-align: justify;\">Nhờ khả năng lưu trữ từng hoạt động một trong qu&aacute; tr&igrave;nh sản xuất, hệ thống điều h&agrave;nh sản xuất MES c&oacute; một nguồn th&ocirc;ng tin rất lớn về hiệu suất c&ocirc;ng việc của nh&agrave; m&aacute;y. Th&ocirc;ng thường, nếu kh&ocirc;ng c&oacute; MES, việc đo lường, ph&acirc;n t&iacute;ch hiệu suất c&ocirc;ng việc của nh&agrave; m&aacute;y l&agrave; v&ocirc; c&ugrave;ng kh&oacute; khăn hoặc kh&ocirc;ng ch&iacute;nh x&aacute;c do số liệu thường kh&ocirc;ng đầy đủ. Ph&acirc;n t&iacute;ch được hiệu suất c&ocirc;ng việc sẽ gi&uacute;p c&aacute;c nh&agrave; quản l&yacute; nắm bắt được t&igrave;nh h&igrave;nh sản xuất của nh&agrave; m&aacute;y, từ đ&oacute; x&aacute;c định những chiến lược cần thiết trong hoạt động sản xuất.</p>\r\n<p style=\"text-align: justify;\"><strong>Hệ thống MES loại bỏ những dữ liệu kh&ocirc;ng cần thiết.</strong></p>\r\n<p style=\"text-align: justify;\">C&aacute;c doanh nghiệp quản l&yacute; điều h&agrave;nh sản xuất theo phương ph&aacute;p thủ c&ocirc;ng thường lưu lại nhiều dữ liệu thừa hoặc kh&ocirc;ng cần thiết, khiến cho bộ lưu trữ dữ liệu dễ bị qu&aacute; tải. Với khả năng ph&acirc;n t&iacute;ch tối ưu, hệ thống điều h&agrave;nh sản xuất MES ph&acirc;n biệt được những dữ liệu n&agrave;o l&agrave; kh&ocirc;ng cần thiết, xếp ch&uacute;ng v&agrave;o một nh&oacute;m dưới dạng n&eacute;n. Trong trường hợp doanh nghiệp vẫn cần sử dụng những th&ocirc;ng tin n&agrave;y, vẫn ho&agrave;n to&agrave;n c&oacute; thể t&aacute;i sử dụng lại.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>',NULL,NULL,'he-thong-dieu-hanh-san-xuat-manufacturing-execution-systems-mes-va-tam-quan-trong','Manufacturing execution systems (MES) là hệ thống máy tính – phần mềm được sử dụng trong nhà máy, dùng  để theo dõi, giám sát và lưu trữ thông tin từ vật tư đầu vào thành sản phẩm đầu ra. MES cung cấp thông tin giúp những người ra quyết định trong nhà máy hiểu được tình trạng hiện thời của nhà máy nhằm tối ưu và cải tiến hoạt đột sản xuất. Hệ thống MES làm việc trực tuyến thời gian thực để điều khiển nhiều thiết bị cùng lúc trong sản xuất. (đầu vào, con người, máy máy và dịch vụ hỗ trợ)','smart factory, Manufacturing execution systems','Published',2,NULL,1,22,'2022-01-20 03:24:50','2022-01-20 03:30:08',NULL),(62,'Ứng dụng robot tự động trong ngành công nghiệp sản xuất nội thất','2022-02-23 08:33:00','1645580443-ung-dung-robot-tu-dong-trong-nganh-cong-nghiep-san-xuat-noi-that.jpg','Trong nhiều năm, tự động hóa chỉ có thể tiếp cận được với một số ít doanh nghiệp trong ngành nội thất. Chỉ những nhà sản xuất lớn và áp dụng mô hình sản xuất hàng loạt mới có thể chuẩn bị đủ nguồn lực (tài chính, nhân sự…) cho việc bổ sung máy móc tự động. Trong khi đó các đơn bị sản xuất nhỏ hơn phần lớn đang mắc kẹt với các quy trình thủ công. Tuy nhiên, hiện nay có một lựa chọn cho các nhà sản xuất đồ nội thất đang muốn mở rộng hoạt động của họ bằng tự động hóa.','<h2 style=\"text-align: justify;\"><strong>Robot c&oacute; ph&ugrave; hợp thay thế c&aacute;c c&ocirc;ng đoạn thủ c&ocirc;ng trong sản xuất đồ nội thất kh&ocirc;ng?</strong></h2>\r\n<p style=\"text-align: justify;\">Hiện nay, nhiều người băn khoăn rằng liệu việc sử dụng robot c&oacute; thực sự ph&ugrave; hợp với c&ocirc;ng nghiệp sản xuất đồ nội thất hay kh&ocirc;ng? Từ l&acirc;u, ứng dụng robot đ&atilde; trở n&ecirc;n phổ biến trong ng&agrave;nh sản xuất &ocirc; t&ocirc; h&agrave;ng thập kỷ qua, từ những c&ocirc;ng đoạn đơn giản đến phức tạp nhất.</p>\r\n<p style=\"text-align: justify;\">Trở ngại lớn ở đ&acirc;y l&agrave; mức độ đ&aacute;p ứng về chất lượng sản phẩm tạo n&ecirc;n từ robot sẽ kh&oacute; đạt được mức độ chất lượng thường được thực hiện ho&agrave;n thiện thủ c&ocirc;ng trong ng&agrave;nh n&agrave;y từ trước đến giờ.</p>\r\n<p style=\"text-align: justify;\">Tuy nhi&ecirc;n, một trong những lợi &iacute;ch của robot l&agrave; ch&uacute;ng rất dễ th&iacute;ch nghi. Những vận h&agrave;nh chuyển động qu&aacute; phức tạp đối với tự động h&oacute;a th&ocirc;ng thường thường hiện đ&atilde; c&oacute; thể thực hiện được với robot một c&aacute;ch kh&ocirc;ng qu&aacute; kh&oacute; khăn. Th&ecirc;m nữa, theo thời gian, với sự ph&aacute;t triển&nbsp; của c&ocirc;ng nghệ, robot ng&agrave;y c&agrave;ng được lập tr&igrave;nh tinh vi hơn để c&oacute; thể &ldquo;học&rdquo; theo những thao t&aacute;c, cử chỉ phức tạp nhất với độ ch&iacute;nh x&aacute;c cao.</p>\r\n<p>&nbsp;</p>\r\n<h2 style=\"text-align: justify;\"><strong>Robot c&oacute; thể gi&uacute;p hồi sinh ng&agrave;nh nội thất</strong></h2>\r\n<p style=\"text-align: justify;\">Tất nhi&ecirc;n, mục đ&iacute;ch của việc th&ecirc;m robot v&agrave;o quy tr&igrave;nh sản xuất đồ nội thất của bạn kh&ocirc;ng phải l&agrave; để loại bỏ ho&agrave;n to&agrave;n sự tham gia của con người. Mục đ&iacute;ch của việc sử dụng robot l&agrave; để tối đa h&oacute;a thời gian v&agrave; chức năng từ c&aacute;c th&agrave;nh phần trong d&acirc;y chuyền sản xuất</p>\r\n<p style=\"text-align: justify;\">V&agrave; điều n&agrave;y thực sự quan trong khi m&agrave; trong v&agrave;i năm gần đ&acirc;y, ng&agrave;nh c&ocirc;ng nghiệp nội thất đ&atilde; xảy ra t&igrave;nh trạng thiếu hụt nh&acirc;n lực tr&igrave;nh độ cao, khiến cho việc t&igrave;m được c&aacute;c thợ thủ c&ocirc;ng l&agrave;nh nghề c&oacute; thể đảm nhiệm nhiều c&ocirc;ng đoạn trong quy tr&igrave;nh sản xuất tại &nbsp;nh&agrave; m&aacute;y trở n&ecirc;n kh&oacute; khăn hơn bao giờ hết . Đ&oacute; cũng l&agrave; 1 nh&acirc;n tố l&agrave;m giảm tốc độ ph&aacute;t triển của doanh nghiệp sản xuất nội thất.</p>\r\n<p style=\"text-align: justify;\">Robot cung cấp một giải ph&aacute;p thay thế cho việc gia c&ocirc;ng v&agrave; c&aacute;c h&igrave;nh thức tự động h&oacute;a kh&aacute;c. Ch&uacute;ng cho ph&eacute;p bạn mở rộng quy m&ocirc; sản xuất của m&igrave;nh m&agrave; kh&ocirc;ng ảnh hưởng đến chất lượng sản phẩm cũng như thương hiệu của m&igrave;nh.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<h2 style=\"text-align: justify;\"><strong>7 ứng dụng robot cho ng&agrave;nh nội thất</strong></h2>\r\n<p style=\"text-align: justify;\">Dưới đ&acirc;y l&agrave; một số ứng dụng tiềm năng cho c&aacute;c nh&agrave; sản xuất đồ nội thất đang t&igrave;m c&aacute;ch th&ecirc;m robot v&agrave;o d&acirc;y chuyển của họ. Ch&uacute;ng c&oacute; thể mang lại những lợi &iacute;ch r&otilde; r&agrave;ng ngay lập tức cho qu&aacute; tr&igrave;nh sản xuất. Ngo&agrave;i ra, n&oacute; cho ph&eacute;p người lao động tối đa h&oacute;a thời gian v&agrave; nỗ lực của họ:</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<ol style=\"text-align: justify;\">\r\n<li><strong> Phay gỗ</strong></li>\r\n</ol>\r\n<p style=\"text-align: justify;\">Phay l&agrave; nhiệm vụ cốt l&otilde;i của nhiều nh&agrave; sản xuất đồ nội thất, bất kể l&agrave; khi bạn đang cắt c&aacute;c h&igrave;nh dạng phẳng để lắp r&aacute;p sau n&agrave;y hay bạn đang đi&ecirc;u khắc c&aacute;c chi tiết 3D th&agrave;nh c&aacute;c khối vật liệu.</p>\r\n<p style=\"text-align: justify;\">Phay bằng r&ocirc;-bốt mang lại mức độ linh hoạt r&otilde; rệt so với c&aacute;c h&igrave;nh thức tự động h&oacute;a kh&aacute;c. Về cơ bản , robot phay lớn hơn m&aacute;y CNC th&ocirc;ng thường &nbsp;n&ecirc;n kh&ocirc;ng bị giới hạn bởi k&iacute;ch thước của ph&ocirc;i m&agrave; bạn c&oacute; thể sử dụng</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<ol style=\"text-align: justify;\" start=\"2\">\r\n<li><strong> Robot kiểm tra sản phẩm</strong></li>\r\n</ol>\r\n<p style=\"text-align: justify;\">Kiểm tra thường l&agrave; giai đoạn cuối c&ugrave;ng trong qu&aacute; tr&igrave;nh sản xuất. Bước n&agrave;y được thực hiện trước khi c&aacute;c sản phẩm nội thất của bạn chuyển qua c&ocirc;ng đoạn đ&oacute;ng g&oacute;i v&agrave; vận chuyển. Quy tr&igrave;nh kiểm tra tốt c&oacute; thể gi&uacute;p giảm thiểu việc l&agrave;m lại v&agrave; thu hồi sản phẩm hư hại. Do đ&oacute;, n&oacute; l&agrave;m tăng chất lượng sản phẩm v&agrave; h&igrave;nh ảnh thương hiệu của doanh nghiệp</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Robot c&oacute; thể được t&iacute;ch hợp với hệ thống quan trắc, m&aacute;y qu&eacute;t si&ecirc;u &acirc;m v&agrave; c&aacute;c cảm biến kh&aacute;c. Như vậy, n&oacute; gi&uacute;p cho bước kiểm tra sản phẩm &nbsp;trở n&ecirc;n tinh gọn, ch&iacute;nh x&aacute;c hơn.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<ol style=\"text-align: justify;\" start=\"3\">\r\n<li><strong> Robot ch&agrave; nh&aacute;m v&agrave; chuẩn bị bề mặt</strong></li>\r\n</ol>\r\n<p style=\"text-align: justify;\">Ch&agrave; nh&aacute;m v&agrave; c&aacute;c c&ocirc;ng đoạn chuẩn bị bề mặt của sản phẩm nội thất l&agrave; những c&ocirc;ng việc tốn nhiều c&ocirc;ng sức. Trong suốt một ca l&agrave;m việc d&agrave;i, độ đồng đều của qu&aacute; tr&igrave;nh ch&agrave; nh&aacute;m thủ c&ocirc;ng c&oacute; thể bị ảnh hưởng (v&igrave; phụ thuộc v&agrave;o người lao động) dẫn đến giảm chất lượng của l&ocirc; sản phẩm</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Lợi &iacute;ch to lớn của việc sử dụng r&ocirc; bốt mang lại l&agrave; ch&uacute;ng c&oacute; thể thực hiện việc ch&agrave; nh&aacute;m đảm bảo t&iacute;nh nhất qu&aacute;n của bề mặt ho&agrave;n thiện. Khi bạn đ&atilde; lập tr&igrave;nh đường đi của r&ocirc;-bốt một c&aacute;ch ch&iacute;nh x&aacute;c, r&ocirc;-bốt sẽ di chuyển để ho&agrave;n th&agrave;nh c&ocirc;ng việc tr&ecirc;n bề mặt vật liệu của nhiều sản phẩm, theo c&ugrave;ng một c&aacute;ch thức ở bất cứ thời điểm n&agrave;o.</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/UvlYur0LdIvjofrwA57UEb5ghWBmjBRiDMpAfPgw.jpeg\" alt=\"\" width=\"800\" height=\"449\" /></p>\r\n<ol start=\"4\">\r\n<li style=\"text-align: justify;\"><strong> Robot sơn v&agrave; phủ</strong></li>\r\n</ol>\r\n<p style=\"text-align: justify;\">Việc sơn thủ c&ocirc;ng thường gặp kh&oacute; khăn do lượng sơn sử dụng kh&ocirc;ng nhất qu&aacute;n. Việc người thợ sơn chậm lại d&ugrave; chỉ trong gi&acirc;y c&oacute; thể khiến họ &nbsp;sử dụng nhiều sơn hơn mức cần thiết. Điều n&agrave;y g&acirc;y l&atilde;ng ph&iacute; v&agrave; l&agrave;m giảm chất lượng của lớp sơn ho&agrave;n thiện.</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/kkzxqhKJErugJfSpSK13zhsKyG3kXaXL9Px5FuV6.jpeg\" alt=\"\" width=\"700\" height=\"380\" /></p>\r\n<p style=\"text-align: justify;\">Robot sơn l&agrave; một lựa chọn ho&agrave;n hảo để n&acirc;ng cao hiệu quả c&ocirc;ng việc sơn đồ nội thất. Nhiều m&ocirc; h&igrave;nh robot kh&aacute;c nhau được thiết kế đặc biệt cho c&aacute;c hoạt động sơn tr&ecirc;n nhiều bề mặt đa dạng, phức tạp.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<ol style=\"text-align: justify;\" start=\"5\">\r\n<li><strong> Robot gia c&ocirc;ng sản phẩm k&iacute;ch thước lớn</strong></li>\r\n</ol>\r\n<p style=\"text-align: justify;\">Một lợi &iacute;ch to lớn của việc sử dụng robot để sản xuất đồ nội thất l&agrave; kh&ocirc;ng gian l&agrave;m việc rộng lớn của ch&uacute;ng. Bạn c&oacute; thể tăng k&iacute;ch thước của hầu hết mọi kh&ocirc;ng gian l&agrave;m việc của r&ocirc; bốt chỉ bằng c&aacute;ch th&ecirc;m c&aacute;c trục bổ trợ b&ecirc;n ngo&agrave;i. Điều n&agrave;y rất hữu &iacute;ch khi bạn đang l&agrave;m việc với c&aacute;c sản phẩm nội thất lớn v&igrave; c&oacute; thể giảm c&aacute;c bước so với c&aacute;c h&igrave;nh thức tự động h&oacute;a kh&aacute;c.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Ch&uacute;ng ta c&oacute; thể thấy v&iacute; dụ về việc sử dụng gia c&ocirc;ng bằng robot để tạo ra c&aacute;c t&aacute;c phẩm đi&ecirc;u khắc với k&iacute;ch thước như người thật. Điều n&agrave;y mở ra nhiều khả năng hơn trong c&aacute;c dự &aacute;n đồ nội thất m&agrave; bạn c&oacute; thể tiếp cận trong tương lai.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<ol style=\"text-align: justify;\" start=\"6\">\r\n<li><strong> Chạm khắc đặc biệt bằng robot</strong></li>\r\n</ol>\r\n<p style=\"text-align: justify;\">Nhiều sản phẩm nội thất mang nhiều đặc điểm c&aacute; nh&acirc;n h&oacute;a, đặc trưng cho nghệ nh&acirc;n hoặc đơn vị l&agrave;m ra sản phẩm chạm khắc, hoặc d&agrave;nh ri&ecirc;ng cho 1 số người sử dụng đặc biệt hoặc thậm ch&iacute; l&agrave; c&oacute; những đặc trưng rất ri&ecirc;ng về mẫu m&atilde; sản phẩm được b&aacute;n bởi c&aacute;c nh&agrave; cung cấp kh&aacute;c nhau.</p>\r\n<p style=\"text-align: justify;\">Robot c&oacute; thể cung cấp nhiều khả năng chạm khắc, đục v&agrave; c&aacute;c h&igrave;nh thức c&aacute; nh&acirc;n h&oacute;a kh&aacute;c nhau đối với sản phẩm nội thất.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<ol style=\"text-align: justify;\" start=\"7\">\r\n<li><strong> Tối ưu h&oacute;a quy tr&igrave;nh kho vận</strong></li>\r\n</ol>\r\n<p style=\"text-align: justify;\">Thực tế c&oacute; thể c&oacute; nhiều c&ocirc;ng việc kh&aacute;c kh&ocirc;ng trực tiếp l&agrave;m tăng gi&aacute; trị cho sản phẩm nội thất nhưng cần thiết trong việc tối ưu quy tr&igrave;nh sản xuất , v&iacute; dụ c&ocirc;ng đoạn vận chuyển trong nh&agrave; m&aacute;y sản xuất nội thất. Tải c&aacute;c sản phẩm đ&oacute;ng g&oacute;i l&ecirc;n pallet l&agrave; một trong những nhiệm vụ như vậy.</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/UrvlhmTvbEzpwbXaciidzt2CMb5ldl6AjQVCS7Bk.jpeg\" alt=\"\" width=\"900\" height=\"500\" /></p>\r\n<p style=\"text-align: justify;\">Nhiều ng&agrave;nh c&ocirc;ng nghiệp sử dụng c&ocirc;ng nghệ xếp pallet bằng robot, từ đ&oacute; c&oacute; thể giảm thiểu về số lượng c&ocirc;ng nh&acirc;n cũng như mức độ rủi ro của con người trong m&ocirc;i trường l&agrave;m việc.</p>\r\n<p>&nbsp;</p>','Ứng dụng robot tự động trong ngành công nghiệp sản xuất nội thất',NULL,'ung-dung-robot-tu-dong-trong-nganh-cong-nghiep-san-xuat-noi-that','Trong nhiều năm, tự động hóa chỉ có thể tiếp cận được với một số ít doanh nghiệp trong ngành nội thất. Chỉ những nhà sản xuất lớn và áp dụng mô hình sản xuất hàng loạt mới có thể chuẩn bị đủ nguồn lực (tài chính, nhân sự…) cho việc bổ sung máy móc tự động. Trong khi đó các đơn bị sản xuất nhỏ hơn phần lớn đang mắc kẹt với các quy trình thủ công. Tuy nhiên, hiện nay có một lựa chọn cho các nhà sản xuất đồ nội thất đang muốn mở rộng hoạt động của họ bằng tự động hóa.','thiết kế nội thất, nội thất, nội thất gỗ, công nghệ gỗ, phần mềm gỗ, robot nội thất','Published',2,NULL,1,21,'2022-02-22 18:40:43','2022-02-22 18:46:43',NULL),(63,'Ứng dụng thực tế ảo tăng cường (AR) vào hoạt động kinh doanh vật liệu trang trí, hoàn thiện','2022-03-11 15:09:00','1646986678-ung-dung-thuc-te-ao-tang-cuong-ar-vao-hoat-dong-kinh-doanh-vat-lieu-trang-tri-hoan-thien.jpg','Công việc kinh doanh nội thất và sản phẩm vật liệu xây dựng ngày càng được hỗ trợ mạnh mẽ hơn với sự phát triển, tiến bộ của các công nghệ thực tế ảo tăng cường, trí tuệ nhân tạo.','<p style=\"text-align: justify;\"><strong>Thay đổi trong th&oacute;i quen mua sắm của kh&aacute;ch h&agrave;ng</strong></p>\r\n<p style=\"text-align: justify;\">Với sự b&ugrave;ng nổ của thị trường vật liệu trang tr&iacute; như v&aacute;n s&agrave;n, gạch ốp l&aacute;t, thảm trải,&hellip; ở cả trong lẫn ngo&agrave;i nước, kh&aacute;ch h&agrave;ng dường như l&agrave; người được hưởng lợi khi c&oacute; những sự đa dạng lựa chọn về m&agrave;u sắc, k&iacute;ch thước, quy c&aacute;ch, chất liệu. Tuy nhi&ecirc;n, việc lựa chọn c&aacute;c loại vật liệu trang tr&iacute;, ho&agrave;n thiện như v&aacute;n s&agrave;n, gạch ốp l&aacute;t tấm ốp tường khi lại trở n&ecirc;n kh&ocirc;ng hề dễ d&agrave;ng khi bạn như lạc giữa một &ldquo;rừng&rdquo; sản phẩm.</p>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/ZCYQhSyx0s7Nbt7VY38daAHgfuqHLV95ygq98QIw.jpeg\" alt=\"\" width=\"800\" height=\"533\" /></p>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: justify;\">Kh&aacute;ch h&agrave;ng lu&ocirc;n c&oacute; xu hướng muốn nh&agrave; cung cấp giao cho họ những sản phẩm mẫu với mục đ&iacute;ch để ngắm tận mắt sản phẩm, để đ&aacute;nh gi&aacute; ch&iacute;nh x&aacute;c xem liệu mẫu sản phẩm đ&oacute; c&oacute; thực sự ph&ugrave; hợp với kh&ocirc;ng gian ng&ocirc;i nh&agrave; của họ hay kh&ocirc;ng. V&agrave; điều n&agrave;y khiến nh&agrave; cung cấp ngốn kh&ocirc;ng &iacute;t chi ph&iacute; cho việc vận chuyển sản phẩm mẫu v&agrave; chi ph&iacute; di chuyển của nh&acirc;n vi&ecirc;n. Với sự ph&aacute;t triển của c&ocirc;ng nghệ thực tế ảo (AR) v&agrave; tr&iacute; tuệ nh&acirc;n tạo (AI), c&oacute; lẽ b&agrave;i to&aacute;n n&agrave;y của c&aacute;c nh&agrave; cung cấp vật liệu trang tr&iacute;, ho&agrave;n thiện đ&atilde; c&oacute; lời giải.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><strong>Giải ph&aacute;p diễn hoạ Floori</strong></p>\r\n<p style=\"text-align: justify;\">Được ph&aacute;t triển bới Actum Lab (Mỹ), Floori l&agrave; giải ph&aacute;p chuyển đổi số ứng dụng c&ocirc;ng nghệ thực tế ảo tăng cường (AR) v&agrave; tr&iacute; tuệ nh&acirc;n tạo (AI), hỗ trợ tối đa kh&acirc;u diễn hoạ doanh nghiệp cung cấp vật liệu trang tr&iacute;, ho&agrave;n thiện như v&aacute;n s&agrave;n, gạch ốp l&aacute;t, tấm ốp tường,&hellip;</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/rvX6kZfldfRrWoSbTekAiuS0w76cCShRkEtqat8o.jpeg\" alt=\"\" width=\"750\" height=\"381\" /></p>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: justify;\">Chỉ với một chiếc smart phone bất kỳ hay một PC-Internet c&oacute; kết nối mạng, kh&aacute;ch h&agrave;ng chỉ cần truy cập v&agrave;o website của bạn v&agrave; Floori sẽ cho ph&eacute;p kh&aacute;ch h&agrave;ng, đại l&yacute; của bạn tuỳ chỉnh, thay đổi c&aacute;c lựa chọn c&aacute;c phối cảnh kh&aacute;c nhau v&agrave; lựa chọn c&aacute;c m&atilde; sản phẩm kh&aacute;c nhau để đ&aacute;nh gi&aacute; về t&iacute;nh thẩm mỹ, ph&ugrave; hợp của sản phẩm. Đặc biệt, với AR, Floori cho ph&eacute;p kh&aacute;ch h&agrave;ng v&agrave; c&aacute;c đại l&yacute; upload kh&ocirc;ng gian thực tế của họ, Floori sẽ tự động nhận diện khu vực s&agrave;n, tấm ốp tường để hỗ trợ người d&ugrave;ng trải nghiệm c&aacute;c m&atilde; sản phẩm kh&aacute;c nhau tr&ecirc;n ch&iacute;nh kh&ocirc;ng gian ph&ograve;ng, ng&ocirc;i nh&agrave; của họ.</p>\r\n<p style=\"text-align: justify;\">Link trải nghiệm giải ph&aacute;p:&nbsp;<a href=\"https://www.cic.com.vn/testfloori/\">https://www.cic.com.vn/testfloori/</a></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><strong>Hiệu quả b&aacute;n h&agrave;ng v&agrave; &yacute; nghĩa marketing</strong></p>\r\n<p style=\"text-align: justify;\">Floori hỗ trợ kh&aacute;ch h&agrave;ng của bạn ra quyết định nhanh hơn khi chỉ trong t&iacute;ch tắc họ đ&atilde; c&oacute; thể nh&igrave;n thấy ng&ocirc;i nh&agrave;, căn ph&ograve;ng của họ ra sao sau khi được &ldquo;kho&aacute;c&rdquo; l&ecirc;n m&igrave;nh m&agrave;u &aacute;o mới bằng ch&iacute;nh sản phẩm của bạn. Theo thống k&ecirc; của Flooret, H&atilde;ng v&aacute;n s&agrave;n nổi tiếng, thuộc top doanh nghiệp v&aacute;n s&agrave;n tại Bắc Mỹ, khi ứng dụng c&aacute;c giải ph&aacute;p như Floori, doanh số hằng năm tăng từ 15-20% so với trước khi sử dụng. Tỉ lệ chuyển đổi cũng được n&acirc;ng l&ecirc;n từ 16-22% chỉ sau 1 th&aacute;ng ứng dụng.</p>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/zVW4ucJEU745eFeJK9I3xDMMUdajvPvWlteoZoiZ.jpeg\" alt=\"\" width=\"700\" height=\"354\" /></p>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: justify;\">Về &yacute; nghĩa marketing, Floori gi&uacute;p lượng truy cập v&agrave;o website của bạn tăng l&ecirc;n từ 15-22%, thời gian kh&aacute;ch h&agrave;ng ở lại website của bạn trung b&igrave;nh tăng l&ecirc;n từ 3 đến 3.5 ph&uacute;t. Đ&acirc;y l&agrave; những chỉ số quan trọng về mặt marketing m&agrave; kh&ocirc;ng phải l&uacute;c n&agrave;o c&aacute;c k&ecirc;nh như Google Adword, Facebook Ad cũng c&oacute; thể mang về cho doanh nghiệp của bạn.</p>\r\n<p style=\"text-align: justify;\">Floori chỉ l&agrave; một trong v&ocirc; số những giải ph&aacute;p chuyển đổi số m&agrave; Nghenoithat đang triển khai.</p>\r\n<p style=\"text-align: justify;\">Để t&igrave;m hiểu c&aacute;c giải ph&aacute;p chuyển đổi số mới trong ng&agrave;nh nội thất v&agrave; VLXD, vui l&ograve;ng li&ecirc;n hệ hotline của Nghề nội thất: 0868934576 hoặc email:&nbsp;<a href=\"mailto:info@nghenoithat.vn\">info@nghenoithat.vn</a>.</p>',NULL,NULL,'ung-dung-thuc-te-ao-tang-cuong-ar-vao-hoat-dong-kinh-doanh-vat-lieu-trang-tri-hoan-thien','Công việc kinh doanh nội thất và sản phẩm vật liệu xây dựng ngày càng được hỗ trợ mạnh mẽ hơn với sự phát triển, tiến bộ của các công nghệ thực tế ảo tăng cường, trí tuệ nhân tạo.','thiết kế nội thất, nội thất, nội thất gỗ, công nghệ gỗ, phần mềm gỗ','Published',2,NULL,1,30,'2022-03-11 01:17:58','2022-03-11 01:17:58',NULL),(64,'Haixun 4.0 phát hành phiên bản nâng cấp hỗ trợ xử lý các mẫu sản phẩm bo cong','2022-03-14 14:58:00','1647417935-haixun-40-phat-hanh-phien-ban-nang-cap-ho-tro-xu-ly-cac-mau-san-pham-bo-cong.png','Từ đầu tháng 3/2022 vừa qua, Hãng phần mềm Haixun chính thức cho ra mắt bản cập nhật tháng 3 với nhiều tính năng được cập nhật, cải tiến.','<p style=\"text-align: justify;\"><strong>Vấn đề khi thiết kế</strong></p>\r\n<p style=\"text-align: justify;\">C&aacute;c mẫu tủ quần &aacute;o k&egrave;m hệ kệ liền tủ hiện nay trở n&ecirc;n rất phổ biến trong xu hướng thiết kế nội thất v&igrave; sự đơn giản, tiện lợi, tiết kiệm diện t&iacute;ch nhưng vẫn đảm bảo t&iacute;nh thời thượng, thẩm mỹ. Tuy nhi&ecirc;n phần lớn c&aacute;c phần mềm thiết kế đồ nội thất gỗ c&ocirc;ng nghiệp hiện nay chưa thể xử l&yacute; được c&aacute;c chi tiết c&oacute; bề mặt được bo cong, cần phải xẻ r&atilde;nh trước khi uốn.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/9xauUsZK1nqQGq5JMyP5qf7LPLxK8UQLDjLXPWen.png\" alt=\"\" width=\"650\" height=\"361\" /></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Thấu hiểu vấn đề n&agrave;y, sau khi lắng nghe &yacute; kiến phản hồi từ người d&ugrave;ng, đầu th&aacute;ng 3/2022 vừa qua, H&atilde;ng phần mềm Haixun ch&iacute;nh thức cho ra mắt bản cập nhật th&aacute;ng 3 với nhiều t&iacute;nh năng được cập nhật, cải tiến, trong đ&oacute; c&oacute; t&iacute;nh năng hỗ trợ xử l&yacute; c&aacute;c chi tiết bo cong.</p>\r\n<p style=\"text-align: justify;\">B&ecirc;n cạnh việc cải thiện n&acirc;ng cao hiệu xuất xử l&yacute; của phần mềm, ở bản n&acirc;ng cấp lần n&agrave;y, Haixun 4.0 cung cấp c&ocirc;ng cụ hỗ trợ thiết kế v&agrave; gia c&ocirc;ng c&aacute;c chi tiết bo cong tr&ecirc;n c&aacute;c sản phẩm nội thất. Đ&acirc;y l&agrave; t&iacute;nh năng nổi bật ở bản update lần n&agrave;y.</p>\r\n<p style=\"text-align: justify;\">Với t&iacute;nh năng n&agrave;y, người d&ugrave;ng ho&agrave;n to&agrave;n c&oacute; thể dễ d&agrave;ng tạo h&igrave;nh cũng như lập tr&igrave;nh gia c&ocirc;ng xẻ r&atilde;nh trước khi uốn với bộ chi tiết c&oacute; sẵn trong thư viện. Sau khi điều chỉnh c&aacute;c k&iacute;ch thước cần thiết, ch&uacute;ng ta sẽ c&oacute; được mẫu kệ ho&agrave;n chỉnh đ&aacute;p ứng được y&ecirc;u cầu thiết kế ban đầu.</p>\r\n<p style=\"text-align: justify;\">T&iacute;nh năng n&agrave;y của Haixun 4.0 chắc chắn sẽ gi&uacute;p cho c&aacute;c nh&agrave; sản xuất nội thất y&ecirc;n t&acirc;m xử l&yacute; c&aacute;c mẫu sản phẩm bo cong phức tạp m&agrave; kh&ocirc;ng cần phải sử dụng đến bất cứ một giải ph&aacute;p thay thế n&agrave;o kh&aacute;c.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><strong>C&aacute;ch thực hiện trong Haixun 4.0</strong></p>\r\n<p style=\"text-align: justify;\">Bước 1: Ở một mẫu tủ bất kỳ, chọn kh&ocirc;ng gian cần th&ecirc;m tấm</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/oA4jnoJYuzsjCqB4k5pFa09vq0bqb75qqeLczgqt.png\" alt=\"\" width=\"650\" height=\"365\" /></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Bước 2: Chọn tới thư mực M&ocirc; đun hệ thống -&gt; Tấm gờ ch&acirc;n -&gt;&nbsp; Tấm gờ ch&acirc;n v&ograve;ng cung (tr&aacute;i/phải)</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/KLBtaSVhSqw2lt2NWXhAV5GmPIYCXBOaL8T220TL.png\" alt=\"\" width=\"650\" height=\"365\" /></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Bước 3: Điền th&ocirc;ng số ph&ugrave; hợp v&agrave; nhấn X&aacute;c định</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/YbWJGuDGxj4Rn9euDqFXT0UWxoGITBh3SFQcJhC0.png\" alt=\"\" width=\"650\" height=\"365\" /></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Giải th&iacute;ch c&aacute;c th&ocirc;ng số:</p>\r\n<p style=\"text-align: justify;\"><strong>+&nbsp; B&aacute;n k&iacute;nh v&ograve;ng cung</strong>: B&aacute;n k&iacute;nh v&ograve;ng cung của tấm cần uốn</p>\r\n<p style=\"text-align: justify;\"><strong>+ Độ d&agrave;y tấm gờ ch&acirc;n:</strong>&nbsp;Độ d&agrave;y tấm bo cần th&ecirc;m</p>\r\n<p style=\"text-align: justify;\"><strong>+ Tăng độ d&agrave;i</strong>: Độ d&agrave;i cần th&ecirc;m trước khi uốn</p>\r\n<p style=\"text-align: justify;\"><strong>+ Khoảng c&aacute;ch r&atilde;nh</strong>: K&iacute;ch thước giữa c&aacute;c r&atilde;nh xẻ</p>\r\n<p style=\"text-align: justify;\"><strong>+ Độ rộng r&atilde;nh</strong>: K&iacute;ch thước r&atilde;nh theo chiều d&agrave;i tấm</p>\r\n<p style=\"text-align: justify;\"><strong>+ Độ s&acirc;u r&atilde;nh:</strong>&nbsp;Chiều s&acirc;u r&atilde;nh cần xẻ</p>\r\n<p style=\"text-align: justify;\"><strong>+ Mở r&atilde;nh (0/1):</strong>&nbsp;Lựa chọn mở r&atilde;nh hay kh&ocirc;ng</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Bước 4:&nbsp;&nbsp;Kết quả</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/3isT0GqewSNgryC12hhXcX8G1O8j7YBT6t3RQRjX.png\" alt=\"\" width=\"650\" height=\"365\" /></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">H&igrave;nh ảnh tấm bo cong trong Haixun sản xuất</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/p1ALBIdD3SzBkGFP59OPW0EB6HrgNhUp4xPxkuVW.png\" alt=\"\" width=\"650\" height=\"350\" /></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Để được hỗ trợ n&acirc;ng cấp, hướng dẫn trong qu&aacute; tr&igrave;nh sử dụng&nbsp;<a href=\"https://www.haixun.vn/\">Haixun 4.0</a>, Qu&yacute; kh&aacute;ch h&agrave;ng vui l&ograve;ng li&ecirc;n hệ hotline: 0868934576.</p>','Haixun 4.0 phát hành phiên bản nâng cấp hỗ trợ xử lý các mẫu sản phẩm bo cong',NULL,'haixun-40-phat-hanh-phien-ban-nang-cap-ho-tro-xu-ly-cac-mau-san-pham-bo-cong','Từ đầu tháng 3/2022 vừa qua, Hãng phần mềm Haixun chính thức cho ra mắt bản cập nhật tháng 3 với nhiều tính năng được cập nhật, cải tiến.','thiết kế nội thất, nội thất, nội thất gỗ, công nghệ gỗ, phần mềm gỗ','Published',2,NULL,1,31,'2022-03-16 01:05:35','2022-03-16 01:05:35',NULL),(65,'CIC chuyển giao công nghệ thực tế ảo tăng cường (AR) cho thương hiệu sàn gỗ Hàn Quốc Dongwha tại triển lãm Vietbuild Hanoi 2022','2022-03-19 16:11:00','1647940395-cic-chuyen-giao-cong-nghe-thuc-te-ao-tang-cuong-ar-cho-thuong-hieu-san-go-han-quoc-dongwha-tai-trien-lam-vietbuild-hanoi-2022.jpg','Từ ngày 23-27/3 sắp tới tại Cung Triển lãm Kiến trúc Xây dựng Quốc gia, CIC chuyển giao công nghệ thực tế ảo tăng cường (AR) cho thương hiệu sàn gỗ Hàn Quốc Donghwa sử dụng ngay tại Triển lãm.','<p style=\"text-align: justify;\">S&agrave;n gỗ Dongwha l&agrave; thương hiệu s&agrave;n gỗ nổi tiếng đến từ H&agrave;n Quốc với chất lượng vượt trội v&agrave; lu&ocirc;n lu&ocirc;n theo đuổi những gi&aacute; trị thực &ndash; đem đến người ti&ecirc;u d&ugrave;ng sản phẩm S&agrave;n gỗ c&oacute; chất lượng v&agrave; gi&aacute; th&agrave;nh tốt nhất, với ước mơ đưa S&agrave;n gỗ Dongwha trở th&agrave;nh thương hiệu h&agrave;ng đầu trong ng&agrave;nh c&ocirc;ng nghiệp S&agrave;n gỗ.</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/o5KicoMWGEZ9tbULXfCSWCrwN7alzpSSR2lFcAwj.jpeg\" alt=\"\" width=\"650\" height=\"329\" /></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Nhằm n&acirc;ng cao chất lượng b&aacute;n h&agrave;ng, tư vấn kh&aacute;ch h&agrave;ng v&agrave; trải nghiệm của người d&ugrave;ng, S&agrave;n gỗ Dongwha đ&atilde; quyết định triển khai c&ocirc;ng nghệ thực tế ảo tăng cường (AR) ngay tại Triển l&atilde;m Vietbuild lần n&agrave;y. CIC vinh dự l&agrave; đơn vị được đồng h&agrave;nh v&agrave; l&agrave; nh&agrave; cung cấp giải ph&aacute;p cho S&agrave;n gỗ Dongwha.</p>\r\n<p style=\"text-align: justify;\">C&ocirc;ng nghệ thực tế ảo tăng cường (AR) cho ph&eacute;p kh&aacute;ch h&agrave;ng c&oacute; thể trải nghiệm sản phẩm s&agrave;n gỗ của thương hiệu Dongwha ngay tr&ecirc;n ch&iacute;nh kh&ocirc;ng gian ph&ograve;ng, căn nh&agrave; của m&igrave;nh, từ đ&oacute; gi&uacute;p kh&aacute;ch h&agrave;ng c&oacute; thể y&ecirc;n t&acirc;m với yếu tố thẩm mĩ, sự ph&ugrave; hợp về m&agrave;u sắc, chất liệu của mẫu v&aacute;n s&agrave;n m&agrave; m&igrave;nh đ&atilde; lựa chọn.</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/HCmH8xGVBNvzmKlgsMarLsrQvh2IKLvDLGeO80q8.jpeg\" alt=\"\" width=\"900\" height=\"499\" /></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">K&iacute;nh mời qu&yacute; Kh&aacute;ch h&agrave;ng, đối t&aacute;c tới tham quan gian h&agrave;ng của S&agrave;n gỗ Dongwha v&agrave; trải nghiệm c&ocirc;ng nghệ thực tế ảo tăng cường do CIC cung cấp tại:</p>\r\n<p style=\"text-align: justify;\">TRIỂN L&Atilde;M QUỐC TẾ VIETBUILD H&Agrave; NỘI 2022 &ndash; LẦN 1</p>\r\n<p style=\"text-align: justify;\">C&aacute;c sản phẩm tham dự: Bộ sưu tập Dongwha Natus, Dongwha Sanus, Dongwha Herringbone</p>\r\n<p style=\"text-align: justify;\">Thời gian: 23/03/2022 &ndash; 27/03/2022</p>\r\n<p style=\"text-align: justify;\">Địa điểm: Cung Triển l&atilde;m Kiến tr&uacute;c X&acirc;y dựng Quốc gia &ndash; 01 Đỗ Đức Dục, quận Nam Từ Li&ecirc;m, H&agrave; Nội.</p>\r\n<p style=\"text-align: justify;\">Vị tr&iacute; gian h&agrave;ng: Khu A1 &ndash; gian h&agrave;ng: 82-83-84-85-86-87.</p>\r\n<p style=\"text-align: justify;\">Vietbuild H&agrave; Nội 2022 với chủ đề: &ldquo;X&acirc;y dựng, vật liệu x&acirc;y dựng, kiến tr&uacute;c, bất động sản v&agrave; trang tr&iacute; nội thất, ngoại thất&rdquo; với 1500 gian h&agrave;ng hứa hẹn sẽ l&agrave; nơi gi&uacute;p qu&yacute; kh&aacute;ch h&agrave;ng, đối t&aacute;c tham quan, trải nghiệm những sản phẩm hiện đại nhất tr&ecirc;n thị trường hiện nay.</p>\r\n<p style=\"text-align: justify;\">Mọi th&ocirc;ng tin chi tiết về giải ph&aacute;p, Qu&yacute; kh&aacute;ch h&agrave;ng vui l&ograve;ng li&ecirc;n hệ về Trung t&acirc;m Giải ph&aacute;p c&ocirc;ng nghệ ng&agrave;nh Nội thất v&agrave; VLXD, C&ocirc;ng ty Cổ phần C&ocirc;ng nghệ v&agrave; Tư vấn CIC để được hỗ trợ v&agrave; giải đ&aacute;p.</p>\r\n<p style=\"text-align: justify;\">Hotline: 0868.934.576/ 0866.059.659</p>','CIC chuyển giao công nghệ thực tế ảo tăng cường (AR) cho thương hiệu sàn gỗ Hàn Quốc Dongwha tại triển lãm Vietbuild Hanoi 2022',NULL,'cic-chuyen-giao-cong-nghe-thuc-te-ao-tang-cuong-ar-cho-thuong-hieu-san-go-han-quoc-dongwha-tai-trien-lam-vietbuild-hanoi-2022','Từ ngày 23-27/3 sắp tới tại Cung Triển lãm Kiến trúc Xây dựng Quốc gia, CIC chuyển giao công nghệ thực tế ảo tăng cường (AR) cho thương hiệu sàn gỗ Hàn Quốc Donghwa sử dụng ngay tại Triển lãm.',NULL,'Published',2,NULL,1,31,'2022-03-22 02:13:15','2022-03-22 02:13:15',NULL),(66,'Chương trình hội thảo trực tuyến “Giới thiệu và hướng dẫn tính năng cập nhật của phần mềm Cabinet Vision bản quyền 2022”','2022-03-24 13:36:00','1648190364-chuong-trinh-hoi-thao-truc-tuyen-gioi-thieu-va-huong-dan-tinh-nang-cap-nhat-cua-phan-mem-cabinet-vision-ban-quyen-2022.jpg','Cabinet Vision là công cụ phần mềm hàng đầu trong ngành để thiết kế và sản xuất tủ bếp, tủ áo, đồ dùng thương mại và hơn thế nữa. Phiên bản Cabinet Vision 2022 đã được ra mắt với nhiều tính năng vượt trội và ưu việt.','<p style=\"text-align: justify;\">Được ph&aacute;t triển bởi h&atilde;ng phần mềm Vero Software từ năm 1990, phần mềm Cabinet Vision đ&atilde; trở th&agrave;nh một trong số những giải ph&aacute;p thiết kế v&agrave; sản xuất nội thất gỗ c&ocirc;ng nghiệp h&agrave;ng đầu trong lĩnh vực với rất nhiều tiện &iacute;ch, t&iacute;nh năng vượt trội. Trải qua, hơn 30 năm ph&aacute;t triển, Cabinet Vision đ&atilde; c&oacute; hơn 35.000 người trải d&agrave;i ở hơn 52 quốc gia tr&ecirc;n thế giới.</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/BffOynFCodClmU1t6Gi6HMS0I478y3A9rT7tpEMi.jpeg\" alt=\"\" width=\"600\" height=\"338\" /></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Cabinet Vision nổi bật với c&aacute;c t&iacute;nh năng như: thiết kế tủ bếp, thiết kế ph&ograve;ng, xuất bản vẽ phối cảnh, tối ưu h&oacute;a vật liệu, xuất bảng b&aacute;o gi&aacute; v&agrave; chi ph&iacute; sản xuất, chi tiết bản vẽ cắt v&aacute;n v&agrave; h&oacute;a đơn nguy&ecirc;n vật liệu. Kết hợp với S2M Center mạnh mẽ, phần mềm tự động xuất ra file G-Code chạy cho c&aacute;c d&ograve;ng m&aacute;y CNC Nesting tr&ecirc;n thị trường, m&aacute;y P2P (point-to-point machines), v&agrave; c&aacute;c d&ograve;ng m&aacute;y CNC chuy&ecirc;n dụng kh&aacute;c.</p>\r\n<p style=\"text-align: justify;\">Đầu năm 2022, H&atilde;ng phần mềm Cabinet Vision cho ra mắt phi&ecirc;n bản 2022. B&ecirc;n cạnh việc cải thiện hiệu năng, thuật to&aacute;n xử l&yacute;, Cabinet Vision 2022 cũng bổ sung, n&acirc;ng cấp h&agrave;ng loạt c&aacute;c t&iacute;nh năng mới so với phi&ecirc;n bản trước đ&oacute;.</p>\r\n<p style=\"text-align: justify;\">Nhằm hỗ trợ kh&aacute;ch h&agrave;ng, người d&ugrave;ng tại thị trường Việt Nam, H&atilde;ng phần mềm Cabinet Vision v&agrave; C&ocirc;ng ty Cổ phần C&ocirc;ng nghệ v&agrave; Tư vấn CIC với tư c&aacute;ch đại l&yacute; uỷ quyền của h&atilde;ng tại Việt Nam tr&acirc;n trọng tổ chức chương tr&igrave;nh Hội thảo online với chủ đề &ldquo;Giới thiệu v&agrave; hướng dẫn t&iacute;nh năng cập nhật của phần mềm Cabinet Vision bản quyền 2022&rdquo; với nhiều nội dung hấp dẫn.</p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/eZM5lxatqdhzRBcSaTUrB4F0VXCl2gWcgYSJJk9n.jpeg\" alt=\"\" width=\"700\" height=\"389\" /></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p>Buổi hội thảo sẽ bao gồm c&aacute;c nội dung ch&iacute;nh như sau:</p>\r\n<p><em><strong>Phần 1:</strong> </em>Giới thiệu chung v&agrave; Giới thiệu th&agrave;nh phần tham dự</p>\r\n<p><em><strong>Phần 2:</strong></em> Giới thiệu giải ph&aacute;p Cabinet Vision</p>\r\n<p>- Giới thiệu về điểm nổi bật của Cabinet Vision;</p>\r\n<p>- Giới thiệu t&iacute;nh năng cập nhật tại phi&ecirc;n bản CV 2022;</p>\r\n<p><em><strong>Phần 3:</strong></em> Hỏi v&agrave; đ&aacute;p</p>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: justify;\">Hội thảo dự kiến được tổ chức v&agrave;o 9h s&aacute;ng, thứ s&aacute;u ng&agrave;y 8/4/2022 theo h&igrave;nh thức trực tuyến tr&ecirc;n nền tảng Zoom. Đặc biệt, BTC sẽ cung cấp v&agrave; hỗ trợ bản d&ugrave;ng thử miễn ph&iacute; Cabinet Vision bản quyền phi&ecirc;n bản 2022 đối với 20 đơn vị đăng k&yacute; đầu ti&ecirc;n.</p>\r\n<p style=\"text-align: justify;\">Qu&yacute; kh&aacute;ch h&agrave;ng quan t&acirc;m vui l&ograve;ng đăng k&yacute; tại đ&acirc;y. Mọi th&ocirc;ng tin chi tiết về chương tr&igrave;nh hội thảo, xin vui l&ograve;ng li&ecirc;n hệ Trung t&acirc;m GPCN ng&agrave;nh Nội thất v&agrave; VLXD (TIB-CIC) theo hotline: 0866059659 để được hỗ trợ.</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>','Chương trình hội thảo trực tuyến “Giới thiệu và hướng dẫn tính năng cập nhật của phần mềm Cabinet Vision bản quyền 2022”',NULL,'chuong-trinh-hoi-thao-truc-tuyen-gioi-thieu-va-huong-dan-tinh-nang-cap-nhat-cua-phan-mem-cabinet-vision-ban-quyen-2022','Cabinet Vision là công cụ phần mềm hàng đầu trong ngành để thiết kế và sản xuất tủ bếp, tủ áo, đồ dùng thương mại và hơn thế nữa. Phiên bản Cabinet Vision 2022 đã được ra mắt với nhiều tính năng vượt trội và ưu việt.',NULL,'Published',2,NULL,1,40,'2022-03-24 23:39:24','2022-06-12 23:37:48',NULL),(67,'CIC hỗ trợ Cửa nhôm Việt Úc triển khai phần mềm chuyên dụng cho thiết kế, bóc tách vật tư và gia công nhôm kính OPERA','2022-05-20 08:56:00','1653443955-cic-ho-tro-cua-nhom-viet-uc-trien-khai-phan-mem-chuyen-dung-cho-thiet-ke-boc-tach-vat-tu-va-gia-cong-nhom-kinh-opera.jpg','Mới đây, Công ty CIC đã ký hợp đồng và hoàn tất quá trình chuyển giao, đào tạo phần mềm nhôm kính OPERA cho Công ty TNHH Sản Xuất Thương Mại Cửa Nhôm Việt Úc.','<p style=\"text-align: justify;\">C&ocirc;ng ty TNHH Sản Xuất Thương Mại Cửa Nh&ocirc;m Việt &Uacute;c l&agrave; một trong những c&ocirc;ng ty h&agrave;ng đầu Việt Nam về thầu nh&ocirc;m k&iacute;nh với nh&agrave; xưởng m&aacute;y m&oacute;c hiện đại, đ&aacute;p ứng hầu hết c&aacute;c ti&ecirc;u chuẩn về kỹ thuật, an to&agrave;n sản xuất. Trong đ&oacute;, Cửa Việt &Uacute;c tập trung v&agrave;o d&ograve;ng sản phẩm cửa nh&ocirc;m kết hợp lưới chống muỗi với dải sản phẩm đa dạng v&agrave; chất lượng.&nbsp;</p>\r\n<p style=\"text-align: center;\"><img src=\"https://www.cic.com.vn/upload_images/images/2022/05/20/1.jpg\" alt=\"\" /></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">Nhằm n&acirc;ng cao hiệu quả c&ocirc;ng việc, hỗ trợ tối đa c&ocirc;ng t&aacute;c b&oacute;c t&aacute;ch vật tư v&agrave; sản xuất, đồng thời hiện đại h&oacute;a hệ thống sản xuất, tăng năng xuất lao động v&agrave; n&acirc;ng cao chất lượng sản phẩm, Việt &Uacute;c đ&atilde; tin tưởng sử dụng phần mềm&nbsp;<a href=\"/san-pham/phan-mem-thiet-ke-gia-cong-nhom-kinh-opera\"><strong>OPERA</strong></a>&nbsp;v&agrave; CIC vinh dự l&agrave; đơn vị được đồng h&agrave;nh cung cấp.</p>\r\n<p style=\"text-align: center;\"><img src=\"https://www.cic.com.vn/upload_images/images/2022/05/20/2.jpg\" alt=\"\" /></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\">H&atilde;ng phần mềm&nbsp;<a href=\"/san-pham/phan-mem-thiet-ke-gia-cong-nhom-kinh-opera\"><strong>OPERA </strong></a>c&oacute; trụ sở tại Sardinia,&Yacute; với hơn 30 năm kinh nghiệm trong lĩnh vực ph&aacute;t triển c&aacute;c giải ph&aacute;p phần mềm trong lĩnh vực thầu nh&ocirc;m k&iacute;nh. Hiện nay,<strong>&nbsp;<a href=\"/san-pham/phan-mem-thiet-ke-gia-cong-nhom-kinh-opera\">OPERA</a></strong>&nbsp;c&oacute; mạng lưới kh&aacute;ch h&agrave;ng rộng lớn với hơn 10.000 kh&aacute;ch h&agrave;ng, trải khắp tr&ecirc;n 70 quốc gia tr&ecirc;n to&agrave;n thế giới.&nbsp;</p>\r\n<p style=\"text-align: justify;\"><a href=\"/san-pham/phan-mem-thiet-ke-gia-cong-nhom-kinh-opera\"><strong>Phần mềm OPERA</strong></a>&nbsp;&aacute;p dụng được cho đa dạng c&aacute;c loại nh&ocirc;m như PMI, PMA, AEI, Eurovn, Huyndai, Việt Ph&aacute;p, Việt Nhật, Austdoor, Topal, Bosswindow, Đ&ocirc;ng &Aacute;,&hellip; Với phần mềm&nbsp;<strong><a href=\"/san-pham/phan-mem-thiet-ke-gia-cong-nhom-kinh-opera\">OPERA</a></strong>, tất cả c&aacute;c kh&acirc;u dự to&aacute;n, b&aacute;o gi&aacute;, t&iacute;nh to&aacute;n gia c&ocirc;ng sẽ được tự động h&oacute;a với tốc độ nhanh ch&oacute;ng v&agrave; t&iacute;nh ch&iacute;nh x&aacute;c cao. V&igrave; vậy sẽ gi&uacute;p qu&aacute; tr&igrave;nh sản xuất nh&ocirc;m k&iacute;nh của c&aacute;c doanh nghiệp trong ng&agrave;nh n&agrave;y thuận lợi hơn, năng suất hơn, chất lượng sản phẩm tuyệt vời hơn.</p>\r\n<p style=\"text-align: justify;\">Để t&igrave;m hiểu th&ecirc;m về phần mềm thiết kế v&agrave; sản xuất nh&ocirc;m k&iacute;nh&nbsp;<strong><a href=\"/san-pham/phan-mem-thiet-ke-gia-cong-nhom-kinh-opera\">OPERA</a></strong>&nbsp;v&agrave; c&aacute;c giải ph&aacute;p chuyển đổi số mới trong ng&agrave;nh nội thất v&agrave; VLXD, Qu&yacute; kh&aacute;ch h&agrave;ng vui l&ograve;ng li&ecirc;n hệ:<br /><strong>Hotline:&nbsp;</strong>0866.059.659<br /><strong>Email:</strong>&nbsp;info@cic.com.vn.</p>','CIC hỗ trợ Cửa nhôm Việt Úc triển khai phần mềm chuyên dụng cho thiết kế, bóc tách vật tư và gia công nhôm kính OPERA',NULL,'cic-ho-tro-cua-nhom-viet-uc-trien-khai-phan-mem-chuyen-dung-cho-thiet-ke-boc-tach-vat-tu-va-gia-cong-nhom-kinh-opera','Mới đây, Công ty CIC đã ký hợp đồng và hoàn tất quá trình chuyển giao, đào tạo phần mềm nhôm kính OPERA cho Công ty TNHH Sản Xuất Thương Mại Cửa Nhôm Việt Úc.',NULL,'Published',2,NULL,1,40,'2022-05-24 18:59:15','2022-06-12 23:37:35',NULL),(68,'CIC chuyển giao công nghệ thực tế ảo tăng cường hỗ trợ bán hàng và marketing sản phẩm ván sàn cho thương hiệu Janhome','2022-05-30 14:09:00','1653894666-cic-chuyen-giao-cong-nghe-thuc-te-ao-tang-cuong-ho-tro-ban-hang-va-marketing-san-pham-van-san-cho-thuong-hieu-janhome.jpg','Vào đầu tháng 5 vừa qua, CIC đã ký hợp đồng chuyển giao cho Công ty Cổ phần Xuất nhập khẩu Tháng Giêng (Janco) giải pháp Floori, hỗ trợ sale & marketing ván sàn.','<p style=\"text-align: center;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><img src=\"/storage/uploads/tinymce/6otXoKqehhK3NTeIEXwygLp4Fsx4CZZlSKujzDWZ.jpeg\" alt=\"\" width=\"447\" height=\"113\" /></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">C&ocirc;ng ty CP Xuất nhập khẩu Th&aacute;ng Gi&ecirc;ng nổi tiếng với thương hiệu Janhome l&agrave; một trong số những đơn vị đầu ng&agrave;nh trong lĩnh vực nhập khẩu v&agrave; ph&acirc;n phối sản phẩm s&agrave;n gỗ c&ocirc;ng nghiệp với mẫu m&atilde; đa dạng, sản phẩm chất lượng.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Nhằm mang lại cho kh&aacute;ch h&agrave;ng c&aacute;ch thức trải nghiệm sản phẩm mới trực quan, mới lạ v&agrave; đẩy mạnh hiệu quả của hoạt động sale marketing, Janco với thương hiệu Janhome đ&atilde; quyết định sử dụng giải ph&aacute;p&nbsp;<a href=\"https://www.cic.com.vn/san-pham/floori-giai-phap-chuyen-doi-so-trong-kinh-doanh-van-san-gach-da-op-lat-p307.html\">Floori</a>&nbsp;do C&ocirc;ng ty Cổ phần C&ocirc;ng nghệ v&agrave; Tư vấn CIC cung cấp. Giải ph&aacute;p n&agrave;y gi&uacute;p kh&aacute;ch h&agrave;ng c&oacute; thể tự trải nghiệm những mẫu v&aacute;n s&agrave;n hay c&aacute;c mẫu gạch ốp l&aacute;t tr&ecirc;n ch&iacute;nh kh&ocirc;ng gian của họ.</span></p>\r\n<p style=\"text-align: center;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><img src=\"/storage/uploads/tinymce/jgBuS1gAgL8nUUQKQhmPRNBsVH4SYYet6QPTWhAw.jpeg\" alt=\"\" width=\"700\" height=\"389\" /></span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Janco l&agrave; đơn vị đầu ti&ecirc;n tại Việt Nam ứng dụng c&ocirc;ng nghệ thực tế ảo tăng cường v&agrave;o hoạt động kinh doanh v&agrave; marketing sản phẩm v&aacute;n s&agrave;n.&nbsp;<a href=\"https://www.cic.com.vn/san-pham/floori-giai-phap-chuyen-doi-so-trong-kinh-doanh-van-san-gach-da-op-lat-p307.html\">Floori</a>&nbsp;được k&igrave; vọng sẽ gi&uacute;p Janco n&acirc;ng cao trải nghiệm v&agrave; mang đến sự h&agrave;i l&ograve;ng cho kh&aacute;ch h&agrave;ng của m&igrave;nh.&nbsp;</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Bằng c&ocirc;ng nghệ AI v&agrave; AR ưu việt,&nbsp;<a href=\"https://www.cic.com.vn/san-pham/floori-giai-phap-chuyen-doi-so-trong-kinh-doanh-van-san-gach-da-op-lat-p307.html\">Floori</a>&nbsp;mang đến cho doanh nghiệp sản xuất v&agrave; kinh doanh v&aacute;n s&agrave;n, gạch đ&aacute; ốp l&aacute;t một c&ocirc;ng cụ hỗ trợ sale v&agrave; marketing cực k&igrave; hiệu quả.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Để t&igrave;m hiểu c&aacute;c giải ph&aacute;p chuyển đổi số mới trong ng&agrave;nh nội thất v&agrave; VLXD, vui l&ograve;ng li&ecirc;n hệ hotline: 0866.059.659 hoặc email: info@cic.com.vn.</span></p>','CIC chuyển giao công nghệ thực tế ảo tăng cường hỗ trợ bán hàng và marketing sản phẩm ván sàn cho thương hiệu Janhome',NULL,'cic-chuyen-giao-cong-nghe-thuc-te-ao-tang-cuong-ho-tro-ban-hang-va-marketing-san-pham-van-san-cho-thuong-hieu-janhome','Vào đầu tháng 5 vừa qua, CIC đã ký hợp đồng chuyển giao cho Công ty Cổ phần Xuất nhập khẩu Tháng Giêng (Janco) giải pháp Floori, hỗ trợ sale & marketing ván sàn.','thiết kế nội thất, nội thất, nội thất gỗ, công nghệ gỗ, phần mềm thực tế ảo','Published',2,NULL,1,40,'2022-05-30 00:11:06','2022-06-12 23:37:20',NULL),(69,'EUROHA triển khai phần mềm OPERA - phần mềm chuyên dụng cho thiết kế, bóc tách vật tư và gia công cửa sổ, cửa đi và hệ mặt dựng nhôm kính','2022-06-13 14:34:00','1655105674-euroha-trien-khai-phan-mem-opera-phan-mem-chuyen-dung-cho-thiet-ke-boc-tach-vat-tu-va-gia-cong-cua-so-cua-di-va-he-mat-dung-nhom-kinh.jpg','Mới đây, Nghenoithat.vn (thuộc Công ty CP Công nghệ và Tư vấn CIC) và EUROHA đã ký kết hợp đồng chuyển giao phần mềm chuyên dụng hỗ trợ thiết kế, bóc tách vật tư và gia công cửa sổ, cửa đi và hệ mặt dựng nhôm kính, Opera Job Management.','<h2 style=\"text-align: justify;\"><strong><span style=\"font-size: 14pt; font-family: \'times new roman\', times, serif;\">Về EUROHA</span></strong></h2>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 14pt; font-family: \'times new roman\', times, serif;\">L&agrave; th&agrave;nh vi&ecirc;n của Nam Hải Group, EUROHA l&agrave; một trong số c&aacute;c nh&agrave; sản xuất thanh nh&ocirc;m định h&igrave;nh phục vụ x&acirc;y dựng h&agrave;ng đầu tr&ecirc;n cả nước với những thương hiệu nổi tiếng như Nam Hải Aluminum, Euroha Aluminum, EUA Aluminum. EUROHA sở hữu nh&agrave; m&aacute;y đ&ugrave;n nh&ocirc;m với quy m&ocirc; l&ecirc;n đến hơn 30.000 m2 c&ugrave;ng hệ thống m&aacute;y m&oacute;c, trang thiết bị, d&acirc;y chuyền sản xuất hiện đại được đầu tư b&agrave;i bản.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 14pt; font-family: \'times new roman\', times, serif;\">Với mục ti&ecirc;u tối ưu quy tr&igrave;nh l&agrave;m việc, tiết kiệm lượng thời gian b&oacute;c t&aacute;ch v&agrave; n&acirc;ng cao t&iacute;nh ch&iacute;nh x&aacute;c trong qu&aacute; tr&igrave;nh sản xuất, EUROHA đ&atilde; lựa chọn sử dụng phần mềm Opera Job Management để hỗ trợ kh&acirc;u b&oacute;c t&aacute;ch vật tư, b&aacute;o gi&aacute; v&agrave; kết nối sản xuất. CIC với vai tr&ograve; l&agrave; đại l&yacute; uỷ quyền của H&atilde;ng phần mềm Opera Job Management tại Việt Nam vinh dự được đồng h&agrave;ng c&ugrave;ng EUROHA.</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong><a href=\"/san-pham/phan-mem-thiet-ke-gia-cong-nhom-kinh-opera\">Về phần mềm nh&ocirc;m k&iacute;nh Opera</a></strong></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 14pt; font-family: \'times new roman\', times, serif;\">Với bề d&agrave;y kinh nghiệm trong việc ph&aacute;t triển c&aacute;c phần mềm thuộc lĩnh vực thầu nh&ocirc;m k&iacute;nh, Opera sở hữu mạng lưới kh&aacute;ch h&agrave;ng v&ocirc; c&ugrave;ng rộng lớn &nbsp;trải rộng tr&ecirc;n to&agrave;n thế giới: khoảng 10.000 kh&aacute;ch h&agrave;ng tại 70 quốc gia.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 14pt; font-family: \'times new roman\', times, serif;\">Phần mềm Opera Job Management n&acirc;ng cao hiệu quả c&ocirc;ng việc trong c&aacute;c kh&acirc;u dự to&aacute;n, b&aacute;o gi&aacute;, kiểm so&aacute;t chi ph&iacute; thực hiện dự &aacute;n một c&aacute;ch ch&iacute;nh x&aacute;c, hỗ trợ xuất hồ sơ sản xuất, quản l&yacute; kho vật tư,&hellip; B&ecirc;n cạnh đ&oacute;, Opera Job Management tương th&iacute;ch với nhiều hệ nh&ocirc;m kh&aacute;c nhau từ Xingfa, Topal, PMI,&hellip; cho đến c&aacute;c hệ nh&ocirc;m cao cấp như Shuco, Technal,&hellip;</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 14pt; font-family: \'times new roman\', times, serif;\">Ch&iacute;nh v&igrave; thế, qu&aacute; tr&igrave;nh sản xuất của c&aacute;c đơn vị &aacute;p dụng phần mềm n&agrave;y sẽ được hiện đại h&oacute;a, thời gian sản xuất được r&uacute;t ngắn, tiết kiệm được nhiều chi ph&iacute; v&agrave; chất lượng sản phẩm vượt trội hơn.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-size: 14pt; font-family: \'times new roman\', times, serif;\">Mọi th&ocirc;ng tin chi tiết xin vui l&ograve;ng li&ecirc;n hệ:<br /></span><span style=\"font-size: 14pt; font-family: \'times new roman\', times, serif;\">Hotline 0866.059.659 <br />Email: <a href=\"mailto:info@cic.com.vn\">info@cic.com.vn</a><br />Website: <a href=\"/\">nghenoithat.vn</a> hoặc <a href=\"https://www.cic.com.vn\">cic.com.vn</a></span></p>','EUROHA triển khai phần mềm OPERA - phần mềm chuyên dụng cho thiết kế, bóc tách vật tư và gia công cửa sổ, cửa đi và hệ mặt dựng nhôm kính',NULL,'euroha-trien-khai-phan-mem-opera-phan-mem-chuyen-dung-cho-thiet-ke-boc-tach-vat-tu-va-gia-cong-cua-so-cua-di-va-he-mat-dung-nhom-kinh','Mới đây, Nghenoithat.vn (thuộc Công ty CP Công nghệ và Tư vấn CIC) và EUROHA đã ký kết hợp đồng chuyển giao phần mềm chuyên dụng hỗ trợ thiết kế, bóc tách vật tư và gia công cửa sổ, cửa đi và hệ mặt dựng nhôm kính, Opera Job Management.',NULL,'Published',2,NULL,1,41,'2022-06-13 00:34:34','2022-06-14 07:10:44',NULL);
