INSERT INTO `products` VALUES (1,'ETABS','etabs','2020-10-07 11:54:00',1,0,'1606814776-etabs.jpg','Etabs - Phần mềm phân tích, thiết kế kết cấu nhà cao tầng','<div class=\" col-md-9 lbody\">\r\n<div class=\"menu1\">\r\n<div class=\"tab-content\">\r\n<div id=\"menu1\" class=\"tab-pane fade active in\">\r\n<div id=\"boxdex\" class=\"contentt boxdex\" data-height=\"650\">\r\n<div id=\"detailFT0\" class=\"clearfix ma15 tinhnang text-center\">\r\n<h2 title=\"Giao diện\"><img src=\"https://www.consoft.vn/uploads/products/27271_10.jpg\" />&nbsp;Giao diện</h2>\r\n<div class=\"ma15 text-left\">\r\n<p><strong>Một cửa sổ với nhiều th&ocirc;ng tin</strong><br /><br />ETABS cung cấp một giao diện người d&ugrave;ng duy nhất để thực hiện việc m&ocirc; h&igrave;nh, ph&acirc;n t&iacute;ch, thiết kế, triển khai chi tiết, v&agrave; b&aacute;o c&aacute;o. Ngo&agrave;i ra phần mềm con cho ph&eacute;p người d&ugrave;ng truy cập nhanh đến c&aacute;c đối tượng, thuộc t&iacute;nh, v&agrave; c&aacute;c thiết lập.<br /><br /><strong>Giao diện người d&ugrave;ng</strong></p>\r\n<p><img src=\"https://www.consoft.vn/uploads/image002.jpg\" alt=\"\" /></p>\r\n<p><em>Kh&ocirc;ng giới hạn số lượng cửa sổ gi&uacute;p cho việc thao t&aacute;c tr&ecirc;n m&ocirc; h&igrave;nh v&agrave; truy cập dự liệu nhanh ch&oacute;ng hơn.</em></p>\r\n<p>&nbsp;<strong>Vận h&agrave;nh linh hoạt</strong><br />&nbsp;</p>\r\n<p><img src=\"https://www.consoft.vn/uploads/image003.jpg\" alt=\"\" /></p>\r\n<p><em>M&ocirc; h&igrave;nh Explorer trong ETABS gi&uacute;p người sử dụng dễ d&agrave;ng quản l&yacute; dữ liệu trong m&ocirc; h&igrave;nh. Người d&ugrave;ng c&oacute; thể khai b&aacute;o, nh&acirc;n bản, sửa đổi c&aacute;c thuộc t&iacute;nh trong nh&oacute;m. K&eacute;o v&agrave; thả c&aacute;c thuộc t&iacute;nh v&agrave;o c&aacute;c m&ocirc; h&igrave;nh để g&aacute;n. C&aacute;c hiển thị được người d&ugrave;ng định nghĩa c&oacute; thể thiết lập dễ d&agrave;ng trong m&ocirc; h&igrave;nh t&igrave;m kiếm để vận h&agrave;nh nhanh ch&oacute;ng</em>.</p>\r\n<p><strong>Tăng tốc đồ họa</strong><br /><br />Đồ họa Direct X với thuật to&aacute;n tăng tốc đồ họa phần cứng cho ph&eacute;p điều khiển m&ocirc; h&igrave;nh theo c&aacute;c hướng view kh&aacute;c nhau hoạc v&agrave;&nbsp;xoay, zoom m&ocirc; h&igrave;nh nhanh ch&oacute;ng.</p>\r\n<p><img src=\"https://www.consoft.vn/uploads/image004.jpg\" alt=\"\" /></p>\r\n</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n<div id=\"content-tab\" class=\"ma15\">&nbsp;</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n</div>\r\n<div id=\"detailFT1\" class=\"clearfix ma15 tinhnang text-center\">\r\n<h2 title=\"M&ocirc; h&igrave;nh\">M&ocirc; h&igrave;nh</h2>\r\n<div class=\"ma15 text-left\">\r\n<p><strong>Templates</strong></p>\r\n<div>\r\n<p>ETABS c&oacute; một loạt thư viện mẫu gi&uacute;p người d&ugrave;ng tạo nhanh m&ocirc; h&igrave;nh một dự &aacute;n. Ở bước tạo m&ocirc; h&igrave;nh theo mẫu người d&ugrave;ng c&oacute; thể x&aacute;c định lưới trục, khoảng c&aacute;ch lưới, số tầng, hệ kết cấu mặc định, v&agrave; tải trọng ph&acirc;n bố ( bao gồm tĩnh tải v&agrave; hoạt tải).</p>\r\n<p><img src=\"https://www.csiamerica.com/sites/default/files/modeling-templates-3.jpg\" /></p>\r\n<p>&nbsp;</p>\r\n<p><strong>Chế độ Model Views</strong></p>\r\n<div>\r\n<p>Xem v&agrave; thao t&aacute;c m&ocirc; h&igrave;nh ph&acirc;n t&iacute;ch với độ ch&iacute;nh x&aacute;c cao. Mặt bằng v&agrave; mặt đứng được tự động tạo dựa v&agrave;o lưới trục. Dễ d&agrave;ng định nghĩa chế độ xem v&agrave; mặt cắt để x&aacute;c định những m&ocirc; h&igrave;nh h&igrave;nh học phức tạp.<br />&nbsp;</p>\r\n<ul>\r\n<li><strong>M&ocirc; h&igrave;nh ph&acirc;n t&iacute;ch:</strong></li>\r\n</ul>\r\n<p><img src=\"https://www.csiamerica.com/sites/default/files/analytical-model-1.jpg\" /><br /><em>M&ocirc; h&igrave;nh ph&acirc;n t&iacute;ch hiển thị phần tử hữu hạn c&aacute;c th&agrave;nh phần kết cấu với c&aacute;c n&uacute;t li&ecirc;n kết, khung, v&agrave; tấm cũng như x&aacute;c định chia lưới phần tử.</em></p>\r\n<ul>\r\n<li><strong>M&ocirc; h&igrave;nh vật l&yacute;</strong></li>\r\n</ul>\r\n<p><img src=\"https://www.csiamerica.com/sites/default/files/physical-model-1.jpg\" /><br /><br />Chế độ xem m&ocirc; h&igrave;nh vật l&yacute; hiển thị c&aacute;c điểm ch&egrave;n, trục xoay cục bộ, c&aacute;c điểm giao tường, v&agrave; h&igrave;nh học.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Hệ lưới tọa độ</strong></p>\r\n<p>Trong ETABS, lưới c&oacute; thể x&aacute;c định theo hệ tọa độ&nbsp;Descartes, dạng h&igrave;nh trụ, hoạc hệ lưới tự do. Kh&ocirc;ng giới hạn số lượn hệ lưới trong một m&ocirc; h&igrave;nh, v&agrave; ch&uacute;ng c&oacute; thể được xoay bất kỳ hướng hoạc đặt ở bất kỳ gốc tọa độ n&agrave;o của m&ocirc; h&igrave;nh.</p>\r\n<div>\r\n<p><img src=\"https://www.csiamerica.com/sites/default/files/grid-system7.jpg\" /></p>\r\n<p><strong>C&ocirc;ng cụ vẽ</strong></p>\r\n<p>Nhiều c&ocirc;ng vụ vẽ được x&acirc;y dựng trong etabs nhằm n&acirc;ng cao khả năng m&ocirc; h&igrave;nh của người d&ugrave;ng. Người d&ugrave;ng c&oacute; thể t&igrave;m thấy nhiều ph&iacute;m tắt v&agrave; chế độ kiểm xo&aacute;t m&ocirc; h&igrave;nh v&agrave; c&oacute; sẵn trong ETABS.</p>\r\n<ul>\r\n<li>Chế độ bắt điểm th&ocirc;ng minh:</li>\r\n</ul>\r\n<div><img src=\"https://www.consoft.vn/uploads/snaps-clipped.jpg\" alt=\"\" /></div>\r\n<ul>\r\n<li>\r\n<p>Chế độ Architectural Tracing<br />&nbsp;</p>\r\n<p><img src=\"https://www.consoft.vn/uploads/arch-tracing-e2013-400-1.jpg\" alt=\"\" /></p>\r\n</li>\r\n</ul>\r\n<div>&nbsp;</div>\r\n<p><strong>Chế độ xem mặt bằng v&agrave; mặt đứng</strong><br />Mặt bằng v&agrave; mặt đứng được tự động theo lưới trục để nhanh ch&oacute;ng trong m&ocirc; h&igrave;nh. Người d&ugrave;ng cũng c&oacute; thể x&aacute;c định chế độ xem cho mặt đứng bất kỳ kh&ocirc;ng theo lưới trục bằng c&aacute;ch sử dụng chế độ Developed Elevation.<br />&nbsp;</p>\r\n<ul>\r\n<li><strong>Chế độ xem mặt bằng v&agrave; mặt đứng</strong></li>\r\n</ul>\r\n<div><img src=\"https://www.csiamerica.com/sites/default/files/auto-elevation.jpg\" /><br /><em>Khi trong chế độ xem 2D, dịch chuyển theo c&aacute;c lưới trục để xem chi tiết m&ocirc; h&igrave;nh tr&ecirc;n mặt bằng v&agrave; mặt đứng. phần đang quan x&aacute;t tr&ecirc;n mặt bằng v&agrave; mặt đứng cũng sẽ được hiển thị đ&aacute;nh dấu trong m&ocirc; h&igrave;nh 3D để người d&ugrave;ng dễ d&agrave;ng nhận biết khu vực đang l&agrave;m việc.</em><br />&nbsp;</div>\r\n<ul>\r\n<li><strong>Chế độ Developed Elevations</strong></li>\r\n</ul>\r\n<p><img src=\"https://www.csiamerica.com/sites/default/files/developed-elevations-1.jpg\" /><br /><em>Chế độ n&agrave;y cho ph&eacute;p tạo ra c&aacute;c mặt bằng &amp; mặt đứng quan x&aacute;t theo định nghĩa của người d&ugrave;ng th&ocirc;ng qua việc x&aacute;c định c&aacute;c đường vẽ thay cho việc hiển thị theo lưới trục. Gi&uacute;p dễ d&agrave;ng kiểm xo&aacute;t c&aacute;c th&agrave;nh phần kết cấu phức tạp.&nbsp;</em></p>\r\n</div>\r\n</div>\r\n</div>\r\n<p>&nbsp;</p>\r\n<p><strong>Tương t&aacute;c bảng biểu v&agrave; hiệu chỉnh dữ liệu m&ocirc; h&igrave;nh</strong></p>\r\n<p>Dữ liệu ETABS c&oacute; thể được xem v&agrave; hiệu chỉnh th&ocirc;ng qua bảng biểu. N&oacute; cho ph&eacute;p x&aacute;c định m&ocirc; h&igrave;nh th&ocirc;ng qua bảng t&iacute;nh excel hoạc xem chế độ ph&acirc;n t&iacute;ch v&agrave; kết quả tr&ecirc;n bảng biểu.</p>\r\n<div>\r\n<p><img src=\"https://www.csiamerica.com/sites/default/files/tables-1.jpg\" /></p>\r\n<p><strong>C&ocirc;ng cụ chia lưới</strong></p>\r\n<div>\r\n<p>Kỹ sư c&oacute; nhiều lựa chọn chia lưới trong ETABS. Đơn giản từ việc lựa chọn đối tượng để chia lưới tự động</p>\r\n<div>\r\n<ul>\r\n<li><strong>Object Based Meshing</strong></li>\r\n</ul>\r\n<p><img src=\"https://www.csiamerica.com/sites/default/files/meshing-etabs-2013-zoomed.jpg\" /></p>\r\n<p>&nbsp;</p>\r\n<ul>\r\n<li><strong>External Meshing</strong></li>\r\n</ul>\r\n<strong><img src=\"https://www.csiamerica.com/sites/default/files/meshing-4.jpg\" /></strong>\r\n<ul>\r\n<li><strong>Line Constraints</strong></li>\r\n</ul>\r\n<p><img src=\"https://www.csiamerica.com/sites/default/files/line-constraint-e2013.jpg\" alt=\"\" /></p>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n<div id=\"content-tab\" class=\"ma15\">&nbsp;</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n</div>\r\n<div id=\"detailFT2\" class=\"clearfix ma15 tinhnang text-center\">\r\n<h2 title=\"Th&agrave;nh phần kết cấu\"><img src=\"https://www.consoft.vn/uploads/products/30230_08.jpg\" />&nbsp;Th&agrave;nh phần kết cấu</h2>\r\n<div class=\"ma15 text-left\">\r\n<p><strong>Th&aacute;p: c&oacute; thể view theo m&agrave;u sắc</strong></p>\r\n<div>\r\n<p><img src=\"https://www.consoft.vn/uploads/towers-etabs-2013.jpg\" alt=\"\" /></p>\r\n<p><strong>Hệ dầm, cột, giằng</strong></p>\r\n<p><img src=\"https://www.consoft.vn/uploads/frames_e2013.jpg\" alt=\"\" /></p>\r\n<p><strong>Thuộc t&iacute;nh tiết diện</strong></p>\r\n<p><img src=\"https://www.consoft.vn/uploads/sections_e2013_0.jpg\" alt=\"\" /></p>\r\n<p><strong>Tấm vỏ</strong></p>\r\n<p><strong>&nbsp;</strong><img src=\"https://www.consoft.vn/uploads/shells-etabs-2013.jpg\" alt=\"\" /></p>\r\n<p><strong>Tường</strong></p>\r\n<ul>\r\n<li><strong>L&otilde;i thang m&aacute;y</strong></li>\r\n</ul>\r\n<p><img src=\"https://www.consoft.vn/uploads/wall-stacks.jpg\" alt=\"\" /></p>\r\n<ul>\r\n<li><strong>Tường chịu lực</strong></li>\r\n</ul>\r\n<p><img src=\"https://www.consoft.vn/uploads/spandrel-etabs.jpg\" alt=\"\" /></p>\r\n<p><strong>Li&ecirc;n kết</strong></p>\r\n<p><img src=\"https://www.consoft.vn/uploads/Link-etabs-2013.jpg\" alt=\"\" /></p>\r\n<p><strong>Tấm s&agrave;n</strong></p>\r\n<p><img src=\"https://www.consoft.vn/uploads/diaphragm-etabs-2013.jpg\" alt=\"\" /></p>\r\n</div>\r\n</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n<div id=\"content-tab\" class=\"ma15\">&nbsp;</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n</div>\r\n<div id=\"detailFT3\" class=\"clearfix ma15 tinhnang text-center\">\r\n<h2 title=\"Tải trọng\"><img src=\"https://www.consoft.vn/uploads/products/20206_04.jpg\" />&nbsp;Tải trọng</h2>\r\n<div class=\"ma15 text-left\">\r\n<p><strong>Tự động th&ecirc;m tải trọng theo ti&ecirc;u chuẩn</strong></p>\r\n<div>\r\n<ul>\r\n<li><strong>Tĩnh tải</strong></li>\r\n</ul>\r\n<p><img src=\"https://www.consoft.vn/uploads/seismic1.jpg\" alt=\"\" /></p>\r\n<p><em>Hỗ trợ c&aacute;c ti&ecirc;u chuẩn:</em></p>\r\n<p>&nbsp;<img src=\"https://www.consoft.vn/uploads/Loading%20code%201.JPG\" alt=\"\" /></p>\r\n<p>&nbsp;</p>\r\n<ul>\r\n<li><strong>Tải trọng gi&oacute;</strong></li>\r\n</ul>\r\n<p><strong><img src=\"https://www.consoft.vn/uploads/wind-loads-etabs-2013.jpg\" alt=\"\" /></strong></p>\r\n<p><br /><em>Hỗ trợ c&aacute;c ti&ecirc;u chuẩn</em></p>\r\n<p><strong><img src=\"https://www.consoft.vn/uploads/Loanding%20code%202.JPG\" alt=\"\" /></strong></p>\r\n<p><strong>Tải trọng tập trung, Tải trọng đường, Tải trọng ph&acirc;n bố theo diện t&iacute;ch, v&agrave; tải trọng do nhiệt</strong></p>\r\n<p><img class=\"img-responsive  lazyloaded\" src=\"https://www.consoft.vn/uploads/load-assigns-etabs-2013.jpg\" data-=\"\" data-expand=\"auto\" /></p>\r\n<p><strong>Lớp&nbsp; phủ bề mặt</strong></p>\r\n<p><img src=\"https://www.consoft.vn/uploads/cladding-4.jpg\" alt=\"\" /></p>\r\n<p><strong>Hệ số giảm tải</strong></p>\r\n<p><em>Hỗ trợ c&aacute;c ti&ecirc;u chuẩn v&agrave; người d&ugrave;ng tự định nghĩa trong in ETABS</em></p>\r\n<p><img src=\"https://www.consoft.vn/uploads/He%20so%20giam%20tai.JPG\" alt=\"\" /></p>\r\n<p>&nbsp;</p>\r\n<p><img src=\"https://www.consoft.vn/uploads/live-load-etabs-2013-2.jpg\" alt=\"\" /></p>\r\n</div>\r\n</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n<div id=\"content-tab\" class=\"ma15\">&nbsp;</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n</div>\r\n<div id=\"detailFT4\" class=\"clearfix ma15 tinhnang text-center\">\r\n<h2 title=\"Ph&acirc;n t&iacute;ch\"><img src=\"https://www.consoft.vn/uploads/products/27157_01.jpg\" />&nbsp;Ph&acirc;n t&iacute;ch</h2>\r\n<div class=\"ma15 text-left\">\r\n<p><strong>Tổng quan</strong></p>\r\n<div class=\"col col-md-12 text-full\">\r\n<p>CSI Solvers đ&atilde; được ph&aacute;t triển trong hơn 35 năm. Nh&acirc;n ph&acirc;n t&iacute;ch SAPFire Analysis Engine hỗ trợ m&aacute;y t&iacute;nh 64 b&iacute;t để tối ưu qu&aacute; tr&igrave;nh ph&acirc;n t&iacute;ch v&agrave; thực hiện cả hai ph&acirc;n t&iacute;ch Eigen v&agrave; Ritz.<br />&nbsp;</p>\r\n<p><img src=\"https://www.consoft.vn/uploads/analysis-details-1.jpg\" alt=\"\" /></p>\r\n<p><strong>Ph&acirc;n t&iacute;ch động</strong></p>\r\n<p><img src=\"https://www.consoft.vn/uploads/dynamics-etabs-2013.jpg\" alt=\"\" /></p>\r\n<p><br />&nbsp;&nbsp;<strong>&nbsp;Ph&acirc;n t&iacute;ch phổ phản ứng</strong></p>\r\n<p><img src=\"https://www.consoft.vn/uploads/response-spectrum-2.jpg\" alt=\"\" /></p>\r\n<p><strong>&nbsp;&nbsp;&nbsp; Ph&acirc;n t&iacute;ch theo lịch sử thời gian</strong></p>\r\n<p><img src=\"https://www.consoft.vn/uploads/time-history-etabs-2013.jpg\" alt=\"\" /></p>\r\n<p>&nbsp;</p>\r\n<p><strong>Ph&acirc;n t&iacute;ch lệch t&acirc;m nhỏ (P-Delta)</strong></p>\r\n<p><img src=\"https://www.consoft.vn/uploads/p-delta-sap2000.gif\" alt=\"\" /><br />&nbsp;</p>\r\n<p><span style=\"font-family: arial, helvetica, sans-serif;\"><strong>Ph&acirc;n t&iacute;ch trạng th&aacute;i oằn</strong></span></p>\r\n<p><img src=\"https://www.consoft.vn/uploads/buckling-etabs-2013.jpg\" alt=\"\" /></p>\r\n<p><strong>Ph&acirc;n t&iacute;ch mất &ocirc;n định tổng thể</strong></p>\r\n<div>\r\n<p><img src=\"https://www.consoft.vn/uploads/pushover-full_0.jpg\" alt=\"\" /></p>\r\n<p><strong>Phụ thuộc thời gian</strong></p>\r\n<ul>\r\n<li>Theo tr&igrave;nh tự thi c&ocirc;ng</li>\r\n</ul>\r\n<p><img src=\"https://www.consoft.vn/uploads/construction-sequencing-etabs-2013.jpg\" alt=\"\" /></p>\r\n<ul>\r\n<li>&nbsp;&nbsp; Co ng&oacute;t từ biến</li>\r\n</ul>\r\n<p><img src=\"https://www.consoft.vn/uploads/creep-shrink-etabs-2013-1.jpg\" alt=\"\" /></p>\r\n<ul>\r\n<li>Trường hợp tải trọng v&agrave; tổ hợp tải trọng</li>\r\n</ul>\r\n<p><img src=\"https://www.consoft.vn/uploads/load-combos-1.jpg\" alt=\"\" /></p>\r\n<ul>\r\n<li>Chế độ ph&acirc;n t&iacute;ch nhanh (Model Alive) - thay đổi nhanh trang th&aacute;i kết cấu để người dung dễ d&agrave;ng h&igrave;nh dung khi thay đổi phần kết cấu</li>\r\n</ul>\r\n</div>\r\n<p>&nbsp;</p>\r\n</div>\r\n</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n<div id=\"content-tab\" class=\"ma15\">&nbsp;</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n</div>\r\n<div id=\"detailFT5\" class=\"clearfix ma15 tinhnang text-center\">\r\n<h2 title=\"Performance Based Design\"><img src=\"https://www.consoft.vn/uploads/products/26586_11.jpg\" />&nbsp;Performance Based Design</h2>\r\n<div class=\"ma15 text-left\">\r\n<div><strong>Tự động h&oacute;a thiết kế dựa theo t&iacute;nh năng</strong><br />&nbsp;</div>\r\n<div>Thiết kế dựa tr&ecirc;n t&iacute;nh năng (PBD) l&agrave; sự chuyển đổi lớn từ c&aacute;c kh&aacute;i niệm thiết kế cấu truyền thống v&agrave; đại diện cho kỹ thuật t&iacute;nh to&aacute;n động đ&oacute;a tương lai. Những phương ph&aacute;p mới n&agrave;y gi&uacute;p đảm bảo rằng thiết kế sẽ chắc chắn đ&aacute;p ứng một mức độ hiệu suất th&iacute;ch hợp trong suốt một trận động đất nhất định.<br /><br />Th&agrave;nh phần cơ bản của PBD l&agrave; ph&acirc;n t&iacute;ch động phi tuyến, trong đ&oacute; c&oacute; một nỗ lực để nắm bắt được ứng xử thực tế của kết cấu bằng c&aacute;ch m&ocirc; h&igrave;nh v&agrave; đ&aacute;nh gi&aacute; một c&aacute;ch r&otilde; r&agrave;ng độ dẻo dai v&agrave; ti&ecirc;u hao năng lượng khi chịu t&aacute;c động bởi c&aacute;c chuyển động mặt đất do động đất. ETABS 2016 giới thiệu c&aacute;c lựa chọn v&agrave; thuật to&aacute;n đặc biệt mới ch việc ứng dụng thực tế v&agrave; hiệu quả c&aacute;c phương ph&aacute;p n&agrave;y.<br />&nbsp;</div>\r\n<div>Ph&acirc;n t&iacute;ch phi tuyến nhanh v&agrave; ổn định được bổ sung trong phương ph&aacute;p PBD.<br />C&aacute;c khớp dẻo trong v&aacute;ch cứng dự tr&ecirc;n cốt th&eacute;p thiết kế hoặc do người d&ugrave;ng khai b&aacute;o được tự động h&oacute;a.<br />C&aacute;c m&ocirc; h&igrave;nh vật liệu th&eacute;p v&agrave; b&ecirc; t&ocirc;ng với c&aacute;c mức độ tương th&iacute;ch (bị r&agrave;ng buộc v&agrave; kh&ocirc;ng bị r&agrave;ng buộc)</div>\r\n<div class=\"col-md-12\">\r\n<div class=\"col col-md-12 only-full\">\r\n<div class=\"row pad-top pad-bottom\">\r\n<div class=\"col-md-4 \">\r\n<div><img src=\"https://www.csiamerica.com/sites/default/files/ETABS-2015-ucac.png\" /></div>\r\n<div class=\"row\">\r\n<div class=\"col-md-12\">\r\n<p class=\"caption\">M&ocirc; h&igrave;nh vật liệu b&ecirc; t&ocirc;ng bị r&agrave;ng buộc v&agrave; kh&ocirc;ng bị r&agrave;ng buộc được so s&aacute;nh</p>\r\n</div>\r\n</div>\r\n</div>\r\n<div class=\"col-md-4 \">\r\n<div><img src=\"https://www.csiamerica.com/sites/default/files/ETABS-2015-cc.png\" /></div>\r\n<div class=\"row\">\r\n<div class=\"col-md-12\">\r\n<p class=\"caption\">M&ocirc; h&igrave;nh vật liệu b&ecirc; t&ocirc;ng bị r&agrave;ng buộc</p>\r\n</div>\r\n</div>\r\n</div>\r\n<div class=\"col-md-4\">\r\n<div><img src=\"https://www.csiamerica.com/sites/default/files/ETABS-2015-s.png\" /></div>\r\n<div class=\"row\">\r\n<div class=\"col-md-12\">\r\n<p class=\"caption\"><strong>M&ocirc; h&igrave;nh vật liệu th&eacute;p</strong></p>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<p>C&aacute;c khớp dẻo v&agrave; phương ph&aacute;p t&iacute;nh to&aacute;n thiết kế theo t&iacute;nh năng được tự động h&oacute;a dựa tr&ecirc;n ti&ecirc;u chuẩn ASCE 41-13.<br />C&aacute;c m&ocirc; h&igrave;nh thớ b&ecirc; t&ocirc;ng v&agrave; th&eacute;p cho v&aacute;ch cứng v&agrave; cột</p>\r\n<div>&nbsp;</div>\r\n<div class=\"col col-md-12 only-full\">\r\n<div class=\"row\">\r\n<div class=\"col-md-12  pad-top\"><center>\r\n<div><img src=\"https://www.csiamerica.com/sites/default/files/ETABS-2015-Shearwall-Fiber-Hinge.png\" /></div>\r\n</center>\r\n<div class=\"row\">\r\n<div class=\"col-md-12\">\r\n<p class=\"caption\">Khớp của v&aacute;ch cứng dạng thớ</p>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<div>C&aacute;c đồ thị v&agrave; bảng biểu của tỉ số D/C gi&uacute;p việc đ&aacute;nh gi&aacute; nhanh hiệu năng</div>\r\n<div class=\"col col-md-12 only-full\">\r\n<div class=\"row\">\r\n<div class=\"col-md-12  pad-top\"><center>\r\n<div><img src=\"https://www.csiamerica.com/sites/default/files/ETABS-2015-DCRatios.png\" /></div>\r\n</center>\r\n<div class=\"row\">\r\n<div class=\"col-md-12\">\r\n<p class=\"caption\"><strong>Tỉ số D/C</strong></p>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<div>Biến dạng vật liệu như l&agrave; đo lường hiệu năng cho tỉ số D/C<br />Một v&agrave;i lựa chọn mới về độ trễ cho c&aacute;c khớp phi tuyến<br />C&aacute;c lựa chọn về độ cứng trễ v&agrave; suy giảm cường độ</div>\r\n<div class=\"col-md-12\">\r\n<div class=\"col col-md-12 only-full\">\r\n<div class=\"row\">\r\n<div class=\"col-md-12  pad-top\"><center>\r\n<div><img src=\"https://www.csiamerica.com/sites/default/files/pbd/hysteresis-loop-models.png\" /></div>\r\n</center>\r\n<div class=\"row\">\r\n<div class=\"col-md-12\">\r\n<p class=\"caption\">C&aacute;c m&ocirc; h&igrave;nh v&ograve;ng lặp độ trễ</p>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<div>Lựa chọn Tựa-tĩnh (phần động lực học) phục vụ ph&acirc;n t&iacute;ch phi tuyến tĩnh c&aacute;c m&ocirc; h&igrave;nh phức tạp<br />Chuyển vị cưỡng bức được mở rộng cho việc đ&aacute;nh gi&aacute; biến dạng<br />Kết quả trung b&igrave;nh c&aacute;c phản ứng th&ocirc;ng qua một v&agrave;i lần ph&acirc;n t&iacute;ch theo thời gian</div>\r\n<div class=\"col-md-12\">\r\n<div class=\"col col-md-12 only-full\">\r\n<div class=\"row\">\r\n<div class=\"col-md-12  pad-top\"><center>\r\n<div><img src=\"https://www.csiamerica.com/sites/default/files/ETABS-2015-Avg-Output.png\" /></div>\r\n</center>\r\n<div class=\"row\">\r\n<div class=\"col-md-12\">\r\n<p class=\"caption\"><em>Phản ứng trung b&igrave;nh</em></p>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n<div id=\"content-tab\" class=\"ma15\">&nbsp;</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n</div>\r\n<div id=\"detailFT6\" class=\"clearfix ma15 tinhnang text-center\">\r\n<h2 title=\"Thiết kế\"><img src=\"https://www.consoft.vn/uploads/products/15162_02.jpg\" />&nbsp;Thiết kế</h2>\r\n<div class=\"ma15 text-left\">\r\n<p id=\"design\"><strong>Khung th&eacute;p</strong><br /><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/steel-design.jpg\" data-=\"\" data-expand=\"auto\" /></p>\r\n<div class=\"col-md-12\">\r\n<p><strong>Khung b&ecirc; t&ocirc;ng</strong></p>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"700\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/conc-frame-etabs-2013-1.jpg\" data-=\"\" data-expand=\"auto\" /></p>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<p><strong>Hốn hợp dầm v&agrave; cột</strong></p>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"700\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/comp-beam-etabs-2013.jpg\" data-=\"\" data-expand=\"auto\" /></p>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<p><strong>Thiết kế tường</strong></p>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"700\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/shear-wall-design-etabs-2013-3.jpg\" data-=\"\" data-expand=\"auto\" /></p>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<p><strong>Thiết kế mối nối th&eacute;p</strong></p>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"700\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/steel-joist-design-etabs-2013.jpg\" data-=\"\" data-expand=\"auto\" /></p>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<p><strong>Mối nối th&eacute;p thanh v&agrave; tấm</strong></p>\r\n</div>\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"700\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/connection-design-3.jpg\" data-=\"\" data-expand=\"auto\" /></p>\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"700\"><br /><strong>Hỗ trợ c&aacute;c ti&ecirc;u chuẩn thiết kế:</strong><br />https://www.csiamerica.com/international-design#concrete-frame-design</p>\r\n</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n<div id=\"content-tab\" class=\"ma15\">&nbsp;</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n</div>\r\n<div id=\"detailFT7\" class=\"clearfix ma15 tinhnang text-center\">\r\n<h2 title=\"Đầu ra\"><img src=\"https://www.consoft.vn/uploads/products/19907_06.jpg\" />&nbsp;Đầu ra</h2>\r\n<div class=\"ma15 text-left\">\r\n<div class=\"col-md-12\">\r\n<h3>Đơn vị hỗn hợp</h3>\r\n<div class=\"col col-md-12 img-full div-resize\" data-divheight=\"423\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/mixed-units-etabs-2013.jpg\" data-=\"\" data-expand=\"auto\" /></div>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<h3>Biến dạng h&igrave;nh học</h3>\r\n<div class=\"col col-md-12 img-full div-resize\" data-divheight=\"700\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/deformed-etabs-2013.jpg\" data-=\"\" data-expand=\"auto\" /></div>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<h3>Shell Force and Stress Contours</h3>\r\n<div class=\"col col-md-12 img-full div-resize\" data-divheight=\"370\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/stresses.jpg\" data-=\"\" data-expand=\"auto\" /></div>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<h3>Reaction Diagrams</h3>\r\n<div class=\"col col-md-12 img-full div-resize\" data-divheight=\"700\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/reactions-etabs-2013.jpg\" data-=\"\" data-expand=\"auto\" /></div>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<h3>Đầu ra dạng bảng</h3>\r\n<div class=\"col col-md-12 img-full div-resize\" data-divheight=\"587\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/tabular-output-etabs-2013-1.jpg\" data-=\"\" data-expand=\"auto\" /></div>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<h3>Mặt cắt c&aacute;c tiết diện</h3>\r\n<div><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/section-cut-etabs-2013-1.jpg\" data-=\"\" data-expand=\"auto\" /></div>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<h3>H&igrave;nh ảnh hoạt họa</h3>\r\n<div><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/analysis-twist-etabs-2013-full.jpg\" data-=\"\" data-expand=\"auto\" /></div>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<h3>H&igrave;nh ảnh Rendered</h3>\r\n<div class=\"col col-md-12 img-full div-resize\" data-divheight=\"700\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/ray-tracing-etabs-2013-zoom.jpg\" data-=\"\" data-expand=\"auto\" /></div>\r\n</div>\r\n<div class=\"bs-docs-section\">&nbsp;</div>\r\n</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n<div id=\"content-tab\" class=\"ma15\">&nbsp;</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n</div>\r\n<div id=\"detailFT8\" class=\"clearfix ma15 tinhnang text-center\">\r\n<h2 title=\"Tạo report\"><img src=\"https://www.consoft.vn/uploads/products/14894_07.jpg\" />&nbsp;Tạo report</h2>\r\n<div class=\"ma15 text-left\">\r\n<div class=\"col-md-12\">\r\n<p><strong>Xuất B&aacute;o c&aacute;o</strong></p>\r\n<div class=\"col col-md-12 text-full\">\r\n<p>C&aacute;c t&iacute;nh năng tạo b&aacute;o c&aacute;o bao gồm mục lục, c&aacute;c th&ocirc;ng tin khai b&aacute;o trong m&ocirc; h&igrave;nh, kết quả &nbsp;ph&acirc;n t&iacute;ch v&agrave; thiết kế trong định dạng bảng biểu. B&aacute;o c&aacute;o c&oacute; thể xem được trong ETABS trực tiếp kết nối với Model Explorer v&agrave; xuất trực tiếp sang Microsoft Word.</p>\r\n</div>\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"579\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/report-generator-etabs-2013-1.jpg\" data-=\"\" data-expand=\"auto\" /></p>\r\n</div>\r\n</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n<div id=\"content-tab\" class=\"ma15\">&nbsp;</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n</div>\r\n<div id=\"detailFT9\" class=\"clearfix ma15 tinhnang text-center\">\r\n<h2 title=\"C&ocirc;ng cụ\"><img src=\"https://www.consoft.vn/uploads/products/7612_09.jpg\" />&nbsp;C&ocirc;ng cụ</h2>\r\n<div class=\"ma15 text-left\">\r\n<div class=\"col-md-12\">\r\n<p><strong>C&ocirc;ng cụ Section Designer</strong></p>\r\n<div class=\"col col-md-12 text-full\">\r\n<p>Thiết kế tiết diện l&agrave; một tiện &iacute;ch được x&acirc;y dựng v&agrave;o ETABS. N&oacute; cho ph&eacute;p người d&ugrave;ng khả năng để tạo ra một tiết diện đặc biệt với bất kỳ h&igrave;nh dạng v&agrave; vật liệu t&ugrave;y &yacute;, bao gồm bố tr&iacute; cốt th&eacute;p. Tất cả c&aacute;c đặc trưng tiết diện, biểu đồ tương t&aacute;c hai trục, v&agrave; biểu đồ quan hệ lực - momen được t&iacute;nh to&aacute;n tự động.</p>\r\n</div>\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"700\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/section-designer-new-etabs-2013.jpg\" data-=\"\" data-expand=\"auto\" /></p>\r\n</div>\r\n</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n<div id=\"content-tab\" class=\"ma15\">&nbsp;</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n</div>\r\n<div id=\"detailFT10\" class=\"clearfix ma15 tinhnang text-center\">\r\n<h2 title=\"Nhập v&agrave; xuất\"><img src=\"https://www.consoft.vn/uploads/products/17145_03.jpg\" />&nbsp;Nhập v&agrave; xuất</h2>\r\n<div class=\"ma15 text-left\">\r\n<div class=\"col-md-12\">\r\n<div><strong>C&aacute;c định dạng được hỗ trợ</strong><br /><br />ETABS hỗ trợ nhiều định dạng trong nhập v&agrave; xuất dữ liệu. Autodesk Revit Structure, AutoCAD (DXF / DWG), CIS / 2, IFC, v&agrave; SDNF đều được hỗ trợ. ETABS cũng hỗ trợ xuất dữ liệu của m&ocirc; h&igrave;nh sang định dạng của Microsoft Access.</div>\r\n<div class=\"col col-md-12 text-full\">\r\n<p class=\"product-feature-sublink\">T&igrave;m hiểu th&ecirc;m tại:&nbsp;<a href=\"https://www.csiamerica.com/building-information-modeling\">https://www.csiamerica.com/building-information-modeling</a></p>\r\n</div>\r\n<div class=\"col col-md-12 img-full div-resize\" data-divheight=\"700\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/import-export-etabs-2013.jpg\" data-=\"\" data-expand=\"auto\" /></div>\r\n</div>\r\n</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n</div>\r\n<p>&nbsp;</p>\r\n</div>\r\n<div class=\"show\"><a class=\"btn btn-info details_click clickmore \" data-id=\"boxdex\" data-class=\"1\">Xem th&ocirc;ng tin đầy đủ</a></div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<div class=\"col-md-3 rbody\">\r\n<div class=\"taituychon\">&nbsp;</div>\r\n</div>\r\n<div id=\"eJOY__extension_root\" class=\"eJOY__extension_root_class\" style=\"all: unset;\">&nbsp;</div>','<h1>ETABS</h1>\r\n<p>ETABS phần mềm m&ocirc; h&igrave;nh, ph&acirc;n t&iacute;ch v&agrave; thiết kế kết cấu nh&agrave; cao tầng. Với kinh nghiệm tr&ecirc;n 40 năm kh&ocirc;ng ngừng nghi&ecirc;n cứu v&agrave; ph&aacute;t triển ETABS c&oacute; thể m&ocirc; phỏng v&agrave; m&ocirc; h&igrave;nh h&oacute;a thiết kế 3D hiện đại nhất từ trước tới nay. Với c&ocirc;ng nghệ ph&acirc;n t&iacute;ch tuyến t&iacute;nh v&agrave; phi tuyến, hỗ trợ tất cả c&aacute;c loại vật liệu, bản vẽ chi tiết một c&aacute;ch nhanh ch&oacute;ng, xuất thuyết minh dễ d&agrave;ng kiểm tra kết quả ph&acirc;n t&iacute;ch chi tiết. Hỗ trợ nhiều ti&ecirc;u chuẩn thiết kế tr&ecirc;n to&agrave;n cầu như ti&ecirc;u chuẩn Mỹ, Ch&acirc;u &Acirc;u, Trung Quốc, Nhật, Anh&hellip;</p>\r\n<p>ETABS t&iacute;ch hợp mọi c&ocirc;ng đoạn trong qu&aacute; tr&igrave;nh đưa ra c&aacute;c bản vẽ tối giản thiết kế từ việc l&ecirc;n &yacute; tưởng của m&ocirc; h&igrave;nh kết cấu. Đơn giản c&ocirc;ng cụ vẽ trực quan bằng việc m&ocirc; h&igrave;nh h&oacute;a tạo ra khung, dầm, s&agrave;n,.. cho t&ograve;a nh&agrave;. C&aacute;c bản vẽ c&oacute; thể được nhập trực tiếp v&agrave;o ETABS hoặc được lưu lại l&agrave;m mẫu. Dựa v&agrave;o đ&oacute; t&aacute;i tạo lại c&aacute;c bản vẽ bằng ETABS. Bộ nh&acirc;n t&iacute;nh to&aacute;n 64-bit SAPFire hiện đại cho ph&eacute;p thiết kế c&aacute;c m&ocirc; h&igrave;nh v&ocirc; c&ugrave;ng lớn v&agrave; phức tạp nhờ ph&acirc;n t&iacute;ch nhanh v&agrave; sử dụng kỹ thuật m&ocirc; phỏng phi tuyến để x&acirc;y dựng th&aacute;p cao tầng với c&aacute;c hiệu ứng theo lịch sử thời gian.</p>\r\n<p>Tối ưu h&oacute;a thiết kế s&agrave;n b&ecirc; t&ocirc;ng v&agrave; khung th&eacute;p tự động. Bao gồm tất cả c&aacute;c loại dầm, cột giằng, tường vữa v&agrave; b&ecirc; t&ocirc;ng. Để đảm bảo lực kết nối của c&aacute;c thanh th&eacute;p, th&eacute;p s&agrave;n được hiển thị trực quan. Thiết kế, ph&acirc;n t&iacute;ch to&agrave;n diện c&oacute; thể t&ugrave;y chỉnh cho c&aacute;c bản vẽ với kết cấu giản lược. Gi&uacute;p thể hiện c&aacute;c chi tiết mặt cắt ngang kết cấu b&ecirc; t&ocirc;ng v&agrave; th&eacute;p.</p>\r\n<p>&nbsp;</p>\r\n<h2>Những điểm nổi trội của ETABS</h2>\r\n<p>So với c&aacute;c chương tr&igrave;nh kh&aacute;c đang c&oacute; mặt tr&ecirc;n thị trường th&igrave; điểm nổi bật nhất của của ETABS so với c&aacute;c hệ thống c&ocirc;ng tr&igrave;nh l&agrave; c&oacute; thể đưa đến việc giảm thời gian r&otilde; rệt y&ecirc;u cầu việc x&acirc;y dựng m&ocirc; h&igrave;nh t&iacute;nh, giảm thời gian xử l&yacute; v&agrave; tăng độ ch&iacute;nh x&aacute;c. Bởi v&igrave; ETABS thực hiện đưa v&agrave;o c&aacute;c t&iacute;nh năng điển h&igrave;nh cho b&agrave;i to&aacute;n hệ thống c&aacute;c c&ocirc;ng tr&igrave;nh d&acirc;n dụng, trong x&acirc;y dựng m&agrave; c&aacute;c hệ chương tr&igrave;nh kh&aacute;c c&oacute; thể kh&ocirc;ng nhận ra được.</p>\r\n<p>C&aacute;c đặc t&iacute;nh n&agrave;y bao gồm tất cả c&aacute;c t&ograve;a nh&agrave; c&oacute; h&igrave;nh dạng đơn giản với hệ dầm nằm ngang v&agrave; c&aacute;c hệ cột thẳng đứng. Một cột đứng c&oacute; thể thiết lập c&aacute;c hệ h&igrave;nh học tương tự với thời gian nhỏ nhất. Mức s&agrave;n trong hệ c&ocirc;ng tr&igrave;nh ch&iacute;nh l&agrave; điển h&igrave;nh. C&aacute;c chương tr&igrave;nh kh&aacute;c hầu hết kh&ocirc;ng nhận dạng cụ thể yếu tố thực tế đang diễn ra. Từ đ&oacute; qu&aacute; tr&igrave;nh t&iacute;nh to&aacute;n tăng l&ecirc;n nhiều lần kh&ocirc;ng cần thiết.</p>\r\n<p>Hầu hết c&oacute; li&ecirc;n hệ rất nhiều đến chiều rộng của nhịp v&agrave; chiều cao của tầng. Những k&iacute;ch thước n&agrave;y c&oacute; ảnh hưởng r&otilde; rệt đến độ cứng của phần tử thanh. C&aacute;c c&ocirc;ng thức t&iacute;nh độ cứng sẽ bị ảnh hưởng của c&aacute;c phần tử. Hầu hết từ c&aacute;c chương tr&igrave;nh x&acirc;y dựng tại đường trọng t&acirc;m k&iacute;ch thước sẽ c&oacute; độ ch&iacute;nh x&aacute;c. C&ugrave;ng với đ&oacute; bạn sẽ mất nhiều thời gian thực hiện hơn.</p>\r\n<h2>C&aacute;c t&iacute;nh năng về nhập liệu</h2>\r\n<p>Phi&ecirc;n bản mới nhất của ETABS l&agrave; một c&ocirc;ng cụ xuất sắc cho c&aacute;c kỹ sư. Kết cấu thiết kế từ nh&agrave; c&ocirc;ng nghiệp tới ng&ocirc;i nh&agrave; cao tầng. C&ugrave;ng với những t&iacute;nh năng vượt trội, trực quan, tiện &iacute;ch v&agrave; dễ sử dụng.</p>\r\n<p>&nbsp;- Giao diện ETABS th&acirc;n thiện với người sử dụng kh&ocirc;ng qu&aacute; kh&oacute; khăn tiếp cận c&ocirc;ng nghệ.</p>\r\n<p>- Nhập liệu, chỉnh sửa hay sao ch&eacute;p dễ d&agrave;ng nhanh ch&oacute;ng nhờ hệ thống thanh c&ocirc;ng cụ.</p>\r\n<p>&nbsp;- Tăng tốc nhập liệu nh&agrave; cao tầng với những kh&aacute;i niệm tầng tương tự.</p>\r\n<p>&nbsp;- M&ocirc; h&igrave;nh c&aacute;c dạng kết cấu nh&agrave; cao tầng gồm hệ kết cấu dầm, cột, s&agrave;n, v&aacute;ch to&agrave;n khối. Hệ thống kết cấu gồm: dầm, cột, s&agrave;n lắp gh&eacute;p v&agrave; l&otilde;i to&agrave;n khối,...</p>\r\n<p>- C&aacute;c thư viện kết cấu sẵn c&oacute; hoặc x&acirc;y dựng sơ đồ kết cấu: s&agrave;n cột hay dầm, v&aacute;ch tr&ecirc;n mặt bằng, mặt đứng c&ocirc;ng tr&igrave;nh bằng c&aacute;c c&ocirc;ng cụ m&ocirc; h&igrave;nh đặc biệt.&nbsp;</p>\r\n<p>- Sử dụng hệ lưới c&aacute;c lựa chọn bắt điểm giống AutoCAD.&nbsp;</p>\r\n<p>-&nbsp; Kết cấu tự động sẽ đ&aacute;nh hệ trục định vị mặt bằng.</p>\r\n<p>&nbsp;- Xuất v&agrave; nhập sơ đồ h&igrave;nh học từ m&ocirc;i trường AutoCAD.</p>\r\n<p>Một cửa sổ với nhiều th&ocirc;ng tin</p>\r\n<p>ETABS cung cấp một giao diện người d&ugrave;ng duy nhất để thực hiện việc m&ocirc; h&igrave;nh, ph&acirc;n t&iacute;ch, thiết kế, triển khai chi tiết, v&agrave; b&aacute;o c&aacute;o. Ngo&agrave;i ra phần mềm con cho ph&eacute;p người d&ugrave;ng truy cập nhanh đến c&aacute;c đối tượng, thuộc t&iacute;nh, v&agrave; c&aacute;c thiết lập.</p>\r\n<p>Thu gọn</p>\r\n<div id=\"eJOY__extension_root\" class=\"eJOY__extension_root_class\" style=\"all: unset;\">&nbsp;</div>',NULL,'Published','ETABS','Etabs - Phần mềm phân tích, thiết kế kết cấu nhà cao tầng','ETABS, sản phẩm thủy lợi',NULL,2,NULL,'2020-10-11 05:03:27','2020-12-02 02:49:05','2020-12-02 02:49:05'),(2,'Thiết bị kiểm tra biến dạng nhỏ của cọc PET - CIC Company','thiet-bi-kiem-tra-bien-dang-nho-cua-coc-pet-cic-company','2020-10-11 13:40:00',1,0,'1602398508-thiet-bi-kiem-tra-bien-dang-nho-cua-coc-pet-cic-company.jpg','Đáp ứng TCVN 9397:2012 Cọc - Kiểm tra khuyết tật bằng phương pháp động biến dạng nhỏ','<div class=\" col-md-9 lbody\">\r\n<div class=\"menu1\">\r\n<div class=\"tab-content\">\r\n<div id=\"menu1\" class=\"tab-pane fade active in\">\r\n<div id=\"boxdex\" class=\"contentt boxdex\" data-height=\"650\">\r\n<p><strong><em><span lang=\"VI\">Th&ocirc;ng số vật l&yacute;:</span></em></strong></p>\r\n<p><em><span lang=\"VI\">- Lớp vỏ:&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Được l&agrave;m bằng nh&ocirc;m v&agrave; th&eacute;p kh&ocirc;ng gỉ c&oacute; độ bền cao</span></em></p>\r\n<p><em><span lang=\"VI\">- K&iacute;ch thước:&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span></em><em><span lang=\"VI\">ɸ</span></em><em><span lang=\"VI\">25,4 x 90 mm</span></em></p>\r\n<p><em><span lang=\"VI\">- Khối lượng:&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 120 g (đầu d&ograve;), 2,3 kg (khối lượng khi vận chuyển)</span></em></p>\r\n<p><em><span lang=\"VI\">- Nhiệt độ:&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Khi sử dụng: -20<sup>0</sup>C đến 55<sup>0</sup>C</span></em></p>\r\n<p><em><span lang=\"VI\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Khi lưu trữ: -40<sup>0</sup>C đến 80<sup>0</sup>C</span></em></p>\r\n<p><em><span lang=\"VI\">- M&ocirc;i trường:&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; IP67</span></em></p>\r\n<p><strong><em><span lang=\"VI\">Đầu d&ograve;:</span></em></strong></p>\r\n<p><em><span lang=\"VI\">- Độ nhạy:&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 100 mV/g</span></em></p>\r\n<p><em><span lang=\"VI\">- Độ tuyến t&iacute;nh:&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; Dưới 1%, từ 0 &ndash; 50g</span></em></p>\r\n<p><em><span lang=\"VI\">- Tần số cộng hưởng:&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 30 kHz</span></em></p>\r\n<p><em><span lang=\"VI\">- Tần số lấy mẫu:&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; 50 kHz</span></em></p>\r\n<p><em><span lang=\"VI\">- Độ ph&acirc;n giải lấy mẫu:&nbsp;&nbsp;&nbsp;&nbsp; 24bit</span></em></p>\r\n<p><strong><em><span lang=\"VI\">Ti&ecirc;u chuẩn:&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span></em></strong><em><span lang=\"VI\">Đ&aacute;p ứng ti&ecirc;u chuẩn ASTM D5882 - 07, TCVN 9397:2012</span></em></p>\r\n<p><strong><em><span lang=\"VI\">Hiệu năng:</span></em></strong></p>\r\n<p><em><span lang=\"VI\">- Chiều d&agrave;i cọc đo được:&nbsp;&nbsp;&nbsp;&nbsp; 2 &ndash; 100m (phụ thuộc v&agrave;o đường k&iacute;nh cọc v&agrave; địa chất)</span></em></p>\r\n<p><em><span lang=\"VI\">- Năng suất kiểm tra:&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; L&ecirc;n tới 100 cọc/giờ (trong điều kiện thuận lợi) với chỉ một người thực hiện</span></em></p>\r\n<p><em><span lang=\"VI\">- Khả năng lưu trữ dữ liệu: kh&ocirc;ng giới hạn (do thiết kế th&ocirc;ng minh với m&aacute;y t&iacute;nh t&aacute;ch rời)</span></em></p>\r\n<p><strong><em><span lang=\"VI\">Y&ecirc;u cầu m&aacute;y t&iacute;nh&nbsp;</span></em></strong><em><span lang=\"VI\">(PET Pro USB)<strong>:</strong></span></em></p>\r\n<p><em><span lang=\"VI\">- Microsoft Windows 2000/ XP/ Vista/ Win 7/ Win10;</span></em></p>\r\n<p><em><span lang=\"VI\">- Độ ph&acirc;n giải m&agrave;n h&igrave;nh tối thiểu 800x600;</span></em></p>\r\n<p><em><span lang=\"VI\">- Cổng kết nối USB.</span></em></p>\r\n<p><em><span lang=\"VI\">- M&aacute;y t&iacute;nh bảng (d&ugrave;ng ngo&agrave;i trời) hoặc Pocket PC (cổng kết nối USB) chạy Windows Mobile 5/6 (khuyến c&aacute;o của nh&agrave; sản xuất).</span></em></p>\r\n<p><strong><em><span lang=\"VI\">Y&ecirc;u cầu smartphone&nbsp;</span></em></strong><em><span lang=\"VI\">(PET Bluetooth)<strong>:</strong></span></em></p>\r\n<p><em><span lang=\"VI\">- Smartphone chạy hệ điều h&agrave;nh android 4 trở l&ecirc;n</span></em></p>\r\n<p>&nbsp;</p>\r\n</div>\r\n<div class=\"show\"><a class=\"btn btn-info details_click clickmore \" data-id=\"boxdex\" data-class=\"1\">Xem th&ocirc;ng tin đầy đủ</a></div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<div class=\"col-md-3 rbody\">\r\n<div class=\"taituychon\">&nbsp;</div>\r\n</div>\r\n<div id=\"eJOY__extension_root\" class=\"eJOY__extension_root_class\" style=\"all: unset;\">&nbsp;</div>','<h2>Thiết bị kiểm tra biến dạng nhỏ PET</h2>\r\n<p>Thiết bị PET (Pile Echo Tester) sử dụng phương ph&aacute;p pulse-echo. Để kiểm tra 1 cọc, người sử dụng d&ugrave;ng b&uacute;a nhẹ trong g&oacute;i dụng cụ, g&otilde; v&agrave;o cọc. T&iacute;n hiệu kết quả (c&ograve;n gọi l&agrave; biểu đồ phản ứng) được ghi lại v&agrave; ph&acirc;n t&iacute;ch bằng gia tốc kế kỹ thuật số của PET, từ đ&oacute; cung cấp c&aacute;c th&ocirc;ng tin về chiều d&agrave;i v&agrave; khuyết tật của cọc.</p>\r\n<p>Đ&acirc;y một giải ph&aacute;p cơ động cao, th&acirc;n thiện với người sử dụng trong việc kiểm tra một số lượng lớn c&aacute;c hệ m&oacute;ng s&acirc;u một c&aacute;ch nhanh ch&oacute;ng v&agrave; ch&iacute;nh x&aacute;c. Kh&ocirc;ng đ&ograve;i hỏi phải mất nhiều thời gian đ&agrave;o tạo, PET l&agrave; một hệ m&ocirc; đun độc lập với m&aacute;y t&iacute;nh, chỉ kết nối th&ocirc;ng qua cổng USB với m&aacute;y t&iacute;nh Notebook, Tablet PC, hoặc Pocket PC. Dựa tr&ecirc;n l&yacute; thuyết truyền s&oacute;ng ứng suất theo một phương trong thanh đ&agrave;n hồi g&acirc;y ra bởi t&aacute;c động của lực xung, trong đ&oacute; thay đổi kh&aacute;ng trở trong thanh s&oacute;ng phản hồi trở lại đỉnh.</p>\r\n<p>S&oacute;ng ứng suất được phản hồi tại mọi vị tr&iacute; c&oacute; sự thay đổi kh&aacute;ng trở cơ học của cọc v&agrave; phản hồi, thu nhận được ở đỉnh cọc sau khoảng thời gian tỷ lệ với khoảng c&aacute;ch vị tr&iacute; thay đổi kh&aacute;ng trở ấy. S&oacute;ng phản hồi n&agrave;y g&acirc;y ra sự thay đổi lực v&agrave; vận tốc đo được tại đỉnh cọc. Mức độ thay đổi bi&ecirc;n độ vận tốc tại đỉnh cọc cho ph&eacute;p x&aacute;c định mức độ thay đổi kh&aacute;ng trở, kết hợp với điều kiện địa chất thực tế l&agrave;m cơ sở cho việc ph&aacute;n đo&aacute;n t&iacute;nh nguy&ecirc;n vẹn của cọc.</p>\r\n<h2>Thiết bị PET gồm 2 model</h2>\r\n<h3>PET Pro USB</h3>\r\n<p>Đ&acirc;y một giải ph&aacute;p cơ động cao, th&acirc;n thiện với người sử dụng trong việc kiểm tra một số lượng lớn c&aacute;c hệ m&oacute;ng s&acirc;u một c&aacute;ch nhanh ch&oacute;ng v&agrave; ch&iacute;nh x&aacute;c. Kh&ocirc;ng đ&ograve;i hỏi phải mất nhiều thời gian đ&agrave;o tạo, PET l&agrave; một hệ m&ocirc; đun độc lập với m&aacute;y t&iacute;nh, chỉ kết nối th&ocirc;ng qua cổng USB với m&aacute;y t&iacute;nh notebook, m&aacute;y t&iacute;nh bảng, hoặc Pocket PC.</p>\r\n<h3>&nbsp;</h3>\r\n<h3>PET Bluetooth</h3>\r\n<h3>L&agrave; một giải ph&aacute;p th&acirc;n thiện với người sử dụng, c&oacute; độ linh hoạt cao trong việc kiểm tra một số lượng lớn c&aacute;c cọc m&oacute;ng s&acirc;u một c&aacute;ch nhanh ch&oacute;ng v&agrave; ch&iacute;nh x&aacute;c. Kh&ocirc;ng đ&ograve;i hỏi kỹ năng chuy&ecirc;n m&ocirc;n qu&aacute; cao, hướng dẫn v&agrave; sử dụng một c&aacute;ch dễ d&agrave;ng với một hệ thống m&ocirc; đun h&oacute;a, độc lập với m&aacute;y t&iacute;nh, c&oacute; thể c&oacute; kết nối kh&ocirc;ng d&acirc;y dạng Bluetooth. Tải phần mềm cho PET Bluetooth từ của h&agrave;ng ứng dụng CH Play.</h3>\r\n<p>.</p>\r\n<p>Th&ocirc;ng số vật l&yacute;</p>\r\n<p>- Lớp vỏ: Được l&agrave;m bằng nh&ocirc;m v&agrave; th&eacute;p kh&ocirc;ng gỉ c&oacute; độ bền cao</p>\r\n<p>- K&iacute;ch thước: ɸ25,4 x 90 mm</p>\r\n<p>- Khối lượng: 120g (đầu d&ograve;), 2,3kg (khối lượng khi vận chuyển)</p>\r\n<p>- Nhiệt độ: Khi sử dụng: -200C đến 550C</p>\r\n<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Khi lưu trữ: -400C đến 800C</p>\r\n<p>- M&ocirc;i trường: IP67</p>\r\n<p>Đầu d&ograve;</p>\r\n<p>- Độ nhạy: 100 mV/g</p>\r\n<p>- Độ tuyến t&iacute;nh: Dưới 1%, từ 0 &ndash; 50g</p>\r\n<p>- Tần số cộng hưởng: 30 kHz</p>\r\n<p>- Tần số lấy mẫu: 50Hz</p>\r\n<p>- Độ ph&acirc;n giải lấy mẫu: 24bit</p>\r\n<p>Hiệu năng</p>\r\n<p>- Chiều d&agrave;i cọc đo được: 2 &ndash; 100m (phụ thuộc v&agrave;o đường k&iacute;nh cọc v&agrave; địa chất)</p>\r\n<p>- Năng suất kiểm tra: L&ecirc;n tới 100 cọc/giờ (trong điều kiện thuận lợi) với chỉ một người thực hiện</p>\r\n<p>- Khả năng lưu trữ dữ liệu: kh&ocirc;ng giới hạn (do thiết kế th&ocirc;ng minh với m&aacute;y t&iacute;nh t&aacute;ch rời)</p>\r\n<p>Y&ecirc;u cầu m&aacute;y t&iacute;nh (PETPro USB):</p>\r\n<p>- Microsoft Windows 2000/ XP/ Vista/ Win 7/ Win10;</p>\r\n<p>- Độ ph&acirc;n giải m&agrave;n h&igrave;nh tối thiểu 800x600;</p>\r\n<p>- Cổng kết nối USB.</p>\r\n<p>- M&aacute;y t&iacute;nh bảng (d&ugrave;ng ngo&agrave;i trời) hoặc Pocket PC (cổng kết nối USB) chạy Windows Mobile 5/6.</p>\r\n<p>Y&ecirc;u cầu smartphone (PET Bluetooth):</p>\r\n<p>- Smartphone chạy hệ điều h&agrave;nh android 4 trở l&ecirc;n.</p>\r\n<p>TI&Ecirc;U CHUẨN &Aacute;P DỤNG</p>\r\n<ul>\r\n<li>TCVN 9397:2012 &ldquo;Cọc &ndash; Kiểm tra khuyết tật bằng phương ph&aacute;p động biến dạng nhỏ (PIT)&rdquo;.</li>\r\n<li>ASTM D5882-07 &ldquo;Phương ph&aacute;p th&iacute; nghiệm biến dạng nhỏ cho m&oacute;ng s&acirc;u&rdquo;.</li>\r\n</ul>\r\n<h2>Một số hạn chế</h2>\r\n<p>Đ&oacute; l&agrave; qu&atilde;ng đường truyền s&oacute;ng c&agrave;ng d&agrave;i th&igrave; năng lượng s&oacute;ng sẽ c&agrave;ng giảm đi. Do đ&oacute; c&aacute;c khuyết tật hoặc đ&aacute;y cọc khoan nhồi nằm s&acirc;u kh&oacute; được ph&aacute;t hiện.&nbsp;</p>\r\n<p>Đối với sự t&aacute;c động của b&uacute;a đập l&ecirc;n đầu cọc khoan nhồi trung b&igrave;nh, bước s&oacute;ng tạo ra v&agrave;o khoảng 1,6 m. Kh&oacute; ph&aacute;t hiện ra được c&aacute;c khuyết tật c&oacute; bề d&agrave;y nhỏ hơn 0,4 m.</p>\r\n<p>C&aacute;c trường hợp c&aacute;c khuyết tật hoặc đ&aacute;y cọc khoan nhồi nằm dưới khuyết tật tr&ecirc;n c&ugrave;ng sẽ kh&ocirc;ng tạo ra được c&aacute;c phản hồi. Phương ph&aacute;p th&iacute; nghiệm kiểm tra với c&aacute;c c&ocirc;ng nghệ hiện tại c&oacute; thể đưa ra được độ s&acirc;u của khuyết tật của cọc khoan nhồi m&agrave; kh&ocirc;ng đưa ra được hướng của n&oacute; so với tim cọc khoan nhồi.</p>\r\n<p>Thu gọn</p>\r\n<div id=\"eJOY__extension_root\" class=\"eJOY__extension_root_class\" style=\"all: unset;\">&nbsp;</div>',NULL,'Published','Thiết bị kiểm tra biến dạng nhỏ của cọc PET - CIC Company','Thiết bị kiểm tra biến dạng nhỏ của cọc PET - CIC Company','CIC, Cty CIC',NULL,2,NULL,'2020-10-11 06:41:48','2020-12-02 02:49:01','2020-12-02 02:49:01'),(3,'Radar xuyên đất (GPR/GEORADAR)','radar-xuyen-dat-gprgeoradar','2020-10-07 17:40:00',1,0,'1602412954-radar-xuyen-dat-gprgeoradar.jpg','Hệ thống radar xuyên đất được thiết kế chủ yếu cho mục đích dò tìm và định vị đường ống, cáp ngầm.','<div class=\" col-md-9 lbody\">\r\n<div class=\"menu1\">\r\n<div class=\"tab-content\">\r\n<div id=\"menu1\" class=\"tab-pane fade active in\">\r\n<div id=\"boxdex\" class=\"contentt boxdex\" data-height=\"650\">\r\n<div>\r\n<table align=\"left\">\r\n<tbody>\r\n<tr>\r\n<td align=\"left\" valign=\"top\">\r\n<p><strong>Model:</strong>&nbsp; PiL_Duo</p>\r\n<p><strong>Ứng dụng:&nbsp;</strong>D&ograve; t&igrave;m v&agrave; bản đồ h&oacute;a c&ocirc;ng tr&igrave;nh ngầm.</p>\r\n<p><strong>Giới thiệu:&nbsp;</strong>PiL_Duo l&agrave; một hệ thống radar xuy&ecirc;n đất được thiết kế chủ yếu cho mục đ&iacute;ch d&ograve; t&igrave;m v&agrave; định vị đường ống, c&aacute;p ngầm. Hệ thống được trang bị ăng ten tần số k&eacute;p 300 MHz v&agrave; 700 MHz gi&uacute;p định vị ch&iacute;nh x&aacute;c c&aacute;c đường ống, c&aacute;p ngầm&nbsp;ở vị tr&iacute; n&ocirc;ng v&agrave; s&acirc;u.&nbsp;&nbsp;Giao diện được thiết kế đặc biệt cho ph&eacute;p đ&aacute;nh dấu nhanh c&aacute;c mục ti&ecirc;u t&igrave;m thấy v&agrave; xuất th&ocirc;ng tin ở định dạng đồ họa (BMP, JPG) ngay tr&ecirc;n hiện trường.</p>\r\n<p><img src=\"https://www.cic.com.vn/upload_images/images/2020/07/21/p1(1).JPG\" alt=\"\" /></p>\r\n<p><strong>Th&ocirc;ng số kỹ thuật:</strong></p>\r\n<p><strong>*&nbsp;</strong>Th&ocirc;ng số chung:</p>\r\n<ul>\r\n<li>K&iacute;ch thước: 850x650x110 mm.</li>\r\n<li>Trọng lượng: 14.5 kg.</li>\r\n<li>Nguồn: LiIon 10.8V.</li>\r\n<li>Cấp bảo vệ: IP65.</li>\r\n</ul>\r\n<p>* Ăng ten:</p>\r\n<ul>\r\n<li>Loại ăng ten: tần số k&eacute;p.</li>\r\n<li>Tần số: 300 MHz v&agrave; 700 MHz.</li>\r\n<li>Dải chiều s&acirc;u qu&eacute;t lớn nhất: 0.1-8m.</li>\r\n</ul>\r\n<p>* Bộ điều khiển:</p>\r\n<ul>\r\n<li>M&agrave;n h&igrave;nh: 10.4 inch</li>\r\n<li>Hiển thị điều chỉnh độ s&acirc;u: c&oacute;.</li>\r\n<li>Hiển thị điều chỉnh độ d&agrave;i: c&oacute;.</li>\r\n<li>Chọn loại đất: c&oacute;.</li>\r\n<li>Lựa chọn hằng số điện m&ocirc;i: c&oacute;.</li>\r\n</ul>\r\n<p>* Phần mềm:&nbsp;<span lang=\"VI\">&nbsp;GPRSoft</span>&nbsp;Pro t&iacute;ch hợp chức năng 3D.</p>\r\n<p><strong><span lang=\"VI\">Thiết bị bao gồm:</span></strong></p>\r\n<p><span lang=\"VI\">- Khối điều khiển ăng ten t&iacute;ch hợp</span>&nbsp;c&ugrave;ng ăng ten<span lang=\"VI\">.</span></p>\r\n<p><span lang=\"VI\">- Phần mềm thu thập</span>&nbsp;v&agrave; xử l&yacute;<span lang=\"VI\">&nbsp;dữ liệu.</span></p>\r\n<p><span lang=\"VI\">-&nbsp;</span>Pin v&agrave; bộ sạc<span lang=\"VI\">.</span></p>\r\n<p><span lang=\"VI\">- Ăng ten tần số k&eacute;p 300 MHz v&agrave; 700 Mhz.</span></p>\r\n<p><span lang=\"VI\">- Xe khảo s&aacute;t</span>&nbsp;SVC-823<span lang=\"VI\">.</span></p>\r\n<p><span lang=\"VI\">- Laptop</span></p>\r\n<p><span lang=\"VI\">- Phần mềm xử l&yacute; dữ liệu GPRSoft</span>&nbsp;Pro<span lang=\"VI\">.</span></p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n</div>\r\n<p><strong>Bảo hành:</strong>&nbsp;36 tháng</p>\r\n<p>&nbsp;</p>\r\n</div>\r\n<div class=\"show\"><a class=\"btn btn-info details_click clickmore \" data-id=\"boxdex\" data-class=\"1\">Xem th&ocirc;ng tin đầy đủ</a></div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<div class=\"col-md-3 rbody\">\r\n<div class=\"taituychon\">&nbsp;</div>\r\n</div>\r\n<div id=\"eJOY__extension_root\" class=\"eJOY__extension_root_class\" style=\"all: unset;\">&nbsp;</div>','<h2>C&ocirc;ng nghệ Radar xuy&ecirc;n đất</h2>\r\n<p>C&ocirc;ng ngh&ecirc;̣ Radar xuy&ecirc;n đ&acirc;́t (GPR) là c&ocirc;ng ngh&ecirc;̣ ti&ecirc;n ti&ecirc;́n nh&acirc;́t hi&ecirc;̣n nay, c&ocirc;ng nghệ ứng dụng với mục đ&iacute;ch định vị các c&ocirc;ng trình ng&acirc;̀m ti&ecirc;̣n ích và ki&ecirc;̉m tra c&aacute;c&nbsp;k&ecirc;́t c&acirc;́u b&ecirc; t&ocirc;ng. Sử dụng c&ocirc;ng ngh&ecirc;̣ radar xuy&ecirc;n đất đ&ecirc;̉ xuy&ecirc;n vào các lớp dưới mặt đ&acirc;́t và b&ecirc;n trong các lớp b&ecirc; t&ocirc;ng đ&ecirc;̉ khảo sát và định vị t&acirc;́t cả các c&ocirc;ng trình ti&ecirc;̣n ích, các đ&ocirc;́i tượng, và các c&ocirc;ng trình ng&acirc;̀m khác. Đ&acirc;y l&agrave; những rủi ro ti&ecirc;̀m &acirc;̉n có th&ecirc;̉ ảnh hưởng trực ti&ecirc;́p và nghi&ecirc;m trọng các dự án của khách hàng n&ecirc;́u ch&uacute;ng ta kh&ocirc;ng phát hi&ecirc;̣n trước.</p>\r\n<h3>1. Kh&aacute;i niệm</h3>\r\n<p>Radar xuy&ecirc;n đất l&agrave; phương ph&aacute;p địa vật l&yacute; hiện đại dựa tr&ecirc;n cơ sở l&yacute; thuyết của trường s&oacute;ng điện từ ở dải tần số từ 10 - 3.000 MHz để nghi&ecirc;n cứu cấu tr&uacute;c v&agrave; đặc t&iacute;nh của kết cấu vật chất n&ocirc;ng với độ ph&acirc;n giải cao.</p>\r\n<h3>2. Nguy&ecirc;n l&yacute; hoạt động</h3>\r\n<ul>\r\n<li>Hệ thống thiết bị GPR gồm c&oacute; c&aacute;c bộ phận ch&iacute;nh: anten ph&aacute;t, anten thu, khối điều khiển, thiết bị hiển thị, nguồn điện.</li>\r\n<li>C&aacute;c xung s&oacute;ng điện từ sẽ được truyền từ anten ph&aacute;t, lan truyền trong m&ocirc;i trường v&agrave; phản xạ lại anten thu từ c&aacute;c mặt ranh giới hoặc c&aacute;c đối tượng c&oacute; c&aacute;c th&ocirc;ng số thuận lợi cho việc phản xạ s&oacute;ng điện từ.</li>\r\n<li>Thời gian lan truyền của s&oacute;ng điện từ từ l&uacute;c ph&aacute;t đến l&uacute;c thu từ v&agrave;i chục đến v&agrave;i ng&agrave;n nano/gi&acirc;y. Thời gian trễ sẽ phản &aacute;nh ch&iacute;nh x&aacute;c th&ocirc;ng tin về độ s&acirc;u của c&aacute;c đối tượng.</li>\r\n<li>Độ s&acirc;u khảo s&aacute;t, độ ph&acirc;n giải phụ thuộc lớn v&agrave;o tần số của anten, năng lượng truyền v&agrave; hằng số điện m&ocirc;i của đất.&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<strong>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</strong></li>\r\n</ul>\r\n<h3>3. C&aacute;c ứng dụng ti&ecirc;u biểu</h3>\r\n<p>C&ocirc;ng nghệ GPR được ứng dụng trong rất nhiều lĩnh vực: d&ograve; t&igrave;m v&agrave; bản đồ ho&aacute; c&ocirc;ng tr&igrave;nh ngầm, giao th&ocirc;ng, x&acirc;y dựng d&acirc;n dụng, địa chất v&agrave; m&ocirc;i trường, khảo cổ học, ph&aacute;p l&yacute; v&agrave; anh ninh, ...</p>\r\n<h4>3.1. D&ograve; t&igrave;m &amp; bản đồ ho&aacute; c&ocirc;ng tr&igrave;nh ngầm</h4>\r\n<p>C&aacute;c hệ thống GPR c&oacute; khả năng x&aacute;c định được cả c&aacute;c vật thể kim loại v&agrave; phi kim.Thiết bị cho ph&eacute;p d&ograve; t&igrave;m ch&iacute;nh x&aacute;c vị tr&iacute; c&aacute;c c&ocirc;ng tr&igrave;nh ngầm dưới l&ograve;ng đất. C&aacute;c hệ thống n&agrave;y thường sử dụng anten trong dải tần từ 210 &ndash; 1000 MHz, c&oacute; phần mềm chuy&ecirc;n dụng hỗ trợ c&ocirc;ng t&aacute;c bản đồ ho&aacute; c&ocirc;ng tr&igrave;nh ngầm ho&agrave;n to&agrave;n tự động. C&ocirc;ng nghệ thiết bị GPR c&oacute; khả năng thu thập dữ liệu nhanh, ch&iacute;nh x&aacute;c hơn c&aacute;c c&ocirc;ng nghệ kh&aacute;c. Kết quả trực quan v&agrave; kh&ocirc;ng l&agrave;m tổn hại đến hiện trạng bề mặt b&ecirc;n tr&ecirc;n.</p>\r\n<p>&nbsp;</p>\r\n<h4>&nbsp;</h4>\r\n<h4>&nbsp;</h4>\r\n<h4>3.2. Ứng dụng trong giao th&ocirc;ng</h4>\r\n<p>Radar xuy&ecirc;n đất gi&uacute;p khảo s&aacute;t nhanh v&agrave; lập bản đồ chiều d&agrave;y c&aacute;c ph&acirc;n lớp nền đường nhựa, nền đường băng s&acirc;n bay, c&aacute;c lớp ba l&aacute;t nền đường sắt, hoặc c&aacute;c hố sụt l&uacute;n tiềm ẩn phục vụ c&ocirc;ng t&aacute;c đ&aacute;nh gi&aacute; chất lượng nền đường giao th&ocirc;ng. C&aacute;c hệ thống thường được gắn với xe k&eacute;o (&ocirc; t&ocirc;, t&agrave;u hoả, ...) anten thường được sử dụng c&oacute; tần số 1000MHz hoặc 2000 MHz ( anten Horn).</p>\r\n<p>&nbsp;</p>\r\n<h4>&nbsp;</h4>\r\n<h4>&nbsp;</h4>\r\n<h4>3.3. Ứng dụng trong x&acirc;y dựng d&acirc;n dụng</h4>\r\n<p>C&ocirc;ng nghệ GPR cũng l&agrave; một trong những phương ph&aacute;p kiểm tra kh&ocirc;ng ph&aacute; hủy (Non Destructive Testing &ndash; NDT). Trong ứng dụng n&agrave;y, c&aacute;c hệ thống GPR sử dụng anten tần số cao (khoảng 1,5 &ndash; 2 GHz) để định vị v&agrave; bản đồ ho&aacute; lưới cốt th&eacute;p, x&aacute;c định chiều d&agrave;y lớp b&ecirc; t&ocirc;ng phủ, v&agrave; ph&aacute;t hiện khuyết tật nằm s&acirc;u trong c&aacute;c kết cấu b&ecirc; t&ocirc;ng cốt th&eacute;p d&agrave;y như tường, cột, s&agrave;n, cầu, ... m&agrave; kh&ocirc;ng g&acirc;y tổn hại đến kết cấu.</p>\r\n<h4>3.4. Ứng dụng khảo s&aacute;t địa chất v&agrave; m&ocirc;i trường</h4>\r\n<p>Hệ thống GPR c&oacute; một dải nhiều sự lựa chọn anten với c&aacute;c tần số kh&aacute;c nhau. Th&ocirc;ng thường từ 20 &ndash; 1.000 MHz, t&ugrave;y theo mục đ&iacute;ch sử dụng. Để khảo s&aacute;t c&aacute;c lớp địa tầng hay d&ograve; t&igrave;m c&aacute;c khoảng trống dưới l&ograve;ng đất, c&aacute;c kho&aacute;ng sản, mạch nước ngầm - thường l&agrave; ở vị tr&iacute; kh&aacute; s&acirc;u so với mặt đất, cần phải sử dụng những ăngten hoạt động ở tần số thấp (20 hoặc 50 MHz), bi&ecirc;n độ lớn để s&oacute;ng radar c&oacute; thể đạt được đến độ s&acirc;u y&ecirc;u cầu (l&ecirc;n tới v&agrave;i chục m&eacute;t t&ugrave;y theo tần số anten v&agrave; điều kiện địa chất).</p>\r\n<p>C&aacute;c hệ thống GPR c&oacute; khả năng hoạt động ở những địa h&igrave;nh gồ ghề phức tạp. Đ&oacute; cũng ch&iacute;nh l&agrave; một lợi thế nữa của c&ocirc;ng nghệ thiết bị GPR.</p>\r\n<h4>3.5. Ứng dụng trong khảo cổ học</h4>\r\n<p>Mục đ&iacute;ch của việc sử dụng phương ph&aacute;p GPR trong việc x&aacute;c định c&aacute;c di t&iacute;ch cổ nằm s&acirc;u dưới l&ograve;ng đất l&agrave; nhằm tr&aacute;nh g&acirc;y tổn hại c&aacute;c cổ vật, c&aacute;c di t&iacute;ch cổ trong qu&aacute; tr&igrave;nh khai quật. Th&ocirc;ng thường, người ta sử dụng c&aacute;c anten trong dải tần từ 210 &ndash; 1000 MHz cho mục đ&iacute;ch n&agrave;y. C&oacute; thể sử dụng hệ thống GPR với tần số cao, khoảng 1 &ndash; 2 GHz để kiểm tra, đ&aacute;nh gi&aacute; t&igrave;nh trạng. Kiểm tra c&aacute;c hư hại b&ecirc;n trong c&aacute;c di t&iacute;ch cổ, cổ vật đang được lưu giữ.</p>\r\n<h4>3.6. Ứng dụng trong ph&aacute;p l&yacute; v&agrave; an ninh</h4>\r\n<p>C&aacute;c hệ thống GPR sử dụng c&aacute;c anten c&oacute; tần số kh&aacute;c nhau phục vụ trong nhiều mục đ&iacute;ch kh&aacute;c nhau như: d&ograve; t&igrave;m c&ocirc;ng tr&igrave;nh ngầm, x&aacute;c người, vũ kh&iacute; được cất giấu, bom, m&igrave;n,...</p>\r\n<ol start=\"4\">\r\n<li><strong> Các lợi ích khi sử dụng c&ocirc;ng ngh&ecirc;̣ Radar:</strong></li>\r\n</ol>\r\n<ul>\r\n<li>Cho ph&eacute;p x&aacute;c định ch&iacute;nh x&aacute;c vị tr&iacute; v&agrave; chiều s&acirc;u đối tượng ngầm được cấu tạo từ mọi chất liệu: kim loại hoặc phi kim loại (nhựa, b&ecirc; t&ocirc;ng, ...), đồng thời ph&aacute;t hiện được c&aacute;c lớp địa tầng hoặc c&aacute;c bất thường trong cấu tr&uacute;c ngầm dưới l&ograve;ng đất.</li>\r\n<li>L&agrave; một phương ph&aacute;p kiểm tra kh&ocirc;ng ph&aacute; hủy gi&uacute;p giảm thiểu c&aacute;c nguy cơ li&ecirc;n đới. Tuyệt đối kh&ocirc;ng g&acirc;y tổn hại đến kết cấu.</li>\r\n<li>Ho&agrave;n to&agrave;n kh&ocirc;ng bị ảnh hưởng bởi nhiễu điện từ khi sử dụng c&aacute;c anten c&oacute; m&agrave;n chắn.</li>\r\n<li>L&agrave; phương ph&aacute;p khảo s&aacute;t ph&ugrave; hợp trong c&aacute;c khu đ&ocirc; thị, c&ocirc;ng nghiệp, kiến tr&uacute;c, văn h&oacute;a. Ngay cả c&aacute;c khu vực nhạy cảm với m&ocirc;i trường.</li>\r\n<li>Kết quả trực quan, sinh động, đ&aacute;ng tin cậy về kết cấu b&ecirc;n trong của c&aacute;c đối tượng.</li>\r\n<li>Tất cả c&aacute;c kết quả khảo s&aacute;t&nbsp; thể được lưu lại tr&ecirc;n bộ ghi dữ liệu để xử l&yacute;. Ph&acirc;n t&iacute;ch th&ecirc;m bằng phần mềm chuy&ecirc;n dụng in ra như l&agrave; một chứng nhận khảo s&aacute;t.</li>\r\n</ul>\r\n<h2>Đặc điểm nổi bật thiết bị d&ograve; t&igrave;m c&ocirc;ng tr&igrave;nh ngầm</h2>\r\n<ol>\r\n<li>Thiết bị GPR, model Detector Duo ph&aacute;t hiện c&aacute;c đối tượng nhờ thiết bị d&ograve; t&igrave;m c&ocirc;ng tr&igrave;nh ngầm như c&aacute;c đường tho&aacute;t nước, đường d&acirc;y c&aacute;p điện, c&aacute;p t&iacute;n hiệu hoặc c&aacute;c đường ống. C&aacute;c&nbsp;c&oacute; cấu tạo bằng vật liệu kim loại hoặc phi kim.</li>\r\n<li>C&aacute;c đối tượng được ph&aacute;t hiện c&oacute; t&iacute;n hiệu điển h&igrave;nh dạng đường ống, c&aacute;p điện kết hợp giải đo&aacute;n chuy&ecirc;n s&acirc;u với c&aacute;c th&ocirc;ng tin/bản vẽ hiện c&oacute; để ph&acirc;n biệt c&aacute;c đối tượng, c&aacute;c đối tượng n&agrave;y c&oacute; thể l&agrave;: đường ống cấp nước, đường ống tho&aacute;t nước hay đường c&aacute;p điện...</li>\r\n<li>Ngo&agrave;i việc được kế thừa anten tần số k&eacute;p 250 v&agrave; 700 MHz của model, Opera Duo c&ograve;n c&oacute; một số c&aacute;c lợi thế kh&aacute;c như sau:</li>\r\n</ol>\r\n<ul>\r\n<li>C&oacute; thể sử dụng phần mềm xử l&yacute; dữ liệu 3D để ph&acirc;n t&iacute;ch chuy&ecirc;n s&acirc;u c&aacute;c dữ liệu. Thu thập được từ thiết bị Opera Duo...</li>\r\n<li>Kết nối với bộ định vị GPS sử dụng chuẩn giao tiếp NMEA</li>\r\n<li>Với một n&uacute;t bấm duy nhất c&oacute; thể điều chỉnh chế độ hoạt động tr&ecirc;n mỗi điều kiện địa chất.</li>\r\n<li>Cho ph&eacute;p lựa chọn từ hơn 20 ng&ocirc;n ngữ kh&aacute;c nhau, trong đ&oacute; c&oacute; tiếng Việt;</li>\r\n<li>Thiết kế phần cứng gi&uacute;p cho&nbsp;thiết bị bền chắc hơn trong khi đ&oacute;&nbsp;thiết bị GPR c&oacute; thể dễ d&agrave;ng điều chỉnh tay cầm, dễ d&agrave;ng di chuyển&nbsp;v&agrave; th&acirc;n thiện với người d&ugrave;ng. Cơ cấu cổ xoay gi&uacute;p ổn định anten. Sử dụng tới 2 bộ đếm đo khoảng c&aacute;ch để x&aacute;c định vị tr&iacute;. Xịt sơn tự động gi&uacute;p đ&aacute;nh dấu đối tượng ngo&agrave;i thực địa (được điều khiển qua phần mềm).</li>\r\n</ul>\r\n<p>Thu gọn</p>\r\n<div id=\"eJOY__extension_root\" class=\"eJOY__extension_root_class\" style=\"all: unset;\">&nbsp;</div>',NULL,'Published','Radar xuyên đất (GPR/GEORADAR)','Hệ thống radar xuyên đất được thiết kế chủ yếu cho mục đích dò tìm và định vị đường ống, cáp ngầm.','Công ty CIC , GPR',NULL,2,NULL,'2020-10-11 10:42:34','2020-12-02 02:49:08','2020-12-02 02:49:08'),(4,'Pipe Flow Expert','pipe-flow-expert','2020-10-08 19:38:00',0,0,'1602420051-pipe-flow-expert.png','Pipe Flow Expert là phần mềm thiết kế, phân tích mạng lưới đường ống phức tạp và mô hình hệ thống đường ống','<p>Kh&ocirc;ng c&oacute; m&ocirc; tả</p>\r\n<div id=\"eJOY__extension_root\" class=\"eJOY__extension_root_class\" style=\"all: unset;\">&nbsp;</div>','<h2>Pipe Flow Expert</h2>\r\n<p>Đường ống l&agrave; một trong những hệ thống cực kỳ quan trọng của mỗi c&ocirc;ng tr&igrave;nh. Kh&aacute;c với tuyến ống v&agrave; hệ thống đường ống phổ biến hơn rất nhiều. Hệ thống đường ống xuất hiện hầu như trong mọi loại c&ocirc;ng tr&igrave;nh từ nhỏ đến lớn : từ c&ocirc;ng tr&igrave;nh d&acirc;n dụng ( t&ograve;a nh&agrave; cao tầng ) tới vận chuyển h&agrave;ng hải như gi&agrave;n khoan hay t&agrave;u biển, ngay cả những bệnh viện cũng cần c&oacute; một hệ thống đường ống phức tạp. Đường ống trong nh&agrave; m&aacute;y c&ocirc;ng nghiệp c&oacute; cấu tr&uacute;c phức tạp v&agrave; đa dạng nhất. Vậy để thiết kế c&aacute;c hệ thống n&agrave;y th&igrave; kỹ sư trong c&aacute;c c&ocirc;ng ty đang sử dụng phần mềm g&igrave;? Pipe Flow Expert ch&iacute;nh l&agrave; một sự lựa chọn tuyệt vời cho hệ thống đường ống phức tạp nhất.</p>\r\n<p>Pipe Flow Expert được sử dụng bởi c&aacute;c nh&agrave; thiết kế hệ thống ống &amp; kỹ sư thủy lực tại hơn 100 quốc gia tr&ecirc;n to&agrave;n thế giới. Phần mềm t&iacute;nh to&aacute;n tốc độ d&ograve;ng chảy, giảm &aacute;p suất đường ống v&agrave; hiệu suất bơm. N&oacute; c&oacute; thể m&ocirc; h&igrave;nh hệ thống đường ống với nhiều điểm cung cấp, bể xả, linh kiện, van v&agrave; nhiều m&aacute;y bơm nối tiếp hoặc song song.&nbsp;</p>\r\n<p>Pipe Flow Expert gi&uacute;p c&aacute;c kỹ sư ph&acirc;n t&iacute;ch v&agrave; giải quyết nhiều vấn đề tổn thất lưu lượng v&agrave; &aacute;p suất của hệ thống đường ống.</p>\r\n<p>Pipe Flow Expert cho ph&eacute;p bạn vẽ một hệ thống đường ống phức tạp v&agrave; ph&acirc;n t&iacute;ch c&aacute;c đặc điểm của hệ thống đ&oacute;.</p>\r\n<p>Pipe Flow Expert t&iacute;nh to&aacute;n lưu lượng ổn định v&agrave; &aacute;p suất tương ứng của hệ thống. Phần mềm cho ph&eacute;p ph&acirc;n t&iacute;ch hiệu quả những hệ thống thay đổi dưới điều kiện vận h&agrave;nh kh&aacute;c nhau.</p>\r\n<h2>C&aacute;c yếu tố theo d&otilde;i bao gồm:</h2>\r\n<ul>\r\n<li>Tốc độ lưu lượng của mỗi ống</li>\r\n<li>Tốc độ lưu chất mỗi ống</li>\r\n<li>Chuẩn số Reynolds</li>\r\n<li>Hệ số ma s&aacute;t</li>\r\n<li>Mất m&aacute;t &aacute;p do ma s&aacute;t</li>\r\n<li>Mất m&aacute;t &aacute;p do c&aacute;c khớp nối</li>\r\n<li>Mất m&aacute;t &aacute;p do c&aacute;c th&agrave;nh phần thiết bị đường ống</li>\r\n<li>&Aacute;p suất tại mỗi điểm nối</li>\r\n<li>Gi&aacute; trị đường &aacute;p lực nước HGL (hydraulic grade line)</li>\r\n<li>C&aacute;c điểm hoạt động của bơm.</li>\r\n<li>NPSHa tại đầu v&agrave;o bơm.</li>\r\n</ul>\r\n<h2>Một số t&iacute;nh năng nổi bật:</h2>\r\n<ul>\r\n<li>Giao diện người d&ugrave;ng th&acirc;n thiện, tốt nhất v&agrave; dễ sử dụng</li>\r\n<li>Bản vẽ isometric 3D v&agrave; chuẩn layout đường ống 2D</li>\r\n<li>Tối ưu h&oacute;a b&aacute;o c&aacute;o dạng PDF - sản xuất kết quả chuy&ecirc;n nghiệp Documents</li>\r\n<li>C&ocirc;ng cụ t&iacute;nh to&aacute;n mạnh mẽ c&oacute; khả năng giải c&aacute;c b&agrave;i to&aacute;n phức tạp</li>\r\n<li>T&iacute;nh to&aacute;n độ mất &aacute;p theo phương ph&aacute;p Darcy-Weisbach</li>\r\n<li>T&iacute;nh to&aacute;n hệ số ma s&aacute;t theo phương tr&igrave;nh Colebrook-White</li>\r\n<li>Khả năng m&ocirc; h&igrave;nh l&ecirc;n tới 1000 ống trong phi&ecirc;n bản đầy đủ của phần mềm</li>\r\n<li>Cơ sở dữ liệu lỏng với dữ liệu của chất lỏng v&agrave; kh&iacute; chung</li>\r\n<li>Cơ sở dữ liệu ống với vật liệu v&agrave; k&iacute;ch thước ống phổ biến</li>\r\n<li>Kết nối cơ sở dữ liệu chung van v&agrave; lắp dữ liệu</li>\r\n<li>Gi&aacute; trị mua phần mềm rất cao do khả năng của phần mềm</li>\r\n<li>Dịch vụ v&agrave; hỗ trợ đ&aacute;ng tin cậy, mạnh mẽ</li>\r\n<li>Học rất nhanh để sử dụng phần mềm</li>\r\n</ul>\r\n<h2>Lợi &iacute;ch của phần mềm Pipe Flow Expert</h2>\r\n<p>Pipe Flow Expert gi&uacute;p thực hiện c&aacute;c dự &aacute;n thiết kế mạng lưới cấp nước với hiệu suất cao v&agrave; chi ph&iacute; thấp.&nbsp;</p>\r\n<p>Trong thiết kế mạng lưới cấp nước, t&iacute;nh to&aacute;n lựa chọn đường ống đ&oacute;ng vai tr&ograve; quan trọng, chi ph&iacute; cho đường ống c&oacute; thể chiếm tới 80%&nbsp; gi&aacute; th&agrave;nh của hệ thống. Do vậy, t&iacute;nh to&aacute;n thủy lực để x&aacute;c định k&iacute;ch thước đường ống cần được giải quyết trước khi thể hiện bản thiết kế của mạng lưới cấp nước l&agrave; một b&agrave;i to&aacute;n &aacute;p lực cần giải quyết.</p>\r\n<p>Phần mềm Pipe Flow Expert cho ph&eacute;p ph&acirc;n t&iacute;ch tất cả yếu tố t&aacute;c nh&acirc;n tới nhiệt độ, chất lỏng, d&ograve;ng chảy trong mạng lưới cấp nước, k&iacute;ch thước thực của đường ống .... từ đ&oacute; cho ph&eacute;p t&iacute;nh to&aacute;n thủy lực được ch&iacute;nh x&aacute;c hơn, đồng thời hỗ trợ c&aacute;c b&aacute;o c&aacute;o về mặt cắt dọc, mặt cắt ngang v&agrave; bố cục tổng thể của mạng lưới.&nbsp;</p>\r\n<p>Đặc biệt Pipe Flow Expert nổi bật hơn c&aacute;c phần mềm kh&aacute;c ở việc m&ocirc; phỏng thiết kế mạng lưới cấp nước ở trong nh&agrave;, hệ thống cứu hỏa của c&aacute;c t&ograve;a nh&agrave; hay mạng lưới cấp nước dưới dạng 3D.</p>\r\n<p>Pipe Flow Expert c&oacute; thể ph&acirc;n t&iacute;ch hệ thống đường ống cho bất kỳ quy m&ocirc;, k&iacute;ch thước n&agrave;o. D&ugrave; bạn đang thiết kế lại c&aacute;c c&ocirc;ng tr&igrave;nh c&oacute; sẵn hay thiết kế một hệ thống mới. Pipe Flow Expert c&oacute; t&iacute;nh năng li&ecirc;n kết hai chiều giữa việc ph&acirc;n t&iacute;ch v&agrave; thiết kế. C&aacute;c kỹ sư v&agrave; bộ phận thiết kế dễ d&agrave;ng th&ocirc;ng qua đồng bộ h&oacute;a th&ocirc;ng tin khi c&oacute; sự thiết kế c&oacute; sự thay đổi.</p>\r\n<p>Thu gọn</p>\r\n<div id=\"eJOY__extension_root\" class=\"eJOY__extension_root_class\" style=\"all: unset;\">&nbsp;</div>',NULL,'Published','Pipe Flow Expert','Pipe Flow Expert là phần mềm thiết kế, phân tích mạng lưới đường ống phức tạp và mô hình hệ thống đường ống','Pipe Flow Expert, CIC',NULL,2,NULL,'2020-10-11 12:40:51','2020-12-02 02:48:46','2020-12-02 02:48:46'),(5,'SAP2000','sap2000','2020-10-01 19:42:00',0,0,'1602420211-sap2000.jpg','SAP2000 Phần mềm phân tích thiết kết cấu tổng hợp','<div class=\" col-md-9 lbody\">\r\n<div class=\"menu1\">\r\n<div class=\"tab-content\">\r\n<div id=\"menu1\" class=\"tab-pane fade active in\">\r\n<div id=\"boxdex\" class=\"contentt boxdex\" data-height=\"650\">\r\n<div id=\"detailFT0\" class=\"clearfix ma15 tinhnang text-center\">\r\n<h2 title=\"Giao diện\"><img src=\"https://www.consoft.vn/uploads/products/25661_10.jpg\" />&nbsp;Giao diện</h2>\r\n<div class=\"ma15 text-left\">\r\n<p><strong>Một cửa sổ, nhiều khung nh&igrave;n</strong></p>\r\n<p>SAP2000 cung cấp một giao diện người d&ugrave;ng đơn giản để hiển thị: M&ocirc; h&igrave;nh, Ph&acirc;n t&iacute;ch, Thiết kế, v&agrave; B&aacute;o c&aacute;o.<br /><br /><em>Giờ đ&acirc;y, người d&ugrave;ng c&oacute; c&aacute;ch xem m&ocirc; h&igrave;nh rất linh hoạt, c&aacute;c cửa sổ m&ocirc; h&igrave;nh v&agrave; c&aacute;c khung nh&igrave;n c&oacute; thể được bố tr&iacute; ra ngo&agrave;i bằng c&aacute;ch sử dụng c&aacute;c cửa sổ c&oacute; thể gắn được.</em></p>\r\n</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n<div id=\"content-tab\" class=\"ma15\">\r\n<ul id=\"tabs\" class=\"nav text-center nav-tabs\" data-tabs=\"tabs\">\r\n<li class=\"active\"><a href=\"https://www.consoft.vn/#TabFT590\" data-toggle=\"tab\" aria-expanded=\"true\">Enhanced User Interface</a></li>\r\n<li><a href=\"https://www.consoft.vn/#TabFT591\" data-toggle=\"tab\" aria-expanded=\"true\">Dockable Windows</a></li>\r\n</ul>\r\n<div id=\"my-tab-content\" class=\"tab-content\">\r\n<div id=\"TabFT590\" class=\"tab-pane  active \"><img src=\"https://www.consoft.vn/uploads/products/25863_sap2000_gui.jpg\" />\r\n<p class=\"ma15\">&nbsp;</p>\r\n</div>\r\n</div>\r\n</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n</div>\r\n<div id=\"detailFT1\" class=\"clearfix ma15 tinhnang text-center\">\r\n<h2 title=\"M&ocirc; h&igrave;nh\"><img src=\"https://www.consoft.vn/uploads/products/23017_05.jpg\" />&nbsp;M&ocirc; h&igrave;nh</h2>\r\n<div class=\"ma15 text-left\">\r\n<div class=\"col-md-12\">\r\n<p><strong>Thư viện mẫu</strong></p>\r\n<p>SAP2000 c&oacute; một thư viện mẫu nhiều lựa chọn, gi&uacute;p bắt đầu một m&ocirc; h&igrave;nh mới nhanh ch&oacute;ng. SAP2000 bao gồm c&aacute;c khu&ocirc;n mẫu tham số cho c&aacute;c loại cấu tr&uacute;c sau: Dầm đơn giản, Gi&agrave;n 3D, Khung 3D, Bể chứa, Cầu thang, Kết cấu đập, v&agrave; đường ống.</p>\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"700\"><img src=\"https://www.csiamerica.com/sites/default/files/templates.jpg\" /></p>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<p><strong>Khung nh&igrave;n m&ocirc; h&igrave;nh</strong></p>\r\n<p>Xem v&agrave; điều khiển m&ocirc; h&igrave;nh ph&acirc;n t&iacute;ch v&agrave; kết cấu với độ ch&iacute;nh x&aacute;c cao. Dễ d&agrave;ng định nghĩa c&aacute;c chế độ xem t&ugrave;y chỉnh v&agrave; mặt bằng để xem v&agrave; điều khiển m&ocirc; h&igrave;nh c&oacute; h&igrave;nh học phức tạp một c&aacute;ch dễ d&agrave;ng.<br /><br /><strong>Khung nh&igrave;n m&ocirc; h&igrave;nh vật thể</strong><br /><br /><img src=\"https://www.csiamerica.com/sites/default/files/sap2000-model-views-physical.jpg\" /></p>\r\n</div>\r\n<div class=\"tab-wrapper\">\r\n<div class=\"col col-md-12 tab-content\">\r\n<div id=\"object-model-view\" class=\"tab-pane active\">\r\n<div class=\"col col-md-12 img-full div-resize\" data-divheight=\"700\">\r\n<p>&nbsp;</p>\r\n<p><em>Chế độ xem m&ocirc; h&igrave;nh vật thể gi&uacute;p hiển thị ch&iacute;nh x&aacute;c c&aacute;c điểm ch&egrave;n cơ bản, c&aacute;c trục xoay địa phương, c&aacute;c n&uacute;t kết nối, v&agrave; h&igrave;nh học.</em></p>\r\n<p><br /><strong>Khung nh&igrave;n m&ocirc; h&igrave;nh phần tử</strong></p>\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"700\"><img src=\"https://www.csiamerica.com/sites/default/files/sap2000-model-views-analytical.jpg\" /></p>\r\n</div>\r\n<div class=\"col col-md-12 text-full\">\r\n<p><em>Khung nh&igrave;n m&ocirc; h&igrave;nh phần tử hiển thị m&ocirc; h&igrave;nh phần tử hữu hạn của kết cấu, được tạo th&agrave;nh từ sự kết nối của c&aacute;c n&uacute;t, khung, vỏ, v&agrave; được chia lưới.</em></p>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<div class=\"col-md-6\">\r\n<p><strong>Hệ lưới</strong></p>\r\n<p>Trong SAP2000, hệ lưới c&oacute; thể được định nghĩa l&agrave; hệ Đề-c&aacute;c hoặc tọa độ trụ. Kh&ocirc;ng c&oacute; giới hạn về số lượng hệ lưới trong một m&ocirc; h&igrave;nh v&agrave; ch&uacute;ng c&oacute; thể xoay theo bất kỳ hướng n&agrave;o hoặc đặt ở bất kỳ gốc n&agrave;o trong m&ocirc; h&igrave;nh.</p>\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"auto\"><img src=\"https://www.csiamerica.com/sites/default/files/sap2000-grids.jpg\" /><br />&nbsp;</p>\r\n</div>\r\n<div class=\"col-md-6\">\r\n<p><strong>Mặt bằng v&agrave; Mặt đứng</strong></p>\r\n<p>C&aacute;c khung nh&igrave;n về mặt bằng v&agrave; mặt đứng được tự động tạo ra ở mỗi đường lưới, cho ph&eacute;p điều hướng m&ocirc; h&igrave;nh nhanh ch&oacute;ng. Người d&ugrave;ng c&oacute; thể tạo c&aacute;c mặt phẳng tiết diện của ri&ecirc;ng m&igrave;nh bằng c&aacute;ch sử dụng t&iacute;nh năng khai b&aacute;o mặt phẳng khai triển.</p>\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"auto\"><img src=\"https://www.csiamerica.com/sites/default/files/plans-elevations.jpg\" /></p>\r\n<p>&nbsp;</p>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<p><strong>Chỉnh sửa dữ liệu linh hoạt</strong><br /><br />T&iacute;nh năng chỉnh sửa cơ sở dữ liệu tương t&aacute;c cho ph&eacute;p người d&ugrave;ng chỉnh sửa dữ liệu m&ocirc; h&igrave;nh trong một khung nh&igrave;n, gi&uacute;p đơn giản h&oacute;a việc chỉnh sửa m&ocirc; h&igrave;nh. C&aacute;c bảng được xuất v&agrave; nhập dễ d&agrave;ng từ Microsoft Excel v&agrave; Microsoft Access.</p>\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"650\"><img src=\"https://www.csiamerica.com/sites/default/files/interactive-database-editing_0.jpg\" /></p>\r\n<p>&nbsp;</p>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<p><strong>C&ocirc;ng cụ chia lưới</strong></p>\r\n<p>C&aacute;c kỹ sư c&oacute; nhiều lựa chọn khi chia lưới trong SAP2000. Đơn giản chỉ cần chọn đối tượng v&agrave; sau đ&oacute; chọn c&aacute;c quy tắc chia lưới tự động để sử dụng.<br /><br /><strong>Chia lưới tổng qu&aacute;t</strong></p>\r\n</div>\r\n<div id=\"meshing-overview\" class=\"tab-pane active\">\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"547\"><img src=\"https://www.csiamerica.com/sites/default/files/meshing-tools.jpg\" /></p>\r\n<div class=\"col col-md-12 text-full\">\r\n<p><em>Khung v&agrave; c&aacute;c bề mặt c&oacute; thể được chia mịn khi ph&acirc;n t&iacute;ch.</em></p>\r\n<p><br /><strong>R&agrave;ng buộc bi&ecirc;n</strong></p>\r\n<div class=\"col col-md-12 tab-content\">\r\n<div id=\"edge-constraints\" class=\"tab-pane active\">\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"547\"><img src=\"https://www.csiamerica.com/sites/default/files/edge-constraints.jpg\" /></p>\r\n<div class=\"col col-md-12 text-full\">\r\n<p><em>R&agrave;ng buộc bi&ecirc;n tự động l&agrave; một thuật to&aacute;n b&ecirc;n trong sẽ giải quyết vấn đề chia lưới kh&ocirc;ng khớp. V&iacute; dụ, nếu c&aacute;c n&uacute;t của một ram dốc v&agrave; một bức tường kh&ocirc;ng tr&ugrave;ng khớp, SAP2000 sẽ kết nối tất cả c&aacute;c mắt lưới kh&ocirc;ng khớp với nhau bằng c&aacute;ch sử dụng thuật to&aacute;n để hoạt động như một \"d&acirc;y k&eacute;o\" giữa c&aacute;c phần tử.</em></p>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n<div id=\"content-tab\" class=\"ma15\">&nbsp;</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n</div>\r\n<div id=\"detailFT2\" class=\"clearfix ma15 tinhnang text-center\">\r\n<h2 title=\"Th&agrave;nh phần kết cấu\"><img src=\"https://www.consoft.vn/uploads/products/14556_08.jpg\" />&nbsp;Th&agrave;nh phần kết cấu</h2>\r\n<div class=\"ma15 text-left\">\r\n<div class=\"col-md-12\">\r\n<p><strong>Phần tử n&uacute;t</strong></p>\r\n<p>SSAP2000 tự động tạo ra c&aacute;c n&uacute;t tại c&aacute;c giao điểm của phần tử hoặc c&aacute;c điểm b&ecirc;n trong khi chia đối tượng. C&aacute;c tọa độ điểm v&agrave; th&ocirc;ng tin của điểm c&oacute; thể được hiển thị tr&ecirc;n m&agrave;n h&igrave;nh trong cửa sổ m&ocirc; h&igrave;nh hoặc ở dạng bảng.</p>\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"519\"><img src=\"https://www.csiamerica.com/sites/default/files/sap2000-joints-1.jpg\" /></p>\r\n<p>&nbsp;</p>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<p><strong>Phần tử khung</strong></p>\r\n<p>Phần tử khung sử dụng dạng tổng qu&aacute;t, ba chiều, dầm &ndash; cột, bao gồm c&aacute;c ảnh hưởng của uốn 2 phương, xoắn, biến dạng dọc trục, v&agrave; biến dạng cắt theo 2 phương. SAP2000 c&oacute; một thư viện c&aacute;c tiết diện b&ecirc;t&ocirc;ng, th&eacute;p v&agrave; tiết diện li&ecirc;n hợp theo ti&ecirc;u chuẩn của cả Hoa Kỳ v&agrave; ti&ecirc;u chuẩn Quốc tế</p>\r\n</div>\r\n<div class=\"tab-wrapper\">\r\n<div class=\"col col-md-12 tab-container\">\r\n<ul class=\"nav-tabs\">\r\n<li class=\"active\">\r\n<p>Phần tử khung tổng qu&aacute;t</p>\r\n</li>\r\n</ul>\r\n</div>\r\n<div class=\"col col-md-12 tab-content\">\r\n<div id=\"frames-overview\" class=\"tab-pane active\">\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"578\"><img src=\"https://www.csiamerica.com/sites/default/files/frames-1.jpg\" /></p>\r\n<div class=\"col col-md-12 text-full\">\r\n<p><em>C&aacute;c điểm trung gian sẽ tự động được tạo ra tại vị tr&iacute; giao của c&aacute;c đối tượng kh&aacute;c với khung, gi&uacute;p đảm bảo kết nối phần tử hữu hạn.</em><br />&nbsp;</p>\r\n<ul class=\"nav-tabs\">\r\n<li class=\"active\">\r\n<p>Đặc trưng tiết diện</p>\r\n</li>\r\n</ul>\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"571\"><img src=\"https://www.csiamerica.com/sites/default/files/section-properties.jpg\" /></p>\r\n<p><em>Ngay cả c&aacute;c tiết diện phi lăng trụ v&agrave; tiết diện th&eacute;p tổ hợp cũng được khai b&aacute;o dể d&agrave;ng, bằng c&aacute;ch sử dụng t&iacute;nh năng Thiết kế tiết diện cho c&aacute;c tiết diện phức tạp.</em></p>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<div class=\"col-md-6\">\r\n<p><strong>Phần tử d&acirc;y c&aacute;p</strong></p>\r\n<p>Phần tử c&aacute;p l&agrave; một phần tử phi tuyến bậc cao được sử dụng để m&ocirc; h&igrave;nh ứng xử mắc x&iacute;ch của c&aacute;p mỏng chịu tải trọng bản th&acirc;n. Độ bền k&eacute;o v&agrave; chuyển vị lớn phi tuyến đ&atilde; được đưa v&agrave;o thuật to&aacute;n.</p>\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"auto\"><img src=\"https://www.csiamerica.com/sites/default/files/cable.jpg\" /></p>\r\n<p>&nbsp;</p>\r\n</div>\r\n<div class=\"col-md-6\">\r\n<p><strong>C&aacute;p dự ứng lực</strong></p>\r\n<p>C&aacute;c c&aacute;p dự ứng lực c&oacute; thể vẽ dễ d&agrave;ng như c&aacute;c đối tượng độc lập, với h&igrave;nh dạng đường thẳng, parabol, đường cong tr&ograve;n hoặc c&aacute;c h&igrave;nh dạng t&ugrave;y &yacute; kh&aacute;c. C&aacute;c tải c&aacute;p, bao gồm mất m&aacute;t ứng suất, dễ d&agrave;ng được định nghĩa trong SAP2000.</p>\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"auto\"><img src=\"https://www.csiamerica.com/sites/default/files/tendon.jpg\" /></p>\r\n<p>&nbsp;</p>\r\n</div>\r\n<div class=\"col-md-6 clear-this\">\r\n<p><strong>Phần tử vỏ</strong></p>\r\n<p>Phần tử vỏ l&agrave; một loại đối tượng bề mặt được sử dụng để m&ocirc; h&igrave;nh m&agrave;ng, tấm, v&agrave; ứng xử vỏ trong c&aacute;c cấu tr&uacute;c phẳng v&agrave; ba chiều. Vật liệu vỏ c&oacute; thể l&agrave; đồng nhất hoặc lớp trong suốt; t&iacute;nh phi tuyến vật liệu cũng c&oacute; thể được xem x&eacute;t khi sử dụng vỏ dạng lớp.</p>\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"auto\"><img src=\"https://www.csiamerica.com/sites/default/files/shells_0.jpg\" /></p>\r\n<p>&nbsp;</p>\r\n</div>\r\n<div class=\"col-md-6\">\r\n<p><strong>Phần tử khối</strong></p>\r\n<p>Phần tử khối l&agrave; một phần tử t&aacute;m n&uacute;t d&ugrave;ng để m&ocirc; h&igrave;nh kết cấu ba chiều v&agrave; khối 3D. N&oacute; dựa tr&ecirc;n c&ocirc;ng thức đẳng tham số bao gồm 9 kiểu uốn kh&ocirc;ng tương th&iacute;ch ngẫu nhi&ecirc;n v&agrave; rất hữu &iacute;ch cho việc m&ocirc; h&igrave;nh c&aacute;c đối tượng, trong đ&oacute; tải trọng, điều kiện bi&ecirc;n, đặc trưng tiết diện, hoặc c&aacute;c phản lực kh&aacute;c nhau theo độ d&agrave;y.</p>\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"auto\"><img src=\"https://www.csiamerica.com/sites/default/files/solid.jpg\" /></p>\r\n<p>&nbsp;</p>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<p><strong>Phần tử li&ecirc;n kết</strong></p>\r\n<p>Một phần tử li&ecirc;n kết c&oacute; thể c&oacute; ba loại ứng xử kh&aacute;c nhau: tuyến t&iacute;nh, phi tuyến, v&agrave; phụ thuộc tần số, t&ugrave;y theo loại thuộc t&iacute;nh được g&aacute;n cho phần tử đ&oacute; v&agrave; loại ph&acirc;n t&iacute;ch đang được thực hiện. C&aacute;c th&agrave;nh phần li&ecirc;n kết sau c&oacute; sẵn trong SAP2000: tuyến t&iacute;nh, đ&agrave;n hồi đa tuyến t&iacute;nh, dẻo đa tuyến t&iacute;nh, Gaps, Hooks, bộ giảm chấn, bộ c&aacute;ch ly ma s&aacute;t, bộ c&aacute;ch ly cao su, bộ c&aacute;ch ly T / C, l&ograve; xo phụ thuộc tần số v&agrave; bộ giảm chấn phụ thuộc tần số.</p>\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"489\"><img src=\"https://www.csiamerica.com/sites/default/files/link.jpg\" /></p>\r\n<p>&nbsp;</p>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<p><strong>Phần tử khớp</strong></p>\r\n<p>Người d&ugrave;ng c&oacute; thể khai b&aacute;o v&agrave; &aacute;p dụng c&aacute;c thuộc t&iacute;nh khớp để thực hiện ph&acirc;n t&iacute;ch đẩy dần trong SAP2000. Ứng xử phi tuyến vật liệu trong c&aacute;c phần tử khung (dầm / cột / giằng) c&oacute; thể được m&ocirc; h&igrave;nh bằng c&aacute;ch sử dụng khớp dạng sợi. C&aacute;ch tiếp cận n&agrave;y x&eacute;t đến t&iacute;nh chất vật liệu trong mặt cắt tiết diện như c&aacute;c điểm rời rạc, mỗi điểm đều c&oacute; c&aacute;c đường cong ứng suất &ndash; biến dạng ch&iacute;nh x&aacute;c của vật liệu. C&aacute;c vật liệu hỗn hợp, như b&ecirc; t&ocirc;ng cốt th&eacute;p v&agrave; h&igrave;nh dạng phức tạp c&oacute; thể được x&eacute;t đến.</p>\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"565\"><img src=\"https://www.csiamerica.com/sites/default/files/hinge_0.jpg\" /></p>\r\n<p>&nbsp;</p>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<p><strong>Phần tử l&ograve; xo</strong></p>\r\n<p>C&aacute;c gối l&ograve; xo l&agrave; c&aacute;c phần tử li&ecirc;n kết được sử dụng để li&ecirc;n kết đ&agrave;n hồi c&aacute;c n&uacute;t với mặt đất v&agrave; c&oacute; thể x&eacute;t tuyến t&iacute;nh hoặc phi tuyến t&iacute;nh. C&aacute;c điều kiện gối phi tuyến c&oacute; thể được m&ocirc; phỏng bao gồm c&aacute;c khe (chỉ chịu n&eacute;n), c&aacute;c l&ograve; xo dẻo hoặc đ&agrave;n hồi đa tuyến, bộ giảm chấn nhớt, v&agrave; c&aacute;c bộ c&aacute;ch ly cơ học.</p>\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"339\"><img src=\"https://www.csiamerica.com/sites/default/files/springs.jpg\" /></p>\r\n<p>&nbsp;</p>\r\n</div>\r\n</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n<div id=\"content-tab\" class=\"ma15\">&nbsp;</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n</div>\r\n<div id=\"detailFT3\" class=\"clearfix ma15 tinhnang text-center\">\r\n<h2 title=\"Tải trọng\"><img src=\"https://www.consoft.vn/uploads/products/25065_04.jpg\" />&nbsp;Tải trọng</h2>\r\n<div class=\"ma15 text-left\">\r\n<div class=\"col-md-12\">\r\n<p><strong>C&aacute;c ti&ecirc;u chuẩn tải trọng tự động</strong></p>\r\n<p>SAP2000 sẽ tự động tạo ra v&agrave; g&aacute;n tải trọng động đất v&agrave; gi&oacute; dựa tr&ecirc;n c&aacute;c ti&ecirc;u chuẩn quốc tế kh&aacute;c nhau. SAP2000 cũng c&oacute; một t&iacute;nh năng tạo tải trọng động phức tạp cho ph&eacute;p người sử dụng để g&aacute;n tải trọng động v&agrave;o khung v&agrave; c&aacute;c phần tử vỏ.</p>\r\n</div>\r\n<div class=\"tab-wrapper\">\r\n<div class=\"col col-md-12 tab-container\">\r\n<ul class=\"nav-tabs\">\r\n<li class=\"active\">\r\n<p><strong><span class=\"gtm-tab\">Seismic</span></strong></p>\r\n<div class=\"col col-md-12 tab-content\">\r\n<div id=\"seismic\" class=\"tab-pane active\">\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"422\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/seismic.jpg\" data-expand=\"auto\" /></p>\r\n<p class=\"col col-md-12 text-full\"><em>C&aacute;c ti&ecirc;u chuẩn được hỗ trợ bao gồm: UBC 94; 97, BOCA 96, NBCC 95; 2005; 2010, IBC 2003; 2006, Chinese 2002, ISI1893 2002, NEHRP 97, c&aacute;c hệ số v&agrave; tải trọng do người d&ugrave;ng khai b&aacute;o.</em></p>\r\n</div>\r\n</div>\r\n</li>\r\n<li>\r\n<p><strong>Tải trọng gi&oacute;</strong></p>\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"422\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/wind.jpg\" data-expand=\"auto\" /></p>\r\n<p><em>C&aacute;c ti&ecirc;u chuẩn được hỗ trợ bao gồm: UBC 94, 97, BOCA 96, ASCE 7-95, -02, -05, NBCC 2005, Mexican 2010, Chinese 2002, IS875 1987, c&aacute;c tải trọng do người d&ugrave;ng khai b&aacute;o.</em></p>\r\n</li>\r\n<li>\r\n<p><strong>Tải trọng di động</strong></p>\r\n</li>\r\n</ul>\r\n<div class=\"col col-md-12 tab-content\">\r\n<div id=\"moving-loads\" class=\"tab-pane active\">\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"422\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/moving-loads_0.jpg\" data-expand=\"auto\" /></p>\r\n<div class=\"col col-md-12 text-full\">\r\n<p><em>Bộ tạo tải trọng động sẽ di chuyển một phương tiện truyền tải trong một l&agrave;n để x&aacute;c định điều kiện bi&ecirc;n lớn nhất.</em></p>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<div class=\"col col-md-12 tab-content\">\r\n<p class=\"tab-pane active\"><br /><br /><strong>Tải trọng s&oacute;ng</strong></p>\r\n</div>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<p>T&iacute;nh năng tải s&oacute;ng sẽ tự động tạo ra tải t&aacute;c động l&ecirc;n kết cấu do t&aacute;c động của s&oacute;ng, d&ograve;ng chảy, đẩy nổi v&agrave; gi&oacute;. Tải trọng tĩnh tuyến t&iacute;nh theo nhiều bước được tạo ra đề m&ocirc; phỏng s&oacute;ng di chuyển qua kết cấu. Ngo&agrave;i ra, tải động (theo lịch sử thời gian) cũng c&oacute; thể được tạo ra để x&eacute;t đến hiệu ứng qu&aacute;n t&iacute;nh khi s&oacute;ng di chuyển qua kết cấu.</p>\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"549\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/wave-loading.jpg\" data-expand=\"auto\" /></p>\r\n<p>&nbsp;</p>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<p><strong>Tải trọng do người d&ugrave;ng khai b&aacute;o</strong></p>\r\n<p>Việc khai b&aacute;o c&aacute;c tải trọng ri&ecirc;ng biệt để m&ocirc; h&igrave;nh một loạt c&aacute;c điều kiện tải được tiến h&agrave;nh bằng c&aacute;c lựa chọn tải trọng do người d&ugrave;ng khai b&aacute;o c&oacute; sẵn trong SAP2000.</p>\r\n</div>\r\n<div class=\"col col-md-12 tab-container\">\r\n<ul class=\"nav-tabs\">\r\n<li class=\"active\">\r\n<p><strong>Lực / Momen</strong></p>\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"571\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/force-moment.jpg\" data-expand=\"auto\" /></p>\r\n<p><em>Tải trọng dạng lực được sử dụng để g&aacute;n lực tập trung v&agrave; momen tập trung tại c&aacute;c n&uacute;t. C&aacute;c gi&aacute; trị c&oacute; thể được x&aacute;c định trong một hệ tọa độ cố định (tọa độ tổng thể hoặc thay thế) hoặc hệ tọa độ địa phương của n&uacute;t.</em></p>\r\n</li>\r\n<li>\r\n<p><strong>Chuyển vị</strong></p>\r\n<div id=\"displacement\" class=\"tab-pane active\">\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"571\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/displacement-loads.jpg\" data-expand=\"auto\" /></p>\r\n<p class=\"col col-md-12 text-full\"><em>Tải trọng do chuyển vị x&eacute;t đến ảnh hưởng của độ l&uacute;n v&agrave; c&aacute;c chuyển vị cưỡng bức b&ecirc;n ngo&agrave;i t&aacute;c động l&ecirc;n kết cấu. Tải trọng do chuyển vị được h&igrave;nh th&agrave;nh th&ocirc;ng qua c&aacute;c li&ecirc;n kết cứng cũng như c&aacute;c gối l&ograve; xo tuyến t&iacute;nh v&agrave; phi tuyến. Sự k&iacute;ch th&iacute;ch động học c&oacute; thể xem x&eacute;t cho kết cấu c&oacute; điền kiện đất nền phức tạp hoặc nhịp lớn</em>.</p>\r\n</div>\r\n<p>&nbsp;</p>\r\n</li>\r\n<li>\r\n<p><strong>Nhiệt độ</strong></p>\r\n<div id=\"temperature\" class=\"tab-pane active\">\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"571\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/temperature-loads.jpg\" data-expand=\"auto\" /></p>\r\n<p class=\"col col-md-12 text-full\"><em>Tải trọng do nhiệt tạo ra biến dạng nhiệt trong phần tử khung. Biến dạng n&agrave;y được tạo ra từ hệ số vật liệu x&eacute;t đến sự gi&atilde;n nở v&igrave; nhiệt v&agrave; sự thay đổi nhiệt độ của phần tử. Tất cả c&aacute;c tải nhiệt được quy định x&eacute;t đến sự thay đổi nhiệt độ từ trạng th&aacute;i kh&ocirc;ng ứng suất trong ph&acirc;n t&iacute;ch tuyến t&iacute;nh, hoặc từ trạng th&aacute;i đ&atilde; t&iacute;ch nhiệt trong ph&acirc;n t&iacute;ch phi tuyến.</em></p>\r\n</div>\r\n<p>&nbsp;</p>\r\n</li>\r\n<li>\r\n<p><strong>Biến dạng</strong></p>\r\n<div id=\"strain\" class=\"tab-pane active\">\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"571\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/strain-loads.jpg\" data-expand=\"auto\" /></p>\r\n<p class=\"col col-md-12 text-full\"><em>S&aacute;u loại biến dạng được &aacute;p dụng, mỗi loại tương ứng với một loại nội lực trong một phần tử khung, bao gồm: lực dọc, 2 lực cắt, momen xoắn v&agrave; 2 momen uốn.</em></p>\r\n</div>\r\n<p>&nbsp;</p>\r\n</li>\r\n<li>\r\n<p><strong>&Aacute;p lực chất lỏng</strong></p>\r\n</li>\r\n</ul>\r\n<div class=\"col col-md-12 tab-content\">\r\n<div id=\"pore-pressure\" class=\"tab-pane active\">\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"571\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/pore-pressure.jpg\" data-expand=\"auto\" /></p>\r\n<div class=\"col col-md-12 text-full\">\r\n<p><em>Tải do &aacute;p lực chất lỏng được sử dụng để m&ocirc; h&igrave;nh ảnh hưởng k&eacute;o v&agrave; đẩy nổi của chất lỏng trong m&ocirc;i trường vật chất, chẳng hạn như ảnh hưởng của nước l&ecirc;n phần tử hạt của đất.</em></p>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<p class=\"tab-pane active\">&nbsp;</p>\r\n</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n<div id=\"content-tab\" class=\"ma15\">&nbsp;</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n</div>\r\n<div id=\"detailFT4\" class=\"clearfix ma15 tinhnang text-center\">\r\n<h2 title=\"Ph&acirc;n t&iacute;ch\"><img src=\"https://www.consoft.vn/uploads/products/401_01.jpg\" />&nbsp;Ph&acirc;n t&iacute;ch</h2>\r\n<div class=\"ma15 text-left\">\r\n<div class=\"col-md-12\">\r\n<div><strong>Tổng quan</strong><br />&nbsp;</div>\r\n<div>C&aacute;c giải ph&aacute;p của CSI đ&atilde; được thử nghiệm v&agrave; kiểm nghiệm bởi ng&agrave;nh c&ocirc;ng nghiệp trong hơn 35 năm. C&ocirc;ng cụ ph&acirc;n t&iacute;ch SAPFire c&oacute; thể hỗ trợ hệ điều h&agrave;nh 64-bit gi&uacute;p tối ưu h&oacute;a ph&acirc;n t&iacute;ch v&agrave; thực hiện cả Ph&acirc;n t&iacute;ch Eigen v&agrave; Ph&acirc;n t&iacute;ch Ritz.</div>\r\n<div class=\"col col-md-12 img-full div-resize\" data-divheight=\"353\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/analysis.jpg\" data-expand=\"auto\" /></div>\r\n<div>&nbsp;</div>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<div><strong>Ph&acirc;n t&iacute;ch tĩnh</strong><br />&nbsp;</div>\r\n<div>SAP2000 c&oacute; thể x&eacute;t cả ph&acirc;n t&iacute;ch tĩnh tuyến t&iacute;nh v&agrave; ph&acirc;n t&iacute;ch tĩnh nhiều bước. Ph&acirc;n t&iacute;ch tĩnh tuyến t&iacute;nh kết cấu gồm việc giải hệ phương tr&igrave;nh tuyến t&iacute;nh được x&aacute;c định dạng K u = r. Một số loại tải nhất định được t&iacute;nh to&aacute;n nhiều bước, c&oacute; nghĩa l&agrave; ch&uacute;ng đại diện cho những loại tải trọng kh&ocirc;ng gian ri&ecirc;ng biệt, được g&aacute;n theo tr&igrave;nh tự. Ch&uacute;ng bao gồm tải do xe cộ, tải động, v&agrave; tải s&oacute;ng.<br />&nbsp;</div>\r\n<div class=\"col col-md-12 img-full div-resize\" data-divheight=\"529\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/statics.jpg\" data-expand=\"auto\" /><br />&nbsp;</div>\r\n<div><br /><strong>Ph&acirc;n t&iacute;ch động lực học</strong><br />&nbsp;</div>\r\n<div>Khả năng ph&acirc;n t&iacute;ch động học của SAP2000 bao gồm t&iacute;nh to&aacute;n c&aacute;c kiểu dao động sử dụng c&aacute;c vector Ritz hoặc Eigen, ph&acirc;n t&iacute;ch phổ phản ứng v&agrave; ph&acirc;n t&iacute;ch lịch sử thời gian cho cả ứng xử tuyến t&iacute;nh v&agrave; phi tuyến.</div>\r\n</div>\r\n<div class=\"tab-wrapper\">\r\n<div class=\"col col-md-12 tab-container\">\r\n<ul class=\"nav-tabs\">\r\n<li class=\"active\">\r\n<div><strong>Theo m&ocirc; h&igrave;nh</strong></div>\r\n<div class=\"col col-md-12 tab-content\">\r\n<div id=\"modal\" class=\"tab-pane active\">\r\n<div class=\"col col-md-12 img-full div-resize\" data-divheight=\"402\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/modal.jpg\" data-expand=\"auto\" /></div>\r\n<div class=\"col col-md-12 text-full\"><em>Ph&acirc;n t&iacute;ch dạng m&ocirc; h&igrave;nh vector- Eigen t&igrave;m ra c&aacute;c kiểu dao động l&agrave; cơ sở cho việc cộng t&aacute;c dụng c&aacute;c trường hợp tải trong m&ocirc; h&igrave;nh phổ phản ứng v&agrave; m&ocirc; h&igrave;nh theo lịch sử thời gian. Ph&acirc;n t&iacute;ch dạng m&ocirc; h&igrave;nh vector-Ritz t&igrave;m ra c&aacute;c kiểu dao động tối ưu để nắm bắt ứng xử cấu tr&uacute;c trong c&aacute;c trường hợp tải trọng m&ocirc; h&igrave;nh phổ phản ứng v&agrave; m&ocirc; h&igrave;nh theo lịch sử thời gian, v&agrave; hiệu quả hơn so với ph&acirc;n t&iacute;ch theo vector- Eigen.</em><br />&nbsp;</div>\r\n</div>\r\n</div>\r\n</li>\r\n<li>\r\n<div><strong>Theo phổ phản ứng</strong></div>\r\n<div id=\"response-spectrum\" class=\"tab-pane active\">\r\n<div class=\"col col-md-12 img-full div-resize\" data-divheight=\"402\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/response.jpg\" data-expand=\"auto\" /></div>\r\n<div class=\"col col-md-12 text-full\"><em>Ph&acirc;n t&iacute;ch phổ phản ứng x&aacute;c định sự đ&aacute;p ứng của một kết cấu đối với tải động đất dạng số liệu thống k&ecirc;. Kiểu ph&acirc;n t&iacute;ch tuyến t&iacute;nh n&agrave;y sử dụng c&aacute;c bản ghi gia tốc nền phổ phản ứng dựa v&agrave;o tải trọng động đất v&agrave; vị tr&iacute; trận động đất, kh&ocirc;ng phải l&agrave; c&aacute;c bản ghi dịch chuyển của nền đất theo lịch sử thời gian. Phương ph&aacute;p n&agrave;y rất hiệu quả v&agrave; c&oacute; t&iacute;nh đến c&aacute;c ứng xử động của kết cấu.</em><br />&nbsp;</div>\r\n</div>\r\n</li>\r\n<li>\r\n<div><strong>Ph&acirc;n t&iacute;ch theo lịch sử thời gian</strong></div>\r\n<div class=\"tab-wrapper\">\r\n<div class=\"col col-md-12 tab-content\">\r\n<div id=\"time-history\" class=\"tab-pane active\">\r\n<div class=\"col col-md-12 img-full div-resize\" data-divheight=\"402\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/time-history_0.jpg\" data-expand=\"auto\" /></div>\r\n<div class=\"col col-md-12 text-full\"><em>Ph&acirc;n t&iacute;ch lịch sử thời gian bao gồm phản ứng theo từng bước của kết cấu đối với chuyển dịch nền đất do động đất v&agrave; c&aacute;c loại tải kh&aacute;c như nổ, m&aacute;y m&oacute;c, gi&oacute;, s&oacute;ng ... Ph&acirc;n t&iacute;ch c&oacute; thể sử dụng phương thức cộng t&aacute;c dụng hoặc c&aacute;c phương ph&aacute;p t&iacute;ch ph&acirc;n trực tiếp, v&agrave; cả hai c&oacute; thể được x&eacute;t ứng xử tuyến t&iacute;nh hoặc phi tuyến. Phương thức m&ocirc; h&igrave;nh phi tuyến, c&ograve;n được gọi l&agrave; FNA cho ph&acirc;n t&iacute;ch phi tuyến nhanh, l&agrave; cực kỳ hiệu quả v&agrave; ch&iacute;nh x&aacute;c cho một loạt c&aacute;c vấn đề. Phương ph&aacute;p t&iacute;ch ph&acirc;n trực tiếp c&ograve;n tổng qu&aacute;t hơn, v&agrave; c&oacute; thể x&eacute;t đến b&agrave;i to&aacute;n chuyển vị lớn v&agrave; ứng xử phi tuyến bậc cao. C&aacute;c ph&acirc;n t&iacute;ch lịch sử thời gian phi tuyến c&oacute; thể được kết hợp với c&aacute;c trường hợp phi tuyến kh&aacute;c (kể cả giai đoạn thi c&ocirc;ng) gi&uacute;p giải quyết một loạt c&aacute;c ứng dụng.</em></div>\r\n</div>\r\n</div>\r\n</div>\r\n</li>\r\n</ul>\r\n</div>\r\n<div class=\"col col-md-12 tab-content\">\r\n<div class=\"tab-pane active\">&nbsp;</div>\r\n</div>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<div><strong>Ph&acirc;n t&iacute;ch mất ổn định</strong></div>\r\n<div class=\"col col-md-12 text-full\">\r\n<div>C&aacute;c dạng mất ổn định tuyến t&iacute;nh (ph&acirc;n nh&agrave;nh) của một kết cấu c&oacute; thể được t&igrave;m thấy dưới bất kỳ trường hợp tải n&agrave;o. Mất ổn định c&oacute; thể được t&iacute;nh theo trạng th&aacute;i phi tuyến t&iacute;nh hoặc giai đoạn thi c&ocirc;ng. Ph&acirc;n t&iacute;ch mất ổn định phi tuyến c&oacute; thể x&eacute;t đến c&aacute;c hiệu ứng P-delta hoặc ảnh hưởng của chuyển vị lớn. Ứng xử mất ổn định sụp đổ c&oacute; thể được ph&aacute;t hiện bằng c&aacute;ch sử dụng ph&acirc;n t&iacute;ch tĩnh c&oacute; kiểm so&aacute;t chuyển vị. Ph&acirc;n t&iacute;ch động c&oacute; thể được sử dụng cho việc m&ocirc; h&igrave;nh ho&aacute; mất ổn định phức tạp hơn, chẳng hạn như trường hợp tải cộng hưởng.</div>\r\n</div>\r\n<div class=\"col col-md-12 img-full div-resize\" data-divheight=\"383\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/buckling-new.jpg\" data-expand=\"auto\" /><br />&nbsp;</div>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<div><br /><strong>Ph&acirc;n t&iacute;ch P-Delta</strong></div>\r\n<div>Ph&acirc;n t&iacute;ch P-delta gi&uacute;p thu được ứng xử mềm h&oacute;a khi chịu n&eacute;n v&agrave; ứng xử tăng độ cứng khi chịu k&eacute;o. Một ph&acirc;n t&iacute;ch P-delta đơn giản do trọng lực v&agrave; tải d&agrave;i hạn c&oacute; thể được sử dụng để thay đổi độ cứng trong c&aacute;c trường hợp tải tuyến t&iacute;nh, sau n&agrave;y c&oacute; thể được cộng t&aacute;c dụng. Ngo&agrave;i ra, tổ hợp tải c&oacute; thể được ph&acirc;n t&iacute;ch cho c&aacute;c hiệu ứng P-delta phi tuyến đầy đủ. Hiệu ứng P-delta được x&eacute;t cho tất cả c&aacute;c phần tử v&agrave; được t&iacute;ch hợp liền mạch trong ph&acirc;n t&iacute;ch v&agrave; thiết kế.</div>\r\n<div class=\"col col-md-12 img-full div-resize\" data-divheight=\"629\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/p-delta-sap2000_0.gif\" data-expand=\"auto\" /></div>\r\n<div>&nbsp;</div>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<div><strong>Ph&acirc;n t&iacute;ch Pushover</strong><br />&nbsp;</div>\r\n<div>năng ph&acirc;n t&iacute;ch đẩy dần bao gồm ti&ecirc;u chuẩn FEMA 356 v&agrave; c&aacute;c t&ugrave;y chọn về khớp dựa tr&ecirc;n quan hệ ứng suất &ndash; biến dạng. Phần tử vỏ phi tuyến nhiều lớp cho ph&eacute;p người d&ugrave;ng x&eacute;t đến ứng xử dẻo của v&aacute;ch b&ecirc;t&ocirc;ng, s&agrave;n, bản th&eacute;p &hellip; trong ph&acirc;n t&iacute;ch Pushover. Quan hệ lực &ndash; chuyển vị được định nghĩa cho c&aacute;c khớp bằng th&eacute;p v&agrave; b&ecirc;t&ocirc;ng.<br />&nbsp;</div>\r\n<div class=\"col col-md-12 img-full div-resize\" data-divheight=\"457\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/pushover-full.jpg\" data-expand=\"auto\" /></div>\r\n<div>&nbsp;</div>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<div><strong>Ph&acirc;n t&iacute;ch theo thời gian</strong><br />&nbsp;</div>\r\n<div>Giai đoạn thi c&ocirc;ng l&agrave; một loại ph&acirc;n t&iacute;ch phi tuyến trong SAP2000. N&oacute; cho ph&eacute;p người d&ugrave;ng khai b&aacute;o một tr&igrave;nh tự thi c&ocirc;ng, trong đ&oacute; người d&ugrave;ng c&oacute; thể bỏ ngoặc th&ecirc;m c&aacute;c bộ phận kết cấu, g&aacute;n tải trọng c&oacute; chọn lựa v&agrave; x&eacute;t đến ảnh hưởng của ứng xử theo thời gian của vật liệu như l&atilde;o h&oacute;a, co ng&oacute;t v&agrave; từ biến.</div>\r\n</div>\r\n<div class=\"tab-wrapper\">\r\n<div class=\"col col-md-12 tab-container\">\r\n<ul class=\"nav-tabs\">\r\n<li class=\"active\"><strong>Staged Construction</strong>\r\n<div class=\"col col-md-12 tab-content\">\r\n<div id=\"staged-construction\" class=\"tab-pane active\">\r\n<div class=\"col col-md-12 img-full div-resize\" data-divheight=\"503\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/staged-1.jpg\" data-expand=\"auto\" /></div>\r\n<div class=\"col col-md-12 text-full\"><em>Giai đoạn thi c&ocirc;ng c&oacute; thể hiểu kh&aacute;c l&agrave; x&acirc;y dựng lớn dần, x&acirc;y dựng theo tuần tự, hoặc x&acirc;y dựng từng ph&acirc;n đoạn.</em><br />&nbsp;</div>\r\n</div>\r\n</div>\r\n</li>\r\n</ul>\r\n<div>\r\n<ul>\r\n<li><strong>Từ biến v&agrave; co ng&oacute;t</strong></li>\r\n</ul>\r\n<div class=\"tab-wrapper\">\r\n<div class=\"col col-md-12 tab-content\">\r\n<div class=\"col-md-12\">\r\n<div class=\"col col-md-12 img-full div-resize\" data-divheight=\"503\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/creep-shrinkage.jpg\" data-expand=\"auto\" /></div>\r\n<div><em>Sự biến dạng d&agrave;i hạn do từ biến v&agrave; co ng&oacute;t c&oacute; thể được t&iacute;nh to&aacute;n c&ugrave;ng với ph&acirc;n t&iacute;ch x&acirc;y dựng theo tr&igrave;nh tự thi c&ocirc;ng. C&aacute;c đặc trưng vật liệu phụ thuộc thời gian dựa tr&ecirc;n ti&ecirc;u chuẩn CEB-FIP năm 1990 v&agrave; c&aacute;c đường cong do người sử dụng khai b&aacute;o để t&iacute;nh to&aacute;n biến dạng từ biến</em></div>\r\n<ul>\r\n<li><strong>Ph&acirc;n t&iacute;ch mật độ năng lượng quang phổ</strong></li>\r\n</ul>\r\n<div>Ph&acirc;n t&iacute;ch mật độ năng lượng quang phổ cho ph&eacute;p x&aacute;c định x&aacute;c suất phản ứng của một kết cấu chịu tải trọng tuần ho&agrave;n (đều h&ograve;a, dạng h&igrave;nh sin) tr&ecirc;n một d&atilde;i tần số. N&oacute; hữu &iacute;ch cho nghi&ecirc;n cứu mỏi, phản ứng ngẫu nhi&ecirc;n do động đất, v&agrave; c&aacute;c ứng dụng kh&aacute;c. Nhiều tải trọng c&oacute; thể được khai b&aacute;o với c&aacute;c tọa độ gốc kh&aacute;c nhau, v&agrave; c&oacute; thể tương quan hoặc kh&ocirc;ng tương quan.</div>\r\n<ul>\r\n<li><strong>Trạng th&aacute;i ổn định</strong></li>\r\n</ul>\r\n<div>Ph&acirc;n t&iacute;ch trạng th&aacute;i ổn định gi&uacute;p x&aacute;c định phản ứng của cấu tr&uacute;c do tải tuần ho&agrave;n (đều h&ograve;a, dạng h&igrave;nh sin) tr&ecirc;n một dải tần số. C&aacute;c đặc trưng độ cứng v&agrave; giảm chấn phụ thuộc tần số (trở kh&aacute;ng phức tạp) c&oacute; thể được xem x&eacute;t để x&acirc;y dựng m&ocirc; h&igrave;nh nền m&oacute;ng v&agrave; c&aacute;c hiệu ứng trường xa, bao gồm sự giảm bức xạ. Ph&acirc;n t&iacute;ch trạng th&aacute;i ổn định c&oacute; thể được sử dụng để t&iacute;nh to&aacute;n ảnh hưởng của việc vận h&agrave;nh nhiều m&aacute;y m&oacute;c ở c&aacute;c tần số kh&aacute;c nhau bằng c&aacute;ch kết hợp c&aacute;c kết quả của một số ph&acirc;n t&iacute;ch trong c&ugrave;ng một m&ocirc; h&igrave;nh.</div>\r\n<div class=\"col col-md-12 img-full div-resize\" data-divheight=\"413\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/steady-state.jpg\" data-expand=\"auto\" /></div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<div><br /><strong>Lực mục ti&ecirc;u</strong></div>\r\n<div>Trong ph&acirc;n t&iacute;ch phi tuyến tĩnh, c&aacute;c phần tử c&aacute;p v&agrave; khung c&oacute; thể bị biến dạng một c&aacute;ch tự động để đạt được c&aacute;c gi&aacute; trị lực dọc mục ti&ecirc;u x&aacute;c định. T&iacute;nh năng được sử dụng phổ biến trong việc k&eacute;o thẳng c&aacute;p để căng trước, nhưng cũng được d&ugrave;ng trong đẩy kết cấu đến một lực x&aacute;c định khi d&ugrave;ng phần tử khung v&agrave; c&aacute;c ứng dụng kh&aacute;c<br />&nbsp;</div>\r\n<div class=\"col-md-12\">\r\n<div><strong>Tổ hợp tải trọng</strong><br />SAP2000 cho ph&eacute;p số trường hợp tải v&agrave; tổ hợp tải kh&ocirc;ng giới hạn. C&aacute;c kiểu tổ hợp tải bao gồm: cộng tuyến t&iacute;nh, bao (min/max), cộng trị tuyệt đối, SRSS v&agrave; tổ hợp tải kh&aacute;c. C&aacute;c tổ hợp tải c&oacute; thể chứa c&aacute;c tổ hợp tải kh&aacute;c.</div>\r\n<div class=\"col-md-12\">\r\n<div class=\"col col-md-12 img-full div-resize\" data-divheight=\"432\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/load-combinations_1.jpg\" data-expand=\"auto\" /></div>\r\n<div class=\"col col-md-12 img-full div-resize\" data-divheight=\"432\"><br /><strong>M&ocirc; h&igrave;nh sống động</strong><br />Đối với c&aacute;c cấu tr&uacute;c nhỏ đến trung b&igrave;nh, ph&acirc;n t&iacute;ch c&oacute; thể được thực hiện ngay khi bạn x&acirc;y dựng v&agrave; sửa đổi m&ocirc; h&igrave;nh. Đối với mỗi thay đổi bạn thực hiện về h&igrave;nh học, đặc trưng, hoặc tải trọng, kết cấu ngay lập tức đ&aacute;p ứng với h&igrave;nh dạng mới, biểu đồ momen, hoặc bất kỳ biểu đồ kết quả n&agrave;o . N&oacute; giống như l&agrave;m việc với một m&ocirc; h&igrave;nh sống, v&agrave; n&oacute; l&agrave; một c&ocirc;ng cụ rất mạnh mẽ cho c&aacute;c kịch bản thiết kế v&agrave; cho việc thử nghiệm kịch bản \"C&aacute;i g&igrave; &ndash; nếu\".</div>\r\n</div>\r\n</div>\r\n</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n</div>\r\n<div id=\"detailFT5\" class=\"clearfix ma15 tinhnang text-center\">\r\n<h2 title=\"Thiết kế\"><img src=\"https://www.consoft.vn/uploads/products/18114_02.jpg\" />&nbsp;Thiết kế</h2>\r\n<div class=\"ma15 text-left\">\r\n<div><strong>Thiết kế khung th&eacute;p</strong><br />&nbsp;</div>\r\n<div>Thiết kế khung th&eacute;p được t&iacute;ch hợp ho&agrave;n chỉnh bao gồm việc tối ưu h&oacute;a k&iacute;ch thước phần tử v&agrave; cung cấp c&aacute;c ti&ecirc;u chuẩn thiết kế. SAP2000 cho ph&eacute;p người d&ugrave;ng xem kết quả thiết kế tại bất kỳ phần tử khung n&agrave;o, thay đổi c&aacute;c tham số hoặc thuộc t&iacute;nh tiết diện, v&agrave; hiển thị c&aacute;c kết quả được cập nhật.</div>\r\n<div class=\"design\">&nbsp;</div>\r\n<div class=\"col-md-12\">\r\n<div class=\"col col-md-12 img-full div-resize\" data-divheight=\"571\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/steel-frame_0.jpg\" data-expand=\"auto\" /></div>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<div class=\"col col-md-12 text-full\">\r\n<div class=\"design\">&nbsp;</div>\r\n</div>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<div class=\"col col-md-12 img-full div-resize\" data-divheight=\"636\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/conc-frame_0.jpg\" data-expand=\"auto\" /></div>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<div><br /><strong>Thiết kế khung nh&ocirc;m</strong></div>\r\n<div class=\"col col-md-12 text-full\">\r\n<div class=\"design\">&nbsp;</div>\r\n</div>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<div class=\"col col-md-12 img-full div-resize\" data-divheight=\"615\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/aluminum-frame.jpg\" data-expand=\"auto\" /></div>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<div><br /><strong>Thiết kế khung th&eacute;p h&igrave;nh dập nguội</strong></div>\r\n<div class=\"col col-md-12 text-full\">\r\n<div class=\"design\">&nbsp;</div>\r\n</div>\r\n</div>\r\n<div class=\"col col-md-12 img-full div-resize\" data-divheight=\"510\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/cold-formed.jpg\" data-expand=\"auto\" /></div>\r\n<div class=\"col col-md-12 img-full div-resize\" data-divheight=\"510\"><br />Hỗ trợ c&aacute;c ti&ecirc;u chuẩn thiết kế:&nbsp;<a href=\"https://www.csiamerica.com/international-design\">https://www.csiamerica.com/international-design</a></div>\r\n</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n<div id=\"content-tab\" class=\"ma15\">&nbsp;</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n</div>\r\n<div id=\"detailFT6\" class=\"clearfix ma15 tinhnang text-center\">\r\n<h2 title=\"Hiển thị kết quả\"><img src=\"https://www.consoft.vn/uploads/products/22862_06.jpg\" />&nbsp;Hiển thị kết quả</h2>\r\n<div class=\"ma15 text-left\">\r\n<div class=\"col-md-12\">\r\n<p><strong>H&igrave;nh dạng bị biến dạng</strong></p>\r\n<p>Người d&ugrave;ng c&oacute; thể hiển thị h&igrave;nh dạng bị biến dạng theo bất kỳ tải trọng hoặc tổ hợp tải n&agrave;o, cũng như h&igrave;nh ảnh động.</p>\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"563\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/deformed_0.jpg\" data-expand=\"auto\" /></p>\r\n<p><br /><br /><strong>Biểu đồ nội lực</strong></p>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<p>C&aacute;c sơ đồ lực cắt v&agrave; momen m&ocirc; tả c&aacute;c lực cắt, momen v&agrave; chuyển vị tại tất cả c&aacute;c vị tr&iacute; dọc theo chiều d&agrave;i của một phần tử khung cho bất kỳ trường hợp tải trọng hoặc tổ hợp tải n&agrave;o. SAP2000 cung cấp t&ugrave;y chọn để di chuyển dọc chiều d&agrave;i để hiển thị gi&aacute; trị hoặc di chuyển trực tiếp đến vị tr&iacute; gi&aacute; trị cực đại.</p>\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"499\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/force-diagram.jpg\" data-expand=\"auto\" /></p>\r\n<p>&nbsp;</p>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<p><strong>Chuyển vị tổng hợp</strong></p>\r\n<p>C&aacute;c t&iacute;nh to&aacute;n chuyển vị t&ugrave;y &yacute; c&oacute; thể được x&aacute;c định bằng c&aacute;ch sử dụng c&aacute;c chuyển vị tổng hợp. Đ&acirc;y l&agrave; c&aacute;ch kết hợp tuyến t&iacute;nh c&aacute;c chuyển vị v&agrave; g&oacute;c xoay của n&uacute;t v&agrave; c&oacute; thể được sử dụng để t&iacute;nh trung b&igrave;nh, độ trượt v&agrave; c&aacute;c đ&aacute;nh gi&aacute; kh&aacute;c. Chuyển vị tổng hợp được t&iacute;nh to&aacute;n cho bất kỳ trường hợp ph&acirc;n t&iacute;ch hoặc tổ hợp tải n&agrave;o</p>\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"477\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/General-Displacement.jpg\" data-expand=\"auto\" /></p>\r\n<p>&nbsp;</p>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<p><strong>Mặt cắt tiết diện</strong></p>\r\n<p>C&aacute;c kết quả nội lực v&agrave; momen tr&ecirc;n bất kỳ mặt cắt n&agrave;o trong kết cấu đều c&oacute; thể được x&aacute;c định bằng c&aacute;ch sử dụng mặt cắt tiết diện. Một mặt cắt tiết diện c&oacute; thể c&oacute; h&igrave;nh dạng bất kỳ, v&agrave; c&oacute; thể được sử dụng để t&iacute;nh to&aacute;n lực cắt tầng, nội lực li&ecirc;n kết, nội lực thiết kế cho v&aacute;ch cứng, v&agrave; cho nhiều mục đ&iacute;ch kh&aacute;c. Kết quả mặt cắt tiết diện c&oacute; thể thực hiện cho tất cả c&aacute;c loại trường hợp tải v&agrave; tổ hợp tải.</p>\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"668\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/section-cut.jpg\" data-expand=\"auto\" /></p>\r\n<p>&nbsp;</p>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<p><strong>Biểu đồ C&ocirc;ng khả dĩ</strong></p>\r\n<p>Trong SAP2000, biểu đồ C&ocirc;ng khả dĩ c&oacute; thể được sử dụng như một trợ gi&uacute;p để x&aacute;c định phần tử n&agrave;o n&ecirc;n được tăng cường độ cứng để đạt được sự kiểm so&aacute;t hiệu quả, đặc biệt l&agrave; chuyển vị ngang của kết cấu.</p>\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"657\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/virtual-work.jpg\" data-expand=\"auto\" /></p>\r\n<p>&nbsp;</p>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<p><strong>Đường ảnh hưởng</strong></p>\r\n<p>SAP2000 sử dụng đường ảnh hưởng để t&iacute;nh to&aacute;n phản ứng đối với tải trọng động do xe cộ.. C&aacute;c đường ảnh hưởng c&oacute; thể được hiển thị trong giao diện người d&ugrave;ng gồm chuyển vị, nội lực, hoặc ứng suất đ&aacute;p ứng của bất kỳ phần tử n&agrave;o trong kết cấu</p>\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"613\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/influence-lines.jpg\" data-expand=\"auto\" /></p>\r\n<p>&nbsp;</p>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<p><strong>Kết quả dạng bảng biểu</strong></p>\r\n<p>SAP2000 c&oacute; khả năng hiển thị bảng cho tất cả dữ liệu đầu v&agrave;o, kết quả ph&acirc;n t&iacute;ch, v&agrave; kết quả thiết kế. Bảng hỗ trợ t&iacute;nh năng sắp xếp, cắt, sao ch&eacute;p v&agrave; d&aacute;n để sử dụng cho c&aacute;c chương tr&igrave;nh kh&aacute;c. In ấn hoặc lưu dữ liệu bảng ra định dạng Access, Excel, Word, HTML, or TEXT.</p>\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"491\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/tabular-output.jpg\" data-expand=\"auto\" /></p>\r\n<p>&nbsp;</p>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<p><strong>Video động</strong></p>\r\n<p>SAP2000 c&oacute; khả năng tạo tệp tin video (.avi) để hiển thị một c&aacute;ch trực quan c&aacute;c kết quả ph&acirc;n t&iacute;ch kh&aacute;c nhau trong một khoảng thời gian cụ thể, chẳng hạn như trong ph&acirc;n t&iacute;ch lịch sử thời gian.</p>\r\n</div>\r\n</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n<div id=\"content-tab\" class=\"ma15\">&nbsp;</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n</div>\r\n<div id=\"detailFT7\" class=\"clearfix ma15 tinhnang text-center\">\r\n<h2 title=\"Tạo b&aacute;o c&aacute;o\"><img src=\"https://www.consoft.vn/uploads/products/5276_07.jpg\" />&nbsp;Tạo b&aacute;o c&aacute;o</h2>\r\n<div class=\"ma15 text-left\">\r\n<div class=\"col-md-12\">\r\n<p><strong>B&aacute;o c&aacute;o nhanh</strong></p>\r\n<p>C&aacute;c b&aacute;o c&aacute;o đ&atilde; được định dạng sẵn. C&aacute;c b&aacute;o c&aacute;o n&agrave;y bao gồm tất cả c&aacute;c dữ liệu m&ocirc; h&igrave;nh th&iacute;ch hợp v&agrave; kết quả ph&acirc;n t&iacute;ch, thiết kế. Dữ liệu được tr&igrave;nh b&agrave;y dưới dạng bảng, c&ugrave;ng với đồ họa, bảng nội dung v&agrave; trang b&igrave;a hiển thị th&ocirc;ng tin dự &aacute;n, t&ecirc;n c&ocirc;ng ty...</p>\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"700\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/quick-report.jpg\" data-expand=\"auto\" /></p>\r\n<p><br /><strong>B&aacute;o c&aacute;o n&acirc;ng cao</strong></p>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<p>T&iacute;nh năng b&aacute;o c&aacute;o n&acirc;ng cao l&agrave; một tiện &iacute;ch mạnh mẽ c&oacute; thể được sử dụng để tạo c&aacute;c b&aacute;o c&aacute;o phức tạp từ m&ocirc; h&igrave;nh SAP2000. C&aacute;c b&aacute;o c&aacute;o n&agrave;y ho&agrave;n to&agrave;n c&oacute; thể t&ugrave;y chỉnh; c&aacute;c c&ocirc;ng ty c&oacute; thể định nghĩa v&agrave; lưu c&aacute;c tệp tin mẫu phức tạp để chuẩn h&oacute;a việc ph&acirc;n t&iacute;ch v&agrave; thiết kế b&aacute;o c&aacute;o.</p>\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"447\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/advanced-report-writer.jpg\" data-expand=\"auto\" /></p>\r\n<p>&nbsp;</p>\r\n</div>\r\n</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n<div id=\"content-tab\" class=\"ma15\">&nbsp;</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n</div>\r\n<div id=\"detailFT8\" class=\"clearfix ma15 tinhnang text-center\">\r\n<h2 title=\"C&ocirc;ng cụ\"><img src=\"https://www.consoft.vn/uploads/products/2943_09.jpg\" />&nbsp;C&ocirc;ng cụ</h2>\r\n<div class=\"ma15 text-left\">\r\n<div class=\"col-md-12\">\r\n<p><strong>Tối ưu h&oacute;a tải trọng</strong></p>\r\n<p>C&ocirc;ng cụ tối ưu h&oacute;a tải l&agrave; một c&ocirc;ng cụ trong SAP2000 d&ugrave;ng để t&iacute;nh to&aacute;n tải sừ dụng tối ưu gi&uacute;p đạt được phản ứng của kết cấu theo mong muốn. Tải trọng c&oacute; thể được &aacute;p dụng dạng tuyến t&iacute;nh, phi tuyến, hoặc trong giai đoạn x&acirc;y dựng. Mục ti&ecirc;u v&agrave; giới hạn c&oacute; thể bao gồm chuyển vị, nội lực, momen &hellip;</p>\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"512\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/load-optimizer_0.jpg\" data-expand=\"auto\" /></p>\r\n<p>&nbsp;</p>\r\n</div>\r\n<div class=\"col-md-12\">\r\n<p><strong>Thiết kế tiết diện</strong></p>\r\n<p>C&ocirc;ng cụ thiết kế tiết diện được t&iacute;ch hợp trong SAP2000. N&oacute; cho ph&eacute;p người sử dụng khả năng tạo c&aacute;c tiết diện chuy&ecirc;n biệt với h&igrave;nh dạng v&agrave; vật liệu bất kỳ, bao gồm cả bố tr&iacute; cốt th&eacute;p. Tất cả c&aacute;c thuộc t&iacute;nh tiết diện, sơ đồ hệ trục, v&agrave; sơ đồ đường cong momen được t&iacute;nh tự độn.</p>\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"567\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/section-designer_0.jpg\" data-expand=\"auto\" /></p>\r\n</div>\r\n</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n<div id=\"content-tab\" class=\"ma15\">&nbsp;</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n</div>\r\n<div id=\"detailFT9\" class=\"clearfix ma15 tinhnang text-center\">\r\n<h2 title=\"Nhập v&agrave; xuất\"><img src=\"https://www.consoft.vn/uploads/products/21706_03.jpg\" />&nbsp;Nhập v&agrave; xuất</h2>\r\n<div class=\"ma15 text-left\">\r\n<div class=\"col-md-12\">\r\n<p><strong>C&aacute;c định dạng được hỗ trợ</strong></p>\r\n<p>SAP2000 hỗ trợ nhiều chuẩn định dạng để nhập v&agrave; xuất dữ liệu. Autodesk Revit Structure, Tekla, AutoCAD (DXF / DWG), CIS / 2, IFC, IGES v&agrave; SDNF đều được hỗ trợ. SAP2000 cũng hỗ trợ xuất m&ocirc; h&igrave;nh sang cơ sở dữ liệu Microsoft Access. Nếu người d&ugrave;ng đang sử dụng c&aacute;c g&oacute;i ph&acirc;n t&iacute;ch kh&aacute;c, SAP2000 c&oacute; thể nhập c&aacute;c tệp tin từ FrameWorks Plus, STAAD v&agrave; STRUDL.</p>\r\n<p class=\"col col-md-12 img-full div-resize\" data-divheight=\"358\"><img class=\"img-responsive  lazyloaded\" src=\"https://www.csiamerica.com/sites/default/files/import-export-1.jpg\" data-expand=\"auto\" /><br /><br /><br /><strong>True Bi-directional Data Transfer with Revit&reg;<br /><br /><img src=\"https://www.consoft.vn/uploads/CSI%20X%20REVIT(1).JPG\" alt=\"\" /></strong></p>\r\n</div>\r\n</div>\r\n<div class=\"clear\">&nbsp;</div>\r\n</div>\r\n<p>&nbsp;</p>\r\n</div>\r\n<div class=\"show\"><a class=\"btn btn-info details_click clickmore \" data-id=\"boxdex\" data-class=\"1\">Xem th&ocirc;ng tin đầy đủ</a></div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<div class=\"col-md-3 rbody\">\r\n<div class=\"taituychon\">&nbsp;</div>\r\n</div>\r\n<div id=\"eJOY__extension_root\" class=\"eJOY__extension_root_class\" style=\"all: unset;\">&nbsp;</div>','<h2>Ph&aacute;t h&agrave;nh SAP2000 v22 của h&atilde;ng Computers and Structures, Inc</h2>\r\n<p>SAP2000 l&agrave; phần mềm ph&acirc;n t&iacute;ch, thiết kế kết cấu quen thuộc với c&aacute;c kỹ sư tr&ecirc;n to&agrave;n thế giới. Ng&agrave;y 15 th&aacute;ng 1 năm 2020 h&atilde;ng Computers and Structures, Inc. ch&iacute;nh thức ph&aacute;t h&agrave;nh SAP2000 v22 với nhiều t&iacute;nh năng v&agrave; cải thiện mới, tập chung v&agrave;o phần m&ocirc; h&igrave;nh tương t&aacute;c kết cấu m&oacute;ng v&agrave; nền đất, cải thiện v&agrave; bổ sung t&iacute;nh năng cho phần ph&acirc;n t&iacute;ch.</p>\r\n<p>Một số t&iacute;nh năng mới như sau:</p>\r\n<p>&nbsp;M&ocirc; h&igrave;nh kết cấu: Tham số chi tiết h&igrave;nh học của kết cấu m&oacute;ng, bao gồm phần tử nền dạng tử l&ograve; xo c&oacute;&nbsp; thể được th&ecirc;m v&agrave;o m&ocirc; h&igrave;nh kết cấu tổng hợp.&nbsp;</p>\r\n<h2>T&iacute;nh năng SAP2000 v22</h2>\r\n<ul>\r\n<li>N&oacute; cung cấp một giao diện người d&ugrave;ng duy nhất gi&uacute;p thực hiện c&aacute;c m&ocirc; h&igrave;nh như: M&ocirc; h&igrave;nh h&oacute;a, Ph&acirc;n t&iacute;ch, Thiết kế v&agrave; B&aacute;o c&aacute;o.</li>\r\n</ul>\r\n<ul>\r\n<li>SAP2000 với nhiều lựa chọn mẫu để nhanh ch&oacute;ng bắt đầu một m&ocirc; h&igrave;nh mới.</li>\r\n</ul>\r\n<ul>\r\n<li>Xem, thao t&aacute;c c&aacute;c m&ocirc; h&igrave;nh ph&acirc;n t&iacute;ch với độ ch&iacute;nh x&aacute;c cao.</li>\r\n</ul>\r\n<ul>\r\n<li>SAP2000 c&oacute; thể được định nghĩa l&agrave; cartesian hoặc h&igrave;nh trụ.</li>\r\n</ul>\r\n<ul>\r\n<li>Gi&uacute;p kỹ sư c&oacute; nhiều lựa chọn hơn khi n&oacute;i đến việc tạo lưới trong SAP2000.</li>\r\n</ul>\r\n<ul>\r\n<li>C&oacute; thể tạo v&agrave; &aacute;p dụng c&aacute;c thuộc t&iacute;nh bản lề để thực hiện c&aacute;c ph&acirc;n t&iacute;ch đẩy trong phần mềm t&iacute;nh to&aacute;n kết cấu tổng hợp</li>\r\n</ul>\r\n<ul>\r\n<li>SAP2000 trang bị c&aacute;c mẫu mạnh nhất v&agrave; t&iacute;ch hợp sẵn cho ph&eacute;p bạn tạo ra c&aacute;c m&ocirc; h&igrave;nh phức tạp.</li>\r\n</ul>\r\n<ul>\r\n<li>Với kỹ thuật ph&acirc;n t&iacute;ch n&acirc;ng cao kh&aacute;c nhau cho ph&eacute;p bạn c&oacute; từng bước ph&acirc;n t&iacute;ch biến dạng.</li>\r\n</ul>\r\n<ul>\r\n<li>Tự động tải địa chấn v&agrave; chức năng phổ phản ứng được th&ecirc;m v&agrave;o.</li>\r\n</ul>\r\n<ul>\r\n<li>X&aacute;c định tải cụ thể một loạt c&aacute;c điều kiện tải với c&aacute;c t&ugrave;y chọn t&iacute;ch hợp SAP2000.</li>\r\n</ul>\r\n<ul>\r\n<li>SAP2000 c&oacute; thể thực hiện ph&acirc;n t&iacute;ch tĩnh tuyến t&iacute;nh v&agrave; cả ph&acirc;n t&iacute;ch tĩnh nhiều bước</li>\r\n</ul>\r\n<ul>\r\n<li>Người d&ugrave;ng c&oacute; thể hiển thị h&igrave;nh học bị biến dạng cũng như h&igrave;nh ảnh động của c&aacute;c chế độ.</li>\r\n</ul>\r\n<ul>\r\n<li>B&aacute;o c&aacute;o in được định dạng xem trước hiện c&oacute; sẵn</li>\r\n</ul>\r\n<p>Phần mềm t&iacute;nh to&aacute;n kết cấu tổng hợp SAP2000 hỗ trợ tất cả c&aacute;c ti&ecirc;u chuẩn c&ocirc;ng nghiệp để nhập v&agrave; xuất dữ liệu.</p>\r\n<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<h2>Cải thiện ph&acirc;n t&iacute;ch với Multiple copies</h2>\r\n<p>Nhiều bản sao của m&ocirc; h&igrave;nh giống nhau c&oacute; thể chạy tr&ecirc;n nhiều m&aacute;y kh&aacute;c nhau. Kết quả ph&acirc;n t&iacute;ch c&oacute; thể hợp nhất với nhau tr&ecirc;n một m&aacute;y nhằm tăng hiệu suất thiết kế kết cấu cũng như xử l&yacute; kết quả. N&oacute; c&oacute; thể sử dụng trong trường hợp chạy số lượng lớn trường hợp tải trọng (như tải trọng động đất cho thiết kế kh&aacute;ng chấn của t&ograve;a nh&agrave;, tải trọng di động cho thiết kế cầu...). Hơn nữa nhiều m&aacute;y t&iacute;nh kh&aacute;c để chạy cho nhiều tải trọng kh&aacute;c nhau c&ugrave;ng một l&uacute;c.</p>\r\n<h2>Design &ndash; Concrete Frame</h2>\r\n<p>Bổ sung ti&ecirc;u chuẩn thiết kế khung b&ecirc; t&ocirc;ng ACI 318-14, ACI 318-11, v&agrave; ACI 318-08 trong đ&oacute; hệ số delta_ns được giới hạn 1.4 dự tr&ecirc;n bảng 6.2.6 v&agrave; 6.6.4.5.1 của ti&ecirc;u chuẩn ACI 318-14, bảng 10.10.2.1 của ACI 318-11, v&agrave; bảng 10.10.2.1 của ACI 318-08.</p>\r\n<h2>Design &ndash; Steel Frame</h2>\r\n<p>Bổ sung ti&ecirc;u chuẩn thiết kế kết cấu khung th&eacute;p Eurocode 3-2005, Italian NTC2008. Trong đ&oacute; biểu thức Mcr được t&iacute;nh theo c&ocirc;ng thức F.2 trong phần F.1.2 của ti&ecirc;u chuẩn EC3:1993. N&oacute; bao gồm điều kiện C2*zg v&agrave; C3*zj. Trong đ&oacute; zg l&agrave; khoảng c&aacute;ch giữa điểm đặt tải v&agrave; t&acirc;m cắt (zs), zj. Khoảng c&aacute;ch được x&aacute;c định trong EC3:1993 mục F.1.2, C2 v&agrave; C3 l&agrave; c&aacute;c hệ số phụ tải.&nbsp;</p>\r\n<h2>Hạn chế trong chế độ xử l&yacute;</h2>\r\n<p>C&oacute; một số hạn chế trong xử l&yacute; Angle, Box, Pipe, Solid, Section Designer, General, v&agrave; phần tử Non-prismatic</p>\r\n<ul>\r\n<li>Angle section: Phương tr&igrave;nh t&iacute;nh to&aacute;n Mcr được cung cấp bởi ti&ecirc;u chuẩn thiết kế kh&ocirc;ng được &aacute;p dụng đ&uacute;ng cho tiết diện v&aacute;t. Thiết kế vẫn t&iacute;nh to&aacute;n Mcr bằng phương tr&igrave;nh mới nhưng với c&aacute;c giả định sau:\r\n<ul>\r\n<li>(1) Gi&aacute; trị zs được lấy l&agrave;m h&igrave;nh chiếu của tọa độ t&acirc;m cắt l&ecirc;n trục dọc theo tải trọng được &aacute;p dụng khi t&iacute;nh zg;</li>\r\n<li>(2) zs được lấy l&agrave;m h&igrave;nh chiếu của tọa độ t&acirc;m cắt l&ecirc;n trục nguy&ecirc;n l&yacute; phụ khi t&iacute;nh zj.&nbsp;</li>\r\n</ul>\r\n</li>\r\n<li>Box, Pipe, v&agrave; Solid sections: T&iacute;nh to&aacute;n của Mcr l&agrave; bảo thủ v&igrave; hằng số cong v&ecirc;nh (Iw) kh&ocirc;ng được t&iacute;nh v&agrave; được coi l&agrave; bằng kh&ocirc;ng.&nbsp;</li>\r\n<li>Section Designer v&agrave; General sections: C&aacute;c phần n&agrave;y được ph&acirc;n loại l&agrave; Class 2 hoặc 3. AlphaLT được giả định l&agrave; 0,76 (đường cong uốn cong d). Hằng số cong v&ecirc;nh (Iw) kh&ocirc;ng được t&iacute;nh to&aacute;n. V&igrave; h&igrave;nh dạng của phần thường kh&ocirc;ng được biết đến n&ecirc;n hằng số được coi l&agrave; bằng 0. C&aacute;c tọa độ trung t&acirc;m cắt zs được coi l&agrave; bằng 0 đối với trọng t&acirc;m.&nbsp;</li>\r\n<li>Nonprismatic sections: Tất cả c&aacute;c thuộc t&iacute;nh cần thiết để t&iacute;nh to&aacute;n Mcr trong mỗi ph&acirc;n đoạn kh&ocirc;ng biến đổi được nội suy tuyến t&iacute;nh từ c&aacute;c phần của hai phần ở cuối đoạn đ&oacute;. Điều n&agrave;y được thực hiện cho từng ph&acirc;n đoạn trong chiều d&agrave;i của đối tượng khung. Điều n&agrave;y chỉ c&oacute; &yacute; nghĩa nếu c&aacute;c phần ở hai đầu của mỗi ph&acirc;n đoạn c&oacute; h&igrave;nh dạng giống nhau (v&iacute; dụ: cả phần I hoặc cả hai phần hộp). Nếu kh&ocirc;ng, cảnh b&aacute;o được cung cấp trong kết quả thiết kế.&nbsp;</li>\r\n</ul>\r\n<h3>Loading</h3>\r\n<p>&nbsp;Th&ecirc;m lựa chọn cho tải trọng động đất tự động New Zealand 1170.5. Thiết kế kết cấu được coi như một s&agrave;n duy nhất. Khi t&ugrave;y chọn n&agrave;y được chọn, gi&aacute; trị Ft được đặt bằng 0 v&agrave; thay v&agrave;o đ&oacute; tải được ph&acirc;n phối lại theo chiều cao của c&ocirc;ng tr&igrave;nh.</p>\r\n<p>Theo modal v&agrave; buckling load cases c&oacute; thể được th&ecirc;m v&agrave;o c&aacute;c tổ hợp tải. Nhiều chế độ c&oacute; thể được th&ecirc;m v&agrave;o trong c&ugrave;ng một trường hợp tải, mỗi chế độ c&oacute; hệ số tỷ lệ ri&ecirc;ng.</p>\r\n<h3>Structural Model</h3>\r\n<p>Dữ liệu thuộc t&iacute;nh nền m&oacute;ng hiện chỉ được lưu dưới dạng dữ liệu nhị ph&acirc;n v&agrave; kh&ocirc;ng thể nhập dữ liệu đ&oacute; từ tệp văn bản .S2K ,. $ 2K) hoặc tệp bảng cơ sở dữ liệu (Excel, Access, XML). Khả năng nhập sẽ được thực hiện trong phi&ecirc;n bản mới hơn</p>\r\n<h3>User Interface</h3>\r\n<p>Tăng tốc đồ họa người d&ugrave;ng khi mở m&ocirc; h&igrave;nh lớn với nhiều đối tượng được hiển thị tốt hơn kh&ocirc;ng bị d&aacute;n đoạn</p>\r\n<p>Cấu h&igrave;nh SAP2000 v22</p>\r\n<ul>\r\n<li>Hệ điều h&agrave;nh được hỗ trợ: Windows 7/8/10</li>\r\n<li>Bộ xử l&yacute;: Intel i5 / i7, AMD Athlon X4 / Ryzen hoặc tốt hơn</li>\r\n<li>RAM: RAM 8 GB (khuy&ecirc;n d&ugrave;ng 16 GB)</li>\r\n<li>Dung lượng đĩa cứng miễn ph&iacute;: 6 GB trở l&ecirc;n</li>\r\n</ul>\r\n<p>Thu gọn</p>\r\n<div id=\"eJOY__extension_root\" class=\"eJOY__extension_root_class\" style=\"all: unset;\">&nbsp;</div>',NULL,'Published','SAP2000','SAP2000 Phần mềm phân tích thiết kết cấu tổng hợp','SAP2000, CIC',NULL,2,NULL,'2020-10-11 12:43:31','2020-12-02 02:48:52','2020-12-02 02:48:52'),(6,'Máy siêu âm cọc khoan nhồi CHUM (Piletest)','may-sieu-am-coc-khoan-nhoi-chum-piletest','2020-10-14 19:45:00',0,0,'1602420684-may-sieu-am-coc-khoan-nhoi-chum-piletest.jpg','Đáp ứng TCVN 9396:2012 Cọc khoan nhồi - Xác định tính đồng nhất của bê tông - Phương pháp xung siêu âm','<div class=\" col-md-9 lbody\">\r\n<div class=\"menu1\">\r\n<div class=\"tab-content\">\r\n<div id=\"menu1\" class=\"tab-pane fade active in\">\r\n<div id=\"boxdex\" class=\"contentt boxdex\" data-height=\"650\">\r\n<table border=\"0\" cellspacing=\"1\" cellpadding=\"1\">\r\n<tbody>\r\n<tr>\r\n<td>\r\n<p><strong><u>Hệ thống Bao gồm:</u></strong></p>\r\n</td>\r\n<td>&nbsp;</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<h2>- Bộ điều khiển ch&iacute;nh CHUM</h2>\r\n<p>- Bộ sạc pin 110/220.<br />- 2 bộ tời + c&aacute;p 100m.<br />- 2 cảm biến thu/nhận s&oacute;ng si&ecirc;u &acirc;m.<br />- 2 bộ đếm đo độ s&acirc;u.<br />- 2 bộ c&aacute;p đo s&acirc;u d&ugrave;ng cho CSL v&agrave; chụp cắt lớp.</p>\r\n<p>-&nbsp;Thiết kế th&ocirc;ng minh với m&aacute;y t&iacute;nh t&aacute;ch rời (kết nối qua cổng USB)</p>\r\n<p>- Phần mềm CHUM<br />- Phần mềm quan s&aacute;t kết quả dạng 3D: 3DT Viewer.</p>\r\n<p>- Phần mềm được cập nhật miễn ph&iacute; trong v&ograve;ng 10 năm.</p>\r\n<p>&nbsp;</p>\r\n<p>- Hỗ trợ trực tuyến qua Internet trong 1 năm đầu: Kh&aacute;ch h&agrave;ng c&oacute; thể gửi trực tiếp dữ liệu kết quả đo cho Piletest. Kết quả đo được ph&acirc;n t&iacute;ch bằng phần mềm CHUM 3D Tomograph. Sau khi ph&acirc;n t&iacute;ch xong dữ liệu, Piletest sẽ gửi lại kết quả cho kh&aacute;ch h&agrave;ng. Dữ liệu kết quả sẽ được quan s&aacute;t bằng phần mềm 3DT viewer.</p>\r\n<p>- Bảo h&agrave;nh 03 năm.</p>\r\n<p>&nbsp;</p>\r\n<p><strong><em>Th&ocirc;ng số vật l&yacute;:</em></strong></p>\r\n<p><em>- K&iacute;ch thước: &nbsp;&nbsp;&nbsp;430x325x105</em></p>\r\n<p><em>- Khối lượng: &nbsp;&nbsp;3,8kg</em></p>\r\n<p><em>- Nhiệt độ khi: &nbsp;Sử dụng: -25<sup>0</sup>C &ndash; 60<sup>0</sup>C</em></p>\r\n<p><em>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;Bảo quản: -40<sup>0</sup>C &ndash; 70<sup>0</sup>C</em></p>\r\n<p><em>&nbsp;<strong>Nguồn:</strong></em></p>\r\n<p><em>- Pin: &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Pin sạc Lithium Ion 11,1V/4,4Ah</em></p>\r\n<p><em>- Nguồn sạc: &nbsp;&nbsp;&nbsp;100 &ndash; 240VAC</em></p>\r\n<p><strong><em>Ti&ecirc;u chuẩn:&nbsp;&nbsp;&nbsp;&nbsp;</em></strong><em>Đạt v&agrave; vượt ASTM D6760 &ndash; 08</em></p>\r\n<p><strong><em>Th&ocirc;ng số kỹ thuật:</em></strong></p>\r\n<p><em>- Đầu d&ograve;: 2 đầu d&ograve; thu/ph&aacute;t t&iacute;n hiệu, tần số 50 kHz, vỏ bọc chống &aacute;p lực, đường k&iacute;nh 25 mm</em></p>\r\n<p><em>- D&acirc;y c&aacute;p: D&acirc;y c&aacute;p chịu lực cao nối đầu d&ograve; với bộ xử l&yacute; t&iacute;n hiệu, c&oacute; thể t&aacute;ch rời khỏi cuộn c&aacute;p</em></p>\r\n<p><em>- Hệ số mẫu: 500 kHz (độ ph&acirc;n giải 2&micro;S)</em></p>\r\n<p><em>- Độ khuếch đại t&iacute;n hiệu của đầu d&ograve;: 8 mức khuếch đại tự động</em></p>\r\n<p><em>Bộ đo s&acirc;u: 2 bộ đo s&acirc;u 24-bit. Sai số &lt;0.1%</em></p>\r\n<p><strong><em>Hiệu năng:</em></strong></p>\r\n<p><em>- Chiều d&agrave;i cọc đo được: 1 &ndash; 145m</em></p>\r\n<p><em>- Khoảng c&aacute;ch c&aacute;c ống tối đa: L&ecirc;n tới 4m với b&ecirc; t&ocirc;ng chất lượng tốt</em></p>\r\n<p><em>- Năng suất kiểm tra: L&ecirc;n tới 3000m cọc/ng&agrave;y</em></p>\r\n<p><em>- Khả năng lưu trữ dữ liệu: kh&ocirc;ng giới hạn (do thiết kế th&ocirc;ng minh với m&aacute;y t&iacute;nh t&aacute;ch rời)</em></p>\r\n<p><strong><em>Y&ecirc;u cầu m&aacute;y t&iacute;nh:</em></strong></p>\r\n<p><em>- Windows 2000/XP/Vista.</em></p>\r\n<p><em>- Độ ph&acirc;n giải m&agrave;n h&igrave;nh tối thiểu 800x600 dpi</em></p>\r\n<p><strong><em>Dữ liệu ra:</em></strong></p>\r\n<p><em>- Thời gian tới, đường cong năng lượng s&oacute;ng truyền v&agrave; vận tốc s&oacute;ng, biểu đồ &ldquo;th&aacute;c nước&rdquo;, logic mờ, m&ocirc; phỏng 3D.</em></p>\r\n<p><em>- Ng&ocirc;n ngữ: Giao diện nhiều ng&ocirc;n ngữ kh&aacute;c nhau</em></p>\r\n<p><strong><em>T&ugrave;y chọn th&ecirc;m:</em></strong></p>\r\n<p><em>- C&aacute;c loại c&aacute;p tời chiều d&agrave;i kh&aacute;c nhau: 50m, 100m, 150m hoặc đặt h&agrave;ng ri&ecirc;ng</em></p>\r\n<p><em>- Phần mềm t&iacute;nh to&aacute;n m&ocirc; phỏng 3D</em></p>\r\n<p><em>- Adapter 12V DC nối với bộ nguồn &ocirc;t&ocirc;</em></p>\r\n<p>&nbsp;</p>\r\n</div>\r\n<div class=\"show\"><a class=\"btn btn-info details_click clickmore \" data-id=\"boxdex\" data-class=\"1\">Xem th&ocirc;ng tin đầy đủ</a></div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<div class=\"col-md-3 rbody\">\r\n<div class=\"taituychon\">&nbsp;</div>\r\n</div>\r\n<div id=\"eJOY__extension_root\" class=\"eJOY__extension_root_class\" style=\"all: unset;\">&nbsp;</div>','<p>M&aacute;y si&ecirc;u &acirc;m cọc khoan nhồi CHUM (Piletest)</p>\r\n<p>Được th&agrave;nh lập c&aacute;ch đ&acirc;y tr&ecirc;n 10 năm, Piletest chuy&ecirc;n ph&aacute;t triển c&aacute;c hệ thống kiểm tra cọc nhằm đảm bảo chất lượng cọc, đồng thời cũng cung cấp c&aacute;c thiết bị thực hiện đ&aacute;nh gi&aacute; chất lượng c&aacute;c hệ thống m&oacute;ng s&acirc;u như cọc, cừ, caissons barrettes....</p>\r\n<p>Thiết bị si&ecirc;u &acirc;m cọc khoan nhồi CHUM (Cross Hole Ultrasonic Monitor): sử dụng phương ph&aacute;p Crosshole Sonic Logging (CSL) để thực hiện việc kiểm tra chất lượng thi c&ocirc;ng cọc khoan nhồi. Hệ thống sử dụng s&oacute;ng si&ecirc;u &acirc;m được gửi đi từ đầu d&ograve; ph&aacute;t tới đầu thu nhận th&ocirc;ng qua m&ocirc;i trường ống c&oacute; đầy nước được nh&uacute;ng v&agrave;o trong l&ograve;ng b&ecirc; t&ocirc;ng</p>\r\n<h2>Một số ưu điểm của m&aacute;y si&ecirc;u &acirc;m cọc khoan nhồi của h&atilde;ng Piletest:</h2>\r\n<ol>\r\n<li>Thiết kế sản phẩm rất th&ocirc;ng minh, gọn nhẹ, dễ d&agrave;ng vận chuyển v&agrave; kiểm tra ngo&agrave;i hiện trường. Thiết kế m&aacute;y t&iacute;nh t&aacute;ch rời thiết bị (kết nối qua cổng USB hoặc Bluetooth) c&oacute; nhiều ưu điểm hơn so với thiết bị cọc khoan nhồi của c&aacute;c h&atilde;ng kh&aacute;c c&oacute; m&aacute;y t&iacute;nh gắn cố định với:</li>\r\n</ol>\r\n<ul>\r\n<li>C&aacute;c trục trặc li&ecirc;n quan tới m&aacute;y t&iacute;nh kh&ocirc;ng ảnh hưởng tới to&agrave;n bộ thiết bị, việc khắc phục c&aacute;c lỗi li&ecirc;n quan tới m&aacute;y t&iacute;nh cũng đơn giản hơn rất nhiều, chi ph&iacute; thấp.</li>\r\n<li>Việc n&acirc;ng cấp phần cứng v&agrave; phần mềm của m&aacute;y t&iacute;nh ho&agrave;n to&agrave;n nằm trong sự chủ động của người sử dụng với chi ph&iacute; thấp, t&iacute;nh linh hoạt cao, lu&ocirc;n đảm bảo cả hệ thống lu&ocirc;n hoạt động nhanh, hiệu quả.</li>\r\n<li>Cắt giảm được chi ph&iacute; đầu tư do kh&ocirc;ng kh&ocirc;ng bắt buộc phải mua m&aacute;y t&iacute;nh, Qu&yacute; kh&aacute;ch h&agrave;ng ho&agrave;n to&agrave;n c&oacute; thể sử dụng laptop (hay PC pocket) hiện c&oacute; trong đơn vị m&igrave;nh để kết nối với thiết bị cọc khoan nhồi của h&atilde;ng Piletest (qua cổng USB hoặc Bluetooth).</li>\r\n</ul>\r\n<ol>\r\n<li>Thiết bị bền, hoạt động ổn định, cho t&iacute;n hiệu c&oacute; độ ch&iacute;nh x&aacute;c cao, được nhiều đơn vị kiểm định chất lượng c&ocirc;ng tr&igrave;nh tại Việt Nam tin d&ugrave;ng.</li>\r\n<li>Phần mềm được cập nhật miễn ph&iacute; trong v&ograve;ng 10 năm.</li>\r\n<li>C&aacute;c sản phẩm của Piletest được bảo h&agrave;nh tới 03 năm (trong khi c&aacute;c h&atilde;ng kh&aacute;c chỉ bảo h&agrave;nh trong v&ograve;ng 01 năm).</li>\r\n<li>Piletest l&agrave; h&atilde;ng c&oacute; ch&iacute;nh s&aacute;ch sau b&aacute;n h&agrave;ng tốt nhất tr&ecirc;n thị trường, c&aacute;c chuy&ecirc;n gia gi&agrave;u kinh nghiệm của Piletest rất nhiệt t&igrave;nh, lu&ocirc;n sẵn s&agrave;ng hỗ trợ trực tiếp tới người sử dụng.</li>\r\n</ol>\r\n<h2>Hệ thống m&aacute;y si&ecirc;u &acirc;m cọc khoan nhồi bao gồm</h2>\r\n<p>- Bộ điều khiển ch&iacute;nh CHUM</p>\r\n<p>- Bộ sạc pin 110/220.</p>\r\n<p>- 2 bộ tời + c&aacute;p 100m.</p>\r\n<p>- 2 cảm biến thu/nhận s&oacute;ng si&ecirc;u &acirc;m.</p>\r\n<p>- 2 bộ đếm đo độ s&acirc;u.</p>\r\n<p>- 2 bộ c&aacute;p đo s&acirc;u d&ugrave;ng cho CSL v&agrave; chụp cắt lớp.</p>\r\n<p>- Thiết kế th&ocirc;ng minh với m&aacute;y t&iacute;nh t&aacute;ch rời (kết nối qua cổng USB)</p>\r\n<p>- Phần mềm CHUM</p>\r\n<p>- Phần mềm quan s&aacute;t kết quả dạng 3D: 3DT Viewer.</p>\r\n<p>- Phần mềm được cập nhật miễn ph&iacute; trong v&ograve;ng 10 năm.</p>\r\n<p>- Hỗ trợ trực tuyến qua Internet trong 1 năm đầu: Kh&aacute;ch h&agrave;ng c&oacute; thể gửi trực tiếp dữ liệu kết quả đo cho Piletest. Kết quả đo được khi si&ecirc;u &acirc;m cọc khoan nhồi ph&acirc;n t&iacute;ch bằng phần mềm CHUM 3D Tomography. Sau khi ph&acirc;n t&iacute;ch xong dữ liệu, Piletest sẽ gửi lại kết quả cho kh&aacute;ch h&agrave;ng. Dữ liệu kết quả sẽ được quan s&aacute;t bằng phần mềm 3DT viewer.</p>\r\n<p>- Bảo h&agrave;nh 03 năm.</p>\r\n<p>&nbsp;Th&ocirc;ng số vật l&yacute;:</p>\r\n<p>- K&iacute;ch thước:&nbsp; &nbsp; 430x325x105</p>\r\n<p>- Khối lượng: &nbsp; 3,8kg</p>\r\n<p>- Nhiệt độ khi:&nbsp; Sử dụng: -250C &ndash; 600C</p>\r\n<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;Bảo quản: -400C &ndash; 700C</p>\r\n<p>&nbsp;Nguồn:</p>\r\n<p>- Pin:&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; Pin sạc Lithium Ion 11,1V/4,4Ah</p>\r\n<p>- Nguồn sạc:&nbsp; &nbsp; 100 &ndash; 240VAC</p>\r\n<p>Ti&ecirc;u chuẩn:&nbsp; &nbsp; Đạt v&agrave; vượt ASTM D6760 &ndash; 08</p>\r\n<h2>Th&ocirc;ng số kỹ thuật:</h2>\r\n<p>- Đầu d&ograve;: 2 đầu d&ograve; thu/ph&aacute;t t&iacute;n hiệu, tần số 50Hz, vỏ bọc chống &aacute;p lực, đường k&iacute;nh 25 mm</p>\r\n<p>- D&acirc;y c&aacute;p: D&acirc;y c&aacute;p chịu lực cao nối đầu d&ograve; với bộ xử l&yacute; t&iacute;n hiệu, c&oacute; thể t&aacute;ch rời khỏi cuộn c&aacute;p</p>\r\n<p>- Hệ số mẫu: 500kHz (độ ph&acirc;n giải 2&micro;S)</p>\r\n<p>- Độ khuếch đại t&iacute;n hiệu của đầu d&ograve;: 8 mức khuếch đại tự động</p>\r\n<p>Bộ đo s&acirc;u: 2 bộ đo s&acirc;u 24-bit. Sai số &lt;0.1%</p>\r\n<p>Hiệu năng:</p>\r\n<p>- Chiều d&agrave;i cọc đo được: 1 &ndash; 145m</p>\r\n<p>- Khoảng c&aacute;ch c&aacute;c ống tối đa: L&ecirc;n tới 4m với b&ecirc; t&ocirc;ng chất lượng tốt</p>\r\n<p>- Năng suất kiểm tra: L&ecirc;n tới 3000m cọc/ng&agrave;y</p>\r\n<p>- Khả năng lưu trữ dữ liệu: kh&ocirc;ng giới hạn (do thiết kế th&ocirc;ng minh với m&aacute;y t&iacute;nh t&aacute;ch rời)</p>\r\n<p>Y&ecirc;u cầu m&aacute;y t&iacute;nh:</p>\r\n<p>- Windows 2000/XP/Vista.</p>\r\n<p>- Độ ph&acirc;n giải m&agrave;n h&igrave;nh tối thiểu 800x600 dpi</p>\r\n<p>Dữ liệu ra:</p>\r\n<p>- Thời gian tới, đường cong năng lượng s&oacute;ng truyền v&agrave; vận tốc s&oacute;ng, biểu đồ &ldquo;th&aacute;c nước&rdquo;, logic mờ, m&ocirc; phỏng 3D.</p>\r\n<p>- Ng&ocirc;n ngữ: Giao diện nhiều ng&ocirc;n ngữ kh&aacute;c nhau</p>\r\n<p>T&ugrave;y chọn th&ecirc;m:</p>\r\n<p>- C&aacute;c loại c&aacute;p tời chiều d&agrave;i kh&aacute;c nhau: 50m, 100m, 150m hoặc đặt h&agrave;ng ri&ecirc;ng</p>\r\n<p>- Phần mềm t&iacute;nh to&aacute;n m&ocirc; phỏng 3D</p>\r\n<p>- Adapter 12V DC nối với bộ nguồn &ocirc;t&ocirc;</p>\r\n<h2>Thiết bị si&ecirc;u &acirc;m cọc khoan nhồi c&oacute; thể ph&aacute;t hiện v&agrave; đ&aacute;nh gi&aacute;</h2>\r\n<p>Vết nứt</p>\r\n<p>C&aacute;c vật lạ</p>\r\n<p>Rỗ v&agrave; rỗng</p>\r\n<p>Ngưng kết b&ecirc; t&ocirc;ng</p>\r\n<p>Ph&aacute;t hiện c&aacute;c dị thường (độ ph&acirc;n giải phụ thuộc v&agrave;o điều kiện thử)</p>\r\n<p>X&aacute;c định ch&iacute;nh x&aacute;c độ s&acirc;u của c&aacute;c dị thường</p>\r\n<p>Cho ảnh thời gian thực về k&iacute;ch thước h&igrave;nh dạng, vị tr&iacute; của dị thường.</p>\r\n<p>Thực hiện ph&eacute;p kiểm tra cho từng lỗ</p>\r\n<p>C&oacute; chiều s&acirc;u lớn, c&oacute; tỷ số t&iacute;n hiệu/tiếng ồn cao, v&agrave; thuật to&aacute;n xử l&yacute; số liệu cao cấp</p>\r\n<p>Khả năng lưu giữ số liệu kh&ocirc;ng hạn chế</p>\r\n<p>Thoả m&atilde;n ho&agrave;n to&agrave;n ti&ecirc;u chuẩn</p>\r\n<h2>C&aacute;c bước thực hiện th&iacute; nghiệm si&ecirc;u &acirc;m cọc khoan nhồi</h2>\r\n<p>Th&iacute; nghiệm si&ecirc;u &acirc;m cọc khoan nhồi với mục đ&iacute;ch x&aacute;c định t&iacute;nh đồng nhất của cọc khoan nhồi/barrette/tường trong đất/b&ecirc; t&ocirc;ng liền khối lớn dựa tr&ecirc;n biểu đồ phổ si&ecirc;u &acirc;m v&agrave; tốc độ s&oacute;ng lan truyền.</p>\r\n<ol>\r\n<li>Kiểm tra ống si&ecirc;u &acirc;m xem c&oacute; chứa đầy nước v&agrave; đ&atilde; được th&ocirc;ng</li>\r\n<li>Thả đồng thời 2 đầu đo xuống tận đ&aacute;y ống</li>\r\n<li>Bật m&aacute;y v&agrave;o c&aacute;c th&ocirc;ng số cần thiết</li>\r\n<li>Chạy test kiểm tra t&iacute;n hiệu thu</li>\r\n<li>K&eacute;o đều 2 đầu đo l&ecirc;n theo một vận tốc nhất định</li>\r\n<li>Scan t&iacute;n hiệu để c&oacute; được phổ si&ecirc;u &acirc;m v&agrave; c&aacute;c biểu đồ cần thiết kh&aacute;c</li>\r\n<li>Kiểm tra kết quả thu được v&agrave; đo lại những điểm nghi vấn khuyết tật nếu thấy cần thiết</li>\r\n<li>L&agrave;m tương tự với cặp ống si&ecirc;u &acirc;m kh&aacute;c</li>\r\n<li>Chuyển sang cấu kiện th&iacute; nghiệm tiếp theo</li>\r\n</ol>\r\n<p>B&aacute;o c&aacute;o kết quả th&iacute; nghiệm:</p>\r\n<ol>\r\n<li>T&ecirc;n, vị tr&iacute; c&ocirc;ng tr&igrave;nh</li>\r\n<li>Chủ đầu tư, Tư vấn thiết kế/gi&aacute;m s&aacute;t, Nh&agrave; thầu thi c&ocirc;ng cọc, Đơn vị th&iacute; nghiệm</li>\r\n<li>C&aacute;c số liệu về th&iacute; nghiệm si&ecirc;u &acirc;m cọc khoan nhồi như k&iacute;ch thước, ng&agrave;y đổ b&ecirc; t&ocirc;ng, ng&agrave;y th&iacute; nghiệm</li>\r\n<li>Bảng tổng hợp kết quả th&iacute; nghiệm</li>\r\n<li>Biểu đồ phổ si&ecirc;u &acirc;m v&agrave; biểu đồ vận tốc s&oacute;ng theo chiều s&acirc;u cấu kiện</li>\r\n<li>Kết luận chung v&agrave; khuyến nghị biện ph&aacute;p xử l&yacute; trong trường hợp cấu kiện c&oacute; khuyết tật</li>\r\n</ol>\r\n<p>Thu gọn</p>\r\n<div id=\"eJOY__extension_root\" class=\"eJOY__extension_root_class\" style=\"all: unset;\">&nbsp;</div>',NULL,'Published','Máy siêu âm cọc khoan nhồi CHUM (Piletest)','Đáp ứng TCVN 9396:2012 Cọc khoan nhồi - Xác định tính đồng nhất của bê tông - Phương pháp xung siêu âm','Công ty CIC , GPR',NULL,2,NULL,'2020-10-11 12:51:24','2020-12-02 02:48:56','2020-12-02 02:48:56'),(7,'Cabinet Vision','cabinet-vision','2020-10-16 19:53:00',1,1,'1607582834-cabinet-vision.jpg','Cabinet Vision là giải pháp phần mềm toàn diện cho quá trình thiết kế và sản xuất nội thất gỗ công nghiệp','<p><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">-<strong> Thiết kế:</strong> Tạo dựng v&agrave; chỉnh sửa c&aacute;c mẫu tủ c&oacute; sẵn được lưu trong bộ thư viện phong ph&uacute; v&agrave; c&oacute; thể mở rộng. Hỗ trợ xuất file .dxf để chỉnh sửa tr&ecirc;n c&aacute;c phần mềm CAD th&ocirc;ng dụng.</span></p>\r\n<p><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/D2ZiPvRD06mXsnBCrrMvh7Cu2dCCpSr0XqmhoNpN.png\" alt=\"thiet-ke-cabinetvision\" width=\"600\" height=\"310\" /></p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>- Kết xuất đồ họa:</strong> X&acirc;y dựng phối cảnh nhanh ch&oacute;ng, chỉnh sửa c&aacute;c t&ugrave;y chọn về &aacute;nh s&aacute;ng, phản xạ vật thể, độ ph&acirc;n giải,.. với t&iacute;nh năng PhotoVision. Tự do lựa chọn g&oacute;c đặt Camera gi&uacute;p mang lại trải nghiệm h&igrave;nh ảnh ch&acirc;n thực nhiều g&oacute;c độ. Hỗ trợ xuất file .dae (Collada) khi người d&ugrave;ng muốn c&oacute; phối cảnh mang hướng diễn họa tốt nhất c&ugrave;ng 3DSMax</span></p>\r\n<p><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/IVbMu37RSWS1KqrnZgudHCv0zHPYzG7000fOgngM.jpeg\" alt=\"\" width=\"600\" height=\"450\" /></p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>- Tạo b&aacute;o c&aacute;o:</strong> T&iacute;nh năng Report Center cho ph&eacute;p tạo tr&ecirc;n 200 b&aacute;o c&aacute;o nhằm theo d&otilde;i về danh s&aacute;ch c&aacute;c nguy&ecirc;n vật liệu, cấu kiện, chi tiết,... theo số lượng, k&iacute;ch thước, c&aacute;ch thức lắp đặt, gia c&ocirc;ng. Th&ecirc;m v&agrave;o đ&oacute;, Bid Center cho người d&ugrave;ng t&ugrave;y chọn c&aacute;c yếu tố ảnh hưởng đến gi&aacute; th&agrave;nh vận chuyển, t&iacute;nh to&aacute;n nh&acirc;n c&ocirc;ng hay lợi nhuận của c&ocirc;ng việc,...</span></p>\r\n<p><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/zLZv5hSwWDZ0ybZ5eMfUPvTauc1NQ7NIZf8XpgxM.png\" alt=\"tao-bao-cao-cabinetvision\" width=\"600\" height=\"309\" /></span></p>\r\n<p><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- <strong>Tạo bản vẽ kĩ thuật (Drawing):</strong></span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Tự động tạo c&aacute;c bản vẽ kĩ thuật, bản vẽ lắp hoặc bản vẽ chi tiết từ m&ocirc; h&igrave;nh 3D đ&atilde; c&oacute; trước đ&oacute;. C&ocirc;ng cụ hiệu chỉnh CAD đa dụng gi&uacute;p tối ưu h&oacute;a việc chỉnh sửa cũng như hiển thị c&aacute;c k&iacute;ch thước li&ecirc;n quan đến sản xuất, hoặc phục vụ sale, marketing,...</span></p>\r\n<p><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/l12W2AEwvCs29WjcDPuyGIg9sy8jj4TSC9WfBxWd.png\" alt=\"drawing-cabinetvision\" width=\"600\" height=\"309\" /></p>\r\n<p><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- <strong>Tối ưu xếp v&aacute;n (Panel Optimiser):</strong></span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Với c&ocirc;ng cụ S2M Center, c&aacute;c tấm v&aacute;n được sử dụng trong lắp r&aacute;p sẽ được xếp cắt đảm bảo ti&ecirc;u ch&iacute; tiết kiệm nguy&ecirc;n vật liệu nhất, kể cả khi sử dụng m&aacute;y cưa b&agrave;n trượt (Panel Saw) hoặc trung t&acirc;m gia c&ocirc;ng CNC (CNC Router). Th&ecirc;m v&agrave;o đ&oacute;, thư viện m&aacute;y v&agrave; dụng cụ căt đa dạng sẽ hỗ trợ người d&ugrave;ng trong việc mở rộng sản xuất cũng như đầu tư trang thiết bị mới.</span></p>\r\n<p><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/U38q6W4zIq8zyjtkBSLj1krMDm7tmE4HOWonHjEP.png\" alt=\"toi-uu-van-cabinetvision\" width=\"600\" height=\"309\" /><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp;</span></p>\r\n<p><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- <strong>Xuất lệnh G Code v&agrave; in tem nh&atilde;n:</strong></span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Dựa tr&ecirc;n c&aacute;c thiết kế đ&atilde; c&oacute;, phần mềm tự động x&acirc;y dựng c&aacute;c đường chạy dao với từng dụng cụ cắt cho trước; kết hợp với tr&igrave;nh bi&ecirc;n dịch (Post Processor) của từng h&atilde;ng m&aacute;y CNC sẽ tạo được bộ m&atilde; lệnh G Code phục vụ việc cắt v&aacute;n theo y&ecirc;u cầu. T&iacute;nh năng x&acirc;y dựng tem nh&atilde;n tự động gi&uacute;p người c&ocirc;ng nhận kiểm so&aacute;t được số lượng, k&iacute;ch thước, quan trọng hơn l&agrave; nguy&ecirc;n c&ocirc;ng được sử dụng tr&ecirc;n 1 tấm cụ thể.</span></p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/mGAiyDl9xhrFqcq6AePUQtTzSEsDgdHQm9rKZNAh.png\" alt=\"toi-uu-van-cabinetvision\" width=\"600\" height=\"310\" /></p>\r\n<div id=\"eJOY__extension_root\" class=\"eJOY__extension_root_class\" style=\"all: unset;\">&nbsp;</div>','<div class=\" col-md-9 lbody\">\r\n<div class=\"menu1\">\r\n<div class=\"tab-content\">\r\n<div id=\"menu1\" class=\"tab-pane fade active in\">\r\n<div id=\"boxdex\" class=\"contentt boxdex\" data-height=\"650\">\r\n<p><span style=\"font-size: 14pt; font-family: \'times new roman\', times, serif;\">Cabinet Vision l&agrave; giải ph&aacute;p kỹ thuật ho&agrave;n thiện cho ng&agrave;nh sản xuất tủ gỗ c&ocirc;ng nghiệp. Với lực lượng kĩ sư thiết kế chuy&ecirc;n v&agrave; kh&ocirc;ng chuy&ecirc;n l&ecirc;n đến 35000 người tại hơn 52 quốc gia, Cabinet Vision đ&atilde; x&acirc;y dựng ph&aacute;t triển c&aacute;c giải ph&aacute;p phần mềm, n&acirc;ng cao chất lượng v&agrave; t&iacute;nh &aacute;p dụng trong hơn 30 năm v&agrave; c&oacute; đến 13 ng&ocirc;n ngữ để lựa chọn.</span></p>\r\n<h2><span style=\"font-size: 14pt; font-family: \'times new roman\', times, serif;\"><strong>T&iacute;nh năng ch&iacute;nh:</strong></span></h2>\r\n</div>\r\n<div class=\"contentt boxdex\" data-height=\"650\"><span style=\"font-size: 14pt; font-family: \'times new roman\', times, serif;\">- Thiết kế c&aacute;c mẫu tủ, kệ v&agrave; lưu lại th&agrave;nh bộ thư viện phục vụ sử dụng l&acirc;u d&agrave;i</span><br /><span style=\"font-size: 14pt; font-family: \'times new roman\', times, serif;\">- Kết xuất đồ họa 3D kh&ocirc;ng gian nội thất, mang đến h&igrave;nh ảnh trực quan cho người thiết kế v&agrave; kh&aacute;ch h&agrave;ng</span><br /><span style=\"font-size: 14pt; font-family: \'times new roman\', times, serif;\">- X&acirc;y dựng b&aacute;o c&aacute;o nguy&ecirc;n liệu, vật tư, tư liệu sản xuất (Sơ đồ rải v&aacute;n, danh s&aacute;ch cắt, bản vẽ lắp,...) v&agrave; b&aacute;o gi&aacute;</span><br /><span style=\"font-size: 14pt; font-family: \'times new roman\', times, serif;\">- Tạo bản vẽ kỹ thuật phục vụ x&acirc;y dựng bộ hồ sơ thiết kế, thi c&ocirc;ng</span><br /><span style=\"font-size: 14pt; font-family: \'times new roman\', times, serif;\">- Tạo m&atilde; lệnh phục vụ gia c&ocirc;ng v&agrave; tem nh&atilde;n quản l&yacute; sản phẩm cuối c&ugrave;ng</span>\r\n<h2><span style=\"font-size: 14pt; font-family: \'times new roman\', times, serif;\"><strong>Ưu điểm:</strong></span></h2>\r\n<p><span style=\"font-size: 14pt; font-family: \'times new roman\', times, serif;\">- &nbsp;Đảm bảo t&iacute;nh liền mạch xuy&ecirc;n suốt từ qu&aacute; tr&igrave;nh thiết kế đến gia c&ocirc;ng</span><br /><span style=\"font-size: 14pt; font-family: \'times new roman\', times, serif;\">- &nbsp;Dễ d&agrave;ng cập nhật thư viện c&aacute;c m&aacute;y CNC, thay đổi nội dung c&aacute;c b&aacute;o c&aacute;o, thống k&ecirc; theo y&ecirc;u cầu của kh&aacute;ch h&agrave;ng</span><br /><span style=\"font-size: 14pt; font-family: \'times new roman\', times, serif;\">- Thực hiện việc tối ưu xếp v&aacute;n kh&ocirc;ng cần th&ecirc;m phần mềm hỗ trợ</span><br /><span style=\"font-size: 14pt; font-family: \'times new roman\', times, serif;\">- Th&iacute;ch hợp cho bộ phận d&aacute;n tem nh&atilde;n tự động của m&aacute;y CNC trung t&acirc;m</span><br /><span style=\"font-size: 14pt; font-family: \'times new roman\', times, serif;\">- T&iacute;nh năng ti&ecirc;u chuẩn người d&ugrave;ng (UCS) khả t&ugrave;y biến mạnh mẽ, đ&aacute;p ứng c&aacute;c nhu cầu phức tạp của c&aacute;c đơn vị sản xuất theo xu thế nội thất hiện đại; UCS mang lại gi&aacute; trị cốt l&otilde;i của Cabinet Vision.</span></p>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>\r\n<div id=\"eJOY__extension_root\" class=\"eJOY__extension_root_class\" style=\"all: unset;\">&nbsp;</div>','<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/videoseries?list=PLlNTCdjRlNJIbsSMQJnuLQZrNXNnpmXXY\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture\" allowfullscreen></iframe>','Published','Phần mềm Cabinet Vision','Phần mềm Cabinet Vision','Phần mềm Cabinet Vision, phần mềm gỗ, phần mềm cnc',NULL,2,NULL,'2020-10-11 12:55:27','2021-01-27 00:27:03',NULL),(8,'Phần mềm nội thất gỗ Haixun','phan-mem-noi-that-go-haixun','2020-12-10 14:34:00',0,0,'1607585957-phan-mem-noi-that-go-haixun.png','Haixun là giải pháp phần mềm toàn diện cho quá trình thiết kế và sản xuất nội thất gỗ công nghiệp','<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>- Thiết kế: </strong>Phần mềm hỗ trợ sản xuất c&aacute;c mẫu tủ, kệ từ c&aacute;c bản vẽ nhập từ AutoCAD, hoặc từ c&aacute;c module tủ c&oacute; sẵn. Người d&ugrave;ng c&oacute; thể dễ d&agrave;ng thiết kế c&aacute;c h&igrave;nh dạng đặc biệt bằng tay một c&aacute;ch nhanh ch&oacute;ng m&agrave; kh&ocirc;ng cần sử dụng bất cứ c&ocirc;ng cụ thiết kế hay c&aacute;c lệnh, m&atilde; phức tạp n&agrave;o.</span><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/OcjOC7XBq3t5AHfaHHY8VkY4lNFcGKTTDo13J0xE.png\" alt=\"thiet-ke-haixun\" width=\"600\" height=\"313\" /></strong></span></p>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- <strong>Xuất nhập CAD: </strong>C&aacute;c chi tiết CAD c&oacute; thể được th&ecirc;m v&agrave;o v&agrave; tự động điều chỉnh theo kh&ocirc;ng gian thiết kế. C&aacute;c chi tiết n&agrave;y c&oacute; thể lưu được th&agrave;nh c&aacute;c mẫu v&agrave; cập nhật v&agrave;o trong cơ sở dữ liệu. C&aacute;c k&iacute;ch cỡ, tỉ lệ v&agrave; c&aacute;c th&ocirc;ng số c&oacute; thể dễ d&agrave;ng điều chỉnh trong lần sử dụng tiếp. C&aacute;c bản vẽ 3D, c&aacute;c h&igrave;nh dạng đặc biệt dạng CAD, v.v&hellip; c&oacute; thể được xuất nhập nhanh ch&oacute;ng</span></p>\r\n<p><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>&nbsp;<img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/xGfQXzRZByOV3PPYL6AkzMX9joSaLQTIjGbsyZ9D.jpeg\" alt=\"\" width=\"600\" height=\"337\" /></strong></span></p>\r\n<p><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/gJM0NIVabOLiBL76nGRJOUnooFE5oZ90Y1mnuQmk.jpeg\" alt=\"\" width=\"600\" height=\"338\" /></strong></span></p>\r\n<p><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>- Rendering: </strong>T&iacute;nh năng Super Rendering cho ph&eacute;p người sử dụng t&ugrave;y chỉnh c&aacute;c thiết kế trong ng&ocirc;i nh&agrave;, tạo ảnh g&oacute;c rộng l&ecirc;n tới 720 độ&nbsp; v&agrave; ảnh nh&igrave;n đa hướng b&ecirc;n trong nh&agrave;, th&ecirc;m hiệu ứng &aacute;nh s&aacute;ng ch&acirc;n thực, giữ được m&agrave;u nguy&ecirc;n bản v&agrave; gi&uacute;p gia tăng trải nghiệm kh&aacute;ch h&agrave;ng với c&aacute;c sản phẩm nội thất, từ đ&oacute; n&acirc;ng cao hiệu quả marketing</span><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/71ULBbvlXzubvYWkY4PE8E65svTM8BWwsnhG3hmK.jpeg\" alt=\"render-haixun\" width=\"600\" height=\"450\" /></strong></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>- X&acirc;y dựng b&aacute;o c&aacute;o phục vụ sản xuất: </strong>Tự động x&acirc;y dựng c&aacute;c b&aacute;o c&aacute;o dưới dạng Excel về nguy&ecirc;n vật liệu, chi tiết phụ kiện, b&aacute;o gi&aacute;. Sau đ&oacute; sử dung c&aacute;c dữ liệu n&agrave;y phục vụ sản xuất bằng Haixun Production System</span></p>\r\n<p style=\"text-align: center;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><img src=\"/storage/uploads/tinymce/D8apQFPdCyjXOttBUd2khxdsuwsgtGVJ7bd1qm1G.png\" alt=\"bao-cao-haixun\" width=\"600\" height=\"311\" /></span></p>\r\n<p style=\"text-align: center;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>- Tạo v&agrave; xuất G Code để chạy m&aacute;y CNC:&nbsp; </strong>Sau khi tối ưu h&oacute;a, phần mềm c&oacute; thể trực tiếp tạo ra nhiều loại t&agrave;i liệu cần thiết cho gia c&ocirc;ng cũng như c&aacute;c kết nối li&ecirc;n tục giữa c&aacute;c trang thiết bị như cưa điện, m&aacute;y d&aacute;n tem tự động, trung t&acirc;m gia c&ocirc;ng P2P, khoan 5 trục,&hellip;.</span></p>\r\n<p><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/sdeXsUDV5My6wx3EsbDCggCzDaYSxziwlIy5LgAA.png\" alt=\"gcode-haixun\" width=\"600\" height=\"319\" />&nbsp;</strong></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>- In tem nh&atilde;n: </strong>Phần nh&atilde;n th&ocirc;ng tin hiển thị th&ocirc;ng tin trực quan cần thiết cho sản xuất v&agrave; gia c&ocirc;ng, như l&agrave; c&aacute;c th&ocirc;ng tin về chi tiết đơn h&agrave;ng, bản vẽ bố cục, th&ocirc;ng tin v&aacute;n v&agrave; c&aacute;c th&ocirc;ng tin kh&aacute;c... R&uacute;t ngắn thời gian sắp xếp nguy&ecirc;n liệu cho c&ocirc;ng nh&acirc;n</span></p>\r\n<p><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/nQpGNHxXoCwVqyvxWUtZxcq0wWR16NJVzWINHrsQ.png\" alt=\"tem-haixun\" width=\"600\" height=\"320\" /></span></p>','<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Haixun được ph&aacute;t triển bởi Hisoonsoft, c&ocirc;ng ty chuy&ecirc;n cung cấp c&aacute;c giải ph&aacute;p về thiết kế nội thất gỗ c&ocirc;ng nghiệp, c&oacute; trụ sở tại Thanh Đảo (Trung Quốc). Đ&acirc;y được coi l&agrave; giải ph&aacute;p thiết kế v&agrave; sản xuất to&agrave;n diện h&agrave;ng đầu tại khu vực, đối thủ nặng k&yacute; của c&aacute;c phần mềm kh&aacute;c về t&iacute;nh ứng dụng.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>T&iacute;nh năng ch&iacute;nh:&nbsp;</strong></span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- Thiết kế c&aacute;c mẫu tủ, kệ v&agrave; lưu lại th&agrave;nh bộ thư viện phục vụ sử dụng l&acirc;u d&agrave;i</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- Kết xuất đồ họa 3D kh&ocirc;ng gian nội thất, mang đến h&igrave;nh ảnh trực quan cho người thiết kế v&agrave; kh&aacute;ch h&agrave;ng (Cloud Rendering)</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- X&acirc;y dựng b&aacute;o c&aacute;o nguy&ecirc;n liệu, vật tư, tư liệu sản xuất (Sơ đồ rải v&aacute;n, danh s&aacute;ch cắt, bản vẽ lắp,...) v&agrave; b&aacute;o gi&aacute;</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- Tạo bản vẽ kỹ thuật phục vụ x&acirc;y dựng bộ hồ sơ thiết kế, thi c&ocirc;ng</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- Tạo m&atilde; lệnh phục vụ gia c&ocirc;ng v&agrave; tem nh&atilde;n quản l&yacute; sản phẩm cuối c&ugrave;ng</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>Ưu điểm:</strong></span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- &nbsp;C&ocirc;ng cụ tạo h&igrave;nh đa dạng về c&aacute;ch thức, linh hoạt về việc chỉnh sửa k&iacute;ch thước, tương quan vị tr&iacute; của c&aacute;c chi tiết trong tủ</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- &nbsp;Quản l&yacute; c&aacute;c đơn h&agrave;ng nhanh ch&oacute;ng, thuận tiện</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- Thực hiện việc tối ưu xếp v&aacute;n kh&ocirc;ng cần th&ecirc;m phần mềm hỗ trợ</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- Th&iacute;ch hợp cho bộ phận d&aacute;n tem nh&atilde;n tự động của m&aacute;y CNC trung t&acirc;m</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- Hỗ trợ t&iacute;nh năng Cloud Rendering cập nhật theo thời gian thực</span></p>','<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/videoseries?list=PLlNTCdjRlNJIsUPnHW7seQwoqqFZlzZ0g\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture\" allowfullscreen></iframe>','Published','Phần mềm nội thất gỗ Haixun','Haixun là giải pháp phần mềm toàn diện cho quá trình thiết kế và sản xuất nội thất gỗ công nghiệp','phần mềm haixun, phần mềm nội thất',NULL,2,NULL,'2020-12-10 00:39:17','2021-12-01 23:54:25',NULL),(9,'Phần mềm Alphacam - Thiết kế và sản xuất gỗ tự nhiên','phan-mem-alphacam-thiet-ke-va-san-xuat-go-tu-nhien','2020-12-10 15:03:00',0,0,'1607587865-phan-mem-alphacam-thiet-ke-va-san-xuat-go-tu-nhien.jpg','ALPHACAM là giải pháp CAD/CAM trực quan mạnh mẽ cho các ngành công nghiệp gỗ, kim loại, đá. Phần mềm có tính linh hoạt  và độ tin cậy cao, xây dựng nhiều module gồm phay, khắc, tiện, gia công 2 đến 5 trục, ….','<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">ALPHACAM c&oacute; thể được ứng dụng trong nhiều l&atilde;nh vực kh&aacute;c nhau , một trong số đ&oacute; l&agrave; lĩnh vực nội thất bao gồm c&aacute;c sản phẩm như: cửa đi, cửa sổ, tủ, cầu thang, đi&ecirc;u khắc tr&ecirc;n mặt phẳng. Tất cả c&aacute;c sản phẩm được thiết kế từ 2D v&agrave; thiết kế 3D đều c&oacute; thể sản xuất dễ d&agrave;ng v&agrave; nhanh ch&oacute;ng với Phần mềm ALPHACAM. ALPHACAM c&oacute; rất nhiều t&iacute;nh năng tiện lợi v&agrave; linh hoạt cung cấp giải ph&aacute;p tốt nhất cho kh&aacute;ch h&agrave;ng .</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>T&iacute;nh năng ch&iacute;nh</strong></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">-Alphacam Router: Module lập tr&igrave;nh gia c&ocirc;ng cho c&aacute;c sản phẩm của ng&agrave;nh c&ocirc;ng nghiệp sản xuất gỗ</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- Lập tr&igrave;nh gia c&ocirc;ng:</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">+ Mặt phẳng 2D</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">+ Phay 3 &ndash; 5 trục</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">+ Khắc, đi&ecirc;u khắc</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">+ Tiện</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>Ưu điểm</strong></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- Giao diện đơn giản</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- Gia c&ocirc;ng mặt phẳng bất kỳ (2D)</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- 3D Milling mạnh mẽ -3D Engraving and Art</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- M&ocirc; phỏng Robot (2017) truyền trực tiếp qua OLP của phần mềm RoboDK</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- T&iacute;ch hợp S2M for Alphacam (Cabinet Vision)</span></p>','<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>Alphacam Router<br /></strong><a href=\"https://advancecad.edu.vn/wp-content/uploads/2015/08/lap-trinh-alphacam.jpg\"><br /></a>T&iacute;ch hợp nhiều chế độ gia c&ocirc;ng 3D th&ocirc; v&agrave; tinh &nbsp;của c&aacute;c khối h&igrave;nh học, c&aacute;c bề mặt hay c&aacute;c file STL c&oacute; sẵn trong thư viện. C&aacute;c chế độ gia c&ocirc;ng kể tr&ecirc;n c&oacute; thể sử dụng tr&ecirc;n hầu hết c&aacute;c bề mặt v&agrave; thực hiện bởi đa dạng loại m&aacute;y CNC từ 3 &ndash; 5 trục</span></p>\r\n<p><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/0NlD9PwZWRTJNt6ut30a8gOliKz4Tt0oy49XiKR1.png\" alt=\"alphacam-1\" width=\"600\" height=\"337\" /></strong></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>Planar Machining &ndash; Gia c&ocirc;ng 2D</strong></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Alphacam hỗ trợ lập tr&igrave;nh để c&aacute;c dụng cụ cắt th&ocirc;ng thường c&oacute; thể l&agrave;m việc tại bất cứ mặt phẳng tọa độ n&agrave;o. Đối với c&aacute;c trục xoay được bổ sung, người d&ugrave;ng vẫn c&oacute; thể lập tr&igrave;nh v&agrave; kiểm so&aacute;t c&aacute;c th&ocirc;ng số li&ecirc;n quan đến g&oacute;c nghiệng v&agrave; c&aacute;c thuật to&aacute;n nội suy d&ugrave;ng cho m&aacute;y CNC 5 trục.</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>&nbsp;</strong></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>Multi-Axis Machining (gia c&ocirc;ng nhiều trục)</strong></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Việc sản xuất tr&ecirc;n c&aacute;c m&aacute;y trung t&acirc;m gia c&ocirc;ng &nbsp;4 v&agrave; 5 trục được hỗ trợ tối ưu với Alphacam. C&aacute;c bộ phận c&oacute; thể được k&eacute;o v&agrave; thả v&agrave;o một đối tượng cố định, thiết lập gốc tọa độ &nbsp;v&agrave; tr&igrave;nh tự gia c&ocirc;ng tự động theo ti&ecirc;u ch&iacute; tối ưu thời gian gia c&ocirc;ng cho d&acirc;y chuyền sản xuất C&ocirc;ng cụ m&ocirc; phỏng &nbsp;ch&acirc;n thực, với đầy đủ thuật to&aacute;n &nbsp;x&acirc;y dựng &nbsp;trong Alphacam &nbsp;nhằm kiểm so&aacute;t c&aacute;c rủi ro lập tr&igrave;nh c&oacute; thể xảy ra trước khi gia c&ocirc;ng thực, từ đ&oacute; đảm bảo việc lập tr&igrave;nh ch&iacute;nh x&aacute;c ngay từ đầu, gi&uacute;p tăng năng suất cho quy tr&igrave;nh</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>3D Milling (Phay 3D)</strong></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">T&iacute;ch hợp nhiều chế độ gia c&ocirc;ng 3D th&ocirc; v&agrave; tinh &nbsp;của c&aacute;c khối h&igrave;nh học, c&aacute;c bề mặt hay c&aacute;c file STL c&oacute; sẵn trong thư viện. C&aacute;c chế độ gia c&ocirc;ng kể tr&ecirc;n c&oacute; thể sử dụng tr&ecirc;n hầu hết c&aacute;c bề mặt v&agrave; thực hiện bởi đa dạng loại m&aacute;y CNC từ 3 &ndash; 5 trục.</span></p>\r\n<p><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/M2EttNPDUAXzqEq4R7fLem5PRTPj7hyVOuYQsiaZ.png\" alt=\"\" width=\"600\" height=\"337\" /></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>3D Engraving (Khắc chữ,hoa văn)</strong></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">T&iacute;nh năng 3D Engraving mạnh mẽ th&iacute;ch hợp cho việc tạo dựng c&aacute;c t&aacute;c phẩm nghệ thuật đi&ecirc;u khắc với độ ch&iacute;nh x&aacute;c cao</span></p>\r\n<p style=\"text-align: justify;\"><img src=\"/storage/uploads/tinymce/leoZ7eKIvq1kz5rNi9EcXAxlXERiHUT0COsSSYLg.png\" alt=\"\" width=\"600\" height=\"337\" /></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>Alphacam Turning (Tiện)</strong></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">&nbsp;&Aacute;p dụng thư viện ti&ecirc;u chuẩn, hỗ trợ lập tr&igrave;nh gia c&ocirc;ng tiện theo nhiều đường k&iacute;nh trục cũng như c&aacute;c bi&ecirc;n dạng h&igrave;nh học kh&aacute;c nhau</span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>&nbsp;</strong></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>&nbsp;Alphacam Art (Đi&ecirc;u khắc)</strong></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">C&ocirc;ng cụ hỗ trợ tối đa việc x&acirc;y dựng c&aacute;c tham số h&igrave;nh học 2D v&agrave; chuyển đổi sang c&aacute;c được chạy dao CNC với độ ch&iacute;nh x&aacute;c cao. C&aacute;c t&iacute;nh năng bổ trợ của Alphacam Art gi&uacute;p đơn giản h&oacute;a việc chỉnh sửa m&ocirc; h&igrave;nh 3D c&oacute; sẵn cũng như m&ocirc; h&igrave;nh 3D được x&acirc;y dựng từ &yacute; tưởng thiết kế của người d&ugrave;ng. T&iacute;ch hợp c&ocirc;ng cụ Aspire for Alphacam phục vụ cho nhu cầu tạo h&igrave;nh c&aacute;c bề mặt trang tr&iacute; c&ocirc;ng phu, c&aacute;c đường gờ kiến tr&uacute;c, biển hiệu, đồ trang sức,&hellip;.</span></p>','<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/videoseries?list=PLlNTCdjRlNJLcvyYlGoxLtEMZkpn1vLqq\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture\" allowfullscreen></iframe>','Published','Phần mềm Alphacam - Thiết kế và sản xuất gỗ tự nhiên','ALPHACAM là giải pháp CAD/CAM trực quan mạnh mẽ cho các ngành công nghiệp gỗ, kim loại, đá. Phần mềm có tính linh hoạt  và độ tin cậy cao, xây dựng nhiều module gồm phay, khắc, tiện, gia công 2 đến 5 trục, ….',NULL,NULL,2,NULL,'2020-12-10 01:11:05','2021-12-01 23:54:10',NULL),(10,'Logikal - Phần mềm gia công hệ cửa, hệ vách dựng','logikal-phan-mem-gia-cong-he-cua-he-vach-dung','2020-12-10 15:17:00',0,1,'1607588809-logikal-phan-mem-gia-cong-he-cua-he-vach-dung.jpg','Tính toán thiết kế, lập trình sản xuất cửa sổ, hệ cửa đi và hệ mặt dựng.','<p><strong>Thiết kế</strong></p>\r\n<p>Thiết kế c&aacute;c hệ cửa đi, cửa số v&agrave; v&aacute;ch dựng dựa tr&ecirc;n bộ cơ sở dữ liệu về profile, phụ kiện v&agrave; li&ecirc;n kết cho trước (C&oacute; thể điều chỉnh). C&aacute;c mẫu n&agrave;y c&oacute; thể được lưu lại th&agrave;nh bộ thư viện, phục vụ qu&aacute; tr&igrave;nh sử dụng l&acirc;u d&agrave;i cửa người d&ugrave;ng</p>\r\n<p>&nbsp;</p>\r\n<p><strong>B&aacute;o c&aacute;o</strong></p>\r\n<p>Với LogiKal&reg;, người d&ugrave;ng c&oacute; thể lựa chọn xuất ra nhiều loại b&aacute;o c&aacute;o như:</p>\r\n<ul>\r\n<li>B&aacute;o c&aacute;o định lượng vật tư theo cửa (Estimation)</li>\r\n<li>B&aacute;o c&aacute;o vật tư tổng quan dự &aacute;n (Material Analysis)</li>\r\n<li>Sơ đồ cắt tối ưu thanh profile (Cut Optimisation)</li>\r\n<li>Sơ đồ hướng dẫn lắp đặt (Assembly List)</li>\r\n<li>Đề nghị mua h&agrave;ng/ nguy&ecirc;n liệu (Order)</li>\r\n<li>B&aacute;o gi&aacute; v&agrave; h&oacute;a đơn (Quotation and Invoice)</li>\r\n</ul>\r\n<p>Đặc biệt, mỗi loại b&aacute;o c&aacute;o kể tr&ecirc;n c&oacute; thể được xuất ra dưới dạng .pdf, .docx,, .xml để c&oacute; thể chỉnh sửa v&agrave; lưu trữ dễ d&agrave;ng</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Tối ưu h&oacute;a</strong></p>\r\n<p>Phần mềm LogiKal&reg; tự động t&iacute;nh to&aacute;n sắp xếp c&aacute;c thanh profile th&agrave;nh phần dựa tr&ecirc;n chiều d&agrave;i thanh ti&ecirc;u chuẩn, đảm bảo được tỉ lệ hao ph&iacute; l&agrave; nhỏ nhất. B&ecirc;n cạnh đ&oacute;, phần mềm cho ph&eacute;p người d&ugrave;ng sử dụng c&aacute;c chiều d&agrave;i thanh profile đặc biệt v&agrave; sử dụng thanh profile dư từ c&aacute;c dự &aacute;n trước, g&oacute;p phần tối đa h&oacute;a lượng nguy&ecirc;n liệu đầu v&agrave;o trong qu&aacute; tr&igrave;nh sản xuất</p>\r\n<p>&nbsp;</p>\r\n<p><strong>CNC</strong></p>\r\n<p>Phần mềm LogiKal&reg; &nbsp;tự động t&iacute;nh to&aacute;n c&aacute;c dữ liệu gia c&ocirc;ng cần thiết để chuyển sang c&ocirc;ng đoạn sản xuất. Sử dụng LogiKal&reg; CNC nhằm chuyển giao c&aacute;c nguy&ecirc;n c&ocirc;ng khoan, phay, cắt g&oacute;c từ m&ocirc; &nbsp;h&igrave;nh thiết kế tới c&aacute;c trung t&acirc;m gia c&ocirc;ng CNC 3 đến 5 trục một c&aacute;ch ch&iacute;nh x&aacute;c v&agrave; nhanh ch&oacute;ng</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Kết nối giải ph&aacute;p ERP/PPS</strong></p>\r\n<p>Dễ d&agrave;ng kết nối LogiKal&reg; tới c&aacute;c giải ph&aacute;p ERP/PPS phổ biến hiện h&agrave;nh bằng giao diện chuy&ecirc;n biệt. Dữ liệu được xuất ra c&aacute;c định dạng XML, CSV v&agrave; DSTV.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Hệ thống Profile</strong></p>\r\n<p>LogiKal&reg; cung cấp bộ cơ sở dữ liệu từ c&aacute;c nh&agrave; cung cấp v&agrave; tạo h&igrave;nh profile h&agrave;ng đầu tr&ecirc;n thế giới. LogiKal&reg; ph&acirc;n biệt r&otilde; v&agrave; thể hiện trực quan điểm kh&aacute;c biệt trong thiết kế profile của từng nh&agrave; cung cấp, hỗ trợ người d&ugrave;ng lựa chọn một hoặc nhiều profile kh&aacute;c nhau ph&ugrave; hợp với nhu cầu sản xuất của từng doanh nghiệp.</p>','<p>Giải ph&aacute;p chuy&ecirc;n nghiệp cho sản xuất cửa sổ, hệ cửa đi v&agrave; hệ mặt dựng đến từ Orgadata</p>\r\n<p>T&iacute;nh năng ch&iacute;nh:</p>\r\n<p>-Thiết kế c&aacute;c&nbsp; hệ cửa đi, cửa số, hệ v&aacute;ch dựng</p>\r\n<p><br />-Tối ưu h&oacute;a t&iacute;nh to&aacute;n việc sử dụng nguy&ecirc;n vật liệu nh&ocirc;m k&iacute;nh cho qu&aacute; tr&igrave;nh sản xuất</p>\r\n<p><br />-X&acirc;y dựng&nbsp; nhiều loại b&aacute;o c&aacute;o theo y&ecirc;u cầu của người thiết kế</p>\r\n<p><br />-T&iacute;nh to&aacute;n c&aacute;c th&ocirc;ng số về kết cấu (của thanh nh&ocirc;m v&agrave; k&iacute;nh)</p>\r\n<p><br />-Tạo G Code gia c&ocirc;ng cắt v&agrave; khoan lỗ tr&ecirc;n thanh profile</p>\r\n<p><br />-Cung cấp thư viện profile&nbsp; theo ti&ecirc;u chuẩn của từng quốc gia</p>','<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/videoseries?list=PLlNTCdjRlNJIXUA6qGW68KNXzsxrJYNcJ\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture\" allowfullscreen></iframe>','Published','Logikal - Phần mềm gia công hệ cửa, hệ vách dựng','Tính toán thiết kế, lập trình sản xuất cửa sổ, hệ cửa đi và hệ mặt dựng','Logikal, Phần mềm gia công hệ cửa, hệ vách dựng',NULL,2,NULL,'2020-12-10 01:26:49','2021-12-01 23:54:59',NULL),(11,'SOFTTECH V6','softtech-v6','2020-11-30 16:58:00',0,2000,'1607594536-softtech-v6.jpg','Tính toán thiết kế, lập trình sản xuất cửa sổ, hệ cửa đi và hệ mặt dựng','<p><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>Thiết kế</strong></span></p>\r\n<ul>\r\n<li><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Linh hoạt giữa việc thiết kế: Thiết kế mới hoặc từ bộ thư viện c&oacute; sẵn</span></li>\r\n<li><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Chỉnh sửa m&ocirc; h&igrave;nh 3D trực quan, hỗ trợ x&acirc;y dựng m&ocirc; h&igrave;nh h&igrave;nh học phức tạp</span></li>\r\n<li><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">X&acirc;y dựng bản vẽ kỹ thuật với đầy đủ h&igrave;nh cắt v&agrave; c&aacute;c th&ocirc;ng số kỹ thuật k&egrave;m theo</span></li>\r\n</ul>\r\n<p><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>&nbsp;</strong></span><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>B&aacute;o gi&aacute;</strong></span></p>\r\n<ul>\r\n<li><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Nhập đơn h&agrave;ng đầu v&agrave;o với số lượng kh&ocirc;ng giới hạn</span></li>\r\n<li><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Nhanh ch&oacute;ng cập nhật những thay đổi ph&aacute;t sinh trong đơn h&agrave;ng với t&iacute;nh năng &ldquo;what-if&rdquo;</span></li>\r\n<li><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Hỗ trợ in trực tiếp b&aacute;o c&aacute;o từ đơn h&agrave;ng hiện c&oacute;</span></li>\r\n<li><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Hỗ trợ chỉnh sửa b&aacute;o c&aacute;o theo y&ecirc;u cầu về định dạng của người d&ugrave;ng</span></li>\r\n</ul>\r\n<p><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>Sản xuất</strong></span></p>\r\n<ul>\r\n<li><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Điều khiển qu&aacute; tr&igrave;nh gia c&ocirc;ng tr&ecirc;n hệ trục tọa độ Oxyz thường</span></li>\r\n<li><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Tạo file DXF. cho c&aacute;c chi tiết đ&atilde; gia c&ocirc;ng</span></li>\r\n<li><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Tạo G Code gia c&ocirc;ng thanh nh&ocirc;m</span></li>\r\n</ul>\r\n<div id=\"eJOY__extension_root\" class=\"eJOY__extension_root_class\" style=\"all: unset;\">&nbsp;</div>','<p><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Giải ph&aacute;p chuy&ecirc;n nghiệp cho sản xuất cửa sổ, hệ cửa đi v&agrave; hệ mặt dựng đến từ Softtech</span></p>\r\n<p><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">T&iacute;nh năng ch&iacute;nh:</span></p>\r\n<ul>\r\n<li><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Thiết kế c&aacute;c th&agrave;nh phần của hệ cửa đi, cửa số, hệ v&aacute;ch dựng</span></li>\r\n<li><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Tối ưu h&oacute;a t&iacute;nh to&aacute;n việc sử dụng nguy&ecirc;n vật liệu nh&ocirc;m k&iacute;nh cho qu&aacute; tr&igrave;nh sản xuất</span></li>\r\n<li><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">X&acirc;y dựng b&aacute;o c&aacute;o theo y&ecirc;u cầu của người thiết kế</span></li>\r\n<li><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">T&iacute;nh to&aacute;n c&aacute;c th&ocirc;ng số về kết cấu dựa theo m&ocirc; h&igrave;nh h&igrave;nh học v&agrave; tham số đầu v&agrave;o</span></li>\r\n<li><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Tạo G Code gia c&ocirc;ng thanh nh&ocirc;m</span></li>\r\n</ul>\r\n<div id=\"eJOY__extension_root\" class=\"eJOY__extension_root_class\" style=\"all: unset;\">&nbsp;</div>','<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/videoseries?list=PLlNTCdjRlNJI4WZq9TncmZ79tw6tTKWPZ\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture\" allowfullscreen></iframe>','Published','SOFTTECH V6','Tính toán thiết kế, lập trình sản xuất cửa sổ, hệ cửa đi và hệ mặt dựng','phần mềm nhôm kính, Softtech V6',NULL,2,NULL,'2020-12-10 03:00:56','2021-02-22 01:01:01',NULL),(12,'Phần mềm nội thất gỗ PYTHA','phan-mem-noi-that-go-pytha','2020-12-16 17:17:00',0,0,'1608114079-phan-mem-noi-that-go-pytha.jpg','Được phát triển bởi PYTHA Lab (1978), Pytha 3D CAD là giải pháp công nghệ giúp các nhà thiết kế và sản xuất đồ nội thất gỗ tối ưu toàn bộ quy trình từ khâu lên ý tưởng, thiết kế tại văn phòng cho đến quá trình triển khai gia công và sản xuất tại nhà máy với nhiều tính năng, bộ công cụ vượt trội.','<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>- Thiết kế:</strong> Module 3D Modeller mạnh mẽ hỗ trợ tạo h&igrave;nh c&aacute;c đối tượng h&igrave;nh học với đa dạng k&iacute;ch thước v&agrave; h&igrave;nh d&aacute;ng. Người d&ugrave;ng c&oacute; thể dễ d&agrave;ng thiết kế c&aacute;c h&igrave;nh dạng đặc biệt bằng &nbsp;một c&aacute;ch nhanh ch&oacute;ng m&agrave; kh&ocirc;ng cần sử dụng bất cứ c&ocirc;ng cụ hay kinh nghiệm thiết kế n&agrave;o</span></p>\r\n<p style=\"text-align: center;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><img src=\"/storage/uploads/tinymce/7B3mSNSfp5ZHnZ7zTh6oJ07DlMZxNrIdjDk4mQqw.png\" alt=\"thiet-ke-pytha\" width=\"600\" height=\"321\" /></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><strong>- Tạo Cabinet tự động:</strong> Với Auto Generator, người thiết kế dễ d&agrave;ng tạo dựng c&aacute;c đối tượng tủ, </span><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">kệ chỉ với v&agrave;i n&uacute;t nhấn. To&agrave;n bộ th&ocirc;ng tin tạo h&igrave;nh đặc th&ugrave; của tủ bếp được t&ugrave;y chỉnh nhanh ch&oacute;ng theo th&ocirc;ng số nhập v&agrave;o. Sau đ&oacute;, c&aacute;c li&ecirc;n kết trong tủ được thiết lập nhanh gọn với module Workshop</span></p>\r\n<p><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/storage/uploads/tinymce/rPj81gICvvb0mOyWWBOpl8hILNKbGGpvxDKrB1dQ.png\" alt=\"tao-cabinet-pytha\" width=\"600\" height=\"321\" /></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- Rendering: &nbsp;Module Radio Lab cho ph&eacute;p người sử dụng t&ugrave;y chỉnh c&aacute;c thiết kế trong kh&ocirc;ng gian nội thất, tạo ảnh g&oacute;c rộng l&ecirc;n tới 720 độ , th&ecirc;m hiệu ứng &aacute;nh s&aacute;ng ch&acirc;n thực, thể hiện ch&iacute;nh x&aacute;c m&atilde; m&agrave;u nguy&ecirc;n bản, gi&uacute;p gia tăng trải nghiệm kh&aacute;ch h&agrave;ng với c&aacute;c sản phẩm nội thất, từ đ&oacute; n&acirc;ng cao hiệu quả marketing.</span></p>\r\n<p style=\"text-align: center;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><img src=\"/storage/uploads/tinymce/UnWVnGZ13hfrzIFZxr5C4lcEu5eEDok5xneHtPr2.jpeg\" alt=\"\" width=\"600\" height=\"722\" /></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- X&acirc;y dựng b&aacute;o c&aacute;o phục vụ sản xuất: &nbsp;T&iacute;nh năng Part List tự động x&acirc;y dựng c&aacute;c b&aacute;o c&aacute;o theo y&ecirc;u cầu người d&ugrave;ng v&agrave; c&oacute; thể xuất dưới dạng Excel về nguy&ecirc;n vật liệu, chi tiết phụ kiện, b&aacute;o gi&aacute;.&nbsp;</span></p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/AoHAFuuDPkU0uoG5ZbQRtttL4Mt9g8QHg4qH1MFd.png\" alt=\"bao-cao-pytha\" width=\"600\" height=\"321\" /></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- Tạo v&agrave; xuất G Code để chạy m&aacute;y CNC: &nbsp;Sau khi tối ưu h&oacute;a sơ đồ cắt, phần mềm c&oacute; thể trực tiếp tạo ra nhiều tệp tin cần thiết cho gia c&ocirc;ng cũng như c&aacute;c kết nối li&ecirc;n tục giữa c&aacute;c trang thiết bị như cưa điện, m&aacute;y d&aacute;n tem tự động, trung t&acirc;m gia c&ocirc;ng P2P, khoan 5 trục,&hellip;. Hỗ trợ kết nối đa dạng nhiều loại m&aacute;y phổ biến tr&ecirc;n thế giới (Homag, Biesse, SCM, ....)</span></p>\r\n<p style=\"text-align: center;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\"><img src=\"/storage/uploads/tinymce/00LEBLRYxpobpFN57Zz7S5aaLBHH3deDRcRdzxkx.png\" alt=\"gcode-pytha\" width=\"600\" height=\"320\" /></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- In tem nh&atilde;n: Phần nh&atilde;n th&ocirc;ng tin hiển thị th&ocirc;ng tin trực quan cần thiết cho sản xuất v&agrave; gia c&ocirc;ng, như l&agrave; c&aacute;c th&ocirc;ng tin về chi tiết đơn h&agrave;ng, bản vẽ bố cục, th&ocirc;ng tin v&aacute;n v&agrave; c&aacute;c th&ocirc;ng tin kh&aacute;c... R&uacute;t ngắn thời gian sắp xếp nguy&ecirc;n liệu cho c&ocirc;ng nh&acirc;n.</span></p>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/SqkarmYeOynOQpMBb9NYi12KJdsqoPsYyr1n1yfH.png\" alt=\"\" width=\"600\" height=\"387\" /><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">&nbsp;</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>','<p><strong>Pytha 3D CAD</strong> l&agrave; giải ph&aacute;p c&ocirc;ng nghệ gi&uacute;p c&aacute;c nh&agrave; thiết kế v&agrave; sản xuất đồ nội thất gỗ tối ưu to&agrave;n bộ quy tr&igrave;nh từ kh&acirc;u l&ecirc;n &yacute; tưởng, thiết kế tại văn ph&ograve;ng cho đến qu&aacute; tr&igrave;nh triển khai gia c&ocirc;ng v&agrave; sản xuất tại nh&agrave; m&aacute;y với nhiều t&iacute;nh năng, bộ c&ocirc;ng cụ vượt trội.</p>\r\n<p><strong>Pytha 3D CAD</strong> tạo ra m&ocirc;i trường thiết kế 3D ti&ecirc;n tiến v&agrave; th&acirc;n thiện với người sử dụng, gi&uacute;p cho c&aacute;c nh&agrave; thiết kế c&oacute; thể tr&igrave;nh chiếu ngay thiết kế của m&igrave;nh bằng h&igrave;nh ảnh độ n&eacute;t cao, c&oacute; thể tương t&aacute;c được với thiết kế của m&igrave;nh bằng c&ocirc;ng nghệ thực tế ảo. Với khả năng hỗ trợ thiết kế tối ưu, <strong>Pytha 3D CAD</strong> gi&uacute;p người sử dụng thiết kế c&aacute;c mẫu sản phẩm mang t&iacute;nh thẩm mỹ cao với nhiều h&igrave;nh dạng, kiểu c&aacute;ch phức tạp m&agrave; hầu hết c&aacute;c phần mềm thiết kế - sản xuất kh&aacute;c tr&ecirc;n thị trường đều kh&ocirc;ng thể xử l&yacute;.</p>\r\n<p><strong>Pytha 3D CAD</strong> cung cấp bộ c&ocirc;ng cụ gi&uacute;p người sử dụng tự động b&oacute;c t&aacute;ch, triển khai c&aacute;c mẫu thiết kế 3D sang sản xuất bằng c&aacute;c bản vẽ kỹ thuật, c&aacute;c danh s&aacute;ch chi tiết cấu tạo v&agrave; chương tr&igrave;nh điều khiển gia c&ocirc;ng CNC tr&ecirc;n c&aacute;c d&ograve;ng m&aacute;y hiện đại. B&ecirc;n cạnh giao diện th&acirc;n thiện như Sketchup, phần mềm t&iacute;ch hợp rất nhiều t&iacute;nh năng ưu việt dựng h&igrave;nh của Autocad, Rhino, Grasshopper, 3dMax, v&agrave; Revit. C&oacute; thể n&oacute;i, <strong>Pytha 3D CAD </strong>l&agrave; một giải ph&aacute;p \"one for all\", (tạm dịch: <em>chỉ một cho tất cả)</em>. Với bề d&agrave;y ph&aacute;t triển đ&atilde; hơn 35 năm tại Đức, hiện <strong>Pytha 3D CAD</strong> l&agrave; phần mềm to&agrave;n diện cho thiết kế v&agrave; sản xuất nội thất với hơn 10.000 người sử dụng tr&ecirc;n to&agrave;n thế giới.</p>\r\n<p><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">Một số ưu điểm:</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- &nbsp;C&ocirc;ng cụ tạo h&igrave;nh mạnh mẽ, đa dạng về c&aacute;ch thức, linh hoạt trong t&ugrave;y biến a k&iacute;ch thước, tương quan vị tr&iacute; của c&aacute;c chi tiết trong đối tượng 3D</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- Thực hiện việc tối ưu xếp v&aacute;n kh&ocirc;ng cần th&ecirc;m phần mềm hỗ trợ&nbsp;</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- Th&iacute;ch hợp cho bộ phận d&aacute;n tem nh&atilde;n tự động của m&aacute;y CNC trung t&acirc;m</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- T&iacute;nh năng Radio Lab mạnh mẽ, ch&acirc;n thực</span></p>','<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/videoseries?list=PLlNTCdjRlNJJDq-6Ke7PFyyxtzITYgx3D\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture\" allowfullscreen></iframe>','Published','Phần mềm nội thất gỗ PYTHA','PYTHA được phát triển bởi PYTHA Lab (1978), công ty chuyên cung cấp các giải pháp về thiết kế nội thất gỗ công nghiệp tại Đức.  Đây được coi là một trong những giải pháp thiết kế và sản xuất toàn diện hàng đầu trên thế giới bởi tính linh hoạt tạo hình, tính thống nhất trong toàn bộ quy trình sản xuất. Đặc biệt, PYTHA được xem là công cụ không thể thiếu sử dụng cho mục đích marketing của doanh nghiệp\r\n\r\nƯu điểm:\r\n-  Công cụ tạo hình mạnh mẽ, đa dạng về cách thức, linh hoạt trong tùy biến a kích thước, tương quan vị trí của các chi tiết trong đối tượng 3D\r\n- Thực hiện việc tối ưu xếp ván không cần thêm phần mềm hỗ trợ \r\n- Thích hợp cho bộ phận dán tem nhãn tự động của máy CNC trung tâm\r\n- Tính năng Radio Lab mạnh mẽ, chân thực\r\n\r\nNhược điểm:\r\n- Chi phí đầu tư ban đầu tương đối cao.','thiết kế nội thất, nội thất, nội thất gỗ, pytha, phần mềm gỗ, phần mềm cnc',NULL,2,NULL,'2020-12-16 03:21:19','2021-12-01 23:53:50',NULL),(13,'Phần mềm gia công kính A+W','phan-mem-gia-cong-kinh-aw','2020-12-17 09:23:00',0,1,'1608171991-phan-mem-gia-cong-kinh-aw.jpg','A+W là phần mềm hàng đầu trong tính toán, thiết kế và quản lý quy trình sản xuất cho ngành công nghiệp kính','<p style=\"text-align: justify;\"><strong><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">A+W Business:</span></strong><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- Giải ph&aacute;p ho&agrave;n thiện đầu v&agrave;o: T&iacute;ch hợp đầy đủ c&aacute;c t&iacute;nh năng về sản xuất v&agrave; thương mại, c&oacute; thể t&ugrave;y biến theo nhu cầu sản xuất đặc th&ugrave;</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- Kiểm so&aacute;t quy tr&igrave;nh sản xuất đơn giản v&agrave; hiệu quả, gi&uacute;p giảm thiểu chi ph&iacute; đầu tư v&agrave; tiết kiệm nguồn thời gian cho doanh nghiệp</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- A+W Barcode Manager hỗ trợ quản l&yacute; khối lượng h&agrave;ng h&oacute;a lưu trữ trong kho, giảm sự tham gia của con người trong m&ocirc;i trường vận chuyển dễ xảy ra sự cố đổ vỡ</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- A+W Shape Optimizer tối đa lượng nguy&ecirc;n liệu sử dụng dựa tr&ecirc;n c&aacute;c thuật to&aacute;n th&ocirc;ng minh v&agrave; mang t&iacute;nh t&ugrave;y biến được</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- Hỗ trợ tạo dựng hồ sơ thiết kế theo c&aacute;c định dạng chuẩn quốc tế; thể hiện ch&iacute;nh x&aacute;c, trực quan c&aacute;c th&ocirc;ng tin sản xuất trong từng đơn h&agrave;ng</span></p>\r\n<p style=\"text-align: justify;\"><strong><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">A+W Production:</span></strong><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- Quản l&yacute; d&acirc;y chuyền v&agrave; đa d&acirc;y chuyền sản xuất</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- Tối ưu nguy&ecirc;n vật liệu, tối ưu đ&oacute;ng g&oacute;i h&agrave;ng h&oacute;a</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- Cập nhật tức thời t&igrave;nh trạng c&ocirc;ng việc tại 1 quy tr&igrave;nh cụ thể, phản hồi tới m&aacute;y chủ trong trường hợp ph&aacute;t sinh sự cố, t&iacute;nh to&aacute;n lại thời gian sản xuất cần thiết khi c&oacute; thay đổi trong quy tr&igrave;nh do lỗi kh&aacute;ch quan.</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- Quản l&yacute; to&agrave;n bộ m&aacute;y m&oacute;c trong d&acirc;y chuyền với giao diện đơn giản, thuận tiện cho thao t&aacute;c</span></p>\r\n<p style=\"text-align: justify;\"><strong><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">A+W Enterprise:</span></strong><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- Xử l&yacute; đơn h&agrave;ng v&agrave; c&aacute;c quy tr&igrave;nh sau nhanh ch&oacute;ng nhờ tự động h&oacute;a từ qu&aacute; tr&igrave;nh mua h&agrave;ng, sản xuất đến nhập kho v&agrave; vận chuyển</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- Hệ thống quản trị dữ liệu bảo mật v&agrave; c&oacute; t&iacute;nh ổn định cao tr&ecirc;n nền tảng UNIX &nbsp;v&agrave; Informix</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- T&iacute;ch hợp BOMs v&agrave; &nbsp;xuất nhập nền tảng CAD gi&uacute;p tự động h&oacute;a t&iacute;nh to&aacute;n, tiết kiệm thời gian v&agrave; gi&aacute; cả cho quy tr&igrave;nh thống k&ecirc; vật tư, nguy&ecirc;n liệu. Ngo&agrave;i ra quy tr&igrave;nh BOMs đ&atilde; được giảm tối đa c&aacute;c lỗi ph&aacute;t sinh nhờ trợ năng giao diện nhập dữ liệu v&agrave; tự động chỉnh sửa th&ocirc;ng số</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- Tối ưu linh hoạt qu&aacute; tr&igrave;nh vận chuyển theo hệ thống định vị th&ocirc;ng minh v&agrave; thuật to&aacute;n bốc dỡ h&agrave;ng &nbsp;DIFOT ưu việt</span></p>','<p style=\"text-align: justify;\"><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- Quản l&yacute; đơn h&agrave;ng c&ugrave;ng c&aacute;c th&ocirc;ng tin kh&aacute;ch h&agrave;ng li&ecirc;n quan</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- T&iacute;nh to&aacute;n, thiết kế tạo h&igrave;nh tấm k&iacute;nh v&agrave; c&aacute;c nguy&ecirc;n c&ocirc;ng tr&ecirc;n tấm</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- Tối ưu h&oacute;a t&iacute;nh to&aacute;n việc sử dụng nguy&ecirc;n liệu k&iacute;nh cho qu&aacute; tr&igrave;nh sản xuất</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- X&acirc;y dựng b&aacute;o c&aacute;o theo y&ecirc;u cầu của người thiết kế</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- Quản l&yacute; kho vận, tối ưu khối lượng h&agrave;ng h&oacute;a vận chuyển theo ti&ecirc;u ch&iacute; ng&agrave;y giao h&agrave;ng v&agrave; địa điểm giao h&agrave;ng</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- Quản l&yacute; quy tr&igrave;nh sản xuất bằng việc tập trung quản l&yacute; theo từng c&ocirc;ng đoạn nhỏ, gửi dữ liệu trạng th&aacute;i c&ocirc;ng việc l&ecirc;n m&aacute;y chủ</span><br /><span style=\"font-family: \'times new roman\', times, serif; font-size: 14pt;\">- Tạo G Code gia c&ocirc;ng tấm k&iacute;nh</span></p>','<iframe width=\"560\" height=\"315\" src=\"https://www.youtube.com/embed/videoseries?list=PLlNTCdjRlNJIcgO1iktKmIaEA-l_dHOtK\" frameborder=\"0\" allow=\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture\" allowfullscreen></iframe>','Published','Phần mềm gia công kính A+W','A+W là phần mềm hàng đầu trong tính toán, thiết kế và quản lý quy trình sản xuất cho ngành công nghiệp kính.','thiết kế nội thất, nội thất, nội thất kính, phần mềm gia công kính, phần mềm kính',NULL,2,NULL,'2020-12-16 19:26:31','2021-12-01 23:51:34',NULL),(14,'Phần mềm thiết kế và gia công kim loại LANTEK','phan-mem-thiet-ke-va-gia-cong-kim-loai-lantek','2021-02-22 15:06:00',0,0,'1613981989-phan-mem-thiet-ke-va-gia-cong-kim-loai-lantek.jpg','Lantek là bộ giải pháp phần mềm toàn diện cho ngành công nghiệp gia công kim loại tấm và thép định hình.','<p><span style=\"font-size: 12pt;\"><strong><span style=\"font-weight: 400;\">METAL PLATFORM</span></strong></span></p>\r\n<h2><span style=\"font-size: 12pt;\"><strong>Lantek Expert</strong></span></h2>\r\n<ul>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><span style=\"font-weight: 400; font-size: 12pt;\">Expert Cut</span></li>\r\n</ul>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Lantek Expert Cut l&agrave; một phần mềm CAD/CAM được thiết kế đặc biệt cho c&aacute;c m&aacute;y gia c&ocirc;ng kim loại tấm CNC (m&aacute;y cắt &ocirc;xi, m&aacute;y cắt plasma, m&aacute;y cắt laser, m&aacute;y cắt tia nước). N&oacute; l&agrave; kết quả của hơn 25 kinh nghiệm trong việc cộng t&aacute;c to&agrave;n diện giữa nh&agrave; sản xuất v&agrave; người sử dụng c&aacute;c loại m&aacute;y. Lantek Expert Cut l&agrave; sự kết hợp ho&agrave;n hảo giữa c&ocirc;ng nghệ m&aacute;y với lập tr&igrave;nh cũng như đ&aacute;p ứng y&ecirc;u cầu quản l&yacute; quy tr&igrave;nh gia c&ocirc;ng</span></p>\r\n<p>&nbsp;</p>\r\n<ul>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><span style=\"font-weight: 400; font-size: 12pt;\">Expert Punch</span></li>\r\n</ul>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Lantek Expert Punch l&agrave; phần mềm CAD/CAM được thiết kế đặc biệt cho c&aacute;c m&aacute;y gia c&ocirc;ng đột dập kim loại tấm. Phần mềm sử dụng c&aacute;c thuật tho&aacute;n th&ocirc;ng minh trong qu&aacute; tr&igrave;nh tối ưu h&oacute;a nguy&ecirc;n liệu; quản l&yacute; c&aacute;c th&ocirc;ng số m&aacute;y m&oacute;c cũng như t&iacute;nh to&aacute;n chi ph&iacute;, thời gian gia c&ocirc;ng</span></p>\r\n<p>&nbsp;</p>\r\n<ul>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><span style=\"font-weight: 400; font-size: 12pt;\">Expert Quattro</span></li>\r\n</ul>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Lantek Expert Quattro l&agrave; giải ph&aacute;p phần mềm thiết kế chuy&ecirc;n biệt cho c&aacute;c m&aacute;y cắt ph&ocirc;i kim loại tấm. Giải ph&aacute;p t&iacute;ch hợp sẵn thuật to&aacute;n hỗ trợ qu&aacute; tr&igrave;nh tối ưu nguy&ecirc;n liệu đầu v&agrave;o</span></p>\r\n<p>&nbsp;</p>\r\n<ul>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><span style=\"font-weight: 400; font-size: 12pt;\">Expert Duct</span></li>\r\n</ul>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Lantek Expert Duct l&agrave; giải ph&aacute;p mạnh mẽ cho việc thiết kế c&aacute;c phần tử trong hệ thống HVAC (Hệ thống nhiệt, th&ocirc;ng gi&oacute; v&agrave; điều h&ograve;a kh&ocirc;ng kh&iacute;)</span></p>\r\n<p>&nbsp;</p>\r\n<h2><span style=\"font-size: 12pt;\"><strong>Lantek Flex 3D</strong></span></h2>\r\n<ul>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><span style=\"font-weight: 400; font-size: 12pt;\">Flex 3D 5x</span></li>\r\n</ul>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Thiết kế chuy&ecirc;n biệt cho qu&aacute; tr&igrave;nh gia c&ocirc;ng 5 trục sử dụng tia laser v&agrave; tia nước. Phần mềm tương th&iacute;ch với hầu hết c&aacute;c giải ph&aacute;p thiết kế 3D hiện h&agrave;nh tr&ecirc;n thế giới. Hỗ trợ xuất nhập c&aacute;c định dạng thiết kế thường d&ugrave;ng nhằm tiết kiệm thời gian tạo h&igrave;nh v&agrave; t&iacute;nh to&aacute;n thiết kế</span></p>\r\n<ul>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><span style=\"font-weight: 400; font-size: 12pt;\">Flex 3D tubes</span></li>\r\n</ul>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Thiết kế sử dụng cho việc thiết kế v&agrave; t&iacute;nh to&aacute;n gia c&ocirc;ng c&aacute;c bi&ecirc;n dạng ống. Dễ d&agrave;ng sử dụng nhờ bộ c&ocirc;ng cụ thiết kế c&oacute; giao diện th&acirc;n thiện. Hỗ trợ tối ưu h&oacute;a v&agrave; kết nối hầu hết c&aacute;c thương hiệu m&aacute;y CNC tr&ecirc;n thế giới</span></p>\r\n<ul>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><span style=\"font-weight: 400; font-size: 12pt;\">Flex 3D Steelwork</span></li>\r\n</ul>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Module sử dụng cho việc thiết kế v&agrave; t&iacute;nh to&aacute;n quy tr&igrave;nh gia c&ocirc;ng th&eacute;p định h&igrave;nh (th&eacute;p chữ I,U,T,H,L v&agrave; c&aacute;c ống th&eacute;p c&oacute; profile vu&ocirc;ng, tr&ograve;n). Hỗ trợ nhập c&aacute;c mẫu thiết kế CAD từ c&aacute;c phần mềm thiết kế bi&ecirc;n dạng th&eacute;p kết cấu h&agrave;ng đầu (DSTV, SAT v&agrave; CAM file). X&acirc;y dựng quy tr&igrave;nh tối ưu, gia c&ocirc;ng cắt c&aacute;c mẫu xuất từ bộ phần mềm Lantek 2D (tệp .dxf)</span></p>\r\n<ul>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><span style=\"font-weight: 400; font-size: 12pt;\">Flex 3D CAD Add-in</span></li>\r\n</ul>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Giải ph&aacute;p thống nhất quy tr&igrave;nh CAD/CAM/ERP, hỗ trợ trải phẳng c&aacute;c thiết kế 3D từ c&aacute;c module kh&aacute;c của bộ phần mềm Lantek. Tương th&iacute;ch với c&aacute;c mẫu thiết kế từ Solidworks, NX v&agrave; Inventor</span></p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">FACTORY MANAGEMENT&nbsp;</span></p>\r\n<h2><span style=\"font-size: 12pt;\"><strong>Lantek MES</strong></span></h2>\r\n<ul>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><span style=\"font-weight: 400; font-size: 12pt;\">Manager&nbsp;</span></li>\r\n</ul>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Giải ph&aacute;p quản l&yacute; quy tr&igrave;nh sản xuất từ giai đoạn ph&aacute;t sinh đơn h&agrave;ng đến sản phẩm cuối c&ugrave;ng theo thời gian thực. T&iacute;nh to&aacute;n, ph&acirc;n t&iacute;ch khả năng tối ưu của to&agrave;n bộ quy tr&igrave;nh, từ đ&oacute; đưa ra thay đổi th&iacute;ch hợp nhằm giảm thiểu chi ph&iacute; v&agrave; thời gian lao động</span></p>\r\n<p>&nbsp;</p>\r\n<ul>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><span style=\"font-weight: 400; font-size: 12pt;\">WOS</span></li>\r\n</ul>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Quản l&yacute; v&agrave; vận h&agrave;nh quy tr&igrave;nh sản xuất chuy&ecirc;n biệt cho c&aacute;c doanh nghiệp gia c&ocirc;ng kim loại tấm dựa tr&ecirc;n c&aacute;c bộ c&ocirc;ng cụ cần thiết trong việc thu thập dữ liệu sản xuất: Trạng th&aacute;i, nh&acirc;n lực, vật liệu, m&aacute;y m&oacute;c, nh&agrave; xưởng, kho b&atilde;i,....</span></p>\r\n<p><br /><br /></p>\r\n<ul>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><span style=\"font-weight: 400; font-size: 12pt;\">Capture</span></li>\r\n</ul>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Module sử dụng nhằm nhập dữ liệu sản xuất từ kh&ocirc;ng gian l&agrave;m việc (shop floor), phục vụ c&aacute;c c&ocirc;ng đoạn tiếp theo cho quy tr&igrave;nh sản xuất</span></p>\r\n<p>&nbsp;</p>\r\n<ul>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><span style=\"font-weight: 400; font-size: 12pt;\">Invertory</span></li>\r\n</ul>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Giải ph&aacute;p quản l&yacute; thời gian thực về số lượng v&agrave; trạng th&aacute;i của kho b&atilde;i</span></p>\r\n<p>&nbsp;</p>\r\n<h2><span style=\"font-size: 12pt;\"><strong>Lantek Integra</strong></span></h2>\r\n<ul>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><span style=\"font-weight: 400; font-size: 12pt;\">Quotes</span></li>\r\n</ul>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Cung cấp bộ c&ocirc;ng cụ nhằm quản l&yacute;, ph&acirc;n loại th&ocirc;ng tin kh&aacute;ch h&agrave;ng; hỗ trợ x&acirc;y dựng phương &aacute;n kinh doanh v&agrave; ph&acirc;n t&iacute;ch rủi ro của từng phương &aacute;n. Li&ecirc;n kết trực tiếp với c&aacute;c giải ph&aacute;p CAD/CAM của Lantek</span></p>\r\n<p>&nbsp;</p>\r\n<ul>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><span style=\"font-weight: 400; font-size: 12pt;\">Sales</span></li>\r\n</ul>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">&nbsp;Được thiết kế đặc biệt nhằm phục vụ c&aacute;c nhu cầu li&ecirc;n quan đến chu kỳ b&aacute;n h&agrave;ng của doanh nghiệp</span></p>\r\n<p>&nbsp;</p>\r\n<ul>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><span style=\"font-weight: 400; font-size: 12pt;\">Purchases</span></li>\r\n</ul>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">&nbsp;Được thiết kế đặc biệt nhằm phục vụ c&aacute;c nhu cầu li&ecirc;n quan đến chu kỳ thanh to&aacute;n của doanh nghiệp bao gồm: Quản l&yacute; th&ocirc;ng tin nh&agrave; cung cấp, thanh to&aacute;n gi&aacute; trị đơn h&agrave;ng tự động hoặc thủ c&ocirc;ng, ph&acirc;n t&iacute;ch v&agrave; lưu trữ quy tr&igrave;nh thanh to&aacute;n,...</span></p>\r\n<p>&nbsp;</p>\r\n<ul>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><span style=\"font-weight: 400; font-size: 12pt;\">Products</span></li>\r\n</ul>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Quản l&yacute; c&aacute;c th&ocirc;ng tin của sản phẩm trong v&agrave; sau quy tr&igrave;nh sản xuất</span></p>\r\n<p><br /><br /><br /></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">ADVANCED MANUFACTURING</span></p>\r\n<h2><span style=\"font-size: 12pt;\"><strong>Lantek Analysis</strong></span></h2>\r\n<ul>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><span style=\"font-weight: 400; font-size: 12pt;\">Manufacturing</span></li>\r\n</ul>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Điều phối dữ liệu thực cho qu&aacute; tr&igrave;nh sản xuất, ph&acirc;n t&iacute;ch v&agrave; đưa ra c&aacute;c dự b&aacute;o bằng thuật to&aacute;n th&ocirc;ng minh của Lantek. Xử l&yacute; to&agrave;n bộ nguồn dữ liệu của chuối cung ứng dựa tr&ecirc;n kinh nghiệm v&agrave; bộ dữ liệu ti&ecirc;u chuẩn 30 năm của Lantek</span></p>\r\n<p>&nbsp;</p>\r\n<ul>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><span style=\"font-weight: 400; font-size: 12pt;\">Customer</span></li>\r\n</ul>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Sử dụng c&aacute;c thuật to&aacute;n th&ocirc;ng minh, Lantek Analysis Customer nghi&ecirc;n cứu h&agrave;nh vị thanh to&aacute;n; dự b&aacute;o thanh to&aacute;n, t&iacute;nh to&aacute;n dự ph&ograve;ng nguồn chi từ đ&oacute; đưa ra gợi &yacute; thanh to&aacute;n ph&ugrave; hợp với sức ti&ecirc;u d&ugrave;ng của kh&aacute;ch h&agrave;ng. C&oacute; 2 module nhỏ hơn l&agrave; Lantek Advanced Planning v&agrave; Lantek Smart Quoting</span></p>\r\n<p>&nbsp;</p>\r\n<h2><span style=\"font-size: 12pt;\"><strong>Lantek MES+</strong></span></h2>\r\n<ul>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><span style=\"font-weight: 400; font-size: 12pt;\">Order Consolidation</span></li>\r\n</ul>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">T&iacute;nh to&aacute;n, đưa ra c&aacute;c gợi &yacute; về c&aacute;ch thức v&agrave; thứ tự thực hiện c&aacute;c nguy&ecirc;n c&ocirc;ng trong 1 quy tr&igrave;nh sản xuất cụ thể. Module tỏ ra hiệu quả khi doanh nghiệp n&agrave;y sở hữu nhiều hơn một kh&ocirc;ng gian sản xuất (nh&agrave; m&aacute;y, ph&acirc;n xưởng,..)</span></p>\r\n<p>&nbsp;</p>\r\n<ul>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><span style=\"font-weight: 400; font-size: 12pt;\">Advanced Connectivity</span></li>\r\n</ul>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Đảm bảo tiến độ cho quy tr&igrave;nh sản xuất dựa tr&ecirc;n c&aacute;c th&ocirc;ng số quản l&yacute; nguy&ecirc;n liệu tồn kho, hợp đồng, đơn gi&aacute;. Tự động điều chỉnh quy tr&igrave;nh dựa tr&ecirc;n c&aacute;c thay đổi của hệ thống MRP (Hoạch định y&ecirc;u cầu nguy&ecirc;n liệu)</span></p>\r\n<p>&nbsp;</p>\r\n<ul>\r\n<li style=\"font-weight: 400;\" aria-level=\"1\"><span style=\"font-weight: 400; font-size: 12pt;\">Advanced Planning</span></li>\r\n</ul>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Với sự trợ gi&uacute;p của dữ liệu thu thập được của c&aacute;c module tr&ecirc;n v&agrave; hệ thống ioT, Lantek Advanced Planning lập kế hoạc sản xuất ph&ugrave; hợp với đặc th&ugrave; về số lượng, nguy&ecirc;n liệu, ng&agrave;y giao h&agrave;ng của 1 hay nhiều đơn h&agrave;ng. C&aacute;c kế hoạch sản xuất n&agrave;y c&oacute; thể được tham khảo từ c&aacute;c quy tr&igrave;nh đ&atilde; x&acirc;y dựng trước đ&oacute;, nhờ v&agrave;o t&iacute;nh năng lưu trữ quy tr&igrave;nh sản xuất của Lantek</span></p>','<p><span style=\"font-weight: 400;\">Lantek l&agrave; bộ giải ph&aacute;p phần mềm to&agrave;n diện cho ng&agrave;nh c&ocirc;ng nghiệp gia c&ocirc;ng kim loại tấm v&agrave; th&eacute;p định h&igrave;nh</span></p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-weight: 400;\">Bộ phần mềm Lantek tập hợp to&agrave;n bộ c&aacute;c module cần thiết cho quy tr&igrave;nh sản xuất kim loại tấm từ&nbsp; giai đoạn tạo đơn h&agrave;ng đến quản l&yacute;&nbsp; quy tr&igrave;nh sau sản xuất. Bộ phần mềm được chia th&agrave;nh 3 nh&oacute;m ch&iacute;nh</span></p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-weight: 400;\">Metal Platform: Tập trung t&iacute;nh to&aacute;n thiết kế, tạo h&igrave;nh v&agrave; gia c&ocirc;ng kim loại tấm, th&eacute;p định h&igrave;nh (Lantek Expert, Lantek Flex 3D)</span></p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-weight: 400;\">Factory Management: Quản l&yacute; quy tr&igrave;nh sản xuất tại nh&agrave; xưởng theo thời gian thực (Lantek MES, Lantek Intergra)</span></p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-weight: 400;\">Advanced Manufacturing: Điều phối quy tr&igrave;nh sản xuất, quản l&yacute; quan hệ kh&aacute;ch h&agrave;ng&nbsp;</span></p>\r\n<p><span style=\"font-weight: 400;\">(Lantek Analysis, Lantek MES+)</span></p>',NULL,'Published','Phần mềm thiết kế và gia công kim loại LANTEK','Lantek là bộ giải pháp phần mềm toàn diện cho ngành công nghiệp gia công kim loại tấm và thép định hình.','phần mềm lantek, phầm mềm kim loại, phần mềm nội thất, phần mềm thiết kế',NULL,2,NULL,'2021-02-22 01:19:49','2021-12-01 23:53:42',NULL),(15,'Thiết bị 3D Scanner RangeVision','thiet-bi-3d-scanner-rangevision','2021-02-22 16:53:00',0,0,'1613988219-thiet-bi-3d-scanner-rangevision.png','RangeVision là công ty chuyên cung cấp thiết bị và phát triển phần mềm liên quan đến công nghệ quét 3D đến từ Nga, Với hơn 10 năm hoạt động, RangeVision có hơn 850 thiết bị được  bán ra và 40 đối tác trên toàn cầu. Các dòng sản phẩm chủ lực của công ty bao gồm các thiết bị quét 3D như NEO, Spectrum và Pro cùng với phần mềm hỗ trợ đi kèm','<p style=\"text-align: justify;\">&nbsp;</p>\r\n<h2 style=\"text-align: justify;\"><span style=\"font-size: 12pt;\"><strong>Phi&ecirc;n bản NEO</strong></span></h2>\r\n<p style=\"text-align: center;\"><img src=\"/storage/uploads/tinymce/vomeNtpUEi5WypO9qiuLvpabNB2iZ81BrZOsGZE1.png\" alt=\"\" width=\"550\" height=\"489\" /></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-size: 12pt;\">Ứng dụng</span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">- Thiết kế ngược</span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">- Hỗ trợ in 3D</span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">- Gi&aacute;o dục</span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">- Tạo h&igrave;nh 3D&nbsp;</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-size: 12pt;\">Th&ocirc;ng số kỹ thuật</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<table style=\"border-collapse: collapse; height: 422px; border-color: #000000; border-style: solid; margin-left: auto; margin-right: auto;\" border=\"1\" width=\"473\">\r\n<tbody>\r\n<tr style=\"height: 50px;\">\r\n<td style=\"height: 50px; width: 240.4px;\">\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">FOV</span></p>\r\n</td>\r\n<td style=\"height: 50px; width: 226px;\">\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">200x150x150 (mm)</span></p>\r\n</td>\r\n</tr>\r\n<tr style=\"height: 50px;\">\r\n<td style=\"height: 50px; width: 240.4px;\">\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">K&iacute;ch thước vật mẫu</span></p>\r\n</td>\r\n<td style=\"height: 50px; width: 226px;\">\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">3 cm - 1,2 m</span></p>\r\n</td>\r\n</tr>\r\n<tr style=\"height: 50px;\">\r\n<td style=\"height: 50px; width: 240.4px;\">\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Độ ch&iacute;nh x&aacute;c</span></p>\r\n</td>\r\n<td style=\"height: 50px; width: 226px;\">\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">0,05 mm</span></p>\r\n</td>\r\n</tr>\r\n<tr style=\"height: 50px;\">\r\n<td style=\"height: 50px; width: 240.4px;\">\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Độ ph&acirc;n giải</span></p>\r\n</td>\r\n<td style=\"height: 50px; width: 226px;\">\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">0,13 mm</span></p>\r\n</td>\r\n</tr>\r\n<tr style=\"height: 50px;\">\r\n<td style=\"height: 50px; width: 240.4px;\">\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Độ ph&acirc;n giải camera</span></p>\r\n</td>\r\n<td style=\"height: 50px; width: 226px;\">\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">2 MP</span></p>\r\n</td>\r\n</tr>\r\n<tr style=\"height: 50px;\">\r\n<td style=\"height: 50px; width: 240.4px;\">\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">K&iacute;ch thước thiết bị</span></p>\r\n</td>\r\n<td style=\"height: 50px; width: 226px;\">\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">430x380x155 mm, 5,5 kg</span></p>\r\n</td>\r\n</tr>\r\n<tr style=\"height: 50px;\">\r\n<td style=\"height: 50px; width: 240.4px;\">\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Đường k&iacute;nh b&agrave;n xoay</span></p>\r\n</td>\r\n<td style=\"height: 50px; width: 226px;\">\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">20 cm</span></p>\r\n</td>\r\n</tr>\r\n<tr style=\"height: 50px;\">\r\n<td style=\"height: 50px; width: 240.4px;\">\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Trọng lượng mẫu vật tối đa</span></p>\r\n</td>\r\n<td style=\"height: 50px; width: 226px;\">\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">20 kg</span></p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>\r\n<p style=\"text-align: justify;\"><br /><br /><br /></p>\r\n<h2 style=\"text-align: justify;\"><span style=\"font-size: 12pt;\"><strong>Phi&ecirc;n bản Spectrum</strong></span></h2>\r\n<p style=\"text-align: center;\"><span style=\"font-size: 12pt;\"><strong><img src=\"/storage/uploads/tinymce/uODAuvb5BMsVr6ZPbLzcw5m9NorxmkinK7p02oQK.jpeg\" alt=\"\" width=\"550\" height=\"655\" /></strong></span></p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-size: 12pt;\">Ứng dụng</span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">- Thiết kế ngược v&agrave; ph&aacute;c mẫu nhanh</span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">- Ứng dụng thiết kế c&ocirc;ng nghiệp &ocirc; t&ocirc;</span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">- Gi&aacute;o dục</span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">- T&aacute;i tạo v&agrave; hỗ trợ bảo quản di t&iacute;ch&nbsp;</span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">- Thiết kế đồ nội thất</span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">- Sản xuất h&agrave;ng lưu niệm</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<p style=\"text-align: justify;\"><span style=\"font-weight: 400; font-size: 12pt;\">Th&ocirc;ng số kỹ thuật</span></p>\r\n<p style=\"text-align: justify;\">&nbsp;</p>\r\n<table style=\"border-collapse: collapse; border-color: #000000; border-style: solid; margin-left: auto; margin-right: auto; height: 375px;\" border=\"1\" width=\"625\">\r\n<tbody>\r\n<tr>\r\n<td style=\"text-align: center; width: 283.6px;\">\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Độ ph&acirc;n giải m&aacute;y chiếu</span></p>\r\n</td>\r\n<td style=\"text-align: center; width: 109.2px;\">\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">HD</span></p>\r\n</td>\r\n<td style=\"text-align: center; width: 110px;\">\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">HD</span></p>\r\n</td>\r\n<td style=\"text-align: center; width: 110px;\">\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">HD</span></p>\r\n</td>\r\n</tr>\r\n<tr>\r\n<td style=\"text-align: center; width: 283.6px;\">\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Độ ph&acirc;n giải camera (MP)</span></p>\r\n</td>\r\n